// ── Runtime error capture (Rule 18 — field_browser.test.js reads this) ──────
// window._fieldErrors collects errors from critical path functions.
// Read by: Playwright browser test, ?debug=1 panel, Night Owl diagnostics.
// Playwright CI job checks this array is empty after 15s page load.
window._fieldErrors = window._fieldErrors || [];

// CC-CMD-2026-07-13-capturefielderror-cap: window._fieldErrors had zero size
// cap and zero per-fn dedup before this. The general Bucket B telemetry sweep
// is about to add captureFieldError() calls to functions with real call-site
// counts of 30+ (renderAll), 25 (findESPNScore), etc -- a repeatedly-firing
// failure branch on any of those would grow this array unbounded over a long
// session, degrading memory and drowning real Health Panel signal in
// duplicate noise. Overriding .push() here (not inside captureFieldError()
// itself) protects every writer uniformly -- captureFieldError(), the
// window.onerror/unhandledrejection handlers below, and every other direct
// window._fieldErrors.push() call site in the file -- without touching any
// of them individually. Real eviction (oldest dropped, tracked via a real
// counter), not a silent stop-recording; real per-fn dedup with a count
// field, not just suppression.
window._fieldErrorsDropped = window._fieldErrorsDropped || 0;
const FIELD_ERRORS_CAP = 500;
const FIELD_ERROR_DEDUP_WINDOW_MS = 60000;
const _fieldErrorsLastByFn = new Map(); // fn -> entry ref, O(1) dedup lookup regardless of interleaving
Object.defineProperty(window._fieldErrors, 'push', {
  value: function fieldErrorsPush(entry) {
    const fn = entry && typeof entry === 'object' ? entry.fn : undefined;
    const now = (entry && typeof entry === 'object' && entry.ts) || Date.now();
    if (fn) {
      const last = _fieldErrorsLastByFn.get(fn);
      if (last && (now - last.ts) < FIELD_ERROR_DEDUP_WINDOW_MS) {
        last.count = (last.count || 1) + 1;
        last.ts = now;
        if (entry.err !== undefined) last.err = entry.err;
        return this.length;
      }
    }
    if (this.length >= FIELD_ERRORS_CAP) {
      const evicted = Array.prototype.shift.call(this);
      if (evicted && evicted.fn && _fieldErrorsLastByFn.get(evicted.fn) === evicted) {
        _fieldErrorsLastByFn.delete(evicted.fn);
      }
      window._fieldErrorsDropped++;
    }
    const len = Array.prototype.push.call(this, entry);
    if (fn) _fieldErrorsLastByFn.set(fn, entry);
    return len;
  },
  writable: true, enumerable: false, configurable: true
});

window.addEventListener('error', e => {
  window._fieldErrors.push({ fn: 'window.onerror', err: e.message, src: e.filename, ts: Date.now() });
});
window.addEventListener('unhandledrejection', e => {
  window._fieldErrors.push({ fn: 'unhandledrejection', err: String(e.reason), ts: Date.now() });
});

// captureFieldError — replace bare catch(e){} on infrastructure calls
// silent=true: captured in _fieldErrors only (no console output)
// silent=false: also console.warn in FIELD_DEBUG mode
function captureFieldError(fn, err, silent=true){
  const entry={fn, err:err?.message||String(err), ts:Date.now()};
  (window._fieldErrors=window._fieldErrors||[]).push(entry);
  if(!silent&&typeof FIELD_DEBUG!=='undefined'&&FIELD_DEBUG)
    console.warn('[FIELD silent fail]',fn,entry.err);
}

// FIELD_OPERATIONS: structured success/failure telemetry, extends captureFieldError()
// rather than replacing it — the Health Panel's window._fieldErrors keeps working.
// CC-CMD-2026-07-12-field-operation-primitive: Chunk 1 of a multi-CC-CMD sequence
// (see docs/CC-CMD-2026-07-12-typed-result-survey.md for Chunk 2). This chunk only
// builds the primitive -- zero existing call sites migrated to it here.
//
// 2026-07-13 (fieldOperation real-pilot — fetchCompoundEditorial, per the
// "fieldOperation vs captureFieldError and Novel Directions" Drive analysis'
// novel direction #1, operation identity): recordSuccess was a no-op stub
// ("additive counters/timing only — no behavior change to any caller") since
// Chunk 1. Giving it a real, capped body so success events are observable for
// the first time -- mirrors window._fieldErrors' ring-buffer pattern
// (FIELD_ERRORS_CAP=500 above), deliberately simplified: no per-fn dedup
// window, since successes don't carry the same hot-loop noise risk repeated
// failures do, and this has exactly one caller today (see fetchCompoundEditorial
// below). Revisit dedup if adoption grows past this pilot.
window._fieldOperations = window._fieldOperations || [];
const FIELD_OPERATIONS_CAP = 200;
function _pushFieldOperation(entry) {
  if (window._fieldOperations.length >= FIELD_OPERATIONS_CAP) Array.prototype.shift.call(window._fieldOperations);
  window._fieldOperations.push(entry);
}
const FIELD_OPERATIONS = {
  recordSuccess({ subsystem, operation, duration, context }) {
    _pushFieldOperation({ subsystem, operation, duration, context, ok: true, ts: Date.now() });
  },
  recordFailure(failure) {
    _pushFieldOperation({
      subsystem: failure.subsystem, operation: failure.operation,
      context: failure.context, ok: false,
      error: failure.error?.message || String(failure.error), ts: Date.now(),
    });
    captureFieldError(`${failure.subsystem}:${failure.operation}`, failure.error, failure.severity !== 'trace');
    // additive: also retain the richer failure object for future consumers
    // (window._fieldFailures or similar) — do not remove or alter what
    // captureFieldError() itself does.
  },
};

async function fieldOperation({
  subsystem,
  operation,
  severity = 'degraded',
  retryable = false,
  context = {},
}, fn) {
  const startedAt = performance.now();
  try {
    const value = await fn();
    FIELD_OPERATIONS.recordSuccess({ subsystem, operation, duration: performance.now() - startedAt, context });
    return { ok: true, value };
  } catch (error) {
    const failure = { subsystem, operation, severity, retryable, context, error, at: Date.now() };
    FIELD_OPERATIONS.recordFailure(failure);
    return { ok: false, code: classifyFieldError(error), ...failure };
  }
}

function classifyFieldError(error) {
  // Start minimal and honest — do not invent categories with no real
  // evidence behind them yet. HTTP status, if present on the error object
  // from this codebase's existing fetch wrappers, is the one classification
  // that's already reliably derivable today.
  if (error && typeof error.status === 'number') return 'HTTP_ERROR';
  return 'UNKNOWN_ERROR';
}

// ── FIELD Health Panel ────────────────────────────────────────────────────────
// Accessible two ways:
//   1. Long-press settings button (⚙) for 1.5s — works on mobile without URL editing
//   2. ?debug=1 URL param — original method still works
//
// Shows runtime health of every feature so non-technical users can diagnose
// "this feature isn't working" without terminal access.
// Screenshot the panel and share it to a Claude session for instant diagnosis.

function buildFieldHealthPanel() {
  const rows = [];
  const ok  = (label, detail) => `<div class="fhp-row fhp-ok">✅ <b>${label}</b> ${detail}</div>`;
  const warn = (label, detail) => `<div class="fhp-row fhp-warn">⚠️ <b>${label}</b> ${detail}</div>`;
  const err  = (label, detail) => `<div class="fhp-row fhp-err">❌ <b>${label}</b> ${detail}</div>`;

  // ── App version ─────────────────────────────────────────────────────────
  const SW = window.SW_VERSION || '?';
  rows.push(ok('Version', SW));

  // ── WC Groups pill ───────────────────────────────────────────────────────
  const _wcPill = document.getElementById('wc-filter-pill');
  const _wcNow = new Date() >= new Date('2026-06-08T00:00:00') && new Date() < new Date('2026-07-20T00:00:00');
  if (!_wcNow) {
    rows.push(ok('WC Groups', 'Pre-tournament window not active'));
  } else if (_wcPill) {
    const _wcVisible = _wcPill.offsetParent !== null;
    rows.push(_wcVisible ? ok('WC Groups', 'Pill present + visible in filter bar') : warn('WC Groups', 'Pill in DOM but hidden (CSS/display issue)'));
  } else {
    rows.push(err('WC Groups', 'Pill not in DOM — buildFilters ran before wcActive? Check console'));
  }

  // ── Game cards ───────────────────────────────────────────────────────────
  const cards = document.querySelectorAll('.game-card').length;
  const tapWired = document.querySelectorAll('.card-body[data-open]').length;
  if (tapWired === 0 && cards > 0)
    rows.push(err('Card Tap', `${cards} cards but 0 pointer events wired — Samsung tap broken`));
  else if (tapWired === cards && cards > 0)
    rows.push(ok('Card Tap', `Pointer events on all ${tapWired} cards`));
  else if (cards === 0)
    rows.push(warn('Card Tap', 'No game cards rendered today'));
  else
    rows.push(warn('Card Tap', `${tapWired}/${cards} cards wired`));

  // ── NHL Analytics ────────────────────────────────────────────────────────
  const nhlGames = (allData?.sports||[]).filter(s => (s.sport||'').toLowerCase().includes('nhl'));
  if (nhlGames.length === 0) {
    rows.push(ok('NHL Analytics', 'No NHL games today'));
  } else {
    let nhlOk = 0, nhlMissing = [];
    nhlGames.forEach(sec => (sec.games||[]).forEach(g => {
      const ha = g._homeAbbr || getNHLAbbrev?.(g.home);
      const st = ha ? getNHLSpecialTeams?.(ha) : null;
      if (st) nhlOk++;
      else nhlMissing.push(`${teamNick(g.home||'')} (${ha||'?'})`);
    }));
    const total = nhlGames.reduce((n,s)=>n+(s.games||[]).length,0);
    if (nhlMissing.length === 0)
      rows.push(ok('NHL Analytics', `ST data for all ${nhlOk} game(s) · Sample: CAR PP ${getNHLSpecialTeams?.('CAR')?.pp}% PK ${getNHLSpecialTeams?.('CAR')?.pk}%`));
    else
      rows.push(err('NHL Analytics', `Missing ST data for: ${nhlMissing.join(', ')} — badges won't fire`));
  }

  // ── NHL game object enrichment ────────────────────────────────────────────
  const nhlAllGames = nhlGames.flatMap(s => s.games||[]);
  const nhlMissingAbbr = nhlAllGames.filter(g => !g._homeAbbr).length;
  if (nhlAllGames.length > 0) {
    if (nhlMissingAbbr === 0)
      rows.push(ok('NHL _homeAbbr', `Set on all ${nhlAllGames.length} NHL game(s)`));
    else
      rows.push(err('NHL _homeAbbr', `${nhlMissingAbbr} game(s) missing — nhlAnalyticsInit may not have run yet`));
  }

  // ── MLB Analytics ────────────────────────────────────────────────────────
  const mlbGames = (allData?.sports||[]).filter(s => (s.sport||'').toLowerCase().includes('mlb') || (s.sport||'').toLowerCase().includes('baseball'));
  if (mlbGames.length === 0) {
    rows.push(ok('MLB Analytics', 'No MLB games today'));
  } else {
    let mlbOk = 0, mlbMissAbbr = 0;
    mlbGames.forEach(sec => (sec.games||[]).forEach(g => {
      if (g._homeAbbr) mlbOk++; else mlbMissAbbr++;
    }));
    const total = mlbGames.reduce((n,s)=>n+(s.games||[]).length,0);
    if (mlbMissAbbr === 0)
      rows.push(ok('MLB Analytics', `_homeAbbr set on ${mlbOk}/${total} game(s)`));
    else
      rows.push(err('MLB Analytics', `${mlbMissAbbr} game(s) missing _homeAbbr — park/umpire badges may not fire`));
  }

  // ── Scouting Report data ─────────────────────────────────────────────────
  const nhlST = typeof NHL_SPECIAL_TEAMS !== 'undefined' ? Object.keys(NHL_SPECIAL_TEAMS).length : 0;
  const nhlGoalies = typeof NHL_GOALIE_RATINGS !== 'undefined' ? Object.keys(NHL_GOALIE_RATINGS).length : 0;
  if (nhlST >= 16 && nhlGoalies >= 15)
    rows.push(ok('Analytics Tables', `NHL: ${nhlST} teams · ${nhlGoalies} goalies`));
  else
    rows.push(err('Analytics Tables', `NHL teams: ${nhlST}/16 · goalies: ${nhlGoalies}/15`));

  // ── Bottom sheet ─────────────────────────────────────────────────────────
  const _bsEl = document.getElementById('bottom-sheet');
  const bsOpen = _bsEl ? _bsEl.classList.contains('open') : false;
  rows.push(ok('Bottom Sheet', bsOpen ? 'Currently open' : 'Ready (tap a game card to verify)'));

  // ── Journalism (FIELD Brief / compound editorial) ─────────────────────────
  // Shows whether AI prose actually rendered, vs the static placeholder.
  try {
    const fbText = document.querySelector('.field-brief-text');
    const briefTxt = fbText ? (fbText.textContent||'').trim() : '';
    const fbKey = typeof fieldBriefCacheKey === 'function' ? fieldBriefCacheKey() : null;
    const cached = fbKey ? sessionStorage.getItem(fbKey) : null;
    const budget = typeof journalismCallsToday === 'function' ? journalismCallsToday() : null;
    const used = budget ? budget.get() : '?';
    const isStatic = /^Tonight on FIELD:/.test(briefTxt) || briefTxt.length < 40;
    const inBackoff = typeof _compoundRetryAfter !== 'undefined' && Date.now() < _compoundRetryAfter;
    const backoffSec = inBackoff ? Math.ceil((_compoundRetryAfter - Date.now()) / 1000) : 0;
    var _makeResetBtn=function(){var b=document.createElement("button");b.textContent="Reset backoff";b.style.cssText="margin-left:6px;background:#c9a84c;color:#000;border:none;border-radius:4px;padding:2px 7px;font-size:.58rem;cursor:pointer;font-weight:700";b.onclick=function(){try{localStorage.removeItem("field_compound_retry_after");_compoundRetryAfter=0;window._compoundLastError="";var o=document.getElementById("fhp-overlay");if(o)o.remove();}catch(e){captureFieldError("health-panel:reset-backoff-button",e,true);}setTimeout(function(){location.reload();},200);};return b.outerHTML;}
    const resetBtn = inBackoff ? ' ' + _makeResetBtn() : '';
    if (cached && cached.length > 40) {
      rows.push(ok('Journalism', `Brief rendered (${cached.length} chars) · ${used} AI calls used`));
    } else if (briefTxt && !isStatic) {
      rows.push(ok('Journalism', `Brief live (${briefTxt.length} chars) · ${used} AI calls`));
    } else if (isStatic && briefTxt) {
      const lastErr = (typeof window._compoundLastError !== 'undefined' && window._compoundLastError) ? ' · err: ' + window._compoundLastError : '';
      rows.push(warn('Journalism', `Static only — compound null · ${used} AI calls${inBackoff ? ` · backoff ${backoffSec}s` : ''}${lastErr}`) + resetBtn);
    } else {
      const lastErr = (typeof window._compoundLastError !== 'undefined' && window._compoundLastError) ? ' · err: ' + window._compoundLastError : '';
      rows.push(warn('Journalism', `No brief text · ${used} AI calls${inBackoff ? ` · backoff ${backoffSec}s` : ''}${lastErr}`) + resetBtn);
    }
  } catch(e) {
    captureFieldError('health-panel:journalism-check', e, true);
    rows.push(warn('Journalism', 'Check failed: ' + (e?.message||'unknown')));
  }

  // ── Prose Quality rolling average (patent prior art) ─────────────────────
  try {
    const _jqRaw = localStorage.getItem('field_jq_scores');
    const _jqScores = _jqRaw ? JSON.parse(_jqRaw) : [];
    if(_jqScores.length) {
      const avg = Math.round(_jqScores.reduce((a,s)=>a+s.score,0)/_jqScores.length);
      const best = Math.max(..._jqScores.map(s=>s.score));
      const worst = Math.min(..._jqScores.map(s=>s.score));
      const avgStat = Math.round((_jqScores.reduce((a,s)=>a+(s.stat||0),0)/_jqScores.length)*10)/10;
      const qIcon = avg >= 60 ? '✅' : avg >= 45 ? '⚠️' : '❌';
      rows.push(ok('Prose Quality', `${qIcon} avg ${avg}/300 · best ${best} · worst ${worst} · stat ${avgStat}/s · ${_jqScores.length} briefs`));
    } else {
      rows.push(ok('Prose Quality', 'No briefs scored yet'));
    }
  } catch(e) { captureFieldError('health-panel:prose-quality-check', e, true); rows.push(warn('Prose Quality', 'Could not read score history')); }

  // ── Phrase Review queue (Tier 3 feedback loop) ───────────────────────────
  try {
    const _revRaw = localStorage.getItem('field_jq_review');
    const _revItems = _revRaw ? JSON.parse(_revRaw) : [];
    if(_revItems.length) {
      const _recent = _revItems.slice(-5);
      const _allPhrases = [...new Set(_revItems.flatMap(r=>r.phrases||[]))];
      rows.push(warn('Phrase Review', `${_revItems.length} low-score briefs · ${_allPhrases.length} unique phrases flagged · Recent: ${_recent.flatMap(r=>r.phrases).slice(0,4).join(', ')}`));
    } else {
      rows.push(ok('Phrase Review', 'No phrases flagged yet'));
    }
  } catch(e) { captureFieldError('health-panel:phrase-review-check', e, true); rows.push(warn('Phrase Review', 'Could not read review queue')); }

  // ── Errors ────────────────────────────────────────────────────────────────
  const errors = window._fieldErrors || [];
  const droppedCount = window._fieldErrorsDropped || 0;
  const droppedNote = droppedCount ? ` · ${droppedCount} older suppressed (cap reached)` : '';
  if (errors.length)
    rows.push(err('Runtime Errors', `${errors.length} captured: ${errors.slice(0,2).map(e=>e.fn+':'+e.err+(e.count>1?` (×${e.count})`:'')).join(' · ')}${droppedNote}`));
  else if (droppedCount)
    rows.push(warn('Runtime Errors', `0 currently captured${droppedNote}`));
  else
    rows.push(ok('Runtime Errors', 'None captured'));

  // ── Score Confidence (PM-20 Step 4) ─────────────────────────────────────
  // Tallies _scoresBySource: verified (both sources agree), mismatch (both
  // disagree — diagnostic), single (only one source has polled).
  // The diagnostic Jeff actually wanted tonight: "did we get the right
  // score for Tigers @ Rays?" becomes answerable inside FIELD itself.
  const _sc_tally = { verified: 0, mismatch: 0, single: 0 };
  const _sc_mismatches = [];
  if (typeof _scoresBySource === 'object' && _scoresBySource) {
    for (const [key, entry] of Object.entries(_scoresBySource)) {
      if (!entry) continue;
      if (entry.espn && entry.apisports) {
        const agree = entry.espn.homeScore === entry.apisports.homeScore &&
                      entry.espn.awayScore === entry.apisports.awayScore;
        if (agree) _sc_tally.verified++;
        else {
          _sc_tally.mismatch++;
          _sc_mismatches.push({ key, espn: entry.espn, apisports: entry.apisports });
        }
      } else if (entry.espn || entry.apisports) {
        _sc_tally.single++;
      }
    }
  }
  const _sc_total = _sc_tally.verified + _sc_tally.mismatch + _sc_tally.single;
  const _sc_lines = [];
  _sc_lines.push(`<div style="color:#76e08a">✅ verified <span style="color:#999;float:right">${_sc_tally.verified} games</span></div>`);
  if (_sc_tally.mismatch > 0)
    _sc_lines.push(`<div style="color:#ff6868">⚠ mismatch <span style="color:#999;float:right">${_sc_tally.mismatch} games</span></div>`);
  else
    _sc_lines.push(`<div style="color:#666">· no mismatches <span style="color:#666;float:right">0 games</span></div>`);
  _sc_lines.push(`<div style="color:#8888aa">· single source <span style="color:#999;float:right">${_sc_tally.single} games</span></div>`);
  // List specific mismatches inline (max 3, then "+ N more")
  if (_sc_mismatches.length) {
    const _sc_show = _sc_mismatches.slice(0, 3);
    for (const m of _sc_show) {
      const [hn, an] = m.key.split('|');
      _sc_lines.push(`<div style="color:#ff9b6b;font-size:.55rem;margin-left:.5rem">⚠ ${an} @ ${hn} · espn:${m.espn.awayScore}-${m.espn.homeScore} · apisports:${m.apisports.awayScore}-${m.apisports.homeScore}</div>`);
    }
    if (_sc_mismatches.length > 3)
      _sc_lines.push(`<div style="color:#888;font-size:.55rem;margin-left:.5rem">+ ${_sc_mismatches.length - 3} more</div>`);
  }
  const _sc_label = _sc_total === 0 ? `<span style="color:#666;font-weight:400;font-size:.55rem"> · no live scores</span>` : '';
  rows.push(`<div id="fhp-score-confidence" style="margin-top:.4rem">
    <div style="color:#c9a84c;font-size:.6rem;font-weight:700;margin-bottom:.25rem">
      🎯 Score Confidence${_sc_label}
    </div>
    <div style="color:#8888aa;font-size:.58rem">${_sc_lines.join('')}</div>
  </div>`);

  // ── CC-CMD-2026-06-15-client-features-2 Commit 3: Brief Corpus Intelligence
  // Populated asynchronously by loadBriefQualityRow() — placeholder row here
  // so layout doesn't jump when the data lands.
  rows.push(`<div id="fhp-brief-quality" class="fhp-row" style="opacity:.75">
    ⏳ <b>Brief Quality</b> Loading from /archive/query…
  </div>`);

  // ── Relay Init Status (relay-init-staleness-visibility) ─────────────────
  // Reads window._relayInitStatus, populated by _recordRelayInit() at each
  // of the 9 relay-overlay init functions' success/failure points. These
  // functions fail silently by design (stubs/fallbacks remain in place),
  // which is correct behavior for users but was previously invisible even
  // for debugging. This section makes it visible without touching any of
  // the 9 functions' existing try/catch or fallback logic.
  {
    const _riFns = ['mlbProbablePitcherInit','mlbPitcherStatsInit','mlbStatsInit','nbaPlayerCluichInit','nhlSeriesInit','nbaCluichInit','nhlGSAXInit','soccerFBrefInit','uflEpaInit'];
    const _riStatus = window._relayInitStatus || {};
    const _riFailLines = [];
    let _riOkCount = 0, _riFailCount = 0;
    for (const fn of _riFns) {
      const s = _riStatus[fn];
      if (!s) continue;
      if (s.ok) _riOkCount++;
      else { _riFailCount++; _riFailLines.push(`<div style="color:#ff9b6b;font-size:.55rem;margin-left:.5rem">⚠ ${fn} · ${s.error || 'failed'}</div>`); }
    }
    const _riPendingCount = _riFns.length - _riOkCount - _riFailCount;
    const _riLabel = _riFailCount > 0
      ? `<span style="color:#ff6868;font-weight:400;font-size:.55rem"> · ${_riFailCount} failing</span>`
      : (_riPendingCount === _riFns.length ? `<span style="color:#666;font-weight:400;font-size:.55rem"> · not yet run</span>` : '');
    rows.push(`<div id="fhp-relay-init" style="margin-top:.4rem">
      <div style="color:#c9a84c;font-size:.6rem;font-weight:700;margin-bottom:.25rem">
        🧩 Relay Init (9 overlays)${_riLabel}
      </div>
      <div style="color:#8888aa;font-size:.58rem">
        <div style="color:#76e08a">✅ loaded <span style="color:#999;float:right">${_riOkCount}/9</span></div>
        ${_riFailCount > 0 ? `<div style="color:#ff6868">⚠ failed <span style="color:#999;float:right">${_riFailCount}/9</span></div>` : ''}
        ${_riPendingCount > 0 ? `<div style="color:#8888aa">· not yet run <span style="color:#999;float:right">${_riPendingCount}/9</span></div>` : ''}
        ${_riFailLines.join('')}
      </div>
    </div>`);
  }

  // ── Relay/CI status (async — populated after panel renders) ─────────────
  // Was 'MCP RELAY' (called auth-gated /mcp tools). Now reads CI + smoke
  // directly from public GitHub API — same data, no auth surface in client.
  rows.push(`<div id="fhp-mcp" style="margin-top:.4rem">
    <div style="color:#c9a84c;font-size:.6rem;font-weight:700;margin-bottom:.25rem">
      🛰️ RELAY · CI
    </div>
    <div id="fhp-mcp-body" style="color:#8888aa;font-size:.58rem">Fetching…</div>
  </div>`);

  return rows.join('');
}

function showFieldHealthPanel() {
  let panel = document.getElementById('fhp-overlay');
  if (panel) { panel.remove(); return; } // toggle off

  panel = document.createElement('div');
  panel.id = 'fhp-overlay';
  panel.style.cssText = `
    position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,.85);
    display:flex;align-items:flex-end;justify-content:center;
    backdrop-filter:blur(4px);
  `;
  panel.innerHTML = `
    <div style="
      background:#0d0d1c;border-top:2px solid #c9a84c;border-radius:18px 18px 0 0;
      width:100%;max-width:600px;max-height:75vh;overflow-y:auto;
      padding:1rem 1.1rem 2.5rem;font-family:monospace;
    ">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:.75rem">
        <span style="font-size:.7rem;font-weight:700;color:#c9a84c;letter-spacing:.08em">
          ⚕ FIELD HEALTH — ${new Date().toLocaleTimeString()}
        </span>
        <button onclick="document.getElementById('fhp-overlay').remove()"
          style="background:rgba(255,255,255,.1);border:none;color:#fff;border-radius:6px;
                 padding:.25rem .6rem;font-size:.65rem;cursor:pointer">✕ Close</button>
      </div>
      <div style="font-size:.6rem;color:#8888aa;margin-bottom:.6rem">
        Screenshot and share to Claude for instant diagnosis.
      </div>
      <div id="fhp-rows">${buildFieldHealthPanel()}</div>
      <div style="margin-top:.75rem;font-size:.55rem;color:#555;text-align:center">
        Long-press ⚙ to open · Tap to close
      </div>
    </div>`;
  panel.addEventListener('click', e => { if (e.target === panel) panel.remove(); });
  document.body.appendChild(panel);
  // Fire MCP status fetch after panel is in DOM
  setTimeout(fetchMCPStatus, 100);
  // CC-CMD-2026-06-15-client-features-2 Commit 3: Brief Quality row from archive.
  // Fire-and-forget; placeholder stays "Loading…" on relay 404 or empty payload.
  setTimeout(() => { try { if (typeof loadBriefQualityRow === 'function') loadBriefQualityRow(); } catch(_) {} }, 120);
}

// ── CC-CMD-2026-06-15-client-features-2 Commit 3: Brief Corpus Intelligence ──
// Average quality_score across the last 14 archived slate-cron briefs,
// with a 7-day trend arrow comparing the most recent half to the prior
// half. Color routing: green if avg > 200, amber if 150-200, red if < 150.

function _briefQualityClassify(avg) {
  if (avg == null || !isFinite(avg)) return { cls: 'fhp-warn', icon: '⚠️' };
  if (avg > 200) return { cls: 'fhp-ok',   icon: '✅' };
  if (avg >= 150) return { cls: 'fhp-warn', icon: '⚠️' };
  return { cls: 'fhp-err', icon: '❌' };
}

function renderBriefQualityRow(briefs) {
  const target = document.getElementById('fhp-brief-quality');
  if (!target) return;
  const list = Array.isArray(briefs) ? briefs
            : Array.isArray(briefs?.results) ? briefs.results
            : Array.isArray(briefs?.briefs) ? briefs.briefs
            : [];
  // Sort by date desc so the half-split lines up with the trend.
  const withScore = list
    .filter(b => b && b.quality_score != null && isFinite(Number(b.quality_score)))
    .map(b => ({ ...b, _qs: Number(b.quality_score) }))
    .sort((a, b) => String(b.date || '').localeCompare(String(a.date || '')));
  if (!withScore.length) {
    target.outerHTML = `<div id="fhp-brief-quality" class="fhp-row" style="opacity:.6">
      — <b>Brief Quality</b> No archived briefs with quality_score yet
    </div>`;
    return;
  }
  const last14 = withScore.slice(0, 14);
  const avg = last14.reduce((a, b) => a + b._qs, 0) / last14.length;
  // Last 7 vs prior 7 trend
  let trend = '→';
  if (last14.length >= 4) {
    const half = Math.floor(last14.length / 2);
    const recent = last14.slice(0, half);
    const prior = last14.slice(half);
    if (recent.length && prior.length) {
      const ra = recent.reduce((a, b) => a + b._qs, 0) / recent.length;
      const pa = prior.reduce((a, b) => a + b._qs, 0) / prior.length;
      const delta = ra - pa;
      if (delta > 5)       trend = '↑';
      else if (delta < -5) trend = '↓';
    }
  }
  const cls = _briefQualityClassify(avg);
  target.outerHTML = `<div id="fhp-brief-quality" class="fhp-row ${cls.cls}">
    ${cls.icon} <b>Brief Quality</b> avg ${Math.round(avg)} ${trend} · ${last14.length} archived
  </div>`;
}

function loadBriefQualityRow() {
  if (typeof renderBriefQualityRow !== 'function') return;
  const cacheKey = 'field_archive_brief_quality';
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const c = JSON.parse(cached);
      if (c && (Date.now() - (c.ts || 0)) < 1800000 && c.data) {
        renderBriefQualityRow(c.data);
        return;
      }
    }
  } catch(e) { captureFieldError('health-panel:brief-quality-cache-read', e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/query?brief_type=slate&source=cron&limit=14')
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      if (!data) return;
      try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch(e) { captureFieldError('health-panel:brief-quality-cache-write', e, true); }
      renderBriefQualityRow(data);
    })
    .catch(e => captureFieldError('health-panel:brief-quality-fetch', e, true));
}

// ── MOBILE-INTEL-A: Right Now Section (debounce fix 800b0e8) ──────────────
// Spec: 1mRtoeL7rOxnkaodTMml1PVgBOJD5XGE9sR3jik_kdpc (May 31 2026)
// Shows 1-2 hero cards for highest-drama live game(s) above the schedule.
// Viewport-aware: P1-P3 portrait + L2 landscape only. Hidden on iPad+.
// Brief sourced from relay KV (A312) — zero AI cost.
// Rule 28: tap -> openGameSheet() already exists. CLEAR.

function selectRightNowGames(sections) {
  // ADR-002 (H2): rank games by named tier, not composite drama + boost.
  const all = [];
  (sections || []).forEach(sec => {
    (sec.games || []).forEach(g => {
      const eData = typeof findESPNScore === 'function' ? findESPNScore(g) : null;
      const isLive = eData?.state === 'in';
      const tier = fieldGameTier(g._id);
      const rank = fieldTierRank(tier);
      all.push({ g, eData, isLive, tier, rank });
    });
  });

  if (!all.length) return [];

  // Sort: live first, then by tier rank desc (named-tier ordering).
  all.sort((a, b) => {
    if (a.isLive !== b.isLive) return a.isLive ? -1 : 1;
    return b.rank - a.rank;
  });

  // P1/P2/L2: 1 card. P3: up to 2 if both live AND second hits CLOSE_LATE+ tier.
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  const landscape = vw > vh;
  const isP3 = !landscape && vw >= 431 && vw <= 600;
  const top = all[0];
  if (!top) return [];

  // If no live and no upcoming games, return nothing
  const upcoming = all.filter(x => !x.isLive && (x.g.start_time > new Date().toISOString()));
  if (!top.isLive && !upcoming.length && all.every(x => !x.isLive)) {
    return [top];
  }

  const CLOSE_LATE_RANK = fieldTierRank('CLOSE_LATE');
  if (isP3 && all[1]?.isLive && (all[1]?.rank ?? 0) >= CLOSE_LATE_RANK) {
    return [top, all[1]];
  }
  return [top];
}

function buildRightNowTiers(g, eData) {
  const isLive = eData?.state === 'in';
  const home = g.home || '';
  const away = g.away || '';
  const homeScore = eData?.homeScore ?? '';
  const awayScore = eData?.awayScore ?? '';
  const series = g.seriesRecord && g.seriesRecord !== '0-0' ? g.seriesRecord : '';

  // Score display
  const scoreStr = isLive
    ? `${away} ${awayScore} · ${home} ${homeScore}`
    : `${away} @ ${home}`;

  // ADR-002 (C3): tier-gated badge, factual tier label, no raw drama number.
  const _rnTier = fieldGameTier(g._id);
  const _rnTense = _rnTier === 'CRUNCH' || _rnTier === 'EXTRA_TIME' || _rnTier === 'CLOSE_LATE';
  const dramaEl = _rnTense
    ? `<span class="drama-mini" style="background:rgba(201,168,76,.15);color:#c9a84c;border:1px solid rgba(201,168,76,.3);border-radius:4px;padding:.1rem .3rem;font-size:.55rem;font-weight:700">${fieldTierLabel(_rnTier)}</span>`
    : '';

  // Live badge
  const liveEl = isLive
    ? `<span style="background:#ef4444;color:#fff;border-radius:3px;padding:.1rem .3rem;font-size:.52rem;font-weight:700">LIVE</span>`
    : '';

  // Broadcast chip (first stream)
  const chipSR = (g.streams || [])[0];
  const chipEl = chipSR
    ? `<span class="stream-chip" style="font-size:.55rem;padding:.1rem .35rem">${chipSR}</span>`
    : '';

  // Clock/period
  const clockEl = isLive && eData?.clock
    ? `<span style="color:var(--smoke)">${eData.clock}${eData.period ? ' P' + eData.period : ''}</span>`
    : '';

  // Series / Scout's Pick chip
  const seriesEl = series
    ? `<span style="color:var(--gold2,#c9a84c);font-size:.55rem">${series}</span>`
    : (!isLive && typeof isScoutsPick === 'function' && isScoutsPick(g))
      ? `<span style="color:#2dd4bf;font-size:.55rem">🔍 Scout's Pick</span>`
      : '';

  // Brief from relay KV cache (A312)
  const brief = (_gameBriefCache && _gameBriefCache[g._id])
    ? _gameBriefCache[g._id].slice(0, 72)
    : '';

  const condensed = `
    <div class="rn-row1">${liveEl}<span>${scoreStr}</span>${dramaEl}</div>
    <div class="rn-row2">${chipEl}${seriesEl}</div>`;

  const standard = `
    <div class="rn-row1">${liveEl}<span>${scoreStr}</span>${dramaEl}</div>
    <div class="rn-row2">${clockEl}${chipEl}${seriesEl}</div>
    ${brief ? `<div class="rn-brief">${brief}</div>` : ''}`;

  const compact = `
    <div class="rn-row1">${liveEl}<span>${scoreStr}</span>${dramaEl}${chipEl}</div>`;

  return { condensed, standard, compact };
}

function renderRightNow(sections) {
  const container = document.getElementById('rn-cards');
  const label = document.getElementById('rn-label');
  if (!container) return;

  const selected = selectRightNowGames(sections);
  if (!selected.length) {
    container.innerHTML = '';
    return;
  }

  const hasLive = selected.some(x => x.isLive);
  if (label) label.textContent = hasLive ? 'RIGHT NOW' : 'UP NEXT';

  container.innerHTML = selected.map(({ g, eData }) => {
    const tiers = buildRightNowTiers(g, eData);
    const gameid = g._id || '';
    return `<div class="rn-card rn-card--condensed"
      data-gameid="${gameid}"
      data-rn-condensed="${tiers.condensed.replace(/"/g,'&quot;')}"
      data-rn-standard="${tiers.standard.replace(/"/g,'&quot;')}"
      data-rn-compact="${tiers.compact.replace(/"/g,'&quot;')}"
      role="button" tabindex="0"
      onclick="typeof openGameSheet==='function'&&openGameSheet('${gameid}')"
      onkeydown="event.key==='Enter'&&typeof openGameSheet==='function'&&openGameSheet('${gameid}')"
      aria-label="Game intel for ${(g.away||'').replace(/'/g,'')} at ${(g.home||'').replace(/'/g,'')}">
      ${tiers.condensed}
    </div>`;
  }).join('');

  // Mark featured game in schedule
  document.querySelectorAll('.game-card.rn-featured').forEach(c => c.classList.remove('rn-featured'));
  selected.forEach(({ g }) => {
    const card = document.querySelector(`.game-card[data-gameid="${g._id}"]`);
    if (card) card.classList.add('rn-featured');
  });

  indexRightNow();
}

function indexRightNow() {
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  const landscape = vw > vh;
  const isPhone = Math.min(vw, vh) <= 600;
  const isL2 = landscape && vw >= 700 && vw < 820;

  const tier = isL2 ? 'compact'
    : (!landscape && vw <= 430) ? 'condensed'
    : (!landscape && isPhone)   ? 'standard'
    : null; // hidden viewports

  if (!tier) return;

  const keyMap = { condensed: 'rnCondensed', standard: 'rnStandard', compact: 'rnCompact' };
  const key = keyMap[tier];

  document.querySelectorAll('.rn-card[data-rn-condensed]').forEach(card => {
    const html = card.dataset[key] || card.dataset.rnCondensed;
    if (html) card.innerHTML = html;
    card.className = `rn-card rn-card--${tier}`;
  });
}

function initRightNowIndexer() {
  // Inline debounce — debounce utility not globally available
  let _rnResizeT;
  window.addEventListener('resize', () => {
    clearTimeout(_rnResizeT);
    _rnResizeT = setTimeout(indexRightNow, 50);
  });
  if (screen?.orientation) {
    screen.orientation.addEventListener('change', () => requestAnimationFrame(indexRightNow));
  }
}

// renderMediaSpecialRightNow() — CC-CMD-2026-07-13-media-special-right-now.
// Promotes genuine single-day MEDIA_SPECIALS entries into #field-right-now,
// rendered into a separate #rn-special-cards container (never inside
// #rn-cards, which renderRightNow() fully overwrites on every call) so it
// coexists with whatever renderRightNow() already produces for real games
// — this file NEVER touches selectRightNowGames/buildRightNowTiers/
// renderRightNow to build this. Deliberately general, not an HRD-specific
// hack: any future single-day special (Opening Night, Field of Dreams Game,
// WBC openers, etc.) surfaces here unmodified, because the filter is a
// generic startDate===endDate===today check, not a name/show match.
// MEDIA_SPECIALS only carries date-level granularity (no precise start
// times), so "genuinely single-day" is the correct, already-available
// signal — a multi-week window (startDate !== endDate) never matches, even
// on a date that falls inside its range.
function renderMediaSpecialRightNow() {
  const container = document.getElementById('rn-special-cards');
  if (!container) return;
  const todayStr = TODAY_ISO;
  const matches = (typeof MEDIA_SPECIALS !== 'undefined' ? MEDIA_SPECIALS : [])
    .filter(s => s.startDate === s.endDate && s.startDate === todayStr);
  if (!matches.length) { container.innerHTML = ''; return; }

  // P3 2-card precedent, reused from selectRightNowGames: only the P3 phone-
  // portrait width (431-600px) allows a 2nd card. Specials have no live/tier
  // concept to gate a 2nd card on (unlike selectRightNowGames' isLive+rank
  // condition), so this mirrors only the viewport-conditional structure of
  // that precedent, not an invented, unrelated cap.
  const vw = window.innerWidth, vh = window.innerHeight;
  const landscape = vw > vh;
  const isP3 = !landscape && vw >= 431 && vw <= 600;
  const shown = matches.slice(0, isP3 ? 2 : 1);

  container.innerHTML = shown.map(s => {
    const c = s.card || {};
    const showEsc = (c.show || '').replace(/'/g, "\\'");
    return `<div class="rn-card rn-card--special"
      role="button" tabindex="0"
      onclick="typeof scrollToMediaSpecial==='function'&&scrollToMediaSpecial('${showEsc}')"
      onkeydown="event.key==='Enter'&&typeof scrollToMediaSpecial==='function'&&scrollToMediaSpecial('${showEsc}')"
      aria-label="${(c.show||'').replace(/"/g,'&quot;')} — tap for details">
      <div class="rn-row1"><span class="rn-special-badge">SPECIAL</span><span>${c.show||''}</span></div>
      <div class="rn-row2"><span>${c.network||''}</span><span>${c.time||''}</span></div>
    </div>`;
  }).join('');
}

// scrollToMediaSpecial(showName) — click-through target for the RIGHT NOW
// special-promotion card. #media-section lazy-renders on scroll-into-view
// (see the IntersectionObserver below), so a user tapping this card before
// ever scrolling that far would find no card in the DOM yet — force the
// real render first if needed, then scroll to the real, existing card.
// Never builds a second copy of the bracket/context UI up here.
function scrollToMediaSpecial(showName) {
  if (typeof mediaRendered !== 'undefined' && !mediaRendered && typeof renderMedia === 'function') {
    try { renderMedia(); mediaRendered = true; } catch(_e) { captureFieldError('surface:media-special-force-render', _e, true); }
  }
  const card = document.querySelector(`.media-card[data-show="${(showName||'').replace(/"/g,'&quot;')}"]`);
  const target = card || document.getElementById('media-section');
  if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

// ── Relay / CI status fetcher ─────────────────────────────────────────────
// Architectural correction (PM-19 retro): the prior implementation called
// the auth-gated /mcp endpoint on field-relay-nba and broke when
// FIELD_MCP_SECRET was deployed (HTTP 401). The right fix is NOT to embed
// the bearer token in client code (that defeats auth). The right fix is
// recognizing that get_ci_status and get_smoke_count are thin wrappers
// around PUBLIC GitHub data — so we fetch that data directly. The
// authenticated /mcp surface stays exclusively for claude.ai's connector.
//
// CORS verified June 2 2026: api.github.com returns ACAO:* on actions/runs,
// raw.githubusercontent.com returns ACAO:* on main-branch files. Both
// public-read with ~60 req/hr unauthenticated rate limit per IP, well
// above panel render frequency.
async function fetchMCPStatus() {
  const el = document.getElementById('fhp-mcp-body');
  if (!el) return;

  const RUNS_URL = 'https://api.github.com/repos/jeffunglesbee-create/jubilant-bassoon/actions/runs?per_page=3';
  const SMOKE_URL = 'https://raw.githubusercontent.com/jeffunglesbee-create/jubilant-bassoon/main/smoke.js';

  const row = (icon, label, val, col='#aaa') =>
    `<div style="display:flex;gap:.4rem;margin-bottom:.2rem">
       <span>${icon}</span>
       <span style="color:#777;min-width:80px">${label}</span>
       <span style="color:${col};font-weight:600">${val}</span>
     </div>`;

  try {
    // Parallel: CI runs + smoke source. Both public, no auth.
    const [runsResp, smokeResp] = await Promise.all([
      fetch(RUNS_URL, { headers: { 'Accept': 'application/vnd.github+json' }}),
      fetch(SMOKE_URL),
    ]);
    if (!runsResp.ok) throw new Error(`GitHub API HTTP ${runsResp.status}`);
    if (!smokeResp.ok) throw new Error(`raw.github HTTP ${smokeResp.status}`);

    const runs = await runsResp.json();
    const smokeSrc = await smokeResp.text();

    // Count smoke assertions by counting top-level assert( calls.
    // Regex anchored to start-of-line (with optional whitespace) to avoid
    // matching the word inside strings or comments.
    const smokeNum = (smokeSrc.match(/^\s*assert\(/gm) || []).length || '?';

    // Most recent 3 workflow runs across all workflow types
    const ciRows = (runs.workflow_runs || []).slice(0, 3).map(r => {
      const conclusion = r.conclusion || r.status || '?';
      const sha = (r.head_sha || '').slice(0, 7);
      const icon = conclusion === 'success' ? '✅' : conclusion === 'failure' ? '❌' : '🔄';
      const col  = conclusion === 'success' ? '#4caf82' : conclusion === 'failure' ? '#e05c5c' : '#c9a84c';
      const shortName = (r.name||'').replace('Smoke Test + Live Verify','Smoke').replace('FIELD Data','Data').replace('Cloudflare API Probe','CF Probe').replace('Deploy gate (fast smoke)','Deploy gate');
      return row(icon, shortName.slice(0,16), `${sha||'?'} · ${conclusion||'?'}`, col);
    }).join('');

    const smokeCol = parseInt(smokeNum) >= 300 ? '#4caf82' : '#c9a84c';

    el.innerHTML = `
      ${row('🧪', 'Smoke', `${smokeNum} assertions`, smokeCol)}
      <div style="margin-top:.25rem;color:#555;font-size:.52rem;margin-bottom:.2rem">Recent runs:</div>
      ${ciRows}
      <div style="margin-top:.35rem">
        <button onclick="fetchMCPStatus()"
          style="background:rgba(201,168,76,.15);border:1px solid #c9a84c;color:#c9a84c;
                 border-radius:5px;padding:.2rem .5rem;font-size:.55rem;cursor:pointer;font-family:monospace">
          ↻ Refresh
        </button>
        <span style="color:#444;font-size:.52rem;margin-left:.4rem">via GitHub API (public)</span>
      </div>`;
  } catch(e) {
    el.innerHTML = `<span style="color:#e05c5c">Relay/CI error: ${e.message}</span>
      <button onclick="fetchMCPStatus()"
        style="margin-left:.5rem;background:rgba(255,255,255,.05);border:1px solid #555;
               color:#888;border-radius:4px;padding:.15rem .4rem;font-size:.52rem;cursor:pointer">
        Retry
      </button>`;
  }
}

// ── Long-press trigger on settings button ─────────────────────────────────
// iOS iPad fix: touchstart with preventDefault() blocks text selection + context menu.
// 700ms fires before iOS context menu (~1000ms); contextmenu handler as belt+suspenders.
// -webkit-user-select:none on .settings-btn prevents text highlight on press.
window.addEventListener('load', () => {
  const settingsBtn = document.getElementById('settings-btn');
  if (!settingsBtn) return;
  let _longPressTimer = null;
  let _longPressFired = false;
  const _cancel = () => { clearTimeout(_longPressTimer); _longPressTimer = null; };

  // Use pointerdown/up/cancel universally — works on Android, iOS, and desktop.
  // pointerType: 'touch' on Android/iOS, 'mouse' on desktop, 'pen' on stylus.
  // DO NOT use e.preventDefault() on touchstart — it suppresses the click event
  // on Android Chrome, breaking the normal tap → openSetup flow entirely.
  // contextmenu handler below is sufficient to block Android long-press menu.
  settingsBtn.addEventListener('pointerdown', e => {
    _longPressFired = false;
    _longPressTimer = setTimeout(() => {
      _longPressFired = true;
      showFieldHealthPanel();
    }, 700);
  }, { passive: true });
  settingsBtn.addEventListener('pointerup',     _cancel);
  settingsBtn.addEventListener('pointerleave',  _cancel);
  settingsBtn.addEventListener('pointercancel', _cancel);

  // Block native context menu on long-press (Android + iOS)
  settingsBtn.addEventListener('contextmenu', e => e.preventDefault());

  // If long-press fired, suppress the subsequent click so openSetup doesn't
  // open on top of the health panel. Reset flag after click is consumed.
  settingsBtn.addEventListener('click', e => {
    if (_longPressFired) { _longPressFired = false; e.stopImmediatePropagation(); }
  }, true); // capture phase — fires before openSetup click handler
});

// ?debug=1 URL param still opens the panel
if (typeof location !== 'undefined' && location.search.includes('debug=1')) {
  window.addEventListener('load', () => setTimeout(showFieldHealthPanel, 800));
}

// ?tab=journal|groups — headless browser / automated viewport verification
// Activates the named tab after load without requiring a click. Safe to use
// in production: has no effect unless the param is present.
if (typeof location !== 'undefined') {
  const _tabParam = new URLSearchParams(location.search).get('tab');
  if (_tabParam === 'journal') {
    window.addEventListener('load', () => setTimeout(() => {
      if (typeof toggleJournalismView === 'function') toggleJournalismView();
    }, 800));
  } else if (_tabParam === 'groups') {
    window.addEventListener('load', () => setTimeout(() => {
      if (typeof toggleWCView === 'function') toggleWCView();
    }, 800));
  }
}

