// ── SR URL Debug Validator (FIELD_DEBUG mode only) ────────────────────────
// Implemented: May 11, 2026 (Session H — Hardcoded Data Optimization)
// Runs HEAD requests against all SR URLs on page load in FIELD_DEBUG mode.
// console.warn() for any non-200 response. Zero production impact.
// Catches broken stream links during dev sessions before users see them.
// Usage: localStorage.setItem('FIELD_DEBUG','1') then reload.
function validateSRUrls(){
  if(!FIELD_DEBUG) return;
  const entries = Object.entries(SR);
  let checked=0, warned=0;
  entries.forEach(([key,val])=>{
    const url = val[1];
    if(!url||!url.startsWith("http")) return;
    fetch(url,{method:"HEAD",mode:"no-cors",signal:AbortSignal.timeout(5000)})
      .then(()=>{ checked++; })
      .catch(e=>{
        warned++;
        console.warn("FIELD SR URL check failed ["+key+"]:", url, e.message||e);
      });
  });
  setTimeout(()=>{
    if(FIELD_DEBUG) console.debug("FIELD SR URL validator: "+entries.length+" entries checked. Errors logged above (if any).");
  }, 6000);
}
// Fire SR URL validator on load (no-op unless FIELD_DEBUG=1)
if(typeof window!=="undefined") window.addEventListener("load",()=>validateSRUrls(),{once:true});

// ── Runtime Silent Error Detector (FIELD_DEBUG mode only) ─────────────────
// Built: May 14, 2026 — detects content correctness failures the smoke test cannot.
// Complements field_audit.js (pre-edit) + field_smoke.js (post-edit structural).
// This runs LIVE in the browser against actual rendered DOM + allData source.
//
// Catches:
//   1. Missing cards — source game in allData with no rendered card
//   2. Phantom cards — rendered card with no matching source game
//   3. Chipless cards — game card with no stream chips rendered
//   4. confirmed:false cards — Layer 1 violation in live render
//   5. Placeholder "?" team names — validateGameEntry() fallback leaked
//   6. Stale cards — start_time >24hr past in live browser
//   7. Duplicate matchups — same home+away appearing twice
//   8. Section count mismatch — allData sections vs rendered sections
//   9. National bundle chip missing — nationalBundle key not reflected in card HTML
//
// Usage: localStorage.setItem('FIELD_DEBUG','1') → reload → open console.
// Output: console.group with ⚠ warnings and ✓ passes. Zero production impact.
// Runs after renderAll() with 500ms delay to let async injections settle.
//
// Does NOT run when a sport filter or team filter is active — filtering is
// intentional and would produce false positives for completeness checks.
function runSilentErrorScan(){
  if(!FIELD_DEBUG) return;
  if(activeFilter!=="all"||myTeamsFilter||freeOnlyFilter) return; // skip when filtered

  const main = document.getElementById("main");
  if(!main) return;

  const issues = [];
  const passes = [];
  const warn  = msg => issues.push("⚠ " + msg);
  const ok    = msg => passes.push("✓ " + msg);

  // Source truth: flatten all games from allData
  const allGames = (allData?.sports||[]).flatMap(s=>(s.games||[]).map(g=>({...g,_section:s.sport})));
  const cards = [...main.querySelectorAll(".game-card")];
  const sections = main.querySelectorAll(".sport-section");

  // ── CHECK 1: Completeness — every source game has a rendered card ─────────
  let missingCount = 0;
  allGames.forEach(g=>{
    const home = (g.home||"").replace(/"/g,"");
    if(!home) return; // unnamed tournament entries are fine
    const found = cards.some(c=>c.dataset.home===home);
    if(!found){ warn(`Missing card: "${home} vs ${g.away||""}" (${g._section})`); missingCount++; }
  });
  if(!missingCount) ok(`Completeness: all ${allGames.length} source games have a rendered card`);

  // ── CHECK 2: No phantom cards — rendered card must have a source game ─────
  let phantomCount = 0;
  cards.forEach(c=>{
    const home = c.dataset.home;
    if(!home) return;
    const found = allGames.some(g=>(g.home||"").replace(/"/g,"")===home);
    if(!found){ warn(`Phantom card: "${home} vs ${c.dataset.away}" — no matching source game (stale or dedup failure)`); phantomCount++; }
  });
  if(!phantomCount) ok(`No phantom cards (${cards.length} cards, all have source games)`);

  // ── CHECK 3: No chipless cards — every card must have ≥1 stream chip ──────
  let chiplessCount = 0;
  cards.forEach(c=>{
    const streamRow = c.querySelector(".stream-row");
    if(!streamRow) return;
    const hasChip = streamRow.querySelector(".stream-chip");
    const hasLocal = c.querySelector(".gotd-badge.local-cov"); // localRsn games
    if(!hasChip && !hasLocal){
      warn(`Chipless card: "${c.dataset.home} vs ${c.dataset.away}" (${c.dataset.sport}) — no stream chips rendered`);
      chiplessCount++;
    }
  });
  if(!chiplessCount) ok(`All ${cards.length} cards have stream chips or local RSN badge`);

  // ── CHECK 4: No confirmed:false cards ────────────────────────────────────
  const unconfirmed = cards.filter(c=>c.dataset.confirmed==="false");
  if(unconfirmed.length){
    unconfirmed.forEach(c=>warn(`Unconfirmed card: "${c.dataset.home} vs ${c.dataset.away}" — confirmed:false in live render`));
  } else {
    ok(`All ${cards.length} cards confirmed:true`);
  }

  // ── CHECK 5: No "?" placeholder team names ────────────────────────────────
  const placeholders = cards.filter(c=>c.dataset.home==="?"||c.dataset.away==="?");
  if(placeholders.length){
    placeholders.forEach(c=>warn(`Placeholder "?" team: "${c.dataset.home} vs ${c.dataset.away}" — validateGameEntry fallback leaked`));
  } else {
    ok(`No "?" placeholder team names`);
  }

  // ── CHECK 6: No stale cards in live browser ───────────────────────────────
  const now = Date.now();
  let staleCount = 0;
  cards.forEach(c=>{
    const t = new Date(c.dataset.starttime).getTime();
    if(!isNaN(t) && t < now - 86400000){
      warn(`Stale card: "${c.dataset.home}" start_time ${c.dataset.starttime} (>${Math.round((now-t)/3600000)}hr ago)`);
      staleCount++;
    }
  });
  if(!staleCount) ok(`No stale cards (all start_times within 24hr window)`);

  // ── CHECK 7: No duplicate matchups ────────────────────────────────────────
  const seenMatchups = new Set();
  let dupeCount = 0;
  cards.forEach(c=>{
    const key = `${c.dataset.home}|${c.dataset.away}`;
    if(seenMatchups.has(key) && c.dataset.home){
      warn(`Duplicate card: "${c.dataset.home} vs ${c.dataset.away}"`);
      dupeCount++;
    }
    seenMatchups.add(key);
  });
  if(!dupeCount) ok(`No duplicate matchups`);

  // ── CHECK 8: Section count matches allData ────────────────────────────────
  const sourceSections = (allData?.sports||[]).filter(s=>(s.games||[]).length>0).length;
  if(sections.length!==sourceSections){
    warn(`Section count: ${sections.length} rendered vs ${sourceSections} in allData — a section may have rendered empty or been suppressed`);
  } else {
    ok(`Section count: ${sections.length} matches allData (${sourceSections} sections)`);
  }

  // ── CHECK 9: National bundle chip verification ─────────────────────────────
  const BUNDLE_CHIP_MAP = {
    MLB_TBS:"TBS", MLB_FOX:"FOX", MLB_FS1:"FS1",
    MLB_APPLE:"Apple TV+", MLB_NBC:"NBC", MLB_PEACOCK_SNB:"Peacock",
    MLB_LEADOFF:"Peacock", MLB_PEACOCK_GOTD:"Peacock",
    NBA_ESPN:"ESPN", NBA_ABC:"ABC", NBA_NBC:"NBC", NBA_PRIME:"Prime Video",
    NHL_TNT:"TNT", NHL_ESPN:"ESPN", NHL_ABC:"ABC", NHL_NBC:"NBC",
    MLS_FS1:"FS1", MLS_FOX:"FOX",
    EPL_PEACOCK:"Peacock", EPL_NBC:"NBC", EPL_ESPN:"ESPN",
    EFL_PLAYOFF:"Paramount+",
    TENNIS_TC:"Tennis Channel", TENNIS_FO:"TNT",
    GOLF_CBS:"CBS", GOLF_NBC:"NBC",
    WC26_FOX:"FOX", WC26_FS1:"FS1", WC26_FREE:"FOX/Tubi FREE",
    UFL_FOX:"FOX", UFL_FS1:"FS1", UFL_ABC:"ABC", UFL_ESPN:"ESPN", UFL_ESPN2:"ESPN2", UFL_NFLN:"NFL Network",
  };
  let badChipCount = 0;
  allGames.forEach(g=>{
    if(!g.nationalBundle) return;
    const expectedText = BUNDLE_CHIP_MAP[g.nationalBundle];
    if(!expectedText) return;
    const home = (g.home||"").replace(/"/g,"");
    const card = cards.find(c=>c.dataset.home===home);
    if(!card) return; // caught by Check 1
    if(!card.innerHTML.includes(expectedText)){
      warn(`Bundle chip mismatch: "${home}" has nationalBundle "${g.nationalBundle}" but chip "${expectedText}" not found in card`);
      badChipCount++;
    }
  });
  if(!badChipCount) ok(`National bundle chips verified`);

  // ── REPORT ────────────────────────────────────────────────────────────────
  const label = issues.length===0
    ? `[FIELD SCAN] ✓ CLEAN — ${cards.length} cards · ${sections.length} sections · 0 issues`
    : `[FIELD SCAN] ⚠ ${issues.length} ISSUE(S) — ${cards.length} cards · ${sections.length} sections`;

  console.group(label);
  if(issues.length===0){
    if(FIELD_DEBUG) console.log("All 9 runtime checks passed. No silent errors detected.");
    if(FIELD_DEBUG) passes.forEach(p=>console.debug(p));
  } else {
    issues.forEach(w=>console.warn(w));
    if(FIELD_DEBUG) console.log(`— ${passes.length} checks passed, ${issues.length} issue(s) above need attention`);
  }
  console.groupEnd();
}
// ─────────────────────────────────────────────────────────────────────────────

// Expand array of SR keys → stream objects {name, url, col, auth, authNote}
function expandStreams(keys){
  return (keys||[]).map(k=>{
    const s=SR[k];
    return s?{key:k,label:s[0],name:s[0],url:s[1],col:s[2],auth:s[3]||"sub",authNote:s[4]||"Subscription required"}:null;
  }).filter(Boolean);
}

