function validateBundles(games, sourceName){
  if(!games||!FIELD_DEBUG) return;
  games.forEach(g=>{
    const key = Array.isArray(g.streams) && g.streams.length && typeof g.streams[0]==='string'
      ? g.streams[0] : g.nationalBundle;
    if(key && typeof key==='string' && !VALID_BUNDLE_KEYS.has(key) && !VALID_NATIONAL_BUNDLES.has(key)){
      console.warn(`[FIELD AUDIT] Unknown bundle "${key}" in ${sourceName}: ${g.home||'?'} vs ${g.away||'?'}`);
    }
  });
}
