// Resolve game streams: accepts bundle key string, key array, or legacy object array
function resolveStreams(streams){
  if(!streams||!streams.length) return [];
  if(typeof streams[0]==="string") return resolveBundle(streams[0]);
  // Legacy object array: {name, url} — enrich with SR data
  return streams.map(s=>{
    const sr=Object.values(SR).find(r=>r[0]===s.name);
    return {...s,col:sr?.[2]||"#888",auth:sr?.[3]||"sub",authNote:sr?.[4]||"Subscription required"};
  });
}

// MLB broadcaster: pre-computed from TODAY_DOW — zero per-game date parsing
function mlbBundle(){
  // Verified 2026 MLB broadcast windows — default for untagged games
  // National windows only apply to specifically assigned games.
  // Most games on any day air only on local RSNs → MLB_LOCAL
  if(TODAY_DOW===0) return "MLB_LOCAL";  // Sunday: SNB+Leadoff explicitly tagged; all other games local RSN
  if(TODAY_DOW===2) return "MLB_LOCAL";  // Tuesday: one TBS exclusive (explicitly tagged); rest are local
  if(TODAY_DOW===5) return "MLB_LOCAL";  // Friday: 2 Apple TV+ games explicitly tagged; rest are local
  if(TODAY_DOW===6) return "MLB_LOCAL";  // Saturday: most games are local RSN; FOX/FS1 games are explicitly tagged
  // Mon/Wed/Thu/other: ESPN has select dates only (30 games total, not weekly)
  // Default to MLB_LOCAL; espnGOTD flag handles ESPN Unlimited chip separately
  return "MLB_LOCAL";
}
const MLB_BUNDLE = mlbBundle();

function mlbStreams(){ return resolveBundle(MLB_BUNDLE); }

