function gameHasFreeStream(g){
  if(!g||!g.streams||!g.streams.length) return false;
  for(const stream of g.streams){
    const key = typeof stream === "string" ? stream : (stream.key||stream.srKey||"");
    if(!key) continue;
    const sr = SR[key];
    if(sr && sr[3] === "free") return true;
  }
  return false;
}
