// ── localStorage prune (Decision 10) — must run before any localStorage reads ──
// Prevents QuotaExhaustedError on PWA init. 7-day TTL on field_brief_* keys.
// Required before Wow#29 streak milestone badges ship additional localStorage keys.
(function pruneOldFieldData(){
  try{
    const cutoff = Date.now() - 7*24*60*60*1000;
    Object.keys(localStorage)
      .filter(k => k.startsWith('field_brief_'))
      .forEach(k => {
        try{
          const item = JSON.parse(localStorage.getItem(k));
          if(!item || !item.timestamp || item.timestamp < cutoff) localStorage.removeItem(k);
        }catch(e){ localStorage.removeItem(k); }
      });
    // ── Standings velocity history: prune snapshots older than 14 days ─
    Object.keys(localStorage)
      .filter(k => k.startsWith('field_standings_history_'))
      .forEach(k => {
        try{
          const hist = JSON.parse(localStorage.getItem(k) || '[]');
          const last = hist[hist.length - 1];
          if (!last || (Date.now() - new Date(last.date).getTime()) > 14*24*60*60*1000)
            localStorage.removeItem(k);
        }catch(e){ localStorage.removeItem(k); }
      });
    // ── Drama arc cleanup: clear history older than 7 days ────────────
    Object.keys(localStorage)
      .filter(k => k.startsWith('field_drama_history_'))
      .forEach(k => {
        try{
          const hist = JSON.parse(localStorage.getItem(k) || '[]');
          const lastT = hist[hist.length - 1]?.t || 0;
          if (!lastT || lastT < cutoff) localStorage.removeItem(k);
        }catch(e){ localStorage.removeItem(k); }
      });
  }catch(e){}
})();

const today = new Date();
// date-display element removed — date shown in date-label button instead
const isoDate = today.getFullYear()+'-'+String(today.getMonth()+1).padStart(2,'0')+'-'+String(today.getDate()).padStart(2,'0');

// ── Delta15 — 15-day rolling localStorage pruner ──────────────────────────────
// Runs once per day at startup. Removes stale cache keys to prevent quota errors
// and cache-poisoning from old game entries. Never touches user preferences.
//
// Covers:
//   field_brief_*, field_drama_history_* — timestamp-based TTL
//   field_drama_peak_* — plain numbers, cheap to regenerate, always prune
//   field_game_notes_*  — plain strings, cheap to regenerate (P1-P4 stack)
//   Any key with embedded YYYY-MM-DD older than 15 days
//
// NEVER prunes (user preferences + permanent state):
//   field_ios_prompt_dismissed · field_free_only · field_my_services
//   field_setup_done · FIELD_USAGE_DATE · field_ios_visit_count
(function delta15(){
  try{
    if(localStorage.getItem('field_delta15_'+isoDate)) return; // already ran today
    const cutoff=Date.now()-15*24*60*60*1000;
    const KEEP=new Set([
      'field_ios_prompt_dismissed','field_free_only','field_my_services',
      'field_setup_done','FIELD_USAGE_DATE','field_ios_visit_count',
      'field_usage_date','field_my_teams'
    ]);
    let pruned=0;
    Object.keys(localStorage).forEach(k=>{
      if(KEEP.has(k)||k.startsWith('field_delta15_')) return;
      // Any key with an embedded YYYY-MM-DD date older than 15 days
      const dm=k.match(/(\d{4}-\d{2}-\d{2})/);
      if(dm&&new Date(dm[1]).getTime()<cutoff){localStorage.removeItem(k);pruned++;return;}
      // Keys with stored JSON containing a timestamp/fetchedAt field
      if(k.startsWith('field_brief_')||k.startsWith('field_drama_history_')){
        try{
          const v=JSON.parse(localStorage.getItem(k)||'{}');
          const ts=v.timestamp||v.fetchedAt||v.t||0;
          if(!ts||ts<cutoff){localStorage.removeItem(k);pruned++;}
        }catch(e){localStorage.removeItem(k);pruned++;}
        return;
      }
      // Drama peaks: plain numbers, no timestamp — cheap to regenerate
      if(k.startsWith('field_drama_peak_')){localStorage.removeItem(k);pruned++;return;}
      // Game notes: plain strings from P1-P4 stack — regenerate on next view
      if(k.startsWith('field_game_notes_')){localStorage.removeItem(k);pruned++;return;}
      // Night Owl / series brief cache entries
      if(k.startsWith('field_night_owl_')||k.startsWith('field_series_brief_')){
        try{
          const v=JSON.parse(localStorage.getItem(k)||'{}');
          const ts=v.timestamp||v.fetchedAt||0;
          if(!ts||ts<cutoff){localStorage.removeItem(k);pruned++;}
        }catch(e){localStorage.removeItem(k);pruned++;}
        return;
      }
    });
    // Self-clean old run markers (keep only today's)
    Object.keys(localStorage)
      .filter(k=>k.startsWith('field_delta15_')&&k!=='field_delta15_'+isoDate)
      .forEach(k=>localStorage.removeItem(k));
    localStorage.setItem('field_delta15_'+isoDate,'1');
    if(typeof FIELD_DEBUG!=='undefined'&&FIELD_DEBUG)
      console.log('[Delta15] pruned',pruned,'stale localStorage keys');
  }catch(e){}
})();

// ── Time helpers ─────────────────────────────────────────────
// ── Canonical timezone (PM-19 retro — TZ data-integrity fix) ────────────
// FIELD is ET-anchored: MLB/NBA/NHL schedules are published in ET, game IDs
// stamped with ET dates, cache keys keyed by ET date. The previous localTz()
// returned the browser's resolved TZ, which leaks UTC (or any non-US zone)
// into date-key generation. Night games past ~6pm PT / 9pm ET would generate
// wrong YYYYMMDD stamps under UTC, causing apparent schedule slips and
// orphaned cache keys.
//
// Policy: accept only America/* zones from the browser (so a user in PT or
// CT still gets their proper local zone for display); fall back to ET for
// UTC, Europe/*, Asia/*, or undefined. For date-key generation specifically,
// ALWAYS use FIELD_TZ regardless of user location — the schedule itself is
// ET-anchored and the keys must match.
const FIELD_TZ = 'America/New_York';
function localTz(){
  try {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
    return tz && tz.startsWith('America/') ? tz : FIELD_TZ;
  } catch { return FIELD_TZ; }
}
// Canonical ET-anchored date key (YYYY-MM-DD). Use for: MLB game IDs,
// schedule fetch URLs, sessionStorage brief keys, anywhere a "what day is
// it for FIELD?" answer is needed.
function fieldDateKey(d){
  return (d instanceof Date ? d : (d ? new Date(d) : new Date()))
    .toLocaleDateString('en-CA', { timeZone: FIELD_TZ });
}

// ── fieldNowET: Temporal-inspired timezone-aware date helpers ────────────
// Replaces hardcoded UTC offset math (e.g. `Date.now() - 4*3600*1000`)
// with DST-correct Intl.DateTimeFormat. Handles EDT→EST transitions
// automatically. Zero dependencies.
//
// Returns {date, year, month, day, hour, minute} in FIELD_TZ.
// date is YYYY-MM-DD (same format as fieldDateKey).
function fieldNowET() {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: FIELD_TZ,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', hour12: false,
  });
  const parts = {};
  fmt.formatToParts(new Date()).forEach(p => { parts[p.type] = p.value; });
  return {
    date: `${parts.year}-${parts.month}-${parts.day}`,
    year: parseInt(parts.year),
    month: parseInt(parts.month),
    day: parseInt(parts.day),
    hour: parseInt(parts.hour === '24' ? '0' : parts.hour),
    minute: parseInt(parts.minute),
  };
}

// Returns {dates, etDate, utcDate, etHour} for V2 polling.
// Eliminates the hardcoded -4h offset that would break during EST.
// dates: array of YYYY-MM-DD to query (deduped).
// Evening expansion: after 4 PM ET, adds tomorrow UTC to catch
// US evening games crossing the UTC midnight boundary.
function fieldDatesToQuery() {
  const et = fieldNowET();
  const utcDate = new Date().toISOString().slice(0, 10);
  const etDate = et.date;
  const dates = utcDate === etDate ? [utcDate] : [etDate, utcDate];
  if (et.hour >= 16) {
    const tomorrow = new Date(Date.now() + 24 * 3600 * 1000).toISOString().slice(0, 10);
    if (!dates.includes(tomorrow)) dates.push(tomorrow);
  }
  return { dates, etDate, utcDate, etHour: et.hour };
}

// Format an ISO timestamp to user's selected timezone (ET, local, or custom)
function fmtTime(iso){
  const tz = selectedTz==="local"?localTz():selectedTz;
  return new Date(iso).toLocaleTimeString('en-US',{timeZone:tz,hour:'numeric',minute:'2-digit',hour12:true});
}
// PM-19 retro: state-aware card time slot. Pre-game shows start time; live shows
// compact score+period; final shows final score; live-without-eData shows "LIVE".
// Replaces the prior "always show start_time" approach which left stale 8:00 PM
// labels on game cards that had been in P2 for an hour.
function buildCardTimeDisplay(isLive, eData, timeStr, startTimeISO) {
  // PM-20 Step 5: confidence glyph derived from eData.confidence (set by findScore)
  // verified -> '✓' (both sources agree), mismatch -> '⚠' (sources differ),
  // single   -> '' (no badge — current state), undefined/null -> '' (legacy)
  const conf = eData?.confidence;
  const glyph = conf === 'verified' ? ' ✓'
              : conf === 'mismatch' ? ' ⚠'
              : '';
  // Final: replace stale timeStr with final score + F marker
  if (eData?.state === 'post' && (eData.homeScore != null || eData.awayScore != null)) {
    const a = eData.awayScore ?? '–';
    const h = eData.homeScore ?? '–';
    return `${a}–${h} F${glyph}`;
  }
  if (!isLive) return timeStr;
  // Live with ESPN data: compact score + period (away–home; matches ticker convention)
  if (eData && (eData.homeScore != null || eData.awayScore != null)) {
    const a = eData.awayScore ?? '–';
    const h = eData.homeScore ?? '–';
    const pp = eData.periodPrefix || 'P';
    const period = eData.period ? `${pp}${eData.period}` : '';
    return `${a}–${h}${period ? ' ' + period : ''}${glyph}`;
  }
  // Live, no scoreboard data: score-tbd only in first 10min (genuine pre-score window)
  // After 10min without data: empty string. The .live-badge (red dot + LIVE)
  // attached to the card already says LIVE — this slot returning "LIVE" too
  // was the third stacked LIVE indicator (with .live-badge + drama-badge).
  if (startTimeISO) {
    const minsIn = (Date.now() - new Date(startTimeISO)) / 60000;
    if (minsIn >= 0 && minsIn < 10) return '<span class="score-tbd" aria-label="Score pending"></span>';
  }
  return '';
}
function getStatus(iso, opts){
  if(!iso) return "upcoming";
  // If caller passes completion signal, respect it over time-based guess
  if(opts && opts.aflComplete !== undefined){
    if(opts.aflComplete >= 100) return "upcoming"; // complete=100 → finished, card goes post
    if(opts.aflComplete > 0)    return "live";     // in progress
    // complete=0 → fall through to time-based
  }
  const diff=(new Date(iso)-Date.now())/60000; // negative = game has started
  if(diff<0&&diff>-210) return "live";   // started within last 3.5hrs → likely still live
  if(diff<0) return "upcoming";          // started > 3.5hrs ago → treat as finished/upcoming
  if(diff<=30) return "soon";            // starts within 30 min → soon
  return "upcoming";
}
// localDayHour removed — mlbStreams now uses pre-computed TODAY_DOW
// mlbStreams defined in SR block above. nhlStreams removed
// (CC-CMD-2026-07-15-never-adopted-utilities-disposal): its TNT/ESPN-
// alternating-by-game# assumption never matched the real 2026 Stanley
// Cup Final broadcast deal (all-ABC, confirmed via the hardcoded G1-G6
// entries below, each resolveBundle("NHL_ABC") directly) -- zero real
// callers, and the 2026 NHL postseason already concluded June 14.

// ── UI Primitives (CC-CMD-2026-07-18-debrief-phase1-primitives) ──
// Five standalone primitives every surface in the app composes from.
// Spec: Drive doc 1cWgNEs3uanFh_PDi2ISSrIBTINdousbHcE1VQphvZ2I Part 2.
// Not yet wired into existing surfaces — that is Phase 2 (Schedule Compound).

// Primitive 1: fieldChip(text, tier, opts)
// Tier color mapping verified against COLOUR-SYS-A tokens in index.html:
//   #ef4444 = --angle-elim  #f59e0b = --caution  #2dd4bf = --access-free
//   #60a5fa = --sport-nhl
function fieldChip(text, tier, opts = {}) {
  const el = document.createElement('span');
  el.className = 'field-chip field-chip--' + tier;
  el.textContent = text;
  if (opts.icon) el.dataset.icon = opts.icon;
  if (opts.small) el.classList.add('field-chip--sm');
  return el;
}

// Primitive 2: card slot template + fillSlot(card, name, content)
// cardTemplate is used by Phase 2 (Schedule Compound) renderCard().
// The data-slot="debrief" slot is reserved for Phase 3 (The Debrief).
const _cardTemplate = (() => {
  const t = document.createElement('div');
  t.className = 'game-card';
  t.innerHTML = `
    <div class="card-stripe" data-slot="stripe"></div>
    <div class="card-header">
      <span data-slot="time-score"></span>
      <span data-slot="drama" hidden></span>
    </div>
    <div class="card-body">
      <span data-slot="home-name"></span>
      <span data-slot="away-name"></span>
      <span data-slot="series" hidden></span>
    </div>
    <div class="card-streams">
      <span data-slot="bundle"></span>
      <span data-slot="crew" hidden></span>
    </div>
    <div class="card-enrichment" data-slot="enrichment" hidden></div>
    <div class="card-brief" data-slot="brief" hidden></div>
    <div class="card-debrief" data-slot="debrief" hidden></div>
    <div class="card-conflict" data-slot="conflict" hidden></div>
  `;
  return t;
})();

function fillSlot(card, name, content) {
  const slot = card.querySelector(`[data-slot="${name}"]`);
  if (!slot) return;
  if (content == null || content === '') {
    slot.hidden = true;
  } else if (typeof content === 'string') {
    slot.textContent = content;
    slot.hidden = false;
  } else if (content instanceof Element) {
    slot.replaceChildren(content);
    slot.hidden = false;
  }
}

// Primitive 3: fieldSection(title, opts)
function fieldSection(title, opts = {}) {
  const section = document.createElement('section');
  section.className = 'field-section';
  if (opts.collapsible) section.classList.add('field-section--collapsible');

  const header = document.createElement('header');
  header.className = 'field-section__header';
  const h3 = document.createElement('h3');
  h3.className = 'field-section__title';
  h3.textContent = title;
  header.appendChild(h3);
  if (opts.count != null) header.appendChild(fieldChip(String(opts.count), 'QUIET', { small: true }));
  if (opts.badge) h3.after(opts.badge);
  if (opts.collapsible) {
    header.style.cursor = 'pointer';
    header.addEventListener('click', () => section.classList.toggle('collapsed'));
  }

  const content = document.createElement('div');
  content.className = 'field-section__content';

  section.append(header, content);
  section._content = content;
  return section;
}

// Primitive 4: fieldState(status, content)
// status: 'loading' | 'empty' | 'partial' | 'ready' | 'error'
function fieldState(status, content) {
  const wrapper = document.createElement('div');
  wrapper.className = 'field-state field-state--' + status;

  if (status === 'loading') {
    const pulse = document.createElement('div');
    pulse.className = 'field-state__pulse';
    wrapper.appendChild(pulse);
  } else if (status === 'empty') {
    const msg = document.createElement('span');
    msg.className = 'field-state__empty';
    msg.textContent = 'No data yet';
    wrapper.appendChild(msg);
  } else if (status === 'partial') {
    if (content) wrapper.appendChild(content);
    wrapper.appendChild(fieldChip('partial', 'QUIET', { small: true }));
  } else if (status === 'ready') {
    if (content) wrapper.appendChild(content);
  }
  // status === 'error' → return empty wrapper (silent per fire-and-forget)

  return wrapper;
}

// Primitive 5: fieldRow(label, value, opts)
function fieldRow(label, value, opts = {}) {
  const row = document.createElement('div');
  row.className = 'field-row';

  const labelEl = document.createElement('span');
  labelEl.className = 'field-row__label';
  labelEl.textContent = label;

  const valueEl = document.createElement('span');
  valueEl.className = 'field-row__value';
  valueEl.textContent = value;

  if (opts.trend === 'up') valueEl.classList.add('field-row__value--up');
  if (opts.trend === 'down') valueEl.classList.add('field-row__value--down');
  if (opts.chip) row.appendChild(opts.chip);

  row.append(labelEl, valueEl);
  return row;
}

// ── Schedule Compound (CC-CMD-2026-07-18-debrief-phase2-schedule-compound) ──
// Phase 2 of 3. Builds on Phase 1 UI Primitives. Phase 3 (The Debrief) depends
// on this. renderCard/updateCard are STAGED for Phase 3 use — they are called
// by The Debrief rendering path once assembleDebrief/fillDebriefSlots are built.
// buildEnrichedGame and shouldShowCard are wired into renderAll and renderESPNScores.

// STAGED: renderCard called by Phase 3 (The Debrief rendering)
// STAGED: updateCard called by Phase 3 and eventually by renderESPNScores once
//         renderAll-produced cards carry data-slot attributes (full compound migration)
// STAGED journalism brief wiring (path 3): brief injection uses .card-brief-inline
//         class elements, not data-slot attrs. Requires renderCard to replace renderAll
//         card generation before fillSlot-based wiring is possible.

function buildEnrichedGame(rawGame, sources) {
  const _src = sources || {};
  const espnScore = _src.espnScore !== undefined
    ? _src.espnScore
    : (typeof findESPNScore === 'function' ? findESPNScore(rawGame) : null);
  const _ctx  = _src.contextGame ?? null;
  const _ctxG = _ctx?.game ?? null;
  return {
    // Identity
    _id:            rawGame._id,
    home:           rawGame.home            || '',
    away:           rawGame.away            || '',
    league:         rawGame.league          || '',
    _sport:         rawGame._sport          || '',
    // Time / state
    start_time:     rawGame.start_time      || '',
    state:          espnScore ? (espnScore.state ?? rawGame.state ?? null) : (rawGame.state ?? null),
    status:         rawGame.status          ?? null,
    _aflComplete:   rawGame._aflComplete,
    // Live scores (ESPN overlay merged over raw)
    homeScore:      espnScore ? (espnScore.homeScore ?? rawGame.homeScore ?? null) : (rawGame.homeScore ?? null),
    awayScore:      espnScore ? (espnScore.awayScore ?? rawGame.awayScore ?? null) : (rawGame.awayScore ?? null),
    period:         espnScore ? (espnScore.period    ?? null) : null,
    clock:          espnScore ? (espnScore.clock     ?? null) : null,
    // Broadcast / streams
    streams:        rawGame.streams         || null,
    gotdStreams:    rawGame.gotdStreams      || null,
    crew:           rawGame.crew            || '',
    espnGOTD:       rawGame.espnGOTD        || false,
    peacockGOTD:    rawGame.peacockGOTD     || false,
    mlbnShowcase:   rawGame.mlbnShowcase    || false,
    localNote:      rawGame.localNote       || '',
    // Context
    venue:          rawGame.venue           || '',
    seriesRecord:   rawGame.seriesRecord    || '',
    narrative:      rawGame.narrative       || null,
    _gameImportance: rawGame._gameImportance || '',
    _importanceIcon: rawGame._importanceIcon || '',
    wp:             rawGame.wp              ?? null,
    // Analytics
    _insights:      rawGame._insights       || null,
    confirmed:      rawGame.confirmed       === true,
    // Debrief — populated from Context Graph when contextGame source is provided
    debrief: {
      dramaSealed:  _ctxG?.drama_peak         ?? null,
      dramaArc:     _ctxG?.drama_arc_parsed   ?? null,
      oddsOutcome:  _ctxG?.opening_odds_parsed ? {
        opening:    _ctxG.opening_odds_parsed,
        closing:    _ctxG.closing_odds_parsed  ?? null,
        homeScore:  _ctxG.home_score           ?? null,
        awayScore:  _ctxG.away_score           ?? null,
        home:       _ctxG.home                 ?? rawGame.home ?? '',
        away:       _ctxG.away                 ?? rawGame.away ?? '',
        wentToOT:   !!_ctxG.went_to_ot,
      } : null,
      preGameBrief: (_ctx?.archive?.gameBriefs?.[0]?.brief_text) ?? (_src.journalismBrief ?? null),
      seriesArc:    _ctx?.series               ?? null,
      bracketDelta: _ctx?.bracketDelta         ?? null,
    },
    // Pass-throughs for downstream consumers
    _raw:       rawGame,
    _espnScore: espnScore,
  };
}

// STAGED — called by Phase 3 (The Debrief). Renders a slot-based card DOM element
// using Phase 1's _cardTemplate and fillSlot. Not yet wired into renderAll's main
// schedule render path (that migration requires a dedicated Phase 2b session once
// renderAll card feature-parity is established in the slot model).
function renderCard(enrichedGame, sport) {
  const card = _cardTemplate.cloneNode(true);
  card.dataset.gameid = enrichedGame._id || '';
  card.dataset.sport  = sport || enrichedGame._sport || '';
  card.dataset.home   = (enrichedGame.home || '').replace(/"/g, '');
  card.dataset.away   = (enrichedGame.away || '').replace(/"/g, '');

  const isLive  = enrichedGame.state === 'in' || enrichedGame.state === 'live' ||
                  enrichedGame.state === 'halftime';
  const isFinal = typeof isGameOver === 'function'
    ? isGameOver(enrichedGame._raw || enrichedGame)
    : (enrichedGame.state === 'post');
  if (isLive)  card.classList.add('live');
  if (isFinal) card.classList.add('is-final');

  // time-score: live/final score line or formatted start time
  const _scoreText = (isLive || isFinal) && enrichedGame.homeScore != null
    ? `${enrichedGame.away} ${enrichedGame.awayScore ?? ''} – ${enrichedGame.homeScore ?? ''} ${enrichedGame.home}`
    : (typeof fmtTime === 'function' ? fmtTime(enrichedGame.start_time) : enrichedGame.start_time);
  fillSlot(card, 'time-score', _scoreText);

  fillSlot(card, 'home-name', enrichedGame.home || null);
  fillSlot(card, 'away-name', enrichedGame.away || null);

  const _sr = enrichedGame.seriesRecord;
  fillSlot(card, 'series', (_sr && _sr !== '0-0') ? _sr : null);

  if (enrichedGame.streams && enrichedGame.streams.length) {
    const _bundleEl = document.createElement('span');
    _bundleEl.textContent = enrichedGame.streams[0]?.key || enrichedGame.streams[0] || '';
    fillSlot(card, 'bundle', _bundleEl);
  }

  fillSlot(card, 'crew', enrichedGame.crew || null);

  // debrief slot — Phase 3: buildDebrief assembles Layers 1-4 into an Element
  fillSlot(card, 'debrief', buildDebrief(enrichedGame));

  return card;
}

// STAGED — called by Phase 3 and future renderESPNScores once cards have data-slot attrs.
// Updates only changed slots in a renderCard-produced card element.
function updateCard(cardEl, enrichedGame) {
  if (!cardEl || !enrichedGame) return;

  const isLive  = enrichedGame.state === 'in' || enrichedGame.state === 'live' ||
                  enrichedGame.state === 'halftime';
  const isFinal = typeof isGameOver === 'function'
    ? isGameOver(enrichedGame._raw || enrichedGame)
    : (enrichedGame.state === 'post');

  // time-score slot (only exists in renderCard-produced cards)
  if (cardEl.querySelector('[data-slot="time-score"]')) {
    const _scoreText = (isLive || isFinal) && enrichedGame.homeScore != null
      ? `${enrichedGame.away} ${enrichedGame.awayScore ?? ''} – ${enrichedGame.homeScore ?? ''} ${enrichedGame.home}`
      : (typeof fmtTime === 'function' ? fmtTime(enrichedGame.start_time) : enrichedGame.start_time);
    fillSlot(cardEl, 'time-score', _scoreText);
  }

  // debrief slot — Phase 3; no-op if null (keeps slot hidden)
  fillSlot(cardEl, 'debrief', enrichedGame.debrief && enrichedGame.debrief.dramaSealed
    ? String(enrichedGame.debrief.dramaSealed) : null);

  // State class sync
  cardEl.classList.toggle('live',     isLive);
  cardEl.classList.toggle('is-final', isFinal);
}

// ── Phase 3b: The Debrief — Layer functions ──────────────────────────────────

// Layer 1: Drama Unsealed — horizontal bar + tier chip + arc-derived duration
// buildDramaUnsealed, buildFieldWasWatching, buildOddsStory, buildSeriesArc,
// buildBracketDeltaLayer, buildDebrief extracted to src/debrief/index.ts (Phase 4 — Debrief domain).

// Session-level cache for Context Graph responses (final games are immutable)
const _debriefContextCache = new Map();

// Post-render pass: replaces string-rendered final-game cards with DOM cards via
// renderCard (which wires the debrief slot). Fires ~600ms after every renderAll.
// Fetches Context Graph per final game, cached after first fetch.
async function injectDebriefCards() {
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  const cards = Array.from(
    document.querySelectorAll('.game-card[data-gameid]:not([data-debrief-injected])')
  );
  await Promise.allSettled(cards.map(async cardEl => {
    if (!cardEl.isConnected) return;
    const gameId = cardEl.dataset.gameid;
    let rawGame = null, sport = '';
    for (const s of (allData?.sports || [])) {
      const g = (s.games || []).find(g => g._id === gameId);
      if (g) { rawGame = g; sport = s.sport; break; }
    }
    if (!rawGame || (typeof isGameOver === 'function' && !isGameOver(rawGame))) return;
    const contextId = rawGame._gameId || gameId;
    try {
      let ctx = _debriefContextCache.get(contextId);
      if (!ctx) {
        // Gap 12: cache-first read from field-debriefs Cache API
        const _debriefCacheKey = `https://field-local/debrief/${encodeURIComponent(contextId)}`;
        try {
          if (typeof caches !== 'undefined') {
            const _dc = await caches.open('field-debriefs');
            const _hit = await _dc.match(_debriefCacheKey);
            if (_hit) { ctx = await _hit.json(); _debriefContextCache.set(contextId, ctx); }
          }
        } catch(_) {}
        if (!ctx) {
          const r = await fetch(`${base}/context/game/${encodeURIComponent(contextId)}`,
            { signal: AbortSignal.timeout(8000) });
          if (!r.ok) return;
          ctx = await r.json();
          _debriefContextCache.set(contextId, ctx);
          // Gap 12: write to Cache API with timestamp for 7-day eviction
          try {
            if (typeof caches !== 'undefined') {
              const _dc = await caches.open('field-debriefs');
              await _dc.put(_debriefCacheKey, new Response(JSON.stringify(ctx), {
                headers: { 'Content-Type': 'application/json', 'X-Cache-Time': String(Date.now()) }
              }));
            }
          } catch(_) {}
        }
      }
      if (!cardEl.isConnected) return;
      const enriched = buildEnrichedGame(rawGame, {
        espnScore:   typeof findESPNScore === 'function' ? findESPNScore(rawGame) : null,
        contextGame: ctx,
      });
      const debriefEl = buildDebrief(enriched);
      if (debriefEl) {
        let debriefDiv = cardEl.querySelector('.card-debrief');
        if (!debriefDiv) {
          debriefDiv = document.createElement('div');
          debriefDiv.className = 'card-debrief';
          cardEl.appendChild(debriefDiv);
        }
        debriefDiv.replaceChildren(debriefEl);
        cardEl.classList.add('is-final');
      }
      cardEl.dataset.debriefInjected = '1';
    } catch (_e) {
      captureFieldError('debrief:inject', _e, true);
    }
  }));
}

// Single-game filter predicate — encapsulates the three game-level filter modes.
// Sport filter (activeFilter) is section-level and remains in renderAll's section loop.
function shouldShowCard(g) {
  if (myTeamsFilter)  return MY_TEAMS.has(g.home) || MY_TEAMS.has(g.away);
  if (rivalsFilter)   return typeof isRivalGame === 'function' && isRivalGame(g);
  if (freeOnlyFilter) return gameHasFreeStream(g);
  return true;
}

// Higher-debounce render coordinator — 500ms window for V2+ESPN merge.
// Wraps scheduleRenderAll; use this when a data path arrives asynchronously
// and should coalesce with other in-flight updates before a structural render.
let _renderDebounceTimer = null;
function scheduleRenderDebounced(delay) {
  const _d = (delay != null && delay >= 0) ? delay : 500;
  if (_renderDebounceTimer) clearTimeout(_renderDebounceTimer);
  _renderDebounceTimer = setTimeout(function() {
    _renderDebounceTimer = null;
    scheduleRenderAll();
  }, _d);
}

// ── Per-game Circadian State (CC-CMD-2026-07-04-circadian-client-phase-v2) ──
// v2.2: cross-sport, per-adapter field awareness — confirmed via live
// browser inspection 2026-07-04 that getCardCircadian's v2.1 version only
// worked for WC26. WC26/V2-normalized sports use game.state ('final'/'post'
// terminal). MLB uses a different field entirely, game.status (via
// normalizeMLBStatus(), index.html:19788: 'pregame'/'live'/'final'/'postponed').
// AFL uses game._aflComplete (0-100 numeric, index.html:21995/22039).
// CFL and Golf have no reliable completion signal on their base game
// objects at all — left on the explicit LATE fallback below, not given
// invented logic (guessing start_time + a fixed duration risks being
// confidently wrong). Re-verify via the CC-CMD's probe block if a new
// adapter shape is added later and this stops matching.
function isGameOver(game) {
  if (game.state === 'final' || game.state === 'post') return true;       // WC26/V2-normalized sports
  if (game.status === 'final' || game.status === 'postponed') return true; // MLB (normalizeMLBStatus vocabulary)
  if (typeof game._aflComplete === 'number' && game._aflComplete >= 100) return true; // AFL
  return false;
}

// Per-game circadian state. Pure function of game.state/status/_aflComplete
// + elapsed time since final — no clock dependency, no global mode, no KV
// fetch. Matches "FIELD — Circadian System Spec Revised" (June 20-21 2026).
//
// mapV2ToESPN() normalizes every V2/WC26 game object's state to
// 'pre'/'in'/'post' before card-render code ever sees it — 'live' and
// 'final' (the relay's own raw vocabulary) never reach this function for
// those sports in practice. Check BOTH, matching the codebase's own
// established defensive pattern (e.g. this file's ensureGameSocket and
// wp_update handlers: `state === 'live' || state === 'in'`). MLB and AFL
// carry no `state` field at all — see isGameOver's comment above.
function getCardCircadian(game) {
  // PRIME (live)
  if (game.state === 'live' || game.state === 'in') return 'PRIME';           // WC26/V2
  if (game.status === 'live') return 'PRIME';                                  // MLB
  if (typeof game._aflComplete === 'number' && game._aflComplete > 0 && game._aflComplete < 100) return 'PRIME'; // AFL

  // PREVIEW (not started)
  if (game.state === 'pre') return 'PREVIEW';           // WC26/V2
  if (game.status === 'pregame') return 'PREVIEW';       // MLB
  if (game._aflComplete === 0) return 'PREVIEW';         // AFL, explicit 0 (not merely absent/undefined)

  // NIGHT/LATE (over)
  if (isGameOver(game)) {
    return minutesSinceFinal(game) < 120 ? 'NIGHT' : 'LATE';
  }

  // CFL, Golf, and anything else with no recognized field: explicit,
  // documented fallback — not a silent gap.
  return 'LATE';
}

// ── Cross-Sport Circadian System (CC-CMD-2026-07-18-gap5-circadian) ──
// Document-level circadian mode (global + per-sport). Distinct from per-game
// circadian (above). Uses cross-adapter state detection same as isGameOver() /
// getCardCircadian() — not spec's g.status-only approach which only covers V2.
let _circadianMode = 'PREVIEW';
let _circadianBySport = {};
let _prevCircadianMode = null;

function computeCircadianContext(now, games) {
  const liveCount = games.filter(g =>
    g.state === 'live' || g.state === 'in' ||
    g.status === 'live' ||
    (typeof g._aflComplete === 'number' && g._aflComplete > 0 && g._aflComplete < 100)
  ).length;
  const finalCount = games.filter(g => isGameOver(g)).length;
  const upcomingCount = games.filter(g =>
    g.state === 'pre' || g.status === 'pregame' || g._aflComplete === 0
  ).length;
  if (liveCount > 0 && liveCount >= finalCount) return 'PRIME';
  if (finalCount > 0 && liveCount === 0 && upcomingCount === 0) return 'LATE';
  if (finalCount > liveCount && finalCount > upcomingCount) return 'NIGHT';
  const hour = now.getHours();
  if (hour >= 5 && hour < 12) return 'DAWN';
  if (hour >= 12 && hour < 18) return 'PREVIEW';
  if (hour >= 18 && hour < 22) return 'PRIME';
  if (hour >= 22 || hour < 2) return 'NIGHT';
  return 'LATE';
}

function computeSportCircadian(now, allSports) {
  const allGames = allSports.flatMap(s => s.games || []);
  const global = computeCircadianContext(now, allGames);
  const bySport = {};
  for (const sec of allSports) {
    if ((sec.games || []).length > 0) {
      bySport[sec.sport] = computeCircadianContext(now, sec.games);
    }
  }
  return { global, bySport };
}

function applyCircadian(mode) {
  document.documentElement.dataset.circadian = mode;
}

// Gap 4: within-tier My Teams boost for the circadian sort comparator.
// Returns 0 for games with a followed team, 1 for others — lower wins.
// Uses MY_TEAMS (existing Set, source of truth). No-ops when MY_TEAMS is
// empty so the sort is unchanged for users with no followed teams.
function myTeamsBoost(g) {
  if (typeof MY_TEAMS === 'undefined' || !MY_TEAMS.size) return 0;
  return (MY_TEAMS.has(g.home) || MY_TEAMS.has(g.away)) ? 0 : 1;
}

// Gap 11: show "Show all sports" suggestion chip when circadian mode transitions
// to LATE/DAWN and the active sport filter has all games finished.
// Never auto-clears the filter — only suggests via a dismissible chip.
function _checkFilterSuggestionChip(prevMode, newMode) {
  if (newMode !== 'LATE' && newMode !== 'DAWN') return;
  if (prevMode === 'LATE' || prevMode === 'DAWN') return;
  if (!activeFilter || activeFilter === 'all') return;
  if (!allData || !Array.isArray(allData.sports)) return;
  const sportSec = allData.sports.find(function(s) { return s.sport === activeFilter; });
  if (!sportSec || !Array.isArray(sportSec.games) || !sportSec.games.length) return;
  const allFinal = sportSec.games.every(function(g) {
    const st = g._espnState || g.state || '';
    return st === 'post' || st === 'final';
  });
  if (!allFinal) return;
  if (document.getElementById('filter-suggestion-chip')) return;
  const filtersEl = document.getElementById('sport-filters');
  if (!filtersEl) return;
  const chip = document.createElement('div');
  chip.id = 'filter-suggestion-chip';
  chip.className = 'filter-suggestion-chip';
  const label = document.createElement('span');
  label.className = 'filter-suggestion-text';
  label.textContent = 'All ' + activeFilter + ' games are final — ';
  const actionBtn = document.createElement('button');
  actionBtn.type = 'button';
  actionBtn.className = 'filter-suggestion-action';
  actionBtn.textContent = 'Show all sports';
  actionBtn.addEventListener('click', function() {
    activeFilter = 'all';
    document.querySelectorAll('.filter-btn').forEach(function(b) { b.classList.remove('active'); });
    const allBtn = document.querySelector('.filter-btn[data-filter="all"]');
    if (allBtn) allBtn.classList.add('active');
    renderAll();
    chip.remove();
  });
  const dismissBtn = document.createElement('button');
  dismissBtn.type = 'button';
  dismissBtn.className = 'filter-suggestion-dismiss';
  dismissBtn.setAttribute('aria-label', 'Dismiss');
  dismissBtn.textContent = '✕';
  dismissBtn.addEventListener('click', function() { chip.remove(); });
  chip.appendChild(label);
  chip.appendChild(actionBtn);
  chip.appendChild(dismissBtn);
  filtersEl.insertAdjacentElement('afterend', chip);
}

// _bundleFinalizedAt: cross-session-accurate finalized_at lookup for
// completed games (CC-CMD-2026-07-08-truth-is-night-stars-client-fix).
// _finalizedAt[game._id] below only knows about games THIS session
// actually witnessed transition to final (Date.now() at first-
// observation) -- worthless on a fresh page load for a game that already
// finished. The newspaper bundle (window._newspaperBundle, stashed
// globally by renderNewspaper()) carries a real finalized_at from the
// relay's D1 archive for recap_date's completed games -- this reads it.
//
// Matches by team nickname + sport, NOT any ID: confirmed live that
// bundle.completed_games[].id embeds spaces/mixed case differently per
// sport (not a reconstructable client-side key), and that the bundle's
// home/away are short nicknames ("Giants") while allData.sports games
// carry full names ("San Francisco Giants") -- a raw string compare would
// never match. Reuses the existing teamNick() helper instead.
// Sport comparison is substring-based, not exact-equality: confirmed live
// that MLB's client _sport ("Baseball (MLB)") and the relay's sport
// ("MLB") are different strings (though game.league === "MLB" does match
// exactly) -- rather than hard-code every sport's exact relay-vs-client
// pairing (unverifiable for sports with no live game to inspect right
// now, e.g. WNBA), a substring check tolerates the format difference.
//
// Guarded on bundle.recap_date === TODAY_ISO: the two cover the same
// calendar day only during the actual bug window (before TODAY_ISO's own
// 4am ET rollover, index.html ~6879) -- confirmed this is not a
// coincidence, it's the same rollover convention this whole late-night
// classification problem exists for. Outside that window there is
// nothing to match and this must not false-positive against an unrelated
// night's games.
// _sportLabelMatches: the canonical way to compare a client sport label
// against any external system's short-code convention. Extracted from
// _bundleFinalizedAt's inline sportOk() closure (CC-CMD-2026-07-08-
// truth-is-night-stars-client-fix, d12d2a24) — this is the SECOND time a
// client sport value crossing a system boundary has needed ad-hoc tolerance
// logic, built independently both times: field-relay-nba's
// resolveWinProbability() needed normalizeSportCode() for the exact same
// reason (client "Baseball (MLB)" never matches the relay's bare 'mlb').
// The next integration that needs this should call this instead of
// reinventing it a third time.
//
// Substring-tolerant by design, not sloppiness: not every sport's exact
// external-vs-client pairing could be verified live when this was written
// (e.g. WNBA had no live game in that day's slate to inspect). Checks both
// the client's general sport tag and its league field, since neither alone
// is guaranteed to line up with every external system's convention (WC26's
// client _sport matches the relay's "FIFA World Cup 2026" directly; MLB's
// client _sport ("Baseball (MLB)") does not match the relay's "MLB", but
// MLB's client league field does, exactly).
//
// clientLeague's comparison is intentionally asymmetric (only checks
// spLeague.includes(bs), never bs.includes(spLeague)) — preserved exactly
// as originally proven, not normalized to match clientSport's fully
// bidirectional check, per this extraction's own instruction to preserve
// existing behavior rather than reimplement it.
function _sportLabelMatches(clientSport, clientLeague, externalSport) {
  const bs = (externalSport || '').toLowerCase().trim();
  if (!bs) return true; // external entry carries no sport tag -- don't over-require
  const spClient = (clientSport || '').toLowerCase();
  const spLeague = (clientLeague || '').toLowerCase();
  return spClient.includes(bs) || bs.includes(spClient) || spLeague === bs || spLeague.includes(bs);
}

function _bundleFinalizedAt(game) {
  try {
    const bundle = window._newspaperBundle;
    if (!bundle || !bundle.completed_games || !bundle.completed_games.length) return null;
    if (!bundle.recap_date || typeof TODAY_ISO === 'undefined' || bundle.recap_date !== TODAY_ISO) return null;
    const h = teamNick(game.home || '').toLowerCase().trim();
    const a = teamNick(game.away || '').toLowerCase().trim();
    if (!h || !a) return null;
    const spClient = _gameSport(game).toLowerCase();
    const spLeague = (game.league || '').toLowerCase();
    const sportOk = (bgSport) => _sportLabelMatches(spClient, spLeague, bgSport);
    const matches = bundle.completed_games.filter(bg =>
      teamNick(bg.home || '').toLowerCase().trim() === h &&
      teamNick(bg.away || '').toLowerCase().trim() === a &&
      sportOk(bg.sport)
    );
    // Doubleheader safety: the bundle carries no per-game hour, only a
    // whole-day recap_date -- if sport+home+away matches more than one
    // entry, this is genuinely ambiguous. Don't guess, fall back.
    if (matches.length !== 1) return null;
    const raw = matches[0].finalizedAt;
    if (!raw) return null;
    // SQLite CURRENT_TIMESTAMP format ("YYYY-MM-DD HH:MM:SS", no offset) --
    // confirmed via real testing (TZ=America/New_York) that naive Date
    // parsing treats this as browser-LOCAL time, not UTC, producing a
    // 240-minute error for ET users. The relay's OTHER timestamp fields in
    // the same response (quality_alert.generated_at) use proper ISO-8601
    // 'Z'-suffixed strings -- this is a raw D1 column value, not an
    // intentionally different format. Explicit UTC parse.
    const iso = raw.includes('T') ? raw : raw.replace(' ', 'T') + 'Z';
    const ts = new Date(iso).getTime();
    return isNaN(ts) ? null : ts;
  } catch (_e) { captureFieldError('newspaper:bundle-finalized-at', _e, true); return null; }
}

// No existing field carries a genuine finalized-at moment (espnScoreTs is
// re-stamped on every poll of an already-final game; saveEspnFinal's
// persisted entry has only a calendar-date string; _seenFinals has no
// timestamp and resets on page load). _finalizedAt (declared next to
// _seenFinals in checkForNewFinals) is the authorized new state that
// fills this gap — written once, at the same firing point _seenFinals
// already uses. Now tried second, after the relay-backed
// _bundleFinalizedAt (CC-CMD-2026-07-08-truth-is-night-stars-client-fix):
// the bundle only covers recap_date's completed games and is
// null-heavy for anything that finalized before the relay-side
// finalized_at column existed, so this session-local map remains the
// fallback for everything the bundle doesn't (yet) know about.
function minutesSinceFinal(game) {
  const bundleTs = (typeof _bundleFinalizedAt === 'function') ? _bundleFinalizedAt(game) : null;
  const ts = bundleTs || _finalizedAt[game._id];
  // No recorded final time (game finished before this session's
  // checkForNewFinals ever ran, or page just loaded, AND the bundle has
  // no matching finalized_at either) — default to LATE's safe, compressed
  // treatment rather than guessing NIGHT's enhanced one for a game we
  // have no real timing evidence for.
  if (!ts) return Infinity;
  return (Date.now() - ts) / 60000;
}

// Aggregate voice for the newspaper banner. Pure function of a games array
// (each item just needs the same shape getCardCircadian expects: .state/
// .status/._aflComplete/._id, per-sport as documented there).
// Does not change what fetchNewspaper fetches — see applyNewspaperVoice,
// which supplies the real games array once one exists (renderAll time, not
// bootNewspaper time — the newspaper bundle itself carries no live per-game
// state array).
function getNewspaperVoice(games) {
  const live = games.filter(g => getCardCircadian(g) === 'PRIME').length;
  const finals = games.filter(g => getCardCircadian(g) === 'NIGHT').length;
  const upcoming = games.filter(g => getCardCircadian(g) === 'PREVIEW').length;
  const late = games.filter(g => getCardCircadian(g) === 'LATE').length;
  if (live > 0) return 'minimal';
  if (finals > upcoming) return 'recap';
  if (upcoming > 0) return 'preview';
  // Real gap fixed here (CC-CMD-2026-07-04-newspaper-voice-late-gap-fix):
  // previously fell through to 'morning' (show everything) whenever every
  // game was LATE and nothing was live/recently-finished/upcoming -- the
  // wrong default, since 'morning' is "nothing has started yet" and an
  // all-LATE slate means the opposite (everything already happened, just
  // outside the 120-min freshness window). Reuses the existing 'recap'
  // voice (no new section-visibility logic needed in applyNewspaperVoice)
  // rather than inventing a new voice value for this case.
  if (late > 0) return 'recap';
  return 'morning';
}

// ── Render stream chips with auth icon + tooltip ─────────────────────────────
// ═══════════════════════════════════════════════════════════════
// DATE NAVIGATION ENGINE
// Today → hardcoded verified data (zero tokens)
// Other dates → single compact AI fetch (cached in sessionStorage)
// Usage counter persists in sessionStorage, resets daily
// ═══════════════════════════════════════════════════════════════

// TODAY_ISO: 4am ET rolling cutoff for late-night sports fans.
// Before 4:00am ET, "today" means the previous ET calendar day — games from
// last night are still on tonight's slate, not rolled off to yesterday.
// e.g. User at 1:30am ET on Jun 6: sees Jun 5 games (still live/final from tonight)
// e.g. User at 4:15am ET on Jun 6: sees Jun 6 schedule (day has genuinely turned over)
// AFL carveout: AFL games use AEST date (Australia/Sydney) for isToday() checks
// because Australian rounds run on the Australian calendar day, not ET. A 7am
// AEST Saturday game is a "Saturday AFL game" regardless of what the US clock says.
(function() {
  const _etNow = new Date();
  const _etHour = parseInt(_etNow.toLocaleString('en-US', {timeZone:'America/New_York', hour:'numeric', hour12:false}), 10);
  // Before 4am ET: roll back to previous ET day
  const _etDate = new Date(_etNow);
  if (_etHour < 4) _etDate.setTime(_etDate.getTime() - 24*60*60*1000);
  window.TODAY_ISO = _etDate.toLocaleDateString('en-CA', {timeZone:'America/New_York'});
})();

// ── Drama Dial — user-controlled sensitivity (Patent Defense Layer 2) ────────
// All drama thresholds read from this. Server CANNOT see or set this value.
// Storage: localStorage (main thread) + IndexedDB (Service Worker fallback).
// ── teamNick — safe team nickname extraction ─────────────────────────────────
// Handles multi-word nicknames: Red Sox, Blue Jays, White Sox, Golden Knights, etc.
// Fallback: last word of team name. Null-safe.
const _multiWordNicks={'Boston Red Sox':'Red Sox','Chicago White Sox':'White Sox',
  'Toronto Blue Jays':'Blue Jays','Portland Trail Blazers':'Trail Blazers',
  'Vegas Golden Knights':'Golden Knights','Oklahoma City Thunder':'Thunder',
  'New York Red Bulls':'Red Bulls','Wolverhampton Wanderers':'Wolves',
  'Sheffield Wednesday':'Wednesday','Sheffield United':'Blades',
  'West Ham United':'West Ham','Crystal Palace':'Palace',
  'Aston Villa':'Villa','Nottingham Forest':'Forest',
  'Brighton and Hove Albion':'Brighton','AFC Bournemouth':'Bournemouth',
  'Tottenham Hotspur':'Spurs','Manchester United':'Man Utd',
  'Manchester City':'Man City','Newcastle United':'Newcastle',
  'Leicester City':'Leicester','Wolverhampton Wanderers':'Wolves',
  // iPad-8: WNBA — last-word nick works for most ('Atlanta Dream' → 'Dream')
  // but ESPN sometimes ships shortened names that collapse to a single letter.
  // Explicit entries guarantee the nick column never falls back to first-char.
  'Las Vegas Aces':'Aces','Atlanta Dream':'Dream','Indiana Fever':'Fever',
  'New York Liberty':'Liberty','Minnesota Lynx':'Lynx','Phoenix Mercury':'Mercury',
  'Washington Mystics':'Mystics','Chicago Sky':'Sky','Los Angeles Sparks':'Sparks',
  'Seattle Storm':'Storm','Connecticut Sun':'Sun','Dallas Wings':'Wings',
  'Golden State Valkyries':'Valkyries',
  'Czech Republic':'Czechia','Bosnia and Herzegovina':'Bosnia',
  'South Africa':'S. Africa','Congo DR':'Congo','DR Congo':'Congo',
  'Ivory Coast':'Ivory Coast','Costa Rica':'Costa Rica',
  'Saudi Arabia':'Saudi Arabia','New Zealand':'New Zealand'};
// Rule 76 (FALLBACK-CAP-A): canonical sport field accessor.
// Game objects use _sport, _section, sport, or league depending on source.
// This function is the SINGLE place the fallback chain lives.
// All downstream code calls _gameSport(g) instead of raw chains.
function _gameSport(g){ return g && (g._sport || g._section || g.league || '') || ''; }

function teamNick(name){
  if(!name) return '';
  if(_multiWordNicks[name]) return _multiWordNicks[name];
  const parts=name.split(' ');
  return parts.length>1?parts[parts.length-1]:name;
}
const getTeamNick=teamNick; // alias for existing references

function getDramaDial(){
  try{const v=parseInt(localStorage.getItem('field_drama_dial'));return(v>=45&&v<=90)?v:65;}catch(_){return 65;}
}
function setDramaDial(value){
  // Display-filter only (2026-07-06) -- no longer synced to the SW. The SW's
  // push trigger is now a factual isCrunchLikePush() boolean gate that does
  // not read this value; the dial controls on-screen badge/OTW sensitivity
  // in the already-open app only. See getDramaDial() call sites.
  const v=Math.max(45,Math.min(90,parseInt(value)||65));
  localStorage.setItem('field_drama_dial',v);
  // Update preview text if slider exists
  const preview=document.getElementById('dial-preview');
  if(preview) preview.textContent=`Close games get badges · ${Math.min(v+20,95)===95?'Only the tightest':v<=50?'Nearly all':'Most'} close games get badged as CRUNCH TIME`;
  // Re-evaluate badges with new threshold
  if(typeof injectDramaBadges==='function') try{injectDramaBadges();}catch(e){}
  // Update header chip
  if(typeof _updateDialChip==='function') _updateDialChip();
}
let viewingDate  = new Date();  // The date currently being viewed
let viewingISO   = TODAY_ISO;   // ISO string of viewing date

// ── Usage tracking ──────────────────────────────────────────────
// Tracks number of Anthropic API calls made today (supplemental + date fetches)
// Resets daily. Free estimate: supplemental calls + date navigation calls.
const USAGE_KEY    = "field_api_usage";
const USAGE_DATE_KEY = "field_api_date";
const DAILY_BUDGET  = 50; // Conservative estimate of daily call budget
const MAX_USES      = 75; // Hard cap — 50% above DAILY_BUDGET; blocks new Claude calls when reached

function canUseAPI(){
  const u = getUsage();
  if(u >= MAX_USES){
    if(FIELD_DEBUG) console.warn("[FIELD] MAX_USES reached — Claude API blocked");
    return false;
  }
  return true;
}

function getUsage(){
  const storedDate = sessionStorage.getItem(USAGE_DATE_KEY);
  if(storedDate !== TODAY_ISO){
    sessionStorage.setItem(USAGE_DATE_KEY, TODAY_ISO);
    sessionStorage.setItem(USAGE_KEY, "0");
    return 0;
  }
  return parseInt(sessionStorage.getItem(USAGE_KEY)||"0");
}
function incrementUsage(){
  const u = getUsage() + 1;
  sessionStorage.setItem(USAGE_KEY, String(u));
  renderUsageBadge(u);
  return u;
}
function renderUsageBadge(u){
  const badge = document.getElementById("usage-badge");
  if(badge) badge.style.display = FIELD_DEBUG ? "flex" : "none";
  const text  = document.getElementById("usage-text");
  if(!badge||!text) return;
  const remaining = Math.max(0, DAILY_BUDGET - u);
  const pct = u / DAILY_BUDGET;
  text.textContent = `${u} call${u!==1?"s":""} · ${remaining} left today`;
  badge.className = "usage-badge " + (pct>=.8?"usage-low":pct>=.5?"usage-warn":"usage-ok");
}

// ── Date label helpers ──────────────────────────────────────────
function isoToLabel(iso){
  const d = new Date(iso + "T12:00:00Z");
  if(iso===TODAY_ISO) return "Today";
  const diff = Math.round((new Date(iso+"T12:00:00Z")-new Date(TODAY_ISO+"T12:00:00Z")) / 86400000);
  if(diff===1)  return "Tomorrow";
  if(diff===-1) return "Yesterday";
  return d.toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"});
}
function updateDateLabel(){
  const lbl = document.getElementById("date-label");
  const prev = document.getElementById("date-prev");
  const next = document.getElementById("date-next");
  if(!lbl) return;
  const diff = Math.round((new Date(viewingISO+"T12:00:00Z") - new Date(TODAY_ISO+"T12:00:00Z")) / 86400000);
  lbl.textContent = isoToLabel(viewingISO);
  lbl.className   = "date-label" + (viewingISO===TODAY_ISO?" today":"");
  if(prev) prev.disabled = diff <= -7;  // max 7 days back
  if(next) next.disabled = diff >= 3;   // max 3 days ahead
}

// ── sessionStorage cache for fetched dates ──────────────────────
function cacheKey(iso){ return "field_sched_" + iso; }
function getCached(iso){
  try{ const v=sessionStorage.getItem(cacheKey(iso)); return v?JSON.parse(v):null; }
  catch(e){ return null; }
}
function setCached(iso,data){
  try{ sessionStorage.setItem(cacheKey(iso), JSON.stringify(data)); }
  catch(e){ if(FIELD_DEBUG) console.debug("FIELD: sessionStorage cache write failed"); }
}

// ── AI fetch for non-today dates ─────────────────────────────────
// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #11): the sole
// caller (goToDate) showed the same "⚠️ Couldn't load schedule... Check
// the browser console... Retry" message whether the real cause was the
// daily AI-call budget being exhausted (retrying is futile until
// tomorrow -- the Retry button would just fail again immediately for the
// same reason) or a genuine transient HTTP/parse failure (retrying might
// actually work). Migrated the return contract from `array|null` to
// `{ok:true,sections}` / `{ok:false,reason}` so the caller can show an
// accurate message for each case.
async function fetchDateSchedule(iso){
  // Check cache first — zero tokens if already fetched
  const cached = getCached(iso);
  if(cached){
    if(FIELD_DEBUG) console.debug("FIELD: cache hit for",iso,"→",cached.length,"sections");
    return {ok:true, sections:cached};
  }

  const d   = new Date(iso+"T12:00:00Z");
  const dow = d.toLocaleDateString("en-US",{weekday:"long"});
  const mon = d.toLocaleDateString("en-US",{month:"long",year:"numeric"});

  const prompt = `${iso} (${dow}, ${mon}). Sports schedule for this date. Respond with JSON only — no prose, no markdown fences.
Schema: {"s":[["HomeTeam","AwayTeam","League","${iso}THH:MM:00Z","streamkey"],...]} or {"s":[]}.
Replace HH:MM with actual UTC kick-off time. Use 24-hour UTC (GMT+0). A 7pm ET game = 23:00 UTC. A 7pm PT game = 02:00 UTC next day. Do not use local timezone. If unsure of the exact time, omit the game entirely rather than guessing.
Include if games exist: NBA playoffs, NHL playoffs, MLB, NFL, UCL/UEL/UECL, EPL, IPL, AFL, Grand Slam tennis, Top14/URC rugby.
Stream keys (pick best fit): espn,abc,nbc,tnt,tbs,fox,fs1,peacock,paramount,apple,prime,netflix,max,mlbtv,tc,willow,bein,sky,watchafl,mlbn.
Return {"s":[]} if no major sport games that day. CRITICAL: If you are not highly confident a specific game is scheduled on this exact date, omit it. An empty {"s":[]} is preferable to inventing a game that is not happening.`;

  let rawTxt = "";
  if(!canUseAPI()) return {ok:false, reason:'budget-exhausted'};
  try{
    incrementUsage();
    if(FIELD_DEBUG) console.debug("FIELD: fetching schedule for",iso);
    const r = await fetch(CLAUDE_PROXY_URL,{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      signal:AbortSignal.timeout(15000),
      body:JSON.stringify({
        model:"claude-haiku-4-5-20251001",
        max_tokens:800,
        messages:[{role:"user",content:prompt}]
      })
    });

    if(!r.ok){
      const errText = await r.text();
      throw new Error(`HTTP ${r.status}: ${errText.slice(0,120)}`);
    }

    const data = await r.json();

    // Surface API-level errors
    if(data.type==="error"||data.error){
      throw new Error(data.error?.message||JSON.stringify(data));
    }

    rawTxt = (data.content||[]).map(b=>b.text||"").join("").trim();
    if(FIELD_DEBUG) console.debug("FIELD: raw response for",iso,"→",rawTxt.slice(0,200));

    // Strip any markdown fences the model adds despite instructions
    const cleaned = rawTxt
      .replace(/^```(?:json)?\s*/i,"")
      .replace(/\s*```\s*$/,"")
      .trim();

    // Extract JSON object if there's leading/trailing prose
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if(!jsonMatch) throw new Error("No JSON object in response: "+cleaned.slice(0,80));

    const parsed = JSON.parse(jsonMatch[0]);
    const rows = parsed.s||[];

    if(!rows.length){
      if(FIELD_DEBUG) console.debug("FIELD: no games for",iso,"(model returned empty)");
      setCached(iso,[]); // Cache empty — correct, no games that day
      return {ok:true, sections:[]};
    }

    // Expand compact arrays → sport sections
    const byLeague = {};
    rows.forEach(row=>{
      if(!Array.isArray(row)||row.length<4) return; // skip malformed
      const [home,away,league,time,streamKey] = row;
      const sport = inferSport(league);
      if(!byLeague[sport]) byLeague[sport]={sport,games:[]};
      byLeague[sport].games.push({
        home:home||"TBD", away:away||"TBD",
        league, start_time:time, venue:"",
        streams:expandStreams(streamKey?[streamKey]:[]),
        _sport:sport
      });
    });

    const sections = Object.values(byLeague);
    if(FIELD_DEBUG) console.debug("FIELD: parsed",sections.length,"sections for",iso);
    setCached(iso, sections);
    return {ok:true, sections};

  }catch(e){
    // Don't cache errors — allow retry on next navigation
    if(FIELD_DEBUG) console.warn("FIELD date fetch error for",iso+":",e.message);
    if(FIELD_DEBUG&&rawTxt) console.warn("FIELD raw response was:",rawTxt.slice(0,300));
    return {ok:false, reason:'error', message:e.message}; // distinct from a legitimate {ok:true, sections:[]}
  }
}

