// ── ESPN fixture fetch for any date — free, zero tokens ──────────────────────
// Fetches NBA, NHL, MLB, and all 9 soccer leagues for any date via ESPN public API.
// Returns array of sport sections (same schema as buildDateSchedule) or null on failure.
async function fetchESPNFixturesForDate(iso){
  const dateStr = iso.replace(/-/g,""); // "20260512"
  const cache = getCached("espn_"+iso);
  if(cache){ if(FIELD_DEBUG) console.debug("FIELD: ESPN fixture cache hit for",iso); return cache; }

  const FETCH_LEAGUES = [
    {sport:"basketball", league:"nba",           section:"NBA",          bundle:"NBA",       prefix:"Q"},
    {sport:"basketball", league:"wnba",          section:"WNBA",         bundle:"WNBA_ESPN", prefix:"Q"},
    {sport:"golf",       league:"pga",           section:"Golf",         bundle:"GOLF_CBS",  prefix:"R"},
    {sport:"hockey",     league:"nhl",           section:"NHL",          bundle:"NHL_ESPN",  prefix:"P"},
    {sport:"baseball",   league:"mlb",           section:"Baseball (MLB)",bundle:"MLB_LOCAL",prefix:"T"},
    ...SOCCER_LEAGUES.map(l=>({sport:"soccer",league:l.league,section:l.section,bundle:l.bundle,prefix:"'"})),
  ];

  const allSections = [];
  let anyData = false;
  // 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #12): investigated
  // the queue's suggestion to distinguish "ESPN genuinely has no games"
  // from "every per-league fetch failed" before building anything. The
  // sole caller (goToDate) falls back to the AI schedule generator either
  // way when this returns null -- AI covers leagues (tennis, rugby,
  // cricket) this ESPN sweep doesn't, so trying it is correct regardless
  // of WHY ESPN returned nothing. No caller-visible behavior would change
  // from differentiating the two causes, same conclusion as findESPNScore
  // earlier this session. What WAS a real, confirmed gap: each of the
  // 15+ per-league fetches has its own catch that silently discards any
  // error (FIELD_DEBUG-gated console.debug only) -- an ESPN-wide outage
  // affecting every league would be completely invisible, indistinguishable
  // from a genuinely empty schedule day. Tracking failure count below and
  // recording real telemetry when any league fetch fails.
  let _leagueFailures = 0;

  await Promise.all(FETCH_LEAGUES.map(async ({sport,league,section,bundle,prefix})=>{
    try{
      const url = `${ESPN_BASE}/${sport}/${league}/scoreboard?dates=${dateStr}&limit=50`;
      // L6 (May 11): User-Agent header removed — browsers strip it (Chrome) or trigger
      // a CORS preflight (Firefox) that ESPN's unofficial API does not satisfy.
      // The header was non-functional in production and risked breaking Firefox fetches.
      const r = await fetch(url,{signal:AbortSignal.timeout(8000)});
      if(!r.ok) return;
      const data = await r.json();
      const events = data.events||[];
      if(!events.length) return;
      const games = events.map(ev=>{
        const comp = (ev.competitions||[])[0]; if(!comp) return null;

        // ── Golf: individual sport — use event/tournament name, no home/away ─
        if(sport === 'golf') {
          const tournName = ev.name || ev.shortName || 'PGA Tour';
          const statusDetail = ev.status?.type?.detail || '';
          const roundNum = ev.status?.period || null;
          const roundLabel = roundNum ? `R${roundNum}` : '';
          // ESPN stores golf with midnight placeholder — suppress 12:00 AM display
          // by normalising the start_time to noon UTC on tournament day
          const rawDate = (ev.date||'').slice(0,10); // "2026-05-28"
          const normTime = rawDate ? rawDate+'T12:00:00Z' : (ev.date||'');
          // Day-aware bundle: Golf Channel Thu/Fri, CBS Sat/Sun
          const evDay = rawDate ? new Date(rawDate+'T12:00:00Z').getDay() : -1;
          const golfBundle = (evDay===0||evDay===6) ? 'GOLF_CBS' : 'GOLF_CHANNEL';

          // ── Extract ESPN leaderboard (competitors[] previously discarded) ────
          // ESPN golf scoreboard returns full per-player leaderboard at no cost.
          // Fields available: athleteId (ESPN), total score, per-round linescores,
          //                   status (active/cut/complete), thru (holes completed).
          // Stored in window._espnGolfLB[tournName] for analytics layer to read.
          const competitors = comp.competitors || [];
          if (competitors.length > 0) {
            const lb = competitors.map(c => ({
              name:       c.athlete?.displayName || '',
              espnId:     c.athlete?.id || '',
              total:      c.score || 'E',
              status:     c.status?.type?.name || 'active',
              linescores: (c.linescores || []).map(l => l.value || l.score || ''),
              thru:       (c.statistics || []).find(s =>
                            (s.name||'').toLowerCase().includes('thru') ||
                            (s.abbreviation||'').toLowerCase() === 'thru'
                          )?.displayValue || '',
              position:   c.status?.position?.displayName || String(c.order || ''),
            })).filter(p => p.name);
            if (!window._espnGolfLB) window._espnGolfLB = {};
            window._espnGolfLB[tournName] = { lb, round: roundNum, updated: Date.now() };
            if(FIELD_DEBUG) console.debug(
              `[ESPN Golf] extracted ${lb.length} players for ${tournName} R${roundNum}`);
          }

          _gid++;
          return {
            _id:`g${_gid}`, _sport:section,
            home: tournName, away: '',  // no away for golf
            league: section + (roundLabel ? ' · '+roundLabel : ''),
            start_time: normTime,
            venue: comp.venue?.fullName || '',
            streams: resolveBundle(golfBundle),
            leaderNote: statusDetail || roundLabel || '',
          };
        }

        const comps = comp.competitors||[];
        const home = comps.find(t=>t.homeAway==="home")||comps[0];
        const away = comps.find(t=>t.homeAway==="away")||comps[1];
        if(!home||!away) return null;
        _gid++;
        // For MLB, build the canonical MLB_{homeAbbr}_{awayAbbr}_{YYYYMMDD} ID so
        // findBriefs() in the Context Graph can match game_id values written by
        // renderMLBGameBriefCard. The generic g${_gid} counter produced IDs that
        // never matched, making all mlb_game briefs permanently unfindable.
        const _homeAbbr = section==="Baseball (MLB)" ? (home.team?.abbreviation||home.team?.displayName||"?") : null;
        const _awayAbbr = section==="Baseball (MLB)" ? (away.team?.abbreviation||away.team?.displayName||"?") : null;
        const _dateStr  = section==="Baseball (MLB)" ? iso.replace(/-/g,'') : null;
        const _id = section==="Baseball (MLB)"
          ? `MLB_${_homeAbbr}_${_awayAbbr}_${_dateStr}`
          : `g${_gid}`;
        return {
          _id, _sport:section,
          home: home.team?.displayName||"?",
          away: away.team?.displayName||"?",
          league:section,
          start_time: ev.date||"",
          venue: (comp.venue?.fullName||""),
          streams: resolveBundle(bundle),
        };
      }).filter(Boolean);
      if(games.length){ allSections.push({sport:section,games}); anyData=true; }
    }catch(e){
      if(FIELD_DEBUG) console.debug("FIELD ESPN fixture:",league,e.message);
      _leagueFailures++;
    }
  }));

  if(_leagueFailures > 0){
    captureFieldError(
      'espn-fixtures:date-sweep',
      new Error(`${_leagueFailures}/${FETCH_LEAGUES.length} per-league fetches failed for ${iso}`),
      false
    );
  }

  if(!anyData) return null; // ESPN had nothing — let AI try
  // Inject tournament cards (WC countdown/games, French Open) into ESPN-path sections.
  // These are hardcoded-array surfaces not fetched from ESPN — must be called here
  // since buildDateSchedule() short-circuits on unknown dates and never reaches them.
  if(iso === TODAY_ISO) {
    maybePushFrenchOpen(allSections);
    maybePushWorldCup(allSections);
    maybePushAFLFinals(allSections);
  }
  setCached("espn_"+iso, allSections);
  if(FIELD_DEBUG) console.debug("FIELD: ESPN fixtures for",iso,"→",allSections.length,"sections");
  return allSections;
}

