// ── Seasonal Intelligence Layer 0 — Calendar Context ─────────────────────────
// Pure date logic. No API. No storage. Returns context for OTW bar + J3 brief.
// Priority: finals > postseason > world_cup > playoff_race > transfer_window >
//           nfl_playoffs > super_bowl > nfl_season > null
function getCalendarContext(){
  const now=new Date();
  const m=now.getMonth(); // 0=Jan
  const d=now.getDate();
  const y=now.getFullYear();

  // NBA/NHL Finals window (late May – late June).
  // Hard expiry: Stanley Cup Final ended 2026-06-14 (CAR won) and the NBA
  // Finals concluded as well. Past this date the badge is stale (the calendar
  // window alone would keep it on through June 22). When expired, fall through
  // to the next applicable context (currently World Cup 2026, Jun 11–Jul 19).
  const FINALS_SEASON_CONTEXT_EXPIRES = '2026-06-14';
  const _todayIso = (typeof window !== 'undefined' && window.TODAY_ISO)
    ? window.TODAY_ISO : now.toISOString().slice(0, 10);
  if(((m===4&&d>=28)||(m===5&&d<=22)) && _todayIso <= FINALS_SEASON_CONTEXT_EXPIRES)
    return {flag:'finals',label:'NBA & NHL Finals',urgency:'max',relevantLeagues:['NBA','NHL']};

  // NBA/NHL Conference Finals / Playoffs (Apr 15 – late May)
  if((m===3&&d>=15)||m===4)
    return {flag:'postseason',label:'NBA & NHL Playoffs',urgency:'high',relevantLeagues:['NBA','NHL']};

  // World Cup 2026 (June 11 – July 19, 2026 specific)
  if(y===2026&&((m===5&&d>=11)||(m===6&&d<=19)))
    return {flag:'world_cup',label:'World Cup 2026',urgency:'max',relevantLeagues:['Soccer']};

  // Soccer Transfer Window (Jul 1 – Aug 31)
  if(m===6||m===7)
    return {flag:'transfer_window',label:'Transfer Window',urgency:'medium',relevantLeagues:['EPL','MLS','CL']};

  // MLB Playoff Race (Sep 1 – Sep 28, last ~28 games)
  if(m===8)
    return {flag:'playoff_race',label:'MLB Playoff Race',urgency:'high',relevantLeagues:['MLB']};

  // MLB Postseason (Oct)
  if(m===9)
    return {flag:'mlb_postseason',label:'MLB Playoffs',urgency:'high',relevantLeagues:['MLB']};

  // NFL Playoffs (Jan 12 – Feb 1 approx)
  if(m===0&&d>=12)
    return {flag:'nfl_playoffs',label:'NFL Playoffs',urgency:'high',relevantLeagues:['NFL']};

  // Super Bowl week (first full weekend of Feb)
  if(m===1&&d<=8)
    return {flag:'super_bowl',label:'Super Bowl',urgency:'max',relevantLeagues:['NFL']};

  // NFL Regular Season (Sep 5 – Jan 11)
  if(m===8||(m>=9&&m<=11)||(m===0&&d<=11))
    return {flag:'nfl_season',label:'NFL Season',urgency:'medium',relevantLeagues:['NFL']};

  // NBA/NHL regular season early window (Nov-Mar) — no special context
  return null;
}

// J3 brief sentence from calendar context — one computed sentence
function calendarContextSentence(ctx){
  if(!ctx) return null;
  const m={
    finals:           'The NBA and NHL Finals are live.',
    postseason:       'The NBA and NHL playoffs are underway.',
    world_cup:        'The 2026 FIFA World Cup is underway.',
    transfer_window:  'The summer transfer window is open across European soccer.',
    playoff_race:     'The MLB playoff picture is tightening with the season winding down.',
    mlb_postseason:   'MLB October baseball is here.',
    nfl_playoffs:     'The NFL playoffs are underway.',
    super_bowl:       'Super Bowl week.',
    nfl_season:       null, // too broad to be useful in brief
  };
  return m[ctx.flag]||null;
}

// ── MLB Team Momentum — last-10 game form ─────────────────────────────────────
// Queries MLB Stats API with date range. Single call, cached 6 hours.
// ── MLB WAVE 1 GETTER FUNCTIONS ───────────────────────────────────────────────

function getUmpireABSRating(umpireLastName) {
  if (!umpireLastName) return null;
  const key = umpireLastName.toLowerCase().replace(/\s+/g,'_').replace(/['.]/g,'');
  const d = UMPIRE_ABS_RATINGS[key];
  if (!d || d.challenged < 3) return null;
  const league = BASEBALL_CONST.MLB_AVG_ABS_OVERTURN;
  const above = d.rate > UMP_WATCH_THRESHOLD;
  const badge = above ? 'UMP WATCH' : null;
  const pct = Math.round(d.rate * 100);
  const leaguePct = Math.round(league * 100);
  const weakNote = d.weakness ? ` · weak: ${d.weakness} zone` : '';
  let context = `${pct}% overturn (${d.overturned}/${d.challenged})${weakNote}`;
  if (above) context += ` — above league avg ${leaguePct}%`;
  else if (d.rate < 0.20) context += ` — tight caller, below avg ${leaguePct}%`;
  return { rate:d.rate, challenged:d.challenged, overturned:d.overturned,
           pitchesCalled:d.pitchesCalled, weakness:d.weakness,
           badge, context, diffFromLeague: pct - leaguePct };
}

function getParkFactor(teamAbbr) {
  if (!teamAbbr) return null;
  // Try direct abbr, also try stripping city from full team name
  const abbr = (teamAbbr||'').toUpperCase().replace(/^THE /,'');
  const d = PARK_FACTORS[abbr];
  if (!d) return null;
  let badge = null, badgeClass = '';
  const {PARK_EXTREME_HITTER_THRESHOLD:EH,PARK_HITTER_THRESHOLD:H,
         PARK_PITCHER_THRESHOLD:P,PARK_EXTREME_PITCHER_THRESHOLD:EP} = BASEBALL_CONST;
  if      (d.runFactor >= EH) { badge = 'LAUNCH PAD';    badgeClass = 'park-hitter-extreme'; }
  else if (d.runFactor >= H)  { badge = "HITTER'S PARK"; badgeClass = 'park-hitter'; }
  else if (d.runFactor <= EP) { badge = "PITCHER'S PARK";badgeClass = 'park-pitcher-extreme'; }
  else if (d.runFactor <= P)  { badge = "PITCHER'S PARK";badgeClass = 'park-pitcher'; }
  const runDiff = d.runFactor - 100;
  const context = `${d.label}: ${runDiff>0?'+':''}${runDiff}% runs · HR factor ${d.hrFactor}`;
  return { ...d, badge, badgeClass, context };
}

// Mirrors mlb-weekly-update.py's name_key() EXACTLY, including its
// known quirk: " ii" is stripped before " iii", and " ii" is a substring
// prefix of " iii", so a real "Player III" input produces "playeri" (not
// "player") — verified bug-for-bug identical via cross-check against the
// real Python function (CC-CMD-2026-07-01 sprintspeed-key-fix). This is
// intentional: the client must match whatever key the data generator
// ACTUALLY produces, not an idealized "corrected" version — a client-side
// fix that produces the "right" key would silently break lookups the
// moment a real Player III enters PLAYER_SPEED/PITCHER_TEMPO/etc. Does
// NOT strip " iv" — Python's name_key() doesn't either (confirmed: real
// pitch_tempo.json key "lynch_iv" keeps the suffix).
function _mlbPlayerKey(playerLastName) {
  let s = String(playerLastName || '').toLowerCase();
  s = s.split(',')[0].trim();
  s = s.replace(' jr.', '').replace(' sr.', '').replace(' ii', '').replace(' iii', '');
  return s.replace(/[\s-]/g, '_');
}

// Shared by any call site that needs to key into PITCHER_ARSENAL/
// PITCHER_TEMPO, which are last-name-only. Both scouting-report call
// sites (starting pitcher) and the At-Bat Edge call site (live current
// pitcher) need this — same bug class fixed twice before this helper
// existed (CC-CMD-2026-07-01 scouting-report-arsenal + -tempo-fix).
// Fixed 2026-07-01 (sprintspeed-key-fix): .split(' ').pop() alone
// returned the wrong word entirely for a suffixed full name — e.g.
// "Bobby Witt Jr." -> "Jr." instead of "Witt". Now reattaches a
// recognized trailing suffix token to the preceding word (e.g. returns
// "Witt Jr." or "Lynch IV", not just "Witt"/"Lynch") and lets
// _mlbPlayerKey() decide what to strip — it must NOT discard "IV" here,
// since _mlbPlayerKey() deliberately keeps IV (matching name_key(), a
// real key is "lynch_iv") while stripping jr/sr/ii/iii.
const _MLB_SUFFIX_TOKENS = new Set(['jr','jr.','sr','sr.','ii','iii','iv']);
function lastNameOf(fullNameOrObj) {
  const raw = typeof fullNameOrObj === 'string'
    ? fullNameOrObj
    : (fullNameOrObj?.name || fullNameOrObj?.lastName || fullNameOrObj?.fullName || '');
  const parts = raw.split(' ').filter(Boolean);
  if (parts.length > 1 && _MLB_SUFFIX_TOKENS.has(parts[parts.length - 1].toLowerCase())) {
    const suffix = parts.pop();
    return `${parts.pop() || ''} ${suffix}`.trim();
  }
  return parts.pop() || '';
}

function getPitchTempo(pitcherLastName) {
  if (!pitcherLastName) return null;
  const d = PITCHER_TEMPO[_mlbPlayerKey(pitcherLastName)];
  if (!d) return null;
  const badge = d.tempoClass === 'Fast' ? 'QUICK TEMPO' : d.tempoClass === 'Slow' ? 'SLOW TEMPO' : null;
  return { ...d, badge, context: `${d.tempoClass} tempo (${d.medianTempo}s · ${d.timerEquiv}s timer equiv)` };
}

function getPitchArsenal(pitcherLastName, topN) {
  if (!pitcherLastName) return null;
  const d = PITCHER_ARSENAL[_mlbPlayerKey(pitcherLastName)];
  if (!d?.pitches?.length) return null;
  const best = d.pitches.slice(0, topN || 3);
  // Savant pitch-arsenal-stats has no velocity column — runValuePer100 replaces
  // it as the pitch-quality metric (CC-CMD-2026-07-01 avv-savant).
  const parts = best.map(p => {
    const rv = p.runValuePer100 != null ? `${p.runValuePer100 > 0 ? '+' : ''}${p.runValuePer100} RV/100` : 'n/a RV';
    const whiffStr = p.whiffRate != null ? `${Math.round(p.whiffRate*100)}% K` : 'n/a whiff';
    return `${p.type} ${rv} (${whiffStr})`;
  });
  const topWhiff = [...d.pitches].sort((a,b)=>(b.whiffRate??-1)-(a.whiffRate??-1))[0];
  return { pitches:d.pitches, topWhiff, context:`Arsenal: ${parts.join(' · ')}` };
}

// Compound prompt context for MLB games (injected into gameLines)
function getMLBAnalyticsContext(game) {
  const lines = [];
  if (!(game?._sport||'').toLowerCase().includes('baseball')) return lines;
  try {
    // G1 Park factor
    const pf = getParkFactor(game._homeAbbr || game.homeTeam);
    if (pf?.badge) lines.push(`  Park: [${pf.badge}] ${pf.context}`);

    // A1 HP umpire ABS
    const umpName = game._hpUmpire || game.umpire || '';
    if (umpName) {
      const ump = getUmpireABSRating(umpName.split(' ').pop());
      if (ump) lines.push(`  Ump: ${ump.badge?'['+ump.badge+'] ':''}${umpName} ${ump.context}`);
    }

    // C1 Arsenal + C7 Tempo (home pitcher)
    for (const pitcher of [game.homePitcher, game.awayPitcher].filter(Boolean)) {
      const last = (pitcher.lastName||pitcher.fullName||'').split(' ').pop().toLowerCase();
      const arsenal = getPitchArsenal(last);
      const tempo = getPitchTempo(last);
      const who = pitcher.lastName || last;
      if (arsenal) lines.push(`  ${who}: ${arsenal.context.replace('Arsenal: ','')}`);
      if (tempo?.badge) lines.push(`  ${who} pace: [${tempo.badge}] ${tempo.context}`);
    }
  } catch(e) { captureFieldError('mlb:analytics-context', e, true); }
  return lines.slice(0,4); // max 4 lines per game
}

// Card badge HTML for park factor
function buildParkFactorBadge(game) {
  if (!(game?._sport||'').toLowerCase().includes('baseball')) return '';
  const pf = getParkFactor(game._homeAbbr || game.homeTeam);
  if (!pf?.badge) return '';
  return `<span class="mlb-park-badge mlb-park-${pf.badgeClass}" title="${pf.context}">${pf.badge}</span>`;
}

// Card badge HTML for ump watch
function buildUmpWatchBadge(game) {
  if (!(game?._sport||'').toLowerCase().includes('baseball')) return '';
  const umpName = game._hpUmpire || game.umpire || '';
  if (!umpName) return '';
  const ump = getUmpireABSRating(umpName.split(' ').pop());
  if (!ump?.badge) return '';
  return `<span class="mlb-ump-badge" title="${ump.context}">[${ump.badge}]</span>`;
}

// ── buildRoundBadge: round label + aggregate score for playoff/tournament games ──
// Renders when game.round is a non-empty string (NBA "Finals", NHL "Stanley Cup Final",
// UFL "Playoff Eliminator", MLS "Quarterfinal", soccer "1st Leg"/"2nd Leg", etc.).
// Part B: also shows "Agg: X-Y" when game.series has both aggregates and leg !== 1.
function buildRoundBadge(game) {
  if (!game?.round) return '';
  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  let html = `<span class="round-badge">${esc(game.round)}</span>`;
  const s = game.series;
  if (s?.homeAggregate != null && s?.awayAggregate != null && s.leg !== 1) {
    html += `<span class="round-badge">Agg: ${s.homeAggregate}-${s.awayAggregate}</span>`;
  }
  return html;
}

// ── _buildAnalyticsChips: R2 data → chip HTML for a game ─────────────────────
// Used by Scout's Pick brief footer (Option A) and Analytics Edge desk card (Option C).
// Returns array of {html, cls} objects for chip rendering.
// Only includes signals that are loaded and above noise threshold.
function _buildAnalyticsChips(game) {
  const chips = [];
  const sp = (_gameSport(game)).toLowerCase();

  // NHL: series-adjusted PP%/PK% + PDO
  if (sp.includes('nhl') || sp.includes('hockey')) {
    const ha = game._homeAbbr || getNHLAbbrev?.(game.home) || '';
    const aa = game._awayAbbr || getNHLAbbrev?.(game.away) || '';
    const hST = ha ? getNHLEffectiveST?.(ha) : null;
    const aST = aa ? getNHLEffectiveST?.(aa) : null;
    if (hST?.isSeries) {
      if (hST.effectivePK != null)
        chips.push({ label: `${ha} PK ${hST.effectivePK.toFixed(1)}%`, cls: 'dac-teal', tip: hST.pkContext });
      if (hST.seriesPDO != null) {
        const hot  = hST.seriesPDO > 1.010;
        const cold = hST.seriesPDO < 0.990;
        if (hot || cold)
          chips.push({ label: `${ha} PDO ${hST.seriesPDO.toFixed(3)} ${hot?'↑':'↓'}`, cls: 'dac-amber',
            tip: hot ? 'Running hot — regression possible' : 'Running cold — improvement likely' });
      }
    }
    if (aST?.isSeries) {
      if (aST.effectivePP != null && aST.effectivePP >= 18)
        chips.push({ label: `${aa} PP ${aST.effectivePP.toFixed(1)}%`, cls: 'dac-teal', tip: aST.ppContext });
      if (aST.seriesPDO != null) {
        const hot  = aST.seriesPDO > 1.010;
        const cold = aST.seriesPDO < 0.990;
        if (hot || cold)
          chips.push({ label: `${aa} PDO ${aST.seriesPDO.toFixed(3)} ${hot?'↑':'↓'}`, cls: 'dac-amber',
            tip: hot ? 'Running hot — regression possible' : 'Running cold — improvement likely' });
      }
    }
    // GSAX for starting goalies
    for (const [lastName, side] of [[game._homeGoalie, 'home'], [game._awayGoalie, 'away']]) {
      if (!lastName) continue;
      const key = lastName.toLowerCase().replace(/[^a-z]/g, '');
      const g   = NHL_GOALIE_RATINGS?.[key];
      if (g?._gsax != null && Math.abs(g._gsax) >= 0.8) {
        const pos = g._gsax > 0 ? '+' : '';
        chips.push({ label: `${lastName} GSAX ${pos}${g._gsax.toFixed(1)}`, cls: g._gsax >= 1.5 ? 'dac-teal' : 'dac-muted',
          tip: `${pos}${g._gsax.toFixed(1)} goals saved above expected this playoffs` });
      }
    }
  }

  // NBA: team clutch DRTG
  if (sp.includes('nba') || sp.includes('basketball')) {
    const hStats = getNBATeamAnalytics?.(game.home);
    const aStats = getNBATeamAnalytics?.(game.away);
    // clutchDrtg can come from a hardcoded stub (OKC/NYK) rather than the
    // nbaCluichInit relay overlay — unlike the NHL series/GSAX chips above,
    // there's no per-team null-gate that proves this value is live, so a
    // relay failure is otherwise invisible here. Flag it in the tooltip.
    const _clutchStale = !_nbaCluichLoaded ? ' · unverified stub, relay data unavailable' : '';
    if (hStats?.clutchDrtg != null) {
      const elite = hStats.clutchDrtg <= 106;
      chips.push({ label: `${(game.home||'').split(' ').pop()} clutch DRTG ${hStats.clutchDrtg.toFixed(1)}`,
        cls: elite ? 'dac-blue' : 'dac-muted',
        tip: `${hStats.clutchDrtg.toFixed(1)} defensive rating in last 5 min, within 5 pts${_clutchStale}` });
    }
    if (aStats?.clutchDrtg != null) {
      const elite = aStats.clutchDrtg <= 106;
      chips.push({ label: `${(game.away||'').split(' ').pop()} clutch DRTG ${aStats.clutchDrtg.toFixed(1)}`,
        cls: elite ? 'dac-blue' : 'dac-muted',
        tip: `${aStats.clutchDrtg.toFixed(1)} defensive rating in late close situations${_clutchStale}` });
    }
  }

  return chips;
}

// ── MLB Probable Pitcher Init — two-phase ────────────────────────────────────
// Phase 1 (T+4100ms): Schedule call → pitcher IDs keyed by home team name.
// Phase 2 (T+4300ms): Parallel stats calls → ERA/K9/WHIP per pitcher ID.
// getStatOfDay() reads synchronously from _mlbPitcherStatsCache.
//
// Source: MLB Stats API via /mlb-stats/schedule + /mlb-stats/people/{id}/stats
// Verified: both endpoints HTTP 200 through relay (June 10 2026).
// Rule: /schedule added to MLB_STATS_API_ALLOWED_PREFIXES June 10 2026.
//
// League averages (2026 MLB starting pitchers):
const _MLB_PITCHER_AVGS = { era: 4.55, k9: 8.50, whip: 1.30 };

// Caches persisted in memory (session lifetime)
let _mlbPitcherIdCache   = {};  // { homeTeamName: { homeId, homeName, awayId, awayName } }
let _mlbPitcherStatsCache = {};  // { pitcherId: { era, k9, whip, gamesStarted, fullName } }
let _mlbPitcherInitPhase = 0;   // 0=uninit, 1=ids-loaded, 2=stats-loaded

// _relayInitStatus (CC-CMD-2026-07-11-relay-init-staleness-visibility):
// shared, checkable record of whether each relay-overlay function's most
// recent attempt succeeded or failed. All 9 functions below share this
// one pattern -- fetch fresh analytics to overlay a hardcoded stub, and
// previously failed with zero trace anywhere. Records BOTH success and
// failure at every real outcome point, never leaves a function's status
// as an unknown third case. Does not change any of the 9 functions'
// actual fetch/overlay logic or remove their try/catch -- purely
// additive instrumentation, the graceful-degradation behavior itself is
// unchanged and correct.
window._relayInitStatus = window._relayInitStatus || {};
function _recordRelayInit(name, ok, error) {
  window._relayInitStatus[name] = { ok: !!ok, at: new Date().toISOString(), error: error || null };
}

async function mlbProbablePitcherInit() {
  if (_mlbPitcherInitPhase >= 1) return;
  try {
    const today = new Date().toISOString().slice(0,10);
    const r = await fetch(
      `${MLB_STATS_RELAY}/schedule?sportId=1&date=${today}&hydrate=probablePitcher`,
      { signal: AbortSignal.timeout(5000) }
    );
    if (!r.ok) { _recordRelayInit('mlbProbablePitcherInit', false, `HTTP ${r.status}`); return; }
    const data = await r.json();
    const games = data?.dates?.[0]?.games || [];
    for (const g of games) {
      const homeTeam = g.teams?.home?.team?.name || '';
      const awayTeam = g.teams?.away?.team?.name || '';
      if (!homeTeam) continue;
      const homeP = g.teams?.home?.probablePitcher;
      const awayP = g.teams?.away?.probablePitcher;
      _mlbPitcherIdCache[homeTeam] = {
        homeId:   homeP?.id   ?? null,
        homeName: homeP?.fullName ?? null,
        awayId:   awayP?.id   ?? null,
        awayName: awayP?.fullName ?? null,
        awayTeam,
      };
    }
    _mlbPitcherInitPhase = 1;
    _recordRelayInit('mlbProbablePitcherInit', true);
    if (FIELD_DEBUG) console.log('[FIELD] MLB pitcher IDs loaded:', Object.keys(_mlbPitcherIdCache).length, 'games');
  } catch(e_) { _recordRelayInit('mlbProbablePitcherInit', false, e_?.message || 'error'); }
}

async function mlbPitcherStatsInit() {
  if (_mlbPitcherInitPhase < 1 || _mlbPitcherInitPhase >= 2) return;
  try {
    // Collect all unique pitcher IDs from tonight's games
    const ids = new Set();
    for (const v of Object.values(_mlbPitcherIdCache)) {
      if (v.homeId) ids.add(v.homeId);
      if (v.awayId) ids.add(v.awayId);
    }
    if (!ids.size) return;
    const today = new Date().toISOString().slice(0,4); // "2026"
    // Fetch all pitcher stats in parallel
    const results = await Promise.allSettled([...ids].map(async id => {
      const r = await fetch(
        `${MLB_STATS_RELAY}/people/${id}/stats?stats=season&group=pitching&season=${today}`,
        { signal: AbortSignal.timeout(4000) }
      );
      if (!r.ok) return;
      const data = await r.json();
      const stat = data?.stats?.[0]?.splits?.[0]?.stat;
      const player = data?.stats?.[0]?.splits?.[0]?.player;
      if (!stat) return;
      _mlbPitcherStatsCache[id] = {
        fullName:     player?.fullName ?? '',
        era:          parseFloat(stat.era) || null,
        k9:           parseFloat(stat.strikeoutsPer9Inn) || null,
        whip:         parseFloat(stat.whip) || null,
        gamesStarted: parseInt(stat.gamesStarted) || 0,
        strikeouts:   parseInt(stat.strikeOuts) || 0,
        inningsPitched: parseFloat(stat.inningsPitched) || 0,
      };
    }));
    _mlbPitcherInitPhase = 2;
    const _mlbPSLoaded = Object.keys(_mlbPitcherStatsCache).length;
    _recordRelayInit('mlbPitcherStatsInit', _mlbPSLoaded > 0, _mlbPSLoaded > 0 ? null : `0/${ids.size} pitchers loaded`);
    if (FIELD_DEBUG) console.log('[FIELD] MLB pitcher stats loaded:', _mlbPSLoaded, 'pitchers');
  } catch(e_) { _recordRelayInit('mlbPitcherStatsInit', false, e_?.message || 'error'); }
}

// Returns { home, away } pitcher stats objects for a game, or null if not loaded.
// home/away: { fullName, era, k9, whip, gamesStarted } | null
function getMLBProbablePitchers(homeTeamName) {
  if (_mlbPitcherInitPhase < 2) return null;
  const ids = _mlbPitcherIdCache[homeTeamName];
  if (!ids) return null;
  return {
    home: ids.homeId ? (_mlbPitcherStatsCache[ids.homeId] || null) : null,
    away: ids.awayId ? (_mlbPitcherStatsCache[ids.awayId] || null) : null,
    homeName: ids.homeName,
    awayName: ids.awayName,
  };
}

// ── mlbStatsInit: loads weekly-updated JSON tables from relay + patches hardcoded stubs ──
// Source: mlb-weekly-update.yml → outbox/mlb/ → /mlb-stats/* relay
// Called at startup T+4000ms. Silent on failure (hardcoded stubs remain as fallback).
// Each JSON file: { updated: ISO_TS, data: { key: {...} } }
const _MLB_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev';
let _mlbStatsLoaded = false;

async function mlbStatsInit() {
  if (_mlbStatsLoaded) return;
  // team_abs/expected_stats/sprint_speed removed 2026-07-12 (Rule 63 dead-
  // code cleanup): their sole consumers (getTeamABSRanking, getRegressionAlert,
  // getSprintSpeed) had zero call sites anywhere in the file -- confirmed via
  // direct grep, not assumed. TEAM_ABS_RANKINGS/PLAYER_EXPECTED_STATS/
  // PLAYER_SPEED and their getters removed together with these fetch entries.
  const FILES = [
    ['pitch_tempo',    d => { Object.assign(PITCHER_TEMPO,         d); }],
    ['pitch_arsenals', d => { Object.assign(PITCHER_ARSENAL,       d); }],
  ];
  let loaded = 0;
  await Promise.allSettled(FILES.map(async ([name, apply]) => {
    try {
      const resp = await fetch(`${_MLB_RELAY}/mlb-stats/${name}.json`);
      if (!resp.ok) return;
      const json = await resp.json();
      const data = json.data || json;
      if (data && typeof data === 'object') { apply(data); loaded++; }
    } catch(e) {}
  }));
  // UMPIRE_ABS_RATINGS deliberately does NOT get a runtime patch here, unlike
  // its 2 siblings above (CC-CMD-2026-07-10-mlb-umpire-abs-sync TASK 0):
  // /mlb-umpire-scrape confirmed live-broken (502 "Savant returned HTTP 500",
  // 4/4 real checks) -- the same Savant-blocks-Cloudflare-Worker-IPs issue
  // that motivated the Statcast-CSV pipeline above in the first place. Its
  // freshness now comes solely from the weekly CI regeneration
  // (scripts/sync-umpire-abs-ratings.js) into the static constant.
  _mlbStatsLoaded = true;
  _recordRelayInit('mlbStatsInit', loaded > 0, loaded > 0 ? null : 'both Savant tables failed');
  if (loaded > 0 && FIELD_DEBUG) console.log(`[FIELD] MLB stats loaded: ${loaded}/2 tables (Savant)`);
}

// ── nbaPlayerCluichInit: fetches live playoff clutch stats per player ─────────
// Replaces [VERIFY playoffs 2026] hardcoded estimates in NBA_CLUTCH_PLAYERS.
// Source: /nba-stats/leaguedashplayerclutch (whitelisted, relay-proxied, June 10 2026).
// Matches by lastName + TEAM_ABBREVIATION to handle Williams/Johnson collisions.
// Minimum 3 GP filter eliminates noise from single-game samples.
//
// Called at T+4700ms alongside team clutch init — same request batch (stats.nba.com).
const NBA_STATS_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/nba-stats';
let _nbaPlayerCluichLoaded = false;

async function nbaPlayerCluichInit() {
  if (_nbaPlayerCluichLoaded) return;
  try {
    const params = new URLSearchParams({
      LeagueID:'00', Season:'2025-26', SeasonType:'Playoffs',
      PerMode:'PerGame', MeasureType:'Base',
      ClutchTime:'Last 5 Minutes', AheadBehind:'Ahead or Behind', PointDiff:'5',
      PlusMinus:'N', PaceAdjust:'N', Rank:'N',
      Outcome:'', Location:'', Month:'0', SeasonSegment:'',
      DateFrom:'', DateTo:'', OpponentTeamID:'0',
      VsConference:'', VsDivision:'', GameSegment:'',
      Period:'0', ShotClockRange:'', LastNGames:'0',
      GameScope:'', PlayerExperience:'', PlayerPosition:'',
      StarterBench:'', TwoWay:'0', Conference:'', Division:'',
    });
    const r = await fetch(
      `${NBA_STATS_RELAY}/leaguedashplayerclutch?${params}`,
      { signal: AbortSignal.timeout(12000) }
    );
    if (!r.ok) { _recordRelayInit('nbaPlayerCluichInit', false, `HTTP ${r.status}`); return; }
    const data = await r.json();
    const rs = data?.resultSets?.[0];
    if (!rs) { _recordRelayInit('nbaPlayerCluichInit', false, 'no resultSets in response'); return; }

    const hdrs = rs.headers;
    const idx = Object.fromEntries(hdrs.map((h, i) => [h, i]));
    const rows = rs.rowSet;

    // Build lookup: "brunson|NYK" → row
    const byKey = {};
    for (const row of rows) {
      const gp = row[idx.GP] ?? 0;
      if (gp < 3) continue;                          // filter noise
      const fullName = (row[idx.PLAYER_NAME] || '');
      const lastName = fullName.split(' ').pop().toLowerCase().replace(/[^a-z-]/g, '');
      const team     = row[idx.TEAM_ABBREVIATION] || '';
      byKey[`${lastName}|${team}`] = row;
      byKey[lastName] = byKey[lastName] || row;      // fallback for unique last names
    }

    // Tier calculation from live data
    function deriveTier(pts, fg, pm, wPct) {
      if (pts >= 6 && fg >= 0.46 && pm > 8)  return 'elite';
      if (pts >= 4 && fg >= 0.43 && pm > 3)  return 'solid';
      if (pm < -5)                             return 'unreliable';
      return 'avg';
    }

    let updated = 0;
    for (const [key, entry] of Object.entries(NBA_CLUTCH_PLAYERS)) {
      const team    = entry.team || '';
      const teamKey = `${key}|${team}`;
      const row     = byKey[teamKey] || byKey[key];
      if (!row) continue;

      const pts  = row[idx.PTS]      ?? null;
      const fg   = row[idx.FG_PCT]   ?? null;
      const pm   = row[idx.PLUS_MINUS] ?? null;
      const wPct = row[idx.W_PCT]    ?? null;
      const gp   = row[idx.GP]       ?? 0;

      if (pts === null || fg === null) continue;

      const pmStr   = pm != null ? (pm >= 0 ? `+${pm.toFixed(1)}` : pm.toFixed(1)) : entry.plusMinus;
      const newTier = deriveTier(pts, fg, pm ?? 0, wPct ?? 0.5);

      // Patch stats; preserve editorial note
      entry.clutchPts  = Math.round(pts * 10) / 10;
      entry.clutchFg   = Math.round(fg * 1000) / 1000;
      entry.plusMinus  = pmStr;
      entry.tier       = newTier;
      entry.gp         = gp;
      entry._live      = true;   // flag: this entry is now from live 2026 playoff data
      updated++;
    }

    _nbaPlayerCluichLoaded = true;
    _recordRelayInit('nbaPlayerCluichInit', true);
    if (FIELD_DEBUG) console.log(`[FIELD] NBA player clutch loaded: ${updated} of ${Object.keys(NBA_CLUTCH_PLAYERS).length} entries updated`);
  } catch(e_) { _recordRelayInit('nbaPlayerCluichInit', false, e_?.message || 'error'); }
}

// ── nhlSeriesInit: loads SCF series-adjusted PP%/PK% from R2 via relay ──────
// Overlays series-specific rates onto NHL_SPECIAL_TEAMS for journalism/Scout's Pick.
// Pattern: same as mlbStatsInit — silent on failure, stubs remain as fallback.
// Called at T+4500ms alongside other analytics inits.
const _NHL_SERIES_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/nhl-series/scf-2026/stats';
let _nhlSeriesLoaded = false;
async function nhlSeriesInit() {
  if (_nhlSeriesLoaded) return;
  try {
    const r = await fetch(_NHL_SERIES_RELAY, { signal: AbortSignal.timeout(5000) });
    if (!r.ok) { _recordRelayInit('nhlSeriesInit', false, `HTTP ${r.status}`); return; }
    const data = await r.json();
    const teams = data.teams || {};
    // Overlay series-adjusted rates onto NHL_SPECIAL_TEAMS
    for (const [abbr, s] of Object.entries(teams)) {
      if (!NHL_SPECIAL_TEAMS[abbr]) NHL_SPECIAL_TEAMS[abbr] = {};
      if (s.seriesPP != null) NHL_SPECIAL_TEAMS[abbr]._seriesPP  = s.seriesPP;
      if (s.seriesPK != null) NHL_SPECIAL_TEAMS[abbr]._seriesPK  = s.seriesPK;
      if (s.seriesPDO!= null) NHL_SPECIAL_TEAMS[abbr]._seriesPDO = s.seriesPDO;
      if (s.ppLabel)  NHL_SPECIAL_TEAMS[abbr]._ppLabel   = s.ppLabel;
      if (s.pkLabel)  NHL_SPECIAL_TEAMS[abbr]._pkLabel   = s.pkLabel;
      if (s.pdoLabel) NHL_SPECIAL_TEAMS[abbr]._pdoLabel  = s.pdoLabel;
    }
    _nhlSeriesLoaded = true;
    _recordRelayInit('nhlSeriesInit', true);
    if (FIELD_DEBUG) console.log('[FIELD] NHL series stats loaded:', Object.keys(teams));
  } catch(e_) { _recordRelayInit('nhlSeriesInit', false, e_?.message || 'error'); }
}

