// Load saved services from localStorage
function loadMyServices(){
  try{ return new Set(JSON.parse(localStorage.getItem("field_my_services")||"[]")); }
  catch(e){ return new Set(); }
}
function saveMyServices(set){
  try{ localStorage.setItem("field_my_services", JSON.stringify([...set])); }
  catch(e){ if(FIELD_DEBUG) console.debug("FIELD: localStorage unavailable (private mode?)"); }
}
let MY_SERVICES = loadMyServices();

// Render the setup modal body
// ── Journalism Quality section (My Services modal) ───────────────────────────
// Surfaces JQ pipeline state — never in the brief UI, only here in admin.
// Subsections: aggregate scores · per-label rolling avgs · recent voice
// violations · phrases flagged · session banned extension.
// Data sources: localStorage field_jq_scores + field_jq_review,
// sessionStorage field_jq_banned_ext. No tap interactions — read-only diagnostic.
function buildJournalismQualitySection(){
  let scores = [], review = [], ext = [];
  try { scores = JSON.parse(localStorage.getItem('field_jq_scores')||'[]'); } catch(_){}
  try { review = JSON.parse(localStorage.getItem('field_jq_review')||'[]'); } catch(_){}
  try { ext = JSON.parse(sessionStorage.getItem('field_jq_banned_ext')||'[]'); } catch(_){}

  const fmtSubLabel = (txt) => `<div class="jq-sublabel">${txt}</div>`;
  const fmtEmpty = (txt) => `<span class="jq-empty">${txt}</span>`;
  const escapeHtml = (s) => String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]);

  // 1. Aggregate
  let aggHtml;
  if(scores.length){
    const total = scores.reduce((a,s)=>a+s.score,0);
    const avg = Math.round(total/scores.length);
    const best = Math.max(...scores.map(s=>s.score));
    const worst = Math.min(...scores.map(s=>s.score));
    const stat = Math.round((scores.reduce((a,s)=>a+(s.stat||0),0)/scores.length)*10)/10;
    aggHtml = `<div class="jq-row"><span class="jq-k">avg</span><span class="jq-v">${avg}/300</span><span class="jq-k">best</span><span class="jq-v">${best}</span><span class="jq-k">worst</span><span class="jq-v">${worst}</span><span class="jq-k">stat</span><span class="jq-v">${stat}/s</span><span class="jq-k">n</span><span class="jq-v">${scores.length}</span></div>`;
  } else {
    aggHtml = fmtEmpty('no briefs scored yet');
  }

  // 2. Per-label rolling avgs (last 5 per label)
  let perLabelHtml = '';
  if(scores.length){
    const byLabel = {};
    scores.forEach(s=>{ (byLabel[s.label] = byLabel[s.label] || []).push(s.score); });
    const labels = Object.keys(byLabel).sort();
    perLabelHtml = labels.map(lbl=>{
      const last5 = byLabel[lbl].slice(-5);
      const avg = Math.round(last5.reduce((a,b)=>a+b,0)/last5.length);
      return `<div class="jq-row"><span class="jq-k">${escapeHtml(lbl)}</span><span class="jq-v">${avg}/300</span><span class="jq-meta">(${last5.length} of ${byLabel[lbl].length})</span></div>`;
    }).join('');
  } else {
    perLabelHtml = fmtEmpty('no per-label history yet');
  }

  // 3. Voice violations (type:'voice', last 5)
  const voice = review.filter(r=>r.type==='voice').slice(-5).reverse();
  let voiceHtml;
  if(voice.length){
    voiceHtml = voice.map(v=>{
      const sport = escapeHtml((v.sport||'').toUpperCase());
      const lbl = escapeHtml(v.label||'');
      const phrases = (v.phrases||[]).map(p=>`<span class="jq-tag jq-tag-voice">${escapeHtml(p)}</span>`).join('');
      return `<div class="jq-row jq-row-stack"><div><span class="jq-k">${sport} VOICE</span><span class="jq-meta">${lbl}</span></div><div>${phrases}</div></div>`;
    }).join('');
  } else {
    voiceHtml = fmtEmpty('none — sport vocabulary clean');
  }

  // 4. Phrases flagged (non-voice, last 5)
  const phrases = review.filter(r=>r.type!=='voice').slice(-5).reverse();
  let phrasesHtml;
  if(phrases.length){
    phrasesHtml = phrases.map(p=>{
      const lbl = escapeHtml(p.label||'');
      const sc = p.score != null ? `<span class="jq-meta">score ${p.score}</span>` : '';
      const tags = (p.phrases||[]).map(ph=>`<span class="jq-tag">${escapeHtml(ph)}</span>`).join('');
      return `<div class="jq-row jq-row-stack"><div><span class="jq-k">${lbl}</span>${sc}</div><div>${tags}</div></div>`;
    }).join('');
  } else {
    phrasesHtml = fmtEmpty('no phrases flagged');
  }

  // 5. Session banned extension
  let extHtml;
  if(ext.length){
    extHtml = `<div class="jq-row jq-row-stack"><div><span class="jq-k">${ext.length} active</span><span class="jq-meta">auto-extended this session</span></div><div>${ext.map(p=>`<span class="jq-tag jq-tag-ext">${escapeHtml(p)}</span>`).join('')}</div></div>`;
  } else {
    extHtml = fmtEmpty('inactive — no brief type below avg 45');
  }

  return `<div class="jq-quality-section">
    <div class="jq-section-title">Journalism Quality</div>
    <div class="jq-section-sub">FIELD's prose evaluation for AI briefs. Read-only.</div>
    ${fmtSubLabel('Aggregate')}${aggHtml}
    ${fmtSubLabel('Per brief type · last 5')}${perLabelHtml}
    ${fmtSubLabel('Voice violations · recent')}${voiceHtml}
    ${fmtSubLabel('Phrases flagged · recent')}${phrasesHtml}
    ${fmtSubLabel('Session quality extension')}${extHtml}
  </div>`;
}

// Pick 'em cumulative stats (CC-CMD-2026-07-05-pick-em-ui TASK 4). Reads
// totalMade/totalCorrect/accuracyRate from window._userState, already
// populated by the existing fetchUserState() GET /user/state call -- no
// new relay-calling mechanism. Reuses the Journalism Quality section's
// own CSS classes so this needs zero new styling. Deliberately no
// streak/current-run/consecutive-day element anywhere in this section.
function buildPickEmStatsSection(){
  const st = (typeof window !== 'undefined') ? window._userState : null;
  // Relay nests these three fields under `picks` (confirmed live,
  // GET /user/state response shape) -- not top-level on st.
  const picks = st && st.picks;
  // totalMade/totalCorrect are 0 (not null/undefined) for any initialized
  // user who hasn't picked yet -- confirmed live via /user/state -- so the
  // "has this user made a pick" gate must check totalMade > 0, not != null,
  // or the friendly empty-state copy below would never show for a real
  // zero-picks user.
  const hasStats = picks && picks.totalMade > 0;
  const body = hasStats
    ? `<div class="jq-row"><span class="jq-k">made</span><span class="jq-v">${picks.totalMade ?? 0}</span><span class="jq-k">correct</span><span class="jq-v">${picks.totalCorrect ?? 0}</span><span class="jq-k">accuracy</span><span class="jq-v">${picks.accuracyRate != null ? (picks.accuracyRate * 100).toFixed(0) + '%' : '—'}</span></div>`
    : `<span class="jq-empty">no picks yet — make one from any upcoming game card</span>`;
  return `<div class="jq-quality-section pick-em-section">
    <div class="jq-section-title">Pick 'em</div>
    <div class="jq-section-sub">Your prediction record. Read-only.</div>
    ${body}
  </div>`;
}

function renderSetupBody(){
  const body = document.getElementById("setup-body");
  const intro = body.querySelector(".setup-intro");
  let html = "";
  SETUP_CATALOGUE.forEach(group=>{
    html += `<div class="setup-group-label">${group.group}</div><div class="setup-services">`;
    group.services.forEach(svc=>{
      const sr = SR[svc.key];
      const col = sr ? sr[2] : "#888";
      const sel = MY_SERVICES.has(svc.key);
      html += `<div class="setup-svc${sel?" selected":""}" data-key="${svc.key}">
        <div class="setup-svc-dot" style="background:${col}"></div>
        ${svc.label}
        <span class="setup-svc-check">✓</span>
      </div>`;
    });
    html += `</div>`;
  });
  // Append after intro
  const existing = body.querySelectorAll(".setup-group-label,.setup-services,.jq-quality-section");
  existing.forEach(el=>el.remove());
  body.insertAdjacentHTML("beforeend", html);
  body.insertAdjacentHTML("beforeend", buildJournalismQualitySection());
  body.insertAdjacentHTML("beforeend", buildPickEmStatsSection());
  // Refresh from /user/state so stats reflect any picks resolved since the
  // last fetch, then re-render this one section in place once it lands.
  if (typeof fetchUserState === 'function') {
    fetchUserState().then(() => {
      const sec = body.querySelector(".pick-em-section");
      if (sec && typeof buildPickEmStatsSection === 'function') sec.outerHTML = buildPickEmStatsSection();
    }).catch(() => {});
  }

  // Wire toggles
  body.querySelectorAll(".setup-svc").forEach(el=>{
    el.addEventListener("click",()=>{
      const key = el.dataset.key;
      if(MY_SERVICES.has(key)){
        MY_SERVICES.delete(key); el.classList.remove("selected");
      } else {
        MY_SERVICES.add(key); el.classList.add("selected");
        // Package inference: auto-add included channels when vMVPD selected
        if(PACKAGE_INCLUDES[key]){
          const added = PACKAGE_INCLUDES[key].filter(ch=>!MY_SERVICES.has(ch));
          added.forEach(ch=>MY_SERVICES.add(ch));
          if(added.length){
            const msg = document.getElementById('pkg-infer-msg') || Object.assign(document.createElement('div'),{id:'pkg-infer-msg',className:'pkg-infer-msg'});
            msg.textContent = `✓ ${added.length} channels added automatically`;
            document.getElementById('setup-body')?.prepend(msg);
            setTimeout(()=>msg.remove(), 3000);
            saveMyServices(); renderSetupBody(); renderCoverageDashboard(); return;
          }
        }
      }
      saveMyServices(); renderCoverageDashboard();
      updateSetupCount();
    });
  });
  updateSetupCount();
}

function updateSetupCount(){
  const el = document.getElementById("setup-count");
  if(el) el.textContent = MY_SERVICES.size > 0 ? `${MY_SERVICES.size} service${MY_SERVICES.size!==1?"s":""} selected` : "";
}

// RSN market suggestions based on IP geolocation city/region
const MARKET_RSN_HINTS = {
  MD:["masn","masnplus","nationalstv"], DC:["masn","masnplus","nationalstv"],
  VA:["masn","masnplus","nationalstv"], DE:["masn","masnplus"], WV:["masn","masnplus"],
  NY:["yes","sny"], CT:["yes","sny"], NJ:["yes","sny"], PA:["yes","sny","snp"],
  OH:["cleg"], CA:["nbcsca"],
};
function getSuggestedRSNs(){
  try{
    const country = sessionStorage.getItem("field_geo_country")||"US";
    // International market detection — uses country_code from ipapi.co
    const INTL_HINTS = {
      "GB": ["sky","tntsports"],          // UK: Sky Sports, TNT Sports UK
      "AU": ["watchafl","foxfooty","kayosports","sevenplus"], // Australia
      "CA": ["sportsnet"],                // Canada: Rogers Sportsnet/TSN
      "IN": ["jiohotstar","starsports"],  // India: JioHotstar, Star Sports
      "DE": ["dazn"],                     // Germany: DAZN
      "IT": ["dazn"],                     // Italy: DAZN + Sky Italia
      "FR": ["dazn"],                     // France: DAZN
      "MX": ["dazn"],                     // Mexico: DAZN
      "NZ": ["skynz","sparksport"],       // New Zealand
    };
    if(country!=="US" && INTL_HINTS[country]) return INTL_HINTS[country];
    // US market — state-level hints
    const r = sessionStorage.getItem("field_geo_city")||"";
    const state = r.split(", ").pop()?.trim().toUpperCase()||"";
    // City-level disambiguation for split-market states
    const city = (sessionStorage.getItem("field_geo_city_only")||"").toLowerCase();
    if(state==="PA"){
      if(city.includes("pittsburgh")) return ["snp","attrsnpit"];
      return ["nbcsphilly","snp"]; // Default: both Philly and PIT hints
    }
    if(state==="TX"){
      if(city.includes("houston")) return ["schn","rsn"];
      if(city.includes("san antonio")) return ["rsn"];
      return ["rsn","schn"]; // Dallas default
    }
    if(state==="CA"){
      if(city.includes("san francisco")||city.includes("oakland")||city.includes("san jose")) return ["nbcsca","athleticstv"];
      if(city.includes("los angeles")||city.includes("anaheim")) return ["rsn"];
      return ["nbcsca","rsn"];
    }
    if(state==="FL"){
      if(city.includes("miami")||city.includes("fort lauderdale")) return ["marlinstv","rsn"];
      if(city.includes("tampa")||city.includes("st. pete")||city.includes("saint pete")) return ["raystv","rsn"];
      return ["rsn"];
    }
    return MARKET_RSN_HINTS[state]||[];
  }catch(e){ return []; }
}
