const AUTH_LABEL = {tv:"TV login",sub:"Subscription",geo:"Geo-restricted",free:"Free"};

// Native app deeplink schemes — opens app directly on mobile, falls back to web URL
const APP_DEEPLINKS = {
  fox:        "foxsports://",     // Fox Sports app (FIFA World Cup, NFL, MLB on FOX)
  fs1:        "foxsports://",     // Fox Sports app — same scheme as FOX
  trutv:      "trutv://",          // truTV simulcast of TNT NHL games
  espn:       "espn://",
  espnplus:   "espn://",
  abc:        "espn://",          // ABC sports via ESPN app
  nbc:        "peacocktv://",
  peacock:    "peacocktv://",
  nbcsn:      "peacocktv://",
  tnt:        "tntdrama://",
  tbs:        "tbs://",
  max:        "max://",
  paramount:  "paramount://",
  netflix:    "nflx://",
  prime:      "aiv://",           // Amazon Prime Video
  apple:      "videos://",        // Apple TV+
  hulu:       "hulu://",
  fubo:       "fubo://watch",         // Fubo app scheme (iOS/Android)
  youtubetv:  "vnd.youtube.yttv://",  // YouTube TV verified iOS/Android scheme
  sling:      "sling://",
  directv:    "directv://",
  mlbtv:      "mlbapp://",
  mlbn:       "mlbapp://",
  mlbplus:    "mlbapp://",
};
// RSN keys: geo-restricted in-market only — never show green ✓ check
// regardless of whether user has them in My Services
const RSN_KEYS = new Set(["rsn","sny","snp","nbcsca","masn","masnplus","nationalstv","yes","cleg","xfinity"]);
function chipHTML(s, srKey, forcehave){
  // BUG-02 guard: undefined name must never render. Fall back to key or generic label.
  if(!s||!s.name||s.name==='undefined') return '';
  const col=s.col||"#888";
  const auth=s.auth||"sub";
  const haveIt = forcehave || (srKey && MY_SERVICES.has(srKey) && !RSN_KEYS.has(srKey));
  const icon = haveIt ? "" : (RSN_KEYS.has(srKey) ? "📍" : (AUTH_ICON[auth]||"🔒"));
  const tipHeader = haveIt ? "✓ You have access" : (AUTH_LABEL[auth]||"Subscription required");
  const tipBody = haveIt
    ? "Included in your saved services. Click to watch."
    : (s.authNote||"Subscription required");
  // Append price staleness note to any authNote containing a dollar amount
  const hasPriceNote = tipBody.includes("$") || tipBody.includes("/mo") || tipBody.includes("/month");
  const priceNote = hasPriceNote ? "<br><em style=\"opacity:.6;font-size:.9em\">Prices as of 2026 — verify current pricing at service.</em>" : "";
  const haveClass = haveIt ? " have-access" : "";
  // Wow#32: Marginal Cost Display
  const chipCost = !haveIt && auth !== 'free' && SERVICE_COST[srKey]
    ? SERVICE_COST[srKey] + '/mo'
    : null;
  const haveSpan = haveIt
    ? `<span class="chip-have">✓ Included</span>`
    : (chipCost ? `<span class="chip-cost">${chipCost}</span>` : `<span class="chip-have"></span>`);
  const freeBadge = auth === "free" ? `<span class="chip-free-badge">FREE</span>` : "";
  // On mobile/touch: use native app deeplink if available, fall back to web
  const deeplink = APP_DEEPLINKS[srKey]||null;
  const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
  let chipHref = s.url;
  let chipOnClick = "";
  if(deeplink && isMobile){
    // Try to open the native app; if it fails (app not installed), open web URL after 500ms
    chipOnClick = `onclick="event.preventDefault();const fb=setTimeout(()=>window.open('${s.url}','_blank'),1200);window.location.href='${deeplink}';clearTimeout(fb)"`;
    chipHref = s.url; // keep as fallback
  }
  return `<a class="stream-chip${haveClass}" data-srkey="${srKey}" aria-label="${s.name}: ${haveIt?"You have access":auth==="free"?"FREE":"Subscription required"}" style="color:${col};border-color:${col};background:${haveIt?col+"2a":col+"1a"}" href="${chipHref}" target="_blank" rel="noopener" ${chipOnClick}
    >${s.name}${freeBadge}${haveSpan}<span class="chip-auth auth-${auth}">${icon}</span><span class="chip-tip"><strong>${tipHeader}</strong><br>${tipBody}${priceNote}</span></a>`;
}


// ── Mobile Smart Stream Chip ──────────────────────────────────────────────────
// At ≤600px (phone), show ONE chip: prioritise what the user owns,
// then free OTA, then free cable, then cheapest paid option.
// This preserves the key decision ("can I watch this?") in minimum space.
function buildMobileSmartChip(streams) {
  if (!streams || !streams.length) return '';
  const resolved = streams.map(s => {
    const key = typeof s === 'string' ? s : (s.key || '');
    const sr = typeof s === 'string' ? SR[s] : (SR[key] || s);
    return { key, sr };
  }).filter(x => x.sr);

  // Priority 1: a service the user owns
  const owned = resolved.find(({ key }) => key && MY_SERVICES.has(key));
  if (owned) return chipHTML(owned.sr, owned.key);

  // Priority 2: free OTA (NBC, ABC, CBS, FOX, CW)
  const freeOTA = resolved.find(({ key }) => FREE_OTA.has(key));
  if (freeOTA) return chipHTML(freeOTA.sr, freeOTA.key);

  // Priority 3: free-with-cable (ESPN, TNT, etc)
  const freeCable = resolved.find(({ key }) => FREE_CABLE.has(key));
  if (freeCable) return chipHTML(freeCable.sr, freeCable.key);

  // Priority 4: cheapest streamer — lowest SERVICE_COST
  const paid = resolved
    .filter(({ key }) => SERVICE_COST[key])
    .sort((a, b) => (parseFloat(SERVICE_COST[a.key]) || 999) - (parseFloat(SERVICE_COST[b.key]) || 999));
  if (paid.length) return chipHTML(paid[0].sr, paid[0].key);

  // Fallback: first chip
  return chipHTML(resolved[0].sr, resolved[0].key);
}

function streamsHTMLCapped(streams, cap){
  if(!streams||!streams.length) return "";
  const visible = streams.slice(0,cap);
  const extra = streams.length - cap;
  let html = visible.map(s=>{
    const key = typeof s==="string" ? s : s.key;
    const sr = typeof s==="string" ? SR[s] : s;
    if(!sr) return "";
    return chipHTML(sr, key);
  }).join("");
  if(extra > 0){
    html += `<span class="chip-overflow" title="${streams.slice(cap).map(s=>SR[typeof s==="string"?s:s.key]?.name||"").join(", ")}">+${extra}</span>`;
  }
  return html;
}
function streamsHTML(streams){
  const items = resolveStreams(streams);
  const chips = items.map(s=>{
    const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
    return chipHTML(s, srKey, false);
  });

  // If no chip has a green ✓ check (user has none of the services),
  // append an MLB.TV fallback chip — always the out-of-market option
  const anyHave = items.some(s=>{
    const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
    return srKey && MY_SERVICES.has(srKey) && !RSN_KEYS.has(srKey);
  });
  if(!anyHave && MY_SERVICES.size > 0 && SR.mlbtv){
    // Only add if MLB.TV not already in the chip list
    const alreadyHasMlbtv = items.some(s=>s.name==="MLB.TV");
    if(!alreadyHasMlbtv){
      const s = {name:SR.mlbtv[0],url:SR.mlbtv[1],col:SR.mlbtv[2],auth:SR.mlbtv[3],authNote:SR.mlbtv[4]};
      chips.push(chipHTML(s, "mlbtv", false));
    }
  }

  // ── Watch Now button ──
  // Find the first service the user owns; render a prominent CTA above the chips.
  // Suppress owned-service chips — they are redundant once Watch Now is active.
  let watchNowHTML = "";
  let ownedKeys = new Set();
  if(MY_SERVICES.size > 0){
    const owned = items.find(s=>{
      const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
      return srKey && MY_SERVICES.has(srKey) && !RSN_KEYS.has(srKey);
    });
    if(owned){
      // Collect ALL owned service keys so we can suppress their chips
      items.forEach(s=>{
        const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
        if(srKey && MY_SERVICES.has(srKey) && !RSN_KEYS.has(srKey)) ownedKeys.add(srKey);
      });
      const srKey = Object.keys(SR).find(k=>SR[k][0]===owned.name)||"";
      const deeplink = APP_DEEPLINKS[srKey]||null;
      const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
      let watchHref = owned.url;
      let watchClick = "";
      if(deeplink && isMobile){
        watchClick = `onclick="event.preventDefault();const fb=setTimeout(()=>window.open('${owned.url}','_blank'),1200);window.location.href='${deeplink}';clearTimeout(fb)"`;
        watchHref = owned.url;
      }
      watchNowHTML = `<a class="watch-now-btn" href="${watchHref}" target="_blank" rel="noopener" style="border-color:${owned.col};color:${owned.col}" ${watchClick}>▶ Watch on ${owned.name}</a>`;
    }
  }

  // Only render chips for services the user does NOT own
  // (owned services are already covered by the Watch Now button)
  const visibleChips = items
    .filter(s=>{
      const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
      return !ownedKeys.has(srKey); // suppress owned, keep unowned
    })
    .map(s=>{
      const srKey = Object.keys(SR).find(k=>SR[k][0]===s.name)||"";
      return chipHTML(s, srKey, false);
    });

  return watchNowHTML + visibleChips.join("");
}

// ── Multiview ────────────────────────────────────────────────
// ── Game Picker ──────────────────────────────────────────────────────────────
let pickerTargetSlot = null;
let _pickerCacheValid = false; // invalidated by mvAdd/mvRemove/mvClear

function openPicker(slotIndex){
  pickerTargetSlot = slotIndex;
  const _psl = getEl("picker-slot-label"); if(_psl) _psl.textContent = `Slot 0${slotIndex+1}`;
  renderPicker();
  const overlay = document.getElementById("picker-overlay");
  overlay.style.display = "flex";
  overlay.classList.remove("closing");
  // Trap focus inside modal
  overlay.querySelector(".picker-close").focus();
}

function closePicker(){
  const overlay = document.getElementById("picker-overlay");
  overlay.classList.add("closing");
  setTimeout(()=>{ overlay.style.display="none"; overlay.classList.remove("closing"); }, 150);
  pickerTargetSlot = null;
}

let _pickerCache = "";
function renderPicker(){
  const body = document.getElementById("picker-body");
  if(!allData || !allData.sports || !allData.sports.length){
    body.innerHTML = '<div class="picker-empty">No events available</div>';
    return;
  }
  // Rebuild only when pinned state changed; pinnedIds is the only variable
  const pinnedSet = new Set(mvSlots.filter(Boolean).map(g=>g._id));
  const pinnedKey = [...pinnedSet].sort().join(",");
  if(_pickerCacheValid && _pickerCache && body._pinnedKey===pinnedKey){
    body.innerHTML = _pickerCache;
    wirePickerButtons(body);
    return;
  }
  const pinnedIds = pinnedSet;
  let html = "";
  allData.sports.forEach(sec=>{
    const games = (sec.games||[]).filter(g=>g.home); // skip empty entries
    if(!games.length) return;
    const icon = SPORT_ICONS[sec.sport]||SPORT_ICONS.default;
    html += `<div class="picker-sport-group">
      <div class="picker-sport-label">${icon} ${sec.sport}</div>`;
    games.forEach(g=>{
      if(!g._id) g._id="g"+(++_gid);
      const st = getStatus(g.start_time, g._aflComplete!==undefined?{aflComplete:g._aflComplete}:undefined);
      const isLive = st==="live";
      const isSoon = st==="soon";
      // Pre-set espn-live/espn-final based on time — ESPN scores refine this
      // This ensures score-wrap visibility CSS triggers even before ESPN responds
      const pinned = pinnedIds.has(g._id);
      const timeStr = fmtTime(g.start_time);
      // Build matchup string
      const isAm = AMERICAN_SPORTS.has(sec.sport);
      let matchupStr;
      if(!g.away) matchupStr = g.home||"TBD";
      else {
        const [l,r] = isAm ? [g.away,g.home] : [g.home,g.away];
        const sep = isAm ? " @ " : " vs ";
        matchupStr = l + sep + r;
      }
      const liveHTML = isLive
        ? `<span class="picker-live"><span class="live-dot"></span>LIVE</span>`
        : "";
      html += `<button class="picker-game${pinned?" already-pinned":""}"
          data-gid="${g._id}"
          ${pinned?'disabled title="Already in multiview"':''}>
        <div class="picker-game-left">
          <div class="picker-matchup">${matchupStr}</div>
          <div class="picker-league">${g.league||sec.sport}${g.venue?" · "+g.venue:""}</div>
        </div>
        <div class="picker-game-right">
          ${liveHTML}
          <div class="picker-time${isLive?" live-t":""}">${timeStr}</div>
        </div>
      </button>`;
    });
    html += `</div>`;
  });
  if(!html) html = '<div class="picker-empty">No events loaded yet — refresh the schedule</div>';
  body.innerHTML = html;
  _pickerCache = html;
  _pickerCacheValid = true;
  body._pinnedKey = pinnedKey;

  wirePickerButtons(body);
}
function wirePickerButtons(body){
  body.querySelectorAll(".picker-game:not(.already-pinned)").forEach(btn=>{
    btn.addEventListener("click",()=>{
      const gid = btn.dataset.gid;
      let game = null;
      (allData.sports||[]).forEach(s=>(s.games||[]).forEach(g=>{ if(g._id===gid) game=g; }));
      if(game && pickerTargetSlot!==null){
        // Remove from any existing slot first
        const ex = mvSlots.findIndex(s=>s&&s._id===gid);
        if(ex!==-1) mvSlots[ex]=null;
        mvSlots[pickerTargetSlot] = game;
        mvRender(pickerTargetSlot);
        if(ex!==-1) mvRender(ex);
        mvSyncBtns();
        closePicker();
      }
    });
  });
}

// Close on overlay backdrop click
document.getElementById("picker-overlay").addEventListener("click",e=>{
  if(e.target===e.currentTarget) closePicker();
});
document.getElementById("picker-close").addEventListener("click", closePicker);

// Close on Escape key
document.addEventListener("keydown",e=>{ if(e.key==="Escape") closePicker(); });

function mvRender(i){
  const el=document.getElementById("ms"+i);
  const g=mvSlots[i];
  if(!g){
    el.className="mv-slot empty";
    el.innerHTML='<div class="mv-empty-lbl"><span class="mv-empty-plus">+</span><span>Add event</span></div>';
    el.onclick=()=>openPicker(i);
    return;
  }
  const st=getStatus(g.start_time, g._aflComplete!==undefined?{aflComplete:g._aflComplete}:undefined);
  el.className="mv-slot filled"+(st==="live"?" live-s":st==="soon"?" soon-s":"");
  const timeStr=fmtTime(g.start_time);
  const timeClass=st==="live"?"mv-time live-t":"mv-time";
  const livePfx=st==="live"?'<span class="live-badge"><span class="live-dot"></span>LIVE · </span>':"";
  el.innerHTML=`
    <span class="mv-num">0${i+1}</span>
    <button class="mv-rm" data-i="${i}">×</button>
    <div class="mv-slot-body">
      <div class="mv-teams">${(()=>{
        if(!g.away) return g.home;
        const isAm=AMERICAN_SPORTS.has(g._sport||"");
        const [l,r]=isAm?[g.away,g.home]:[g.home,g.away];
        const sep=isAm?' <span style="opacity:.5;font-size:.7em">@</span> ':' <span style="opacity:.4">vs</span> ';
        return l+sep+r;
      })()}</div>
      <div class="mv-league">${g.league||""}</div>
      <div class="${timeClass}">${livePfx}${timeStr}</div>
      <div class="mv-streams">${streamsHTML(g.streams)}</div>
    </div>`;
  el.querySelector(".mv-rm").addEventListener("click",e=>{ e.stopPropagation(); mvRemove(i); });
  el.onclick=null; // filled slots: only × button is interactive
}
function mvRemove(i){ mvSlots[i]=null; mvRender(i); mvSyncBtns(); _pickerCacheValid=false; }
function mvAdd(g){
  const ex=mvSlots.findIndex(s=>s&&s._id===g._id);
  if(ex!==-1){ mvRemove(ex); return; }
  const empty=mvSlots.findIndex(s=>s===null);
  if(empty===-1){
    const p=document.getElementById("mv-panel");
    p.style.transition="background .15s"; p.style.background="rgba(255,68,68,.1)";
    setTimeout(()=>{p.style.background="";},300); return;
  }
  mvSlots[empty]=g; mvRender(empty); mvSyncBtns(); _pickerCacheValid=false;
  // UserDO: pin = high-intent watch signal (fire-and-forget)
  if (typeof recordWatchOpen === 'function') recordWatchOpen(g._id, g._sport || '');
}
function mvSyncMvPanel(){
  const panel = document.getElementById("mv-panel");
  if(!panel) return;
  const hasSlots = mvSlots.some(s => s !== null);
  panel.classList.toggle("mv-empty", !hasSlots);
}
function mvSyncBtns(){
  const inMv=new Set(mvSlots.filter(Boolean).map(g=>g._id));
  document.querySelectorAll(".watch-btn").forEach(btn=>{
    const id=btn.dataset.id;
    btn.classList.toggle("in-mv",inMv.has(id));
    btn.textContent=inMv.has(id)?"✓ In multiview":"+ Multiview";
  });
  // Collapse panel when all slots empty, expand when any slot filled
  const panel = document.getElementById("mv-panel");
  if(panel){
    const anyFilled = mvSlots.some(Boolean);
    panel.classList.toggle("mv-collapsed", !anyFilled);
  }
}
document.getElementById("mv-clear").addEventListener("click",()=>{
  for(let i=0;i<4;i++){ mvSlots[i]=null; mvRender(i); }
  mvSyncBtns(); _pickerCacheValid=false;
});
// Wire onclick for all 4 slots on initial load — mvRender only fires
// on changes (add/remove/clear), so empty slots need explicit init
for(let i=0;i<4;i++) mvRender(i);

// ── Team display convention ─────────────────────────────────────────────────
// American sports: AWAY @ HOME (visiting team listed first)
// European / international: HOME vs AWAY (home team listed first)
// Sports where there is no home/away team — leaderboard format
const INDIVIDUAL_SPORTS = new Set(["Golf","PGA Tour","Formula 1","F1","Tennis","Golf (PGA)","LPGA"]);

// V2_LEAGUES — client-side registry for V2 (relay-backed) league sources.
// Each entry names the underlying sport, the league key the relay routes use,
// the display label, and whether the data flows from ESPN (vs SlashGolf /
// odds-API / other providers). Single source of truth for `golf:pga` so the
// PGA card and the golf journalism prompt agree on the data shape.
//
// SlashGolf coexists as the source for LIV / DP World / LPGA / Champions Tour
// — tours ESPN does not cover. ESPN PGA does NOT replace SlashGolf; both
// cards can render side-by-side. The SLASH_GOLF_DAILY_LIMIT budget governs
// SlashGolf calls only.
const V2_LEAGUES = {
  pga: { sport: 'golf', league: 'pga', label: 'PGA TOUR', espnSource: true },
};

const AMERICAN_SPORTS = new Set([
  "NBA Playoffs","NBA","NHL Playoffs","NHL",
  "Baseball (MLB)","MLB","NFL","WNBA","NCAA Basketball",
  "Canadian Football (CFL)","CFL"
]);
// ESPN CDN logo URL builder
// ESPN serves team logos at a consistent CDN path by sport/team abbreviation
// SportsDB team badge URLs stored in sportsdbTeamLogos map
const sportsdbTeamLogos = {}; // teamName.lower() -> url

function getTeamLogo(teamName, sport){
  const key = (teamName||"").toLowerCase().trim();
  if(sportsdbTeamLogos[key]) return sportsdbTeamLogos[key];
  // Soccer: numeric ESPN IDs → CDN URL (different pattern from abbrev-based sports)
  const SOCCER_SPORT_SET = new Set(["Premier League","La Liga","Ligue 1","Bundesliga","Serie A","MLS Soccer",
    "EFL Championship Playoffs","EFL League One Playoffs","EFL League Two Playoffs",
    "UEFA Champions League","UEFA Europa League","UEFA Conference League"]);
  if(SOCCER_SPORT_SET.has(sport) || (sport||"").toLowerCase().includes("soccer")||
     (sport||"").toLowerCase().includes("liga")||(sport||"").toLowerCase().includes("ligue")){
    const sid = SOCCER_ESPNID[key];
    if(sid) return `https://a.espncdn.com/i/teamlogos/soccer/500/${sid}.png`;
    return null;
  }
  // ESPN logos: https://a.espncdn.com/i/teamlogos/{sport}/500/{abbrev}.png
  if(espnTeamAbbrevs[key]){
    const {abbrev, espnSport} = espnTeamAbbrevs[key];
    return `https://a.espncdn.com/i/teamlogos/${espnSport}/500/${abbrev}.png`;
  }
  return null;
}

