// allGamesFlat: returns flat array of all games across all sport sections.
// Replaces allGamesFlat() patterns.
function allGamesFlat() {
  return (allData?.sports || []).flatMap(s => s.games || []);
}

// findGameById extracted to src/identity/index.ts (Phase 4 — Identity domain).
// gameNetwork(g, defaultLabel) lives in field_utils.js (pure).
// getDramaPeak: read peak drama score for a game from localStorage.
// Optional `game` param (CC-CMD-2026-07-08-pick-cross-session-resolution
// follow-up): when a real game object is available, tries the
// cross-session-stable key first (injectDramaBadges now dual-writes to it),
// so a peak accumulated before a _gid reset (midnight-crossover, goToDate)
// is still found. Falls back to the volatile gameId-keyed value.
function getDramaPeak(gameId, game) {
  const stableKey = (game && typeof _pickStorageKey === 'function') ? _pickStorageKey(game) : '';
  if (stableKey) {
    const v = localStorage.getItem('field_drama_peak_' + stableKey);
    if (v != null) return parseFloat(v) || 0;
  }
  return parseFloat(localStorage.getItem('field_drama_peak_' + gameId) || '0');
}

// findEspnEntry: find espnScores entry matching a FIELD game object.
// Replaces 10 inline Object.values(espnScores).find(v => ...) patterns
// that each had slightly different home/away matching logic.
// STALE-FINAL GUARD (CC-CMD-2026-07-07-pickem-stale-final-resolution-fix
// v6): reuses the exact check already proven in findESPNScore()'s
// _staleFinalGuard (June 10 2026) -- a FINAL score must never match a
// card whose start_time hasn't passed yet, since a name-only match can
// collide across days. requireSameDate defaults true; the false path is
// for a future, separate consolidation CC-CMD to migrate genuinely
// display-only consumers that should degrade to a stale value rather
// than show nothing -- no caller in this CC-CMD passes false.
function findEspnEntry(game, { requireSameDate = true } = {}) {
  if (!game) return null;
  // Real-ID fast path (CC-CMD-2026-07-09-realid-fix-and-generalize): game
  // construction (static schedule / ESPN fixtures) and espnScores
  // construction (V2/mapV2ToESPN) are independent code paths -- see
  // _resolveRealGameId. When game._gameId has already been resolved to a
  // real external ID, matching it directly is strictly stronger evidence
  // than fuzzy team-name matching, and inherently can't collide across
  // dates/rematches the way name matching can -- so the stale-final guard
  // below doesn't apply to this branch. No fuzzy fallback if the ID doesn't
  // match: a resolved real ID is authoritative, not a hint.
  if (game._gameId) {
    return Object.values(espnScores).find(v => v._gameId && v._gameId === game._gameId) || null;
  }
  const h = (game.home || '').toLowerCase().replace(/[^a-z]/g, '').slice(-6);
  const a = (game.away || '').toLowerCase().replace(/[^a-z]/g, '').slice(-6);
  const entry = Object.values(espnScores).find(v => {
    const vh = (v.homeName || '').toLowerCase().replace(/[^a-z]/g, '');
    const va = (v.awayName || '').toLowerCase().replace(/[^a-z]/g, '');
    return vh.endsWith(h) && va.endsWith(a);
  }) || null;
  if (requireSameDate && entry && entry.state === 'post' && game.start_time &&
      new Date(game.start_time).getTime() > Date.now()) {
    return null; // stale-final guard — see findESPNScore's original June 10 comment
  }
  return entry;
}

// _resolveRealGameId extracted to src/identity/index.ts (Phase 4 — Identity domain).
// rankGamesByDrama: sort games by preGameScore, excluding non-games (ATP field entries).
// Replaces 4 inline filter/sort patterns.
function rankGamesByDrama(games) {
  return (games || [])
    .filter(g => g.home && g.away && g.home !== 'ATP/WTA Field')
    .sort((a, b) => preGameScore(b) - preGameScore(a));
}

// ─────────────────────────────────────────────────────────────────────────
// ── scheduleRenderAll — debounced renderAll for async data arrivals ──────────
// Problem: soccer fixtures, MLB fixtures, and supplemental data all arrive within
// ~500ms of each other, each triggering a full renderAll() + DOM rebuild (~77KB
// HTML string built, 690 DOM nodes created/replaced on every call).
// Solution: data-arrival paths call scheduleRenderAll() instead of renderAll().
//   - Consecutive calls within 150ms collapse into a single final render.
//   - User-interaction paths (filter clicks, date nav, TZ change) call renderAll()
//     directly so they respond instantly with no perceptible delay.
// Expected effect: 4 startup re-renders → 1 final re-render after data settles.
let _renderAllPending = null;
// FIELD render-signature gate (CC-CMD-2026-07-10-render-signature-gate):
// async data arrivals should not rebuild the schedule unless the visible
// schedule/card payload actually changed. Live score changes are patched
// by renderESPNScores() (its own DOM-equality guard, unchanged by this);
// structural renders are reserved for new/removed/reordered games,
// filter/date/timezone/viewport changes, and card copy/enrichment baked
// into renderAll() output. Ported from a ChatGPT-authored proposal
// (Drive doc "FIELD no-rerender optimization rationale — July 10
// index.html"), adapted to this codebase's real field/variable names,
// with a confirmed gap in the source's own implementation fixed before
// shipping: Pick'em state lives in localStorage (_getPickCache()), not
// on the game object, so a naive copy of g.* fields (which is all the
// source's _fieldGameRenderPayload did) would never notice a pick being
// made or resolved and would silently skip the structural render that
// updates the pick widget -- exactly the failure the source document's
// own rationale warned against.
//
// View Transitions (CC-CMD-2026-07-10-view-transitions-render): the gate
// above decides WHEN a rebuild is necessary; scheduleRenderAll's genuine-
// rebuild branch decides HOW it presents -- wrapped in
// document.startViewTransition() for a browser-native cross-fade instead
// of an instant DOM swap. Real timing measured live against production
// (23 games / 5 sections, avg 69ms, max 80ms across 5 runs) before
// wrapping -- well under the ~100ms perceptible-lag threshold, so the
// callback resolving synchronously does not leave a visible frozen frame.
// Feature-detected (unsupported engines fall through to the exact same
// doRender() call, byte-identical to pre-this-CC-CMD behavior) and
// reduced-motion-gated via matchMedia: the existing CSS-only reduced-
// motion rule (index.html ~1140, `*,*::before,*::after{animation-
// duration:0.01ms!important...}`) does NOT reach `::view-transition-*`
// top-layer pseudo-elements, so this needs its own explicit JS check
// rather than relying on that established pattern. Direct user-
// interaction paths (filter clicks, date nav, TZ change) call renderAll()
// with no argument (the skipUnchanged param is falsy there), not the
// cache-preserving true form -- a different call shape than this doc
// anticipated -- and are deliberately left unwrapped; see the
// outbox for the reasoning (the codebase's own preceding comment already
// states these are meant to respond instantly, and "genuinely better,
// not merely different" isn't something a headless-browser probe can
// establish for a perceptual/aesthetic question).
window.FIELD_RENDER_PIPELINE = window.FIELD_RENDER_PIPELINE || {
  version: 'render-sig-gate-v1',
  scheduled: 0,
  structuralRenders: 0,
  skippedStructuralRenders: 0,
  lastSignature: ''
};
function _fieldViewportBucket(){
  const w = window.innerWidth || document.documentElement.clientWidth || 0;
  if (w <= 600) return 'phone';
  if (w < 820) return 'small-landscape';
  if (w < 1200) return 'tablet';
  if (w < 1440) return 'desktop';
  return 'wide';
}
function _fieldSafeGameBrief(g){
  try { return (g && g._id && typeof _gameBriefCache !== 'undefined') ? (_gameBriefCache[g._id]||'') : ''; }
  catch(_) { return ''; }
}
// Pick'em fix: picks are keyed in localStorage by _pickStorageKey(game)
// (falling back to g._id), exactly mirroring buildPickWidgetHTML's own
// lookup convention (index.html ~28314) -- not a new key scheme. Pick
// cache is parsed ONCE per signature computation (by the caller) and
// passed in, not re-parsed per game -- this signature runs on every
// scheduleRenderAll debounce firing, including live-poll cycles, so a
// per-game localStorage.getItem+JSON.parse would be real, avoidable cost.
function _fieldGamePickSignature(g, pickCache){
  try {
    if (!pickCache || !g) return '';
    const gid = g.start_time ? (_pickStorageKey(g) || g._id || '') : (g._id || '');
    const pick = gid ? pickCache[gid] : null;
    if (!pick) return '';
    return `${pick.predictedWinner||''}|${pick.resolved?1:0}|${pick.wasCorrect===null?'':(pick.wasCorrect?1:0)}|${pick.probabilityLabel||''}`;
  } catch(_) { return ''; }
}
