// ── LAYER 4: STRUCTURAL ENTRY VALIDATION ─────────────────────────────────
// Catches empty teams, home===away, missing start_time, empty streams
// Called in buildTodaySchedule() before pushing to sections.
function validateGameEntry(game, source){
  const errors=[];
  if(!game.home||game.home.trim()==="") errors.push("empty home team");
  // away:"" is permitted for tournament-format entries (tennis rounds, golf events)
  // Only flag truly missing away field (undefined/null), not intentional empty string
  if(game.away===undefined||game.away===null) errors.push("missing away team field");
  if(game.home && game.away && game.home===game.away) errors.push("home===away");
  if(!game.start_time||isNaN(new Date(game.start_time))) errors.push("invalid start_time");
  // localRsn and nationalBundle are valid alternatives to streams array
  const hasStreams=(game.streams&&game.streams.length>0)||game.localRsn||game.nationalBundle;
  if(!hasStreams) errors.push("no streams, localRsn, or nationalBundle");
  if(errors.length>0 && FIELD_DEBUG){
    console.warn(`[FIELD AUDIT] Invalid game entry in ${source}: ${game.home||'?'} vs ${game.away||'?'} —`,errors.join(", "));
  }
  return errors.length===0;
}
