  // ── PREGAME SORT SCORE ───────────────────────────────────────────────────
  // ─────────────────────────────────────────────────────────────────────────
  // Parses league strings to auto-generate narrative labels + importance flags.
  // Activates: DA-03 badge · narrative.label · drama_score playoff_boost · Wow #24.
  // QW-3 / J0-B -- Series record parser for J1/J2/J3/J4
  // parseSeriesRecord() moved to top-level utility block (was scope-leaking — called outside buildTodaySchedule)

  function elimination_boost(g) {
    const s = (g.league||'').toLowerCase();
    // Game 7 / deciding game
    if (/game 7|g7|tied 3-3|series tied 3-3/.test(s))
      return {importance:'series_deciding', boost:30, label:'Game 7 — winner takes all', icon:'🏆'};
    // Must-win elimination (team trails 3-1 or 3-0)
    if (/leads 3-0|up 3-0/.test(s))
      return {importance:'elimination', boost:22, label:'Facing sweep — must win to survive', icon:'⚠️'};
    if (/leads 3-1|up 3-1/.test(s))
      return {importance:'elimination', boost:18, label:'Elimination game', icon:'⚠️'};
    if (/leads 3-2|up 3-2/.test(s))
      return {importance:'elimination', boost:22, label:'Elimination game', icon:'⚠️'};
    // Clinch game (team can win series)
    if (/leads 3-0/.test(s) && /game 4/i.test(g.league||''))
      return {importance:'clinch', boost:15, label:'Can sweep the series', icon:'✓'};
    if (/leads 3-1/.test(s))
      return {importance:'clinch', boost:15, label:'One win from advancing', icon:'✓'};
    if (/leads 3-2/.test(s))
      return {importance:'clinch', boost:18, label:'One win from the series', icon:'✓'};
    // High-stakes: tied series
    if (/tied 2-2|series tied 2-2/.test(s))
      return {importance:'playoff_impl', boost:12, label:'Series tied — pivotal game', icon:'📊'};
    if (/tied 1-1|series tied 1-1/.test(s))
      return {importance:'playoff_impl', boost:8, label:'Series tied after split', icon:'📊'};
    // Second leg knockout (EFL/Cup)
    if (/2nd leg|second leg/.test(s))
      return {importance:'playoff_impl', boost:12, label:'Knockout second leg', icon:'⚽'};
    // General playoff context
    if (/leads 2-1|up 2-1/.test(s))
      return {importance:'playoff_impl', boost:8, label:'One team holds the edge', icon:'📊'};
    if (/leads 1-0|up 1-0/.test(s))
      return {importance:'playoff_impl', boost:5, label:'Series advantage', icon:'📊'};
    // Playoff/cup final: single decisive match → series_deciding importance
    if (/final/i.test(s) && /playoff|cup|champions|europa|conference/i.test(s))
      return {importance:'series_deciding', boost:28, label:'Playoff Final', icon:'🏆'};

    // ── MLS drama (no promotion/relegation) ──────────────────────────
    if (/mls/i.test(s)) {
      if (/mls.?cup.?final/i.test(s)) return {importance:"series_deciding",boost:28,label:"MLS Cup Final",icon:"🏆"};
      if (/conference.?final|eastern.?final|western.?final/i.test(s)) return {importance:"series_deciding",boost:22,label:"Conference Final",icon:"🏆"};
      if (/supporters.{0,15}shield|shield.{0,10}race/i.test(g.matchupNote||"")) return {importance:"series_deciding",boost:20,label:"Supporters’ Shield race",icon:"🛡️"};
      if (/playoff.{0,20}spot|conference.{0,20}race|clinch/i.test(g.matchupNote||"")) return {importance:"playoff_impl",boost:14,label:"Playoff position race",icon:"📊"};
      if (/el.?tráfico|el.?trafico/i.test(g.league||g.matchupNote||"")) return {importance:"series_deciding",boost:20,label:"El Tráfico — LA’s biggest derby",icon:"🔥"};
      if (/hudson.?river.?derby/i.test(g.league||g.matchupNote||"")) return {importance:"playoff_impl",boost:15,label:"Hudson River Derby",icon:"🔥"};
      if (/cascadia/i.test(g.league||g.matchupNote||"")) return {importance:"playoff_impl",boost:12,label:"Cascadia Derby",icon:"🔥"};
      if (/hell.?is.?real|ohio.?cup/i.test(g.league||g.matchupNote||"")) return {importance:"playoff_impl",boost:12,label:"Regional MLS rivalry",icon:"🔥"};
    }

    // ── Soccer league relegation/European stakes ─────────────────────────
    // _gameImportance set manually via overlay for known relegation/Europe battles.
    // Auto-detect from matchupNote when present (overlay sets it on data day).
    // Final-day detection: league string contains matchday at season end.
    const isFinalDay = /matchday 38|matchweek 38|jornada 38|md38|mw38|spieltag 34|journée 38/i.test(s);
    if (isFinalDay) {
      // All final-day games have elevated stakes — title, Europe, or relegation all live
      // Specific games get manual _gameImportance via overlay; this is the floor boost
      return {importance:'playoff_impl', boost:12, label:'Final day — season destiny', icon:'🏟️'};
    }
    // Relegation battle detected via matchupNote or league label
    if (/relegat/i.test(g.matchupNote||'') || /relegat/i.test(g.localNote||''))
      return {importance:'elimination', boost:22, label:'Relegation battle', icon:'⚠️'};
    // European spot race
    if (/champions league|europa league|conference league/i.test(g.matchupNote||''))
      return {importance:'playoff_impl', boost:12, label:'European spot on the line', icon:'🌍'};

    return null;
  }

  // Apply narrative context to all game arrays before rendering
  function applyNarrativeContext(games) {
    games.forEach(g => {
      if (!g.narrative) {
        const ctx = g.seriesRecord ? parseSeriesRecord(g) : elimination_boost(g);
        if (ctx) {
          g._gameImportance = ctx.importance;
          g._importanceIcon = ctx.icon;
          g.narrative = {boost: ctx.boost, label: ctx.label, source:'auto'};
          g._series = ctx;
        }
      } else if(g.seriesRecord && !g._series) {
        g._series = parseSeriesRecord(g);
      }
    });
  }
  // ─────────────────────────────────────────────────────────────────────────
  // ── LAYER 4: Validate all game arrays before rendering ─────────────────
  const _vGames=(arr,src)=>arr.filter(g=>validateGameEntry(g,src));

  nbaGames.forEach(g=>g._sport="NBA Playoffs");
  applyNarrativeContext(nbaGames);
  if(nbaGames.length)  sections.push({sport:"NBA Playoffs",games:_vGames(nbaGames,"nbaGames")});
  nhlGames.forEach(g=>g._sport="NHL Playoffs");
  applyNarrativeContext(nhlGames);
  if(nhlGames.length)  sections.push({sport:"NHL Playoffs",games:_vGames(nhlGames,"nhlGames")});
  mlbGames.forEach(g=>g._sport="Baseball (MLB)");
  applyNarrativeContext(mlbGames);  // QW-3/QW-5: elimination badges + narrative labels for ALCS/NLCS/WS
  if(mlbGames.length)  sections.push({sport:"Baseball (MLB)",games:_vGames(mlbGames,"mlbGames")});
  mlsSoccer.forEach(g=>g._sport="MLS Soccer");
  applyNarrativeContext(mlsSoccer); // QW-3/QW-5: MLS Cup playoff series context
  if(mlsSoccer.length) sections.push({sport:"MLS Soccer",games:_vGames(mlsSoccer,"mlsSoccer")});
  uclGames.forEach(g=>g._sport="UEFA Champions League");
  uelGames.forEach(g=>g._sport="UEFA Europa League");
  ueclGames.forEach(g=>g._sport="UEFA Conference League");
  applyNarrativeContext(uclGames);    // UCL/UEL/UECL finals → series_deciding
  applyNarrativeContext(uelGames);
  applyNarrativeContext(ueclGames);
  eflGames.forEach(g=>g._sport="EFL Championship Playoffs");
  eflL1Games.forEach(g=>g._sport="EFL League One Playoffs");
  eflL2Games.forEach(g=>g._sport="EFL League Two Playoffs");
  applyNarrativeContext(eflGames);    // drama score: Wembley finals → series_deciding
  applyNarrativeContext(eflL1Games);
  applyNarrativeContext(eflL2Games);
  if(eflGames.length)  sections.push({sport:"EFL Championship Playoffs",games:eflGames});
  if(eflL1Games.length) sections.push({sport:"EFL League One Playoffs",games:eflL1Games});
  if(eflL2Games.length) sections.push({sport:"EFL League Two Playoffs",games:eflL2Games});
  if(uclGames.length)  sections.push({sport:"UEFA Champions League",games:uclGames});
  if(uelGames.length)  sections.push({sport:"UEFA Europa League",games:uelGames});
  if(ueclGames.length) sections.push({sport:"UEFA Conference League",games:ueclGames});
  iplGames.forEach(g=>g._sport="IPL");
  wweGames.forEach(g=>g._sport="WWE/Pro Wrestling");
  aflGames.forEach(g=>g._sport="Australian Football (AFL)");
  if(iplGames.length)  sections.push({sport:"IPL",games:iplGames});
  if(wweGames.length)  sections.push({sport:"WWE/Pro Wrestling",games:wweGames});
  if(aflGames.length)  sections.push({sport:"Australian Football (AFL)",games:aflGames});
  sections.push(...tennisSections);
  // All live-data soccer leagues — applyNarrativeContext before rendering
  // Fix: La Liga/Ligue 1/others previously had no narrative context → zero elimination boost
  applyNarrativeContext(eplGames);
  applyNarrativeContext(laLigaGames);
  applyNarrativeContext(ligue1Games);
  if(typeof bundesligaGames !== 'undefined') applyNarrativeContext(bundesligaGames);
  if(typeof serieAGames    !== 'undefined') applyNarrativeContext(serieAGames);
  if(eplGames.length)      sections.push({sport:"Premier League", games:eplGames});
  if(laLigaGames.length)   sections.push({sport:"La Liga", games:laLigaGames});
  if(ligue1Games.length)   sections.push({sport:"Ligue 1", games:ligue1Games});

  // ── Golf (PGA Tour) ───────────────────────────────────────────────────────
  // Travelers Championship — Jun 25-28 2026, TPC River Highlights, Cromwell CT
  //   Final PGA Tour Signature Event of 2026 season. Purse: $20M ($3.6M winner).
  //   Defending: Keegan Bradley (won 2023 + 2025; New England native).
  //   Key field: Scheffler (#1, 2024 champ here), Wyndham Clark (#8, fresh off U.S. Open),
  //   Cameron Young (#3), Fleetwood (#7, runner-up 2025), Morikawa (#9). McIlroy skipping.
  //   Course: par-70, 6,841 yds, Bentgrass. Short + birdie-friendly, stadium crowds.
  //   Broadcast: Golf Channel Thu-Fri 3-6 PM ET · Golf Channel Sat 1-3, Sun 2-4 · NBC Sat 3-6, Sun 4-7
  //   ESPN+/PGA Tour Live + Peacock streaming all week.
  const golfGames=[
    // ── Travelers Championship — R1-R4 Jun 25-28 2026, TPC River Highlands Cromwell CT ─
    {
      home: 'Travelers Championship', away: '',
      league: 'PGA Tour · Signature Event · Cromwell, CT',
      start_time: '2026-06-25T19:00:00Z', // R1 Thu Jun 25 — Golf Channel 3 PM ET
      tournEnd: '2026-06-28',
      _sport: 'golf', _id: 'golf_travelers_2026',
      matchupNote: 'Final Signature Event of 2026. Scheffler (world #1, 2024 champion here) vs. Wyndham Clark (fresh off U.S. Open at Shinnecock) vs. defending champion Keegan Bradley. McIlroy skipping — third Signature Event missed this season.',
    },
  ].filter(g=>{
    // Show for full tournament duration (Thu-Sun), not just isToday of start_time
    const todayStr = new Date().toLocaleDateString('en-CA',{timeZone:localTz()||'America/New_York'});
    if(g.tournEnd){
      const startStr = new Date(g.start_time).toLocaleDateString('en-CA',{timeZone:'America/New_York'});
      return todayStr >= startStr && todayStr <= g.tournEnd;
    }
    return isToday(g.start_time)||
      (new Date(g.start_time) > new Date() && new Date(g.start_time) < new Date(Date.now()+7*24*3600*1000));
  });
  if(golfGames.length) sections.push({sport:"Golf", games:golfGames});
  // Slash Golf enrichment fires async after init (T+3500ms)
  // slashGolfPrefetchAll() will inject leaderNote into golf cards via injectSlashGolfLeaderNotes()

  // ── WNBA — Season started May 8, 2026 (30th season, 15 teams) ─────────────
