// ── Supplemental AI call (rugby only — cricket/IPL/AFL now hardcoded) ─────────
// Day-skip table — saves the API round-trip on days these sports don't run:
//   Mon(1), Tue(2), Wed(3) → skip entirely
//   Thu(4) → AFL hardcoded; rugby possible (Top14/URC Thu nights) → ask rugby only
//   Fri(5), Sat(6), Sun(0) → rugby in season; ask rugby only
// Cricket/IPL is fully hardcoded in buildTodaySchedule so never asked here.
// AFL Thu games are hardcoded in buildTodaySchedule; no need to ask the model.
async function fetchSupplemental(isoDate,dayOfWeek,monthYear){
  const d=new Date().getDay(); // 0=Sun,1=Mon,...,6=Sat
  if(d===1||d===2||d===3||d===4) return []; // Mon-Thu: no Top14/URC (rugby runs Fri/Sat/Sun)
  // Thu–Sun: ask for rugby only (cricket fully covered by hardcoded IPL data)
  const prompt=""+isoDate+" "+dayOfWeek+". Return rugby matches ONLY (Top14/URC/SuperRugby). JSON only, no prose. Format: {\"s\":[]} if none, or {\"s\":[[\"HomeTeam\",\"AwayTeam\",\"League\",\"TIME_UTC\",\"streamkey\"]]} where TIME_UTC is the actual UTC kickoff time (e.g. "+isoDate+"T13:00:00Z). Stream keys: dazn,sky,espnplus,peacock,prime. CRITICAL: Return {\"s\":[]} rather than generating a match you are not certain is scheduled today. Omit > invent. An empty response is correct when uncertain.";
  if(!canUseAPI()) return [];
  try{
    incrementUsage();
    const r=await fetch(CLAUDE_PROXY_URL,{
      method:"POST",headers:{"Content-Type":"application/json"},
      signal:AbortSignal.timeout(4000),
      body:JSON.stringify({model:"claude-haiku-4-5-20251001",max_tokens:200,
        messages:[{role:"user",content:prompt}]})
    });
    if(!r.ok){ const e=await r.text(); throw new Error("HTTP "+r.status+": "+e.slice(0,80)); }
    const data=await r.json();
    if(data.type==="error"||data.error) throw new Error(data.error?.message||"API error");
    const rawS=(data.content||[]).map(b=>b.text||"").join("").trim();
    const cleanS=rawS;
    const mS=cleanS.match(/\{[\s\S]*\}/);
    if(!mS) throw new Error("No JSON in supplemental response");
    const parsed=JSON.parse(mS[0]);
    if(!parsed.s||!parsed.s.length) return [];
    const games={sport:"Rugby",games:[]};
    parsed.s.forEach(([home,away,league,time,streamKey])=>{
      games.games.push({home,away,league,start_time:time,venue:"",streams:expandStreams([streamKey])});
    });
    return games.games.length?[games]:[];
  }catch(e){
    if(FIELD_DEBUG) console.warn("FIELD supplemental ["+isoDate+"]:", e.message);
    return [];
  }
}


