// ── Dynamic pregame injection ───────────────────────────────────────────────
// Derives sport-specific pregame/postgame cards from allData.sports at render time.
// Network pulled from game.streams[] — same data that drives broadcast chips.
// No manual update needed when the schedule changes.
function buildDynamicPregames(){
  if(!allData||!allData.sports) return [];
  const cards = [];
  const dow = new Date().getDay(); // 0=Sun … 6=Sat
  let nbaDone=false, nhlDone=false, golfDone=false;

  for(const sec of allData.sports){
    const game = (sec.games||[])[0];
    if(!game) continue;
    const sport = sec.sport||"";

    // NBA Playoffs pregame + Inside the NBA
    if(!nbaDone&&sport.includes("NBA")&&game){
      nbaDone=true;
      const gameTime = game.start_time ? fmtTime(game.start_time) : "TBD";
      const isWeekend = dow===0||dow===6;
      const pregameLabel = isWeekend ? "NBA Tip-Off presented by AT&T" : "NBA GameTime";
      const pregameOffset = isWeekend ? 30 : 60;
      const pregameTime = game.start_time
        ? fmtTime(shiftTime(game.start_time, -pregameOffset))
        : "TBD";
      // J8: surface matchupNote in SMT card for playoff editorial context
      const nbaContextLine = game.matchupNote ? ' '+game.matchupNote.split('.')[0].slice(0,80)+'.' : '';
      const nbaNet = gameNetwork(game, 'ESPN');
      cards.push({
        show:pregameLabel, network:nbaNet, chip:"ESPN",
        time:pregameTime+" ET",
        desc:"Pregame coverage ahead of "+(game.away||"")+" @ "+(game.home||"")+" ("+gameTime+" ET, "+nbaNet+")."+nbaContextLine+" Series updates, injury reports, panel preview.",
        link:"https://www.espn.com/watch/",
        journalNote: (() => {
          // Item 1: dynamic journalNote — series record + stat edge + Scout's Pick signal
          const _base = (game.seriesRecord && game.seriesRecord !== '0-0')
            ? game.away + ' @ ' + game.home + ' \u00b7 ' + game.seriesRecord : null;
          try {
            const _sd = typeof getStatOfDay === 'function' ? getStatOfDay(game, 'nba') : null;
            const _statStr = _sd ? ' \u00b7 ' + _sd.shortText : '';
            const _spStr = (typeof isScoutsPick === 'function' && isScoutsPick(game)) ? ' \uD83D\uDD0D' : '';
            return _base ? _base + _statStr + _spStr : null;
          } catch(e_) { return _base; }
        })(),
        _gameId: _resolveRealGameId(game),
        _scoutPick: !!(typeof isScoutsPick === 'function' && (() => { try { return isScoutsPick(game); } catch(e_) { return false; } })()),
      });
      const lastGame = sec.games[sec.games.length-1];
      if(lastGame&&lastGame.start_time){
        const postTime = fmtTime(shiftTime(lastGame.start_time, 150));
        cards.push({
          show:"Inside the NBA", network:"ESPN", chip:"ESPN",
          time:"~"+postTime+" ET",
          desc:"Ernie Johnson, Charles Barkley, Shaquille O'Neal, and Kenny Smith react to tonight's NBA playoff results. Produced by TNT Sports from Atlanta; airs on ESPN immediately after the final game.",
          link:"https://www.espn.com/watch/"
        });
      }
    }

    // NHL Playoffs pregame
    if(!nhlDone&&sport.includes("NHL")&&game){
      nhlDone=true;
      const gameTime = game.start_time ? fmtTime(game.start_time) : "TBD";
      const srKey = game.streams&&game.streams[0]&&SR[game.streams[0]];
      const network = gameNetwork(game, srKey ? srKey[0] : "ESPN");
      const pregameTime = game.start_time
        ? fmtTime(shiftTime(game.start_time, -30))
        : "TBD";
      // J8: matchupNote for playoff context in NHL SMT card
      const nhlContextLine = game.matchupNote ? ' '+game.matchupNote.split('.')[0].slice(0,80)+'.' : '';
      cards.push({
        show:"NHL Playoffs Pregame", network, chip:"ESPN",
        time:pregameTime+" ET",
        desc:"Pregame analysis for "+(game.away||"")+" @ "+(game.home||"")+" ("+gameTime+" ET, "+network+")."+nhlContextLine+" Series preview and lineup reports.",
        link:"https://www.espn.com/watch/",
        journalNote: (() => {
          const _base = (game.seriesRecord && game.seriesRecord !== '0-0')
            ? (game.league || 'NHL Playoffs') + ' \u00b7 ' + game.seriesRecord : null;
          try {
            const _sd = typeof getStatOfDay === 'function' ? getStatOfDay(game, 'nhl') : null;
            const _statStr = _sd ? ' \u00b7 ' + _sd.shortText : '';
            const _spStr = (typeof isScoutsPick === 'function' && isScoutsPick(game)) ? ' \uD83D\uDD0D' : '';
            return _base ? _base + _statStr + _spStr : null;
          } catch(e_) { return _base; }
        })(),
        _gameId: _resolveRealGameId(game),
        _scoutPick: !!(typeof isScoutsPick === 'function' && (() => { try { return isScoutsPick(game); } catch(e_) { return false; } })()),
      });
    }

    // Golf weekend pre-show (CBS Sports, Sat/Sun 12:30pm)
    if(!golfDone&&(sport.includes("Golf")||sport.includes("PGA"))&&(dow===6||dow===0)&&game){
      golfDone=true;
      cards.push({
        show:"CBS Sports Golf Pre-Show", network:"CBS Sports", chip:"CBS",
        time:"12:30 PM ET",
        desc:"CBS Sports preview for "+(game.home||game.away||"today's round")+". Leaderboard check, featured groups, and round preview before main coverage begins.",
        link:"https://www.cbssports.com/golf/"
      });
    }
  }
  return cards;
}

// ── SMT time-phase awareness (Spec: SMT-A May 21 2026) ───────────────────────
// Returns the current phase of the sports media day.
// Used to sort MEDIA_TODAY cards by relevance to the current time.
function getCurrentSMTPhase() {
  const h = new Date().getHours(); // local hour
  if (h < 10) return 'morning';      // 12am–10am: overnight recap / morning shows
  if (h < 13) return 'midday';       // 10am–1pm: morning shows, pre-game prep
  if (h < 17) return 'afternoon';    // 1pm–5pm: afternoon games, early shows
  if (h < 21) return 'evening';      // 5pm–9pm: prime time games, pregame shows
  return 'postgame';                  // 9pm+: live games, postgame shows
}

// Returns true if a media card's show time is currently on-air or within 30min
function isShowCurrentlyAiring(card) {
  if (!card.time) return false;
  try {
    // Parse time strings like "7:30 PM ET", "10 AM ET", "11:30pm"
    const m = card.time.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)/i);
    if (!m) return false;
    let h = parseInt(m[1]);
    const mins = parseInt(m[2] || '0');
    const ampm = m[3].toLowerCase();
    if (ampm === 'pm' && h !== 12) h += 12;
    if (ampm === 'am' && h === 12) h = 0;
    const showMinutes = h * 60 + mins;
    const nowMinutes = new Date().getHours() * 60 + new Date().getMinutes();
    return nowMinutes >= showMinutes && nowMinutes < showMinutes + 90; // 90min window
  } catch (_) { return false; }
}

// Scores a media card for current relevance (higher = more relevant now)
function scoreSMTCard(card) {
  const phase = getCurrentSMTPhase();
  let score = 0;
  // Cards currently airing get highest priority
  if (isShowCurrentlyAiring(card)) score += 100;
  // Phase-specific boosts
  const phaseBoosts = {
    morning:   ['SportsCenter', 'Get Up', 'First Take', 'The Pat McAfee Show'],
    midday:    ['First Take', 'The Herd', 'Undisputed', 'SportsCenter'],
    afternoon: ['Around the Horn', 'Pardon the Interruption', 'MLB Central'],
    evening:   ['NBA Tip-Off', 'NHL Face Off', 'Baseball Tonight', 'Inside the NBA', 'Pregame'],
    postgame:  ['Inside the NBA', 'Baseball Tonight', 'NHL After Hours', 'SportsCenter'],
  };
  const boostList = phaseBoosts[phase] || [];
  if (boostList.some(s => (card.show || '').includes(s))) score += 20;
  // Tonight's sports relevance — boost cards for sports that have games tonight
  if (allData) {
    const tonightSports = new Set((allData.sports || []).map(s => s.sport || s.section || ''));
    const cardNetwork = (card.network || card.chip || '').toLowerCase();
    if (tonightSports.has('Basketball (NBA)') && cardNetwork.includes('nba')) score += 15;
    if (tonightSports.has('Hockey (NHL)') && cardNetwork.includes('nhl')) score += 15;
    if (tonightSports.has('Baseball (MLB)') && cardNetwork.includes('mlb')) score += 10;
  }
  // Item 2: Scout's Pick signal — pregame card for tonight's top pick ranks higher.
  // Uses buildSlateScoutsPick() cross-slate selector (one pick per night).
  // card._gameId is attached by buildDynamicPregames() and buildWCMediaCards()
  // when a game qualifies; scoreSMTCard reads it here without computing pick again.
  if (card._scoutPick) score += 25;
  // Item 6: Live state suppression — pregame card deprioritizes once game is live.
  // espnScores state:'in' means the pregame window is over; drop it below live content.
  if (card._gameId && typeof espnScores !== 'undefined') {
    const liveEntry = Object.values(espnScores).find(v =>
      v._gameId === card._gameId && v.state === 'in');
    if (liveEntry) score -= 50; // pregame card, game is already live — drop it
  }
  return score;
}

// ── Item 4: buildWCMediaCards — per-game WC cards from allData ───────────────
// Replaces the single blanket MEDIA_SPECIALS WC card with per-game cards.
// Generates one card per WC game on today's slate, deriving network from
// nationalBundle and injecting matchupNote as journalNote.
// Deduplicated by show name in renderMedia — won't conflict with MEDIA_SPECIALS.
function buildWCMediaCards() {
  if (!allData || !allData.sports) return [];
  const cards = [];
  const WC_NETWORK = {
    WC26_FOX: 'FOX', WC26_FS1: 'FS1', WC26_FREE: 'FOX / Tubi FREE',
  };
  const WC_LINK = {
    WC26_FOX: 'https://www.foxsports.com/soccer/fifa-world-cup',
    WC26_FS1: 'https://www.foxsports.com/live',
    WC26_FREE: 'https://tubitv.com/live',
  };
  const WC_CHIP = {
    WC26_FOX: 'fox', WC26_FS1: 'FS1', WC26_FREE: 'fox',
  };

  let hasWCGames = false;
  for (const sec of allData.sports) {
    if (!(sec.sport || '').includes('FIFA')) continue;
    for (const game of (sec.games || [])) {
      if (!game._id || !game.home) continue;
      hasWCGames = true;
      const network = WC_NETWORK[game.nationalBundle] || 'FOX/FS1';
      const link    = WC_LINK[game.nationalBundle]    || 'https://www.foxsports.com/soccer/fifa-world-cup';
      const chip    = WC_CHIP[game.nationalBundle]    || 'fox';
      const gameTime = game.start_time ? fmtTime(game.start_time) : 'TBD';

      // Item 1: dynamic journalNote — matchupNote + stat edge if Scout's Pick
      let journalNote = game.matchupNote
        ? game.matchupNote.split('.')[0].slice(0, 100) + '.'
        : null;
      try {
        if (typeof isScoutsPick === 'function' && isScoutsPick(game)) {
          const _wcSd = typeof getStatOfDay === 'function'
            ? getStatOfDay(game, 'FIFA World Cup 2026') : null;
          if (_wcSd) {
            journalNote = (journalNote ? journalNote + ' ' : '') +
              '\uD83D\uDD0D Scout’s Pick: ' + _wcSd.shortText;
          }
        }
      } catch(e_) { captureFieldError('wc:media-card-journal-note', e_, true); }

      const leagueShort = (game.league || '').replace('FIFA World Cup 2026 — ', '').replace('FIFA World Cup 2026', 'Group Stage');

      // Trap teams: which path-trapped team(s) are playing in this game?
      const _trapTeams = (_wcPathTraps || [])
        .filter(t => t.team === game.home || t.team === game.away ||
                     t.fifaCode === game.home || t.fifaCode === game.away)
        .map(t => ({ team: t.team, delta: t.delta }));

      cards.push({
        show: game.away + ' vs ' + game.home,
        network, chip,
        time: gameTime + ' ET',
        desc: leagueShort + '. ' + (game.matchupNote || (game.away + ' face ' + game.home + ' in group stage action.')) ,
        link,
        journalNote,
        _gameId: _resolveRealGameId(game),
        _scoutPick: !!(typeof isScoutsPick === 'function' && isScoutsPick(game)),
        _trapTeams,
      });
    }
  }

  // WC Tournament Brief card — surfaces bracket context on main schedule
  if (hasWCGames && cards.length > 0) {
    cards.unshift({
      show: 'World Cup 2026 · Tournament Brief',
      network: 'FOX · Telemundo',
      chip: 'fox',
      time: '',
      desc: 'Loading tournament context…',
      link: 'https://www.foxsports.com/soccer/fifa-world-cup',
      journalNote: null,
      _wcTournBrief: true,  // marker for async brief injection
    });
    // Async fetch: inject tournament brief text after render
    _fetchWCTournBriefForSchedule();
  }

  return cards;
}

// Async: fetch /wc/brief/tournament and inject into the tournament brief card on schedule
let _wcTournBriefFetched = false;
let _wcPathTraps = null; // cached bracketTraps array for TRAP chip on game cards
function _fetchWCTournBriefForSchedule() {
  if (_wcTournBriefFetched) return;
  _wcTournBriefFetched = true;
  const relay = typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE
    : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  Promise.all([
    fetch(relay + '/wc/brief/tournament', { cache: 'no-store' }).then(r => r.ok ? r.json() : null).catch(() => null),
    fetch(relay + '/wc/bracket', { cache: 'no-store' }).then(r => r.ok ? r.json() : null).catch(() => null),
    fetch(relay + '/wc/traps', { cache: 'no-store' }).then(r => r.ok ? r.json() : null).catch(() => null),
    (typeof fetchWCStandings === 'function' ? fetchWCStandings() : Promise.resolve(null)).catch(() => null),
    (typeof fetchWCResults === 'function' ? fetchWCResults() : Promise.resolve(null)).catch(() => null),
  ]).then(([briefData, bracketData, trapsResult, standings, matchResults]) => {
    // Cache path traps for game card TRAP chip
    if (trapsResult?.bracketTraps?.length) {
      _wcPathTraps = trapsResult.bracketTraps;
    }
    // Pre-populate scenarios cache so night owl advancement context fires
    // without requiring the user to have opened the WC Groups tab.
    try {
      if (typeof _wcComputeAllScenarios === 'function' && standings
          && Object.keys(standings).length > 0) {
        window._wcScenariosCache = _wcComputeAllScenarios(
          standings, matchResults || [], null,
          window._wcOddsProbsCache || null,
          null
        );
      }
    } catch (_) { /* non-blocking */ }
    // POST matchupNotes for upcoming WC games so relay's writeWCResult
    // can inject PRE-GAME CONTEXT into journalism prompts.
    // Fires once per schedule load — fire-and-forget, never blocks.
    // Note: wc26Raw entries don't carry homeScore/awayScore — completion is
    // encoded in the league string (e.g. "· USA wins 4-1", "· 1-1 Draw"),
    // so the unfinished check uses a league-string regex instead.
    try {
      const nowMs = Date.now();
      const _isFinished = (s) => / wins \d+-\d+| draw\b|·\s*\d+-\d+/i.test(s || '');
      const upcoming = (typeof wc26Raw !== 'undefined' && Array.isArray(wc26Raw))
        ? wc26Raw.filter(g =>
            g.matchupNote &&
            g.home && g.away &&
            !_isFinished(g.league) &&
            new Date(g.start_time).getTime() > nowMs - 4 * 3600 * 1000 &&  // started ≤4h ago
            new Date(g.start_time).getTime() < nowMs + 7 * 24 * 3600 * 1000 // within 7 days
          )
        : [];
      for (const g of upcoming.slice(0, 20)) {  // cap at 20 POSTs
        fetch(relay + '/wc/matchup/cache', {
          method:  'POST',
          headers: { 'Content-Type': 'application/json' },
          body:    JSON.stringify({
            home: g.home,
            away: g.away,
            note: g.matchupNote,
          }),
        }).catch(() => {});  // fire-and-forget
      }
    } catch (_) { /* non-blocking */ }
    // Find the tournament brief card in the DOM
    const cards = document.querySelectorAll('.smt-card, .desk-card');
    for (const card of cards) {
      if (!card.textContent.includes('Tournament Brief')) continue;
      const descEl = card.querySelector('.smt-card-desc, .desk-card-desc, .smt-card-time');
      if (!descEl) continue;
      // Build bracket context string
      let text = '';
      if (briefData?.brief) {
        text = briefData.brief;
      }
      if (bracketData?.bracketSlots) {
        const s = bracketData.bracketSlots;
        // api-sports uses "USA", WC_TEAMS uses "United States" — check both
        const isUSA = (t) => t === 'United States' || t === 'USA';
        // Find USA in bracket
        const usaSlot = Object.entries(s).find(([k,v]) => isUSA(v.team) && k.includes('_A'));
        if (usaSlot) {
          const matchNum = usaSlot[0].replace('R32_','').replace('_A','');
          const opponent = s['R32_' + matchNum + '_B'];
          const r16Slot = Object.entries(s).find(([k,v]) => isUSA(v.team) && k.startsWith('R16'));
          if (opponent && r16Slot) {
            const r16Match = r16Slot[0].replace('_A','').replace('_B','');
            const r16Opp = isUSA(s[r16Match + '_A']?.team) ? s[r16Match + '_B'] : s[r16Match + '_A'];
            text += (text ? ' ' : '') + 'USA bracket path: R32 vs ' + (opponent?.team || '?') +
              ', R16 vs ' + (r16Opp?.team || '?') + '.';
          }
        }
      }
      if (text) {
        descEl.textContent = text.slice(0, 300);
        descEl.style.color = 'var(--smoke, #aaa)';
      }
      break;
    }
  });
}

// ── Item 3: buildPlayoffSpecials — auto-generate Finals/CF cards from allData ─
// Reduces TYPE A manual work: no need to add MEDIA_SPECIALS entries for
// active Finals/Conference Finals series — this generates them dynamically.
// Only fires for games with series records (playoff context confirmed).
// MEDIA_SPECIALS manual entries still override via dedup in renderMedia.
function buildPlayoffSpecials() {
  if (!allData || !allData.sports) return [];
  const cards = [];
  let nbaFinalsDone = false, nhlFinalsDone = false;

  for (const sec of allData.sports) {
    for (const game of (sec.games || [])) {
      if (!game.seriesRecord || game.seriesRecord === '0-0') continue;
      const league = (game.league || '').toLowerCase();
      const network = gameNetwork(game);
      const gameTime = game.start_time ? fmtTime(game.start_time) : 'TBD';

      // NBA Finals
      if (!nbaFinalsDone && /nba finals/i.test(game.league || '')) {
        nbaFinalsDone = true;
        const note = game.matchupNote ? game.matchupNote.split('.')[0].slice(0, 100) + '.' : '';
        // Item 1: stat edge in journalNote
        let journalNote = game.away + ' @ ' + game.home + ' \u00b7 ' + game.seriesRecord;
        try {
          const _sd = typeof getStatOfDay === 'function' ? getStatOfDay(game, 'nba') : null;
          if (_sd) journalNote += ' \u00b7 ' + _sd.shortText;
        } catch(e_) { captureFieldError('journalism:playoff-specials-nba-statedge', e_, true); }
        cards.push({
          show: 'NBA Finals ' + game.seriesRecord,
          network: network || 'ABC',
          chip: 'ESPN',
          time: gameTime + ' ET',
          desc: game.away + ' @ ' + game.home + '. ' + note + (note ? '' : ' NBA Finals on ABC.'),
          link: 'https://www.espn.com/nba/playoffs/bracket',
          journalNote,
          _gameId: _resolveRealGameId(game),
          _scoutPick: false,
        });
      }

      // Stanley Cup Final
      if (!nhlFinalsDone && /stanley cup final/i.test(game.league || '')) {
        nhlFinalsDone = true;
        let journalNote = game.away + ' @ ' + game.home + ' \u00b7 ' + game.seriesRecord;
        try {
          const _sd = typeof getStatOfDay === 'function' ? getStatOfDay(game, 'nhl') : null;
          if (_sd) journalNote += ' \u00b7 ' + _sd.shortText;
        } catch(e_) { captureFieldError('journalism:playoff-specials-nhl-statedge', e_, true); }
        cards.push({
          show: 'Stanley Cup Final ' + game.seriesRecord,
          network: network || 'ABC',
          chip: 'ESPN',
          time: gameTime + ' ET',
          desc: game.away + ' @ ' + game.home + '. ' + (game.matchupNote ? game.matchupNote.split('.')[0].slice(0,100) + '.' : 'Stanley Cup Final on ABC/ESPN.'),
          link: 'https://www.espn.com/nhl/playoffs/bracket',
          journalNote,
          _gameId: _resolveRealGameId(game),
          _scoutPick: false,
        });
      }
    }
  }
  return cards;
}

// ── Item 5: buildDynamicPostgames — Baseball Tonight, WC post-match etc ───────
// Generates postgame show cards timed ~2.5hr after the last game of the night.
// Covers gaps in buildDynamicPregames() which only adds Inside the NBA + Golf.
function buildDynamicPostgames() {
  if (!allData || !allData.sports) return [];
  const cards = [];
  const dow = new Date().getDay();
  let mlbDone = false, wcDone = false;

  for (const sec of allData.sports) {
    const sport = sec.sport || '';
    const games = sec.games || [];
    if (!games.length) continue;
    const lastGame = games[games.length - 1];
    if (!lastGame.start_time) continue;

    // Baseball Tonight (MLB nights — not weekends which have different coverage)
    if (!mlbDone && sport.includes('MLB') && games.length > 0) {
      mlbDone = true;
      const postTime = fmtTime(shiftTime(lastGame.start_time, 210)); // ~3.5hr after last first pitch
      cards.push({
        show: 'Baseball Tonight',
        network: 'ESPN', chip: 'ESPN',
        time: '~' + postTime + ' ET',
        desc: 'Highlights, scores, and analysis from tonight\u2019s full MLB slate. Karl Ravech and analysts break down the biggest plays, pitching performances, and standings implications.',
        link: 'https://www.espn.com/watch/',
      });
    }

    // WC post-match coverage (Golazo / FOX Sports postgame)
    if (!wcDone && sport.includes('FIFA')) {
      wcDone = true;
      const postTime = fmtTime(shiftTime(lastGame.start_time, 120)); // ~2hr after last kickoff
      const lastNet = lastGame.nationalBundle === 'WC26_FREE' ? 'FOX' :
                      lastGame.nationalBundle === 'WC26_FS1'  ? 'FS1' : 'FOX';
      cards.push({
        show: 'FIFA World Cup Postgame',
        network: lastNet, chip: 'fox',
        time: '~' + postTime + ' ET',
        desc: 'Post-match analysis and reaction following today\u2019s FIFA World Cup 2026 matches. ' + lastGame.away + ' vs ' + lastGame.home + ' wraps the day\u2019s action.',
        link: 'https://www.foxsports.com/soccer/fifa-world-cup',
      });
    }
  }
  return cards;
}

function renderMedia(){
  // ── Assemble MEDIA_TODAY from templates + specials + dynamic injection ─────
  const dow = new Date().getDay();
  const isWeekend = dow===0||dow===6;
  const todayStr = TODAY_ISO;

  const baseCards    = isWeekend ? [...MEDIA_WEEKEND_BASE] : [...MEDIA_WEEKDAY];
  const specialCards = MEDIA_SPECIALS
    .filter(s => todayStr >= s.startDate && todayStr <= s.endDate)
    .map(s => s.card);
  const pregameCards  = buildDynamicPregames();
  const wcCards       = buildWCMediaCards();       // Item 4: per-game WC cards
  const playoffCards  = buildPlayoffSpecials();    // Item 3: auto Finals/CF cards
  const postgameCards = buildDynamicPostgames();   // Item 5: Baseball Tonight, WC post

  // Merge; deduplicate by show name (specials/pregames can override base).
  // Priority order: base < specials < playoff-auto < WC-per-game < pregames < postgames.
  // MEDIA_SPECIALS manual entries win over auto-generated playoff cards (manual has richer desc).
  const seen = new Set();
  let MEDIA_TODAY = [];
  for(const card of [...baseCards, ...specialCards, ...playoffCards, ...wcCards, ...pregameCards, ...postgameCards]){
    if(!seen.has(card.show)){ seen.add(card.show); MEDIA_TODAY.push(card); }
  }

  // SMT-A: sort by current relevance — currently airing first, then phase-aware
  MEDIA_TODAY.sort((a, b) => scoreSMTCard(b) - scoreSMTCard(a));

  const MEDIA_CHIP_COLORS = {
    ESPN:"#ff3c3c", FS1:"#f0c040", CBS:"#a78bfa",
    TNT:"#ff6b35",  NBC:"#00b4d8", MLB:"#c9a84c",
    prime:"#f8cf47", golazo:"#00b86b", netflix:"#e50914",
    default:"#888"
  };
  const grid = document.getElementById("media-grid");
  if(!grid) return;
  grid.innerHTML = MEDIA_TODAY.filter(m => m.show && m.network && m.time).map(m=>{
    const col = MEDIA_CHIP_COLORS[m.chip]||MEDIA_CHIP_COLORS.default;
    return `<div class="media-card" data-show="${(m.show||'').replace(/"/g,'&quot;')}">
      <div class="media-accent" style="background:${col}55"></div>
      <div class="media-body">
        <div class="media-show">${m.show}</div>
        <div class="media-meta">
          <span class="media-chip" style="color:${col};border-color:${col}40;background:${col}12">${m.network}</span>
          <span class="media-time">${m.time}</span>
        </div>
        <div class="media-desc">${m.desc}</div>
        ${m.journalNote?`<div class="field-note">${m.journalNote}</div>`:""}
        ${(m._trapTeams && m._trapTeams.length) ? m._trapTeams.map(tr => `<div class="wc-trap-chip">⚠ TRAP · ${tr.team} +${Math.round(tr.delta * 100)}pp as runner-up</div>`).join('') : ''}
        <a class="stream-chip" href="${m.link}" target="_blank" rel="noopener" style="color:${col};border-color:${col};background:${col}1a;font-size:.6rem;padding:.12rem .45rem">Watch →</a>
      </div>
    </div>`;
  }).join("");
}







// ── FIELD Desk ────────────────────────────────────────────────────────────────
// Aggregates editorial content already generated by other journalism systems.
// Zero new AI calls — pulls from:
//   _gameBriefCache        (WNBA/MLB game briefs from compound prompt)
//   sessionStorage         (series previews, EPL match briefs, field brief text)
//   J1/J4 badge state      (anti-hype flags, scout's picks from allData)
//   MEDIA_SPECIALS         (journalNote lines already in SMT cards)
//
// Card types:
//   type-brief   (gold)   — FIELD Brief / Night Owl summary
//   type-series  (indigo) — Series preview for each active playoff series
//   type-scout   (teal)   — Scout's Picks digest
//   type-antihype(amber)  — Anti-Hype report when J1 fires
//   type-europa  (orange) — UCL/UEL/UECL match briefs aggregated
// Tap-to-expand for desk cards and ambient brief card.
// Cards store full text in data-full; truncated text shown by default.
// Tap toggles between truncated and full. Tap again to collapse.
function _deskCardToggle(el) {
  const body = el.querySelector('.desk-card-body, .ap-card-text');
  if (!body) return;
  const full = el.dataset.full;
  if (!full) return;
  if (el.dataset.expanded === '1') {
    const len = parseInt(el.dataset.truncLen) || 250;
    body.textContent = full.slice(0, len).trim() + (full.length > len ? '\u2026' : '');
    el.dataset.expanded = '0';
  } else {
    body.textContent = full;
    el.dataset.expanded = '1';
  }
}

// Desk mode gate, added 2026-07-03 -- real, confirmed problem: FIELD Desk
// populated on every single page load via 6 real trigger call sites (normal
// journalism-pipeline events), regardless of whether the user ever looks at
// it -- the exact "stacked into the main consumer flow" issue identified
// earlier. Fixed by gating the single shared choke point (this function,
// not each of the 6 call sites individually -- lower risk, one change) 
// behind explicit entry. Reuses the section's own existing cold-load
// laziness as the mechanism (confirmed real: ~60px until populated) --
// just tightens WHEN "populate" fires, no new framework.
let _deskModeEntered = false;
let _rfdTimer = null;
function scheduleFieldDesk(delay) {
  if (!_deskModeEntered) return; // not yet entered -- stay cold
  if (_rfdTimer) clearTimeout(_rfdTimer);
  _rfdTimer = setTimeout(() => { _rfdTimer = null; renderFieldDesk(); }, delay || 200);
}
function renderFieldDesk(){
  const grid = document.getElementById('field-desk-grid');
  if(!grid) return;
  const cards = [];
  let desksec = document.getElementById('field-desk-section');

  // ── Card 1: FIELD Brief mirror ──────────────────────────────────────────
  try{
    const fbKey = typeof fieldBriefCacheKey === 'function' ? fieldBriefCacheKey() : null;
    const fbText = fbKey ? sessionStorage.getItem(fbKey) : null;
    if(fbText && fbText.length > 30){
      const _df1 = fbText.replace(/"/g,'&quot;');
      cards.push(`<div class="desk-card type-brief tappable" data-full="${_df1}" data-trunc-len="300" onclick="_deskCardToggle(this)">
        <div class="desk-card-label"><span class="desk-card-label-icon">📋</span>FIELD Brief</div>
        <div class="desk-card-body">${fbText.slice(0,300).trim()}${fbText.length>300?'\u2026':''}</div>
      </div>`);
    }
  }catch(e_){
    if(typeof window._fieldErrors !== 'undefined') window._fieldErrors.push({fn:'renderFieldDesk',err:e_?.message||String(e_),ts:Date.now()});}

  // ── Card 2: Series previews from sessionStorage ─────────────────────────
  const seriesCards = [];
  try{
    if(allData?.sports){
      (allData.sports).forEach(sec=>{
        (sec.games||[]).forEach(g=>{
          if(!g.seriesRecord || g.seriesRecord==='0-0') return;
          const ck = typeof seriesPreviewCacheKey==='function' ? seriesPreviewCacheKey(g) : null;
          const text = ck ? sessionStorage.getItem(ck) : null;
          if(text && text.length > 20){
            const _dfs = text.replace(/"/g,'&quot;');
            seriesCards.push(`<div class="desk-card type-series tappable" data-full="${_dfs}" data-trunc-len="250" onclick="_deskCardToggle(this)">
              <div class="desk-card-label"><span class="desk-card-label-icon">🏆</span>Series Brief · ${g.seriesRecord||''}</div>
              <div class="desk-card-title">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}</div>
              <div class="desk-card-body">${text.slice(0,250).trim()}${text.length>250?'\u2026':''}</div>
            </div>`);
          }
        });
      });
    }
  }catch(e_){ captureFieldError('render:field-desk-card2-series', e_, true); }
  cards.push(...seriesCards.slice(0,3));

  // ── Card 3: Game briefs from _gameBriefCache (WNBA/MLB) ────────────────
  try{
    if(typeof _gameBriefCache !== 'undefined'){
      const briefEntries = Object.entries(_gameBriefCache).slice(0,3);
      briefEntries.forEach(([gid, text])=>{
        if(!text || text.length < 20) return;
        let title = gid;
        try{
          (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
            if(g._id===gid) title = `${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}`;
          }));
        }catch(e__){}
        const _dfg = text.replace(/"/g,'&quot;');
        cards.push(`<div class="desk-card type-brief tappable" data-full="${_dfg}" data-trunc-len="250" onclick="_deskCardToggle(this)">
          <div class="desk-card-label"><span class="desk-card-label-icon">📰</span>FIELD Game Brief</div>
          <div class="desk-card-title">${title}</div>
          <div class="desk-card-body">${text.slice(0,250).trim()}${text.length>250?'\u2026':''}</div>
        </div>`);
      });
    }
  }catch(e_){ captureFieldError('render:field-desk-card3-briefs', e_, true); }

  // ── Card 4: Scout's Pick — single editorial pick of the night ──────────────
  // Uses buildSlateScoutsPick() to select ONE game from tonight's slate.
  // Shows the stat evidence + reason inline — no list, one confident recommendation.
  try{
    const allGames = (typeof allData !== 'undefined')
      ? (allData?.sports||[]).flatMap(s => s.games||[])
      : [];
    const topPick = (typeof buildSlateScoutsPick === 'function') ? buildSlateScoutsPick(allGames) : null;
    if(topPick){
      const sd = (typeof getStatOfDay === 'function')
        ? getStatOfDay(topPick, _gameSport(topPick)) : null;
      const statLine = sd ? `<div style="font-size:.64rem;color:#2dd4bf;margin-top:.2rem">📊 ${sd.fullText}</div>` : '';
      const gameKey = topPick._id || `${topPick.home}_${topPick.away}`;
      const ms = (typeof _bdlMilestonesCache !== 'undefined') ? _bdlMilestonesCache?.[gameKey] : null;
      const msLine = ms ? `<div style="font-size:.64rem;color:var(--smoke);margin-top:.15rem">🏆 ${ms.playerName} needs ${ms.gap} more ${ms.stat}</div>` : '';
      const isWCGame = /wc26|world cup|fifa/i.test(topPick._sport||topPick.league||'');
      const wcLine = isWCGame && /MD[23]/.test(topPick.league||'')
        ? `<div style="font-size:.64rem;color:var(--smoke);margin-top:.15rem">⚽ Advancement on the line</div>` : '';
      const network = gameNetwork(topPick);
      const networkLine = network ? `<span style="opacity:.6"> · ${network}</span>` : '';
      const seriesLine = topPick.seriesRecord ? `<div style="font-size:.64rem;color:var(--smoke);margin-top:.15rem">${topPick.seriesRecord}</div>` : '';
      // Count other qualifying games for footnote
      const totalPicks = allGames.filter(g=>{try{return isScoutsPick(g);}catch(e_){return false;}}).length;
      const footnote = totalPicks > 1 ? `<div style="font-size:.58rem;color:var(--smoke);margin-top:.4rem;opacity:.6">+${totalPicks-1} more qualifying tonight</div>` : '';
      cards.push(`<div class="desk-card type-scout" style="cursor:pointer" onclick="(()=>{const c=document.querySelector('[data-gameid=\"${topPick._id||''}\"]');if(c)c.scrollIntoView({behavior:'smooth',block:'center'});})()" title="Click to scroll to this game">
        <div class="desk-card-label"><span class="desk-card-label-icon">🔍</span>Scout's Pick · Tonight</div>
        <div class="desk-card-title" style="font-size:.8rem;font-weight:700;margin-top:.2rem">${topPick.away||''} @ ${topPick.home||''}${networkLine}</div>
        ${seriesLine}${statLine}${msLine}${wcLine}${footnote}
      </div>`);
    }
  }catch(e_){ captureFieldError('render:field-desk-card4-scouts-pick', e_, true); }

  // ── Card 5: Analytics Edge (Option C) ────────────────────────────────────
  // Appears on playoff/Finals nights when R2 analytics data is loaded.
  // Trigger: ≥1 featured game (SCF/Finals/WC) AND ≥1 R2 dataset loaded.
  // One game section per featured game, chip-based layout.
  // Designed to be scannable not readable — no prose, just signals.
  try {
    const _analyticsGames = (allData?.sports || [])
      .flatMap(s => s.games || [])
      .filter(g => {
        const lg = (g.league || g._sport || '').toLowerCase();
        return /stanley cup final|scf|nba finals|finals g\d/i.test(lg) ||
               (g.seriesRecord && /wc26|world cup/i.test(lg) === false && g.seriesRecord !== '0-0');
      });

    const _anyR2Loaded = _nhlSeriesLoaded || _nbaCluichLoaded || _nhlGSAXLoaded;
    if (_analyticsGames.length > 0 && _anyR2Loaded) {
      const gameSections = [];
      for (const ag of _analyticsGames.slice(0, 3)) {
        const chips = (typeof _buildAnalyticsChips === 'function') ? _buildAnalyticsChips(ag) : [];
        if (!chips.length) continue;
        const chipsHtml = (typeof _chipsHTML === 'function') ? _chipsHTML(chips) : '';
        const gameTitle = `${ag.away || '?'} @ ${ag.home || '?'}`;
        const seriesNote = ag.seriesRecord ? `<span class="dac dac-muted">${ag.seriesRecord}</span>` : '';
        gameSections.push(`
          <div class="desk-analytics-game">
            <div class="desk-analytics-game-title">${gameTitle}</div>
            <div class="desk-analytics-chips">${seriesNote}${chipsHtml}</div>
          </div>`);
      }
      if (gameSections.length > 0) {
        const sourceLabel = [
          _nhlSeriesLoaded ? 'NHL series' : '',
          _nbaCluichLoaded ? 'NBA clutch' : '',
          _nhlGSAXLoaded   ? 'GSAX'       : '',
        ].filter(Boolean).join(' · ');
        cards.push(`<div class="desk-card type-analytics">
          <div class="desk-card-label">
            <span class="desk-card-label-icon">📊</span>Analytics Edge
            <span style="font-size:.55rem;color:var(--smoke);font-weight:400;text-transform:none;letter-spacing:0;margin-left:auto">${sourceLabel}</span>
          </div>
          ${gameSections.join('')}
        </div>`);
      }
    }
  } catch(e_) { captureFieldError('render:field-desk-card5-analytics', e_, true); }

  // ── Card 6: Anti-Hype report ─────────────────────────────────────────────
  try{
    const hypeFlags = [...document.querySelectorAll('.anti-hype-badge')];
    if(hypeFlags.length > 0){
      const flagLines = hypeFlags.slice(0,3).map(badge=>{
        const card = badge.closest('.game-card');
        const home = card?.dataset.home||'';
        const away = card?.dataset.away||'';
        const label = badge.textContent||'';
        return `<div style="margin-bottom:.3rem"><strong style="font-size:.74rem">${away} @ ${home}</strong> <span style="font-size:.64rem;color:rgba(245,158,11,.9)">${label}</span></div>`;
      }).join('');
      cards.push(`<div class="desk-card type-antihype">
        <div class="desk-card-label"><span class="desk-card-label-icon">⚠️</span>Anti-Hype Report · ${hypeFlags.length} flag${hypeFlags.length===1?'':'s'}</div>
        <div class="desk-card-body">${flagLines}<div style="font-size:.64rem;color:var(--smoke);margin-top:.3rem">FIELD sees lower drama potential than the broadcast is suggesting.</div></div>
      </div>`);
    }
  }catch(e_){ captureFieldError('render:field-desk-card6-antihype', e_, true); }

  // ── Card 6: European soccer match briefs aggregated ──────────────────────
  try{
    const eplCards = [...document.querySelectorAll('.epl-match-brief-card')];
    eplCards.forEach(briefCard=>{
      const textEl = briefCard.querySelector('.epl-brief-text.loaded');
      if(!textEl || !textEl.textContent || textEl.textContent.length < 20) return;
      const gid = briefCard.dataset.gameid;
      let title = '';
      try{
        (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
          if(g._id===gid) title=`${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}`;
        }));
      }catch(e__){}
      const isEuropa = (briefCard.closest('[data-sport]')?.dataset.sport||'').toLowerCase().includes('europa');
      const _rawEpl = textEl.textContent;
      const _dfe = _rawEpl.replace(/"/g,'&quot;');
      cards.push(`<div class="desk-card ${isEuropa?'type-europa':'type-series'} tappable" data-full="${_dfe}" data-trunc-len="250" onclick="_deskCardToggle(this)">
        <div class="desk-card-label"><span class="desk-card-label-icon">⚽</span>Match Brief</div>
        ${title?`<div class="desk-card-title">${title}</div>`:''}
        <div class="desk-card-body">${_rawEpl.slice(0,250).trim()}${_rawEpl.length>250?'\u2026':''}</div>
      </div>`);
    });
  }catch(e_){ captureFieldError('render:field-desk-card6-epl', e_, true); }

  // P5: if no AI cards yet, show static brief text from #field-brief as a placeholder
  if(!cards.length){
    try {
      const staticBriefEl = document.querySelector('#field-brief .field-brief-text');
      const staticText = staticBriefEl?.textContent?.trim();
      if(staticText && staticText.length > 30 && !/Loading|Fetching|unavailable/i.test(staticText)){
        cards.push(`<div class="desk-card type-brief tappable" data-full="${staticText.replace(/"/g,'&quot;')}" data-trunc-len="300" onclick="_deskCardToggle(this)">
          <div class="desk-card-label"><span class="desk-card-label-icon">📋</span>FIELD Brief <span style="font-size:.45rem;opacity:.5;margin-left:.3rem">GENERATING</span></div>
          <div class="desk-card-body">${staticText.slice(0,300).trim()}${staticText.length>300?'\u2026':''}</div>
        </div>`);
      }
    } catch(e_) { captureFieldError('render:field-desk-static-fallback', e_, true); }
    if(!cards.length){ if(desksec) desksec.style.display='none'; return; }
  }
  if(desksec) desksec.style.display='';
  // CLS fix: skip DOM wipe if content hasn't changed — prevents collapse-expand shift
  const _newHTML = cards.join('');
  if (grid.innerHTML !== _newHTML) {
    grid.innerHTML = _newHTML;
  }
}


// ── Brief Archive — CC-CMD-2026-06-15-brief-archive Task 1 ────────────────
// Fire-and-forget persistence of every AI brief to D1 `briefs` via relay
// /archive/brief. The brief is already cached in sessionStorage and (for
// some types) KV with a TTL — this writes a permanent copy keyed by
// {brief_type, date, game_id} so editorial output survives cache expiry.
// CRITICAL: this must NEVER delay or break brief display. No await on the
// call sites; the .catch(()=>{}) below is mandatory. Archive backend
// failures are silent by design — if D1 / relay are down we lose the
// archive entry, not the user-visible brief.
function archiveBrief(type, sport, gameId, text, hash) {
  if (!text || text.length < 50) return;
  const date = new Date().toISOString().slice(0, 10);
  const id = type + '_' + date + '_' + (gameId || 'all');
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/brief', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({
      id, brief_type: type, date,
      sport: sport || null,
      game_id: gameId || null,
      brief_text: text,
      context_hash: hash || null,
      word_count: text.split(/\s+/).length,
    }),
  }).catch(e => captureFieldError('archive:brief', e, false));
}

// CC-CMD-2026-06-17: richer client-side archive helper for brief types that
// never reach the relay queue/KV (currently: series_preview and stakes_brief).
// Game_recap (Night Owl) and game_brief (J1 compound) writes are owned by
// the relay queue consumer + dead-hour KV sweep — do NOT call this helper
// from those paths. Object-keyed signature carries quality_score + model so
// the archive captures the L3 telemetry alongside the prose, and source:'client'
// lets the D1 dashboard distinguish browser-emitted rows from queue rows.
// Fire-and-forget; the try/catch + .catch() guarantee that an archive failure
// cannot block sessionStorage writes or the visible brief render.
async function _archiveBrief({briefType, sport, gameId, briefText, qualityScore, model}) {
  try {
    if (!briefText || typeof briefText !== 'string') return;
    const date = new Date().toISOString().slice(0, 10);
    const id = `${briefType}_${gameId || sport || 'unknown'}_${date}_${Date.now()}`;
    const base = (typeof V2_RELAY_BASE !== 'undefined')
      ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
    await fetch(base + '/archive/brief', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        id, date, brief_type: briefType,
        sport: sport || null,
        game_id: gameId || null,
        brief_text: briefText,
        model: model || 'gemini-3.1-flash-lite',
        quality_score: qualityScore || null,
        word_count: briefText.split(/\s+/).filter(Boolean).length,
        source: 'client',
      }),
    }).catch(e => captureFieldError('archive:brief-client-fetch', e, false));
  } catch(e) { captureFieldError('archive:brief-client', e, false); }
}

// ── FIELD Journalism Tab (PM-19, June 2 2026) ──────────────────────────────
// Magazine-style vertical-read destination. Sources from same caches as
// renderFieldDesk but presents in editorial reading order with J3 → J2 → J1
// hierarchy and explicit section markers.

function toggleJournalismView() {
  const body = document.body;
  const willActivate = !body.classList.contains('journalism-mode');
  // C2: scroll-position save/restore — preserve user's place in the schedule
  if (willActivate) {
    try { window._fieldScheduleScrollY = window.scrollY || 0; } catch(_) {}
  }
  body.classList.toggle('journalism-mode', willActivate);
  try { localStorage.setItem('field_journalism_mode', willActivate ? '1' : '0'); } catch(_) {}
  // Mutual exclusion: dismiss wc-mode if activating journalism
  if (willActivate && body.classList.contains('wc-mode')) {
    body.classList.remove('wc-mode');
    const _wcNavLnk = document.getElementById('wc-nav-link');
    if (_wcNavLnk) _wcNavLnk.classList.remove('active');
    const wcSec = document.getElementById('wc-section');
    if (wcSec) { wcSec.setAttribute('hidden', ''); wcSec.style.display = ''; }
  }
  // Mutual exclusion: dismiss pickem-mode too (CC-CMD-2026-07-05-pick-em-reconcile — 3-way now).
  if (willActivate && body.classList.contains('pickem-mode')) {
    body.classList.remove('pickem-mode');
    const _pickemNavLnk = document.getElementById('pickem-nav-link');
    if (_pickemNavLnk) _pickemNavLnk.classList.remove('active');
    const pickemSec = document.getElementById('pickem-section');
    if (pickemSec) { pickemSec.setAttribute('hidden', ''); pickemSec.style.display = ''; }
  }
  const navLink = document.getElementById('jrn-nav-link');
  if (navLink) navLink.classList.toggle('active', willActivate);
  if (willActivate) {
    renderJournalism();
    setTimeout(() => {
      const sec = document.getElementById('field-journalism-section');
      if (sec) {
        sec.removeAttribute('hidden');
        if (window.innerWidth >= 1200) {
          sec.scrollIntoView({behavior:'smooth',block:'start'});
        } else {
          window.scrollTo({top: 0, behavior: 'smooth'});
        }
      }
    }, 50);
  } else {
    // Re-add hidden attribute so the section is hidden across all viewports
    // when journalism-mode is off. The CSS body:not(.journalism-mode) rule
    // also hides it, but the attribute is belt-and-suspenders for older
    // browsers / inline-style residue.
    const sec = document.getElementById('field-journalism-section');
    if (sec) { sec.setAttribute('hidden', ''); sec.style.display = ''; }
    // C2: restore prior schedule scroll position rather than jumping to top
    const restoreY = (typeof window._fieldScheduleScrollY === 'number') ? window._fieldScheduleScrollY : 0;
    window.scrollTo({top: restoreY, behavior: 'smooth'});
  }
}

// C2: resize-aware journalism-mode behavior. If user rotates iPad portrait → landscape
// while in journalism-mode and crosses the 1200px threshold, the laptop+ layout (C3)
// will be in effect. For now, just ensure the section's [hidden] attr is cleared so
// the section stays visible across the transition. No teardown of body class needed —
// the CSS media queries handle the layout swap automatically.
(function(){
  let _jrnResizeRaf = null;
  window.addEventListener('resize', function(){
    if (_jrnResizeRaf) return;
    _jrnResizeRaf = requestAnimationFrame(function(){
      _jrnResizeRaf = null;
      if (document.body.classList.contains('journalism-mode')) {
        const sec = document.getElementById('field-journalism-section');
        if (sec && sec.hasAttribute('hidden')) sec.removeAttribute('hidden');
      }
    });
  }, { passive: true });
})();

function renderJournalism() {
  const sec = document.getElementById('field-journalism-section');
  const content = document.getElementById('jrn-content');
  if (!sec || !content) return;
  sec.removeAttribute('hidden');
  // Invalidate any archive-fallback fetch still in flight from
  // renderJournalismArchive() -- see that function's own guard comment.
  // Today's content below must never be clobbered by a late archive response.
  delete content.dataset.jrnArchiveReq;

  try {
    const tz = (typeof localTz === 'function') ? localTz() : 'America/New_York';
    const d = new Date();
    const dateStr = d.toLocaleDateString('en-US', { timeZone: tz, weekday:'short', month:'short', day:'numeric' });
    const dateEl = document.getElementById('jrn-date');
    if (dateEl) dateEl.textContent = dateStr;
  } catch(_) {}

  const sections = [];
  let briefCount = 0;
  let seriesCount = 0;
  let gameBriefCount = 0;

  // J3 Editorial
  try {
    const fbKey = typeof fieldBriefCacheKey === 'function' ? fieldBriefCacheKey() : null;
    const fbText = fbKey ? sessionStorage.getItem(fbKey) : null;
    if (fbText && fbText.length > 30) {
      const safe = fbText.replace(/</g,'&lt;').replace(/>/g,'&gt;');
      sections.push({ type: 'j3-editorial', html: `<article class="jrn-editorial-block">
        <div class="jrn-editorial-label">J3 · The Editorial</div>
        <div class="jrn-editorial">${safe}</div>
      </article>` });
      briefCount++;
    }
  } catch(_) {}

  // J2 Series Previews
  try {
    const seriesEntries = [];
    if (allData?.sports) {
      (allData.sports).forEach(sec_ => {
        (sec_.games||[]).forEach(g => {
          if (!g.seriesRecord) return;
          const ck = typeof seriesPreviewCacheKey === 'function' ? seriesPreviewCacheKey(g) : null;
          const text = ck ? sessionStorage.getItem(ck) : null;
          if (!text || text.length < 30) return;
          let weight = 0;
          const lg = (g.league||'').toLowerCase();
          if (/nba finals|stanley cup final/i.test(lg)) weight = 100;
          else if (/wcf|ecf|conference finals/i.test(lg)) weight = 80;
          else weight = 50;
          seriesEntries.push({ g, text, weight });
        });
      });
    }
    seriesEntries.sort((a,b) => b.weight - a.weight);
    seriesEntries.forEach(({ g, text }) => {
      const safe = text.replace(/</g,'&lt;').replace(/>/g,'&gt;');
      const marker = g.league || 'PLAYOFF GAME';
      const matchup = `${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}`;
      const streamLabel = gameNetwork(g);
      const timeStr = (typeof fmtTime === 'function') ? fmtTime(g.start_time) : '';
      const metaParts = [timeStr ? timeStr + ' ET' : '', streamLabel].filter(Boolean);
      let tonightHtml = '';
      if (g._id && typeof _gameBriefCache !== 'undefined' && _gameBriefCache[g._id]) {
        const j1 = _gameBriefCache[g._id];
        const safeJ1 = j1.replace(/</g,'&lt;').replace(/>/g,'&gt;');
        tonightHtml = `<div class="jrn-series-tonight"><span class="jrn-series-tonight-label">J1 · Tonight</span>${safeJ1}</div>`;
        gameBriefCount++;
      }
      sections.push({ type: 'j2-series', html: `<section class="jrn-series" data-gameid="${g._id||''}">
        <div class="jrn-eyebrow">J2 · Series Preview</div>
        <div class="jrn-series-marker">◆ ${marker}</div>
        <div class="jrn-series-game">${matchup}${metaParts.length?' · '+metaParts.join(' · '):''}</div>
        <div class="jrn-series-text">${safe}</div>
        ${tonightHtml}
        ${g._id ? `<a class="jrn-card-link" href="#" onclick="event.preventDefault();jumpToGameCard('${g._id}')">View card →</a>` : ''}
      </section>` });
      seriesCount++;
    });
  } catch(_) {}

  // J1 Regular-Season Slate
  try {
    if (typeof _gameBriefCache !== 'undefined') {
      const slateItems = [];
      const usedIds = new Set();
      (allData?.sports||[]).forEach(sec_ => (sec_.games||[]).forEach(g => {
        if (g.seriesRecord && g._id) {
          const ck = typeof seriesPreviewCacheKey === 'function' ? seriesPreviewCacheKey(g) : null;
          if (ck && sessionStorage.getItem(ck)) usedIds.add(g._id);
        }
      }));
      Object.entries(_gameBriefCache).forEach(([gid, text]) => {
        if (!text || text.length < 20) return;
        if (usedIds.has(gid)) return;
        let game = null;
        (allData?.sports||[]).forEach(sec_ => (sec_.games||[]).forEach(g => { if (g._id === gid) game = g; }));
        if (!game) return;
        const safe = text.replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const matchup = `${game.away||''} ${game.neutral?'vs':'@'} ${game.home||''}`;
        const stream = gameNetwork(game);
        const timeStr = (typeof fmtTime === 'function') ? fmtTime(game.start_time) : '';
        const metaParts = [timeStr ? timeStr + ' ET' : '', stream].filter(Boolean);
        slateItems.push(`<li class="jrn-slate-item" data-gameid="${gid}">
          <div class="jrn-slate-game">${matchup}</div>
          ${metaParts.length ? `<div class="jrn-slate-meta">${metaParts.join(' · ')}</div>` : ''}
          <div class="jrn-slate-brief">${safe}</div>
        </li>`);
        gameBriefCount++;
      });
      if (slateItems.length) {
        sections.push({ type: 'j1-slate', html: `<section class="jrn-slate">
          <div class="jrn-eyebrow">J1 · Tonight's Briefs</div>
          <div class="jrn-slate-marker">◆ Regular-Season Slate</div>
          <ul class="jrn-slate-list">${slateItems.join('')}</ul>
        </section>` });
      }
    }
  } catch(_) {}

  // Gap 8: sort sections by circadian mode priority, then tag each with data-journal-priority
  const _JOURNAL_PRIORITY = {
    PREVIEW: { 'j3-editorial': 1, 'j2-series': 0, 'j1-slate': 2 },
    PRIME:   { 'j3-editorial': 0, 'j2-series': 1, 'j1-slate': 2 },
    NIGHT:   { 'j3-editorial': 1, 'j2-series': 2, 'j1-slate': 0 },
    LATE:    { 'j3-editorial': 0, 'j2-series': 2, 'j1-slate': 1 },
    DAWN:    { 'j3-editorial': 0, 'j2-series': 2, 'j1-slate': 1 },
  };
  const _jMode = (typeof _circadianMode !== 'undefined' && _JOURNAL_PRIORITY[_circadianMode]) ? _circadianMode : 'PRIME';
  const _jPri = _JOURNAL_PRIORITY[_jMode];
  sections.sort((a, b) => ((_jPri[a.type] !== undefined ? _jPri[a.type] : 99) - (_jPri[b.type] !== undefined ? _jPri[b.type] : 99)));

  if (!sections.length) {
    content.innerHTML = '<div class="jrn-empty">Tonight\'s editorial is loading. Briefs render as the journalism pipeline completes — usually within the first minute after page load.</div>';
  } else {
    const interleaved = [];
    sections.forEach((s, i) => {
      if (i > 0) interleaved.push('<div class="jrn-section-divider"></div>');
      const pri = _jPri[s.type] !== undefined ? _jPri[s.type] : i;
      let tagged = s.html;
      if (s.type === 'j3-editorial') {
        tagged = tagged.replace('<article class="jrn-editorial-block">', `<article class="jrn-editorial-block" data-journal-priority="${pri}">`);
      } else if (s.type === 'j2-series') {
        tagged = tagged.replace(/(<section class="jrn-series"[^>]*)>/, `$1 data-journal-priority="${pri}">`);
      } else if (s.type === 'j1-slate') {
        tagged = tagged.replace('<section class="jrn-slate">', `<section class="jrn-slate" data-journal-priority="${pri}">`);
      }
      interleaved.push(tagged);
    });
    interleaved.push('<div class="jrn-archive-link"><a href="#" onclick="event.preventDefault();renderJournalismArchive()">Yesterday\'s FIELD →</a></div>');
    content.innerHTML = interleaved.join('');
  }

  const stackEl = document.getElementById('jrn-stack-summary');
  if (stackEl) {
    const parts = [];
    if (briefCount) parts.push('1 editorial');
    if (seriesCount) parts.push(seriesCount + ' series brief' + (seriesCount===1?'':'s'));
    if (gameBriefCount) parts.push(gameBriefCount + ' game brief' + (gameBriefCount===1?'':'s'));
    stackEl.textContent = parts.length ? parts.join(' · ') : 'briefs loading';
  }

  // C3: companion content (desktop 1440px+ only — CSS hides at smaller viewports
  // so always-render is cheap). Pass counts so we don't re-iterate.
  try {
    renderJournalismCompanion({ briefCount, seriesCount, gameBriefCount });
    // CC-CMD-2026-06-15-client-features Commit 1: Archive timeline fire-and-forget.
    // Never blocks the main journalism render; .catch(()=>{}) in loadArchiveTimeline.
    try { if (typeof loadArchiveTimeline === 'function') loadArchiveTimeline(); } catch(_) { captureFieldError('surface:archive-timeline', _, true); }
    // CC-CMD-2026-06-15-client-features-2 Commit 1: Upset archaeology fire-and-forget.
    try { if (typeof loadUpsets === 'function') loadUpsets(); } catch(_) { captureFieldError('surface:upsets', _, true); }
    // CC-CMD-2026-06-15-client-features-2 Commit 2: Market consensus fire-and-forget.
    try { if (typeof loadMarketConsensus === 'function') loadMarketConsensus(); } catch(_) { captureFieldError('surface:market-consensus', _, true); }
  } catch(_) { captureFieldError('surface:journalism-companion', _, false); }
}

function jumpToGameCard(gameId) {
  if (!gameId) return;
  if (window.innerWidth < 1200 && document.body.classList.contains('journalism-mode')) {
    toggleJournalismView();
  }
  setTimeout(() => {
    const card = document.querySelector(`.game-card[data-gameid="${gameId}"]`);
    if (card) {
      card.scrollIntoView({behavior:'smooth', block:'center'});
      card.style.outline = '2px solid var(--gold2)';
      setTimeout(() => { card.style.outline = ''; }, 1400);
    }
  }, 100);
}

// C4: Cross-link from bottom sheet → journalism tab anchored to the game.
// Closes the bottom sheet, enters journalism-mode if not already in it,
// then scrolls the matching [data-gameid] entry into view with a pulse.
function openJournalismForGame(gameId) {
  if (!gameId) return;
  try { closeBottomSheet(); } catch(_) {}
  setTimeout(() => {
    if (!document.body.classList.contains('journalism-mode')) {
      toggleJournalismView();
    } else {
      // Already in journalism mode — ensure content is rendered fresh
      try { renderJournalism(); } catch(_e) { captureFieldError('journalism:reopen-rerender', _e, true); }
    }
    setTimeout(() => {
      const el = document.querySelector(`[data-gameid="${gameId}"].jrn-series, [data-gameid="${gameId}"].jrn-slate-item`);
      if (el) {
        el.scrollIntoView({behavior:'smooth', block:'center'});
        const prevOutline = el.style.outline;
        el.style.outline = '2px solid var(--gold2)';
        el.style.outlineOffset = '4px';
        setTimeout(() => { el.style.outline = prevOutline; el.style.outlineOffset = ''; }, 1600);
      }
    }, 250);
  }, 100);
}

// ── CC-CMD-2026-06-15-client-features Commit 1: Archive Timeline ──────────
// renderArchiveTimeline — fire-and-forget pull from relay /archive/query.
// Source-cited briefs from D1 (slate cron writes). On failure, the section
// remains hidden; the main journalism rail is unaffected. sessionStorage
// cache keyed 'field_archive_timeline' avoids re-fetch on tab switches.
function renderArchiveTimeline(briefs) {
  const target = document.getElementById('jrn-archive-timeline');
  if (!target) return;
  const arr = Array.isArray(briefs) ? briefs
            : Array.isArray(briefs?.results) ? briefs.results
            : Array.isArray(briefs?.briefs) ? briefs.briefs
            : [];
  if (!arr.length) { target.setAttribute('hidden',''); return; }
  const rows = arr.slice(0, 10).map(b => {
    const date = String(b.date || '').slice(5).replace('-', '/');
    const type = String(b.brief_type || 'brief').toLowerCase();
    const text = String(b.brief_text || '').replace(/\s+/g,' ').trim();
    const snippet = text.length > 110 ? text.slice(0, 110) + '…' : text;
    const qs = (b.quality_score != null) ? `<span class="jrn-arch-qs">QS ${Math.round(b.quality_score)}</span>` : '';
    const id = (b.id || '').replace(/[^a-z0-9_-]/gi,'');
    return `<li class="jrn-arch-row" data-id="${id}" data-full="${encodeURIComponent(text)}">
      <span class="jrn-arch-date">${date}</span>
      <div class="jrn-arch-body">
        <div class="jrn-arch-meta">
          <span class="jrn-arch-type ${type}">${type.replace('_',' ')}</span>
          ${qs}
        </div>
        <div class="jrn-arch-snippet">${snippet}</div>
      </div>
    </li>`;
  }).join('');
  target.removeAttribute('hidden');
  target.innerHTML = `<div class="jrn-archive-timeline-head">
      <span class="jrn-archive-timeline-eyebrow">FIELD Archive</span>
      <span class="jrn-archive-timeline-sub">recent editorial · tap to expand</span>
    </div>
    <ul class="jrn-archive-timeline-list">${rows || '<li class="jrn-arch-empty">No archived briefs yet.</li>'}</ul>`;
  target.querySelectorAll('.jrn-arch-row').forEach(row => {
    row.addEventListener('click', () => {
      const expanded = row.classList.toggle('expanded');
      const snippet = row.querySelector('.jrn-arch-snippet');
      if (snippet) {
        if (expanded) {
          try { snippet.textContent = decodeURIComponent(row.dataset.full || ''); }
          catch(_e) { captureFieldError('journalism:archive-timeline-decode', _e, true); }
        } else {
          try {
            const t = decodeURIComponent(row.dataset.full || '');
            snippet.textContent = t.length > 110 ? t.slice(0, 110) + '…' : t;
          } catch(_e) { captureFieldError('journalism:archive-timeline-decode', _e, true); }
        }
      }
    });
  });
}

// Fire-and-forget archive fetch. The .catch(()=>{}) is mandatory.
// sessionStorage 'field_archive_timeline' caches the parsed response for
// the session; tab-switch re-renders read the cache instead of hitting
// the relay again. 30-min stale-after-write soft cap.
function loadArchiveTimeline() {
  if (typeof renderArchiveTimeline !== 'function') return;
  const cacheKey = 'field_archive_timeline';
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const c = JSON.parse(cached);
      if (c && (Date.now() - (c.ts || 0)) < 1800000 && c.data) {
        renderArchiveTimeline(c.data);
        return;
      }
    }
  } catch(e) { captureFieldError('archive:timeline-cache-read', e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/query?brief_type=slate&source=cron&limit=7')
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      if (!data) return;
      try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch(e) { captureFieldError('archive:timeline-cache-write', e, true); }
      renderArchiveTimeline(data);
    })
    .catch(e => captureFieldError('archive:timeline-fetch', e, false));
}

// ── CC-CMD-2026-06-15-client-features-2 Commit 1: Upset Archaeology ──────────
// Pulls games where the moneyline underdog won. Primary endpoint is
// /archive/upsets; on 404 we fall back to /archive/query?limit=20 and
// filter client-side. Both paths .catch(() => {}). Major upset = ML > +300.

// Normalize a games array out of multiple possible response envelopes.
function _upsetExtractGames(payload) {
  if (!payload) return [];
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload.results)) return payload.results;
  if (Array.isArray(payload.upsets)) return payload.upsets;
  if (Array.isArray(payload.games)) return payload.games;
  return [];
}

// True when the underdog (per moneyline) actually won the game.
function _isUpset(g) {
  if (!g) return false;
  const hs = g.home_score ?? g.homeScore;
  const as = g.away_score ?? g.awayScore;
  if (hs == null || as == null) return false;
  const homeWon = hs > as;
  // Find a moneyline pair. Accept opening_odds.{home,away} or odds.moneyline.{home,away}
  const ml = (g.opening_odds && g.opening_odds.moneyline) || g.opening_odds || g.odds?.moneyline;
  if (!ml) return false;
  const mlH = Number(ml.home);
  const mlA = Number(ml.away);
  if (!isFinite(mlH) || !isFinite(mlA)) return false;
  // American odds: higher positive number = bigger underdog
  const homeIsDog = mlH > mlA;
  return homeWon ? homeIsDog : !homeIsDog;
}

function renderUpsets(games) {
  const target = document.getElementById('jrn-upsets');
  if (!target) return;
  const list = Array.isArray(games) ? games.filter(_isUpset) : [];
  if (!list.length) { target.setAttribute('hidden',''); return; }
  // Sort by dog price desc — biggest upsets first.
  list.sort((a, b) => (_upsetDogPrice(b) || 0) - (_upsetDogPrice(a) || 0));
  const rows = list.slice(0, 8).map(g => {
    const date = String(g.date || '').slice(5).replace('-', '/');
    const home = g.home || g.home_team || '?';
    const away = g.away || g.away_team || '?';
    const hs = g.home_score ?? g.homeScore ?? '';
    const as = g.away_score ?? g.awayScore ?? '';
    const dogPrice = _upsetDogPrice(g);
    const isMajor = dogPrice != null && dogPrice > 300;
    const dogLabel = dogPrice != null
      ? `<span class="jrn-upset-tag">${dogPrice > 0 ? '+' : ''}${dogPrice} underdog</span>`
      : '<span class="jrn-upset-tag">underdog win</span>';
    return `<li class="jrn-upset-card ${isMajor ? 'major' : ''}">
      <span class="jrn-upset-date">${date}</span>
      <div class="jrn-upset-body">
        <div class="jrn-upset-matchup"><b>${away}</b> ${as} @ <b>${home}</b> ${hs}</div>
        <div class="jrn-upset-meta">${dogLabel}${g.sport ? `<span>${String(g.sport)}</span>` : ''}</div>
      </div>
    </li>`;
  }).join('');
  target.removeAttribute('hidden');
  target.innerHTML = `<div class="jrn-upsets-head">
      <span class="jrn-upsets-eyebrow">Upsets</span>
      <span class="jrn-upsets-sub">underdog wins · biggest first</span>
    </div>
    <ul class="jrn-upsets-list">${rows}</ul>`;
}

// ── CC-CMD-2026-06-15-client-features-2 Commit 2: Market Consensus Tracker ───
// "MARKET WATCH" stats block — aggregate market outcomes per sport.
// Pure derivation over archived games with opening_odds; rendered as a
// compact label/stats grid. If no games carry odds data the section
// stays hidden (relay still deploying).

function _consensusFavoriteWonRate(games) {
  let n = 0, fav = 0;
  for (const g of games) {
    const ml = (g.opening_odds && g.opening_odds.moneyline) || g.opening_odds || g.odds?.moneyline;
    if (!ml) continue;
    const mlH = Number(ml.home);
    const mlA = Number(ml.away);
    if (!isFinite(mlH) || !isFinite(mlA)) continue;
    const hs = g.home_score ?? g.homeScore;
    const as = g.away_score ?? g.awayScore;
    if (hs == null || as == null) continue;
    n++;
    const favHome = mlH < mlA; // lower (or more negative) = favorite
    const homeWon = hs > as;
    if (favHome === homeWon) fav++;
  }
  return n ? { rate: fav / n, n } : null;
}

function _consensusHomeWinRate(games) {
  let n = 0, home = 0;
  for (const g of games) {
    const hs = g.home_score ?? g.homeScore;
    const as = g.away_score ?? g.awayScore;
    if (hs == null || as == null) continue;
    n++;
    if (hs > as) home++;
  }
  return n ? { rate: home / n, n } : null;
}

function _consensusOverRate(games) {
  let n = 0, over = 0;
  for (const g of games) {
    const total = g.opening_odds?.total ?? g.odds?.total;
    if (total == null) continue;
    const t = Number(total);
    if (!isFinite(t)) continue;
    const hs = g.home_score ?? g.homeScore;
    const as = g.away_score ?? g.awayScore;
    if (hs == null || as == null) continue;
    const sum = Number(hs) + Number(as);
    if (!isFinite(sum)) continue;
    if (sum === t) continue; // push
    n++;
    if (sum > t) over++;
  }
  return n ? { rate: over / n, n } : null;
}

// computeMarketConsensus(games) — bucket games by sport, derive rates.
// Returns [{sport, favRate, homeRate, overRate, n}] for sports with >= 3
// games carrying opening_odds. Sorted by sample size descending.
function computeMarketConsensus(games) {
  if (!Array.isArray(games)) return [];
  const buckets = new Map();
  for (const g of games) {
    if (!g) continue;
    const ml = (g.opening_odds && g.opening_odds.moneyline) || g.opening_odds || g.odds?.moneyline;
    if (!ml) continue;
    const sport = String(_gameSport(g)||'Other').trim() || 'Other';
    if (!buckets.has(sport)) buckets.set(sport, []);
    buckets.get(sport).push(g);
  }
  const out = [];
  for (const [sport, list] of buckets.entries()) {
    if (list.length < 3) continue;
    const fav = _consensusFavoriteWonRate(list);
    const home = _consensusHomeWinRate(list);
    const over = _consensusOverRate(list);
    out.push({
      sport,
      n: list.length,
      favRate: fav ? fav.rate : null,
      homeRate: home ? home.rate : null,
      overRate: over ? over.rate : null,
    });
  }
  out.sort((a, b) => b.n - a.n);
  return out;
}

function renderMarketConsensus(games) {
  const target = document.getElementById('jrn-market-consensus');
  if (!target) return;
  const rows = computeMarketConsensus(games);
  if (!rows.length) { target.setAttribute('hidden',''); return; }
  const pct = v => v == null ? '—' : Math.round(v * 100) + '%';
  const html = rows.slice(0, 6).map(r => {
    const stats = [];
    if (r.favRate != null) stats.push(`Favorites <b>${pct(r.favRate)}</b>`);
    if (r.homeRate != null) stats.push(`Home <b>${pct(r.homeRate)}</b>`);
    if (r.overRate != null) stats.push(`Overs <b>${pct(r.overRate)}</b>`);
    return `<li class="jrn-mc-row">
      <span class="jrn-mc-label">${r.sport}</span>
      <span class="jrn-mc-stats">${stats.join(' · ')}</span>
    </li>`;
  }).join('');
  target.removeAttribute('hidden');
  target.innerHTML = `<div class="jrn-mc-head">Market Watch</div>
    <ul class="jrn-mc-list">${html}</ul>`;
}

// Fire-and-forget. Same /archive/query pull as the upset loader serves
// double-duty here — the sessionStorage cache from loadUpsets is reused
// when present to avoid a duplicate fetch.
function loadMarketConsensus() {
  if (typeof renderMarketConsensus !== 'function') return;
  // Prefer the cached upset payload if it's the broader query shape.
  try {
    const cached = sessionStorage.getItem('field_archive_upsets');
    if (cached) {
      const c = JSON.parse(cached);
      if (c && Array.isArray(c.games) && (Date.now() - (c.ts || 0)) < 1800000) {
        renderMarketConsensus(c.games);
        // Still keep the cached pull authoritative — return.
        return;
      }
    }
  } catch(e) { captureFieldError('archive:market-consensus-cache-read', e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/query?limit=50')
    .then(r => r.ok ? r.json() : null)
    .then(payload => {
      if (!payload) return;
      const games = _upsetExtractGames(payload);
      if (!games.length) return;
      try { sessionStorage.setItem('field_archive_upsets',
        JSON.stringify({ ts: Date.now(), games })); } catch(e) { captureFieldError('archive:market-consensus-cache-write', e, true); }
      renderMarketConsensus(games);
    })
    .catch(e => captureFieldError('archive:market-consensus-fetch', e, false));
}

// Fire-and-forget upset loader. Try /archive/upsets first; on any failure
// fall back to /archive/query?limit=20 and filter locally. Both paths
// .catch(() => {}) — the journalism rail is never blocked.
function loadUpsets() {
  if (typeof renderUpsets !== 'function') return;
  const cacheKey = 'field_archive_upsets';
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const c = JSON.parse(cached);
      if (c && (Date.now() - (c.ts || 0)) < 1800000 && Array.isArray(c.games)) {
        renderUpsets(c.games);
        return;
      }
    }
  } catch(e) { captureFieldError('archive:upsets-cache-read', e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/upsets')
    .then(r => r.ok ? r.json() : null)
    .then(payload => {
      if (payload) {
        const games = _upsetExtractGames(payload);
        if (games.length) {
          try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), games })); } catch(e) { captureFieldError('archive:upsets-cache-write', e, true); }
          renderUpsets(games);
          return;
        }
      }
      // Fallback: /archive/query?limit=20 with client-side filter.
      fetch(base + '/archive/query?limit=20')
        .then(r2 => r2.ok ? r2.json() : null)
        .then(payload2 => {
          if (!payload2) return;
          const games2 = _upsetExtractGames(payload2);
          if (!games2.length) return;
          try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), games: games2 })); } catch(e) { captureFieldError('archive:upsets-cache-write', e, true); }
          renderUpsets(games2);
        })
        .catch(e => captureFieldError('archive:upsets-fallback-fetch', e, false));
    })
    .catch(e => captureFieldError('archive:upsets-fetch', e, false));
}

// C3: Companion sidebar at desktop (1440px+). Sources are read-only — same
// caches the schedule already uses. Patent-visible surfacing of the J1-J5
// quality architecture via the field_jq_scores telemetry.
function renderJournalismCompanion(counts) {
  const aside = document.getElementById('jrn-companion');
  if (!aside) return;
  const c = counts || { briefCount: 0, seriesCount: 0, gameBriefCount: 0 };
  const blocks = [];

  // Block 1: Tonight's Read summary
  const totalBriefs = (c.briefCount||0) + (c.seriesCount||0) + (c.gameBriefCount||0);
  if (totalBriefs) {
    const parts = [];
    if (c.briefCount) parts.push(`<strong>${c.briefCount}</strong> editorial`);
    if (c.seriesCount) parts.push(`<strong>${c.seriesCount}</strong> series brief${c.seriesCount===1?'':'s'}`);
    if (c.gameBriefCount) parts.push(`<strong>${c.gameBriefCount}</strong> game brief${c.gameBriefCount===1?'':'s'}`);
    blocks.push(`<div class="jrn-companion-block">
      <div class="jrn-companion-label">Tonight's Read</div>
      <div class="jrn-companion-summary">${parts.join(' · ')}</div>
    </div>`);
  } else {
    blocks.push(`<div class="jrn-companion-block">
      <div class="jrn-companion-label">Tonight's Read</div>
      <div class="jrn-companion-empty">Briefs loading…</div>
    </div>`);
  }

  // Block 2: Yesterday — link to archive
  blocks.push(`<div class="jrn-companion-block">
    <div class="jrn-companion-label">Archive</div>
    <a class="jrn-companion-link" onclick="event.preventDefault();renderJournalismArchive()">Yesterday's FIELD →</a>
  </div>`);

  // Block 3: Later Tonight — playoff games (seriesRecord) still upcoming today
  try {
    const now = Date.now();
    const items = [];
    (allData?.sports||[]).forEach(sec_ => (sec_.games||[]).forEach(g => {
      if (!g.seriesRecord || !g.start_time) return;
      const gt = new Date(g.start_time).getTime();
      if (isNaN(gt) || gt <= now) return;
      const matchup = `${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}`;
      const timeStr = (typeof fmtTime === 'function') ? fmtTime(g.start_time) : '';
      const streamLabel = gameNetwork(g);
      const metaBits = [timeStr ? timeStr + ' ET' : '', g.league || '', streamLabel].filter(Boolean);
      items.push({ matchup, meta: metaBits.join(' · '), gt });
    }));
    items.sort((a,b) => a.gt - b.gt);
    if (items.length) {
      const lis = items.slice(0, 4).map(i => `<li class="jrn-companion-item">
        ${i.matchup}
        <div class="jrn-companion-item-meta">${i.meta}</div>
      </li>`).join('');
      blocks.push(`<div class="jrn-companion-block">
        <div class="jrn-companion-label">Later Tonight</div>
        <ul class="jrn-companion-list">${lis}</ul>
      </div>`);
    }
    // Honest note: FIELD's schedule is today-only (buildTodaySchedule). Multi-day
    // outlook is intentionally omitted rather than fabricated.
  } catch(_e) { captureFieldError('journalism:companion-later-tonight', _e, true); }

  // Block 4: Active Layers (PM-19 retro) — patent-visible static surfacing of
  // the quality enforcement chain. Distinct from per-brief telemetry: this
  // shows the ARCHITECTURE (what's instrumented), the next block shows the
  // OUTCOMES (recent score averages). Together they document the layered
  // quality chain that's central to the USPTO provisional claim.
  blocks.push(`<div class="jrn-companion-block">
    <div class="jrn-companion-label">Active Layers</div>
    <ul class="jrn-companion-list">
      <li class="jrn-companion-item"><strong>L1</strong> · Prompt-level
        <div class="jrn-companion-item-meta">voice + state clauses + matchup anchors</div></li>
      <li class="jrn-companion-item"><strong>L2</strong> · Detection retry
        <div class="jrn-companion-item-meta">8 detectors: cliche, lead, stats, score, wire-copy, narrative, record, sport vocab</div></li>
      <li class="jrn-companion-item"><strong>L3</strong> · Scoring + feedback
        <div class="jrn-companion-item-meta">Datamuse freshness + per-sport quality target</div></li>
    </ul>
  </div>`);

  // Block 5: Quality Scores (patent-visible J1-J5 telemetry)
  try {
    const scores = JSON.parse(localStorage.getItem('field_jq_scores')||'[]');
    if (Array.isArray(scores) && scores.length >= 3) {
      // Take most recent 20 to avoid stale data dominating
      const recent = scores.slice(-20);
      const avgScore = recent.reduce((a,s) => a + (s.score||0), 0) / recent.length;
      const avgStat  = recent.reduce((a,s) => a + (s.stat ||0), 0) / recent.length;
      const scoreClass = avgScore >= 145 ? 'good' : (avgScore >= 120 ? '' : 'warn');
      const statClass  = avgStat  >= 1.8 ? 'good' : (avgStat  >= 1.4 ? '' : 'warn');
      blocks.push(`<div class="jrn-companion-block">
        <div class="jrn-companion-label">Quality (recent ${recent.length})</div>
        <div class="jrn-quality-row">
          <span class="jrn-quality-row-label">Prose score</span>
          <span class="jrn-quality-row-value ${scoreClass}">${Math.round(avgScore)}/300</span>
        </div>
        <div class="jrn-quality-row">
          <span class="jrn-quality-row-label">Stat depth</span>
          <span class="jrn-quality-row-value ${statClass}">${avgStat.toFixed(1)}/sent</span>
        </div>
      </div>`);
    }
  } catch(_e) { captureFieldError('journalism:companion-quality-scores', _e, true); }

  aside.innerHTML = blocks.join('');
}

function renderJournalismArchive() {
  const content = document.getElementById('jrn-content');
  if (!content) return;
  // BUG FIX (2026-07-12): this function's card-rendering branch referenced
  // a bare `tz` that was never declared in this scope (only ever declared
  // LOCALLY inside other, unrelated functions) -- every call that reached
  // it threw ReferenceError: tz is not defined, silently doing nothing
  // (uncaught in an onclick handler). Declared here, same fallback idiom
  // renderJournalism() already uses one screen over.
  const tz = (typeof localTz === 'function') ? localTz() : 'America/New_York';
  // Stale-response guard: renderJournalism() clears this token whenever
  // today's view (re)renders. If the user leaves the archive (or re-opens
  // it) while the server fallback below is still in flight, its response
  // must not land on top of whatever's on screen by the time it resolves.
  const _archiveReqId = 'r' + Date.now() + '_' + Math.random().toString(36).slice(2);
  content.dataset.jrnArchiveReq = _archiveReqId;

  const renderCards = (entries) => {
    const cards = entries.map(e => {
      const safe = e.text.replace(/</g,'&lt;').replace(/>/g,'&gt;');
      const label = e.date
        ? e.date.toLocaleDateString('en-US', { timeZone: tz, weekday:'long', month:'long', day:'numeric' })
        : e.dateStr;
      return `<article class="jrn-editorial-block">
        <div class="jrn-editorial-label">${label}</div>
        <div class="jrn-editorial">${safe}</div>
      </article>`;
    });
    const interleaved = [];
    cards.forEach((c, i) => { if (i > 0) interleaved.push('<div class="jrn-section-divider"></div>'); interleaved.push(c); });
    interleaved.push('<div class="jrn-archive-link"><a href="#" onclick="event.preventDefault();renderJournalism()">← Back to Today</a></div>');
    content.innerHTML = interleaved.join('');
  };
  const renderEmpty = () => {
    content.innerHTML = `<div class="jrn-empty">No prior FIELD editorials found.<br>Archive populates as slate briefs are generated — check back after tonight's editorial runs.</div>
      <div class="jrn-archive-link"><a href="#" onclick="event.preventDefault();renderJournalism()">← Back to Today</a></div>`;
  };

  // PM-19 retro: archive keys must match the keys briefs are stored under.
  // Both ends use ET via fieldDateKey — survives users in non-ET zones.
  const today = new Date();
  const archiveEntries = [];
  for (let i = 1; i <= 7; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const ds = fieldDateKey(d);
    const key = 'field_brief_' + ds;  // matches fieldBriefCacheKey now that it uses FIELD_TZ
    const text = sessionStorage.getItem(key);
    if (text && text.length > 30) {
      archiveEntries.push({ date: d, dateStr: ds, text });
    }
  }
  if (archiveEntries.length) { renderCards(archiveEntries); return; }

  // Session storage has nothing for THIS browser (fresh session, cleared
  // storage, or the user just hasn't had FIELD open on those specific days
  // here) -- fall back to the server-backed archive (D1 via /archive/query)
  // instead of silently declaring "no archive" when real archived briefs
  // exist. Same endpoint + 30-min cache convention loadArchiveTimeline()
  // already uses (Rule 78 -- reuse the existing pattern, don't add a
  // second independent naked fetch against the same endpoint).
  content.innerHTML = '<div class="jrn-empty">Loading archive…</div>';
  const cacheKey = 'field_archive_timeline';
  const useServerData = (data) => {
    if (content.dataset.jrnArchiveReq !== _archiveReqId) return; // stale — see guard comment above
    const arr = Array.isArray(data) ? data
      : Array.isArray(data?.results) ? data.results
      : Array.isArray(data?.briefs) ? data.briefs
      : [];
    const serverEntries = arr
      .map(b => ({
        date: b.date ? new Date(b.date + 'T12:00:00') : null, // noon local avoids UTC-midnight date-shift
        dateStr: b.date || '',
        text: String(b.brief_text || '').trim(),
      }))
      .filter(e => e.text.length > 30);
    if (!serverEntries.length) { renderEmpty(); return; }
    renderCards(serverEntries);
  };
  let cached = null;
  try {
    const raw = sessionStorage.getItem(cacheKey);
    if (raw) {
      const c = JSON.parse(raw);
      if (c && (Date.now() - (c.ts || 0)) < 1800000 && c.data) cached = c.data;
    }
  } catch(e) { captureFieldError('archive:journalism-archive-cache-read', e, true); }
  if (cached) { useServerData(cached); return; }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(base + '/archive/query?brief_type=slate&source=cron&limit=7')
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      if (!data) { if (content.dataset.jrnArchiveReq === _archiveReqId) renderEmpty(); return; }
      try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch(e) { captureFieldError('archive:journalism-archive-cache-write', e, true); }
      useServerData(data);
    })
    .catch(e => { captureFieldError('archive:journalism-archive-fetch', e, false); if (content.dataset.jrnArchiveReq === _archiveReqId) renderEmpty(); });
}


// ═══════════════════════════════════════════════════════════════
// BALLDONTLIE ENGINE — Injuries, Stats, Live Game Data
// ═══════════════════════════════════════════════════════════════

// ── Cache ──────────────────────────────────────────────────────
const bdlCache = {
  injuries:  {},   // sport → [{player, team, status, description}]
  stats:     {},   // sport → [{player, team, stat_line}]
  gameData:  {},   // game_id → {period, time, status, home_score, away_score}
  lastFetch: {},   // sport → timestamp
};
const BDL_CACHE_TTL = 60 * 60 * 1000; // 1 hour for injuries/stats

// ── Sport keys map FIELD sport names → BDL API paths ──────────
const BDL_SPORT_MAP = {
  // NOTE May 15 2026: All /v1/injuries endpoints returning 404.
  // Balldontlie free key does not support injury data at these paths.
  // Re-add entries when correct API paths are verified.
  // "NBA Playoffs": { league:"nba", injuryPath:"/nba/v1/injuries", statsPath:"/nba/v1/stats" },
};

// ── Generic BDL fetch with auth header ────────────────────────
async function bdlFetch(path, params = {}) {
  if (!BDL_KEY) return null;
  const url = new URL(BDL_BASE + path);
  Object.entries(params).forEach(([k,v]) => url.searchParams.set(k, v));
  try {
    const r = await fetch(url.toString(), {
      headers: { "Authorization": BDL_KEY },
      signal: AbortSignal.timeout(4000)
    });
    if (!r.ok) { if(FIELD_DEBUG) console.warn("[BDL] HTTP", r.status, path); return null; }
    return await r.json();
  } catch(e) {
    if(FIELD_DEBUG) console.warn("[BDL] fetch error:", e.message);
    captureFieldError('bdl:fetch', e, true);
    return null;
  }
}

// ── Fetch injuries for a sport ─────────────────────────────────
// ── BDL localStorage persistence ─────────────────────────────────────────────
// Injury data rarely changes minute-to-minute. Persisting to localStorage
// means returning users within 1hr see 0 BDL requests on reload.
// Key format: "bdl_inj_{sport}" → {data:[...], ts:timestamp}
function bdlSave(key, data){
  try{
    localStorage.setItem("bdl_"+key, JSON.stringify({data, ts:Date.now()}));
  }catch(e){ /* storage full or private mode — silent */ }
}
function bdlLoad(key){
  try{
    const raw = localStorage.getItem("bdl_"+key);
    if(!raw) return null;
    const {data, ts} = JSON.parse(raw);
    if(Date.now() - ts < BDL_CACHE_TTL) return data; // fresh
    localStorage.removeItem("bdl_"+key);             // expired — clear it
  }catch(e){if(FIELD_DEBUG)console.debug('[bdlLoad] cache error:',e.message);captureFieldError('bdl:cache-read', e, true);}
  return null;
}

async function bdlFetchInjuries(sportName) {
  const map = BDL_SPORT_MAP[sportName];
  if (!map) return [];
  const now = Date.now();
  // Layer 1: in-memory cache (fastest, resets on reload)
  if (bdlCache.injuries[sportName] && (now - bdlCache.lastFetch["inj_"+sportName]) < BDL_CACHE_TTL) {
    return bdlCache.injuries[sportName];
  }
  // Layer 2: localStorage cache (survives reload — returning users pay 0 BDL requests)
  const stored = bdlLoad("inj_"+sportName);
  if(stored){
    bdlCache.injuries[sportName] = stored;       // warm the in-memory cache
    bdlCache.lastFetch["inj_"+sportName] = now;  // prevent re-checking localStorage this session
    if(FIELD_DEBUG) console.debug(`[BDL] ${sportName} injuries from localStorage`);
    return stored;
  }
  const data = await bdlFetch(map.injuryPath, { per_page: 100 });
  if (!data || !data.data) return [];
  const injuries = data.data.map(i => ({
    player: i.player ? `${i.player.first_name} ${i.player.last_name}` : (i.player_name || ""),
    team:   i.team   ? (i.team.abbreviation || i.team.name || "") : (i.team_name || ""),
    status: i.status || "",
    desc:   i.description || i.injury_notes || "",
  })).filter(i => i.player && i.status);
  bdlCache.injuries[sportName] = injuries;
  bdlCache.lastFetch["inj_"+sportName] = now;
  bdlSave("inj_"+sportName, injuries); // persist to localStorage for next reload
  if(FIELD_DEBUG) console.debug(`[BDL] ${sportName} injuries: ${injuries.length} (saved to localStorage)`);
  return injuries;
}


// ── Build injury HTML for a game card ─────────────────────────
// Returns "" if no relevant injuries, or a badge string
function bdlInjuryBadge(home, away, injuries) {
  if (!injuries || !injuries.length) return "";
  const homeWords = home.toLowerCase().split(" ").filter(w => w.length > 3);
  const awayWords = away.toLowerCase().split(" ").filter(w => w.length > 3);
  const relevant = injuries.filter(inj => {
    const t = inj.team.toLowerCase();
    return homeWords.some(w => t.includes(w)) || awayWords.some(w => t.includes(w));
  });
  if (!relevant.length) return "";
  // Show max 3 injuries — prioritize OUT over Q over D
  const priority = { "out":0, "o":0, "questionable":1, "q":1, "doubtful":2, "d":2 };
  const sorted = relevant.sort((a,b) => {
    const pa = priority[a.status.toLowerCase()] ?? 3;
    const pb = priority[b.status.toLowerCase()] ?? 3;
    return pa - pb;
  }).slice(0,3);
  const chips = sorted.map(inj => {
    const s = inj.status.toUpperCase();
    const cls = s === "OUT" || s === "O" ? "inj-out" : s === "Q" || s === "QUESTIONABLE" ? "inj-q" : "inj-d";
    return `<span class="inj-chip ${cls}"><span class="inj-player">${inj.player}</span><span class="inj-status">${s}</span></span>`;
  }).join("");
  return `<div class="inj-row">${chips}</div>`;
}

// ── Prefetch FD live scores — single batch call replaces N sequential calls ──
// OLD: 9 sequential calls with 7s gaps = 63s minimum, 9 API quota units
// NEW: 1 batch call via /matches?competitions=PL,PD,...  = <1s, 1 quota unit
// Relay caches the response 60s — all users share the same upstream call
// 2026-07-13 (follow-up to CC-CMD-2026-07-13-fetchnhlrelayscores-migration,
// same bug pattern confirmed by direct read): migrated to fieldOperation().
// The catch only conditionally console.debug'd and never called
// captureFieldError -- the relay-fd caller's own
// `.catch(e=>captureFieldError(...))` could never fire. applyFDLiveToCards()
// moved inside the wrapped callback, as the last statement, to preserve the
// original behavior exactly: the old catch's `return;` skipped it on
// failure, so it only ran on success -- same here, since it's now simply
// the last line of a callback that only completes on success.
async function fdPrefetchSoccerLive(){
  if(!allData||!allData.sports) return;
  const soccerSections = allData.sports.filter(s => FD_LEAGUE_MAP[s.sport]);
  if(!soccerSections.length) return;

  // Build competition code list from only the competitions active today
  const codes = [...new Set(soccerSections.map(s => FD_LEAGUE_MAP[s.sport]))].join(',');
  const dateStr = isoDate; // YYYY-MM-DD current viewing date

  return fieldOperation({subsystem:'scores', operation:'fetch-fd-soccer', retryable:true}, async () => {
    // Single batch request: all competitions, today's date
    const data = await fdFetch(`/matches?competitions=${codes}&dateFrom=${dateStr}&dateTo=${dateStr}`);
    const allMatches = data.matches || [];

    // Distribute matches into fdLiveCache keyed by competition code
    // Also capture match IDs into fdMatchIdCache for H2H lookup
    const byCode = {};
    for(const m of allMatches){
      const code = m.competition?.code;
      if(!code) continue;
      if(!byCode[code]) byCode[code] = [];
      const homeShort = m.homeTeam?.shortName || m.homeTeam?.name || "";
      const awayShort = m.awayTeam?.shortName || m.awayTeam?.name || "";
      byCode[code].push({
        id:        m.id,
        homeTeam:  homeShort,
        awayTeam:  awayShort,
        homeScore: m.score?.fullTime?.home ?? m.score?.halfTime?.home ?? null,
        awayScore: m.score?.fullTime?.away ?? m.score?.halfTime?.away ?? null,
        htHome: m.score?.halfTime?.home ?? null,
        htAway: m.score?.halfTime?.away ?? null,
        minute:    m.minute || null,
        status:    m.status,
        goals:     (m.goals||[]).map(g=>({
          team:   g.team?.shortName || g.team?.name || "",
          player: teamNick(g.scorer?.name),
          minute: g.minute
        }))
      });
      // Store FD match ID for H2H lookup — key by "home_away" normalized
      if(m.id && homeShort && awayShort){
        const matchKey = homeShort.toLowerCase().replace(/[^a-z]/g,'').slice(0,6)
          + '_' + awayShort.toLowerCase().replace(/[^a-z]/g,'').slice(0,6);
        fdMatchIdCache[matchKey] = m.id;
      }
    }

    // Populate cache for each competition
    const now = Date.now();
    for(const [code, matches] of Object.entries(byCode)){
      fdLiveCache[code]     = matches;
      fdLiveCacheTime[code] = now;
    }
    if(FIELD_DEBUG) console.debug(`[FD] batch fetched ${allMatches.length} matches across ${Object.keys(byCode).length} competitions`);
    applyFDLiveToCards();
  });
}

// Apply FD live scores to soccer game cards (parallel path to Fotmob)
function applyFDLiveToCards(){
  if(!allData||!allData.sports) return;
  let updated = 0;
  allData.sports.forEach(sec=>{
    const code = FD_LEAGUE_MAP[sec.sport];
    if(!code) return;
    const matches = fdLiveCache[code];
    if(!matches||!matches.length) return;
    (sec.games||[]).forEach(game=>{
      if(!game._id) return;
      const fdMatch = matches.find(m=>{
        const h=(m.homeTeam||"").toLowerCase(), a=(m.awayTeam||"").toLowerCase();
        const gh=(game.home||"").toLowerCase(), ga=(game.away||"").toLowerCase();
        return (gh.includes(h)||h.includes(gh.split(" ")[0]))&&
               (ga.includes(a)||a.includes(ga.split(" ")[0]));
      });
      if(!fdMatch) return;
      const isLive    = ["IN_PLAY","PAUSED","LIVE"].includes(fdMatch.status);
      const isFinished= fdMatch.status==="FINISHED";
      if(!isLive && !isFinished) return;
      if(fdMatch.homeScore==null||fdMatch.awayScore==null) return;
      const key  = `${game.home}|${game.away}`;
      const mins = fdMatch.minute||0;
      // Write into espnScores — FD is authoritative, always overwrites FPL
      espnScores[key] = {
        _gameId: game._id || resolveGameIdByHome(game.home),
        state:       isFinished?"post":"in",
        period:      mins>45?2:1,
        clock:       isFinished?"":(mins>0?String(mins):""),
        detail:      isFinished?"FT":(mins>0?`${mins}'`:"LIVE"),
        homeScore:   fdMatch.homeScore,
        awayScore:   fdMatch.awayScore,
        homeName:    game.home,
        awayName:    game.away,
        home:        game.home,
        away:        game.away,
        homeWinning: fdMatch.homeScore>fdMatch.awayScore,
        periodPrefix:"'",
        source:      "fd",
      };
      espnScoreTs[key] = Date.now();
      if(fdMatch.goals?.length) _fdGoalCache[key] = fdMatch.goals;
      updated++;
    });
  });
  if(updated) renderESPNScores();
}

// ── Prefetch injuries for all sports visible today ─────────────
async function bdlPrefetchAll() {
  if (!BDL_KEY || !allData || !allData.sports) return;
  const sportsToday = [...new Set(allData.sports.map(s => s.sport))];
  const toFetch = sportsToday.filter(s => BDL_SPORT_MAP[s]);
  if(FIELD_DEBUG) console.log("[BDL] prefetching injuries for:", toFetch);
  await Promise.allSettled(toFetch.map(s => bdlFetchInjuries(s)));
  // Re-render cards to inject badges now that data is available
  injectBdlInjuryBadges();
}

// ── Inject injury badges into already-rendered game cards ──────
// Fix 9: Sync BDL injury context for compound prompt — reads from warm bdlCache (no await)
// Called from buildCompoundPrompt after bdlPrefetchAll has run (data available in bdlCache)
function bdlInjuryContextSync(home, away, sportName) {
  try {
    const injuries = bdlCache?.injuries?.[sportName];
    if (!injuries?.length) return '';
    const hW = (home||'').toLowerCase().split(' ').filter(w=>w.length>3);
    const aW = (away||'').toLowerCase().split(' ').filter(w=>w.length>3);
    const relevant = injuries.filter(inj=>{
      const t=(inj.team||'').toLowerCase();
      return hW.some(w=>t.includes(w))||aW.some(w=>t.includes(w));
    });
    if(!relevant.length) return '';
    return 'Injuries: '+relevant.slice(0,3).map(i=>`${i.player} (${i.status})`).join(', ')+'.';
  } catch(e_) { return ''; }
}
// ── J1 Anti-Hype + J4 Scout's Pick — per-card badge injection ───────────────
// J4 Scout's Pick: preGameScore > 70 AND not a national TV game
//   Signals: high drama potential being overlooked by broadcast calendar
// J1 Anti-Hype (BNI): computeBroadcastNarrativeIndex returns non-null
//   narrative-push:       market gap > 200 on national broadcast (blowout risk)
//   elimination-inflation: series framing on genuinely low-drama game
//   home-market:           big-market team + marquee crew + low preGameScore
//
// Only fires on pre-game cards. Removed automatically when game goes live/final.
// Called from renderAll() + after odds load. Idempotent.
function injectJ1J4Badges() {
  if (!allData?.sports) return;
  // Build gameId → game fast lookup
  const gameMap = {};
  (allData.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{ if(g._id) gameMap[g._id]={g,sec}; }));

  document.querySelectorAll('.game-card').forEach(card=>{
    const gid = card.dataset.gameid;
    if (!gid) return;
    const entry = gameMap[gid];
    if (!entry) return;
    const { g } = entry;

    // Clear existing badges + class every cycle (idempotent)
    card.querySelector('.scout-pick-badge')?.remove();
    card.querySelector('.anti-hype-badge')?.remove();
    card.classList.remove('scout-pick-card');

    // Badges are pre-game only — skip live and final cards
    if (card.classList.contains('espn-live') || card.classList.contains('espn-final')) return;

    const cardBody = card.querySelector('.card-body');
    if (!cardBody) return;

    // ── J4: Scout's Pick ──────────────────────────────────────────────────
    // M2 Patent mitigation: uses isScoutsPick() boolean gates, not composite threshold.
    // See isScoutsPick() definition for the full rationale.
    if (isScoutsPick(g)) {
      card.classList.add('scout-pick-card');
      // Persist: Night Owl reads this at game-end to grade delivery vs prediction.
      // Stored once (first badge injection) — isScoutsPick() may not match at game-end
      // if V2 state changes, so we need the pre-game determination to survive.
      try {
        // Cross-session-stable key (CC-CMD-2026-07-08-pick-cross-session-resolution
        // follow-up): g._id is session-volatile, but this entry is written
        // pre-game and read by Night Owl at game-end, which can be a later
        // session -- the exact bug class the pick storage fix addressed.
        // Falls back to g._id only if a stable key can't be built.
        const _spKey = 'field_scout_pick_' + ((typeof _pickStorageKey === 'function' ? _pickStorageKey(g) : '') || g._id || '');
        if (!localStorage.getItem(_spKey)) {
          // Capture qualifying gate and stat evidence so Night Owl verdict is specific.
          // Gate C (stat anomaly) carries shortText/fullText for "graded on delivery of X" framing.
          let _spGate = g.seriesRecord ? 'series'
            : /playoff|final/i.test(g.league||'') ? 'playoff'
            : /MD[23]\b/.test(g.league||'') ? 'wc-stakes'
            : 'stat-anomaly';
          let _spStatShort = '', _spStatFull = '';
          try {
            const _spSd = (typeof getStatOfDay === 'function')
              ? getStatOfDay(g, sec?.sport || g._sport || '') : null;
            if (_spSd) { _spStatShort = _spSd.shortText; _spStatFull = _spSd.fullText; }
            // Refine gate label when stat anomaly is the primary signal
            if (!g.seriesRecord && !/playoff|final/i.test(g.league||'') && _spStatShort) _spGate = 'stat-anomaly';
          } catch(e_) {}
          localStorage.setItem(_spKey, JSON.stringify({
            home: g.home||'', away: g.away||'',
            signal: _spGate,
            statShort: _spStatShort,
            statFull:  _spStatFull,
            t: Date.now(),
          }));
        }
      } catch(_) {}
      const badge = document.createElement('span');
      badge.className = 'scout-pick-badge';
      badge.setAttribute('role', 'button');
      badge.setAttribute('tabindex', '0');
      badge.style.cursor = 'pointer';
      badge.addEventListener('click', (e) => {
        e.stopPropagation();
        if (typeof openBottomSheet === 'function') openBottomSheet(g._id);
      });
      badge.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); if (typeof openBottomSheet === 'function') openBottomSheet(g._id); }
      });
      // Option B: stat folds into badge text when available.
      // "🔍 Scout's Pick: CAR 93.5% PK%" — one signal, not two parallel badges.
      // .stat-day-badge suppressed for Scout's Pick games (info already in badge).
      let _spStatLine = '';
      try {
        const _spStat = (typeof getStatOfDay === 'function')
          ? getStatOfDay(g, sec?.sport || g._sport || '') : null;
        if (_spStat) _spStatLine = _spStat.shortText;
      } catch(e_) {}
      badge.textContent = _spStatLine
        ? `🔍 Scout's Pick: ${_spStatLine}`
        : '🔍 Scout\'s Pick';
      // Tooltip: full stat context + qualifying signal
      let scoutTitle = 'Under-the-radar tonight';
      try {
        const _spStat2 = (typeof getStatOfDay === 'function')
          ? getStatOfDay(g, sec?.sport || g._sport || '') : null;
        if (_spStat2) scoutTitle = _spStat2.fullText;
        else if (g.seriesRecord) scoutTitle = `${g.seriesRecord} · not on national TV`;
        else if (/playoff|final|series/i.test(g.league||'')) scoutTitle = 'Playoff stakes · not on national TV';
      } catch(e_) {}
      badge.title = scoutTitle;
      cardBody.appendChild(badge);
      // Stat of Day badge suppressed — stat is integrated into Scout's Pick badge above

      // ── Queue-backed Scout's Pick brief ─────────────────────────────────
      // Enqueue a dedicated 60-80 word "why watch" brief for the top pick.
      // Only fires for the single top pick returned by buildSlateScoutsPick().
      // Polls /journalism/result/:jobId and injects into .brief-scout-note.
      try {
        const allGames2 = (allData?.sports||[]).flatMap(s => s.games||[]);
        const topPick2 = (typeof buildSlateScoutsPick === 'function') ? buildSlateScoutsPick(allGames2) : null;
        const isTopPick = topPick2 && (topPick2._id === g._id ||
          (topPick2.home === g.home && topPick2.away === g.away));
        if (isTopPick && JOURNALISM_ENQUEUE_RELAY) {
          const series2 = g.seriesRecord || '';
          const sd2 = (typeof getStatOfDay === 'function') ? getStatOfDay(g, _gameSport(g)) : null;
          const spBriefKey = `field_sp_brief_v${_swv}_${g._id||''}_${series2.replace(/\s/g,'_')}`;
          const spJobKey   = `field_sp_job_v${_swv}_${g._id||''}_${series2.replace(/\s/g,'_')}`;
          // Check sessionStorage for completed brief first
          const cachedBrief = (() => { try { return sessionStorage.getItem(spBriefKey); } catch(e_) { return null; } })();
          if (cachedBrief && cachedBrief.length > 40) {
            let noteEl = cardBody.querySelector('.brief-scout-note');
            if (!noteEl) {
              noteEl = document.createElement('div');
              noteEl.className = 'brief-scout-note';
              cardBody.appendChild(noteEl);
            }
            const text = cachedBrief;
            // Option A: Scout's Pick brief footer — R2 analytics chips below brief text
        const _spChips = (typeof _buildAnalyticsChips === 'function') ? _buildAnalyticsChips(g) : [];
        const _spChipsHtml = (typeof _chipsHTML === 'function') ? _chipsHTML(_spChips) : '';
        noteEl.innerHTML = '<span>' + ('🔍 ' + text).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>'
          + (_spChipsHtml ? '<div class="sp-analytics-footer">' + _spChipsHtml + '</div>' : '');
          } else {
            // Enqueue or poll existing job
            (async () => {
              try {
                let jobId = (() => { try { return sessionStorage.getItem(spJobKey); } catch(e_) { return null; } })();
                if (!jobId) {
                  const spPrompt = [
                    `Write a FIELD Scout's Pick brief for tonight's hidden-gem game.`,
                    '',
                    'GAME DATA:',
                    `${g.away||'?'} @ ${g.home||'?'}.`,
                    g.matchupNote ? `Context: ${g.matchupNote}` : '',
                    sd2 ? `Key stat: ${sd2.fullText}.` : '',
                    series2 ? `Series: ${series2}.` : '',
                    ``,
                    `Rules:`,
                    `- 50-70 words. One paragraph. No headers.`,
                    `- Lead with WHY this non-national game is worth watching — the specific analytical reason.`,
                    `- Cite the key stat verbatim if provided. Never use "hidden gem", "under the radar", "must-watch".`,
                    `- Write like a well-prepared friend explaining why they're skipping the national game for this one.`,
                    FIELD_PROSE_STYLE,
                  ].filter(Boolean).join('\n');
                  const eq = await fetch(JOURNALISM_ENQUEUE_RELAY, {
                    method: 'POST',
                    headers: {'Content-Type':'application/json'},
                    // scoreThreshold 240 -- see generateJournalismViaRelay's
                    // comment (CC-CMD-2026-07-09-jq-threshold-240-migration).
                    // home/away/matchupNote (CC-CMD-2026-07-09-enqueue-
                    // context-gap): no homeScore/awayScore here -- this
                    // fires pre-game (line ~14692: "Badges are pre-game
                    // only"), so no score data genuinely exists yet.
                    body: JSON.stringify({prompt: spPrompt, sport: g._sport||'', briefType: 'scouts-pick', max_tokens: 300, scoreThreshold: 240, home: g.home||'', away: g.away||'', matchupNote: g.matchupNote||null}),
                  });
                  if (eq.ok) {
                    const data = await eq.json();
                    if (data.jobId) {
                      try { sessionStorage.setItem(spJobKey, data.jobId); } catch(e_) {}
                      jobId = data.jobId;
                    }
                  }
                }
                // Poll for result (max 20s)
                if (jobId && JOURNALISM_RESULT_RELAY) {
                  for (let i = 0; i < 10; i++) {
                    await new Promise(r => setTimeout(r, 2000));
                    const pr = await fetch(`${JOURNALISM_RESULT_RELAY}/${jobId}`, {signal: AbortSignal.timeout(3000)});
                    if (!pr.ok) continue;
                    const result = await pr.json();
                    if (result.status === 'done' && result.text && result.text.length > 40) {
                      // Deterministic leak strip (CC-CMD-2026-07-10-prompt-data-
                      // separation follow-up) -- this is a relay-queue result, no
                      // client-side quality chain runs on it otherwise.
                      const _spCleanText = stripPromptLeaks(result.text);
                      try { sessionStorage.setItem(spBriefKey, _spCleanText); } catch(e_) {}
                      try { sessionStorage.removeItem(spJobKey); } catch(e_) {}
                      // Inject into card (card may have re-rendered — find fresh)
                      const freshCard = document.querySelector(`[data-gameid="${g._id||''}"]`);
                      const freshBody = freshCard?.querySelector('.card-body');
                      if (freshBody) {
                        let noteEl2 = freshBody.querySelector('.brief-scout-note');
                        if (!noteEl2) {
                          noteEl2 = document.createElement('div');
                          noteEl2.className = 'brief-scout-note';
                          freshBody.appendChild(noteEl2);
                        }
                        const text = _spCleanText;
                        // Option A: Scout's Pick brief footer — R2 analytics chips below brief text
                        const _spChips = (typeof _buildAnalyticsChips === 'function') ? _buildAnalyticsChips(g) : [];
                        const _spChipsHtml = (typeof _chipsHTML === 'function') ? _chipsHTML(_spChips) : '';
                        noteEl2.innerHTML = '<span>' + ('🔍 ' + text).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>'
                          + (_spChipsHtml ? '<div class="sp-analytics-footer">' + _spChipsHtml + '</div>' : '');
                      }
                      break;
                    }
                    if (result.status === 'failed') break;
                  }
                }
              } catch(e_) { captureFieldError('journalism:scouts-pick-poll', e_, true); }
            })();
          }
        }
      } catch(e_) {}
    }

    // ── J1: Anti-Hype (BNI) ──────────────────────────────────────────────
    // Broadcast narrative exceeds the game's actual drama potential
    const bni = computeBroadcastNarrativeIndex(g);
    if (bni) {
      const badge = document.createElement('span');
      badge.className = 'anti-hype-badge';
      const label = bni === 'narrative-push'         ? '⚠️ Hype Check'
                  : bni === 'elimination-inflation'  ? '⚠️ Series Hype'
                  :                                    '⚠️ Big Market Push';
      badge.textContent = label;
      const strength = getBNIStrength(g, bni);
      badge.title = `BNI: ${bni.replace(/-/g,' ')} · Signal strength ${strength}`;
      cardBody.appendChild(badge);
    }
  });
}

function injectBdlInjuryBadges() {
  document.querySelectorAll(".game-card").forEach(card => {
    if (card.querySelector(".inj-row")) return; // already injected
    const sport = card.dataset.sport || "";
    const home  = card.dataset.home  || "";
    const away  = card.dataset.away  || "";
    const injuries = bdlCache.injuries[sport] || [];
    const badge = bdlInjuryBadge(home, away, injuries);
    if (!badge) return;
    const meta = card.querySelector(".game-meta");
    if (meta) meta.insertAdjacentHTML("afterend", badge);
  });
}


