const fdLiveCache      = {}; // code → [{id,homeTeam,awayTeam,score,minute,status,goals}]
const fdH2HCache       = {}; // "h_a" → {homeWins,awayWins,draws,lastMeetings[]}
const fdMatchIdCache   = {}; // "home6_away6" → FD match ID (populated by fdPrefetchSoccerLive)
const fdLiveCacheTime  = {}; // code → timestamp of last live fetch
const FD_LIVE_TTL      = 1800000; // 30min — matches go SCHEDULED→IN_PLAY→FINISHED

// ── Shared soccer goal caches (populated by FD + FPL paths, merged for display) ──
const _fdGoalCache  = {}; // "home|away" → [{player, minute, team}] from football-data.org
const _fplScorerCache = {}; // "home|away" → {home:[], away:[]} from FPL fixtures stats

// ══════════════════════════════════════════════════════════════════════════════
// Open-Meteo Weather Engine
// Free · No API key · No rate limit
// Exact URL format: https://api.open-meteo.com/v1/forecast?latitude={lat}&longitude={lon}
//   &hourly=temperature_2m,wind_speed_10m,wind_direction_10m,temperature_80m,rain,showers
//   &current=temperature_2m,precipitation,rain,is_day,wind_speed_10m,wind_direction_10m
//   &wind_speed_unit=mph&temperature_unit=fahrenheit
// outdoor:true → fetch and show badge · outdoor:false → dome/indoor, skip
// ══════════════════════════════════════════════════════════════════════════════

const OM_BASE = "https://api.open-meteo.com/v1/forecast";
const WX_TTL  = 3600000; // 1-hour cache
const wxCache = {}; // "lat_lon" → weather object
const wxCacheTime = {}; // "lat_lon" → timestamp

// Fuzzy venue lookup — matches "Fenway Park, Boston" and "Fenway Park"
// Returns true for outdoor venues — uses VENUE_COORDS[2] flag
// Falls back to keyword heuristic for unlisted venues
const INDOOR_KEYWORDS = ["arena","garden","center","centre","dome","coliseum",
  "fieldhouse","forum","palace","pavilion","theater","theatre"];
// ── PARK_ORIENTATION: degrees (true north) that center field faces ────────
// Used by windContextNote() to determine "out to CF" vs "in from CF" context
// Wind delta < -30° = blowing OUT toward CF (hitter's park)
// Wind delta > +30° = blowing IN from CF (pitcher's park)
const PARK_ORIENTATION = {
  'Fenway Park':              57,  // NE to CF (famous left-field wall)
  'Yankee Stadium':           28,  // NNE
  'Wrigley Field':            45,  // NE (famous wind off Lake Michigan)
  'Oracle Park':             346,  // NNW (infamous SF wind off McCovey Cove)
  'Dodger Stadium':           25,  // NNE
  'Busch Stadium':           340,  // NNW
  'Nationals Park':           25,  // NNE
  'Citizens Bank Park':       30,  // NNE
  'Great American Ball Park': 20,  // NNE
  'Kauffman Stadium':          5,  // N
  'Comerica Park':            10,  // N
  'Petco Park':              315,  // NW
  'Oriole Park':              35,  // NE (Camden Yards)
  'Guaranteed Rate Field':    20,  // NNE (Guaranteed Rate, CWS)
  'Angels Stadium':          285,  // WNW
  'loanDepot park':           25,  // NNE (Miami)
  'Progressive Field':        15,  // NNE (Cleveland)
  'Coors Field':             342,  // NNW (famous Colorado wind)
  'Globe Life Field':        355,  // N (retractable but included for outdoor mode)
};

// Wind context note for MLB parks: combines live wind with park geometry
// Returns: "18mph out to CF — hitter's conditions" or null
function windContextNote(venue, windDir, windSpeed){
  if(!venue || windSpeed < 8) return null;
  let orientation = null;
  for(const [park, deg] of Object.entries(PARK_ORIENTATION)){
    if(venue.includes(park.split(',')[0]) || park.includes(venue.split(',')[0])){
      orientation = deg; break;
    }
  }
  if(orientation === null) return null;
  const delta = ((windDir - orientation + 540) % 360) - 180;
  const spd = Math.round(windSpeed);
  if(delta < -30) return `${spd}mph out to CF — hitter's conditions`;
  if(delta >  30) return `${spd}mph in from CF — pitcher's conditions`;
  return `${spd}mph crosswind`;
}

// wxBadge: compact HTML badge for game cards
function wxBadge(wx){
  if(!wx) return '';
  const parts = [];
  const icon = wxIcon(wx);
  if(wx.temp !== undefined) parts.push(`${icon} ${wx.temp}°F`);
  const windDisplay = wx.windNote
    ? `💨 ${wx.windNote}`
    : (wx.gusts||wx.wind||0) > 5 ? `💨 ${Math.round(wx.gusts||wx.wind)}mph ${cardinalDir(wx.windDir||0)}` : null;
  if(windDisplay && !wx.windNote) parts.push(windDisplay);
  else if(wx.windNote) { if(parts.length) parts[0] += ''; parts.push(`💨 ${wx.windNote}`); }
  if((wx.rain||0)>1||(wx.precip||0)>1) parts.push(`🌧️ ${Math.round(wx.precip||wx.rain)}mm`);
  if((wx.snowfall||0)>0.2) parts.push('❄️ Snow');
  if((wx.aqi||0)>100){
    const aqiEmoji = (wx.aqi||0)>200 ? '⚠️' : '🌫️';
    const aqiLabel = (wx.aqi||0)>200 ? 'Very unhealthy' : (wx.aqi||0)>150 ? 'Unhealthy' : 'Moderate AQI';
    parts.push(`${aqiEmoji} AQI ${wx.aqi} — ${aqiLabel}`);
  }
  if(!parts.length) return '';
  const alertStyle = wx.alert
    ? 'color:var(--caution);border:1px solid rgba(245,158,11,.3);'
    : 'color:var(--smoke);';
  return `<span class="wx-badge" style="font-size:.72rem;${alertStyle}padding:.1rem .4rem;border-radius:4px;background:rgba(255,255,255,.05)">${parts.join(' · ')}</span>`;
}

// AQI cache — separate from wxCache (different Open-Meteo endpoint)
const AQI_CACHE = {}, AQI_CACHE_TIME = {};
const AQI_TTL = 3600000; // 1-hour

async function fetchAQI(lat, lon){
  const key = `${lat.toFixed(3)}_${lon.toFixed(3)}`;
  const now = Date.now();
  if(AQI_CACHE[key] && (now-(AQI_CACHE_TIME[key]||0)) < AQI_TTL) return AQI_CACHE[key];
  try{
    const url = `https://air-quality-api.open-meteo.com/v1/air-quality?latitude=${lat}&longitude=${lon}&current=us_aqi,pm2_5`;
    const r = await fetch(url, {signal: AbortSignal.timeout(4000)});
    if(!r.ok) throw new Error('AQI '+r.status);
    const json = await r.json();
    const cur = json.current || {};
    const aqi = { us_aqi: Math.round(cur.us_aqi||0), pm2_5: Math.round((cur.pm2_5||0)*10)/10 };
    AQI_CACHE[key] = aqi;
    AQI_CACHE_TIME[key] = now;
    return aqi;
  }catch(e){
    if(FIELD_DEBUG) console.warn('[AQI]', e.message);
    return null;
  }
}

// Core fetch — uses exact URL from specification, 1-hour cache
async function fetchWeather(lat, lon){
  const key = `${lat.toFixed(3)}_${lon.toFixed(3)}`;
  const now = Date.now();
  if(wxCache[key] && (now - (wxCacheTime[key]||0)) < WX_TTL) return wxCache[key];
  // T1-05: restore from sessionStorage on page reload within TTL
  try{
    const stored = sessionStorage.getItem("field_wx_"+key);
    if(stored){
      const parsed = JSON.parse(stored);
      if(parsed && parsed._t && (now - parsed._t) < WX_TTL){
        wxCache[key] = parsed; wxCacheTime[key] = parsed._t; return parsed;
      }
    }
  }catch(e){}
  try{
    const url = `${OM_BASE}?latitude=${lat}&longitude=${lon}`
      + `&hourly=temperature_2m,wind_speed_10m,wind_direction_10m,direct_radiation,snowfall`
      + `&current=temperature_2m,apparent_temperature,precipitation,rain,is_day,wind_speed_10m,wind_direction_10m,wind_gusts_10m`
      + `&wind_speed_unit=mph&temperature_unit=fahrenheit`;
    const r = await fetch(url, {signal: AbortSignal.timeout(5000)});
    if(!r.ok) throw new Error("OM " + r.status);
    const json = await r.json();
    const c = json.current || {};
    const wx = {
      temp:    Math.round(c.temperature_2m ?? 0),
      precip:  c.precipitation ?? 0,
      rain:    c.rain ?? 0,
      wind:      Math.round(c.wind_speed_10m ?? 0),
      gusts:     Math.round(c.wind_gusts_10m ?? 0),
      windDir:   c.wind_direction_10m ?? 0,
      feelsLike: Math.round(c.apparent_temperature ?? c.temperature_2m ?? 0),
      isDay:     c.is_day === 1,
      hourly:    json.hourly || null,
      snowfall:  (json.hourly?.snowfall || [])[new Date().getUTCHours()] || 0,
      directRad: (json.hourly?.direct_radiation || [])[new Date().getUTCHours()] || 0,
    };
    // AQI from separate Open-Meteo air quality endpoint (non-blocking)
    try{ const aqiData=await fetchAQI(lat,lon); if(aqiData) wx.aqi=aqiData.us_aqi; }catch(e){}
    wx.desc  = wxDescription(wx);
    wx.icon  = wxIcon(wx);
    wx.alert = wxAlert(wx);
    wxCache[key]     = wx;
    wxCacheTime[key] = now;
    // T1-05: persist to sessionStorage so page reloads within TTL skip the fetch
    try{ wx._t = now; sessionStorage.setItem("field_wx_"+key, JSON.stringify(wx)); }catch(e){}
    return wx;
  }catch(e){
    if(FIELD_DEBUG) console.warn("[Weather]", e.message);
    return null;
  }
}

// Inject weather badges into all outdoor game cards in the current view
// Uses in-memory cache — instant if weather already fetched, no-op if not
function injectWeatherBadges(){
  if(!allData||!allData.sports) return;
  allData.sports.forEach(sec=>{
    (sec.games||[]).forEach(game=>{
      if(!game.venue||!game._id) return;
      if(!isOutdoorVenue(game.venue)) return;
      const coords = getVenueCoords(game.venue);
      if(!coords) return;
      const [lat,lon] = coords;
      const wx = wxCache[`${lat.toFixed(3)}_${lon.toFixed(3)}`];
      if(!wx) return;
      const card = document.querySelector(`.game-card[data-gameid="${game._id}"]`);
      if(!card) return;
      // Find or create badge-row below matchup
      let badgeRow = card.querySelector(".badge-row");
      if(!badgeRow){
        badgeRow = document.createElement("div");
        badgeRow.className = "badge-row";
        badgeRow.style.cssText = "padding:.1rem .5rem .25rem;display:flex;flex-wrap:wrap;gap:.2rem;align-items:center";
        const body = card.querySelector(".card-body");
        if(body) body.appendChild(badgeRow);
      }
      const old = badgeRow.querySelector(".wx-badge");
      if(old) old.remove();
      // Compute wind context note for MLB park geometry
      const windNote = windContextNote(game.venue, wx.windDir, wx.gusts||wx.wind);
      const wxDisplay = windNote ? {...wx, windNote} : wx;
      badgeRow.insertAdjacentHTML("beforeend", wxBadge(wxDisplay));
    });
  });
}

// Prefetch weather for all outdoor venues today — fires 4s after init
// Batches unique lat/lon pairs, ignores duplicates (same city, different venue names)
async function weatherPrefetchAll(){
  if(!allData||!allData.sports) return;
  const seen = new Set();
  const fetches = [];
  allData.sports.forEach(sec=>{
    (sec.games||[]).forEach(game=>{
      if(!game.venue||!isOutdoorVenue(game.venue)) return;
      const coords = getVenueCoords(game.venue);
      if(!coords) return;
      const [lat,lon] = coords;
      const key = `${lat.toFixed(3)}_${lon.toFixed(3)}`;
      if(seen.has(key)) return;
      seen.add(key);
      fetches.push(fetchWeather(lat,lon));
    });
  });
  if(FIELD_DEBUG) console.log(`[Weather] fetching ${fetches.length} outdoor venues`);
  // Stagger 150ms apart — open-meteo has burst limits; simultaneous requests trigger 429
  for(const f of fetches){ await f; await new Promise(r=>setTimeout(r,150)); }
  injectWeatherBadges();
}

