// Returns the major (if any) starting within the next 1-5 days
function getUpcomingMajor(){
  const now = Date.now();
  for(const [key, m] of Object.entries(MAJOR_CONFIG)){
    const start = new Date(m.dates[0]).getTime();
    const diff = start - now;
    // Show preview 0-5 days before the major starts
    if(diff >= 0 && diff <= 5*24*3600*1000) return {key, ...m};
  }
  return null;
}

// Render the major preview card into a container element
// FALLBACK FIX (May 13 2026): added staticNote to MAJOR_CONFIG for each upcoming major.
// Root cause: api.anthropic.com requires auth; the claude.ai sandbox injects it
// automatically, but standalone HTML opened from disk/Drive has no proxy →
// fetch() returns 401 → catch fires silently → claudeNote stays "" → sentence blank.
// Fix: staticNote in MAJOR_CONFIG guarantees the sentence renders in all contexts.
// Priority: localStorage cached API note > fresh API note > staticNote hardcoded fallback.
async function renderMajorPreviewCard(container){
  const major = getUpcomingMajor();
  if(!major||!container) return;

  // iPad-9: cache key bumped to v2 — invalidates briefs that were
  // generated with the unhardened prompt (some contained venue mismatches,
  // e.g. "Oakmont" for the 2026 U.S. Open which is at Shinnecock Hills).
  const cacheKey = "major_preview_" + major.key + "_v2";
  let claudeNote = localStorage.getItem(cacheKey);

  // staticNote: hardcoded fallback — always works without API auth
  const staticNote = major.staticNote || "";

  if(!claudeNote){
    try{
      // iPad-9: prompt hardening. The defenderNote previously read
      // "won 2025 U.S. Open at Oakmont; defending at Shinnecock Hills" —
      // the model occasionally latched onto the prior-year venue. Split
      // venue + defender context and pin the current venue at the top.
      const prompt = `Write exactly one sentence contextualizing this upcoming golf major for a casual sports fan.\n\nCURRENT VENUE (use this — DO NOT substitute any other course name): ${major.venue}, ${major.city}.\n\nFacts you may use: ${major.edition} ${major.name} at ${major.venue}. Defending champion ${major.defender}. ${major.defenderNote}. Starts ${major.dates[0]}.\n\nDO NOT INVENT: no player career stats, course records, hole numbers, weather predictions, prize money figures, past tournament results, course architects, yardage, par numbers, or any specific facts beyond what is provided above.\nDO NOT substitute a different venue (e.g. a prior year's course mentioned in the defender's record) for the CURRENT VENUE above. If you cannot write a sentence using only the given facts, return the string "TBD" instead.\nBe specific to the facts given, factual, and engaging.`;
      if(!canUseAPI()) throw new Error("MAX_USES reached");
      incrementUsage();
      const resp = await fetch(CLAUDE_PROXY_URL,{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-haiku-4-5-20251001",
          max_tokens:80,
          messages:[{role:"user",content:prompt}]
        })
      });
      const data = await resp.json();
      claudeNote = (data.content||[]).find(b=>b.type==="text")?.text?.trim()||"";
      // B4: model returns "TBD" when it cannot write a confident sentence from given facts.
      if(claudeNote === "TBD" || claudeNote.toUpperCase() === "TBD") claudeNote = "";
      // iPad-9: venue-contradiction guard. If the generated brief omits
      // the current venue OR mentions a different course name that the
      // structured data does not list, reject it and fall back to
      // staticNote rather than render a hallucination to the user.
      if (claudeNote && major.venue) {
        const noteText = claudeNote.toLowerCase();
        const venueKey = major.venue.toLowerCase().split(' ')[0]; // first token, e.g. "shinnecock"
        if (!noteText.includes(venueKey)) {
          if (FIELD_DEBUG) console.warn('[MajorPreview] venue mismatch — generated brief omits', major.venue);
          claudeNote = '';
        }
      }
      if(claudeNote) localStorage.setItem(cacheKey, claudeNote);
    }catch(e){
      if(FIELD_DEBUG) console.warn("[MajorPreview]",e.message);
      // API unavailable (no auth in standalone browser, or MAX_USES) — fall through to staticNote
    }
  }

  // Prefer live API note if available; always fall back to hardcoded staticNote
  const displayNote = claudeNote || staticNote;

  container.innerHTML = `
    <div class="major-preview-card">
      <div class="major-preview-title">⛳ ${major.name} — ${major.edition} Edition</div>
      <div class="major-preview-meta">${major.venue} · ${major.city} · ${major.dates[0]}</div>
      <div class="major-preview-meta">${major.broadcastNote}</div>
      ${displayNote?`<div class="major-preview-note">${displayNote}</div>`:""}    </div>`;
}
// ══════════════════════════════════════════════════════════════════════════════
// Slash Golf Engine (live-golf-data.p.rapidapi.com)
// Provides: PGA Tour schedule, live leaderboard, round scores
// orgId=1 = PGA Tour · orgId=2 = LPGA · No strict rate limit on free tier
// Cache: schedule 24hr · leaderboard 15min · round scores 15min
// ══════════════════════════════════════════════════════════════════════════════

function slashGolfHeaders(){
  return {
    "x-rapidapi-host": SLASH_GOLF_HOST,
    "x-rapidapi-key":  SLASH_GOLF_KEY,
    "Content-Type":    "application/json",
  };
}

// ── Daily request counter — hard ceiling of 18 req/day ──────────────────────
// Free tier: 20 req/day. We cap at 18 to leave 2 as buffer.
// Counter resets at midnight UTC. Stored in localStorage.
const SLASH_GOLF_DAILY_LIMIT = 60;
let _slashGolf429Until = 0; // backoff timestamp — set on RapidAPI 429, clears after 60min
function slashGolfReqCount(){
  const today = TODAY_ISO;
  const stored = JSON.parse(localStorage.getItem("sg_req")||"{}");
  if(stored.date !== today) return 0;
  return stored.count || 0;
}
function slashGolfBumpCount(){
  const today = TODAY_ISO;
  const stored = JSON.parse(localStorage.getItem("sg_req")||"{}");
  const count = (stored.date === today ? (stored.count||0) : 0) + 1;
  localStorage.setItem("sg_req", JSON.stringify({date:today, count}));
  if(FIELD_DEBUG) console.debug(`[SlashGolf] req ${count}/${SLASH_GOLF_DAILY_LIMIT} today`);
  return count;
}
function slashGolfBudgetOk(){
  if(Date.now() < _slashGolf429Until) return false; // in 429 backoff window
  return slashGolfReqCount() < SLASH_GOLF_DAILY_LIMIT;
}

// Generic fetch with cache + daily budget guard
// Layer 1: in-memory (instant, reset on reload)
// Layer 2: localStorage (survives reloads, respects TTL — fixes per-reload budget burn)
async function slashGolfFetch(path, cacheKey, ttl){
  const memCached = slashGolfCache[cacheKey];
  if(memCached && Date.now() - memCached.ts < ttl) return memCached.data;
  // localStorage layer — survives page reloads
  try{
    const lsRaw = localStorage.getItem('field_sg_'+cacheKey);
    if(lsRaw){
      const lsParsed = JSON.parse(lsRaw);
      if(Date.now() - lsParsed.ts < ttl){
        slashGolfCache[cacheKey] = lsParsed; // warm in-memory
        return lsParsed.data;
      }
    }
  }catch(e){}
  if(!slashGolfBudgetOk()){
    if(FIELD_DEBUG) console.warn('[SlashGolf] daily budget exhausted — using stale cache');
    return memCached?.data || null;
  }
  try{
    const r = await fetch(`${SLASH_GOLF_BASE}${path}`,
      {headers: slashGolfHeaders(), signal: AbortSignal.timeout(8000)});
    if(r.status === 429){
      _slashGolf429Until = Date.now() + 3600000; // back off 60min on RapidAPI rate limit
      if(FIELD_DEBUG) console.warn('[SlashGolf] 429 — backing off 60min');
      return memCached?.data || null;
    }
    if(!r.ok) throw new Error(`SlashGolf HTTP ${r.status}`);
    const data = await r.json();
    const entry = {data, ts: Date.now()};
    slashGolfCache[cacheKey] = entry;
    try{ localStorage.setItem('field_sg_'+cacheKey, JSON.stringify(entry)); }catch(e){}
    slashGolfBumpCount();
    return data;
  }catch(e){
    if(FIELD_DEBUG) console.warn('[SlashGolf]', e.message);
    return memCached?.data || null;
  }
}

// Fetch full PGA Tour season schedule
// Response: { schedule: [{tournId, name, date:{start,end}, course:{name,location},
//              purse, status, currentRound, firstPlace:{firstName,lastName,total}}] }
async function fetchSlashGolfSchedule(){
  const year = new Date().getFullYear();
  return slashGolfFetch(
    `/schedule?orgId=${SLASH_GOLF_ORG}&year=${year}`,
    `schedule_${year}`,
    86400000 // 24-hour cache for schedule
  );
}

// Fetch live leaderboard for a specific tournament
// Response: { leaderboard: [{position, firstName, lastName, total, today, thru, status}] }
async function fetchSlashGolfLeaderboard(tournId){
  const year = new Date().getFullYear();
  return slashGolfFetch(
    `/leaderboard?orgId=${SLASH_GOLF_ORG}&tournId=${tournId}&year=${year}`,
    `leaderboard_${tournId}`,
    3600000 // 60-min cache — optimal for 20 req/day free tier (see budget analysis)
  );
}

// Fetch OWGR world rankings — weekly cache, ~1 req/week
async function fetchSlashGolfRankings(){
  return slashGolfFetch(
    `/rankings?orgId=${SLASH_GOLF_ORG}`,
    "rankings",
    604800000 // 7-day cache — rankings update weekly
  );
}

// Build a compact leaderNote string from the leaderboard response
// Returns: "Reitan -15 · Im -14 · Fowler -13" (top 3 or fewer)
function buildGolfLeaderNote(leaderboard){
  if(!leaderboard) return "";
  const leaders = (leaderboard.leaderboard || leaderboard.players || [])
    .filter(p => p.position && p.lastName)
    .sort((a,b) => (parseInt(a.position)||99) - (parseInt(b.position)||99))
    .slice(0, 3);
  if(!leaders.length) return "";
  return leaders.map(p => {
    const name = p.lastName || p.playerName || "";
    const score = p.total || p.totalScore || "E";
    const pos = p.position === "1" ? "" : `T${p.position} `;
    return `${name} ${score}`;
  }).join(" · ");
}

// Build top-10 leaderboard HTML block for golf card
// Built: May 14, 2026 — shows when tournament is active/ongoing
// Returns: HTML string for .golf-leaderboard div, or "" if no data
function buildGolfTop10HTML(leaderboard, roundLabel){
  if(!leaderboard) return "";
  const players = (leaderboard.leaderboard || leaderboard.players || [])
    .filter(p => p.position && (p.lastName || p.playerName))
    .sort((a,b) => (parseInt(a.position)||99) - (parseInt(b.position)||99))
    .slice(0, 10);
  if(!players.length) return "";

  const titleHTML = roundLabel
    ? `<div class="golf-lb-title">⛳ ${roundLabel}</div>`
    : `<div class="golf-lb-title">⛳ Leaderboard</div>`;

  const rows = players.map(p => {
    const pos    = String(p.position || "");
    const posNum = parseInt(pos) || 99;
    const posStr = posNum <= 1 ? "1" : `T${pos}`;
    const name   = p.lastName || p.playerName || "";
    const country= p.country || p.countryCode || "";
    const total  = String(p.total || p.totalScore || "E");
    const today  = p.today || p.todayScore || "";

    // Score colour class
    const sc = total.startsWith("-") ? "lb-under" : total === "E" ? "lb-even" : "lb-over";
    // Today's round score in parens if available and different from total
    const todayStr = today && today !== total ? ` (${today})` : "";
    const nameStr  = country ? `${name} <span style="opacity:.5">${country}</span>` : name;
    const isTop3   = posNum <= 3;

    return `<div class="golf-lb-row${isTop3 ? " lb-top3" : ""}">` +
      `<span class="golf-lb-pos">${posStr}</span>` +
      `<span class="golf-lb-name">${nameStr}</span>` +
      `<span class="golf-lb-score ${sc}">${total}${todayStr}</span>` +
    `</div>`;
  }).join("");

  return `<div class="golf-leaderboard">${titleHTML}${rows}</div>`;
}

// Find today's and upcoming active tournaments in the schedule
function getActiveTournaments(schedule){
  if(!schedule) return [];
  const tournaments = schedule.schedule || schedule.tournaments || schedule || [];
  const today = TODAY_ISO;
  const nowMs = Date.now();
  const sevenDays = 7 * 24 * 3600 * 1000;

  return tournaments.filter(t => {
    if(!t.date) return false;
    const start = t.date.start || t.startDate || "";
    const end = t.date.end || t.endDate || "";
    const startMs = new Date(start).getTime();
    const endMs = new Date(end + "T23:59:59Z").getTime();
    const isActive = startMs <= nowMs && nowMs <= endMs;
    const isUpcoming = startMs > nowMs && startMs - nowMs <= sevenDays;
    return isActive || isUpcoming;
  });
}

// Map Slash Golf tournament status to FIELD round info
// golfRoundLabel extracted to src/utils/sport-format.js (Phase 3c).

// Look up the current tournament leader's OWGR world rank, if notable
// (top 50 -- a real, well-known golf convention, e.g. major eligibility
// cutoffs) and rankings data is available. Real value-add beyond
// leaderboard alone: notes when the leader is a genuinely elite player,
// context leaderboard (this week's standing) alone doesn't carry.
// Field-name-tolerant (rankings/players/rank list; lastName/name;
// rank/position/owgr) matching buildGolfLeaderNote's own established
// defensive-tolerance style, since this session made zero real live
// calls against SlashGolf's rate-limited API to confirm the exact
// rankings response shape (CC-CMD-2026-07-15-golf-rankings TASK 0/2 --
// see outbox for why: Rule 78, do not burn a scarce shared daily budget
// for verification alone).
function findLeaderWorldRank(leaderboard, rankings){
  if(!leaderboard || !rankings) return "";
  const leaders = (leaderboard.leaderboard || leaderboard.players || [])
    .filter(p => p.position && p.lastName)
    .sort((a,b) => (parseInt(a.position)||99) - (parseInt(b.position)||99));
  const top = leaders[0];
  if(!top || !top.lastName) return "";
  const rankList = rankings.rankings || rankings.players || rankings.rank || [];
  if(!Array.isArray(rankList)) return "";
  const match = rankList.find(r => (r.lastName||r.name||"").toLowerCase().includes(top.lastName.toLowerCase()));
  if(!match) return "";
  const rank = parseInt(match.rank ?? match.position ?? match.owgr);
  if(!rank || rank > 50) return "";
  return `World #${rank}`;
}

// Inject Slash Golf leaderboard data into matching Golf game cards in the DOM
// Called after schedule + leaderboard fetch completes
function injectSlashGolfLeaderNotes(activeTournaments, leaderboards, rankings){
  if(!allData||!allData.sports) return;
  allData.sports.forEach(sec => {
    if(sec.sport !== "Golf") return;
    (sec.games || []).forEach(game => {
      if(!game._id) return;
      // Match game to a tournament by name (fuzzy: event name includes tourn name key words)
      const tourn = activeTournaments.find(t => {
        const tName = (t.name||"").toLowerCase();
        const gName = (game.home||"").toLowerCase();
        // Match if first significant word of tournament name appears in game home
        const tWords = tName.replace(/[^a-z0-9\s]/g,"").split(/\s+/).filter(w=>w.length>3);
        return tWords.some(w => gName.includes(w));
      });
      if(!tourn) return;

      // Get leaderboard for this tournament
      const lb = leaderboards[tourn.tournId];
      if(!lb && !tourn.firstPlace) return;

      // Build leaderNote from leaderboard data or firstPlace fallback
      let leaderNote = "";
      if(lb){
        leaderNote = buildGolfLeaderNote(lb);
        const wr = findLeaderWorldRank(lb, rankings);
        if(wr && leaderNote) leaderNote = `${leaderNote} (${wr})`;
      } else if(tourn.firstPlace){
        const fp = tourn.firstPlace;
        leaderNote = `${fp.lastName||""} ${fp.total||""}`;
        // Try to get T2 from schedule data if available
      }

      // Add round info
      const roundLabel = golfRoundLabel(tourn);
      if(roundLabel && leaderNote) leaderNote = `${roundLabel} · ${leaderNote}`;
      else if(roundLabel) leaderNote = roundLabel;

      // Update the game object
      game.leaderNote = leaderNote;
      game.slashGolfTournId = tourn.tournId;

      // Update the DOM chip directly (instant, no re-render)
      const card = document.querySelector(`.game-card[data-gameid="${game._id}"]`);
      if(!card) return;
      let chip = card.querySelector(".leader-chip");
      if(!chip){
        const matchupDiv = card.querySelector(".matchup");
        if(matchupDiv){
          chip = document.createElement("span");
          chip.className = "leader-chip";
          matchupDiv.appendChild(chip);
        }
      }
      if(chip && leaderNote) chip.textContent = "⛳ " + leaderNote;

      // Round badge
      if(roundLabel){
        let badge = card.querySelector(".round-badge");
        if(!badge){
          const lb2 = card.querySelector(".league-badge");
          if(lb2){
            badge = document.createElement("span");
            badge.className = "round-badge";
            lb2.parentNode.insertBefore(badge, lb2.nextSibling);
          }
        }
        if(badge) badge.textContent = roundLabel;
      }

      // ── TOP 10 LEADERBOARD — inject when tournament is active ───────────
      // Only show when lb data is available and tournament is ongoing (not upcoming)
      // isActive: if we have lb data and this tourn passed getActiveTournaments date check,
      // it's active. Empty/null status (common from Slash Golf API) should not block display.
      // Only explicitly skip if status says "upcoming", "scheduled", or "pre".
      const statusStr = (tourn.status || "").toLowerCase();
      const isActive = !statusStr.includes("upcoming") &&
                       !statusStr.includes("scheduled") &&
                       !statusStr.includes("pre-tournament");
      const lbHTML = lb && isActive ? buildGolfTop10HTML(lb, roundLabel) : "";
      let lbEl = card.querySelector(".golf-leaderboard");
      if(lbHTML){
        if(!lbEl){
          lbEl = document.createElement("div");
          // Insert after stream-row if present, else append to card-body
          const streamRow = card.querySelector(".stream-row");
          if(streamRow) streamRow.after(lbEl);
          else card.querySelector(".card-body")?.appendChild(lbEl);
        }
        if(lbEl) lbEl.outerHTML = lbHTML; // replace with fresh HTML
      } else if(lbEl){
        lbEl.remove(); // hide leaderboard when tournament not active
      }
      // ────────────────────────────────────────────────────────────────────
    });
  });
}

// Main prefetch — fires at T+3500ms
// Budget: 20 req/day free tier. Hard ceiling: 18/day (see slashGolfBudgetOk()).
// Strategy: 1 schedule/day + 1 leaderboard/event/hour = ~17 req/day max
// Mon-Wed (no active events): only schedule fetch if cache cold = 0-1 req
// Thu-Sun (tournament days): schedule + leaderboards within budget
async function slashGolfPrefetchAll(){
  try{
    if(FIELD_DEBUG) console.debug("[SlashGolf] starting prefetch, budget:", slashGolfReqCount()+"/"+SLASH_GOLF_DAILY_LIMIT);

    // 1. Schedule (24hr cache — essentially free after first load)
    const schedule = await fetchSlashGolfSchedule();
    if(!schedule){ if(FIELD_DEBUG) console.warn("[SlashGolf] no schedule"); return; }

    // 2. Active / upcoming events
    const active = getActiveTournaments(schedule);
    if(FIELD_DEBUG) console.debug(`[SlashGolf] ${active.length} active/upcoming events`);
    if(!active.length) return;

    // 2b. SlashGolf does NOT create PGA Tour Golf sections. ESPN enriched
    // (/v2/golf/enriched) is the primary PGA Tour source; golf section
    // creation happens in the loadPGASlate callback (T+4000ms). SlashGolf
    // remains active for LIV Golf, DP World Tour, LPGA, Champions Tour,
    // annotating whatever cards already exist via injectSlashGolfLeaderNotes
    // (step 4) below -- it does not build game entries itself.
    // buildSlashGolfGamesForToday (an earlier, superseded approach to
    // building game entries directly from this schedule) removed
    // (CC-CMD-2026-07-15-never-adopted-utilities-disposal) -- zero real
    // callers, confirmed genuinely obsolete architecture, not a gap.

    // 3. Leaderboards ONLY for in-progress events (not upcoming)
    // On Mon-Wed there are no in-progress events → 0 leaderboard requests
    const inProgress = active.filter(t => {
      const s = (t.status||"").toLowerCase();
      // Broad: catches "In Progress", "in_progress", "active", "live", round labels, empty
      return s.includes("progress") || s.includes("active") || s.includes("live") ||
             s.includes("round") || /^r[1-4]$/.test(s) || !s;
    });
    const leaderboards = {};
    await Promise.allSettled(inProgress.map(async t => {
      const lb = await fetchSlashGolfLeaderboard(t.tournId);
      if(lb) leaderboards[t.tournId] = lb;
    }));

    // 3b. OWGR world rankings (CC-CMD-2026-07-15-golf-rankings): weekly
    // cache (fetchSlashGolfRankings's own 7-day TTL, already inside
    // slashGolfFetch) -- calling this on every prefetch is safe, it only
    // hits the real API when that cache is actually stale. Conceptually
    // separate from leaderboard (this tournament's current standing) --
    // rankings is season-long career standing, independent of any one
    // event. Real value: notes when a leaderboard leader is a genuinely
    // elite (top-50 OWGR) player, context leaderboard alone doesn't carry.
    const rankings = inProgress.length ? await fetchSlashGolfRankings() : null;

    // 4. Inject into golf cards
    injectSlashGolfLeaderNotes(active, leaderboards, rankings);

    if(FIELD_DEBUG) console.debug("[SlashGolf] prefetch complete", leaderboards);
  }catch(e){
    if(FIELD_DEBUG) console.warn("[SlashGolf] prefetch error", e.message);
  }
}

// ══════════════════════════════════════════════════════════════════════════════
// ESPN PGA engine (V2 enriched relay)
// Source: relay /v2/golf/enriched — leaderboard + per-player stats in one call.
// Coverage: PGA Tour only. SlashGolf retains LIV / DP World / LPGA / Champions.
// Stats available from ESPN: GIR%, driving distance, driving accuracy, putts/GIR,
// sand saves, round scores, position, toPar. Strokes gained is NOT in the ESPN
// payload — never reference it in cards or journalism prompts.
// ══════════════════════════════════════════════════════════════════════════════

// Build a PGA leaderboard card from /v2/golf/enriched response.
// Two render paths:
//   active === true  → tournament header + top-10 leaderboard table
//   active === false → upcoming-event card (name + date) from data.nextEvent
// Per-player stats degrade gracefully — when a stat is missing the column is
// rendered empty, never as a placeholder dash that implies bad data.
function renderPGALeaderboard(data) {
  if (!data) return "";
  // Between-tournament path
  if (data.active === false) {
    const ne = data.nextEvent || {};
    const name = ne.name || ne.event || "Next tournament";
    const date = ne.startDate || ne.date || ne.start || "";
    const loc  = ne.location || ne.course || "";
    return `<div class="pga-card pga-upcoming">
      <div class="pga-eyebrow">PGA TOUR · NEXT EVENT</div>
      <div class="pga-title">${name}</div>
      ${date ? `<div class="pga-upcoming-date">${date}${loc ? ' · ' + loc : ''}</div>` : ''}
    </div>`;
  }
  // Active tournament path
  const ev = data.event || data.tournament || {};
  const round = ev.round || data.round || "";
  const status = ev.status || data.status || "";
  const evName = ev.name || data.name || "PGA TOUR";
  const location = ev.location || ev.course || "";
  const head = `<div class="pga-head">
    <div class="pga-eyebrow">PGA TOUR${round ? ` · Round ${round}` : ""}${status ? ` · ${status}` : ""}</div>
    <div class="pga-title">${evName}</div>
    ${location ? `<div class="pga-meta">${location}</div>` : ''}
  </div>`;

  const players = (data.leaderboard || data.players || []).slice(0, 10);
  if (!players.length) return `<div class="pga-card">${head}</div>`;

  const rows = players.map(p => {
    const pos    = String(p.position || p.pos || "");
    const name   = p.name || p.displayName || `${p.firstName||""} ${p.lastName||""}`.trim();
    const toPar  = p.toPar != null ? String(p.toPar) : (p.total != null ? String(p.total) : "");
    const today  = p.today != null ? String(p.today) : "";
    const thru   = p.thru || "";
    const stats  = p.stats || {};
    const gir    = (stats.gir != null) ? `${Math.round(stats.gir)}%` : "";
    const drive  = (stats.drivingDistance != null) ? `${Math.round(stats.drivingDistance)}yd` : "";
    const sand   = (stats.sandSaves != null && stats.sandSaves > 0) ? `${Math.round(stats.sandSaves)}%` : "";
    const birds  = (stats.birdies != null) ? String(stats.birdies) : "";
    const bogs   = (stats.bogeys != null)  ? String(stats.bogeys)  : "";
    const dubs   = (stats.doublesOrWorse != null && stats.doublesOrWorse > 0) ? String(stats.doublesOrWorse) : "";
    return `<tr class="pga-row">
      <td class="pga-pos">${pos}</td>
      <td class="pga-name">${name}</td>
      <td class="pga-tp">${toPar}</td>
      <td class="pga-today">${today}</td>
      <td class="pga-thru">${thru}</td>
      <td class="pga-gir">${gir}</td>
      <td class="pga-drive">${drive}</td>
      <td class="pga-sand">${sand}</td>
      <td class="pga-birds">${birds}</td>
      <td class="pga-bogs">${bogs}</td>
      <td class="pga-dubs">${dubs}</td>
    </tr>`;
  }).join("");

  const table = `<table class="pga-leaderboard">
    <thead><tr>
      <th>Pos</th><th>Player</th><th>To Par</th><th>Today</th><th>Thru</th><th>GIR</th><th>Drive</th><th>Sand</th><th>B</th><th>Bo</th><th>D+</th>
    </tr></thead>
    <tbody>${rows}</tbody>
  </table>`;

  return `<div class="pga-card">${head}${table}</div>`;
}

// Cut-line projection during R2 of a major (cut is set after 36 holes).
// Returns null outside R2+ or when the field is too small to draw a cut.
// Mode states:
//   'projection' — R2 in progress (some players still on the course)
//   'final'      — R2 complete; cut is set
//   'historical' — R3+; cut already applied. Value = worst toPar in field
//                  (only made-cut players remain on the leaderboard).
// Cut position is 60 + ties for US Open / Masters / PGA / Open (standardized).
// Output: { mode, value, playersInField, playersCompleted, cutPosition }
function computeCutLineProjection(pgaData) {
  if (!pgaData) return null;
  const round = Number(pgaData.round);
  if (!Number.isFinite(round) || round < 2) return null; // suppress before R2
  const lb = pgaData.leaderboard;
  if (!Array.isArray(lb) || lb.length < 60) return null; // not enough field for a 60+ties cut
  const parseTP = (v) => {
    if (v == null) return null;
    if (typeof v === 'number' && Number.isFinite(v)) return v;
    const s = String(v).trim();
    if (s === '' || s === '—' || s === 'CUT' || s === 'WD' || s === 'MDF') return null;
    if (s === 'E' || s.toUpperCase() === 'EVEN') return 0;
    const n = parseFloat(s.replace(/^\+/, ''));
    return Number.isFinite(n) ? n : null;
  };
  const sorted = lb.map(p => parseTP(p && p.toPar)).filter(v => v != null).sort((a, b) => a - b);
  if (sorted.length < 60) return null;
  const cutPosition = 60;
  if (round >= 3) {
    // Cut already applied — only made-cut players remain. The worst toPar
    // in the field is the historical cut value.
    return {
      mode: 'historical',
      value: sorted[sorted.length - 1],
      playersInField: sorted.length,
      playersCompleted: sorted.length,
      cutPosition,
    };
  }
  // Round 2 path: cut = toPar at 0-indexed position 59 (60th best score).
  const projected = sorted[cutPosition - 1];
  const completed = lb.filter(p => {
    const thru = Number(p && p.thru);
    return Number.isFinite(thru) && thru >= 18;
  }).length;
  const isFinal = completed >= sorted.length;
  return {
    mode: isFinal ? 'final' : 'projection',
    value: projected,
    playersInField: sorted.length,
    playersCompleted: completed,
    cutPosition,
  };
}

// fmtGolfToPar extracted to src/utils/golf-format.js (Phase 3).

// Pack-density signal — how many players sit within 3 strokes of the leader.
// A dense pack signals field compression (more dramatic than a runaway).
// Returns null when insufficient data (<10 players with valid toPar) or when
// the field is thin (<5 within 3 — not newsworthy). When non-null:
//   { count, tier: 'dense' | 'moderate', leaderToPar }
// Dense ≥ 8 within 3; moderate 5–7.
function computeGolfPackDensity(pgaData) {
  const lb = pgaData && pgaData.leaderboard;
  if (!Array.isArray(lb) || lb.length === 0) return null;
  const parseTP = (v) => {
    if (v == null) return null;
    if (typeof v === 'number' && Number.isFinite(v)) return v;
    const s = String(v).trim();
    if (s === '' || s === '—' || s === 'CUT' || s === 'WD' || s === 'MDF') return null;
    if (s === 'E' || s.toUpperCase() === 'EVEN') return 0;
    const n = parseFloat(s.replace(/^\+/, ''));
    return Number.isFinite(n) ? n : null;
  };
  const valid = lb.map(p => parseTP(p && p.toPar)).filter(v => v != null);
  if (valid.length < 10) return null; // insufficient signal
  const leaderToPar = Math.min(...valid);
  const count = valid.filter(v => Math.abs(v - leaderToPar) <= 3).length;
  if (count < 5) return null; // thin field, skip
  return { count, leaderToPar, tier: count >= 8 ? 'dense' : 'moderate' };
}

// Inject the rendered PGA leaderboard HTML into the live DOM. Modeled on
// injectSlashGolfLeaderNotes — finds golf game cards in allData.sports and
// inserts the ESPN PGA block. Coexists with SlashGolf's .golf-leaderboard
// strip: ESPN PGA carries the rich GIR / drive / accuracy stats SlashGolf
// does not surface, so when both data sources are available for the same
// event the ESPN card renders alongside (not in place of) the SlashGolf
// strip. Identification uses a dedicated .pga-leaderboard-block container
// so the SlashGolf .golf-leaderboard injection logic stays untouched.
function injectPGALeaderboard(pgaData) {
  if (!pgaData) return;
  const html = renderPGALeaderboard(pgaData);
  if (!html) return;
  if (!allData || !allData.sports) return;
  // Identify the target card. Prefer a golf section game whose name or
  // venue matches the ESPN event; fall back to the first Golf section game
  // when the event-name match is ambiguous (between-tournament path emits a
  // generic "Next event" card without a strong fingerprint).
  const evName = (pgaData.name || '').toLowerCase();
  const evVenue = (pgaData.venue || '').toLowerCase();
  let target = null;
  let firstGolfCard = null;
  for (const sec of allData.sports) {
    if (sec.sport !== 'Golf') continue;
    for (const g of (sec.games || [])) {
      if (!g._id) continue;
      if (!firstGolfCard) firstGolfCard = g;
      const home = (g.home || '').toLowerCase();
      const venue = (g.venue || '').toLowerCase();
      if (evName && (home.includes(evName.split(/\s+/)[0]) || evName.includes(home.split(/\s+/)[0]))) { target = g; break; }
      if (evVenue && venue.includes(evVenue.split(/\s+/)[0])) { target = g; break; }
    }
    if (target) break;
  }
  // Between-tournament path: no fingerprint match — attach to the first golf
  // card so the upcoming-event preview lands somewhere visible.
  if (!target) target = firstGolfCard;
  if (!target) return; // No golf cards at all today; skip silently.

  const card = document.querySelector(`.game-card[data-gameid="${target._id}"]`);
  if (!card) return;
  // Use a dedicated wrapper class so re-injects on subsequent loads replace
  // cleanly, and so SlashGolf's .golf-leaderboard selector still works.
  let block = card.querySelector('.pga-leaderboard-block');
  if (!block) {
    block = document.createElement('div');
    block.className = 'pga-leaderboard-block';
    // Place AFTER SlashGolf's .golf-leaderboard when present so the two
    // strips read as one stacked unit (SlashGolf summary above, ESPN detail
    // below). Otherwise sit immediately after .stream-row, then card-body.
    const sg = card.querySelector('.golf-leaderboard');
    if (sg) sg.after(block);
    else {
      const sr = card.querySelector('.stream-row');
      if (sr) sr.after(block);
      else card.querySelector('.card-body')?.appendChild(block);
    }
  }
  block.innerHTML = html;
  // Append pack-density chip below the leaderboard (skipped when null —
  // either insufficient data or the pack is too thin to be newsworthy).
  try {
    const pack = computeGolfPackDensity(pgaData);
    if (pack) {
      const chip = document.createElement('div');
      chip.className = 'golf-pack-chip' + (pack.tier === 'dense' ? ' dense' : '');
      chip.textContent = `Pack: ${pack.count} within 3`;
      block.appendChild(chip);
    }
  } catch(_) {}
  // Cut-line badge — projection during R2, final cut after R2, historical
  // after R3+. Guarded by computeCutLineProjection (round/field gates inside).
  try {
    const cut = computeCutLineProjection(pgaData);
    if (cut) {
      const badge = document.createElement('div');
      badge.className = 'cut-line-badge';
      const v = fmtGolfToPar(cut.value);
      if (cut.mode === 'projection') {
        badge.textContent = `Projected cut: ${v} (${cut.playersCompleted} of ${cut.playersInField} done)`;
      } else if (cut.mode === 'final') {
        badge.textContent = `Cut: ${v}`;
      } else {
        badge.textContent = `Made cut at ${v}`;
      }
      block.appendChild(badge);
    }
  } catch(_) {}
}

// Load PGA enriched slate from the V2 relay.
// Cache: sessionStorage 10-minute TTL, keyed by TODAY_ISO.
// Returns the parsed response (active:true|false branch), or null on failure.
// Independent of SlashGolf — does not call SlashGolf endpoints or consume its
// SLASH_GOLF_DAILY_LIMIT budget.
// FIELD estimated Strokes Gained engine — derived metrics from canonical
// /v2/golf/enriched data. Computes field averages and per-player SG proxies
// using Broadie methodology. Called after loadPGASlate fetch; reads canonical
// field names (p.stats.gir, p.stats.drivingDistance, etc.) directly — no
// shape mapping. Mutates data: adds data._fieldAvg and p.stats._derived.
function computeGolfDerivedMetrics(data) {
  if (!data || !data.leaderboard) return;
  const lb = data.leaderboard.filter(p => p.stats && p.stats.gir > 0);
  if (lb.length < 10) return; // pre-tournament stats are 0/null
  const avg = (arr, fn) => { const vals = arr.map(fn).filter(v => v != null && v > 0); return vals.length ? vals.reduce((a,b) => a+b, 0) / vals.length : null; };
  const fieldAvg = {
    gir: avg(lb, p => p.stats.gir),
    dist: avg(lb, p => p.stats.drivingDistance),
    acc: avg(lb, p => p.stats.drivingAccuracy),
    ppg: avg(lb, p => p.stats.puttsPerGir),
  };
  data._fieldAvg = fieldAvg;
  data.leaderboard.forEach(p => {
    const s = p.stats;
    if (!s || !s.gir || s.gir <= 0) return;
    const d = s._derived = {};
    if (s.gir != null && s.drivingAccuracy != null) {
      d.ballStriking = Math.round(s.gir * 0.7 + s.drivingAccuracy * 0.3);
    }
    if (s.puttsPerGir != null && fieldAvg.ppg != null) {
      const greensPerRound = (s.gir / 100) * 18;
      d.sgPuttingEst = +((fieldAvg.ppg - s.puttsPerGir) * greensPerRound).toFixed(2);
    }
    if (fieldAvg.gir != null) {
      d.sgApproachEst = +(((s.gir - fieldAvg.gir) / 100) * 18 * 0.4).toFixed(2);
    }
    if (s.drivingDistance != null && fieldAvg.dist != null) {
      const distAdv = (s.drivingDistance - fieldAvg.dist) / 10 * 0.18;
      const accFactor = (s.drivingAccuracy != null && fieldAvg.acc != null)
        ? (s.drivingAccuracy - fieldAvg.acc) / 100 * 0.5 : 0;
      d.sgOTTEst = +(distAdv + accFactor).toFixed(2);
    }
    if (p.rounds && p.rounds.length >= 2) {
      const scores = p.rounds.map(r => typeof r === 'number' ? r : (r && r.score ? r.score : null)).filter(v => v != null);
      if (scores.length >= 2) {
        d.momentum = scores[scores.length - 1] - scores[scores.length - 2];
        d.trend = scores.length >= 3
          ? (scores.slice(-3).reduce((a,b) => a+b, 0) / 3 < scores.slice(0, -1).reduce((a,b) => a+b, 0) / (scores.length - 1) ? 'improving' : 'steady')
          : null;
      }
    }
  });
}

// ── Golf archive hook (CC-CMD-2026-06-19 / Prompt 12C) ────────────────────
// Golf doesn't flow through V2/GameDO/saveEspnFinal, so the per-game
// /archive/game + /archive/drama signals miss the entire sport. This pair
// (detector + sender) mirrors saveEspnFinal for a round at completion.
// Dedup: in-memory per session keyed by "{eventId}_R{round}"; the relay
// must idempotently dedupe across sessions.
const _golfRoundSaved = {};
function _isGolfRoundComplete(pgaData) {
  if (!pgaData) return false;
  const status = String(pgaData.status || '').toLowerCase();
  // Permissive substring match — ESPN status text varies ("Final", "Round
  // Complete", "Official"). Any of these is treated as round-done.
  if (/(complete|official|final)/.test(status)) return true;
  // Fallback: every leaderboard player in the top 60 has thru >= 18.
  const lb = pgaData.leaderboard;
  if (!Array.isArray(lb) || lb.length < 60) return false;
  const top60 = lb.slice(0, 60);
  return top60.every(p => {
    const thru = Number(p && p.thru);
    return Number.isFinite(thru) && thru >= 18;
  });
}
function saveGolfRoundFinal(pgaData) {
  if (!pgaData) return;
  const eventId = pgaData.eventId || '';
  const round = pgaData.round || '';
  const dedup = eventId + '_R' + round;
  if (_golfRoundSaved[dedup]) return;
  _golfRoundSaved[dedup] = true;

  const evName = pgaData.name || 'PGA Tour Event';
  const leader = pgaData.leaderboard?.[0];
  const leaderNote = leader ? `${leader.name} ${leader.toPar}` : '';

  // Archive game row
  const relayBase = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  const today = (typeof TODAY_ISO !== 'undefined') ? TODAY_ISO : new Date().toISOString().slice(0,10);

  fetch(relayBase + '/archive/game', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      sport: 'golf', league: 'PGA Tour', date: today,
      home: evName, away: 'R' + round,
      home_score: leader?.toPar ?? null,
      venue: pgaData.venue || '',
      source_id: 'golf_' + (eventId || today),
      note: leaderNote,
    }),
    keepalive: true,
  }).catch(e => captureFieldError('archive:golf-game', e, false));

  // Drama from golf-specific signals
  const pack = (typeof computeGolfPackDensity === 'function') ? computeGolfPackDensity(pgaData) : null;
  const cut  = (typeof computeCutLineProjection === 'function') ? computeCutLineProjection(pgaData) : null;

  // Golf drama: pack density drives tension, cut line proximity adds stakes
  let golfDrama = 40; // baseline
  if (pack?.count >= 8) golfDrama += 25;      // dense pack = high tension
  else if (pack?.count >= 5) golfDrama += 15;
  if (cut?.mode === 'projection' || cut?.mode === 'final') {
    // Notable players near cut = drama
    golfDrama += 10;
  }
  // Leader margin: 1-stroke lead = exciting, 5+ = boring
  if (leader && pgaData.leaderboard?.[1]) {
    const margin = Math.abs((leader.toPar||0) - (pgaData.leaderboard[1].toPar||0));
    if (margin <= 1) golfDrama += 15;
    else if (margin <= 3) golfDrama += 5;
    else golfDrama -= 10;
  }
  golfDrama = Math.max(0, Math.min(100, golfDrama));

  const arcPayload = {
    peak: golfDrama,
    peakPeriod: 'R' + round,
    sustainedMinutes: 0, // golf doesn't have minute-level drama tracking
    trend: 'steady',
    classification: golfDrama >= 70 ? 'thriller' : golfDrama >= 50 ? 'nail-biter' : 'sleeper',
    samples: [{ s: golfDrama, p: round }],
  };

  fetch(relayBase + '/archive/drama', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      source_id: 'golf_' + (eventId || today),
      drama_peak: golfDrama,
      drama_arc: JSON.stringify(arcPayload),
    }),
    keepalive: true,
  }).catch(e => captureFieldError('archive:golf-drama', e, false));
}

async function loadPGASlate() {
  const today = (typeof TODAY_ISO !== 'undefined') ? TODAY_ISO : new Date().toISOString().slice(0,10);
  const cacheKey = `pga:${today}`;
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const parsed = JSON.parse(cached);
      if (parsed && parsed.ts && (Date.now() - parsed.ts) < 600000) return parsed.data;
    }
  } catch(_e) { captureFieldError('golf:pga-slate-cache-read', _e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  try {
    const r = await fetch(`${base}/v2/golf/enriched?date=${today}`, {
      signal: AbortSignal.timeout(8000),
    });
    if (!r.ok) return null;
    const data = await r.json();
    computeGolfDerivedMetrics(data);
    try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch(_e) { captureFieldError('golf:pga-slate-cache-write', _e, true); }
    return data;
  } catch(e) {
    if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.warn('[PGA] loadPGASlate', e.message);
    captureFieldError('golf:pga-slate-fetch', e, true);
    return null;
  }
}

// Build a golf-specific context block for journalism prompt injection.
// Consumed by J1/J2 brief generators when game._sport indicates PGA. Emits
// the tournament header, top-5 leaderboard rows, and per-player narrative
// translations for leaders' stats. The narrative translations are what turn
// raw numbers into prose the model can build on — e.g. a GIR around 78%
// becomes "hit the green in regulation on about 4 of every 5 holes, well
// above tour average (~65%)."
//
// Only stats present in the ESPN enriched payload are referenced:
//   - GIR percentage
//   - driving distance (yards)
//   - driving accuracy (fairways hit %)
//   - putts per GIR
//   - sand saves (up-and-down from bunker %)
// Tour-average reference points are baked in so the model has a comparison
// anchor without inventing numbers.
function buildGolfPromptContext(pgaData) {
  if (!pgaData || pgaData.active === false) {
    const ne = pgaData?.nextEvent || {};
    const name = ne.name || ne.event || '';
    const date = ne.startDate || ne.date || '';
    return name
      ? `[GOLF CONTEXT]\nNo active PGA tournament today. Next event: ${name}${date ? ' (' + date + ')' : ''}.`
      : '';
  }
  const evName = pgaData.name || 'PGA Tour event';
  const round = pgaData.round || '';
  const status = pgaData.status || '';
  const location = pgaData.venue || '';
  const headerBits = [evName];
  if (round) headerBits.push(`Round ${round}`);
  if (status) headerBits.push(status);
  if (location) headerBits.push(location);

  const players = (pgaData.leaderboard || pgaData.players || []).slice(0, 5);
  const lbLines = players.map(p => {
    const pos = p.position || p.pos || '';
    const name = p.name || p.displayName || `${p.firstName||''} ${p.lastName||''}`.trim();
    const tp = (p.toPar != null) ? p.toPar : (p.total != null ? p.total : '');
    const today = (p.today != null) ? ` (today ${p.today})` : '';
    const thru = p.thru ? ` thru ${p.thru}` : '';
    return `${pos} ${name} ${tp}${today}${thru}`.trim();
  }).filter(Boolean);

  const statLines = [];
  players.forEach(p => {
    const name = p.name || p.displayName || `${p.firstName||''} ${p.lastName||''}`.trim();
    const s = p.stats || {};
    const bits = [];
    if (s.gir != null && s.gir > 0) {
      const v = Math.round(s.gir);
      bits.push(`GIR ${v}% (tour avg ~65%; ${v >= 75 ? 'elite ball-striking' : v >= 65 ? 'on tour avg' : 'below tour avg'})`);
    }
    if (s.drivingDistance != null && s.drivingDistance > 0) {
      const v = Math.round(s.drivingDistance);
      bits.push(`drives ${v}yd${v >= 310 ? ' (long off the tee)' : ''}`);
    }
    if (s.drivingAccuracy != null && s.drivingAccuracy > 0) {
      const v = Math.round(s.drivingAccuracy);
      bits.push(`fairways ${v}%${v >= 68 ? ' (accurate)' : v < 55 ? ' (wayward)' : ''}`);
    }
    if (s.puttsPerGir != null && s.puttsPerGir > 0) {
      bits.push(`${(+s.puttsPerGir).toFixed(2)} putts/GIR${(+s.puttsPerGir) <= 1.75 ? ' (sharp on the greens)' : ''}`);
    }
    if (s.sandSaves != null && s.sandSaves > 0) {
      const v = Math.round(s.sandSaves);
      bits.push(`sand saves ${v}%`);
    }
    if (bits.length) statLines.push(`${name}: ${bits.join(' · ')}`);
    // Derived metrics from FIELD analytics engine
    const d = s._derived || {};
    const dBits = [];
    if (d.sgPuttingEst != null && Math.abs(d.sgPuttingEst) >= 0.3) {
      dBits.push('est. ' + (d.sgPuttingEst > 0 ? '+' : '') + d.sgPuttingEst + ' SG putting/rd');
    }
    if (d.sgApproachEst != null && Math.abs(d.sgApproachEst) >= 0.2) {
      dBits.push('est. ' + (d.sgApproachEst > 0 ? '+' : '') + d.sgApproachEst + ' SG approach/rd');
    }
    if (d.ballStriking != null) {
      dBits.push('ball-striking ' + d.ballStriking + (d.ballStriking >= 75 ? ' (elite)' : d.ballStriking >= 65 ? '' : ' (struggling)'));
    }
    if (d.momentum != null && d.momentum !== 0) {
      dBits.push('momentum ' + (d.momentum > 0 ? '+' : '') + d.momentum + ' vs prev rd');
    }
    if (dBits.length) statLines.push('  ' + name + ' FIELD est.: ' + dBits.join(' · '));
  });

  const parts = [
    '[GOLF CONTEXT]',
    headerBits.join(' · '),
  ];
  if (lbLines.length) {
    parts.push('Leaderboard top 5:');
    lbLines.forEach(l => parts.push('  ' + l));
  }
  // Field-compression signal: how many players sit within 3 strokes of the
  // lead. Same helper that drives the on-card chip; lets the journalism
  // model frame "crowded leaderboard" vs "runaway" without inventing it.
  try {
    const pack = (typeof computeGolfPackDensity === 'function') ? computeGolfPackDensity(pgaData) : null;
    if (pack) {
      const label = pack.tier === 'dense' ? 'dense' : 'moderate';
      parts.push(`Pack density: ${pack.count} players within 3 strokes of the lead — ${label} field`);
    }
  } catch(_) {}
  // Cut-line context — projection during R2, final/historical otherwise.
  // Same helper as the on-card badge; the prompt line uses sentence form.
  try {
    const cut = (typeof computeCutLineProjection === 'function') ? computeCutLineProjection(pgaData) : null;
    if (cut) {
      const v = (typeof fmtGolfToPar === 'function') ? fmtGolfToPar(cut.value) : String(cut.value);
      if (cut.mode === 'projection') {
        parts.push(`Cut line: projected ${v} (${cut.playersCompleted}/${cut.playersInField} players through R2)`);
      } else if (cut.mode === 'final') {
        parts.push(`Cut line: ${v} (final)`);
      } else {
        parts.push(`Cut line: ${v} (made-cut floor in current field)`);
      }
      // Notable-player-near-cut framing. Activates only when the relay
      // supplies pgaData.notablePlayers (an array of athleteId strings or
      // names flagged as top-20 WGR / major winners). Without that, the
      // client cannot identify "notable" without inventing (Rule 1), so
      // this block stays silent. Relay-side handoff documented below.
      const notableSet = new Set((pgaData.notablePlayers || []).map(x => String(x).toLowerCase()));
      if (notableSet.size && Array.isArray(pgaData.leaderboard)) {
        const cv = cut.value;
        const near = [];
        for (const p of pgaData.leaderboard) {
          const name = (p.name || p.displayName || `${p.firstName||''} ${p.lastName||''}`.trim());
          const id = String(p.athleteId || '').toLowerCase();
          if (!notableSet.has(name.toLowerCase()) && !notableSet.has(id)) continue;
          const tp = (typeof p.toPar === 'number') ? p.toPar : parseFloat(String(p.toPar||'').replace(/^\+/, ''));
          if (!Number.isFinite(tp)) continue;
          const delta = tp - cv;
          if (Math.abs(delta) > 1) continue;
          const side = delta < 0 ? 'below' : delta > 0 ? 'above' : 'on';
          const tpFmt = (typeof fmtGolfToPar === 'function') ? fmtGolfToPar(tp) : String(tp);
          near.push(`${name} at ${tpFmt} — ${side} the projected cut line`);
        }
        near.forEach(line => parts.push(line));
      }
    }
  } catch(_) {}
  if (statLines.length) {
    parts.push('Leaders by the numbers:');
    statLines.forEach(l => parts.push('  ' + l));
    parts.push('FIELD estimated SG values are derived from traditional stats using Broadie methodology. Label as estimates, not official PGA Tour figures.');
    parts.push('Use these stats to anchor narrative — translate percentages to plain prose. Cite only the numbers above; never invent figures the data does not contain.');
  }
  // Field averages block
  if (pgaData._fieldAvg) {
    const fa = pgaData._fieldAvg;
    const faBits = [];
    if (fa.gir) faBits.push('GIR ' + Math.round(fa.gir) + '%');
    if (fa.dist) faBits.push('driving ' + Math.round(fa.dist) + 'yd');
    if (fa.acc) faBits.push('fairways ' + Math.round(fa.acc) + '%');
    if (fa.ppg) faBits.push('putts/GIR ' + fa.ppg.toFixed(2));
    if (faBits.length) parts.push('Field averages this week: ' + faBits.join(' \xb7 '));
  }
  return parts.join('\n');
}

// ══════════════════════════════════════════════════════════════════════════════
// Home Run Derby — bracket structure + journalism context (CC-CMD-2026-07-13-
// hrd-bracket-client). Single-night, fixed 8-slot bracket, known field in
// advance — unlike golf's multi-day tournament shape, the bracket structure
// itself doesn't need live data to build and test correctly, only the live
// results do. Companion relay work (field-relay-nba's /homeRunDerby/{gamePk}
// proxy) was not confirmed landed as of this build — see buildHRDBracket's
// own doc comment for the live-results hook this is built against, not
// wired to any live source yet.
//
// Real, verified 2026 field (cross-checked across 5 sources):
// Kyle Schwarber (Phillies, MLB HR leader), Bryce Harper (Phillies, 2018
// champion / 2013 runner-up, home stadium), Munetaka Murakami (White Sox,
// second-ever Japanese-born participant after Ohtani 2021), Junior Caminero
// (Rays, 2025 runner-up), Ben Rice (Yankees), Jac Caglianone (Royals,
// youngest at 23), Willson Contreras (Red Sox), Jordan Walker (Cardinals).
// Format: Round 1 all eight, 20 swings each, top 4 HR totals advance (ties
// broken by longest HR distance); semis/final 15 swings each, seeded
// 1v4/2v3; ties broken by 3-swing swing-off.
// ══════════════════════════════════════════════════════════════════════════════

const HRD_FIELD_2026 = [
  { name: 'Kyle Schwarber',     team: 'Phillies',  note: 'MLB HR leader' },
  { name: 'Bryce Harper',       team: 'Phillies',  note: '2018 champion · 2013 runner-up · home stadium' },
  { name: 'Munetaka Murakami',  team: 'White Sox', note: 'second-ever Japanese-born participant, after Ohtani 2021' },
  { name: 'Junior Caminero',    team: 'Rays',      note: '2025 runner-up' },
  { name: 'Ben Rice',           team: 'Yankees',   note: '' },
  { name: 'Jac Caglianone',     team: 'Royals',    note: 'youngest in the field, age 23' },
  { name: 'Willson Contreras',  team: 'Red Sox',   note: '' },
  { name: 'Jordan Walker',      team: 'Cardinals', note: '' },
];

// 2026-07-13 (hrd-verified-final-result): the live /homeRunDerby/{gamePk}
// pipeline never left status:"Preview" all night (confirmed genuine
// MLB-side gap, not a caching or wrong-ID issue on our end -- see codex
// incident hrd-live-gamepk-stuck-preview-2026-07-13). The real result IS
// known and verified -- cross-checked live across 4 independent sources
// within minutes of the event ending (Bleacher Report, DraftKings Network,
// Philadelphia Inquirer, Yahoo Sports), all agreeing on the same score and
// storyline. Used the same way HRD_FIELD_2026 above is used -- a static,
// dated, one-time verified fact for this specific event, not a live-data
// mechanism. Do not reuse this pattern for a future year's Derby without
// re-verifying fresh.
const HRD_2026_VERIFIED_FINAL = {
  champion: 'Jordan Walker',
  runnerUp: 'Kyle Schwarber',
  finalScore: '12-11',
  summary: 'Walker trailed 8-11 with one swing left in the final round, then '
    + 'homered on 4 straight swings to overtake Schwarber and win 12-11 -- '
    + 'in front of the hometown Citizens Bank Park crowd loudly pulling for '
    + 'Schwarber. First Cardinals player ever to win the Home Run Derby. '
    + 'Schwarber finishes as Derby runner-up for the second time in his career.',
};

// buildHRDBracket(apiResponse) — derives the full bracket state from the
// REAL MLB Stats API homeRunDerby response shape (relay path
// /mlb-stats/homeRunDerby/{gamePk}), not an invented shape.
//
// CC-CMD-2026-07-13-hrd-live-wiring TASK 0 finding, real not guessed: a real
// live response was captured (docs/hrd-api-response-reference-2026-07-13.json,
// sandbox-fetched since Claude Code's own sandbox egress AND the
// probe_relay_route tool's allow-list both confirmed blocked for this path)
// and it revealed the tournament's real topology does NOT match this file's
// original build (hrd-bracket-client): Round 1 is NOT "all 8 compete, top 4
// by total HR advance" — it is a true single-elimination bracket from Round
// 1 onward, with real seeded head-to-head matchups (1v8, 2v7, 3v6, 4v5) in
// the captured response. rounds[1]/rounds[2] (semis/final) carry NO
// `matchups` array until the prior round completes -- at that point the API
// itself supplies the real pairing (topSeed/bottomSeed), so this function
// never computes seeding itself; it only ever reads whatever matchups the
// API has already decided, for all three rounds uniformly. Winner
// determination also always defers to the API's own `isWinner`/`isComplete`
// flags (real bonus-time/tiebreak rules are computed server-side; this
// client makes no attempt to re-derive them).
//
// apiResponse shape (real, from the captured reference file):
//   { status: { state }, rounds: [
//       { round: 1, matchups: [ { topSeed: {player:{fullName,id}, seed,
//           numHomeRuns, topDerbyHitData:{totalDistance}, isWinner,
//           isComplete, isStarted}, bottomSeed: {...} }, ... ] },
//       { round: 2, matchups: [...] | absent until round 1 completes },
//       { round: 3, matchups: [...] | absent until round 2 completes },
//   ] }
// Safe with apiResponse absent/undefined/malformed (pre-event placeholder —
// falls back to the known field with no matchups, never fabricates pairings).
function _hrdMapSlot(slot) {
  if (!slot || !slot.player) return null;
  return {
    name: slot.player.fullName || '',
    playerId: slot.player.id ?? null,
    seed: slot.seed ?? null,
    hrTotal: slot.numHomeRuns ?? null,
    longestHR: (slot.topDerbyHitData && slot.topDerbyHitData.totalDistance) || null,
    isWinner: !!slot.isWinner,
    isComplete: !!slot.isComplete,
    isStarted: !!slot.isStarted,
  };
}
function _hrdMapMatchup(m) {
  if (!m) return null;
  const top = _hrdMapSlot(m.topSeed);
  const bottom = _hrdMapSlot(m.bottomSeed);
  if (!top || !bottom) return null;
  const winner = top.isWinner ? top : (bottom.isWinner ? bottom : null);
  return { top, bottom, winner, complete: top.isComplete && bottom.isComplete };
}
function buildHRDBracket(apiResponse) {
  const rounds = (apiResponse && Array.isArray(apiResponse.rounds)) ? apiResponse.rounds : [];
  const byRound = (n) => rounds.find(rd => rd.round === n) || null;
  const mapRound = (n) => {
    const src = byRound(n);
    return (src && Array.isArray(src.matchups)) ? src.matchups.map(_hrdMapMatchup).filter(Boolean) : [];
  };

  // 2026-07-13 (hrd-round1-pool-fix): the real captured API response
  // (docs/hrd-api-response-reference-2026-07-13.json) labels round 1
  // `"type": "Pool"` and rounds 2/3 `"type": "Bracket"` -- confirmed against
  // 5+ live news sources during this fix (Fox Sports, Yahoo, ABC News,
  // NBC10, MLB.com, all matching): round 1 is NOT head-to-head elimination.
  // All 8 batters compete independently (20 swings each); the API's
  // topSeed/bottomSeed "matchup" pairing in round 1 (1v8, 2v7, 3v6, 4v5) is
  // a batting-ORDER pairing for broadcast pacing, not a competitive pairing
  // -- isWinner within a round-1 pair does not determine advancement.
  // Advancement is: rank all 8 by numHomeRuns, ties broken by longest HR
  // distance (topDerbyHitData.totalDistance), top 4 advance. Rounds 2/3
  // (type:"Bracket") ARE genuine head-to-head elimination -- unchanged,
  // still correctly handled by the existing matchup mapping below.
  const round1Src = byRound(1);
  const round1Type = (round1Src && round1Src.type) || null;
  const round1 = mapRound(1); // kept for backward compat / raw pairing data
  const round1Slots = round1.flatMap(m => [m.top, m.bottom]).filter(Boolean);
  const round1Leaderboard = round1Slots
    .slice()
    .sort((a, b) => (b.hrTotal ?? -1) - (a.hrTotal ?? -1) || (b.longestHR ?? -1) - (a.longestHR ?? -1))
    .map((slot, i) => ({ ...slot, rank: i + 1, advancing: i < 4 }));
  const round1Complete = round1.length > 0 && round1.every(m => m.complete);
  const round2 = mapRound(2); // semifinals — only populated by the API once round 1 completes
  const round2Complete = round2.length > 0 && round2.every(m => m.complete);
  const round3 = mapRound(3); // final — only populated by the API once round 2 completes

  const champion = (round3.length === 1 && round3[0].complete) ? round3[0].winner : null;

  // 2026-07-13 (hrd-hasLiveData-preview-guard): discovered live during tonight's
  // actual event -- the pre-event PLACEHOLDER response has the exact same
  // matchup-array structure as a real result (4 pairs, 8 slots), just with
  // every slot at 0 HR / isStarted:false / state:"Preview". The old
  // `round1.length > 0` check can't tell a real result from that placeholder,
  // so buildHRDPromptContext could have stated "1. Schwarber — 0 HR" for
  // every player as fact -- actively wrong, worse than "not yet available".
  // Require real evidence of activity: API state isn't Preview, OR at least
  // one slot is genuinely started/complete. Confirmed via a real live probe
  // against the actual event (status.state stayed "Preview" with a
  // cache-busted, non-cached upstream fetch) that this guard is necessary,
  // not theoretical.
  const apiState = (apiResponse && apiResponse.status && apiResponse.status.state) || null;
  const round1AnyStarted = round1Slots.some(s => s.isStarted || s.isComplete);
  const hasLiveData = round1.length > 0 && (apiState !== 'Preview' || round1AnyStarted);

  return {
    field: HRD_FIELD_2026,
    hasLiveData,
    state: apiState,
    round1, round1Type, round1Leaderboard, round1Complete,
    round2, round2Complete,
    round3, champion,
  };
}

// renderHRDBracket(bracket) — HTML card for the bracket. Matches
// renderPGALeaderboard's convention: takes a derived data object, returns
// an HTML string, renders correctly whether the bracket is all-placeholder
// (pre-event, no matchups decided anywhere) or partially/fully populated.
// 2026-07-13 (hrd-round1-pool-fix): Round 1 renders as a ranked leaderboard
// (round1Leaderboard) -- half golf-leaderboard, half bracket, matching the
// real tournament shape. Semifinals/Final render as head-to-head matchup
// cards (unchanged, those rounds genuinely are elimination bracket).
function _hrdRenderMatchup(m, label, extraCls) {

  const cls = 'hrd-semi' + (extraCls ? ' ' + extraCls : '');
  if (!m) {
    return `<div class="${cls}"><div class="hrd-semi-label">${label}</div><div class="hrd-semi-player">TBD</div><div class="hrd-semi-player">TBD</div></div>`;
  }
  const line = (slot) => {
    const hr = slot.hrTotal != null ? ` — ${slot.hrTotal} HR` : '';
    const seedTxt = slot.seed != null ? `(${slot.seed}) ` : '';
    const isWin = m.winner && m.winner.name === slot.name;
    return `<div class="hrd-semi-player${isWin ? ' hrd-winner' : ''}">${seedTxt}${slot.name}${hr}</div>`;
  };
  return `<div class="${cls}"><div class="hrd-semi-label">${label}</div>${line(m.top)}${line(m.bottom)}</div>`;
}
function _hrdRenderLeaderboardRow(slot) {
  const hr = slot.hrTotal != null ? slot.hrTotal : '—';
  const dist = slot.longestHR != null ? `${Math.round(slot.longestHR)}ft` : '';
  const field = HRD_FIELD_2026.find(p => p.name === slot.name);
  const team = field ? field.team : '';
  const rowCls = 'hrd-pool-row' + (slot.advancing ? ' hrd-winner' : '');
  return `<div class="${rowCls}">
    <span class="hrd-pool-rank">${slot.rank}</span>
    <span class="hrd-pool-name">${slot.name}${team ? ` <span class="hrd-team">${team}</span>` : ''}</span>
    <span class="hrd-pool-hr">${hr} HR</span>
    <span class="hrd-pool-dist">${dist}</span>
  </div>`;
}
function renderHRDBracket(bracket) {
  if (!bracket) return '';
  const round1HTML = bracket.round1Leaderboard.length
    ? bracket.round1Leaderboard.map(_hrdRenderLeaderboardRow).join('')
    : HRD_FIELD_2026.map(p => `<div class="hrd-pool-row"><span class="hrd-pool-name">${p.name} <span class="hrd-team">${p.team}</span></span></div>`).join('');

  const round2HTML = bracket.round2.length
    ? bracket.round2.map((m, i) => _hrdRenderMatchup(m, `Semifinal ${i + 1}`)).join('')
    : [1, 2].map(i => _hrdRenderMatchup(null, `Semifinal ${i}`)).join('');

  const round3HTML = bracket.round3.length
    ? _hrdRenderMatchup(bracket.round3[0], 'Final', 'hrd-final')
    : `<div class="hrd-final-tbd">Final: TBD</div>`;

  const championHTML = bracket.champion
    ? `<div class="hrd-champion">🏆 ${bracket.champion.name} — 2026 Home Run Derby Champion</div>`
    : '';

  return `<div class="hrd-card">
    <div class="hrd-head">
      <div class="hrd-eyebrow">HOME RUN DERBY${bracket.state ? ' · ' + String(bracket.state).toUpperCase() : ''}</div>
      <div class="hrd-title">2026 Bracket</div>
    </div>
    <div class="hrd-round-label">Round 1${bracket.round1Complete ? ' · top 4 advance' : ' · pool, top 4 advance'}</div>
    <div class="hrd-bracket-rounds">${round1HTML}</div>
    <div class="hrd-round-label">Semifinals</div>

    <div class="hrd-bracket-rounds">${round2HTML}</div>
    <div class="hrd-round-label">Final</div>
    <div class="hrd-bracket-rounds">${round3HTML}${championHTML}</div>
  </div>`;
}

// buildHRDPromptContext(bracket) — journalism context builder, matching
// buildGolfPromptContext's convention: [TAG]-prefixed string built from a
// parts array, real static storylines (from the CC-CMD's own 5-source-
// verified field), graceful when live round results aren't available yet.
// Never fabricates a result the bracket data doesn't actually contain.
function buildHRDPromptContext(bracket) {
  const b = bracket || buildHRDBracket(null);
  const parts = ['[HOME RUN DERBY CONTEXT]'];
  parts.push('2026 Field (8 sluggers — Round 1: all 8 compete independently, 20 swings each, ranked by total home runs (ties broken by longest HR distance), top 4 advance; Semifinals/Final: seeded head-to-head, 15 swings each, official MLB bonus-time and tiebreak rules apply):');
  HRD_FIELD_2026.forEach(p => {
    parts.push(`  ${p.name} (${p.team})${p.note ? ' — ' + p.note : ''}`);
  });
  parts.push('Storylines:');
  parts.push('  Kyle Schwarber enters as the 2026 MLB home run leader.');
  parts.push('  Bryce Harper returns to a Derby he knows well — 2018 champion, 2013 runner-up — at his home stadium, Citizens Bank Park.');
  parts.push('  Junior Caminero is back after finishing runner-up in 2025.');
  parts.push('  Munetaka Murakami becomes just the second Japanese-born Derby participant, after Shohei Ohtani in 2021.');
  parts.push('  Jac Caglianone, 23, is the youngest competitor in the field.');
  parts.push('  Format note: the swing-based, clock-free system has replaced the timed format used since 2015.');
  if (!b.hasLiveData) {
    parts.push(`Final result (live tracking never populated tonight, but the real outcome is verified): `
      + `${HRD_2026_VERIFIED_FINAL.champion} defeats ${HRD_2026_VERIFIED_FINAL.runnerUp}, `
      + `${HRD_2026_VERIFIED_FINAL.finalScore}. ${HRD_2026_VERIFIED_FINAL.summary}`);
  } else {
    parts.push('Round 1 (pool, ranked by home runs):');
    b.round1Leaderboard.forEach(slot => {
      const status = slot.hrTotal == null ? ' — not yet started'
        : slot.isComplete ? '' : ' — in progress';
      const adv = slot.advancing ? ' (advancing)' : '';
      parts.push(`  ${slot.rank}. ${slot.name} — ${slot.hrTotal ?? 0} HR${adv}${status}`);
    });
    if (b.round2.length) {
      parts.push('Semifinals:');
      b.round2.forEach((m, i) => {
        const status = m.complete && m.winner ? ` — ${m.winner.name} wins` : '';
        parts.push(`  Semifinal ${i + 1}: ${m.top.name} vs ${m.bottom.name}${status}`);
      });
    }
    if (b.champion) {
      parts.push(`Champion: ${b.champion.name}.`);
    } else if (b.round3.length) {
      parts.push(`Final: ${b.round3[0].top.name} vs ${b.round3[0].bottom.name}.`);
    }
  }
  return parts.join('\n');
}

// loadHRDBracket() — fetch + cache wrapper matching loadPGASlate()'s
// established async + sessionStorage-cache convention. TTL matches
// NBA_LIVE_BS_TTL (90s — "one per ESPN poll cycle", the same live-event
// cadence this file already uses for other in-progress-game data), per
// the CC-CMD's own "match it, don't invent a new interval" instruction.
const HRD_GAME_PK = 839032;
const HRD_LIVE_TTL = 90 * 1000;
async function loadHRDBracket() {
  const cacheKey = 'hrd:' + HRD_GAME_PK;
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const parsed = JSON.parse(cached);
      if (parsed && parsed.ts && (Date.now() - parsed.ts) < HRD_LIVE_TTL) return parsed.data;
    }
  } catch(_e) { captureFieldError('hrd:cache-read', _e, true); }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  try {
    const r = await fetch(`${base}/mlb-stats/homeRunDerby/${HRD_GAME_PK}`, {
      signal: AbortSignal.timeout(8000),
    });
    if (!r.ok) return null;
    const data = await r.json();
    try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch(_e) { captureFieldError('hrd:cache-write', _e, true); }
    return data;
  } catch(e) {
    if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.warn('[HRD] loadHRDBracket', e.message);
    captureFieldError('hrd:fetch', e, true);
    return null;
  }
}

// injectHRDBracket(apiResponse) — finds the static "T-Mobile Home Run Derby"
// MEDIA_SPECIALS card (hrd-entry-v2) and injects the live renderHRDBracket()
// output into it. Adapted from injectPGALeaderboard's real mechanics
// (TASK 0 finding): golf targets a `.game-card[data-gameid]` from
// allData.sports, but the HRD entry is a MEDIA_SPECIALS card rendered by
// renderMedia() into #media-grid as a plain `.media-card` with NO
// identifying attribute at all -- renderMedia()'s template now stamps
// `data-show` (see its own definition) so this has a stable target, mirroring
// `.game-card[data-gameid]`'s role for golf. Idempotent — a dedicated
// wrapper class lets repeat calls (the 90s poll) replace cleanly.
function injectHRDBracket(apiResponse) {
  if (!apiResponse) return;
  const bracket = buildHRDBracket(apiResponse);
  const html = renderHRDBracket(bracket);
  if (!html) return;
  const card = document.querySelector('.media-card[data-show="T-Mobile Home Run Derby"]');
  if (!card) return; // card not rendered yet (renderMedia() hasn't fired, or lazy section not in view) — next poll retries
  let block = card.querySelector('.hrd-bracket-block');
  if (!block) {
    block = document.createElement('div');
    block.className = 'hrd-bracket-block';
    const desc = card.querySelector('.media-desc');
    if (desc) desc.after(block);
    else card.querySelector('.media-body')?.appendChild(block);
  }
  block.innerHTML = html;
  // Stash for buildHRDPromptContext's real journalism-context consumer
  // (mirrors window._pgaDataCache's role for golf — see the fetchGameBriefOnDemand
  // splice point, CC-CMD-2026-07-13-hrd-live-wiring TASK 2).
  try { window._hrdDataCache = apiResponse; } catch(_e) {}
}

// _hrdPollLoop() — repeat-fetch cadence for the ~2-hour live window tonight.
// Gated to the event's own date (matches hrd-entry-v2's MEDIA_SPECIALS
// startDate/endDate scoping) and stops once the API itself reports the
// event finalized (status.state — no longer "Preview"/"In Progress").
function _hrdPollLoop() {
  if (TODAY_ISO !== '2026-07-13') return; // event day only — no wasted polling any other day
  let stopped = false;
  const tick = () => {
    if (stopped) return;
    loadHRDBracket().then(data => {
      if (!data) return;
      injectHRDBracket(data);
      const state = data.status && data.status.state;
      if (state && !/preview|in.?progress|live/i.test(state)) stopped = true; // event finalized — stop polling
    });
  };
  tick(); // fire immediately once the media section is visible
  const intervalId = setInterval(() => { if (stopped) { clearInterval(intervalId); return; } tick(); }, HRD_LIVE_TTL);
}

// ══════════════════════════════════════════════════════════════════════════════
// Football-Data.org engine
// Free tier: 10 req/min, no commercial use, attribution required
// Covers: PL, ELC, PD, SA, BL1, FL1, CL, EL, ECL and more
// ══════════════════════════════════════════════════════════════════════════════

async function fdFetch(path){
  // Routes through relay worker — CORS bypass + X-Auth-Token added server-side
  // Free tier: 10 req/min shared across all users via relay-level Cloudflare caching
  const r = await fetch(`${FD_RELAY}${path}`, {
    signal: AbortSignal.timeout(8000)
  });
  if(!r.ok) throw new Error(`FD relay ${r.status} ${path}`);
  return r.json();
}

// Fetch and cache standings for a competition code (PL, PD, SA, etc.)
// Returns array of {pos, team, played, won, draw, lost, gf, ga, gd, pts, form}
// form is a 5-char string like "WWDLW" (most recent last)
// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #10): investigated
// the queue's "distinguish 429/rate-limit, add backoff like slashGolfFetch"
// suggestion before building it. fdFetchStandings has exactly 1 real
// caller (toggleStandings, a click-triggered standings-panel expand, not a
// poll loop), and fdStandingsCache above already prevents repeat fetches
// for the same competition within a session -- the "hammering a 10 req/min
// free-tier limit" risk a dedicated backoff system would exist to prevent
// is much lower here than for a function polled on an interval. Building
// that machinery for a user-click-triggered, already-cached call would be
// over-engineering relative to the actual risk. What WAS a real, confirmed
// gap: this catch had zero persistent telemetry, only a FIELD_DEBUG-gated
// console.warn. Added captureFieldError, matching the established pattern.
async function fdFetchStandings(code){
  if(fdStandingsCache[code]) return fdStandingsCache[code];
  try{
    const data = await fdFetch(`/competitions/${code}/standings?season=2025`);
    const table = (data.standings||[]).find(s=>s.type==="TOTAL")?.table || [];
    const rows = table.map(r=>({
      pos:   r.position,
      team:  r.team?.shortName || r.team?.name || "?",
      played:r.playedGames,
      won:   r.won,
      draw:  r.draw,
      lost:  r.lost,
      gf:    r.goalsFor,
      ga:    r.goalsAgainst,
      gd:    r.goalDifference >= 0 ? `+${r.goalDifference}` : String(r.goalDifference),
      pts:   r.points,
      form:  (r.form||"").replace(/,/g,"").slice(-5) // last 5 results: "WWDLW"
    }));
    fdStandingsCache[code] = rows;
    return rows;
  }catch(e){
    if(FIELD_DEBUG) console.warn("FD standings:", e.message);
    captureFieldError('standings:fd', e, false);
    return null;
  }
}

// Fetch H2H record between two FD team IDs
// Returns {homeWins, awayWins, draws, lastMeetings:[{date,homeTeam,awayTeam,homeScore,awayScore}]}

// ── H2H history for soccer match briefs ─────────────────────────────────────
// fdFetchH2H: fetches last 5 meetings between two teams from football-data.org
// Used in fetchEPLMatchBriefFromClaude() to give the AI historical context.
// Free tier: results cached in fdH2HCache to avoid duplicate calls.
// FD match IDs are resolved at fetch time from the daily fixtures response.
async function fdFetchH2H(matchId){
  const cKey = String(matchId);
  if(fdH2HCache[cKey]) return fdH2HCache[cKey];
  try{
    const data = await fdFetch(`/matches/${matchId}/head2head?limit=5`);
    const agg  = data.aggregates || {};
    const mtch = (data.matches||[]).slice(0,5).map(m=>({
      date:      (m.utcDate||'').slice(0,10),
      homeTeam:  m.homeTeam?.shortName || '',
      awayTeam:  m.awayTeam?.shortName || '',
      homeScore: m.score?.fullTime?.home ?? '?',
      awayScore: m.score?.fullTime?.away ?? '?',
    }));
    const result = {
      homeWins:     agg.homeTeam?.wins  ?? 0,
      awayWins:     agg.awayTeam?.wins  ?? 0,
      draws:        agg.homeTeam?.draws ?? 0,
      lastMeetings: mtch,
    };
    fdH2HCache[cKey] = result;
    return result;
  }catch(e){
    if(FIELD_DEBUG) console.warn('FD H2H:', e.message);
    captureFieldError('soccer:fd-h2h', e, true);
    return null;
  }
}

// Build a compact H2H summary string for AI prompts (sync — uses cache only)
// Returns '' if no H2H data available; call fdFetchH2H() first for async fetch.
function buildH2HSummary(matchId){
  const h = fdH2HCache[String(matchId)];
  if(!h) return '';
  const total = h.homeWins + h.awayWins + h.draws;
  if(!total) return '';
  const recentLine = h.lastMeetings.slice(0,3).map(m=>
    `${m.date.slice(5)} ${m.homeTeam} ${m.homeScore}-${m.awayScore} ${m.awayTeam}`
  ).join('; ');
  return `H2H last ${total} meetings: ${h.homeWins}W-${h.draws}D-${h.awayWins}L.${recentLine?' Recent: '+recentLine+'.':''}`;
}

// Render a football-data.org standings panel (richer than ESPN for soccer)
// Shows: #, Team, P, W, D, L, GF, GA, GD, Pts, Form
function renderFDStandingsPanel(panel, rows, sportName){
  const formDot = c => {
    const col = c==="W"?"#22c55e":c==="L"?"#ef4444":"#94a3b8";
    return `<span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${col};margin:0 1px" title="${c==="W"?"Win":c==="L"?"Loss":"Draw"}"></span>`;
  };
  const rowsHtml = rows.slice(0,20).map((r,i)=>{
    const cls = i<4 ? "highlight" : i>=rows.length-3 ? "relegation" : "";
    const formHtml = (r.form||"").split("").map(formDot).join("") || "—";
    return `<tr class="${cls}">
      <td style="color:var(--smoke);padding-right:.3rem;font-size:.65rem">${r.pos}</td>
      <td style="max-width:90px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:.72rem">${r.team}</td>
      <td style="text-align:right;font-size:.65rem">${r.played}</td>
      <td style="text-align:right;font-size:.65rem">${r.won}</td>
      <td style="text-align:right;font-size:.65rem">${r.draw}</td>
      <td style="text-align:right;font-size:.65rem">${r.lost}</td>
      <td style="text-align:right;font-size:.65rem;color:var(--smoke)">${r.gd}</td>
      <td style="text-align:right;color:var(--gold2);font-weight:700;font-size:.72rem">${r.pts}</td>
      <td style="padding-left:.3rem">${formHtml}</td>
    </tr>`;
  }).join("");
  panel.innerHTML = `<table class="standings-table" style="width:100%">
    <thead><tr>
      <th style="font-size:.6rem">#</th>
      <th>Team</th>
      <th style="text-align:right;font-size:.6rem">P</th>
      <th style="text-align:right;font-size:.6rem">W</th>
      <th style="text-align:right;font-size:.6rem">D</th>
      <th style="text-align:right;font-size:.6rem">L</th>
      <th style="text-align:right;font-size:.6rem">GD</th>
      <th style="text-align:right;font-size:.6rem">Pts</th>
      <th style="font-size:.6rem">Form</th>
    </tr></thead>
    <tbody>${rowsHtml}</tbody>
  </table>
  <div style="font-size:.58rem;color:var(--smoke);padding:.2rem .5rem .1rem;text-align:right">
    via football-data.org · 
    <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#22c55e;margin:0 2px"></span>W
    <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#94a3b8;margin:0 2px"></span>D
    <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#ef4444;margin:0 2px"></span>L
  </div>
  <div style="font-size:.5rem;text-align:right;margin-top:.4rem;opacity:.4;letter-spacing:.03em">data: football-data.org</div>`;
}

async function fetchESPNStandings(sportName){
  const map = ESPN_STANDINGS_MAP[sportName];
  if(!map) return null;
  const cacheKey = map.sport+"/"+map.league;
  if(espnStandingsCache[cacheKey]) return espnStandingsCache[cacheKey];
  try{
    const url = `${ESPN_BASE}/${map.sport}/${map.league}/standings`;
    const r = await fetch(url);
    if(!r.ok) throw new Error("ESPN standings HTTP "+r.status);
    const json = await r.json();
    // ESPN standings structure: children[].standings.entries[]
    const entries = [];
    const groups = json.children || [json];
    groups.forEach(g=>{
      const ents = g.standings?.entries || [];
      ents.forEach(e=>{
        const stats = {};
        (e.stats||[]).forEach(s=>{ stats[s.name]=s.displayValue||s.value; });
        entries.push({
          rank:       e.stats?.find(s=>s.name==="rank")?.value || entries.length+1,
          team:       e.team?.displayName || e.team?.shortDisplayName || "",
          abbrev:     e.team?.abbreviation || "",
          wins:       stats.wins        || stats.W    || "",
          losses:     stats.losses      || stats.L    || "",
          pct:        stats.winPercent  || stats.PCT  || "",
          gb:         stats.gamesBehind || stats.GB   || "",
          streak:     stats.streak      || "",
          last10:     stats.Last10      || stats.L10  || "",
          pts:        stats.points      || stats.PTS  || "",
          played:     stats.gamesPlayed || stats.GP   || "",
          draws:      stats.ties        || stats.D    || "",
          gd:         stats.goalDifference != null ? String(stats.goalDifference) : "",
          group:      g.name            || "",
        });
      });
    });
    if(entries.length) espnStandingsCache[cacheKey] = entries;
    if(FIELD_DEBUG) console.debug(`[ESPN Standings] ${sportName}: ${entries.length} teams`);
    return entries.length ? entries : null;
  }catch(e){
    if(FIELD_DEBUG) console.warn("[ESPN Standings] failed for "+sportName+":", e.message);
    captureFieldError('standings:espn-fetch', e, true);
    return null;
  }
}

// Toggle standings panel on soccer game cards
// Priority: FD.org (form table) → ESPN → SDB stub
async function toggleStandings(btn, leagueId, season){
  const card = btn.closest(".game-card");
  if(!card) return;
  const sportName = card.dataset.sport || "";
  const isSoccerSport = !!FD_LEAGUE_MAP[sportName] || sportName === "MLS Soccer";
  const openLabel  = isSoccerSport ? "▼ Table"     : "▼ Standings";
  const closeLabel = isSoccerSport ? "▲ Table"     : "▲ Standings";
  let panel = card.querySelector(".standings-panel");
  if(panel){
    const isOpen = panel.style.display !== "none";
    panel.style.display = isOpen ? "none" : "block";
    btn.textContent = isOpen ? openLabel : closeLabel;
    return;
  }
  btn.textContent = "…";
  panel = document.createElement("div");
  panel.className = "standings-panel";
  panel.style.display = "block";

  // ── Football-Data.org first (form table, most complete) ─────────────────
  const fdCode = FD_LEAGUE_MAP[sportName];
  if(fdCode){
    try{
      const fdRows = await fdFetchStandings(fdCode);
      if(fdRows && fdRows.length){
        renderFDStandingsPanel(panel, fdRows, sportName);
        card.appendChild(panel);
        btn.textContent = closeLabel;
        return;
      }
    }catch(e){ if(FIELD_DEBUG) console.warn("[Standings] FD failed:", e.message); }
  }

  // ── ESPN fallback ─────────────────────────────────────────────────────────
  try{
    const espnEntries = await fetchESPNStandings(sportName);
    if(espnEntries && espnEntries.length){
      renderESPNStandingsPanel(panel, espnEntries, sportName);
      card.appendChild(panel);
      btn.textContent = closeLabel;
      return;
    }
  }catch(e){ if(FIELD_DEBUG) console.warn("[Standings] ESPN failed:", e.message); }

  // ── Final stub — silently restore; no error card expansion ────────────────
  btn.textContent = openLabel;  // restore — no cascade
  if(FIELD_DEBUG) console.debug("[Standings] all sources failed for", leagueId);
}

// Render ESPN standings into a panel — called from toggleStandings
function renderESPNStandingsPanel(panel, entries, sportName){
  const isMLS    = sportName.includes("MLS");
  const isSoccer = isMLS || sportName.includes("Premier")||sportName.includes("Liga")||
                   sportName.includes("Bundesliga")||sportName.includes("Serie")||
                   sportName.includes("Ligue");

  if (isMLS) {
    const confMap = {};
    entries.forEach(e => { const g = e.group||"Conference"; if(!confMap[g]) confMap[g]=[]; confMap[g].push(e); });
    let bodyHtml = "";
    Object.keys(confMap).sort().forEach((conf,ci) => {
      const rows = confMap[conf];
      bodyHtml += `<tr><td colspan="9" style="font-size:.58rem;font-weight:700;color:var(--gold2);padding:.3rem .3rem .1rem;letter-spacing:.04em;text-transform:uppercase;border-top:${ci>0?"1px solid rgba(255,255,255,.08)":"none"}">${conf}</td></tr>`;
      rows.forEach((r,i) => {
        const cls  = i < 3 ? "highlight" : "";
        const mark = i < 9 ? (i < 3 ? "★" : "·") : "";
        const gdn  = Number(r.gd);
        const gdVal = r.gd ? (gdn > 0 ? "+"+r.gd : r.gd) : "—";
        bodyHtml += `<tr class="${cls}">
          <td style="color:var(--smoke);font-size:.6rem;padding-right:.3rem">${r.rank||i+1}</td>
          <td style="max-width:88px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:.7rem">${r.team}</td>
          <td style="text-align:right;font-size:.62rem">${r.played||"—"}</td>
          <td style="text-align:right;font-size:.62rem">${r.wins||"—"}</td>
          <td style="text-align:right;font-size:.62rem;color:var(--smoke)">${r.draws||"—"}</td>
          <td style="text-align:right;font-size:.62rem">${r.losses||"—"}</td>
          <td style="text-align:right;font-size:.62rem;color:var(--smoke)">${gdVal}</td>
          <td style="text-align:right;color:var(--gold2);font-weight:700;font-size:.7rem">${r.pts||"—"}</td>
          <td style="padding-left:.2rem;font-size:.55rem;color:var(--smoke)">${mark}</td>
        </tr>`;
      });
    });
    panel.innerHTML = `<table class="standings-table" style="width:100%">
      <thead><tr>
        <th style="font-size:.58rem">#</th><th>Team</th>
        <th style="text-align:right;font-size:.58rem">P</th>
        <th style="text-align:right;font-size:.58rem">W</th>
        <th style="text-align:right;font-size:.58rem">D</th>
        <th style="text-align:right;font-size:.58rem">L</th>
        <th style="text-align:right;font-size:.58rem">GD</th>
        <th style="text-align:right;font-size:.58rem">Pts</th>
        <th></th>
      </tr></thead>
      <tbody>${bodyHtml}</tbody>
    </table>
    <div style="font-size:.55rem;color:var(--smoke);padding:.2rem .5rem .1rem;display:flex;justify-content:space-between">
      <span>★ Top 3 · Playoff spot (top 9 per conf)</span>
      <span>via ESPN · MLS 2026</span>
    </div>`;
    return;
  }

  const rows = entries.slice(0,12).map((r,i)=>{
    const highlight = i<4 && isSoccer ? "highlight" : i===0 && !isSoccer ? "highlight" : "";
    const streak = r.streak ? `<td style="text-align:right;font-size:.65rem;color:var(--smoke)">${r.streak}</td>` : "";
    const l10    = r.last10 ? `<td style="text-align:right;font-size:.65rem">${r.last10}</td>` : "";
    const gb     = r.gb     ? `<td style="text-align:right;font-size:.65rem;color:var(--smoke)">${r.gb!=="0"?r.gb:"-"}</td>` : "";
    return `<tr class="${highlight}">
      <td style="color:var(--smoke);padding-right:.4rem">${i+1}</td>
      <td style="max-width:100px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${r.team}</td>
      <td style="text-align:right">${r.wins}</td>
      <td style="text-align:right">${r.losses}</td>
      ${isSoccer?`<td style="text-align:right;color:var(--gold2);font-weight:700">${r.pts}</td>`:`<td style="text-align:right;font-size:.7rem">${r.pct}</td>`}
      ${gb}${streak}${l10}
    </tr>`;
  }).join("");
  const extraCols = entries[0]?.streak ? "<th>STK</th>" : "";
  const l10Col    = entries[0]?.last10  ? "<th>L10</th>"  : "";
  const gbCol     = entries[0]?.gb      ? "<th>GB</th>"   : "";
  const rightCol  = isSoccer ? "<th>Pts</th>" : "<th>PCT</th>";
  panel.innerHTML = `<table class="standings-table">
    <thead><tr><th>#</th><th>Team</th><th>W</th><th>L</th>${rightCol}${gbCol}${extraCols}${l10Col}</tr></thead>
    <tbody>${rows}</tbody>
  </table><div style="font-size:.6rem;color:var(--smoke);padding:.25rem .5rem;text-align:right">via ESPN · live</div>`;
}

// ── ATP Tour Live Scores ─────────────────────────────────────────────────────
// Built: May 14, 2026
// Endpoint: https://app.atptour.com/api/v2/gateway/livematches/website?scoringTournamentLevel=tour
// CORS: Access-Control-Allow-Origin: * — fully open, no proxy needed
// Auth: None — public GET endpoint
// Cache: max-age=10s — poll every 10s live, 2min idle
// If-Modified-Since: supported — only transfers data when scores change
// Covers: all active ATP Tour events simultaneously (Masters 1000 + 500 + 250)
// MatchStatus values: "F" = Finished, others (TBD from live test) = In Progress

const ATP_ENDPOINT = 'https://field-relay-nba.jeffunglesbee.workers.dev/atp/livematches/website';
const ATP_REFRESH_LIVE = 15000;   // 15s when live matches active
const ATP_REFRESH_IDLE = 120000;  // 2min when no live matches
let atpLastModified = null;
let atpIntervalId = null;
let atpPollingDisabled = false;  // Relay live — /atp/* route added to field-relay-nba

async function fetchATPLiveScores(){
  if(atpPollingDisabled) return;
  if(!document.querySelector('.sport-section[data-sport="Tennis"]')) {
    return; // No tennis section today — don't poll or reschedule
  }
  try {
    const headers = {'Accept':'application/json'};
    if(atpLastModified) headers['If-Modified-Since'] = atpLastModified;
    const r = await fetch(ATP_ENDPOINT, {headers, signal:AbortSignal.timeout(5000)});

    if(r.status === 304){
      // Scores unchanged — no injection needed, reschedule
    } else if(r.ok){
      atpLastModified = r.headers.get('Last-Modified');
      const json = await r.json();
      const tournaments = json?.Data?.LiveMatchesTournamentsOrdered || [];
      injectATPScores(tournaments);
      const hasLive = tournaments.some(t =>
        (t.LiveMatches||[]).some(m => m.MatchStatus !== 'F')
      );
      if(FIELD_DEBUG) console.debug(`[ATP] ${tournaments.length} tournaments · hasLive=${hasLive}`);
      clearTimeout(atpIntervalId);
      atpIntervalId = setTimeout(fetchATPLiveScores, hasLive ? ATP_REFRESH_LIVE : ATP_REFRESH_IDLE);
      return;
    }
  } catch(e){
    // Any failure (CORS TypeError, AbortError from timeout, network error)
    // means ATP Tour API is unreachable from browser — disable permanently.
    // Browser already logged the CORS error; we just stop retrying.
    atpPollingDisabled = true;
    if(FIELD_DEBUG) console.debug('[ATP] polling disabled:', e.name, e.message);
    return; // exits WITHOUT scheduling setTimeout
  }
  atpIntervalId = setTimeout(fetchATPLiveScores, ATP_REFRESH_IDLE);
}

function buildATPScore(match){
  const p1 = match.PlayerTeam;
  const p2 = match.OpponentTeam;
  const p1n = p1.Player.PlayerLastName || '?';
  const p2n = p2.Player.PlayerLastName || '?';
  const p1s = p1.Seed ? `(${p1.Seed})` : '';
  const p2s = p2.Seed ? `(${p2.Seed})` : '';

  // Build compact set score string — only non-null sets
  const sets = (p1.SetScores||[])
    .map((s,i) => s.SetScore != null ? `${s.SetScore}-${(p2.SetScores[i]||{}).SetScore??'?'}` : null)
    .filter(Boolean);

  const isLive = match.MatchStatus !== 'F';
  const isFinished = match.MatchStatus === 'F';

  // Current game score + server dot during live play
  const gameStr = isLive && p1.GameScore != null
    ? ` ${p1.GameScore}-${p2.GameScore}`
    : '';
  const serverDot = isLive
    ? (match.ServerTeam === 0 ? ' ●' : ' ○')
    : '';

  let scoreChip, situation, playerLine;
  playerLine = `${p1n}${p1s} v ${p2n}${p2s}`;

  if(isFinished && match.WinningPlayerId){
    const winnerName = match.WinningPlayerId === p1.Player.PlayerId ? p1n : p2n;
    scoreChip = `✓ ${winnerName} · ${sets.join(' ')}`;
    situation = `${match.MatchTimeTotal} · Umpire: ${match.UmpireLastName||''}`.trim();
  } else if(isLive){
    scoreChip = `🎾 ${sets.join(' ')}${gameStr}${serverDot}`.trim();
    situation = (match.ExtendedMessage||'').replace(/\r\n/g,' ').replace(/\s+/g,' ').trim();
  } else {
    // Scheduled/upcoming
    scoreChip = `${match.RoundName} · ${match.CourtName}`;
    situation = `${p1n}${p1s} v ${p2n}${p2s}`;
    playerLine = match.RoundName;
  }

  return {playerLine, scoreChip, situation, isLive, isFinished};
}

function injectATPScores(tournaments){
  if(!allData?.sports) return;
  const tennisSections = allData.sports.filter(s => s.sport === 'Tennis');
  if(!tennisSections.length) return;

  // Flatten all matches with their tournament context
  const allMatches = tournaments.flatMap(t =>
    (t.LiveMatches||[]).map(m => ({...m, _tourn:t}))
  );
  if(!allMatches.length) return;

  tennisSections.forEach(sec => {
    (sec.games||[]).forEach(game => {
      if(!game._id) return;
      const gameName = (game.home||'').toLowerCase();

      // Match ATP tournament to FIELD game by keyword — same fuzzy pattern as golf
      const atpMatch = allMatches.find(m => {
        const tWords = (m._tourn.EventTitle||'')
          .toLowerCase().replace(/[^a-z0-9\s]/g,'').split(/\s+/).filter(w=>w.length>3);
        return tWords.some(w => gameName.includes(w));
      });
      if(!atpMatch) return;

      const score = buildATPScore(atpMatch);

      // Update game object for any future re-render
      game.leaderNote = score.scoreChip;
      game._atpLive = score.isLive;
      game._atpSituation = score.situation;
      game._atpPlayerLine = score.playerLine;

      // Update DOM directly — no re-render needed
      const card = document.querySelector(`.game-card[data-gameid="${game._id}"]`);
      if(!card) return;

      // 1. Update event name → player matchup
      const nameEl = card.querySelector('.event-name');
      if(nameEl && score.playerLine) nameEl.textContent = score.playerLine;

      // 2. Update/create score chip (reuse .leader-chip)
      let chip = card.querySelector('.leader-chip');
      if(!chip){
        const matchupDiv = card.querySelector('.matchup');
        if(matchupDiv){ chip = document.createElement('span'); chip.className='leader-chip'; matchupDiv.appendChild(chip); }
      }
      if(chip){
        chip.textContent = score.scoreChip;
        chip.classList.toggle('atp-score-live', score.isLive);
      }

      // 3. Update/create situation line
      if(score.situation){
        let sit = card.querySelector('.atp-situation');
        if(!sit){
          sit = document.createElement('div');
          sit.className = 'atp-situation';
          const leagueRow = card.querySelector('.league-row,.badge-row');
          if(leagueRow) leagueRow.after(sit);
          else card.querySelector('.card-body')?.appendChild(sit);
        }
        if(sit) sit.textContent = score.situation;
      }

      // 4. Live pulsing glow — reuse espn-live class
      card.classList.toggle('espn-live', score.isLive);
    });
  });
}
// ─────────────────────────────────────────────────────────────────────────────

// ── Game Situation Badge — live card context ────────────────────
// Fires during live games: "3rd & 7 at DAL 22" or "Bases loaded, 2 out, 3-2 count"
// Reads ESPN scoreboard situation field (already fetched in fetchESPNScores loop)
const espnSituation = {}; // game_id → situation string

function buildSituationBadge(situation){
  if(!situation) return "";
  const parts = [];
  // NFL
  if(situation.downDistanceText) parts.push(situation.downDistanceText);
  else if(situation.shortDownDistanceText) parts.push(situation.shortDownDistanceText);
  // Baseball
  if(situation.balls!==undefined && situation.strikes!==undefined && situation.outs!==undefined){
    const bases = [];
    if(situation.onFirst) bases.push("1st");
    if(situation.onSecond) bases.push("2nd");
    if(situation.onThird) bases.push("3rd");
    const baseTxt = bases.length ? bases.join("+")+` loaded` : "bases empty";
    parts.push(`${situation.balls}-${situation.strikes} · ${situation.outs} out · ${baseTxt}`);
  }
  // Basketball shot clock
  if(situation.shotClock) parts.push(`SC: ${situation.shotClock}`);
  // Hockey
  if(situation.powerPlay) parts.push("⚡ Power Play");
  if(!parts.length) return "";
  return `<div class="situation-badge">${parts.join(" · ")}</div>`;
}

