const CLAUDE_PROXY_URL = 'https://field-claude-proxy.jeffunglesbee.workers.dev'; // Cloudflare Pages Function proxy

// ── O(1) Newspaper: pre-rendered journalism from relay KV (Layer 2) ──────────
// Patent-safe: relay stores PROSE ONLY (ADR-002 Rule A). No interest level
// values. No classification. Client still runs all drama scoring.
// Layer 3 delta: hash game context before any client AI call — skip if unchanged.
const JOURNALISM_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/journalism/tonight';
// WOW 6 Journalism Quality Gate — live-path route (May 31 2026)
// Routes browser → relay → proxy with all 6 quality layers enforced server-side.
// Returns JQ-graded prose. Browser still scores for debug panel display, but
// the canonical quality enforcement is on the relay (patent posture).
const JOURNALISM_GENERATE_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/journalism/generate';
const JOURNALISM_ENQUEUE_RELAY  = 'https://field-relay-nba.jeffunglesbee.workers.dev/journalism/enqueue';
const JOURNALISM_RESULT_RELAY   = 'https://field-relay-nba.jeffunglesbee.workers.dev/journalism/result';

// iPad-7: model refusal filter. Haiku occasionally emits meta-commentary
// instead of a brief — most often when the prompt's exemplar section
// doesn't match the sport being briefed (e.g. NBA PPG exemplars sent for
// an NHL game with no hockey stats to verify against). Pattern-matches
// the common refusal openings and returns true so the caller can
// suppress + fall back to a factual stub. Patterns from observed cases
// in IPAD-REGRESSION-FIXES.md Bug 7.
function _isModelRefusal(text) {
  if (!text) return false;
  const t = String(text);
  return /I appreciate the detailed framework/i.test(t) ||
         /I need to flag (?:a|the |critical)/i.test(t) ||
         /Which approach do you prefer/i.test(t) ||
         /I cannot write (?:this|the) brief/i.test(t) ||
         /I can write this brief in two ways/i.test(t) ||
         /I (?:do not|don't) have (?:specific|verified) /i.test(t) && /stats|data|facts/i.test(t);
}

// generateJournalismViaRelay — drop-in replacement for direct CLAUDE_PROXY_URL
// calls in the journalism path. Sends prompt + sport hint + briefType. Returns
// the same string shape that callers expect (raw prose), or null on failure.
// Audit fields (score, retries, layers_fired) are logged when FIELD_DEBUG is on
// and stored on window._lastJQAudit for the debug panel.
//
// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #4 -- investigated,
// original premise found NOT to hold, do not re-attempt): the queue's
// finding claimed proof-mode's `return null;` here indistinguishably
// triggers every caller's legacy-direct-proxy fallback, causing "an
// unwanted live call." Traced a real caller (renderSeriesPreviewCard's
// fallback path) end to end: in proof mode, `window.fetch` is globally
// monkey-patched (~L4866) to return `{}` for every request, including the
// legacy proxy's own `fetch(CLAUDE_PROXY_URL, ...)` call -- so that
// fallback also gets intercepted, `data.content` is undefined, `text`
// stays empty, and the caller returns null anyway. No real live API call
// occurs either way. The claimed bug does not exist; do not re-implement
// a fix for it. What DID need fixing (done below): the model-refusal
// branch was the only one of this function's 3 real failure causes with
// no captureFieldError telemetry.
async function generateJournalismViaRelay(prompt, opts = {}) {
  if (_proofMode) return null; // proof mode: no relay calls
  if (!prompt || prompt.length < 10) {
    captureFieldError('journalism:generate:' + (opts.briefType || 'generic'), new Error(`bad prompt: length ${prompt ? prompt.length : 0}`), true);
    return null;
  }
  try {
    const body = {
      prompt,
      sport:     opts.sport     || null,
      briefType: opts.briefType || 'generic',
      max_tokens: opts.max_tokens || 1500,
      // 240 = 80% of the 300-point relay ceiling ("excellence" per the
      // June 24 correction that wired Dimensions 7/10 through and
      // established this as the real current standard). 130 was a
      // pre-rebuild fossil from when the scale topped out at 180, never
      // updated when the ceiling moved (CC-CMD-2026-07-09-jq-threshold-
      // 240-migration).
      scoreThreshold: opts.scoreThreshold || 240,
      game:           opts.game           || null,
      matchupNote:    opts.matchupNote    || null,
    };
    const r = await fetch(JOURNALISM_GENERATE_RELAY, {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify(body),
      signal: AbortSignal.timeout(opts.timeout || 25000), // quality chain runs 6+ LLM retries; 25s default
    });
    if (!r.ok) {
      if (FIELD_DEBUG) console.warn('[JQ Gate] relay returned', r.status);
      captureFieldError('journalism:generate:' + (opts.briefType || 'generic'), new Error('HTTP ' + r.status), false);
      return null;
    }
    const data = await r.json();
    if (!data || !data.text) {
      captureFieldError('journalism:generate:' + (opts.briefType || 'generic'), new Error('relay 200 but no usable data.text'), false);
      return null;
    }
    // iPad-7: model refusal filter (CRITICAL user-facing fix). If Haiku
    // refuses to fabricate (e.g. NHL prompt sent with NBA-shaped exemplars),
    // the raw meta-commentary used to reach the user as the "brief." Detect
    // refusal patterns and suppress — caller falls back to a factual stub.
    if (_isModelRefusal(data.text)) {
      if (FIELD_DEBUG) console.warn('[JQ Gate] model refusal detected — suppressing', data.text.slice(0, 80));
      // 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #4): this was
      // the only one of this function's 3 real failure causes (HTTP error,
      // missing data.text, model refusal) with no captureFieldError
      // telemetry -- despite its own header comment flagging model refusal
      // as a "CRITICAL user-facing fix." Closing that asymmetry: the Health
      // Panel can now show how often Haiku refuses to write a brief, a real
      // content-quality signal that was previously only visible in a live
      // FIELD_DEBUG console session.
      captureFieldError('journalism:generate:' + (opts.briefType || 'generic'), new Error('model refusal: ' + data.text.slice(0, 80)), false);
      return null;
    }
    // Persist audit for debug panel
    window._lastJQAudit = {
      score: data.score,
      retries: data.retries,
      layers_fired: data.layers_fired,
      ms: data.ms,
      briefType: data.briefType,
      initial_cliches: data.initial_cliches,
      final_cliches:   data.final_cliches,
      initial_cross_sport: data.initial_cross_sport,
      final_cross_sport:   data.final_cross_sport,
    };
    if (FIELD_DEBUG) console.debug('[JQ Gate]', data.briefType, 'score:', data.score, 'retries:', data.retries, 'layers:', data.layers_fired);
    return stripPromptLeaks(data.text);
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[JQ Gate] error:', e.message);
    captureFieldError('journalism:generate:' + (opts.briefType || 'generic'), e, false);
    return null;
  }
}

let _journalismCache = null; // { brief, generatedAt, contextHash }
let _journalismFetchedAt = 0;
const JOURNALISM_CLIENT_TTL = 5 * 60 * 1000; // 5 min client cache

async function fetchPrerenderedJournalism() {
  const now = Date.now();
  if (_journalismCache && (now - _journalismFetchedAt) < JOURNALISM_CLIENT_TTL) {
    return _journalismCache;
  }
  try {
    // Layer 4: Accept-Encoding hints Cloudflare to serve Brotli-compressed response
    const r = await fetch(JOURNALISM_RELAY, {
      headers: {'Accept-Encoding': 'br, gzip'},
      signal: AbortSignal.timeout(4000),
    });
    if (!r.ok) { captureFieldError('journalism:prerendered-fetch', new Error('HTTP ' + r.status), true); return null; }
    const data = await r.json();
    if (!data?.brief) { captureFieldError('journalism:prerendered-fetch', new Error('relay 200 but no usable data.brief'), true); return null; }
    _journalismCache = data;
    _journalismFetchedAt = now;
    if (FIELD_DEBUG) console.log(`[O(1)] Relay journalism loaded — age: ${r.headers.get('X-Journalism-Age')||'?'} cycle: ${r.headers.get('X-Journalism-Cycle')||'?'}`);
    return data;
  } catch(e) {
    if (FIELD_DEBUG) console.log('[O(1)] Relay journalism unavailable — falling back to client AI');
    captureFieldError('journalism:prerendered-fetch', e, true);
    return null;
  }
}

// Layer 3: delta hash — avoid client AI call if game context unchanged
// Returns a fast djb2 hash of game IDs + scores to detect meaningful changes
function buildJournalismContextHash(sections) {
  const ctx = (sections||[]).flatMap(s=>(s.games||[]).map(g=>`${g._id||g.home+g.away}:${g._espnScore||''}`)).join('|');
  return ctx.split('').reduce((h,c)=>(Math.imul(31,h)+c.charCodeAt(0))|0,0).toString(16);
}
