// ── PM-20: Source-Tagged Score Store + Confidence Layer (June 3 2026) ────────
// _scoresBySource keeps independent witnesses separate so two sources polling
// the same game can verify each other instead of last-writer-wins overwriting.
// Spec: Drive 15c5euHkvuFnrF63my0rsNJ6QVkjHN06TdphwoYt1_gU
// Shape: _scoresBySource["Home|Away"] = { espn: {...,ts}, apisports: {...,ts} }
// Sources may join later: nhlapi, mlbstats, squiggle.
let _scoresBySource = {};

// findScore(g) — confidence-aware lookup. Returns shape-compatible with the
// previous findESPNScore (so existing 20 callers continue to work) PLUS additive
// fields: confidence ('verified' | 'mismatch' | 'single'), sources (array),
// mismatch detail when sources disagree.
//
// ── PM-24: Read-time witness aggregation (June 5 2026) ───────────────────────
// PM-20 left 'verified' structurally unreachable: ESPN writes under "New York
// Knicks|San Antonio Spurs" while api-sports writes under "Knicks|Spurs" — two
// entries in _scoresBySource for the same game, each with a single witness.
// findScore previously took the FIRST fuzzy-matched entry and returned 'single'.
//
// PM-24 fix: gather ALL fuzzy-matched entries, UNION their witnesses (freshest
// per source), THEN evaluate confidence. The 'verified' state becomes reachable
// without refactoring the 20+ writers that route through _scoresBySource[key].
// Write-side canonicalization can come later — this unblocks the green dot now.
function findScore(game) {
  const home = (game.home || '').toLowerCase();
  const away = (game.away || '').toLowerCase();
  // Sport guard — preserved from findESPNScore — prevents city-name cross-contamination
  const sc = typeof classifySport === 'function' ? classifySport(game, null) : {};
  const gameSoccer = sc.isSoccer;
  // PM-24: aggregate witnesses across all fuzzy-matched keys
  let espnWitness = null, apiWitness = null;
  const matchedKeys = [];
  for (const [key, entry] of Object.entries(_scoresBySource)) {
    if (!entry) continue;
    const [hn, an] = key.split('|').map(s => s.toLowerCase());
    const matches = (espnTeamMatch(hn, home) && espnTeamMatch(an, away)) ||
                    (espnTeamMatch(hn, away) && espnTeamMatch(an, home));
    if (!matches) continue;
    // Same periodPrefix sport-guard as findESPNScore — apply to whichever source we use
    const probe = entry.espn || entry.apisports;
    if (!probe) continue;
    const pp = probe.periodPrefix || '';
    if (gameSoccer  && (pp === 'Q' || pp === 'H' || pp === 'P' || pp === 'T')) continue;
    if (!gameSoccer && (pp === "'" || pp === '1H' || pp === '2H')) continue;
    matchedKeys.push(key);
    // Take the freshest witness per source across all matched entries
    if (entry.espn && (!espnWitness || (entry.espn.ts || 0) > (espnWitness.ts || 0))) {
      espnWitness = entry.espn;
    }
    if (entry.apisports && (!apiWitness || (entry.apisports.ts || 0) > (apiWitness.ts || 0))) {
      apiWitness = entry.apisports;
    }
  }
  if (!espnWitness && !apiWitness) return null;
  const present = [];
  if (espnWitness) present.push('espn');
  if (apiWitness)  present.push('apisports');
  if (espnWitness && apiWitness) {
    const agree = espnWitness.homeScore === apiWitness.homeScore &&
                  espnWitness.awayScore === apiWitness.awayScore;
    const fresh = (espnWitness.ts || 0) > (apiWitness.ts || 0) ? espnWitness : apiWitness;
    return {
      ...fresh,
      sources: present,
      confidence: agree ? 'verified' : 'mismatch',
      mismatch: agree ? null : {
        espn:      { h: espnWitness.homeScore, a: espnWitness.awayScore },
        apisports: { h: apiWitness.homeScore,  a: apiWitness.awayScore },
      },
      _pm24_matched: matchedKeys, // diagnostic: which keys were merged (verify in console)
    };
  }
  const only = espnWitness || apiWitness;
  return {
    ...only,
    sources: present,
    confidence: 'single',
    mismatch: null,
    _pm24_matched: matchedKeys,
  };
}

