async function fetchV2Games(sport, date) {
  try {
    const d = date || new Date().toISOString().slice(0, 10);
    const r = await fetch(`${V2_RELAY_BASE}/v2/games?sport=${sport}&date=${d}`,
      { signal: AbortSignal.timeout(6000) });
    if (!r.ok) {
      // CC-CMD-2026-07-16-frozen-card-duplicate-status: this failure was
      // completely silent -- confirmed live via a Health Panel screenshot
      // showing real 403s from this same relay base (scores:fetch-nba-relay)
      // within ~25 min of a WNBA card freezing at its last live state.
      // A !r.ok here means espnScores never gets refreshed for this sport
      // this poll cycle -- the card just keeps re-rendering its last known
      // (possibly pre-final) state until a later poll succeeds. Reporting
      // it so a future incident is diagnosable instead of invisible.
      captureFieldError('scores:fetch-v2-games', new Error(`${sport} ${d}: HTTP ${r.status}`), true);
      return [];
    }
    const data = await r.json();
    return data?.games || [];
  } catch(e) {
    captureFieldError('scores:fetch-v2-games', e, true);
    if (FIELD_DEBUG) console.warn('[V2] fetchV2Games failed:', sport, e.message);
    return [];
  }
}
// ═══════════════════════════════════════════════════════════════════════════
// GameSocket — WebSocket client for per-game live state (WOW 1, May 31 2026)
// ═══════════════════════════════════════════════════════════════════════════
// Connects to the per-game DurableObject at /ws/game/:sport/:gameId.
// On receiving 'facts' messages, calls the onFacts callback with raw fields.
// On error/close, auto-disconnects and surfaces .available = false so the
// polling fallback (existing fetchESPNScores / fetchV2Games loop) continues
// to drive updates. DUAL-MODE design — polling is the safety net.
//
// ADR-002: this client receives raw facts only. Drama computation, badge
// rendering, and CRUNCH TIME detection all stay in the browser as before.
// The socket is a faster delivery channel for the same facts that polling
// would have returned. No new intelligence is introduced.
//
// Usage:
//   const gs = new GameSocket('nba', '12345', factsFn);
//   gs.connect();
//   // ...later: gs.signalCrunch({homeScore:101, awayScore:99, period:4, ...});
//   // ...or:    gs.disconnect();
// ═══════════════════════════════════════════════════════════════════════════
class GameSocket {
  constructor(sport, gameId, onFacts) {
    this.sport     = sport;
    this.gameId    = String(gameId);
    this.onFacts   = typeof onFacts === 'function' ? onFacts : (()=>{});
    this.ws        = null;
    this.available = false;
    this._retryMs  = 5000;
    this._closed   = false;
    this._pingT    = null;
  }
  static wsBase() {
    // Convert https://...workers.dev → wss://...workers.dev
    return V2_RELAY_BASE.replace(/^https:/, 'wss:').replace(/^http:/, 'ws:');
  }
  connect() {
    if (this._closed) return;
    if (this.ws && (this.ws.readyState === WebSocket.OPEN || this.ws.readyState === WebSocket.CONNECTING)) return;
    try {
      const url = `${GameSocket.wsBase()}/ws/game/${encodeURIComponent(this.sport)}/${encodeURIComponent(this.gameId)}`;
      this.ws = new WebSocket(url);
    } catch(e) {
      this.available = false;
      return;
    }
    this.ws.onopen = () => {
      this.available = true;
      try { this.ws.send(JSON.stringify({ type:'hello', sport:this.sport, gameId:this.gameId })); } catch(_){}
      // Light keepalive every 45s.
      this._pingT = setInterval(() => {
        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
          try { this.ws.send(JSON.stringify({ type:'ping' })); } catch(_){}
        }
      }, 45000);
    };
    this.ws.onmessage = (ev) => {
      let msg = null;
      try { msg = JSON.parse(ev.data); } catch(_){}
      if (!msg) return;
      if (msg.type === 'facts') {
        try { this.onFacts(msg); } catch(_){}
        // PM-27: record freshness timestamp + emit field:ws_fresh for WS Pulse subscriber
        try {
          const _wsKey = `${this.sport}:${this.gameId}`;
          if (typeof _lastWSMessageTime !== 'undefined') _lastWSMessageTime.set(_wsKey, Date.now());
          if (typeof fieldEvents !== 'undefined') {
            fieldEvents.dispatchEvent(new CustomEvent('field:ws_fresh', { detail: {
              type: 'field:ws_fresh', target: _wsKey, source: 'ws',
              reason: 'message_received', at: Date.now(),
              payload: { gameId: this.gameId, sport: this.sport }
            }}));
          }
        } catch(_) {}
      }
    };
    const cleanup = () => {
      this.available = false;
      if (this._pingT) { clearInterval(this._pingT); this._pingT = null; }
      if (!this._closed) {
        // Reconnect with backoff; polling fallback covers the gap.
        setTimeout(() => this.connect(), this._retryMs);
      }
    };
    this.ws.onclose = cleanup;
    this.ws.onerror = cleanup;
  }
  disconnect() {
    this._closed = true;
    this.available = false;
    if (this._pingT) { clearInterval(this._pingT); this._pingT = null; }
    if (this.ws) { try { this.ws.close(); } catch(_){} this.ws = null; }
  }
  // Pin this game for backgrounded push delivery via the DO's subscriber list.
  pin(subscription, prefs) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      try { this.ws.send(JSON.stringify({ type:'pin', subscription, prefs })); } catch(_){}
    }
  }
  unpin(endpoint) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      try { this.ws.send(JSON.stringify({ type:'unpin', endpoint })); } catch(_){}
    }
  }
  // Signal client-side-detected CRUNCH TIME. The DO dedupes per (gameId, period)
  // and fans out Web Push to pinned subscribers. RUWT compliance: this browser
  // already made the named-condition determination; the DO only delivers.
  signalCrunch(detail) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      try { this.ws.send(JSON.stringify({ type:'signal-crunch', ...detail })); return true; } catch(_){}
    }
    // WebSocket not open — use HTTP signal endpoint as fallback.
    try {
      fetch(`${V2_RELAY_BASE}/signal/crunch/${encodeURIComponent(this.sport)}/${encodeURIComponent(this.gameId)}`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(detail),
        keepalive: true,
      }).catch((e_)=>{ captureFieldError('ws:signal-crunch-fetch', e_, true); });
      return true;
    } catch(_e) { captureFieldError('ws:signal-crunch-fallback', _e, true); return false; }
  }
}
// Map of active GameSocket instances, keyed by `${sport}:${gameId}`.
const _gameSockets = new Map();
function ensureGameSocket(sport, gameId, onFacts) {
  if (!sport || !gameId) return null;
  const key = `${sport}:${gameId}`;
  let gs = _gameSockets.get(key);
  if (!gs) {
    // ── S0 integration: default onFacts dispatches through the Event Bus ──
    // If the caller doesn't provide an explicit handler, route facts into
    // emitScoreEvent so all bus subscribers (Night Owl, lead burst, etc.)
    // react to WebSocket-delivered facts the same way they react to polling.
    // Callers can pass their own onFacts to override (e.g. for direct card
    // re-render); they should still call emitScoreEvent themselves to keep
    // the bus consistent.
    const handler = (typeof onFacts === 'function') ? onFacts : (msg) => {
      try {
        if (typeof emitScoreEvent === 'function') {
          emitScoreEvent({
            gameId:      msg.gameId || gameId,
            sport:       msg.sport || sport,
            homeScore:   msg.homeScore,
            awayScore:   msg.awayScore,
            period:      msg.period,
            periodLabel: msg.periodLabel || '',
            clock:       msg.clock || '',
            state:       msg.state || 'in',
            isFinal:     msg.state === 'final' || msg.state === 'post',
            source:      'ws',
            // FIXED 2026-07-03: real, confirmed gap found by checking
            // whether today's relay-side G3/G4/G5/G6 fix actually
            // reaches any real client surface -- it didn't. This is the
            // only real caller of ensureGameSocket, relying on this
            // default handler, which silently dropped these fields even
            // though the relay now sends them and msg already has them.
            situation:   msg.situation || null,
            matchEvents: msg.matchEvents || null,
            linescores:  msg.linescores || null,
            homeAbbr:    msg.homeAbbr || null,
            awayAbbr:    msg.awayAbbr || null,
          });
        }
      } catch(_) { /* never throw from socket handler */ }
    };
    gs = new GameSocket(sport, gameId, handler);
    _gameSockets.set(key, gs);
    gs.connect();
  }
  return gs;
}
function dropGameSocket(sport, gameId) {
  const key = `${sport}:${gameId}`;
  const gs = _gameSockets.get(key);
  if (gs) { gs.disconnect(); _gameSockets.delete(key); }
}

function mapV2ToESPN(fg) {
  if (!fg?.id) return null;
  // api-sports.io sometimes returns state:"pre" even when a game is live
  // (confirmed NBA Finals G2 2026-06-06: state="pre", clock="10:12", periodNum=2).
  // Detect live state from clock/periodNum presence when state is wrong.
  //
  // CC-CMD-2026-07-05-pickem-cfl-mlb-gaps TASK 1: this heuristic had the
  // opposite false-positive for MLB, confirmed live via direct relay fetch
  // (/v2/games?sport=mlb) -- a freshly-scheduled, genuinely pregame game
  // returns state:"pre", periodNum:1, clock:"0:00" (single leading zero,
  // not "00:00"), home/away score both 0 (not null). The old string-equality
  // clock check (`fg.clock !== '00:00'`) let "0:00" through as a "live"
  // clock, and separately `score != null` treated a valid 0 score as
  // evidence of live play -- either alone flipped every pregame MLB game to
  // state:"in" the moment the relay started tracking it, which excluded it
  // from getCardCircadian's PREVIEW gate (used by the Pick 'em list) well
  // before the game actually started. Parse the clock to total seconds so
  // any zero-padding variant reads as "no elapsed time", and require a real
  // (>0) score alongside periodNum -- both still correctly catch the
  // original NBA Finals G2 case (clock "10:12" -> 622s > 0).
  const clockSeconds = (() => {
    if (!fg.clock) return null;
    const parts = String(fg.clock).split(':').map(Number);
    return parts.some(isNaN) ? null : parts.reduce((acc, v) => acc * 60 + v, 0);
  })();
  const hasLiveClock = clockSeconds != null && clockSeconds > 0;
  const hasLiveScore = (fg.home?.score ?? 0) > 0 || (fg.away?.score ?? 0) > 0;
  const isActuallyLive = fg.state === 'live' ||
    (fg.state !== 'final' && (hasLiveClock || (fg.periodNum != null && fg.periodNum > 0 && hasLiveScore)));
  const state = fg.state==='final' ? 'post' : isActuallyLive ? 'in' : 'pre';
  // Guard: api-sports.io sometimes returns null scores for final games.
  // When both scores are null on a final, preserve previous values via merge guard
  // downstream. Use null (not 0) so merge guard can detect the gap.
  const homeScore = fg.home?.score ?? (state==='post' ? null : 0);
  const awayScore = fg.away?.score ?? (state==='post' ? null : 0);
  return {
    state,
    homeScore: homeScore ?? 0, awayScore: awayScore ?? 0,
    _scoresNull: state==='post' && fg.home?.score==null && fg.away?.score==null,
    home: fg.home?.name||'', away: fg.away?.name||'',
    homeName: fg.home?.name||'', awayName: fg.away?.name||'',
    homeWinning: (fg.home?.score??0)>(fg.away?.score??0),
    clock: fg.clock||'', detail: fg.periodLabel||'', period: fg.periodNum||0,
    periodPrefix: V2_PERIOD_PREFIX[fg.sport]||'',
    situation: fg.situation||null,
    _gameId: fg.id, _sport: fg.sport, source:'v2',
    // Linescores from relay adapter (quarter_1..4 for NBA, inning 1..9 for MLB)
    homeLinescores: fg.linescores?.home || [],
    awayLinescores: fg.linescores?.away || [],
    // WP and leaders start null; filled by Savant (MLB), statistics endpoint (NBA/NHL), or NHL relay
    espnEventId: null, wp: null, wp_prev: null,
    homeLeader: null, awayLeader: null,
    bsdEventId: fg.bsdEventId || null,  // BSD event ID — activates pitch/momentum when set
    // AP/CFP poll rank (CC-CMD-2026-07-15-cfb-section-injection). Safe no-op
    // until the relay's own companion fix (CC-CMD-2026-07-15-cfb-
    // curatedrank-relay, separate repo) forwards fg.home/away.curatedRank --
    // ?? null either way. isFeaturedTierGame (CC-CMD-2026-07-15-featured-
    // tier-overflow) already reads these defensively.
    homeCuratedRank: fg.home?.curatedRank ?? null,
    awayCuratedRank: fg.away?.curatedRank ?? null,
    start_time: fg.start || '',
    round: fg.round || '',
    series: fg.series || null,
  };
}

// ── V2 standalone poll loop (Phase 2, 2026-05-29) ────────────────────────
// Replaces ESPN polling for all FIELD_V2_SOURCES-enabled sports.
// Runs independently of fetchESPNScores. Each sport polled in parallel.
// Interval: 30s while any live game detected, 60s otherwise.
let _v2PollTimeout = null;
let _v2PollCycle   = 0;
let _wcSectionInjected = false; // true once FIFA section added to allData.sports from V2
const _wcBriefsFetched = new Set(); // dedup: game IDs we've already fetched post-match briefs for
const _nbaBriefsFetched = new Set(); // dedup: NBA game IDs we've already fetched post-game briefs for
const _nhlBriefsFetched = new Set(); // dedup: NHL game IDs we've already fetched post-game briefs for

// renderWCBracketImpact — fetches bracket impact from D1 and renders
// a compact delta table adjacent to a finished WC game card.
// Called fire-and-forget from the V2 WC poll loop after brief is fetched.
// Requires relay CC-CMD-2026-06-24-bracket-impact-pre-snapshot deployed.
async function renderWCBracketImpact(gameId, home, away, relayBase) {
  try {
    const today = new Date().toLocaleDateString('en-CA', {timeZone: 'America/New_York'});
    const key   = `${home}_${away}_${today}`.replace(/\s+/g, '_').slice(0, 120);
    const r = await fetch(
      `${relayBase}/archive/bracket-replay?triggered_by=${encodeURIComponent(key)}`,
      { signal: AbortSignal.timeout(2500) }
    );
    if (!r.ok) return;
    const d = await r.json();
    const rows = d.rows || [];
    if (rows.length < 2) return;  // need pre + post rows

    // Build impact: rows ordered by team, created_at — first = before, second = after
    const byTeam = {};
    for (const row of rows) {
      const t = row.team;
      if (!byTeam[t]) {
        byTeam[t] = { before: row.champion_prob, r32Before: row.r32_prob };
      } else {
        byTeam[t].after    = row.champion_prob;
        byTeam[t].r32After = row.r32_prob;
      }
    }
    const entries = Object.entries(byTeam)
      .filter(([, d]) => d.before != null && d.after != null
                      && Math.abs(d.after - d.before) >= 0.002)
      .map(([team, d]) => {
        const change = Math.round((d.after - d.before) * 1000) / 1000;
        const pct    = Math.round(Math.abs(change) * 100 * 10) / 10;
        const arrow  = change > 0 ? '↑' : '↓';
        const stB    = d.r32Before >= 0.98 ? 'QUALIFIED' : d.r32Before <= 0.02 ? 'ELIMINATED' : `P(${Math.round(d.r32Before*100)}%)`;
        const stA    = d.r32After  >= 0.98 ? 'QUALIFIED' : d.r32After  <= 0.02 ? 'ELIMINATED' : `P(${Math.round(d.r32After *100)}%)`;
        const state  = stB !== stA ? `${stB} → ${stA}` : stA;
        return { team, state, arrow, pct, change };
      })
      .sort((a, b) => Math.abs(b.change) - Math.abs(a.change))
      .slice(0, 5);
    if (!entries.length) return;

    // Find the game card in the DOM
    const gameCard = document.querySelector(`[data-gameid="${CSS.escape(gameId)}"]`);
    if (!gameCard) return;
    if (gameCard.nextElementSibling?.classList.contains('wc-bracket-impact-card')) return;

    const card = document.createElement('div');
    card.className = 'wc-bracket-impact-card';
    card.innerHTML =
      '<div class="wc-impact-label">BRACKET IMPACT</div>'
      + entries.map(e =>
          `<div class="wc-impact-row">`
          + `<span class="wc-impact-team">${e.team}</span>`
          + `<span class="wc-impact-state">${e.state}</span>`
          + `<span class="wc-impact-delta ${e.change > 0 ? 'pos' : 'neg'}">${e.arrow}${e.pct}%</span>`
          + `</div>`
        ).join('');
    gameCard.insertAdjacentElement('afterend', card);
  } catch (e) { captureFieldError('archive:bracket-impact', e, false); /* non-blocking */ }
}

// V2 in-game leaders (fetchV2Leaders) — REMOVED 2026-06-30. API-Sports.io
// basketball-tier subscription lapsed (do-not-renew, June 26 2026 decision).
// Called the relay's /apisports/basketball/games/statistics/players passthrough,
// which no longer exists. homeLeader/awayLeader fields remain in espnScores
// shape (always null now) — downstream renderers already null-safe by design.

// ── Generic V2 sport section injection (CC-CMD-2026-07-15-cfb-section-
// injection) — mirrors the FIFA World Cup injection pattern below, but
// genuinely generic (sportKey/sectionLabel params) so a future CBB adapter
// can reuse it without rebuilding this. V2 polling fetches cfb games into
// espnScores, but nothing previously turned them into allData.sports card
// entries -- confirmed only WC26 had a dedicated injection block; CFB/NFL
// games sat in espnScores forever, never rendered by renderAll(). Unlike
// WC26, there is no pre-existing hardcoded fallback schedule for CFB to
// dedup against (confirmed via grep -- no sections.push for CFB anywhere),
// so this is simpler: first sighting always creates a fresh section.
const _v2SectionInjected = {}; // sportKey -> true once its section exists in allData.sports
function injectV2SportSection(sportKey, sectionLabel) {
  try {
    const keys = Object.keys(espnScores).filter(k => espnScores[k]?._sport === sportKey);
    if (!keys.length) return;
    const games = keys.map(k => {
      const e = espnScores[k];
      const [home, away] = k.split('|');
      return {
        home, away, _id: e._gameId || e.espnEventId || k,
        league: sectionLabel, _sport: sectionLabel, _section: sectionLabel,
        start_time: e.start_time || '',
        state: e.state || 'pre',
        confirmed: true,
        round: e.round || '',
        // Threaded from mapV2ToESPN (CC-CMD-2026-07-15-cfb-section-
        // injection); real values arrive once the relay's companion fix
        // (CC-CMD-2026-07-15-cfb-curatedrank-relay) lands. isFeaturedTierGame
        // (CC-CMD-2026-07-15-featured-tier-overflow) reads these directly.
        homeCuratedRank: e.homeCuratedRank ?? null,
        awayCuratedRank: e.awayCuratedRank ?? null,
      };
    });
    const existing = allData?.sports?.find(s => s.section === sectionLabel || s.sport === sectionLabel);
    if (existing) {
      // Subsequent polls: merge V2 state into the existing section, same
      // overlay pattern the FIFA block below uses (V2 wins per-field, keyed
      // by lowercased home|away).
      const byKey = new Map();
      (existing.games || []).forEach(g => byKey.set(`${(g.home||'').toLowerCase()}|${(g.away||'').toLowerCase()}`, g));
      games.forEach(v => {
        const k = `${(v.home||'').toLowerCase()}|${(v.away||'').toLowerCase()}`;
        byKey.set(k, { ...byKey.get(k), ...v });
      });
      existing.games = Array.from(byKey.values());
      _v2SectionInjected[sportKey] = true;
    } else if (allData?.sports) {
      allData.sports.push({ sport: sectionLabel, section: sectionLabel, games });
      buildFilters(allData.sports);
      _v2SectionInjected[sportKey] = true;
    }
  } catch (_e) { captureFieldError(`v2-section-inject:${sportKey}`, _e, true); }
}

async function fetchV2AllScores() {
  _v2PollCycle++;
  // Date strategy: US evening games span two UTC dates.
  // - 7pm ET games start at 23:00 UTC on the ET date (e.g. Jun 5 UTC)
  // - 8:30pm ET games start at 00:30 UTC the next day (e.g. Jun 6 UTC)
  // Solution: fieldDatesToQuery() handles this DST-correctly via Intl.DateTimeFormat.
  // No hardcoded UTC offsets — works for both EDT (-4) and EST (-5).
  const _dtq = fieldDatesToQuery();
  const datesToQuery = _dtq.dates;
  const etDate = _dtq.etDate;
  const date = _dtq.utcDate; // used by stale-final guard and anyLive check
  const enabled = Object.entries(FIELD_V2_SOURCES).filter(([,v]) => v).map(([k]) => k);
  if (!enabled.length) return scheduleV2Poll(60000);

  let anyLive = false;
  let _roundDataNewThisPoll = false;
  // Query each sport across all dates (ET + UTC when they differ) to catch
  // full US evening schedule: 7pm ET games on ET date, 8:30pm ET on UTC date.
  await Promise.allSettled(enabled.flatMap(sport =>
    datesToQuery.map(async queryDate => {
    try {
      const games = await fetchV2Games(sport, queryDate);
      games.forEach(fg => {
        if (!fg?.home?.name || !fg?.away?.name) return;
        // Guard: skip final games that are genuinely from a prior day.
        // A game is valid if its UTC start date matches either the ET query date
        // or the UTC query date — covering the full US evening window.
        // e.g. BAL@TOR starts 23:07 UTC Jun 5 (ET date Jun 5, UTC date Jun 5),
        // queried on Jun 6 UTC: gameUtcDate=Jun5, etDate=Jun5 → valid, keep it.
        if (fg.state === 'final' && fg.start) {
          const gameUtcDate = new Date(fg.start).toISOString().slice(0, 10);
          if (gameUtcDate !== date && gameUtcDate !== etDate) return;
        }
        const key = `${fg.home.name}|${fg.away.name}`;
        const prev = espnScores[key];
        const v2Entry = mapV2ToESPN(fg);

        // Guard: never overwrite a known live or final score with a pre-game entry.
        // V2 returns both today's finished game AND tomorrow's scheduled game for the
        // same teams in the same response. forEach processes them sequentially and the
        // pre-game can overwrite the final. e.g. CIN@STL final (10-3) then CIN@STL
        // pre (null scores) both appear in the Jun 6 UTC response.
        if (v2Entry.state === 'pre' && prev && (prev.state === 'in' || prev.state === 'post')) {
          // Skip — don't overwrite a real score with tomorrow's pre-game placeholder
          return;
        }

        // Layer 1 null-score guard (June 15 2026): when V2 returns a final game
        // with null scores AND there's no previous espnScores entry to preserve,
        // skip the write entirely. Without this, the card renders a false 0-0.
        // The score will be backfilled by hydrateEspnScoresFromFinals() (localStorage
        // or static schedule fallback) if available, or the card simply renders
        // without a score overlay — which is correct for historical games.
        if (v2Entry._scoresNull && !prev) {
          if (FIELD_DEBUG) console.warn('[V2] null-score final skipped (no prev):', key);
          return;
        }

        // Merge guard: V2 provides scores/period/clock; preserve richer fields
        // already set by NHL relay, Savant, or statistics endpoint.
        // homeLinescores: prefer V2 if it has data (relay now sends quarter scores);
        //   fall back to prev only when V2 has none yet (e.g. game not started).
        espnScores[key] = {
          ...v2Entry,
          // Score merge guard: when V2 returns null scores on a final game,
          // preserve previous scores rather than showing 0-0
          homeScore: (v2Entry._scoresNull && prev?.homeScore) ? prev.homeScore : v2Entry.homeScore,
          awayScore: (v2Entry._scoresNull && prev?.awayScore) ? prev.awayScore : v2Entry.awayScore,
          homeLeader:     prev?.homeLeader     ?? null,
          awayLeader:     prev?.awayLeader     ?? null,
          wp:             prev?.wp             ?? null,
          wp_prev:        prev?.wp_prev        ?? null,
          homeLinescores: v2Entry.homeLinescores.length ? v2Entry.homeLinescores : (prev?.homeLinescores || []),
          awayLinescores: v2Entry.awayLinescores.length ? v2Entry.awayLinescores : (prev?.awayLinescores || []),
        };
        espnScoreTs[key] = Date.now();
        // PM-20 Step 3: ALSO write to source-tagged store with apisports
        // attribution. Independent witness for findScore() cross-source
        // verification with the ESPN-native writer.
        _scoresBySource[key] = _scoresBySource[key] || {};
        _scoresBySource[key].apisports = {
          state:        v2Entry.state,
          period:       v2Entry.period,
          clock:        v2Entry.clock,
          detail:       v2Entry.detail,
          homeScore:    (v2Entry._scoresNull && prev?.homeScore) ? prev.homeScore : v2Entry.homeScore,
          awayScore:    (v2Entry._scoresNull && prev?.awayScore) ? prev.awayScore : v2Entry.awayScore,
          homeName:     v2Entry.homeName,
          awayName:     v2Entry.awayName,
          home:         v2Entry.home,
          away:         v2Entry.away,
          periodPrefix: v2Entry.periodPrefix,
          ts:           Date.now(),
        };
        if (fg.state === 'live' || v2Entry.state === 'in') anyLive = true;

        // ── Round/Series/_gameId propagation to allData.sports game objects ─────
        // V2 relay populates fg.round (from postseason_games) and fg.series
        // (from ESPN /soccer/xg for two-legged ties). Propagate to allData.sports
        // so the card template's buildRoundBadge(g) can display them.
        // Also propagate _gameId so injectDebriefCards uses the ESPN event ID as
        // contextId instead of the internal g{n} fallback for hardcoded-schedule
        // sports (MLB, NHL, etc.). Without this, /context/game/g18 is fetched
        // instead of /context/game/espn:401816164 — returning a pre-game brief
        // even after the game is final.
        if (fg.round || fg.series || v2Entry._gameId) {
          const _rGame = (allData?.sports || []).flatMap(s => s.games || []).find(g => `${g.home}|${g.away}` === key);
          if (_rGame) {
            if (fg.round && _rGame.round !== fg.round) { _rGame.round = fg.round; _roundDataNewThisPoll = true; }
            if (fg.series) _rGame.series = fg.series;
            if (v2Entry._gameId && !_rGame._gameId) {
              _rGame._gameId = v2Entry._gameId;
              // If the card was already injected with the wrong contextId (g{n}),
              // clear the stamp so injectDebriefCards re-fetches with the correct one.
              const _dCard = document.querySelector(`.game-card[data-gameid="${_rGame._id}"][data-debrief-injected]`);
              if (_dCard) { _dCard.removeAttribute('data-debrief-injected'); setTimeout(() => injectDebriefCards().catch(() => {}), 0); }
            }
          }
        }

        // ── Soccer/WC live-stats persistence (P6A, June 19 2026) ─────────────
        // V2 clears situation to null when a soccer match goes final, so the
        // Night Owl recap prompt gets zero shot/possession data and hallucinates
        // stats. Every poll cycle while the game is live, mirror the relay's
        // raw situation object to localStorage under a stable team-pair key.
        // The last live poll before final wins, leaving the closing stats
        // intact even after V2 nulls the situation.
        //
        // Persist shape verbatim (Rule 60 — relay owns the contract). No
        // field renaming, no normalisation. Recap consumer reads back the
        // same shape the live UI saw. wc-situation-probe (2026-06-19) showed
        // every final wc26 game returns situation=null; no live game was in
        // flight at probe time, so the exact key set is captured live by
        // whatever the relay emits — see outbox/wc-situation-result-*.txt.
        if (V2_PERIOD_PREFIX[sport] === "'" &&  // soccer family (wc26/mls/epl/etc.)
            v2Entry.state !== 'post' &&
            fg.situation &&
            typeof fg.situation === 'object' &&
            Object.keys(fg.situation).length > 0) {
          try {
            const stash = {
              situation: fg.situation,
              homeScore: v2Entry.homeScore,
              awayScore: v2Entry.awayScore,
              periodLabel: v2Entry.detail,
              state: v2Entry.state,
              ts: Date.now(),
            };
            localStorage.setItem('soccer_stats_' + key, JSON.stringify(stash));
          } catch(_) { /* quota / private mode — silent */ }
        }

        // MLB Savant WP trigger — was in ESPN poll loop; MLB removed from ESPN_SPORTS
        // so must fire here instead when a live MLB game is detected.
        if (sport === 'mlb' && (fg.state === 'live' || v2Entry.state === 'in') && !espnScores[key].wp) {
          try {
            const mlbSec  = (allData?.sports||[]).find(s=>(s.sport||'').includes('Baseball'));
            const mlbGame = (mlbSec?.games||[]).find(g =>
              espnTeamMatch(g.home||'', fg.home?.name||'') && espnTeamMatch(g.away||'', fg.away?.name||''));
            if (mlbGame?.sourceId) {
              fetchSavantGameFeed(mlbGame.sourceId).then(savant => {
                if (savant?.wp != null && espnScores[key]) {
                  espnScores[key].wp_prev = espnScores[key].wp;
                  espnScores[key].wp = savant.wp;
                  // Provenance tag mirrors _liveOddsWP (odds-api SSE path) so
                  // Savant-sourced wp is distinguishable from odds-derived wp
                  // on the same espnScores[key].wp field (CC-CMD avv-savant).
                  espnScores[key]._savantWP = { wp: savant.wp, wpa: savant.wpa ?? null, ts: Date.now(), source: 'savant' };
                }
              });
            }
          } catch(e_sav) { if(FIELD_DEBUG) console.warn('[V2-Savant]', e_sav.message); }
        }

        // Basketball leaders (homeLeader/awayLeader) — REMOVED 2026-06-30.
        // fetchV2Leaders + the /apisports passthrough it called are gone
        // (API-Sports.io subscription lapsed). See HANDOFF for removal log.

        // MLB pitcher leaders — StatsAPI boxscore (VERIFIED: teams.{home|away}.pitchers[last] = current pitcher)
        // gamePk sourced from allData (same pattern as Savant WP trigger).
        // /games/statistics/players does NOT exist for baseball — StatsAPI is the correct source.
        if (sport === 'mlb' && (fg.state === 'live' || v2Entry.state === 'in')) {
          try {
            const mlbSec  = (allData?.sports||[]).find(s=>(s.sport||'').includes('Baseball'));
            const mlbGame = (mlbSec?.games||[]).find(g =>
              espnTeamMatch(g.home||'', fg.home?.name||'') && espnTeamMatch(g.away||'', fg.away?.name||''));
            if (mlbGame?.sourceId) fetchMLBLeader(mlbGame.sourceId, key).catch(()=>{});
          } catch(e_mlbl) { if(FIELD_DEBUG) console.warn('[V2-MLB-Leader]', e_mlbl.message); }
        }
      });
      if (FIELD_DEBUG && games.length)
        console.debug(`[V2] ${sport}/${queryDate}: ${games.length} games, ${games.filter(g=>g.state==='live').length} live`);
    } catch(e) {
      if (FIELD_DEBUG) console.warn('[V2] poll error:', sport, queryDate, e.message);
    }
  })));

  hydrateEspnScoresFromFinals(); // restore known final scores before rendering (V2 returns null on finals)

  // CFB schedule section (CC-CMD-2026-07-15-cfb-section-injection). Ready
  // for a future CBB adapter via the same injectV2SportSection() call with
  // a different sportKey/sectionLabel -- not built here, per that CC-CMD's
  // own "do not preemptively apply to a sport with no real data source yet."
  if (FIELD_V2_SOURCES.cfb) injectV2SportSection('cfb', 'College Football');

  // WNBA schedule section (CC-CMD-2026-07-15-wnba-schedule-cards) --
  // injectV2SportSection's first real reuse. WNBA already flows through
  // this same V2 poll loop (FIELD_V2_SOURCES.wnba: true, "Phase 1/2: LIVE")
  // into espnScores -- confirmed real via a live /v2/games?sport=wnba
  // fetch -- but nothing previously turned those entries into allData.sports
  // card entries; the only WNBA "schedule" was a hardcoded array
  // (wnbaGames, buildTodaySchedule()) whose dates stop at June 28, so it
  // has produced zero real cards for weeks. Safe to layer alongside it:
  // injectV2SportSection looks up the existing section by `sport ===
  // sectionLabel`, so if the hardcoded array ever does match today's date
  // again it merges into the same section rather than duplicating.
  if (FIELD_V2_SOURCES.wnba) injectV2SportSection('wnba', 'WNBA');

  // MLS schedule section (CC-CMD-2026-07-16-mls-schedule-cards). Same gap
  // class as WNBA above: MLS already flows through this same V2 poll loop
  // (FIELD_V2_SOURCES.mls: true) into espnScores -- confirmed live via a
  // real /v2/games?sport=mls fetch returning 4 real MLS games for today,
  // sport:"mls" on every entry, exactly matching mapV2ToESPN's _sport
  // field and injectV2SportSection's own filter -- but nothing previously
  // turned those entries into allData.sports card entries. The only MLS
  // "schedule" was a hardcoded array (mlsSoccer, buildTodaySchedule())
  // whose own comment says it covers "Last Before World Cup Break (May
  // 25-Jul 16)" and was emptied out for the break -- MLS resumes today
  // (Jul 16) with the break comment's own end date, and the array was
  // never repopulated, so it has produced zero real cards since May 25.
  // 'MLS Soccer' matches the hardcoded path's own section label exactly
  // (see buildTodaySchedule's sections.push({sport:"MLS Soccer",...})),
  // so if that array is ever repopulated it merges into the same section
  // rather than duplicating, same guarantee WNBA's injection already has.
  if (FIELD_V2_SOURCES.mls) injectV2SportSection('mls', 'MLS Soccer');

  // ── Inject FIFA World Cup section into allData.sports ─────────────────────
  // V2 polling fetches wc26 games → espnScores. allData.sports may already
  // contain a FIFA section pushed by maybePushWorldCup() from wc26Raw
  // (the hardcoded schedule with matchupNotes + streams). Two failure modes
  // we have to avoid:
  //   1. Splicing a duplicate FIFA section when wc26Raw already produced one
  //      — leads to two cards per match + filter bar collisions.
  //   2. The "subsequent polls" branch looks up the section by `s.section`,
  //      which the wc26Raw section never sets — so live state updates
  //      silently skipped the wc26Raw section. WC games appeared static or
  //      vanished depending on which branch fired first.
  // Fix: idempotent injection. Look up by either `sport` or `section`. If a
  // FIFA section already exists, mark as injected and use the update path
  // to merge V2 live state in. Otherwise splice a fresh one.
  if (FIELD_V2_SOURCES.wc26) {
    try {
      const wcKeys = Object.keys(espnScores).filter(k => {
        const e = espnScores[k];
        if (!e || !/wc26|world cup|fifa/i.test(e._sport || e.league || e.detail || '')) return false;
        // Filter: only today's games in ET (removes yesterday's late starts)
        if (e.start_time && !isToday(e.start_time)) return false;
        return true;
      });
      // iPad-10: pre-flight dedup. If maybePushWorldCup already pushed a
      // FIFA section, flip _wcSectionInjected so the update branch runs
      // instead of splicing a duplicate. Look up by sport OR section.
      const existingFifaSection = allData?.sports?.find(s =>
        /FIFA/i.test(s.sport || '') || /FIFA/i.test(s.section || '')
      );
      if (existingFifaSection && !_wcSectionInjected) {
        _wcSectionInjected = true;
        // Backfill the `section` field so the update branch's find() works.
        if (!existingFifaSection.section) existingFifaSection.section = 'FIFA World Cup 2026';
      }
      if (wcKeys.length > 0) {
        const wcGames = wcKeys.map(k => {
          const e = espnScores[k];
          const [home, away] = k.split('|');
          return {
            home, away, _id: e._gameId || e.espnEventId || k,
            league: e.league || 'FIFA World Cup 2026',
            _sport: 'FIFA World Cup 2026', _section: 'FIFA World Cup 2026',
            start_time: e.start_time || e.startTime || '',
            state: e.state || 'pre',
            confirmed: true,
            streams: resolveBundle('WC26_FOX'),
            nationalBundle: e.nationalBundle || 'WC26_FOX',
            matchupNote: e.matchupNote || '',
            round: e.round || '',
            series: e.series || null,
          };
        });
        if (!_wcSectionInjected) {
          // First injection: add FIFA section to allData.sports
          const fifaSection = {
            sport: 'FIFA World Cup 2026',
            section: 'FIFA World Cup 2026',
            games: wcGames,
          };
          if (allData?.sports) {
            const mlbIdx = allData.sports.findIndex(s => (s.sport || '').includes('Baseball'));
            if (mlbIdx >= 0) allData.sports.splice(mlbIdx, 0, fifaSection);
            else allData.sports.push(fifaSection);
            buildFilters(allData.sports);
          }
          _wcSectionInjected = true;
        } else {
          // Subsequent polls: merge V2 live state into the existing FIFA section.
          // Use sport OR section for lookup (wc26Raw seeds only `sport`).
          const fifaSection = allData?.sports?.find(s =>
            /FIFA/i.test(s.section || '') || /FIFA/i.test(s.sport || '')
          );
          if (fifaSection) {
            // iPad-10: MERGE — keep wc26Raw games not yet in V2, overlay V2
            // games on top so live state (scores, clock, state) wins where
            // V2 has it but wc26Raw's matchupNote / streams / venue survive
            // for upcoming games V2 hasn't yet returned.
            const byKey = new Map();
            (fifaSection.games || []).forEach(g => {
              const k = `${(g.home||'').toLowerCase()}|${(g.away||'').toLowerCase()}`;
              byKey.set(k, g);
            });
            wcGames.forEach(v => {
              const k = `${(v.home||'').toLowerCase()}|${(v.away||'').toLowerCase()}`;
              const existing = byKey.get(k) || {};
              byKey.set(k, { ...existing, ...v,
                matchupNote: v.matchupNote || existing.matchupNote || '',
                streams: (existing.streams && existing.streams.length) ? existing.streams : v.streams,
                venue: existing.venue || v.venue || '',
              });
            });
            fifaSection.games = Array.from(byKey.values());
          }
        }
        scheduleRenderAll();

        // ── WC game brief consumption ─────────────────────────────────────
        // When a WC game transitions to 'final', async-fetch the post-match
        // brief from relay KV (brief:game:{eventId}, 1hr TTL). Inject as
        // matchupNote so it flows into game card rendering + CDW notes.
        // Uses existing /journalism/game/{id} relay route (same KV namespace).
        // Dedup via _wcBriefsFetched Set — each game brief fetched once.
        const _wcRelayBase = typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE
          : 'https://field-relay-nba.jeffunglesbee.workers.dev';
        for (const wg of wcGames) {
          if (wg.state !== 'final' || !wg._id || _wcBriefsFetched.has(wg._id)) continue;
          _wcBriefsFetched.add(wg._id);
          // Fire-and-forget: don't block the poll cycle
          (async (gameId, gameKey) => {
            try {
              const r = await fetch(
                `${_wcRelayBase}/journalism/game/${encodeURIComponent(gameId)}`,
                { signal: AbortSignal.timeout(1500) }
              );
              if (!r.ok) return;
              const data = await r.json();
              const brief = data?.brief;
              if (!brief) return;
              // Inject into espnScores so subsequent polls pick it up
              const entry = espnScores[gameKey];
              if (entry) entry.matchupNote = brief;
              // Update the FIFA section game object directly
              const fifaSec = allData?.sports?.find(s => (s.section || '').includes('FIFA'));
              if (fifaSec) {
                const g = (fifaSec.games || []).find(gg => gg._id === gameId);
                if (g) g.matchupNote = brief;
              }
              scheduleRenderAll();
              // Render bracket impact debrief card if snapshots exist
              renderWCBracketImpact(gameId, wg.home || '', wg.away || '', _wcRelayBase)
                .catch(() => {});
              if (FIELD_DEBUG) console.debug('[V2-WC] brief consumed for', gameId, brief.slice(0, 60) + '…');
            } catch(_e) { captureFieldError('journalism:v2-wc-brief-consume', _e, true); }
          })(wg._id, wcKeys.find(k => {
            const e = espnScores[k];
            return (e._gameId || e.espnEventId || k) === wg._id;
          }) || '');
        }
      }
    } catch(e_wc) { if(FIELD_DEBUG) console.warn('[V2-WC] section inject error:', e_wc.message); }
  }

  // ── NBA post-game brief consumption ───────────────────────────────────────
  // When an NBA game transitions to 'final' in V2 poll, async-fetch the
  // post-game brief from relay KV (brief:game:nba:{id}, 1hr TTL).
  // Inject as matchupNote so it flows into game card rendering.
  // Mirrors WC brief consumption pattern. Dedup via _nbaBriefsFetched Set.
  if (FIELD_V2_SOURCES.nba) {
    const nbaKeys = Object.keys(espnScores).filter(k => {
      const e = espnScores[k];
      return e && e.state === 'post' && /nba/i.test(e._sport || e.league || '');
    });
    const _nbaRelayBase = typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE
      : 'https://field-relay-nba.jeffunglesbee.workers.dev';
    for (const key of nbaKeys) {
      const e = espnScores[key];
      const gameId = e._gameId || e.espnEventId || '';
      if (!gameId || _nbaBriefsFetched.has(gameId)) continue;
      _nbaBriefsFetched.add(gameId);
      (async (gId, gKey) => {
        try {
          const r = await fetch(
            `${_nbaRelayBase}/journalism/game/${encodeURIComponent(gId)}`,
            { signal: AbortSignal.timeout(1500) }
          );
          if (!r.ok) return;
          const data = await r.json();
          const brief = data?.brief;
          if (!brief) return;
          if (espnScores[gKey]) espnScores[gKey].matchupNote = brief;
          // Also update allData game object
          const nbaSec = (allData?.sports||[]).find(s => /NBA/i.test(s.sport||'') || /NBA/i.test(s.section||''));
          if (nbaSec) {
            const g = (nbaSec.games||[]).find(gg => (gg._id||gg.sourceId||'') === gId);
            if (g) g.matchupNote = brief;
          }
          scheduleRenderAll();
          if (FIELD_DEBUG) console.debug('[V2-NBA] brief consumed for', gId, brief.slice(0, 60) + '…');
        } catch(_e) { captureFieldError('journalism:v2-nba-brief-consume', _e, true); }
      })(gameId, key);
    }
  }

  // ── NHL post-game brief consumption ───────────────────────────────────────
  // Same pattern as NBA. NHL adapter uses numeric IDs (no prefix).
  if (FIELD_V2_SOURCES.nhl) {
    const nhlKeys = Object.keys(espnScores).filter(k => {
      const e = espnScores[k];
      return e && e.state === 'post' && /nhl/i.test(e._sport || e.league || '');
    });
    const _nhlRelayBase = typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE
      : 'https://field-relay-nba.jeffunglesbee.workers.dev';
    for (const key of nhlKeys) {
      const e = espnScores[key];
      const gameId = e._gameId || e.espnEventId || '';
      if (!gameId || _nhlBriefsFetched.has(gameId)) continue;
      _nhlBriefsFetched.add(gameId);
      (async (gId, gKey) => {
        try {
          const r = await fetch(
            `${_nhlRelayBase}/journalism/game/${encodeURIComponent(gId)}`,
            { signal: AbortSignal.timeout(1500) }
          );
          if (!r.ok) return;
          const data = await r.json();
          const brief = data?.brief;
          if (!brief) return;
          if (espnScores[gKey]) espnScores[gKey].matchupNote = brief;
          const nhlSec = (allData?.sports||[]).find(s => /NHL/i.test(s.sport||'') || /NHL/i.test(s.section||''));
          if (nhlSec) {
            const g = (nhlSec.games||[]).find(gg => (gg._id||gg.sourceId||'') === gId);
            if (g) g.matchupNote = brief;
          }
          scheduleRenderAll();
          if (FIELD_DEBUG) console.debug('[V2-NHL] brief consumed for', gId, brief.slice(0, 60) + '…');
        } catch(_e) { captureFieldError('journalism:v2-nhl-brief-consume', _e, true); }
      })(gameId, key);
    }
  }

  if (_roundDataNewThisPoll) scheduleRenderAll(); // cards re-render when round data first arrives
  renderESPNScores(); // re-render with fresh V2 data
  try {
    const _circResult = computeSportCircadian(new Date(), allData?.sports || []);
    applyCircadian(_circResult.global);
    const _circPrev = _circadianMode;
    _circadianMode = _circResult.global;
    _circadianBySport = _circResult.bySport;
    _prevCircadianMode = _circPrev;
    // Gap 11: check if mode transitioned to LATE/DAWN with an active sport filter
    try { _checkFilterSuggestionChip(_circPrev, _circResult.global); } catch(_gp11) {}
    // Gap 8: re-render Journal tab when circadian mode changes (re-sorts sections)
    if (_circPrev !== _circResult.global && document.body.classList.contains('journalism-mode')) {
      try { renderJournalism(); } catch(_gp8) {}
    }
  } catch(_) {}
  scheduleV2Poll(anyLive ? 30000 : 60000);
}

function scheduleV2Poll(ms) {
  if (_v2PollTimeout) clearTimeout(_v2PollTimeout);
  _v2PollTimeout = setTimeout(fetchV2AllScores, ms);
}

function startV2ScorePolling() {
  if (_v2PollTimeout) return; // already running
  fetchV2AllScores();
}


const ESPN_SUMMARY_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/espn-summary';
// NBA CDN live data relay — /nba/* route already deployed on field-relay-nba
// Whitelist includes: playbyplay_*, boxscore_*, todaysScoreboard_00.json
const NBA_CDN_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/nba';
// Baseball Savant GameFeed — CORS-open, no relay needed
// Provides live WP (homeTeamWinProbability 0-1) + Statcast exit velocity per play
// Confirmed CORS-open: access-control-allow-origin: * (May 21 2026)
const SAVANT_BASE = 'https://baseballsavant.mlb.com';

// ── Items 4-6: Journalism depth relay bases ──────────────────────────────────
const BDL_RELAY   = 'https://field-relay-nba.jeffunglesbee.workers.dev/bdl';
const NHL_RELAY   = 'https://field-relay-nba.jeffunglesbee.workers.dev/nhl';
const MLB_STATS_RELAY = 'https://field-relay-nba.jeffunglesbee.workers.dev/mlb-stats';
const SQUIGGLE_RELAY  = 'https://field-relay-nba.jeffunglesbee.workers.dev/squiggle'; // AFL Squiggle API proxy

// Item 4 — BDL season averages for active playoff players
// Cache: localStorage 24h per player (season stats don't change intraday)
// Output: "Brunson: 24.2 PPG / 6.7 APG this season" — real facts for journalism
const _bdlStatCache = {};

// ── Item 7 — ESPN Athlete Stats ──────────────────────────────────────────────
// Coverage: MLB (primary — BDL is NBA-only), NHL, NBA (supplement BDL)
// Sources: site.api.espn.com public endpoints — no API key required, CORS-open
// Cache: localStorage 24h per player + in-memory session cache
// Output: "J.Brunson: 28.4 PPG / 6.7 APG · F.Freeman: .312 AVG / 8 HR / 31 RBI"
// Runs as pre-fetch in fetchCompoundEditorial — stored in _espnAthleteContextCache
// Reads synchronously from cache in buildCompoundPrompt Item 7 block
const _espnAthleteContextCache = {}; // gameId → formatted stat string

const ESPN_ATHLETE_SPORT_MAP = {
  'Basketball':       'basketball/nba',
  'Baseball':         'baseball/mlb',
  'Hockey':           'hockey/nhl',
  'NFL Football':     'football/nfl',
  'College Football': 'football/college-football',
};

// Parse ESPN stats array into a readable line for the given sport
function _parseESPNStatLine(name, stats, sportSection) {
  const get = (...keys) => {
    for (const k of keys) {
      const s = stats.find(x => x.name===k || x.abbreviation===k || x.shortDisplayName===k);
      if (s?.displayValue && s.displayValue !== '--') return s.displayValue;
    }
    return null;
  };
  if (sportSection === 'Basketball') {
    const pts = get('avgPoints','PTS'), ast = get('avgAssists','AST'), reb = get('avgRebounds','REB');
    const parts = [pts&&`${pts} PPG`, ast&&`${ast} APG`, reb&&`${reb} RPG`].filter(Boolean);
    return parts.length ? `${name}: ${parts.join(' / ')}` : '';
  }
  if (sportSection === 'Baseball') {
    const era = get('ERA','earnedRunAverage');
    if (era) {
      const wins = get('wins','W'), k = get('strikeouts','K','SO');
      const parts = [`${era} ERA`, wins&&`${wins}W`, k&&`${k}K`].filter(Boolean);
      return `${name}: ${parts.join(' / ')}`;
    }
    const avg = get('avg','AVG','battingAverage'), hr = get('homeRuns','HR'), rbi = get('RBI','rbi');
    const parts = [avg&&`.${avg.replace(/^0\./,'')} AVG`, hr&&`${hr} HR`, rbi&&`${rbi} RBI`].filter(Boolean);
    return parts.length ? `${name}: ${parts.join(' / ')}` : '';
  }
  if (sportSection === 'Hockey') {
    const g = get('goals','G'), a = get('assists','A'), pts = get('points','PTS'), pm = get('plusMinus','+/-');
    const parts = [g&&`${g}G`, a&&`${a}A`, pts&&`${pts}PTS`, pm&&`${pm}+/-`].filter(Boolean).slice(0,3);
    return parts.length ? `${name}: ${parts.join(' / ')}` : '';
  }
  return '';
}

async function fetchESPNAthleteStats(names, sportSection) {
  if (!names?.length) return '';
  const espnPath = ESPN_ATHLETE_SPORT_MAP[sportSection];
  if (!espnPath) return '';
  const results = [];
  for (const raw of names.slice(0, 4)) {
    const name = raw.trim();
    if (!name || name.length < 4) continue;
    const ck = `espn_ath_${espnPath.replace(/\//g,'_')}_${name.toLowerCase().replace(/\s+/g,'_')}`;
    if (_bdlStatCache[ck]) { results.push(_bdlStatCache[ck]); continue; } // reuse single cache
    try {
      const cached = localStorage.getItem(ck);
      if (cached) { const p=JSON.parse(cached); if(Date.now()-p.ts<86400000){_bdlStatCache[ck]=p.line;results.push(p.line);continue;} }
    } catch(_){}
    try {
      // Step 1: search for athlete ID
      const sr = await fetch(
        `https://site.api.espn.com/apis/site/v2/sports/${espnPath}/athletes?name=${encodeURIComponent(name)}&limit=5`,
        {signal:AbortSignal.timeout(5000)}
      );
      if (!sr.ok) continue;
      const sd = await sr.json();
      const pool = sd.athletes || sd.items || [];
      const athlete = pool.find(a=>{
        const full=(a.fullName||a.displayName||`${a.firstName||''} ${a.lastName||''}`).toLowerCase();
        return full.includes(name.toLowerCase()) || name.toLowerCase().includes((a.lastName||'').toLowerCase());
      });
      if (!athlete?.id) continue;
      // Step 2: fetch statistics
      const ar = await fetch(
        `https://site.api.espn.com/apis/site/v2/sports/${espnPath}/athletes/${athlete.id}/statistics`,
        {signal:AbortSignal.timeout(5000)}
      );
      if (!ar.ok) continue;
      const ad = await ar.json();
      // ESPN returns statistics.splits.categories — find the "Total" or first category
      const cats = ad.statistics?.splits?.categories || [];
      const cat = cats.find(c=>c.name==='total'||c.displayName==='Total'||c.name==='general') || cats[0];
      const stats = cat?.stats || [];
      if (!stats.length) continue;
      const shortName = name.split(' ').map((w,i)=>i===0?w[0]+'.':w).join('');
      const line = _parseESPNStatLine(shortName, stats, sportSection);
      if (!line) continue;
      _bdlStatCache[ck] = line;
      try { localStorage.setItem(ck, JSON.stringify({line, ts:Date.now()})); } catch(_){}
      results.push(line);
    } catch(e_) {
      if(FIELD_DEBUG) console.warn('[ESPN-ATHLETE]', name, e_.message);
    }
  }
  return results.join(' · ');
}

// Pre-fetch ESPN athlete stats for all tonight's games — called before compound prompt
// Stores results in _espnAthleteContextCache[gameId]
async function fetchESPNAthleteContextAll(games) {
  const tasks = [];
  for (const g of (games||[]).slice(0,8)) {
    if (_espnAthleteContextCache[g._id]) continue; // already warm
    const sport = _gameSport(g);
    const espnPath = ESPN_ATHLETE_SPORT_MAP[sport];
    if (!espnPath) continue;
    tasks.push((async()=>{
      const names = [];
      // MLB: use structured pitcher names (most reliable source of real player names)
      if (sport.toLowerCase().includes('baseball')||sport.toLowerCase().includes('mlb')) {
        if (g.homePitcher?.lastName) names.push(g.homePitcher.fullName||g.homePitcher.lastName);
        if (g.awayPitcher?.lastName) names.push(g.awayPitcher.fullName||g.awayPitcher.lastName);
      }
      // All sports: extract names from matchupNote (e.g. "Brunson 29.0 PPG this series")
      if (g.matchupNote) {
        const m = g.matchupNote.matchAll(/([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)/g);
        for (const match of m) {
          const n = match[1];
          if (!names.includes(n) && !/^(The|This|His|Her|Their|New|Old|Last|Next|Game|Series|Round|Season|East|West|North|South|Conference|Division|Finals|Cup|Bowl|World)$/.test(n.split(' ')[0])) {
            names.push(n);
          }
        }
      }
      if (!names.length) return;
      const line = await fetchESPNAthleteStats(names, sport);
      if (line) _espnAthleteContextCache[g._id] = line;
    })());
  }
  await Promise.allSettled(tasks);
}
async function fetchBDLPlayerContext(playerNames) {
  if (!playerNames?.length) return '';
  const results = [];
  for (const raw of playerNames.slice(0, 4)) {
    const name = raw.trim();
    if (!name) continue;
    const cacheKey = 'bdl_stat_' + name.toLowerCase().replace(/\s+/g,'_');
    // 24h localStorage cache
    try {
      const cached = localStorage.getItem(cacheKey);
      if (cached) { const p = JSON.parse(cached); if (Date.now() - p.ts < 86400000) { results.push(p.line); continue; } }
    } catch(_) {}
    if (_bdlStatCache[cacheKey]) { results.push(_bdlStatCache[cacheKey]); continue; }
    try {
      const lastName = name.split(' ').slice(-1)[0];
      const sr = await fetch(`${BDL_RELAY}/nba/v1/players?search=${encodeURIComponent(lastName)}&per_page=5`, { signal: AbortSignal.timeout(3000) });
      if (!sr.ok) continue;
      const sd = await sr.json();
      const player = (sd.data||[]).find(p => {
        const full = `${p.first_name||''} ${p.last_name||''}`.toLowerCase();
        return full.includes(name.toLowerCase()) || name.toLowerCase().includes((p.last_name||'').toLowerCase());
      });
      if (!player?.id) continue;
      const ar = await fetch(`${BDL_RELAY}/nba/v1/season_averages?player_ids[]=${player.id}&season=2025`, { signal: AbortSignal.timeout(3000) });
      if (!ar.ok) continue;
      const ad = await ar.json();
      const avg = (ad.data||[])[0];
      if (!avg) continue;
      const pts  = avg.pts  != null ? `${Number(avg.pts).toFixed(1)} PPG`  : '';
      const ast  = avg.ast  != null ? `${Number(avg.ast).toFixed(1)} APG`  : '';
      const reb  = avg.reb  != null ? `${Number(avg.reb).toFixed(1)} RPG`  : '';
      const line = [pts, ast, reb].filter(Boolean).join(' / ');
      if (!line) continue;
      const entry = `${name}: ${line} (season)`;
      _bdlStatCache[cacheKey] = entry;
      try { localStorage.setItem(cacheKey, JSON.stringify({line: entry, ts: Date.now()})); } catch(_) {}
      results.push(entry);
    } catch(_) {}
  }
  return results.length ? results.join(' · ') : '';
}

// ── BDL Recent Form — NBA momentum signal (last 5 games) ────────────────────
// Answers "how has this player performed recently?" vs season average
// CC-CMD-2026-07-15-bdl-recent-form: the two "Used in" claims this comment
// previously made (J3 compound prompt momentum context, Night Owl arc
// context) were both confirmed false -- J3's real [DRAMA: RISING/COOLING]
// tag is powered by ctx.dramaTrend, a game-level signal, not player-level
// form; buildNightOwlStatic contains no BDL/momentum reference at all.
// Real home found instead: the compound-prompt series matchupNote pipeline
// (~L29253 prefetch, ~L29094 [SEASON STATS] reader) -- same real player
// names already extracted there for season averages, now also prefetched
// here and surfaced as a sibling [RECENT FORM] tag, a genuinely distinct
// signal (this player's own recent trend, not getStatOfDay's team-vs-
// league deviation or ctx.dramaTrend's game-level trend).
// Cache: 4h per player (recent form changes more than season avg)
// Pattern: "Brunson: 34.1 PPG last 5 (34.1 APG / 5.2 RPG)" — .formatted field
const _bdlRecentFormCache = {};
async function fetchBDLRecentForm(playerName) {
  if (!playerName) return null;
  const ck = `bdl_recent_${playerName.toLowerCase().replace(/\s+/g,'_')}`;
  if (_bdlRecentFormCache[ck]) return _bdlRecentFormCache[ck];
  try {
    const cached = localStorage.getItem(ck);
    if (cached) {
      const p = JSON.parse(cached);
      if (Date.now() - p.ts < 14400000) { _bdlRecentFormCache[ck]=p.data; return p.data; } // 4h TTL
    }
  } catch(_) {}
  try {
    // Step 1: look up player ID (reuse _bdlStatCache key pattern if already fetched)
    const lastName = playerName.split(' ').slice(-1)[0];
    const sr = await fetch(`${BDL_RELAY}/nba/v1/players?search=${encodeURIComponent(lastName)}&per_page=5`,
      {signal:AbortSignal.timeout(4000)});
    if (!sr.ok) return null;
    const sd = await sr.json();
    const player = (sd.data||[]).find(p=>{
      const full = `${p.first_name||''} ${p.last_name||''}`.toLowerCase();
      return full.includes(playerName.toLowerCase()) || playerName.toLowerCase().includes((p.last_name||'').toLowerCase());
    });
    if (!player?.id) return null;
    // Step 2: get stats from last 5 games (dates_from = 10 days ago covers at least 5 NBA games)
    const daysAgo10 = new Date(Date.now()-10*86400000).toISOString().slice(0,10);
    const gr = await fetch(
      `${BDL_RELAY}/nba/v1/stats?player_ids[]=${player.id}&dates_from=${daysAgo10}&per_page=10`,
      {signal:AbortSignal.timeout(5000)}
    );
    if (!gr.ok) return null;
    const gd = await gr.json();
    const games = (gd.data||[]).filter(s=>s.pts!=null).slice(0,5); // last 5 completed games
    if (games.length < 3) return null; // not enough data
    const avg = f => (games.reduce((s,g)=>s+(g[f]||0),0)/games.length);
    const pts = avg('pts').toFixed(1), ast = avg('ast').toFixed(1), reb = avg('reb').toFixed(1);
    const data = {
      name: playerName,
      gamesBack: games.length,
      line: `${pts} PPG / ${ast} APG / ${reb} RPG`,
      formatted: `${playerName}: ${pts} PPG last ${games.length} (${ast} APG / ${reb} RPG)`,
    };
    _bdlRecentFormCache[ck] = data;
    try { localStorage.setItem(ck, JSON.stringify({data, ts:Date.now()})); } catch(_) {}
    return data;
  } catch(e_) {
    if(FIELD_DEBUG) console.warn('[BDL-RECENT]', playerName, e_.message);
    return null;
  }
}

// Item 5 — NHL live shot + save% context
// Calls /nhl/v1/score/now which returns shots on goal per team + game IDs
// Cache: 90s (updates between periods; doesn't need to be real-time)
let _nhlLiveStatsCache = {};
let _nhlLiveStatsFetchedAt = 0;
async function fetchNHLLiveStats() {
  const now = Date.now();
  if (now - _nhlLiveStatsFetchedAt < 90000 && Object.keys(_nhlLiveStatsCache).length) return _nhlLiveStatsCache;
  try {
    const r = await fetch(`${NHL_RELAY}/v1/scoreboard/now`, { signal: AbortSignal.timeout(4000) });
    if (!r.ok) return _nhlLiveStatsCache;
    const d = await r.json();
    const fresh = {};
    for (const g of (d.games||[])) {
      if (!['LIVE','CRIT'].includes(g.gameState||'')) continue;
      const home = g.homeTeam?.name?.default || g.homeTeam?.abbrev || '';
      const away = g.awayTeam?.name?.default || g.awayTeam?.abbrev || '';
      const homeSog = g.homeTeam?.sog ?? null;
      const awaySog = g.awayTeam?.sog ?? null;
      // Boxscore for goalie save% — gamecenter/{id}/boxscore
      let goalieNote = '';
      try {
        const br = await fetch(`${NHL_RELAY}/v1/gamecenter/${g.id}/boxscore`, { signal: AbortSignal.timeout(3000) });
        if (br.ok) {
          const bd = await br.json();
          // ── Leaders: top-points skater per team (VERIFIED 2026-05-30) ───
          // playerByGameStats.{homeTeam|awayTeam}.{forwards|defensemen}[]
          // each entry: { name:{default:"C. Caufield"}, goals, assists, points }
          const pickSkaterLeader = (teamStats) => {
            const skaters = [...(teamStats?.forwards||[]), ...(teamStats?.defensemen||[])];
            if (!skaters.length) return null;
            skaters.sort((a,b) => (b.points??0) - (a.points??0));
            const top = skaters[0];
            if (!(top?.points)) return null;
            const name = top?.name?.default || '';
            return name ? { name, val: top.points, unit: 'PTS' } : null;
          };
          const homeSkLeader = pickSkaterLeader(bd.playerByGameStats?.homeTeam);
          const awaySkLeader = pickSkaterLeader(bd.playerByGameStats?.awayTeam);
          if (espnScores[key]) {
            if (homeSkLeader) espnScores[key].homeLeader = homeSkLeader;
            if (awaySkLeader) espnScores[key].awayLeader = awaySkLeader;
            if (FIELD_DEBUG && (homeSkLeader||awaySkLeader))
              console.debug(`[NHL-Leaders] ${key}: home=${homeSkLeader?.name} away=${awaySkLeader?.name}`);
          }
          // Find starting goalies from playerByGameStats
          const homeG = (bd.playerByGameStats?.homeTeam?.goalies||[])[0];
          const awayG = (bd.playerByGameStats?.awayTeam?.goalies||[])[0];
          const fmt = (gl, team) => {
            if (!gl) return '';
            const name = gl.name?.default?.split(' ').slice(-1)[0] || '';
            const sa   = gl.toi ? (gl.saves||0) : null;
            const sv   = (gl.savePctg != null) ? `${(gl.savePctg*100).toFixed(1)}%` : '';
            return (name && sv) ? `${name} ${sv} sv%` : '';
          };
          const hg = fmt(homeG, home), ag = fmt(awayG, away);
          if (hg || ag) goalieNote = [ag, hg].filter(Boolean).join(' · ');
          // PM-28e: extract byPeriod goals → espnScores homeLinescores/awayLinescores
          // bd.linescore.byPeriod[{periodDescriptor:{number}, away, home}]
          try {
            const byPeriod = bd?.linescore?.byPeriod || [];
            if (byPeriod.length >= 1) {
              const homeLS = byPeriod.map(p => p.home ?? 0);
              const awayLS = byPeriod.map(p => p.away ?? 0);
              const eKey = `${home}|${away}`;
              if (espnScores[eKey]) {
                espnScores[eKey].homeLinescores = homeLS;
                espnScores[eKey].awayLinescores = awayLS;
              }
              if (FIELD_DEBUG) console.debug('[PM-28e] NHL byPeriod:', eKey, homeLS, 'vs', awayLS);
            }
          } catch(_e28) {}
        }
      } catch(_) {}
      const sogNote = (homeSog != null && awaySog != null)
        ? `Shots: ${away.split(' ').slice(-1)[0]} ${awaySog}–${homeSog} ${home.split(' ').slice(-1)[0]}`
        : '';
      const key = `${home}|${away}`;
      fresh[key] = [sogNote, goalieNote].filter(Boolean).join(' · ');
    }
    _nhlLiveStatsCache = fresh;
    _nhlLiveStatsFetchedAt = now;
    return fresh;
  } catch(_) { return _nhlLiveStatsCache; }
}

// ── fetchMLBLeader: current pitcher as in-game leader ─────────────────────
// Source: MLB Stats API /game/{gamePk}/boxscore (same endpoint as fetchMLBBoxscoreContext)
// Called from V2 poll loop for live MLB games with a known gamePk.
// VERIFIED: teams.{home|away}.pitchers[] last entry = current pitcher ID.
// teams.{home|away}.players['ID{id}'].person.lastName + stats.pitching.inningsPitched / strikeOuts
// Writes {name, val, unit:'IP'} to espnScores[key].homeLeader / awayLeader.
const _mlbLeaderCache = {}; // espnKey → {ts}
const MLB_LEADER_TTL = 90000;
async function fetchMLBLeader(gamePk, espnKey) {
  const cacheKey = `mlbl:${espnKey}`;
  const cached = _mlbLeaderCache[cacheKey];
  if (cached && Date.now() - cached.ts < MLB_LEADER_TTL) return;
  _mlbLeaderCache[cacheKey] = { ts: Date.now() };
  try {
    const r = await fetch(`${MLB_STATS_RELAY}/game/${gamePk}/boxscore`, { signal: AbortSignal.timeout(4000) });
    if (!r.ok) return;
    const d = await r.json();
    // Backfill raw data for fetchMLBBoxscoreContext cache sharing
    const boxCacheKey = `mlb_box_${gamePk}`;
    if (_mlbBoxscoreCache[boxCacheKey] && !_mlbBoxscoreCache[boxCacheKey].raw)
      _mlbBoxscoreCache[boxCacheKey].raw = d;
    const teams = d?.teams || {};
    const pickPitcher = (side) => {
      const pitchers = teams[side]?.pitchers || [];
      const curId = pitchers[pitchers.length - 1];
      if (!curId) return null;
      const info = teams[side]?.players?.[`ID${curId}`];
      if (!info) return null;
      const name = info.person?.lastName || '';
      const ip   = info.stats?.pitching?.inningsPitched || '';
      const so   = info.stats?.pitching?.strikeOuts;
      const val  = ip ? (so != null ? `${ip} IP ${so}K` : `${ip} IP`) : null;
      return (name && val) ? { name, val, unit: 'IP' } : null;
    };
    const homeLeader = pickPitcher('home');
    const awayLeader = pickPitcher('away');
    if (espnScores[espnKey]) {
      if (homeLeader) espnScores[espnKey].homeLeader = homeLeader;
      if (awayLeader) espnScores[espnKey].awayLeader = awayLeader;
      if (FIELD_DEBUG && (homeLeader||awayLeader))
        console.debug(`[MLB-Leader] ${espnKey}: home=${homeLeader?.name} away=${awayLeader?.name}`);
    }
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[MLB-Leader]', e.message);
  }
}

// Item 6 — MLB Stats boxscore: pitcher stats + team batting
// Uses game.sourceId (gamePk) already stored on MLB game objects
// Cache: 90s per gamePk
const _mlbBoxscoreCache = {};
async function fetchMLBBoxscoreContext(gamePk) {
  if (!gamePk) return '';
  const cacheKey = `mlb_box_${gamePk}`;
  const cached = _mlbBoxscoreCache[cacheKey];
  if (cached && Date.now() - cached.ts < 90000) return cached.line;
  try {
    const r = await fetch(`${MLB_STATS_RELAY}/game/${gamePk}/boxscore`, { signal: AbortSignal.timeout(4000) });
    if (!r.ok) return '';
    const d = await r.json();
    const teams = d.teams || {};
    const parts = [];
    // Pitcher stats — current pitcher for each team
    for (const side of ['home','away']) {
      const pitchers = teams[side]?.pitchers || [];
      const curPitcherId = pitchers[pitchers.length - 1]; // current = last used
      const info = teams[side]?.players?.[`ID${curPitcherId}`];
      if (!info) continue;
      const name = info.person?.lastName || '';
      const s = info.stats?.pitching || {};
      const ip   = s.inningsPitched || '';
      const so   = s.strikeOuts != null ? `${s.strikeOuts}K` : '';
      const era  = s.era ? `${s.era} ERA` : '';
      const runs = s.earnedRuns != null ? `${s.earnedRuns} ER` : '';
      // numberOfPitches/pitchesThrown are the same value in this endpoint's
      // own response (confirmed via the prior probe's live check) -- keep
      // one, not both, to avoid a redundant duplicate in the display line.
      const pitches = s.numberOfPitches != null ? `${s.numberOfPitches}p` : '';
      const bf      = s.battersFaced != null ? `${s.battersFaced}BF` : '';
      const line = [ip ? `${ip} IP` : '', so, runs, era, pitches, bf].filter(Boolean).join(' ');
      if (name && line) parts.push(`${name}: ${line}`);
    }
    // Team batting averages
    for (const side of ['home','away']) {
      const tb = teams[side]?.teamStats?.batting || {};
      const avg = tb.avg ? `${side === 'home' ? teams[side]?.team?.name?.split(' ').slice(-1)[0] : teams[side]?.team?.name?.split(' ').slice(-1)[0]} .${String(Math.round(Number(tb.avg)*1000)).padStart(3,'0')}` : '';
      if (avg) parts.push(avg);
    }
    const line = parts.join(' · ');
    _mlbBoxscoreCache[cacheKey] = { line, ts: Date.now() };
    return line;
  } catch(_) { return ''; }
}
const relayNBAScores = {};
let   RELAY_HEALTHY  = false;
let   RELAY_PRIMARY  = false;
const RELAY_CUTOVER_DATE = '2026-05-19';

async function relayHealthCheck() {
  try {
    const r = await fetch(RELAY_BASE.replace('/nba','/health'), {signal:AbortSignal.timeout(4000)});
    RELAY_HEALTHY = r.ok;
  } catch { RELAY_HEALTHY = false; }
  if (RELAY_HEALTHY && TODAY_ISO >= RELAY_CUTOVER_DATE) RELAY_PRIMARY = true;
  if (FIELD_DEBUG) console.debug(`[RELAY] health=${RELAY_HEALTHY} primary=${RELAY_PRIMARY}`);
  return RELAY_HEALTHY;
}

function normalizeNBAGameRelay(g) {
  const home = g.homeTeam, away = g.awayTeam;
  const homeScore = Number(home.score ?? 0);
  const awayScore = Number(away.score ?? 0);
  const stateMap = {1:'pre', 2:'in', 3:'post'};
  const periodMap = {1:'Q1',2:'Q2',3:'Q3',4:'4th',5:'OT',6:'2OT',7:'3OT'};
  return {
    state:       stateMap[g.gameStatus] ?? 'pre',
    period:      g.period ?? 0,
    periodLabel: periodMap[g.period] ?? g.gameStatusText ?? '',
    clock:       g.gameClock ?? '',
    detail:      g.gameStatusText ?? '',
    homeScore, awayScore,
    homeName:    home.teamName   ?? '',
    awayName:    away.teamName   ?? '',
    homeCity:    home.teamCity   ?? '',
    awayCity:    away.teamCity   ?? '',
    homeTricode: home.teamTricode ?? '',
    awayTricode: away.teamTricode ?? '',
    homeWinning: homeScore > awayScore,
    seriesText:  g.seriesText ?? null,
    gameId:      g.gameId,
    source:      'relay',
  };
}

async function fetchNBAScoreboardViaRelay() {
  const r = await fetch(`${RELAY_BASE}/liveData/scoreboard/todaysScoreboard_00.json`, {signal:AbortSignal.timeout(6000)});
  if (!r.ok) throw new Error(`RELAY scoreboard ${r.status}`);
  const {scoreboard} = await r.json();
  return (scoreboard.games||[]).map(normalizeNBAGameRelay);
}
async function fetchNBAStandingsViaRelay() {
  const r = await fetch(`${RELAY_BASE}/liveData/standings/standings_v2.json`, {signal:AbortSignal.timeout(6000)});
  if (!r.ok) throw new Error(`RELAY standings ${r.status}`);
  return r.json();
}
async function fetchNBABoxScoreViaRelay(gameId) {
  const r = await fetch(`${RELAY_BASE}/liveData/boxscore/boxscore_${gameId}.json`, {signal:AbortSignal.timeout(6000)});
  if (!r.ok) throw new Error(`RELAY boxscore ${r.status}`);
  return r.json();
}
// Parallel validation + primary path — fires after each ESPN poll cycle
// 2026-07-13 (follow-up to CC-CMD-2026-07-13-fetchnhlrelayscores-migration,
// same bug pattern confirmed by direct read, not assumed): migrated to
// fieldOperation() -- this function's own catch only conditionally
// console.warn'd (FIELD_DEBUG-gated) and never called captureFieldError,
// so the sole caller's `.catch(e=>captureFieldError('relay-nba',e,true))`
// could never fire (the promise never rejected) AND the internal warn
// itself was invisible outside a debug session. Same fix as the NHL relay:
// fieldOperation()'s own catch is now the sole (and genuinely telemetered)
// catcher.
async function fetchNBARelayScores() {
  if (!RELAY_HEALTHY) return;
  return fieldOperation({subsystem:'scores', operation:'fetch-nba-relay', retryable:true}, async () => {
    const games = await fetchNBAScoreboardViaRelay();
    let disc = 0;
    games.forEach(g => {
      const homeKey = `${g.homeCity} ${g.homeName}`;
      const awayKey = `${g.awayCity} ${g.awayName}`;
      const key = `${homeKey}|${awayKey}`;
      relayNBAScores[key] = g;
      if (RELAY_PRIMARY && !FIELD_V2_SOURCES.nba) {
        // Post-cutover NBA CDN write — only when V2 is NOT the NBA score source.
        // V2 pivot (2026-05-29) made api-sports.io primary for NBA; CDN relay is
        // now used only for _nbaGameIdMap (PBP routing) via fetchNBAScoreboard().
        espnScores[key] = {
          _gameId: resolveGameIdByHome(homeKey),
          state: g.state, period: g.period, clock: g.clock, detail: g.detail,
          homeScore: g.homeScore, awayScore: g.awayScore,
          homeName: homeKey, awayName: awayKey,
          home: homeKey, away: awayKey,
          _sport: 'NBA Playoffs',
          homeWinning: g.homeWinning, periodPrefix: 'Q', source: 'relay',
        };
        espnScoreTs[key] = Date.now();
      } else if (FIELD_DEBUG && espnScores[key] && g.state === 'in') {
        const e = espnScores[key];
        if (e.homeScore !== g.homeScore || e.awayScore !== g.awayScore) {
          console.warn(`[RELAY≠ESPN] ${homeKey} vs ${awayKey}: R=${g.homeScore}-${g.awayScore} E=${e.homeScore}-${e.awayScore}`);
          disc++;
        }
      }
    });
    if (FIELD_DEBUG) console.log(`[RELAY] ${games.length} games | disc=${disc} | primary=${RELAY_PRIMARY}`);
    // Rule 24: trigger drama pipeline when relay updates espnScores (matches NHL relay pattern)
    if (RELAY_PRIMARY && games.length) renderESPNScores();
  });
}

// ── Midnight crossover watcher — re-runs schedule if date changes ──────────
// Wrapped in try-catch: must NEVER throw or fetchSchedule() below is blocked.
try {
  (function() {
    const _tz = (function(){ try{ return localTz(); }catch(e){ return 'UTC'; } })();
    let _lastDate = new Date().toLocaleDateString('en-CA', {timeZone: _tz});
    setInterval(() => {
      try {
        const _tz2 = (function(){ try{ return localTz(); }catch(e){ return 'UTC'; } })();
        const _nowDate = new Date().toLocaleDateString('en-CA', {timeZone: _tz2});
        if (_nowDate !== _lastDate) {
          _lastDate = _nowDate;
          if (typeof viewingISO !== 'undefined' && typeof TODAY_ISO !== 'undefined' &&
              viewingISO === TODAY_ISO && typeof fetchSchedule === 'function') {
            fetchSchedule();
          }
        }
      } catch(e_mid) {}
    }, 60000);
  })();
} catch(e_mid_outer) {} // swallow — must not block fetchSchedule()

