// ── Page Visibility API ───────────────────────────────────────────────────
// Pause polling when app is backgrounded (saves battery + API quota).
// Resume immediately on return — stale scores fix themselves within one poll.
document.addEventListener('visibilitychange', () => {
  if (document.visibilityState === 'hidden') {
    // Pause: cancel scheduled poll
    if (espnIntervalId) { clearTimeout(espnIntervalId); espnIntervalId = null; }
    if (FIELD_DEBUG) console.log('[Visibility] app hidden — polling paused');
  } else {
    // Resume: immediate fetch + restart normal cycle
    if (FIELD_DEBUG) console.log('[Visibility] app visible — resuming polls');
    if (espnIntervalId === null) fetchESPNScores(); // only if we paused it
  }
});

