// ── NHL Analytics Wave 1 ──────────────────────────────────────────────────────
// Source: NHL Stats API probe May 27 2026 — outbox/nhl/nhl-analytics-probe-*.json
// All figures: 2026 playoffs (seasonId=20252026, gameTypeId=3).
// ADR-NHL-001: hardcode STABLE data (stats), never COUNTERS (wins, standings).
// Test: "Will this be wrong next week?" — percentages change slowly → stable.
//
// PRECAUTIONS (learned from MLB Wave 1):
//   1. Key format confirmed via probe — NOT guessed.
//   2. getNHLAbbrev() normalises accents so "Montréal" = "Montreal" (probe showed
//      API uses é; FIELD game data and NHL_ABBREV_MAP do not).
//   3. _homeAbbr/_awayAbbr set by nhlAnalyticsInit() on all NHL game objects.
//      Badges/getters never call getNHLAbbrev() without this being set first.
//   4. Smoke assertions (A207-A210) check field PRESENCE and key CORRECTNESS,
//      not just syntax.

// Reverse map: "Carolina Hurricanes" → "CAR"
// Derived from NHL_ABBREV_MAP — single source of truth.
const NHL_NAME_TO_ABBREV = Object.fromEntries(
  Object.entries(NHL_ABBREV_MAP).map(([a,n])=>[n,a])
);

// Full name → abbreviation with accent normalisation
function getNHLAbbrev(fullName) {
  if (!fullName) return null;
  const d = NHL_NAME_TO_ABBREV[fullName];
  if (d) return d;
  // Normalise: strip combining diacritics (é→e, ü→u etc.)
  const norm = s => s.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim();
  const q = norm(fullName);
  for (const [abbrev, name] of Object.entries(NHL_ABBREV_MAP)) {
    if (norm(name) === q) return abbrev;
  }
  return null;
}

