// ── Getters ───────────────────────────────────────────────────────────────────

function getNHLSpecialTeams(abbrev) {
  if (!abbrev) return null;
  const entry = NHL_SPECIAL_TEAMS[abbrev];
  if (!entry) return null;
  // Return with series-adjusted overlay if available (_seriesPP/_seriesPK from nhlSeriesInit)
  // Consumers should prefer _seriesPP/PK when present (more relevant during active series)
  return entry;
}

// Returns the most relevant PP%/PK% for journalism context:
// series-adjusted during active SCF, season stats otherwise.
function getNHLEffectiveST(abbrev) {
  const st = getNHLSpecialTeams(abbrev);
  if (!st) return null;
  return {
    ...st,
    effectivePP:  st._seriesPP  != null ? st._seriesPP  : st.pp,
    effectivePK:  st._seriesPK  != null ? st._seriesPK  : st.pk,
    seriesPDO:    st._seriesPDO ?? null,
    ppContext:    st._ppLabel   || `${st.pp}% PP (season)`,
    pkContext:    st._pkLabel   || `${st.pk}% PK (season)`,
    pdoContext:   st._pdoLabel  || null,
    isSeries: st._seriesPP != null,
  };
}

function getNHLGoalieProfile(lastName) {
  if (!lastName) return null;
  const key = lastName.toLowerCase().replace(/[^a-z]/g,'');
  return NHL_GOALIE_RATINGS[key] || null;
}

// Returns 2-4 context lines for compound prompt; empty string if no data.
function getNHLAnalyticsContext(game) {
  if (!game) return '';
  const lines = [];
  try {
    const ha = game._homeAbbr || getNHLAbbrev(game.home);
    const aa = game._awayAbbr || getNHLAbbrev(game.away);

    // ── [SCF MATCHUP] anchor (PM-18 Item C, June 2 2026) ─────────────────────
    // Parallels existing NBA [WCF CHAMPION] / [CHAMPION] anchors in
    // getNBAAnalyticsContext. Closes the 'tighten their grip on the Cup'
    // hallucination diagnosed PM-18 (4:31pm screenshot) — model improvised a
    // current-cup-holder narrative because nothing in the prompt grounded
    // who actually holds the trophy vs who is playing for it.
    //
    // Static for the 2026 Stanley Cup Final. CAR last won 2006 (20 years);
    // VGK won 2023 (3 years ago) — neither team holds the current (2025) Cup.
    // The Finals matchup is open; neither team is 'defending' the title.
    const isSCF = /stanley cup final|\bSCF\b/i.test(game.league || '');
    if (isSCF) {
      if (ha === 'CAR' || aa === 'CAR') {
        lines.push(`[SCF MATCHUP] Carolina Hurricanes — first Stanley Cup Final since winning it in 2006 (20 years). Fourth conference-final breakthrough attempt since 2019; lost the prior three.`);
      }
      if (ha === 'VGK' || aa === 'VGK') {
        lines.push(`[SCF MATCHUP] Vegas Golden Knights — third Cup Final in nine years as a franchise (won 2023, lost 2018). Under late-season hire John Tortorella, who took over from Bruce Cassidy with 10 games left in the regular season.`);
      }
      // Trophy anchor — neither team holds the current Cup
      lines.push(`[SCF TROPHY] Neither team is defending the Stanley Cup. The Finals is open. Do NOT write 'tighten grip on the Cup', 'defend the Cup', or 'reigning champion' framings for either side.`);
    }

    // Use series-adjusted rates when available (nhlSeriesInit overlays _seriesPP/_seriesPK)
    const hST = getNHLEffectiveST(ha);
    const aST = getNHLEffectiveST(aa);

    if (hST && aST) {
      const seriesNote = hST.isSeries ? ' (series)' : '';
      // Power play — use effective (series-adjusted when available)
      const ppParts = [];
      if (hST.effectivePP >= 20) ppParts.push(`${teamNick(game.home||'')} ${hST.effectivePP.toFixed(1)}% PP${seriesNote}`);
      if (aST.effectivePP >= 20) ppParts.push(`${teamNick(game.away||'')} ${aST.effectivePP.toFixed(1)}% PP${seriesNote}`);
      if (hST.effectivePP <= 10) ppParts.push(`${teamNick(game.home||'')} ${hST.effectivePP.toFixed(1)}% PP (league-worst)${seriesNote}`);
      if (aST.effectivePP <= 10) ppParts.push(`${teamNick(game.away||'')} ${aST.effectivePP.toFixed(1)}% PP (league-worst)${seriesNote}`);
      if (ppParts.length) lines.push(`[PP/PK] ${ppParts.join(' · ')} | PK: ${ha} ${hST.effectivePK.toFixed(1)}%${seriesNote} · ${aa} ${aST.effectivePK.toFixed(1)}%${seriesNote}`);

      // PDO — series window luck indicator (only when series data loaded)
      if (hST.seriesPDO != null && aST.seriesPDO != null) {
        const pdoParts = [];
        if (hST.seriesPDO > 1.010) pdoParts.push(`${ha} PDO ${hST.seriesPDO.toFixed(3)} — running hot, regression possible`);
        else if (hST.seriesPDO < 0.990) pdoParts.push(`${ha} PDO ${hST.seriesPDO.toFixed(3)} — running cold, due for improvement`);
        if (aST.seriesPDO > 1.010) pdoParts.push(`${aa} PDO ${aST.seriesPDO.toFixed(3)} — running hot, regression possible`);
        else if (aST.seriesPDO < 0.990) pdoParts.push(`${aa} PDO ${aST.seriesPDO.toFixed(3)} — running cold, due for improvement`);
        if (pdoParts.length) lines.push(`[PDO] ${pdoParts.join(' · ')}`);
      }

      // Possession — flag SAT gap > 8 or either team extreme
      const satGap = Math.abs(hST.sat - aST.sat);
      const domTeam = hST.sat > aST.sat ? game.home : game.away;
      const domSat  = Math.max(hST.sat, aST.sat);
      if (satGap >= 8)   lines.push(`[POSSESSION] ${teamNick(domTeam||'')} controls ${domSat.toFixed(0)}% of shot attempts (SAT — Corsi proxy)`);
      else if (domSat >= 55) lines.push(`[POSSESSION] ${ha} ${hST.sat.toFixed(0)}% SAT · ${aa} ${aST.sat.toFixed(0)}% SAT`);

      // Faceoff dominance
      const foGap = Math.abs(hST.fo - aST.fo);
      if (foGap >= 8) {
        const foTeam = hST.fo > aST.fo ? game.home : game.away;
        const foWin  = Math.max(hST.fo, aST.fo);
        lines.push(`[FACEOFFS] ${teamNick(foTeam||'')} wins ${foWin.toFixed(0)}% of draws — possession starts controlled`);
      }
    }

    // Goalie matchup (set by fetchNHLRelayScores when starting goalies are announced)
    const hG = getNHLGoalieProfile(game._homeGoalie);
    const aG = getNHLGoalieProfile(game._awayGoalie);
    if (hG && aG) {
      // Use GSAX (true goals saved above expected) when MoneyPuck R2 data is loaded
      // Falls back to save% proxy when GSAX unavailable
      const hTier = hG._gsaxTier || hG.tier;
      const aTier = aG._gsaxTier || aG.tier;
      const hGSAX = hG._gsax;
      const aGSAX = aG._gsax;
      const svGap = Math.abs(hG.sv - aG.sv);

      if (hTier === 'elite' && aTier === 'elite') {
        const gsaxNote = (hGSAX != null && aGSAX != null)
          ? ` · GSAX: ${hGSAX > 0 ? '+' : ''}${hGSAX.toFixed(1)} / ${aGSAX > 0 ? '+' : ''}${aGSAX.toFixed(1)}`
          : '';
        lines.push(`[GOALIE DUEL] Both starters elite: ${game._homeGoalie} .${Math.round(hG.sv*1000)} sv% · ${game._awayGoalie} .${Math.round(aG.sv*1000)} sv%${gsaxNote}`);
      } else if (svGap >= 0.015) {
        const betterG = hG.sv > aG.sv ? `${game._homeGoalie} (${teamNick(game.home||'')})` : `${game._awayGoalie} (${teamNick(game.away||'')})`;
        const betterGSAX = hG.sv > aG.sv ? hGSAX : aGSAX;
        const gsaxNote = betterGSAX != null ? ` · GSAX +${betterGSAX.toFixed(1)} this playoff run` : '';
        lines.push(`[GOALIE EDGE] ${betterG} — .${Math.round(Math.max(hG.sv,aG.sv)*1000)} vs .${Math.round(Math.min(hG.sv,aG.sv)*1000)} sv%${gsaxNote}`);
      }
    } else if (hG || aG) {
      const g = hG || aG;
      const name = hG ? game._homeGoalie : game._awayGoalie;
      if (g._gsaxTier === 'elite' || g.tier === 'elite')
        lines.push(`[GOALIE] ${name} elite this playoffs: .${Math.round(g.sv*1000)} sv%, ${g.gaa.toFixed(2)} GAA`);
    }

    // ── Tier A #1 — Pull Window Predictor (live, 3rd period only)
    const pullSig = predictGoaliePullState(game);
    if (pullSig) lines.push(pullSig.line);

    // ── Tier A #2 — PDO Regression Signal (forward-looking variance call)
    const hPDO_t = getNHLPDOSignal(ha);
    const aPDO_t = getNHLPDOSignal(aa);
    if (hPDO_t) lines.push(hPDO_t.line);
    if (aPDO_t) lines.push(aPDO_t.line);

    // ── Tier A #3 — Penalty Drift Indicator (live, needs game-state counts)
    const driftSig = computePenaltyDriftSignal(game._homePenalties, game._awayPenalties, ha, aa);
    if (driftSig) lines.push(driftSig.line);

  } catch(e) { if(FIELD_DEBUG) console.error('[NHL Analytics]', e.message); }
  return lines.join('\n');
}

// ── NHL PDO (luck indicator) ──────────────────────────────────────────────────
// PDO = team shooting% × 1000 + team sv% × 1000. League average = 1000.
// Above 1020 = likely running hot; below 980 = likely unlucky.
// Source: Natural Stat Trick (5-on-5, playoffs).
// [VERIFY] values after each series against naturalstattrick.com
const NHL_PDO = {
  'CAR': { pdo: 1012, shoot: 8.4, note: 'Process-driven — possession dominance (57% SAT) backs results' },  // [VERIFY]
  'VGK': { pdo: 1018, shoot: 9.4, note: 'Hart elite, PP converting — slightly elevated but within range' }, // [VERIFY]
  'COL': { pdo: 1008, shoot: 9.2, note: null },
  'MTL': { pdo: 992,  shoot: 8.1, note: 'Underperforming xG — Dobes keeping them alive' },
  'BOS': { pdo: 985,  shoot: 7.4, note: null },
  'OTT': { pdo: 976,  shoot: 7.8, note: null },
};

function getNHLPDO(abbrev) {
  return abbrev ? (NHL_PDO[abbrev] || null) : null;
}

// ── NHL Game Character Predictor ─────────────────────────────────────────────
// Combines possession (SAT), special teams, goalie tiers → game archetype.
// Returns { label, badge, rationale } or null if insufficient data.
// Wave 2 — built May 31 2026.
function predictNHLGameCharacter(game) {
  if (!game) return null;
  const ha = game._homeAbbr || getNHLAbbrev(game.home);
  const aa = game._awayAbbr || getNHLAbbrev(game.away);
  const hST = getNHLEffectiveST(ha);
  const aST = getNHLEffectiveST(aa);
  const hG  = getNHLGoalieProfile(game._homeGoalie);
  const aG  = getNHLGoalieProfile(game._awayGoalie);
  if (!hST || !aST) return null;

  // Both goalies elite + both PK above 85 → GOALIE DUEL
  const bothElite = hG?.tier === 'elite' && aG?.tier === 'elite';
  const bothSolidPK = hST.pk >= 84 && aST.pk >= 84;
  if (bothElite && bothSolidPK)
    return { label: 'GOALIE DUEL', badge: '[GOALIE DUEL]',
      rationale: `${game._homeGoalie||ha} vs ${game._awayGoalie||aa} — both elite. Tight game, likely decided by one mistake.` };

  // Big PP vs elite PK → SPECIAL TEAMS BATTLE
  const ppGap = Math.abs(hST.pp - aST.pp);
  const onePPElite = Math.max(hST.pp, aST.pp) >= 22;
  const onePKElite = Math.min(hST.pk, aST.pk) >= 88;
  if (ppGap >= 10 && onePPElite && onePKElite)
    return { label: 'SPECIAL TEAMS BATTLE', badge: '[SPECIAL TEAMS]',
      rationale: `${hST.pp > aST.pp ? ha : aa} PP (${Math.max(hST.pp,aST.pp).toFixed(1)}%) meets elite PK (${Math.max(hST.pk,aST.pk).toFixed(1)}%). Special teams decide this.` };

  // Large possession gap + one goalie elite → POSSESSION FIGHT
  const satGap = Math.abs(hST.sat - aST.sat);
  const domTeam = hST.sat > aST.sat ? ha : aa;
  if (satGap >= 8 && (hG?.tier === 'elite' || aG?.tier === 'elite'))
    return { label: 'POSSESSION FIGHT', badge: '[POSSESSION FIGHT]',
      rationale: `${domTeam} owns the puck (${Math.max(hST.sat,aST.sat).toFixed(0)}% SAT) but faces an elite goalie. The question is whether the territorial advantage converts.` };

  // Both teams bottom-10 defense (proxy: both PK < 80, high-scoring game likely)
  if (hST.pk < 80 && aST.pk < 80)
    return { label: 'HIGH-SCORING', badge: '[HIGH SCORING]',
      rationale: `Both teams vulnerable on penalty kill. Goals come in bunches.` };

  return null; // insufficient signal for a strong prediction
}

// ── NHL Pull Window Predictor (Tier A #1, June 2 2026) ──────────────────────
// Forward-looking prediction of goalie-pull windows from clock + deficit.
// Distinct from #11a (which fires on ESPN sit.goaliePulled AFTER pull happens).
// This predicts ~90s BEFORE pull is likely, enabling drama amplification.
//
// Phase logic (regulation 3rd period only — no pull in playoff sudden-death OT):
//   deficit 1 → window opens 3:00 left → likely pulled 1:30 left
//   deficit 2 → window opens 4:00 left → likely pulled 2:30 left
//   deficit 3 → window opens 5:00 left → likely pulled 3:30 left
// Pre-3rd, OT, or post-game → null.
//
// Returns { phase, badge, line, trailingTeam, secondsRemaining } or null.
function predictGoaliePullState(game) {
  if (!game) return null;
  const sp = (game._sport || '').toLowerCase();
  if (!sp.includes('nhl') && !sp.includes('hockey')) return null;
  if ((game.state || '') !== 'in') return null;

  const period = parseInt(game.period) || 0;
  if (period !== 3) return null; // pre-3rd or OT — no standard pull window

  // Parse "M:SS" clock string to seconds
  const clockStr = String(game.clock || '').trim();
  const m = clockStr.match(/^(\d+):(\d{2})$/);
  if (!m) return null;
  const secs = parseInt(m[1]) * 60 + parseInt(m[2]);
  if (secs <= 0) return null;

  const hs = parseInt(game.homeScore) || 0;
  const as = parseInt(game.awayScore) || 0;
  const diff = Math.abs(hs - as);
  if (diff === 0 || diff > 3) return null; // tied or out-of-reach (4+)

  // Trailing team
  const trailingTeam = hs < as ? game.home : game.away;
  const trailingAbbr = hs < as
    ? (game._homeAbbr || getNHLAbbrev?.(game.home))
    : (game._awayAbbr || getNHLAbbrev?.(game.away));

  // Thresholds in seconds
  const TH = { 1:{open:180, pull: 90}, 2:{open:240, pull:150}, 3:{open:300, pull:210} }[diff];
  if (!TH || secs > TH.open) return null;

  const phase = secs <= TH.pull ? 'likely_pulled' : 'window_approaching';
  const teamNickFn = (typeof teamNick === 'function') ? teamNick : (s => s || '');
  const nick = teamNickFn(trailingTeam || trailingAbbr || '');

  if (phase === 'likely_pulled') {
    return {
      phase: 'likely_pulled',
      badge: '[6-ON-5 LIKELY]',
      line: `[6-ON-5 LIKELY] ${nick} trail ${diff}, ${clockStr} left — empty-net window active`,
      trailingTeam: trailingAbbr || trailingTeam,
      secondsRemaining: secs,
    };
  }
  const pullM = Math.floor(TH.pull/60), pullS = TH.pull % 60;
  const pullStr = `${pullM}:${String(pullS).padStart(2,'0')}`;
  return {
    phase: 'window_approaching',
    badge: '[PULL WINDOW]',
    line: `[PULL WINDOW APPROACHING] ${nick} trail ${diff}, ${clockStr} left — pull becomes likely inside ${pullStr}`,
    trailingTeam: trailingAbbr || trailingTeam,
    secondsRemaining: secs,
  };
}

// ── NHL PDO Regression Signal (Tier A #2, June 2 2026) ──────────────────────
// Reads NHL_PDO and surfaces forward-looking regression direction.
// Above 1020 = running hot, regression DOWN due. Below 985 = unlucky, UP due.
// Returns { tag, direction, line } or null if abbrev absent / PDO neutral.
function getNHLPDOSignal(abbrev) {
  if (!abbrev) return null;
  const p = NHL_PDO?.[abbrev];
  if (!p || typeof p.pdo !== 'number') return null;
  if (p.pdo > 1020) {
    return {
      tag: 'RUNNING HOT',
      direction: 'down',
      line: `[REGRESSION WATCH] ${abbrev} PDO ${p.pdo} — running hot, due for negative variance`,
    };
  }
  if (p.pdo < 985) {
    return {
      tag: 'REGRESSION DUE',
      direction: 'up',
      line: `[REGRESSION DUE] ${abbrev} PDO ${p.pdo} — underperforming, due for positive variance`,
    };
  }
  return null; // within normal band 985–1020
}

// ── NHL Penalty Drift Indicator (Tier A #3, June 2 2026) ────────────────────
// Refs even out calls within a game. A 2+ penalty deficit predicts a make-up
// call statistically. This function accepts in-game penalty counts and outputs
// the drift signal. Counts wired via trackNHLPenaltyTransitions (below).
//
// Returns { team, deficit, line } or null if no drift or insufficient data.
function computePenaltyDriftSignal(homePenalties, awayPenalties, homeAbbr, awayAbbr) {
  const hp = parseInt(homePenalties);
  const ap = parseInt(awayPenalties);
  if (!Number.isFinite(hp) || !Number.isFinite(ap)) return null;
  const drift = Math.abs(hp - ap);
  if (drift < 2) return null;
  // Team with FEWER penalties is statistically due to take the next one
  const dueTeam = hp > ap ? awayAbbr : homeAbbr;
  const undisciplined = hp > ap ? homeAbbr : awayAbbr;
  if (!dueTeam || !undisciplined) return null;
  return {
    team: dueTeam,
    deficit: drift,
    line: `[MAKE-UP CALL DUE] ${undisciplined} ${Math.max(hp,ap)} PIMs, ${dueTeam} ${Math.min(hp,ap)} — next call statistically tilts ${dueTeam}'s way`,
  };
}

// Penalty inference: when ESPN situation flips a team OFF power-play,
// the opposing team took a penalty. Tracks counts on game object via
// game._homePenalties / game._awayPenalties. Idempotent.
// Called from fetchESPNScores poll cycle (caller-side wiring).
function trackNHLPenaltyTransitions(game, prevSit, curSit) {
  if (!game || !curSit) return;
  // Initialise counters once
  if (typeof game._homePenalties !== 'number') game._homePenalties = 0;
  if (typeof game._awayPenalties !== 'number') game._awayPenalties = 0;
  if (!prevSit) return; // need a prior snapshot to detect transitions
  // Home PP just ENDED → away took the penalty (kill expired or scored on)
  // We can't disambiguate kill-expire vs PP-goal cheaply, so we increment on
  // the START of PP, not the end. Edge: missed if first poll catches mid-PP.
  if (curSit.homePowerPlay && !prevSit.homePowerPlay) game._awayPenalties++;
  if (curSit.awayPowerPlay && !prevSit.awayPowerPlay) game._homePenalties++;
}

// ── buildScoutingReport — raw analytics for bottom sheet ─────────────────────
// Shows the underlying numbers the AI uses — so users can see WHERE IT COMES FROM.
// Sport-detected: MLB shows park/umpire/pitcher data; NHL shows possession/ST/goalie.
// Returns HTML string or '' if no data available.
function buildScoutingReport(game, sport) {
  if (!game) return '';
  const sp = (sport || game._sport || '').toLowerCase();
  const rows = [];

  // ── MLB ────────────────────────────────────────────────────────────────────
  if (sp.includes('baseball') || sp.includes('mlb')) {
    // Park factor
    const abbr = game._homeAbbr || game.homeTeam;
    const pf = abbr ? getParkFactor?.(abbr) : null;
    if (pf) {
      const runDiff = pf.runFactor - 100;
      const hrDiff  = pf.hrFactor  - 100;
      const pfVal = runDiff > 0
        ? `<em>+${runDiff}% runs</em> · +${hrDiff}% HR${pf.badgeClass === 'park-hitter-extreme' ? ' · 🚀 Launch Pad' : ''}`
        : `<span class="scout-warn">${runDiff}% runs</span> · ${hrDiff}% HR${pf.badgeClass === 'park-pitcher' || pf.badgeClass === 'park-pitcher-extreme' ? ' · 🛡 Pitcher\'s Park' : ''}`;
      rows.push({ lbl: 'Park', val: `${pf.label || (game.venue ? game.venue.split(',')[0] : abbr)} · ${pfVal}` });
    }
    // HP Umpire
    const umpName = game._hpUmpire || game.umpire || '';
    if (umpName) {
      const last = umpName.split(' ').pop();
      const ump = getUmpireABSRating?.(last);
      if (ump) {
        const rate = Math.round(ump.rate * 100);
        const watchFlag = ump.rate >= 0.65 ? ' · <span class="scout-warn">⚠ UMP WATCH</span>' : '';
        const zone = ump.weakness ? ` · weak: ${ump.weakness} zone` : '';
        rows.push({ lbl: 'Umpire', val: `${last} · ${rate}% overturns · ${ump.challenged} challenged${zone}${watchFlag}` });
      } else {
        rows.push({ lbl: 'Umpire', val: umpName });
      }
    }
    // Probable pitchers
    const hp = game.homePitcher, ap = game.awayPitcher;
    if (hp || ap) {
      const fmtP = p => {
        if (!p) return 'TBD';
        const era = p.era != null ? ` · ${p.era} ERA` : '';
        const rec = (p.wins != null && p.losses != null) ? ` · ${p.wins}-${p.losses}` : '';
        // getPitchTempo/getPitchArsenal (PITCHER_TEMPO/PITCHER_ARSENAL) are
        // keyed by last-name-only, but p.name (from normalizeMLBPitcher) is
        // always a full name — extract the last name once via the shared
        // lastNameOf() helper (index.html ~L7622) and reuse it for both
        // lookups. Without this, either line silently never matches and
        // never renders (CC-CMD-2026-07-01 scouting-report-arsenal + -tempo-fix).
        const pLast = lastNameOf(p);
        const tempo = getPitchTempo?.(pLast);
        const tempoStr = tempo ? ` · <em>${tempo.tempoClass}</em> tempo` : '';
        const arsenal = getPitchArsenal?.(pLast);
        // Skip the line entirely when whiffRate is null (source CSV's
        // whiff_percent empty for this pitch) rather than show a false "0%
        // whiff" — null is "no data", not "zero whiffs".
        const arsenalStr = (arsenal?.topWhiff && arsenal.topWhiff.whiffRate != null)
          ? ` · <em>${arsenal.topWhiff.type}</em> ${Math.round(arsenal.topWhiff.whiffRate * 100)}% whiff`
          : '';
        return `${p.name || p.lastName || '?'}${era}${rec}${tempoStr}${arsenalStr}`;
      };
      if (ap) rows.push({ lbl: teamNick(game.away||''), val: fmtP(ap) });
      if (hp) rows.push({ lbl: teamNick(game.home||''), val: fmtP(hp) });
    }
  }

  // ── NHL ────────────────────────────────────────────────────────────────────
  if (sp.includes('hockey') || sp.includes('nhl')) {
    const ha = game._homeAbbr || getNHLAbbrev?.(game.home);
    const aa = game._awayAbbr || getNHLAbbrev?.(game.away);
    const hST = ha ? getNHLSpecialTeams?.(ha) : null;
    const aST = aa ? getNHLSpecialTeams?.(aa) : null;
    if (hST && aST) {
      const hSatStr = hST.sat > aST.sat ? `<em>${ha} ${hST.sat.toFixed(0)}% SAT</em>` : `${ha} ${hST.sat.toFixed(0)}% SAT`;
      const aSatStr = aST.sat > hST.sat ? `<em>${aa} ${aST.sat.toFixed(0)}% SAT</em>` : `${aa} ${aST.sat.toFixed(0)}% SAT`;
      const satEdge = Math.abs(hST.sat - aST.sat) >= 8 ? ` · <em>+${Math.abs(hST.sat - aST.sat).toFixed(0)}% edge ${hST.sat > aST.sat ? ha : aa}</em>` : '';
      rows.push({ lbl: 'Possession', val: `${hSatStr} · ${aSatStr}${satEdge}` });
      rows.push({ lbl: 'Special Tm',
        val: `${ha} PP <em>${hST.pp.toFixed(1)}%</em> · PK <em>${hST.pk.toFixed(1)}%</em>` +
             `  |  ${aa} PP <em>${aST.pp.toFixed(1)}%</em> · PK <em>${aST.pk.toFixed(1)}%</em>` });
      if (Math.abs(hST.fo - aST.fo) >= 4)
        rows.push({ lbl: 'Faceoffs',
          val: `${ha} ${hST.fo.toFixed(0)}%  ·  ${aa} ${aST.fo.toFixed(0)}%` +
               (hST.fo > aST.fo + 6 || aST.fo > hST.fo + 6
                 ? ` · <em>${hST.fo > aST.fo ? ha : aa} wins the draws</em>` : '') });
    }
    // Goalies
    const hG = game._homeGoalie ? getNHLGoalieProfile?.(game._homeGoalie) : null;
    const aG = game._awayGoalie ? getNHLGoalieProfile?.(game._awayGoalie) : null;
    const hGname = game._homeGoalie, aGname = game._awayGoalie;
    if (hG && aG) {
      const hTier = hG.tier === 'elite' ? ' 🔵' : hG.tier === 'below' ? ' 🔴' : '';
      const aTier = aG.tier === 'elite' ? ' 🔵' : aG.tier === 'below' ? ' 🔴' : '';
      rows.push({ lbl: 'Goalies',
        val: `${hGname} <em>.${Math.round(hG.sv*1000)}</em>${hTier}  ·  ${aGname} <em>.${Math.round(aG.sv*1000)}</em>${aTier}` });
    } else if (hG || aG) {
      const g = hG||aG, n = hGname||aGname;
      const tier = g.tier === 'elite' ? ' 🔵' : g.tier === 'below' ? ' 🔴' : '';
      rows.push({ lbl: 'Goalie', val: `${n} <em>.${Math.round(g.sv*1000)} sv%</em> · ${g.gaa.toFixed(2)} GAA${tier}` });
    }
  }

  if (!rows.length) return '';
  const rowsHTML = rows.map(r =>
    `<div class="bs-scout-row"><span class="bs-scout-lbl">${r.lbl}</span><span class="bs-scout-val">${r.val}</span></div>`
  ).join('');

  // NBA: append live lineup edge section from RAI cache (no new fetch — reads existing cache)
  let raiSection = '';
  if (sp.includes('basketball') || sp.includes('nba')) {
    // Look up RAI cache: try espnId first, then home|away (cross-keyed in fetchRosterAdvantage)
    const _raiEspnId = game._espnId || '';
    const _raiLabelKey = `${game.home||''}|${game.away||''}`; 
    const rai = _raiCache[_raiEspnId] || _raiCache[_raiLabelKey] || null;
    if (rai) raiSection = buildRaiSheetSection(rai, game.home||'', game.away||'');
  }

  // MLB: append platoon context from MLB live feed cache
  if (sp.includes('baseball') || sp.includes('mlb')) {
    const labelKey = `${game.home||''}|${game.away||''}`;
    const platoonEntry = _mlbPlatoonCache[game.sourceId] || _mlbPlatoonCache[labelKey];
    const p = platoonEntry?.result;
    if (p?.platoonLabel) {
      const edgeCls = p.platoonEdge === 'batter' ? 'rai-pos' : p.platoonEdge === 'pitcher' ? 'rai-neg' : '';
      const countLine = p.countLabel ? `<div style="font-size:.63rem;color:var(--smoke);margin-top:.15rem">${p.countLabel}</div>` : '';
      // Live current-pitcher arsenal/tempo — updates every at-bat including
      // reliever substitutions, unlike the Scouting Report's one-time
      // pre-game starter line (CC-CMD-2026-07-01 atbat-edge-arsenal).
      const pitcherLast = p.pitcherName ? lastNameOf(p.pitcherName) : '';
      const pArsenal = pitcherLast ? getPitchArsenal?.(pitcherLast) : null;
      const pTempo   = pitcherLast ? getPitchTempo?.(pitcherLast)   : null;
      const arsenalStr = (pArsenal?.topWhiff && pArsenal.topWhiff.whiffRate != null)
        ? ` · <em>${pArsenal.topWhiff.type}</em> ${Math.round(pArsenal.topWhiff.whiffRate * 100)}% whiff`
        : '';
      const tempoStr = pTempo ? ` · <em>${pTempo.tempoClass}</em> tempo` : '';
      raiSection = `<div class="bs-section">
        <div class="bs-section-label">At-Bat Edge</div>
        <div class="bs-section-body">
          <div class="rai-row"><span class="rai-lbl">Matchup</span><span class="rai-val ${edgeCls}">${p.platoonLabel}</span></div>
          ${p.batterName ? `<div class="rai-row"><span class="rai-lbl">Batter</span><span style="font-size:.67rem">${p.batterName}</span></div>` : ''}
          ${p.pitcherName ? `<div class="rai-row"><span class="rai-lbl">Pitcher</span><span style="font-size:.67rem">${p.pitcherName}${arsenalStr}${tempoStr}</span></div>` : ''}
          ${countLine}
        </div>
      </div>`;
    }
  }

  return `<div class="bs-section">
    <div class="bs-section-label">Scouting Report</div>
    <div class="bs-section-body"><div class="bs-scout-table">${rowsHTML}</div></div>
  </div>${raiSection}`;
}


// Badge builder: [SPECIAL TEAMS] and [POSSESSION] chips on NHL cards
function buildNHLAnalyticsBadges(game) {
  if (!game) return '';
  const sp = (game._sport||'').toLowerCase();
  if (!sp.includes('hockey') && !sp.includes('nhl')) return '';
  const ha = game._homeAbbr || getNHLAbbrev(game.home);
  const aa = game._awayAbbr || getNHLAbbrev(game.away);
  const hST = getNHLSpecialTeams(ha);
  const aST = getNHLSpecialTeams(aa);
  if (!hST || !aST) return '';
  const badges = [];
  // [SPECIAL TEAMS] — one team elite PP (≥25%) vs elite PK (≥88%)
  if ((hST.pp >= 25 || aST.pp >= 25) && (hST.pk >= 88 || aST.pk >= 88))
    badges.push(`<span class="nhl-badge nhl-st" title="PP: ${ha} ${hST.pp}% · ${aa} ${aST.pp}% | PK: ${ha} ${hST.pk}% · ${aa} ${aST.pk}%">⚡ SPECIAL TEAMS</span>`);
  // [POSSESSION] — SAT gap ≥ 8%
  const satGap = Math.abs(hST.sat - aST.sat);
  if (satGap >= 8) {
    const leader = hST.sat > aST.sat ? ha : aa;
    const leadSat = Math.max(hST.sat, aST.sat);
    badges.push(`<span class="nhl-badge nhl-pos" title="Corsi: ${ha} ${hST.sat}% · ${aa} ${aST.sat}%">🏒 ${leader} ${leadSat.toFixed(0)}% SAT</span>`);
  }
  return badges.join('');
}

