// ── NBA Analytics Context (Wave 1 — parallel to getNHLAnalyticsContext) ──────
// Returns 2-4 context lines for compound journalism prompt.
// Injected automatically for all NBA games.
function getNBAAnalyticsContext(game) {
  if (!game) return '';
  const lines = [];
  try {
    const hStats = getNBATeamAnalytics(game.home);
    const aStats = getNBATeamAnalytics(game.away);

    // Defending champion context — surfaces in all OKC journalism
    if (hStats?.champion) lines.push(`[CHAMPION] ${game.home} are the defending NBA champions (2024-25 — defeated Pacers in 7 games, SGA Finals MVP). Ousted by SAS in 2026 WCF G7.`);
    else if (aStats?.champion) lines.push(`[CHAMPION] ${game.away} are the defending NBA champions (2024-25 — defeated Pacers in 7 games, SGA Finals MVP). Ousted by SAS in 2026 WCF G7.`);

    // WCF champion context — surfaces in SAS journalism
    const hSASAbbr = getNBAAbbrev(game.home);
    const aSASAbbr = getNBAAbbrev(game.away);
    if (hSASAbbr === 'SAS') lines.push(`[WCF CHAMPION] San Antonio Spurs are the 2026 Western Conference Champions — defeated defending champion OKC in 7 games. Wembanyama 28.2 PPG this postseason. First Finals since 2014.`);
    else if (aSASAbbr === 'SAS') lines.push(`[WCF CHAMPION] San Antonio Spurs are the 2026 Western Conference Champions — defeated defending champion OKC in 7 games. Wembanyama 28.2 PPG this postseason. First Finals since 2014.`);

    if (hStats && aStats) {
      const avgPace = ((hStats.pace + aStats.pace) / 2);
      const leagueAvg = 100.8;
      const bothEliteD = hStats.drtg <= 111 && aStats.drtg <= 111;

      // Pace badge
      if (avgPace >= 103)  lines.push(`[FAST PACE] Both teams fast (avg ${avgPace.toFixed(0)} poss/48 — league avg ${leagueAvg}). Expect a track meet.`);
      else if (avgPace <= 98) lines.push(`[SLOW GRIND] Both teams halfcourt (avg ${avgPace.toFixed(0)} poss/48 — below league avg). Defense drives this game.`);

      // Defense matchup
      const betterD = hStats.drtg < aStats.drtg ? game.home : game.away;
      const betterDrtg = Math.min(hStats.drtg, aStats.drtg);
      if (bothEliteD) lines.push(`[ELITE D BOTH] ${game.home} ${hStats.drtg.toFixed(1)} DRTG (Rank ${hStats.drtgRank}) · ${game.away} ${aStats.drtg.toFixed(1)} DRTG (Rank ${aStats.drtgRank}). Both top-5 defenses.`);
      else if (betterDrtg <= 109) lines.push(`[DEFENSE EDGE] ${betterD} elite defense (${betterDrtg.toFixed(1)} DRTG, Rank ${Math.min(hStats.drtgRank,aStats.drtgRank)}).`);

      // Efficiency gap (potential mismatch)
      const effGap = Math.abs(hStats.ortg - aStats.drtg);
      if (effGap >= 8) {
        const offTeam = hStats.ortg > aStats.ortg ? game.home : game.away;
        lines.push(`[MISMATCH ALERT] ${offTeam} ORTG vs opponent DRTG — significant offensive advantage on paper.`);
      }
    }

    // Team-level clutch DRTG from R2 (nbaCluichInit fills clutchDrtg/clutchNetRtg)
    if (hStats?.clutchDrtg != null && aStats?.clutchDrtg != null) {
      const hCDrtg = hStats.clutchDrtg;
      const aCDrtg = aStats.clutchDrtg;
      const clutchGap = Math.abs(hCDrtg - aCDrtg);
      const betterDefTeam = hCDrtg < aCDrtg ? game.home : game.away;
      const betterCDrtg   = Math.min(hCDrtg, aCDrtg);
      const worseCDrtg    = Math.max(hCDrtg, aCDrtg);
      if (betterCDrtg <= 108) {
        lines.push(`[TEAM CLUTCH] ${betterDefTeam} ${betterCDrtg.toFixed(1)} DRTG in clutch situations (last 5 min, within 5 pts) — elite late-game defense.`);
      } else if (clutchGap >= 5) {
        lines.push(`[TEAM CLUTCH] ${betterDefTeam} significantly better in clutch (${betterCDrtg.toFixed(1)} vs ${worseCDrtg.toFixed(1)} DRTG) — advantage in close games.`);
      }
    }

    // Clutch player context (for J3 pre-game)
    const hClutch = getNBAClutchProfile((game._homeLeader||{}).name?.split(' ').pop());
    const aClutch = getNBAClutchProfile((game._awayLeader||{}).name?.split(' ').pop());
    if (hClutch?.tier === 'elite') lines.push(`[CLUTCH] ${hClutch.note} (${(hClutch.clutchFg*100).toFixed(0)}% FG clutch, ${hClutch.plusMinus} net)`);
    else if (aClutch?.tier === 'elite') lines.push(`[CLUTCH] ${aClutch.note} (${(aClutch.clutchFg*100).toFixed(0)}% FG clutch, ${aClutch.plusMinus} net)`);

  } catch(e) { if(FIELD_DEBUG) console.error('[NBA Analytics]', e.message); }
  return lines.join('\n');
}

// ── NBA Game Character Predictor (Wave 2) ─────────────────────────────────────
// Combines pace + both defenses → game archetype label + badge.
// Returns { label, badge, rationale } or null.
function predictNBAGameCharacter(game) {
  if (!game) return null;
  const hStats = getNBATeamAnalytics(game.home);
  const aStats = getNBATeamAnalytics(game.away);
  if (!hStats || !aStats) return null;

  const avgPace  = (hStats.pace + aStats.pace) / 2;
  const avgDrtg  = (hStats.drtg + aStats.drtg) / 2;
  const leagueAvg = 100.8;
  const bothEliteD = hStats.drtg <= 111 && aStats.drtg <= 111;
  const bothTopD   = hStats.drtg <= 109 && aStats.drtg <= 109;

  // Two historic defenses + halfcourt pace → CHESS MATCH
  if (bothTopD && avgPace <= 99.5)
    return { label: 'CHESS MATCH', badge: '[CHESS MATCH]',
      rationale: `${game.home} (${hStats.drtg.toFixed(1)} DRTG, #${hStats.drtgRank}) vs ${game.away} (${aStats.drtg.toFixed(1)} DRTG, #${aStats.drtgRank}). Both elite defenses, below-average pace. The halfcourt decides everything.` };

  // Both elite D + moderate pace → GRIND-FEST
  if (bothEliteD && avgPace <= 101)
    return { label: 'GRIND-FEST', badge: '[GRIND-FEST]',
      rationale: `Two elite defenses (avg DRTG ${avgDrtg.toFixed(1)}). Low-scoring, physical game. Whoever gets to the line wins.` };

  // Fast pace + weak D → TRACK MEET
  if (avgPace >= 103 && avgDrtg >= 115)
    return { label: 'TRACK MEET', badge: '[TRACK MEET]',
      rationale: `Both teams play fast (avg ${avgPace.toFixed(0)} poss/48). Defense is optional tonight.` };

  // Fast pace + one elite D → CHESS MATCH WITH PACE
  if (avgPace >= 102 && bothEliteD)
    return { label: 'CHESS MATCH', badge: '[CHESS MATCH]',
      rationale: `Elite defenses despite fast pace. Whoever slows it down gains the advantage.` };

  // Large DRTG gap → MISMATCH
  const drtgGap = Math.abs(hStats.drtg - aStats.drtg);
  if (drtgGap >= 5) {
    const favored = hStats.drtg < aStats.drtg ? game.home : game.away;
    return { label: 'MISMATCH', badge: '[MISMATCH]',
      rationale: `${favored} defense (${Math.min(hStats.drtg,aStats.drtg).toFixed(1)} DRTG) significantly better. Defensive identity team has the edge.` };
  }

  return null;
}

// ── NBA Regression Alert (Wave 2) ────────────────────────────────────────────
// Detects unsustainable shooting performance vs. underlying efficiency.
// Manual injection: update after each Finals game.
// Usage: injectNBARegression(gameKey, { team, stat, observed, expected, alert })
const _nbaRegressionCache = {}; // gameKey → regression data
function injectNBARegression(gameKey, data) { _nbaRegressionCache[gameKey] = data; }
function getNBARegression(gameKey) { return _nbaRegressionCache[gameKey] || null; }

// nhlAnalyticsInit — sets _homeAbbr/_awayAbbr/_sport on all NHL game objects.
// Called at T+4500ms so that game objects exist before any badge rendering.
// Precaution: without this, all NHL analytics badges silently produce nothing.
function nhlAnalyticsInit() {
  let enriched = 0;
  (allData?.sports||[]).forEach(sec => {
    if (!(sec.sport||'').toLowerCase().includes('nhl') && !(sec.sport||'').toLowerCase().includes('hockey')) return;
    (sec.games||[]).forEach(g => {
      if (!g._homeAbbr) { g._homeAbbr = getNHLAbbrev(g.home); }
      if (!g._awayAbbr) { g._awayAbbr = getNHLAbbrev(g.away); }
      if (!g._sport)    { g._sport = sec.sport; }
      enriched++;
    });
  });
  if (FIELD_DEBUG && enriched) console.log(`[NHL Analytics] Enriched ${enriched} game objects with _homeAbbr/_awayAbbr/_sport`);
  // Smoke-test: confirm VGK and CAR lookup correctly
  if (FIELD_DEBUG) {
    console.log('[NHL Analytics] Lookup test:',
      'VGK ST=', JSON.stringify(getNHLSpecialTeams('VGK')),
      'getNHLAbbrev(Montreal)=', getNHLAbbrev('Montreal Canadiens'),
      'andersen goalie=', JSON.stringify(getNHLGoalieProfile('Andersen'))
    );
  }
}

// ── getStatOfDay — tonight's most anomalous analytical fact ──────────────────
// Returns the single number with the biggest deviation from league average
// across all analytics data for this game. Used to:
//   1. Power the Scout's Pick "Stat of Day" badge (one-line evidence for the pick)
//   2. Inject a FEATURED STAT into the compound prompt with a citation rule
//
// Selection: largest |value - leagueAvg| / leagueAvg (normalised deviation)
// so that a 10pt PK advantage (93% vs 82% avg) outweighs a 5% SAT edge.
//
// 2026 playoff league averages (calculated from probe data — 16 teams):
//   PP%: 18.0  PK%: 82.0  SAT%: 50.0  FO%: 50.0
//   MLB park factor avg: 100  Umpire overturn avg: 45%
const _NHL_AVGS = { pp: 18.0, pk: 82.0, sat: 50.0, fo: 50.0 };

function getStatOfDay(game, sport) {
  if (!game) return null;
  const sp = (sport || game._sport || '').toLowerCase();
  const candidates = [];

  // ── NHL ──────────────────────────────────────────────────────────────────
  if (sp.includes('nhl') || sp.includes('hockey')) {
    const ha = game._homeAbbr || getNHLAbbrev?.(game.home);
    const aa = game._awayAbbr || getNHLAbbrev?.(game.away);
    const hST = ha ? getNHLSpecialTeams?.(ha) : null;
    const aST = aa ? getNHLSpecialTeams?.(aa) : null;
    if (hST && aST) {
      // Each candidate: { deviation, text, team, value, label, context }
      const push = (team, abbr, val, avg, label, fmtVal, ctx) =>
        candidates.push({ deviation: Math.abs(val - avg) / avg, team, abbr, val, label, fmtVal, ctx });

      push(game.home, ha, hST.pk, _NHL_AVGS.pk, 'PK%',
        `${hST.pk.toFixed(1)}%`, `${Math.round(hST.pk - _NHL_AVGS.pk)}pts above playoff average`);
      push(game.away, aa, aST.pk, _NHL_AVGS.pk, 'PK%',
        `${aST.pk.toFixed(1)}%`, `${Math.round(aST.pk - _NHL_AVGS.pk)}pts above playoff average`);
      push(game.home, ha, hST.pp, _NHL_AVGS.pp, 'PP%',
        `${hST.pp.toFixed(1)}%`, `${hST.pp > _NHL_AVGS.pp ? '+' : ''}${(hST.pp - _NHL_AVGS.pp).toFixed(1)}pts vs playoff average`);
      push(game.away, aa, aST.pp, _NHL_AVGS.pp, 'PP%',
        `${aST.pp.toFixed(1)}%`, `${aST.pp > _NHL_AVGS.pp ? '+' : ''}${(aST.pp - _NHL_AVGS.pp).toFixed(1)}pts vs playoff average`);
      push(game.home, ha, hST.sat, _NHL_AVGS.sat, 'SAT%',
        `${hST.sat.toFixed(0)}%`, `${hST.sat > 50 ? 'above' : 'below'} average possession`);
      push(game.away, aa, aST.sat, _NHL_AVGS.sat, 'SAT%',
        `${aST.sat.toFixed(0)}%`, `${aST.sat > 50 ? 'above' : 'below'} average possession`);
    }
    // Goalie outlier
    const hG = game._homeGoalie ? getNHLGoalieProfile?.(game._homeGoalie) : null;
    const aG = game._awayGoalie ? getNHLGoalieProfile?.(game._awayGoalie) : null;
    if (hG && hG.tier === 'elite')
      candidates.push({ deviation: (hG.sv - 0.9) / 0.9, team: game.home, abbr: ha,
        val: hG.sv, label: 'sv%', fmtVal: `.${Math.round(hG.sv*1000)}`, ctx: 'elite sv% this playoffs' });
    if (aG && aG.tier === 'elite')
      candidates.push({ deviation: (aG.sv - 0.9) / 0.9, team: game.away, abbr: aa,
        val: aG.sv, label: 'sv%', fmtVal: `.${Math.round(aG.sv*1000)}`, ctx: 'elite sv% this playoffs' });
  }

  // ── MLB ──────────────────────────────────────────────────────────────────
  if (sp.includes('mlb') || sp.includes('baseball')) {
    const abbr = game._homeAbbr;
    const pf = abbr ? getParkFactor?.(abbr) : null;
    if (pf) {
      const runDiff = pf.runFactor - 100;
      if (Math.abs(runDiff) >= 10)
        candidates.push({ deviation: Math.abs(runDiff) / 100, team: pf.label || game.home, abbr,
          val: runDiff, label: 'run factor', fmtVal: `${runDiff > 0 ? '+' : ''}${runDiff}%`,
          ctx: `${runDiff > 0 ? 'hitter-friendly' : 'pitcher-friendly'} park` });
    }
    const umpName = game._hpUmpire || '';
    if (umpName) {
      const last = umpName.split(' ').pop();
      const ump = getUmpireABSRating?.(last);
      if (ump && ump.rate >= 0.55)
        candidates.push({ deviation: (ump.rate - 0.45) / 0.45, team: last, abbr: 'UMP',
          val: ump.rate, label: 'overturn rate', fmtVal: `${Math.round(ump.rate*100)}%`,
          ctx: 'calls challenged at the plate' });
    }
  }

  // ── MLB probable pitcher signals ─────────────────────────────────────────
  // Three candidates: ERA edge (differential), ace signal (elite ERA), K9 (strikeout artist).
  // Reads synchronously from _mlbPitcherStatsCache (pre-loaded at T+4300ms).
  // Requires both phases of mlbProbablePitcherInit to be complete.
  if (sp.includes('mlb') || sp.includes('baseball')) {
    try {
      const pitchers = (typeof getMLBProbablePitchers === 'function')
        ? getMLBProbablePitchers(game.home) : null;
      if (pitchers?.home && pitchers?.away) {
        const hP = pitchers.home, aP = pitchers.away;
        const MIN_GS = 4; // minimum starts to be meaningful
        if (hP.gamesStarted >= MIN_GS || aP.gamesStarted >= MIN_GS) {
          // Helper: "Carlos Rodón" → "Rodón"
          const lastName = n => (n || '').split(' ').pop();

          // 1. Ace on mound — ERA <= 2.50 (normalised vs league avg 4.55)
          for (const [p, side] of [[hP, game.home], [aP, game.away]]) {
            if (!p.era || p.gamesStarted < MIN_GS) continue;
            if (p.era <= 2.50) {
              const dev = (_MLB_PITCHER_AVGS.era - p.era) / _MLB_PITCHER_AVGS.era;
              candidates.push({
                deviation: dev,
                team: side, abbr: '',
                val: p.era, label: 'ERA',
                fmtVal: p.era.toFixed(2),
                shortText: `${lastName(p.fullName)} ${p.era.toFixed(2)} ERA`,
                fullText:  `${p.fullName} ${p.era.toFixed(2)} ERA — ${(_MLB_PITCHER_AVGS.era - p.era).toFixed(2)} below league average`,
                ctx: 'ace on the mound',
              });
            }
          }

          // 2. ERA differential — gap >= 2.00 between starters
          if (hP.era && aP.era && hP.gamesStarted >= MIN_GS && aP.gamesStarted >= MIN_GS) {
            const eraGap = Math.abs(hP.era - aP.era);
            if (eraGap >= 2.00) {
              const better = hP.era < aP.era ? hP : aP;
              const worse  = hP.era < aP.era ? aP : hP;
              const side   = hP.era < aP.era ? game.home : game.away;
              candidates.push({
                deviation: eraGap / 4.0,
                team: side, abbr: '',
                val: eraGap, label: 'ERA edge',
                fmtVal: `${better.era.toFixed(2)} vs ${worse.era.toFixed(2)}`,
                shortText: `ERA edge ${better.era.toFixed(2)} vs ${worse.era.toFixed(2)}`,
                fullText:  `${lastName(better.fullName)} ${better.era.toFixed(2)} ERA vs ${lastName(worse.fullName)} ${worse.era.toFixed(2)} — significant pitching edge`,
                ctx: `${lastName(better.fullName)} holds clear advantage on the mound`,
              });
            }
          }

          // 3. Strikeout artist — K/9 >= 10.0
          for (const [p, side] of [[hP, game.home], [aP, game.away]]) {
            if (!p.k9 || p.gamesStarted < MIN_GS) continue;
            if (p.k9 >= 10.0) {
              const dev = (p.k9 - _MLB_PITCHER_AVGS.k9) / _MLB_PITCHER_AVGS.k9;
              candidates.push({
                deviation: dev,
                team: side, abbr: '',
                val: p.k9, label: 'K/9',
                fmtVal: p.k9.toFixed(1),
                shortText: `${lastName(p.fullName)} ${p.k9.toFixed(1)} K/9`,
                fullText:  `${p.fullName} ${p.k9.toFixed(1)} K/9 — elite strikeout rate (league avg ${_MLB_PITCHER_AVGS.k9})`,
                ctx: 'high strikeout rate — game could hinge on punch-outs',
              });
            }
          }
        }
      }
    } catch(e_) {}
  }

  // ── NBA ──────────────────────────────────────────────────────────────────
  // Gate D data: DRTG differential vs league average — fires on elite/poor defense matchups.
  // League avg: _AVG entry in NBA_TEAM_ANALYTICS. Regular-season fires year-round.
  if (sp.includes('nba') || sp.includes('basketball')) {
    try {
      const hStats = (typeof getNBATeamAnalytics === 'function') ? getNBATeamAnalytics(game.home) : null;
      const aStats = (typeof getNBATeamAnalytics === 'function') ? getNBATeamAnalytics(game.away) : null;
      const leagueAvgDrtg = NBA_TEAM_ANALYTICS?._AVG?.drtg ?? 114.7;
      const leagueAvgPace = NBA_TEAM_ANALYTICS?._AVG?.pace ?? 100.8;
      if (hStats) {
        const drtgDev = Math.abs(hStats.drtg - leagueAvgDrtg) / leagueAvgDrtg;
        if (drtgDev > 0.015) { // ~2.2pt gap at league avg — meaningful defensive edge
          const dir = hStats.drtg < leagueAvgDrtg ? 'elite defense' : 'poor defense';
          candidates.push({ deviation: drtgDev, team: game.home, abbr: getNBAAbbrev?.(game.home)||'',
            val: hStats.drtg, label: 'DRTG', fmtVal: hStats.drtg.toFixed(1),
            ctx: `${dir} — ${Math.abs(hStats.drtg - leagueAvgDrtg).toFixed(1)}pts ${hStats.drtg < leagueAvgDrtg ? 'better' : 'worse'} than league average` });
        }
        const paceDev = Math.abs(hStats.pace - leagueAvgPace) / leagueAvgPace;
        if (paceDev > 0.025) { // ~2.5 possessions/game — meaningfully fast/slow
          candidates.push({ deviation: paceDev * 0.7, team: game.home, abbr: getNBAAbbrev?.(game.home)||'',
            val: hStats.pace, label: 'pace', fmtVal: hStats.pace.toFixed(1),
            ctx: `${hStats.pace > leagueAvgPace ? 'fastest' : 'slowest'}-paced team in the league` });
        }
      }
      if (aStats) {
        const drtgDev = Math.abs(aStats.drtg - leagueAvgDrtg) / leagueAvgDrtg;
        if (drtgDev > 0.015) {
          const dir = aStats.drtg < leagueAvgDrtg ? 'elite defense' : 'poor defense';
          candidates.push({ deviation: drtgDev, team: game.away, abbr: getNBAAbbrev?.(game.away)||'',
            val: aStats.drtg, label: 'DRTG', fmtVal: aStats.drtg.toFixed(1),
            ctx: `${dir} — ${Math.abs(aStats.drtg - leagueAvgDrtg).toFixed(1)}pts ${aStats.drtg < leagueAvgDrtg ? 'better' : 'worse'} than league average` });
        }
      }
    } catch(e_) {}
  }

  // ── NHL FO% — faceoff differential ───────────────────────────────────────
  // FO% differential is a real but underreported edge — already in NHL_SPECIAL_TEAMS
  if (sp.includes('nhl') || sp.includes('hockey')) {
    try {
      const ha = game._homeAbbr || getNHLAbbrev?.(game.home);
      const aa = game._awayAbbr || getNHLAbbrev?.(game.away);
      const hST = ha ? getNHLEffectiveST?.(ha) : null;
      const aST = aa ? getNHLEffectiveST?.(aa) : null;
      if (hST?.fo && aST?.fo) {
        const foDiff = Math.abs(hST.fo - aST.fo);
        if (foDiff >= 8) { // 8pt FO% gap is analytically significant
          const better = hST.fo > aST.fo ? {team:game.home,abbr:ha,fo:hST.fo} : {team:game.away,abbr:aa,fo:aST.fo};
          candidates.push({ deviation: foDiff / 50, team: better.team, abbr: better.abbr,
            val: better.fo, label: 'FO%', fmtVal: `${better.fo.toFixed(1)}%`,
            ctx: `${foDiff.toFixed(0)}-point faceoff advantage tonight` });
        }
      }
    } catch(e_) {}
  }

  if (!candidates.length) return null;
  const best = candidates.sort((a, b) => b.deviation - a.deviation)[0];
  return {
    ...best,
    shortText: `${teamNick(best.team||'')} ${best.fmtVal} ${best.label}`,
    fullText:  `${teamNick(best.team||'')} ${best.fmtVal} ${best.label} — ${best.ctx}`,
  };
}

// Badge: renders under Scout's Pick; returns '' if no stat available
function buildStatOfDayBadge(game, sport) {
  const s = getStatOfDay(game, sport);
  if (!s) return '';
  return `<span class="stat-day-badge" title="${s.fullText}">📊 ${s.shortText}</span>`;
}

// 2026-07-13 (CC-CMD-2026-07-13-fetchnhlrelayscores-migration): migrated
// to fieldOperation(). The old internal try/catch swallowed every
// exception (fetch failure, timeout, malformed JSON) before it could ever
// reach the sole caller's own `.catch(e=>captureFieldError(...))` chain --
// since this function's own catch always resolved the promise (never let
// it reject), that caller-side catch could structurally never fire. The
// Health Panel has been recording zero NHL-relay failures regardless of
// how many actually occurred. fieldOperation()'s own try/catch is now the
// sole catcher -- it never rejects either (matching the old external
// behavior of "never throw to the caller"), but it DOES call
// FIELD_OPERATIONS.recordFailure() -> captureFieldError() internally on
// every real exception, which is the actual fix.
async function fetchNHLRelayScores() {
  // Only run if there's an NHL section visible today
  if (!document.querySelector('.sport-section[data-sport="NHL Playoffs"]')) return;
  return fieldOperation({subsystem:'scores', operation:'fetch-nhl-relay', retryable:true}, async () => {
    const r = await fetch(`${NHL_RELAY_BASE}/v1/scoreboard/now`, {
      signal: AbortSignal.timeout(6000)
    });
    if (!r.ok) return;
    const data = await r.json();

    let updated = 0;
    for (const g of (data.games || [])) {
      const awayAbbr = g.awayTeam?.abbrev;
      const homeAbbr = g.homeTeam?.abbrev;
      if (!awayAbbr || !homeAbbr) continue;

      // Resolve full names — use abbrev map, fall back to API name fields
      const awayName = NHL_ABBREV_MAP[awayAbbr] || g.awayTeam?.commonName?.default || awayAbbr;
      const homeName = NHL_ABBREV_MAP[homeAbbr] || g.homeTeam?.commonName?.default || homeAbbr;

      const gameState = g.gameState || 'FUT';
      const isLive  = ['LIVE', 'CRIT'].includes(gameState); // CRIT = last 5min
      const isFinal = ['FINAL', 'OFF'].includes(gameState);
      if (!isLive && !isFinal) continue;

      const homeScore = g.homeTeam?.score ?? 0;
      const awayScore = g.awayTeam?.score ?? 0;
      const period    = g.period || 0;
      const clock     = g.clock?.timeRemaining || '';
      const isOT      = period > 3;
      const detail    = isFinal ? (isOT ? 'Final/OT' : 'Final') : (clock || 'LIVE');

      const key = `${homeName}|${awayName}`;
      espnScores[key] = {
        state:   isFinal ? 'post' : 'in',
        period, clock, detail,
        homeScore, awayScore, homeName, awayName,
        home: homeName, away: awayName,
        _sport: 'NHL Playoffs',
        homeWinning: homeScore > awayScore,
        periodPrefix: 'P', // matches ESPN_SPORTS NHL entry
        source: 'nhl-relay',
      };
      espnScoreTs[key] = Date.now();
      updated++;
    }
    if (updated) renderESPNScores();
  });
}

// #11b — Tempo-adjusted polling: cadence varies 20-45s by aggregate named tier
// across the section's games. High-tier games poll faster; quiet sections slower.
// ADR-002 (L1): tier-driven cadence — was composite drama + 3 hardcoded
// thresholds. Internal logic only (poll interval, never user-visible).
function computeLiveInterval(sectionSport) {
  if(!allData?.sports) return ESPN_REFRESH_LIVE;
  const sec = allData.sports.find(s => s.sport === sectionSport);
  if(!sec) return 45000;
  const topRank = Math.max(0, ...(sec.games||[]).map(g => g._id ? fieldTierRank(fieldGameTier(g._id)) : 0));
  // NOTE: SSE (AmbientDO) delivers subscriber events (Night Owl, lead change burst,
  // CRUNCH) at ~3s latency via emitScoreEvent(source:'sse'). However SSE does NOT
  // write to espnScores[] — card score display is updated only by polling.
  // Therefore polling must run at full cadence; reducing it would stale the score
  // shown on cards even while SSE events fire correctly.
  // Future: if SSE handler writes to espnScores + triggers renderESPNScores, then
  // polling could be reduced safely. Until then: do not gate on isSSECovered here.
  if(topRank >= fieldTierRank('CRUNCH'))            return 20000; // 20s — CRUNCH/EXTRA_TIME and above
  if(topRank >= fieldTierRank('CLOSE_LATE'))        return 25000; // 25s — CLOSE_LATE
  if(topRank >= fieldTierRank('MARQUEE_NATIONAL'))  return 30000; // 30s — marquee/playoff series
  if(topRank >= fieldTierRank('LIVE'))              return 30000; // 30s — generic live game
  return 45000;                                                    // 45s — pre-game / quiet section
}

// Fetch all sport scoreboards and merge into espnScores
// ── ESPN Polling Architecture ─────────────────────────────────────────────
// Seven failure modes fixed in this revision:
//
// P1 Promise.all → one uncaught throw stops ALL leagues AND kills scheduler
//    Fix: Promise.allSettled + outer try/finally (scheduler ALWAYS restarts)
//
// P2 network error → league marked 'post' → 15-min blackout
//    Fix: _espnLeagueErrors{} tracks error state separately from game state
//         catch path: increment errors, use exponential backoff, preserve prior state
//
// P3 !r.ok early return → _espnLeagueLastPoll never set → rapid-fire retry
//    Fix: always set _espnLeagueLastPoll; use error backoff for !r.ok
//
// P4 activeSections race condition → MLB excluded on first poll → 15-min wait
//    Fix: _espnFirstPoll flag — first call polls ALL ESPN_SPORTS unconditionally
//
// P5 no outer guard → quiet-hour block / relay calls can kill scheduler
//    Fix: outer try/finally ensures setTimeout ALWAYS fires
//
// P6 concurrent second call from post-MLB-load → duplicate scheduler chains
//    Fix: field:data-ready event reschedules existing chain instead of spawning new one
//
// P7 nextInterval ignores never-polled leagues not yet in allLeagues
//    Fix: after field:data-ready, reschedule to 1s if MLB still unpolled
// ─────────────────────────────────────────────────────────────────────────
let _espnFirstPoll = true;      // cleared after first fetchESPNScores call
const _espnLeagueErrors = {};   // league → consecutive error count

async function fetchESPNScores(){
  _pollCycle++; // drives lead change burst decay
  if(espnIntervalId){ clearTimeout(espnIntervalId); espnIntervalId = null; } // prevent duplicate schedulers

  const today = new Date();
  const dateStr = today.getFullYear()
    + String(today.getMonth()+1).padStart(2,'0')
    + String(today.getDate()).padStart(2,'0'); // "20260506"

  let _hasLive = false; let _hasUpcoming = false; // kept for relay fire-and-forget below
  let allLeagues = [];

  try { // ── OUTER GUARD: scheduler restarts even if everything here throws ────────

  // Sport-aware filter: only poll leagues with sections in today's schedule
  // REMEDY D: first poll bypasses activeSections for never-polled leagues —
  // guarantees MLB (loaded async by fetchMLBFixtures) gets its first poll at startup.
  const activeSections = new Set((allData?.sports||[]).map(s => s.sport));
  const filteredESPN = ESPN_SPORTS.filter(l =>
    activeSections.has(l.section) ||               // normal filter
    (_espnFirstPoll && !_espnLeagueLastPoll[l.league]) // REMEDY D: bootstrap — poll all unvisited
  );
  _espnFirstPoll = false; // only fires once

  const todayISO = new Date().toISOString().split("T")[0];
  const filteredSoccer = SOCCER_LEAGUES
    .filter(l => (!l.endDate || l.endDate >= todayISO) &&
                 (l.league === "eng.1" || activeSections.has(l.section) || !allData?.sports?.length))
    .map(l=>({sport:"soccer",league:l.league,section:l.section,periodPrefix:"'"}));

  allLeagues = [...filteredESPN, ...filteredSoccer];

  // Layer 1: only poll leagues due — respects per-league state and error backoff
  const now = Date.now();
  const leaguesToPoll = allLeagues.filter(l => {
    const last     = _espnLeagueLastPoll[l.league] || 0;
    const state    = _espnLeagueState[l.league] || 'pre';
    const errCount = _espnLeagueErrors[l.league] || 0;
    // REMEDY C: errored leagues use exponential backoff, not the 'post' interval
    const interval = errCount > 0
      ? Math.min(15000 * Math.pow(2, errCount - 1), 300000) // 15s→30s→60s→120s→300s
      : state === 'live' ? computeLiveInterval(l.section)
      : state === 'pre'  ? ESPN_REFRESH_IDLE
      : ESPN_REFRESH_FINISHED;
    return (now - last) >= interval;
  });

  if(FIELD_DEBUG) console.debug(
    `[ESPN] ${leaguesToPoll.length}/${allLeagues.length} due |`,
    Object.entries(_espnLeagueState).filter(([,v])=>v==='live').map(([k])=>k).join(',') || 'none live'
  );

  // Layer 2: REMEDY A+B — Promise.allSettled prevents one league error from stopping others
  await Promise.allSettled(leaguesToPoll.map(async ({sport, league, section, periodPrefix}) => {

    // ── Phase 1 safety net: V2 cutover check (belt-and-suspenders)
    // V2 sports removed from ESPN_SPORTS/SOCCER_LEAGUES in Phase 2, so this block
    // is effectively dead code for those sports. Retained as fallback in case a V2
    // sport is re-added to the ESPN config accidentally.
    const v2Key = ESPN_TO_V2_MAP[league];
    if (v2Key && FIELD_V2_SOURCES[v2Key]) {
      try {
        const games = await fetchV2Games(v2Key, todayISO);
        let hasLive = false, hasPre = false;
        games.forEach(fg => {
          if (!fg?.home?.name || !fg?.away?.name) return;
          const key = `${fg.home.name}|${fg.away.name}`;
          const v2Entry = mapV2ToESPN(fg) || {};
          espnScores[key] = v2Entry;
          espnScoreTs[key] = Date.now();
          // PM-20 Step 3: source-tagged parallel write for V2 fallback cascade path
          _scoresBySource[key] = _scoresBySource[key] || {};
          _scoresBySource[key].apisports = {
            state:        v2Entry.state,
            period:       v2Entry.period,
            clock:        v2Entry.clock,
            detail:       v2Entry.detail,
            homeScore:    v2Entry.homeScore,
            awayScore:    v2Entry.awayScore,
            homeName:     v2Entry.homeName,
            awayName:     v2Entry.awayName,
            home:         v2Entry.home,
            away:         v2Entry.away,
            periodPrefix: v2Entry.periodPrefix,
            ts:           Date.now(),
          };
          if (fg.state === 'live') hasLive = true;
          if (fg.state === 'pre')  hasPre  = true;
        });
        _espnLeagueState[league]   = hasLive ? 'live' : hasPre ? 'pre' : 'post';
        _espnLeagueLastPoll[league] = Date.now();
        _espnLeagueErrors[league]   = 0;
        if (hasLive) _hasLive    = true;
        if (hasPre)  _hasUpcoming = true;
        if (FIELD_DEBUG) console.debug(`[V2] ${v2Key} polled: ${games.length} games, ${hasLive?'LIVE':'no live'}`);
      } catch(e) {
        if (FIELD_DEBUG) console.warn('[V2] poll failed:', v2Key, e.message);
        _espnLeagueErrors[league]   = (_espnLeagueErrors[league] || 0) + 1;
        _espnLeagueLastPoll[league] = Date.now();
      }
      return; // skip ESPN call for this league
    }
    // ── ESPN path (unchanged for non-V2 sports) ──────────────────────────
    const url = `${ESPN_BASE}/${sport}/${league}/scoreboard?dates=${dateStr}&limit=50`;
    let leagueHasLive = false, leagueHasPre = false;
    let fetchOk = false;
    try{
      const r = await fetch(url,{signal:AbortSignal.timeout(8000)});
      if(!r.ok){
        // REMEDY C: !r.ok → error backoff, not rapid-fire retry
        _espnLeagueErrors[league] = (_espnLeagueErrors[league]||0) + 1;
        _espnLeagueLastPoll[league] = Date.now();
        // Preserve prior state — a 4xx doesn't mean games are over
        return;
      }
      const data = await r.json();
      fetchOk = true;
      (data.events||[]).forEach(ev=>{
        const comp = (ev.competitions||[])[0];
        if(!comp) return;
        const comps = comp.competitors||[];
        const home = comps.find(t=>t.homeAway==="home")||comps[0];
        const away = comps.find(t=>t.homeAway==="away")||comps[1];
        if(!home||!away) return;

        const status = ev.status||{};
        const state  = status.type?.state||"pre";
        const period = status.period||0;
        const clock  = status.displayClock||"";
        const detail = status.type?.shortDetail||"";

        const homeScore = parseInt(home.score||0);
        const awayScore = parseInt(away.score||0);
        const homeName  = home.team?.displayName||"";
        const awayName  = away.team?.displayName||"";

        if(state==="in")  leagueHasLive = true;
        if(state==="pre") leagueHasPre  = true;

        const sit = comp.situation||{};
        const outs    = sit.outs    ?? null;
        const balls   = sit.balls   ?? null;
        const strikes = sit.strikes ?? null;
        const onFirst  = sit.onFirst  ?? false;
        const onSecond = sit.onSecond ?? false;
        const onThird  = sit.onThird  ?? false;

        const homeLS = (home.linescores||[]).map(l=>parseInt(l.value||0)).filter(v=>!isNaN(v));
        const awayLS = (away.linescores||[]).map(l=>parseInt(l.value||0)).filter(v=>!isNaN(v));

        // ── Item 1: ESPN in-game leaders — zero extra API calls ───────────────
        // comp.leaders is in every ESPN scoreboard response at no extra cost.
        // Provides: top scorer name + stat per team → feeds journalism prompts.
        // "Brunson 28pts, Mitchell 22pts" replaces "Knicks lead by 3 in Q4"
        const _extractLeader = (competitor) => {
          const leaders = competitor.leaders || [];
          const priority = ['points','goals','hits','passingYards','rushingYards'];
          for (const sn of priority) {
            const cat = leaders.find(l=>(l.name||'').toLowerCase()===sn||(l.abbreviation||'').toLowerCase()===sn.slice(0,3));
            if (cat?.leaders?.[0]) {
              const p = cat.leaders[0];
              const name = p.athlete?.shortName||p.athlete?.displayName||'';
              const val = p.displayValue||String(p.value||'');
              const unit = cat.shortDisplayName||cat.abbreviation||'';
              if (name&&val) return {name,val,unit};
            }
          }
          const first = leaders[0]?.leaders?.[0];
          if (first?.athlete) return {name:first.athlete.shortName||first.athlete.displayName||'',val:first.displayValue||'',unit:leaders[0]?.shortDisplayName||''};
          return null;
        };
        const homeLeader = _extractLeader(home);
        const awayLeader  = _extractLeader(away);

        const key = `${homeName}|${awayName}`;
        const situation = comp.situation || null;
        const _prev = espnScores[key]; // preserve async WP across polls
        espnScores[key] = {
          _gameId: resolveGameIdByHome(homeName), // for drama history lookup
          espnEventId: ev.id || null,             // ESPN numeric event ID — for WP, PBP, boxscore fetches
          state, period, clock, detail,
          homeScore, awayScore, homeName, awayName,
          home: homeName, away: awayName,
          _sport: section,
          homeWinning: homeScore > awayScore,
          periodPrefix,
          outs, balls, strikes,
          onFirst, onSecond, onThird,
          situation,
          homeLinescores: homeLS,
          awayLinescores: awayLS,
          homeLeader, awayLeader, // in-game top performers — see Item 1
          wp:      _prev?.wp      ?? null, // populated by WP fetch cycle
          wp_prev: _prev?.wp_prev ?? null, // set to previous wp before update
        };
        espnScoreTs[key] = Date.now();
        // PM-20 Step 2: ALSO write to source-tagged store. Parallel write —
        // espnScores[key] continues to receive the merged view for migration
        // safety. The .espn slot here is the independent ESPN witness for
        // findScore() cross-source verification with API-Sports.
        _scoresBySource[key] = _scoresBySource[key] || {};
        _scoresBySource[key].espn = {
          state, period, clock, detail,
          homeScore, awayScore, homeName, awayName,
          home: homeName, away: awayName,
          periodPrefix,
          ts: Date.now(),
        };
        // STEP 4: fire async WP fetch for live NBA games
        // D3 gate: skip when FIELD_V2_SOURCES.nba=true — api-sports.io is primary,
        // ESPN WP endpoint returns null/404 post-pivot. Avoids wasted request per poll.
        if (state === 'in' && ev.id && sport === 'basketball' && league === 'nba' && !FIELD_V2_SOURCES.nba) {
          if (FIELD_DEBUG) console.log('[WP] firing for gameId:', ev.id);
          fetchESPNWinProb(ev.id).then(wp => {
            if (wp !== null && espnScores[key]) {
              espnScores[key].wp_prev = espnScores[key].wp;
              espnScores[key].wp = wp;
            }
          });
        }
        // STEP 4b: fire Savant WP fetch for live MLB games
        // sourceId = MLB Stats API gamePk (stored on allData game as game.sourceId)
        if (state === 'in' && sport === 'baseball' && league === 'mlb') {
          const mlbGame = (allData?.sports || [])
            .find(s => s.sport === 'Baseball (MLB)')?.games
            ?.find(g => espnTeamMatch(g.home||'', homeName) || espnTeamMatch(g.away||'', homeName));
          const sourceId = mlbGame?.sourceId;
          if (sourceId) {
            if (FIELD_DEBUG) console.log('[SAVANT] firing for sourceId:', sourceId);
            fetchSavantGameFeed(sourceId).then(savant => {
              if (savant && espnScores[key]) {
                espnScores[key].wp_prev = espnScores[key].wp;
                espnScores[key].wp = savant.wp;
                // Provenance tag mirrors _liveOddsWP (odds-api SSE path) so
                // Savant-sourced wp is distinguishable from odds-derived wp
                // on the same espnScores[key].wp field (CC-CMD avv-savant).
                espnScores[key]._savantWP = { wp: savant.wp, wpa: savant.wpa ?? null, ts: Date.now(), source: 'savant' };
              }
            });
          }
        }
      });
    }catch(e){
      // REMEDY C: network/parse error → error backoff, NOT 'post' state
      // Prior state is preserved — a timeout ≠ "all games finished"
      if(FIELD_DEBUG) console.debug("FIELD ESPN:",league,"–",e.message);
      _espnLeagueErrors[league] = (_espnLeagueErrors[league]||0) + 1;
      _espnLeagueLastPoll[league] = Date.now();
      return; // skip normal state update below
    }
    // Success path: clear error count, update state normally
    _espnLeagueErrors[league] = 0;
    _espnLeagueLastPoll[league] = Date.now();
    _espnLeagueState[league]    = leagueHasLive ? 'live' : leagueHasPre ? 'pre' : 'post';
  }));

  renderESPNScores();

  // Fire RELAY + FPL + FD in parallel — don't block ESPN cycle
  // 2026-07-13: .catch() removed -- fetchNBARelayScores() is now migrated
  // to fieldOperation(), whose own promise never rejects (see the function's
  // own comment). Same reasoning as the NHL relay line below.
  fetchNBARelayScores();
  // 2026-07-13 (CC-CMD-2026-07-13-fetchnhlrelayscores-migration): the
  // .catch(e=>captureFieldError(...)) chain other fire-and-forget relay
  // calls on these lines use is removed here specifically -- now that
  // fetchNHLRelayScores() is migrated to fieldOperation(), its returned
  // promise never rejects (fieldOperation()'s own try/catch always
  // resolves to {ok:false,...} on failure, matching this function's prior
  // external behavior of never throwing to its caller), so a .catch() here
  // is dead code that can structurally never fire. FIELD_OPERATIONS.recordFailure()
  // already calls captureFieldError() internally on every real failure --
  // the telemetry this line used to (never actually) provide is now
  // genuinely produced, just via fieldOperation()'s own catch instead of
  // this caller's. Sibling lines (fetchNBARelayScores/fetchFPLLiveScores/
  // fdPrefetchSoccerLive) are NOT migrated yet and correctly keep their own
  // .catch() -- out of scope for this CC-CMD, not touched.
  fetchNHLRelayScores();
  // 2026-07-13: .catch() removed -- fetchFPLLiveScores() is now migrated
  // to fieldOperation(), whose own promise never rejects.
  fetchFPLLiveScores();
  // 2026-07-13: .catch() removed -- fdPrefetchSoccerLive() is now migrated
  // to fieldOperation(), whose own promise never rejects.
  fdPrefetchSoccerLive();

  // Gap 8: Quiet Hour Detection
  {
    const liveLeagues = allLeagues.filter(l => _espnLeagueState[l.league] === 'live');
    if(liveLeagues.length > 0){
      const allQuiet = liveLeagues.every(l => {
        const sec = allData?.sports?.find(s => s.sport === l.section);
        const maxDrama = sec ? Math.max(0, ...(sec.games||[]).map(g => {
          // Rule 24: use live smoothed drama when available — preGameScore is a
          // pre-game estimate and can misfire quiet hour during live crunch time
          const live = g._id ? getSmoothedDrama(g._id) : null;
          return live != null ? live : preGameScore(g);
        })) : 0;
        return maxDrama < QUIET_THRESHOLD;
      });
      if(allQuiet){
        _quietLowCount++;
        if(_quietLowCount >= QUIET_CYCLES_GATE && !_quietHourActive){
          _quietHourActive = true;
          const qBanner = (_DOM?.otwBanner||document.getElementById('otw-banner'));
          if(qBanner && !qBanner.dataset.quietHour){
            qBanner.dataset.quietHour = '1';
            if(FIELD_DEBUG) console.debug('[QUIET HOUR] All live games low-drama — extending poll to 90s');
          }
        }
      } else {
        if(_quietHourActive){
          _quietHourActive = false;
          const qBanner = (_DOM?.otwBanner||document.getElementById('otw-banner'));
          if(qBanner) delete qBanner.dataset.quietHour;
        }
        _quietLowCount = 0;
      }
    } else {
      _quietLowCount = 0;
      _quietHourActive = false;
    }
  }

  } catch(outerErr) {
    // REMEDY A/E: outer guard — nothing above should throw but if it does, we survive
    if(FIELD_DEBUG) console.warn('[ESPN] outer error, scheduler restarting:', outerErr?.message);
  }

  // REMEDY A/E: ALWAYS schedule next call — runs even if try block threw
  // This is the single most important guarantee: polling never dies permanently.
  const now2 = Date.now();
  const safeAllLeagues = allLeagues.length ? allLeagues : ESPN_SPORTS.slice(0,3); // fallback if allLeagues empty
  const nextInterval = safeAllLeagues.reduce((min, l) => {
    const errCount = _espnLeagueErrors[l.league] || 0;
    const state    = _espnLeagueState[l.league] || 'pre';
    const interval = errCount > 0
      ? Math.min(15000 * Math.pow(2, errCount - 1), 300000)
      : state === 'live'
      ? (_quietHourActive ? QUIET_POLL_INTERVAL : computeLiveInterval(l.section))
      : state === 'pre'  ? ESPN_REFRESH_IDLE
      : ESPN_REFRESH_FINISHED;
    const last  = _espnLeagueLastPoll[l.league] || 0;
    const dueIn = Math.max(0, (last + interval) - now2);
    return Math.min(min, dueIn);
  }, ESPN_REFRESH_IDLE);
  espnIntervalId = setTimeout(fetchESPNScores, Math.max(5000, nextInterval));
}

// ── ESPN Win Probability — Site Summary API ───────────────────────────────
// Source: site.api.espn.com/apis/site/v2/sports/basketball/nba/summary
// Public REST endpoint; CORS locked to espn.com — relay bypasses
// WP array: winprobability[].homeWinPercentage — 0-1 FRACTION (e.g. 0.872 = 87.2%)
// ESPN Gamecast display * 100 → "87.2" in DOM (that's why DOM showed 62.1 not 0.621)
// Most recent snapshot = last entry in array (.at(-1))
// Scale confirmed live: 0.872 observed SA@OKC G2, 3rd Qtr, May 21 2026
async function fetchESPNWinProb(gameId) {
  const url = `${ESPN_SUMMARY_RELAY}/sports/basketball/nba/summary?event=${gameId}`;
  try {
    const r = await fetch(url, { signal: AbortSignal.timeout(4000) });
    if (!r.ok) {
      if (FIELD_DEBUG) console.log('[WP] fetchESPNWinProb: relay HTTP', r.status, url);
      return null;
    }
    const d = await r.json();
    // winprobability is an array; most recent snapshot is last entry
    const wp =
      d?.winprobability?.at(-1)?.homeWinPercentage ??  // primary: array of snapshots
      d?.winprobability?.[0]?.homeWinPercentage    ??  // fallback: first entry
      null;
    if (FIELD_DEBUG) console.log('[WP] fetchESPNWinProb:', wp !== null ? wp : ('null — top keys: ' + Object.keys(d||{}).join(',')));
    return wp;
  } catch(e) {
    if (FIELD_DEBUG) console.log('[WP] fetchESPNWinProb error:', e?.message);
    return null;
  }
}

// ── Baseball Savant GameFeed — Live WP + Statcast for MLB ─────────────────
// Endpoint: baseballsavant.mlb.com/gf?game_pk={mlbSourceId}
// CORS: access-control-allow-origin: * (no relay needed)
// gamePk = game.sourceId (MLB Stats API numeric ID, NOT ESPN event ID)
// Returns: { wp: homeTeamWinProbability (0-1), lastWpa: homeTeamWinProbabilityAdded }
// WP scale: 0-1 fraction (e.g. 0.72 = 72% home win prob) — same as ESPN WP
// Confirmed live: gamePk 778507 showed homeTeamWinProbability 24x in gameWpa array
async function fetchSavantGameFeed(sourceId) {
  if (!sourceId) return null;
  const url = `${SAVANT_BASE}/gf?game_pk=${sourceId}`;
  try {
    const r = await fetch(url, { signal: AbortSignal.timeout(5000) });
    if (!r.ok) {
      if (FIELD_DEBUG) console.log('[SAVANT] HTTP', r.status, 'for gamePk', sourceId);
      return null;
    }
    const d = await r.json();
    const gameWpa = d?.scoreboard?.stats?.wpa?.gameWpa;
    if (!Array.isArray(gameWpa) || !gameWpa.length) {
      if (FIELD_DEBUG) console.log('[SAVANT] gameWpa empty for gamePk', sourceId);
      return null;
    }
    const last = gameWpa[gameWpa.length - 1];
    const wp    = last?.homeTeamWinProbability   ?? null;
    const wpa   = last?.homeTeamWinProbabilityAdded ?? null;
    if (FIELD_DEBUG) console.log('[SAVANT] gamePk', sourceId, '→ wp:', wp, 'wpa:', wpa);
    return wp !== null ? { wp, wpa } : null;
  } catch(e) {
    if (FIELD_DEBUG) console.log('[SAVANT] error:', e?.message);
    return null;
  }
}

// Fuzzy match: does the ESPN team name match a FIELD game team name?
// resolveGameIdByHome extracted to src/identity/index.ts (Phase 4 — Identity domain).

// Find matching ESPN score for a FIELD game object
//
// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #3): 25+ real
// callers all treat a bare `null` return identically, whether it means
// "genuinely no data yet" or "stale-final guard correctly blocked a
// mismatched score." Read every real caller before deciding what to do
// here (novel thinking, not a mechanical fieldOperation() wrap, which
// doesn't fit -- this function is synchronous and never throws): NONE of
// them would behave differently even if they COULD distinguish the two
// cases -- the correct action for both is identical ("no live data for
// this card right now"). Changing the return contract for 25+ call sites
// to expose a distinction nothing would act on is exactly the kind of
// invasive, high-risk, low-value migration Rule 69 warns against. The
// REAL gap is observability, not caller behavior: the stale-final guard
// firing was previously invisible outside a live FIELD_DEBUG session (one
// of its 3 call sites didn't even have that), even though a HIGH firing
// rate would be real evidence the underlying June 10 2026 root cause
// (api-sports.io mistagging late games under the wrong date) is still
// happening upstream. Fix: record real, persistent telemetry
// (FIELD_OPERATIONS.recordFailure, severity:'trace' since this is the
// guard working correctly, not a genuine failure) at all 3 sites where it
// fires -- purely additive, zero change to the return contract, zero
// caller updates needed.
// Dedup set: no-match fires at most once per matchup per session load.
const _noMatchRecorded = new Set();

function findESPNScore(game){
  // ── STALE-FINAL GUARD (June 10 2026) ─────────────────────────────────────
  // Problem: api-sports.io returns late games (e.g. June 9 8:40pm ET =
  // June 10 00:40 UTC) under date=2026-06-10 as FINAL. findScore() matches
  // them to tonight's scheduled card (same matchup, same teams) by team name
  // alone — no time check — and the previous day's final score shows on a
  // future game card. Root cause: _scoresBySource has no temporal guard.
  // Fix: a FINAL score must never appear on a card whose start_time has not
  // yet passed. Applied to both the PM-20 source-tagged path and legacy path.
  // Safe for all sports — game.start_time is always UTC ISO from the schedule.
  const _staleFinalGuard = (score, g) => {
    if (!score || score.state !== 'post' || !g || !g.start_time) return false;
    return new Date(g.start_time).getTime() > Date.now();
  };
  const _recordStaleFinalBlock = (path) => {
    // Guard working as designed — not a failure, just debug noise.
    if (FIELD_DEBUG) console.warn('[FIELD] stale-final blocked:', game.away, '@', game.home, game.start_time, '('+path+')');
  };

  // PM-20: try source-tagged store first (returns confidence-aware view)
  const tagged = typeof findScore === 'function' ? findScore(game) : null;
  if (tagged) {
    if (_staleFinalGuard(tagged, game)) {
      _recordStaleFinalBlock('tagged');
      return null;
    }
    return tagged;
  }
  // Migration fallback: legacy espnScores (last-writer-wins, no source attribution)
  // Remove once all writers migrated to _scoresBySource.
  const home = (game.home||"").toLowerCase();
  const away = (game.away||"").toLowerCase();
  // Sport guard: prevent city-name cross-contamination (e.g. NBA "Toronto" scoring on MLS "Toronto FC")
  // EXCLUDE clearly non-soccer: Q=basketball, H=college-bball, P=hockey, T=baseball
  // DO NOT exclude 1H/2H — fetchSoccerFixtures stores soccer scores with those prefixes
  const sc = typeof classifySport==='function' ? classifySport(game,null) : {};
  // Individual-sport and non-ESPN-indexed leagues have no team-score entry in espnScores.
  // isSoccer: SOCCER_LEAGUES=[] so espnScores never has soccer; all soccer served via findScore()→_scoresBySource.apisports
  if (sc.isCFL || sc.isAFL || sc.isGolf || sc.isTennis || sc.isCricket || sc.isRugby || sc.isSoccer) return null;
  const gameSoccer = sc.isSoccer;
  for(const [key, score] of Object.entries(espnScores)){
    const pp = score.periodPrefix||'';
    if(gameSoccer  && (pp==='Q'||pp==='H'||pp==='P'||pp==='T')) continue;
    if(!gameSoccer && (pp==="'"||pp==='1H'||pp==='2H')) continue;
    const [hn, an] = key.split("|").map(s=>s.toLowerCase());
    if(espnTeamMatch(hn, home) && espnTeamMatch(an, away)) {
      if (_staleFinalGuard(score, game)) { _recordStaleFinalBlock('legacy-forward'); continue; }
      return score;
    }
    if(espnTeamMatch(hn, away) && espnTeamMatch(an, home)) {
      if (_staleFinalGuard(score, game)) { _recordStaleFinalBlock('legacy-reversed'); continue; }
      return score;
    }
  }
  const _nmKey = `${game.away}|${game.home}`;
  if (!_noMatchRecorded.has(_nmKey) && typeof FIELD_OPERATIONS !== 'undefined') {
    _noMatchRecorded.add(_nmKey);
    FIELD_OPERATIONS.recordFailure({
      subsystem: 'scores', operation: 'find-espn-score-no-match',
      severity: 'trace', retryable: false,
      context: { home: game.home, away: game.away },
      error: new Error(`no match found: ${game.away} @ ${game.home}`),
      at: Date.now(),
    });
  }
  return null;
}

// Fetch domestic soccer fixtures from ESPN public API — free, no key
// Fetch any MLB games not already in the hardcoded schedule from ESPN
// ── MLB Stats API Adapter — Session 1 (May 16 2026) ──────────────────────────
// Source: statsapi.mlb.com (official, free, CORS-open, no key)
// Replaces ESPN as primary MLB data source; ESPN is the fallback.
// Broadcast chip resolution is fully automatic from API broadcasts array.
// Only ESPN GOTD and Peacock GOTD require manual ESPN_GOTD_SCHEDULE entry.

function parseBroadcasts(broadcasts, gameDate, date) {
  const result = {
    nationalBundle:  null,
    localBlackedOut: false,
    espnGOTD:        false, // set by ESPN_GOTD_SCHEDULE only — not auto-detected from API
    peacockGOTD:     false, // set by ESPN_GOTD_SCHEDULE only — not auto-detected from API
    mlbnShowcase:    false,
    apiRsnName:      null,  // home-market RSN name from API broadcasts (homeAway==='home')
    freeGame:        false,
    availableForStreaming: false,
  };
  const d = date instanceof Date ? date : new Date(date);

  for (const b of broadcasts) {
    const name = b.name ?? '';

    // API RSN — capture home-market non-national broadcast name as primary RSN source
    if (b.homeAway === 'home' && !b.isNational && !result.apiRsnName) {
      result.apiRsnName = name || null;
    }

    // Direct chip mapping — national exclusives (automatic)
    if (MLB_BROADCAST_CHIP_MAP[name]) {
      result.nationalBundle  = MLB_BROADCAST_CHIP_MAP[name];
      result.localBlackedOut = true;
      continue;
    }

    // Peacock — time-based resolution (automatic)
    // Leadoff (noon ET = 17:00 UTC) is NOT exclusive; local RSN still airs.
    // SNB (7pm ET = 23:00 UTC) IS exclusive; local RSN blacked out.
    if (name === 'Peacock') {
      const gameHourUTC = new Date(gameDate).getUTCHours();
      const isLeadoff   = gameHourUTC < PEACOCK_LEADOFF_HOUR_ET;
      if (isLeadoff) {
        result.nationalBundle  = 'MLB_LEADOFF';
        result.localBlackedOut = false;
      } else {
        const isPostCutoff = (
          d.getMonth() > SNB_NBC_CUTOFF.month ||
          (d.getMonth() === SNB_NBC_CUTOFF.month && d.getDate() >= SNB_NBC_CUTOFF.day)
        );
        result.nationalBundle  = isPostCutoff ? 'MLB_NBC' : 'MLB_PEACOCK_SNB';
        result.localBlackedOut = true;
      }
      continue;
    }

    // ESPN — skip; GOTD not reliably distinguishable by type field until verified.
    // espnGOTD is set via ESPN_GOTD_SCHEDULE[TODAY_ISO] in loadMLBSlate().
    // TODO: once type:'I' confirmed for GOTD, add: if(b.type==='I') result.espnGOTD=true;
    if (name === 'ESPN' || name === 'ESPN+') continue;

    // MLB Network — automatic blackout (covers Showcase and regular MLB Network games)
    if (name === 'MLB Network') {
      result.mlbnShowcase    = true;
      result.localBlackedOut = true;
      continue;
    }

    // Unknown national broadcast — catch-all for future new national TV partners
    if (b.isNational && !result.nationalBundle) {
      result.localBlackedOut = true;
    }
  }
  result.freeGame             = broadcasts.some(b => b.freeGame === true);
  result.availableForStreaming = broadcasts.some(b => b.availableForStreaming === true);
  return result;
}

function normalizeMLBStatus(code) {
  if (!code) return 'pregame';
  if (code === 'I' || code === 'MA') return 'live';
  if (code === 'F' || code === 'FT' || code === 'FR') return 'final';
  if (code === 'DR') return 'postponed';
  return 'pregame';
}

function normalizeMLBPeriod(linescore) {
  if (!linescore?.currentInning) return '';
  const ord  = linescore.currentInningOrd ?? `${linescore.currentInning}th`;
  const half = linescore.inningHalf === 'Bottom' ? 'Bot' : 'Top';
  return `${half} ${ord}`;
}

function normalizeMLBGame(g, date) {
  const home      = g.teams.home;
  const away      = g.teams.away;
  const homeAbbr  = home.team.abbreviation;
  const awayAbbr  = away.team.abbreviation;
  const homeScore = home.score ?? 0;
  const awayScore = away.score ?? 0;
  // PM-19 retro: was .toLocaleDateString('en-CA') — browser TZ leak. ET-anchor required
  // since MLB schedules are ET-anchored and game IDs must match schedule fetch keys.
  const dateStr   = fieldDateKey(date).replace(/-/g, '');
  const broadcast = parseBroadcasts(g.broadcasts ?? [], g.gameDate, date);

  return {
    id:             `MLB_${homeAbbr}_${awayAbbr}_${dateStr}`,
    sourceId:       String(g.gamePk),
    source:         'mlb-stats',
    home:           home.team.name,
    away:           away.team.name,
    homeTeam:       homeAbbr,
    awayTeam:       awayAbbr,
    homeScore,
    awayScore,
    score:          `${homeScore}-${awayScore}`,
    league:         'MLB',
    status:         normalizeMLBStatus(g.status?.statusCode),
    period:         normalizeMLBPeriod(g.linescore),
    margin:         Math.abs(homeScore - awayScore),
    start_time:     g.gameDate,
    confirmed:      true,   // Stats API is authoritative — confirmed source
    nationalBundle: broadcast.nationalBundle,
    localRsn:       broadcast.localBlackedOut ? null : (broadcast.apiRsnName ?? MLB_TEAM_RSN[homeAbbr] ?? 'MLB_LOCAL'),
    espnGOTD:       broadcast.espnGOTD,
    peacockGOTD:    broadcast.peacockGOTD,
    mlbnShowcase:   broadcast.mlbnShowcase,
    isPlayoff:      !['R', 'S', 'E', 'A'].includes(g.gameType ?? 'R'),
    startTimeTBD:   g.status?.startTimeTBD || false,
    freeGame:       broadcast.freeGame || false,
    availableForStreaming: broadcast.availableForStreaming || false,
    inning:         g.linescore?.currentInning ?? 0,
    inningHalf:     g.linescore?.inningHalf ?? '',
    outs:           g.linescore?.outs ?? 0,
    venue:          g.venue?.name ?? '',
    streams:        broadcast.nationalBundle
                      ? resolveBundle(broadcast.nationalBundle)
                      : resolveBundle('MLB_LOCAL'),
    _sport:         'Baseball (MLB)',
    _postponed:     normalizeMLBStatus(g.status?.statusCode) === 'postponed',
    // Probable pitchers (from probablePitcher(stats) hydration)
    homePitcher:    normalizeMLBPitcher(home.probablePitcher),
    awayPitcher:    normalizeMLBPitcher(away.probablePitcher),
    // HP umpire — from officials hydration (feeds UMP WATCH badge + J3 Brief)
    // officials[] each has: { official: { id, fullName }, officialType: 'Home Plate'|'First Base'|... }
    _hpUmpire:      (g.officials ?? []).find(o => o.officialType === 'Home Plate')?.official?.fullName ?? null,
    // Abbreviation aliases used by park factor + analytics getters
    _homeAbbr:      homeAbbr,
    _awayAbbr:      awayAbbr,
    // PM-28b: Extract per-inning H/R/E from MLB Stats API linescore hydration.
    // g.linescore.innings[] is available via hydrate=linescore in fetchMLBSchedule.
    // Previously discarded — caused eData.innings to always be [], silently breaking
    // getStatisticalExtremes() no-hitter check (line ~18149) and comeback check (~18169).
    // Schema per inning: { num, home:{runs,hits,errors}, away:{runs,hits,errors} }
    innings: (g.linescore?.innings || []).map(i => ({
      n:  i.num         ?? 0,
      hr: i.home?.runs  ?? 0,
      hh: i.home?.hits  ?? 0,
      he: i.home?.errors ?? 0,
      ar: i.away?.runs  ?? 0,
      ah: i.away?.hits  ?? 0,
      ae: i.away?.errors ?? 0,
    })),
    _adapterProof: {
      adapterId: 'mlb-stats-api',
      sourceId:  'mlb-stats-api-official',
      gamePk:    String(g.gamePk),
    },
  };
}

// Parse probable pitcher object from MLB Stats API probablePitcher(stats) hydration
function normalizeMLBPitcher(p){
  if(!p) return null;
  const season=p.stats?.find(s=>s.type?.displayName==='season');
  const stat=season?.splits?.[0]?.stat;
  return {
    name:        p.fullName||p.name||'TBD',
    id:          p.id,
    era:         stat?.era??null,
    wins:        stat?.wins??null,
    losses:      stat?.losses??null,
    whip:        stat?.whip??null,
    kPer9:       stat?.strikeoutsPer9Inn??null,
    ip:          stat?.inningsPitched??null,
    handedness:  p.pitchHand?.code??null,
  };
}

async function fetchMLBSchedule(date) {
  // PM-19 retro: ET-anchored date — schedules published in ET, fetch keys must match
  const dateStr = fieldDateKey(date);
  const url     = `${MLB_STATS_BASE}/schedule?sportId=1&date=${dateStr}&hydrate=broadcasts(all),team,linescore,probablePitcher(stats),officials`;
  try {
    const r = await fetch(url, {signal: AbortSignal.timeout(8000)});
    if (!r.ok) throw new Error(`MLB Stats API ${r.status}`);
    const data  = await r.json();
    const games = data.dates?.[0]?.games ?? [];
    return games.map(g => normalizeMLBGame(g, date));
  } catch (err) {
    if (FIELD_DEBUG) console.warn('[MLB Stats API] unavailable — ESPN fallback', err.message);
    captureFieldError('mlb:schedule-fetch', err, true);
    return null;
  }
}

// _mlbRecentPitchPaceMs / _mlbAvgPitchesPerAtBat (CC-CMD-2026-07-10-mlb-
// whos-up-next): real, measured inputs for the "who's up next" forecast
// below, derived from THIS game's own recent playEvents[] -- never a
// hardcoded pitch-clock constant or a league-average assumption. Both
// require a real sample before returning anything; thin/missing data
// returns null (the caller omits the forecast rather than guessing),
// matching this codebase's established silence-over-guessing discipline.
function _mlbRecentPitchPaceMs(feedData) {
  try {
    const allPlays = feedData?.liveData?.plays?.allPlays || [];
    const currentPlay = feedData?.liveData?.plays?.currentPlay;
    const recentPlays = allPlays.slice(-4);
    if (currentPlay) recentPlays.push(currentPlay);
    const pitchStarts = [];
    for (const p of recentPlays) {
      for (const ev of (p.playEvents || [])) {
        if (ev.isPitch === true && ev.startTime) {
          const t = new Date(ev.startTime).getTime();
          if (!isNaN(t)) pitchStarts.push(t);
        }
      }
    }
    pitchStarts.sort((a, b) => a - b);
    const gaps = [];
    for (let i = 1; i < pitchStarts.length; i++) {
      const gap = pitchStarts[i] - pitchStarts[i - 1];
      // Real pitch-to-pitch pacing is seconds, not minutes -- a generous
      // 3-minute ceiling excludes inning breaks/pitching changes/replay
      // reviews without assuming a specific pitch-clock number.
      if (gap > 0 && gap <= 180000) gaps.push(gap);
    }
    if (gaps.length < 3) return null; // genuinely thin -- omit, don't guess
    gaps.sort((a, b) => a - b);
    const mid = Math.floor(gaps.length / 2);
    return gaps.length % 2 ? gaps[mid] : Math.round((gaps[mid - 1] + gaps[mid]) / 2);
  } catch (_) { return null; }
}
function _mlbAvgPitchesPerAtBat(feedData) {
  try {
    const allPlays = feedData?.liveData?.plays?.allPlays || [];
    const completedPlays = allPlays.filter(p => p.playEvents && p.playEvents.length);
    if (completedPlays.length < 3) return null;
    let totalPitches = 0;
    for (const p of completedPlays) totalPitches += (p.playEvents || []).filter(ev => ev.isPitch === true).length;
    if (totalPitches === 0) return null;
    return totalPitches / completedPlays.length;
  } catch (_e) { captureFieldError('mlb:avg-pitches-per-atbat', _e, true); return null; }
}

// fetchMLBLiveGame — Heat Index inputs (baserunners, outs, count) + current matchup
// currentPlay.matchup.{batter,pitcher}.fullName added 2026-05-30
// battingOrder/currentBatterId/playerNames/recentPitchPaceMs/avgPitchesPerAtBat
// added 2026-07-10 (CC-CMD-2026-07-10-mlb-whos-up-next), for _mlbWhosUpNext().
async function fetchMLBLiveGame(gamePk) {
  const url  = `${MLB_STATS_BASE.replace('v1','v1.1')}/game/${gamePk}/feed/live`;
  const r    = await fetch(url);
  if (!r.ok) throw new Error(`MLB live game ${r.status}`);
  const data = await r.json();
  const lp   = data.liveData?.linescore ?? {};
  const play = data.liveData?.plays?.currentPlay ?? {};
  const homeBattingOrder = data.liveData?.boxscore?.teams?.home?.battingOrder || [];
  const awayBattingOrder = data.liveData?.boxscore?.teams?.away?.battingOrder || [];
  const players = data.gameData?.players || {};
  const playerNames = {};
  [...homeBattingOrder, ...awayBattingOrder].forEach(id => { playerNames[id] = players[`ID${id}`]?.fullName || null; });
  return {
    inning:     lp.currentInning ?? 0,
    inningHalf: lp.inningHalf ?? '',
    outs:       lp.outs ?? 0,
    balls:      play.count?.balls ?? 0,
    strikes:    play.count?.strikes ?? 0,
    onFirst:    !!lp.offense?.first,
    onSecond:   !!lp.offense?.second,
    onThird:    !!lp.offense?.third,
    awayScore:  lp.teams?.away?.runs ?? 0,
    homeScore:  lp.teams?.home?.runs ?? 0,
    // Current at-bat matchup — journalism + situation context
    batter:  play.matchup?.batter?.fullName  || null,
    pitcher: play.matchup?.pitcher?.fullName || null,
    // "Who's up next" forecast inputs — all real, measured from THIS
    // game's own data, never a hardcoded/league constant.
    currentBatterId:    play.matchup?.batter?.id ?? null,
    battingOrder:       { home: homeBattingOrder, away: awayBattingOrder },
    playerNames,
    recentPitchPaceMs:  _mlbRecentPitchPaceMs(data),
    avgPitchesPerAtBat: _mlbAvgPitchesPerAtBat(data),
  };
}

// _mlbWhosUpNext: mechanical lineup-rotation forecast from real batting
// order + this game's own real, measured pace -- NEVER predicts an
// outcome (hit, strikeout, etc.), matching this codebase's anti-
// fabrication rules. aheadSlots is an explicit, documented parameter
// (default 3), not a silently-hardcoded assumption. Returns null (the
// caller omits the forecast) if the current batter can't be located in
// a real, full 9-slot order, or if pace/pitches-per-AB data is thin.
function _mlbWhosUpNext(liveGame, aheadSlots = 3) {
  if (!liveGame) return null;
  const { recentPitchPaceMs, avgPitchesPerAtBat, currentBatterId, inningHalf, battingOrder, playerNames } = liveGame;
  if (recentPitchPaceMs == null || avgPitchesPerAtBat == null || !currentBatterId) return null;
  const offenseSide = inningHalf === 'Top' ? 'away' : (inningHalf === 'Bottom' ? 'home' : null);
  if (!offenseSide) return null;
  const order = battingOrder?.[offenseSide] || [];
  if (order.length !== 9) return null; // real full lineup not available -- don't guess
  const curIdx = order.indexOf(currentBatterId);
  if (curIdx === -1) return null; // can't locate current batter in the order -- don't guess a slot
  const targetIdx = (curIdx + aheadSlots) % 9;
  const targetBatterId = order[targetIdx];
  const targetName = targetBatterId != null ? playerNames?.[targetBatterId] : null;
  if (!targetBatterId || !targetName) return null;
  const estMinutes = Math.round((aheadSlots * avgPitchesPerAtBat * recentPitchPaceMs) / 60000);
  if (!(estMinutes > 0)) return null; // degenerate estimate -- don't show a bogus "0 min"
  return { name: targetName, slot: targetIdx + 1, estMinutes };
}

// mlbBaserunnerBonus removed (CC-CMD-2026-07-15-never-adopted-utilities-
// disposal): its own comment said "wired into Heat Index in subsequent
// session" but no Heat Index aggregator was ever built. Confirmed
// genuinely superseded, not just unadopted -- applyQW1SituationBonus's
// real, live BASEBALL section already computes a more refined version
// of the identical baserunner/outs/inning drama signal independently.

// loadMLBSlate — main entry point; wired into fetchMLBFixtures below
async function loadMLBSlate(date) {
  const mlbGames = await fetchMLBSchedule(date);
  if (mlbGames) {
    // CC-CMD-2026-07-16-broadcast-chip-durable-fix: this is the PRIMARY,
    // boot-time render path (fetchMLBFixtures -> loadMLBSlate ->
    // normalizeMLBGame/parseBroadcasts) -- it previously consulted ONLY
    // this file's own manual ESPN_GOTD_SCHEDULE table, never the server's
    // real structural GOTD detection (build-field-data.js's
    // fetchEspnMlbGotd, the 'ESPN Unlmtd' signal from site.api.espn.com,
    // already wired and working -- confirmed real, not assumed) sitting
    // right there in field-data-today.json. Cross-referencing it here
    // (same _mlbOverlayMap-style home|away key convention already used
    // elsewhere in this file) makes GOTD detection durable without a
    // human extending a date table going forward, closing the long-
    // standing TODO parseBroadcasts's own comment names.
    // Also closes a real, separate gap: parseBroadcasts deliberately
    // skips ESPN broadcasts entirely (`if (name === 'ESPN' ...) continue`)
    // -- correct for avoiding false GOTD positives, but it means this
    // path never checked ESPN_CABLE_SCHEDULE (the ~30-games/season ESPN
    // cable exclusive window, a real, separate, already-current manual
    // table -- distinguishing it from GOTD by broadcast NAME alone is
    // documented as unreliable, per this file's own ESPN_CABLE_SCHEDULE
    // comment, so it correctly stays a maintained lookup, not name-based
    // auto-detection) at all -- a cable game (like 2026-07-16 NYM@PHI,
    // real, confirmed) silently got zero ESPN signal from this path.
    const _mlbFieldDataByKey = {};
    (_fieldDataCache?.schedules?.mlb || []).forEach(o => { _mlbFieldDataByKey[`${o.home}|${o.away}`] = o; });
    return mlbGames.map(g => {
      const key = `${g.awayTeam}@${g.homeTeam}`;
      const serverEntry = _mlbFieldDataByKey[`${g.home}|${g.away}`];
      const isEspnGOTD    = g.espnGOTD    || serverEntry?.espnGOTD    || ESPN_GOTD_SCHEDULE[TODAY_ISO]    === key;
      const isPeacockGOTD = g.peacockGOTD || serverEntry?.peacockGOTD || PEACOCK_GOTD_SCHEDULE[TODAY_ISO] === key;
      // ESPN cable exclusive — independent of GOTD; only consulted when
      // nothing else (server nationalBundle, or this path's own live
      // broadcast parse) already identified a national broadcast.
      const _cableSlot = (!isEspnGOTD && !isPeacockGOTD && !g.nationalBundle && !serverEntry?.nationalBundle)
        ? _lookupEspnCableSlot(TODAY_ISO, key) : null;
      const nationalBundle = g.nationalBundle || serverEntry?.nationalBundle
        || (_cableSlot ? (_cableSlot.abc ? 'MLB_ABC' : 'MLB_ESPN_CABLE') : null);

      // ESPN GOTD — NON-EXCLUSIVE: shows espnapp + local RSN chips (in-market)
      // Doc ref: "Code Changes Log MLB Local Chip Rule May 11" — MLB_ESPNU_GOTD: ["espnapp","rsn"]
      const streams = isEspnGOTD      ? resolveBundle('MLB_ESPNU_GOTD')
                    : isPeacockGOTD   ? resolveBundle('MLB_PEACOCK_GOTD')
                    : nationalBundle  ? resolveBundle(nationalBundle)
                    : g.streams;

      // Peacock GOTD weekday — EXCLUSIVE: local RSN suppressed (blacked out)
      // ESPN GOTD — NON-EXCLUSIVE: local RSN still shows (in-market viewers)
      const localRsn = isPeacockGOTD ? null : g.localRsn;

      return {
        ...g,
        espnGOTD:    isEspnGOTD,
        peacockGOTD: isPeacockGOTD,
        nationalBundle,
        streams,
        localRsn,
      };
    });
  }
  if (FIELD_DEBUG) console.warn('[MLB] Stats API unavailable — using ESPN fallback');
  return null;
}

// ── Live MLB status refresh (dedicated, lightweight — no full re-render) ──
// fetchMLBFixtures() only ever runs once (boot). ESPN score-matching
// (_n.state, driving espn-live/espn-final/circadian via renderESPNScores)
// can lag up to 15 min behind real status (ESPN_REFRESH_FINISHED mode --
// see initNightOwlPoll's own comment for the same characterization).
// This keeps MLB's own, faster, authoritative status current without
// paying for a full renderAll() rebuild on every refresh.
async function refreshMLBStatus() {
  if (!allData?.sports) return;
  const mlbSec = allData.sports.find(s => s.sport === 'Baseball (MLB)');
  if (!mlbSec || !mlbSec.games?.length) return;

  let freshGames;
  try {
    freshGames = await loadMLBSlate(new Date());
  } catch (e) {
    captureFieldError('mlb-status-refresh', e, false);
    return;
  }
  if (!freshGames || !freshGames.length) return;

  // Match by the same home|away|hour key fetchMLBFixtures() already uses
  // for doubleheader-safe matching -- reuse the established convention,
  // don't invent a new key shape.
  const keyOf = g => `${g.home}|${g.away}|${(g.start_time||'').slice(0,13)}`;
  const freshByKey = new Map(freshGames.map(g => [keyOf(g), g]));

  for (const game of mlbSec.games) {
    const fresh = freshByKey.get(keyOf(game));
    if (!fresh || fresh.status === game.status) continue; // no change

    const oldStatus = game.status;
    game.status = fresh.status;
    // Also refresh score fields -- a status change to 'final' without
    // an updated final score would be a half-applied, misleading patch.
    if (fresh.homeScore != null) game.homeScore = fresh.homeScore;
    if (fresh.awayScore != null) game.awayScore = fresh.awayScore;

    const card = document.querySelector(`[data-gameid="${game._id}"]`);
    if (!card) continue; // card not currently rendered (filtered out, etc.) -- fine, allData is still correct for next full render

    const isLive  = fresh.status === 'live';
    const isFinal = fresh.status === 'final' || fresh.status === 'postponed';
    syncCardAttributes(card, game, null, isLive, isFinal);

    if (FIELD_DEBUG) console.debug('[MLB] status refresh:', game.home, oldStatus, '->', fresh.status);
  }

  // ── Correct a stuck ESPN/V2 score witness (direct user request,
  // 2026-07-12: "MLB game cards always get stuck at INN 9, never final") ──
  // Root cause, confirmed live in production before this fix: game.status
  // above already flips to 'final' correctly (this function's own header
  // comment calls it "faster, authoritative"), but nothing before this
  // point ever touched the visible card. renderESPNScores() -- the ONLY
  // code path that toggles the espn-live/espn-final classes and writes the
  // score-wrap's period text -- reads exclusively from
  // _scoresBySource/espnScores via findScore()/findESPNScore(), never from
  // game.status. api-sports.io's own `state` field for MLB has a
  // documented history of not resolving reliably (see mapV2ToESPN's
  // CC-CMD-2026-07-05-pickem-cfl-mlb-gaps comment on the same variable) --
  // when it never reports 'post' for a given game, the card stays visually
  // frozen on its last live inning forever. Not a new fallback source:
  // this corrects the existing, single score-witness store that
  // renderESPNScores() already reads, using data this function already
  // trusts as authoritative, then lets that one existing render path do
  // the actual drawing. Runs every poll (not just on the transition above)
  // so a witness that resists correction once keeps getting corrected
  // until it sticks.
  let anyWitnessCorrected = false;
  for (const game of mlbSec.games) {
    if (game.status !== 'final' && game.status !== 'postponed') continue;
    for (const entry of Object.values(_scoresBySource)) {
      if (!entry) continue;
      const probe = entry.espn || entry.apisports;
      if (!probe) continue;
      const matches = (espnTeamMatch(probe.homeName, game.home) && espnTeamMatch(probe.awayName, game.away)) ||
                      (espnTeamMatch(probe.homeName, game.away) && espnTeamMatch(probe.awayName, game.home));
      if (!matches) continue;
      for (const w of ['espn', 'apisports']) {
        if (entry[w] && entry[w].state !== 'post') {
          entry[w] = { ...entry[w], state: 'post', homeScore: game.homeScore, awayScore: game.awayScore, ts: Date.now() };
          anyWitnessCorrected = true;
        }
      }
    }
    for (const [legacyKey, legacyEntry] of Object.entries(espnScores)) {
      if (!legacyEntry || legacyEntry.state === 'post') continue;
      const matches = (espnTeamMatch(legacyEntry.homeName, game.home) && espnTeamMatch(legacyEntry.awayName, game.away)) ||
                      (espnTeamMatch(legacyEntry.homeName, game.away) && espnTeamMatch(legacyEntry.awayName, game.home));
      if (!matches) continue;
      espnScores[legacyKey] = { ...legacyEntry, state: 'post', homeScore: game.homeScore, awayScore: game.awayScore };
      espnScoreTs[legacyKey] = Date.now();
      anyWitnessCorrected = true;
    }
  }
  if (anyWitnessCorrected && typeof renderESPNScores === 'function') renderESPNScores();

  // "Who's up next" forecast (CC-CMD-2026-07-10-mlb-whos-up-next): the
  // real, existing live-MLB-card update cycle -- fetchMLBLiveGame() had
  // zero callers before this. One extra fetch per currently-live MLB
  // game per 90s cycle (statsapi.mlb.com is CORS-open/free, already
  // called unguarded elsewhere in this file with no rate-limit concern
  // on record). Silently omits per-game on any fetch error or thin data
  // -- never blocks the status refresh above.
  await Promise.all(mlbSec.games.filter(g => g.status === 'live' && g.sourceId).map(async game => {
    const card = document.querySelector(`[data-gameid="${game._id}"]`);
    if (!card) return;
    try {
      const liveGame = await fetchMLBLiveGame(game.sourceId);
      const forecast = _mlbWhosUpNext(liveGame);
      card.querySelectorAll('.mlb-whos-up-next').forEach(el => el.remove());
      const chip = renderMLBWhosUpNextChip(forecast);
      if (chip) {
        const matchup = card.querySelector('.matchup');
        if (matchup) matchup.insertAdjacentHTML('afterend', chip);
      }
    } catch (e) {
      captureFieldError('mlb-whos-up-next', e, false);
    }
  }));
}

// Mirrors initNightOwlPoll's exact proven cadence (90s interval, first
// check shortly after boot) -- same reasoning applies here: MLB games
// need a check faster than whatever the slow path (ESPN, or in
// fetchMLBFixtures' case, nothing at all after boot) provides.
(function initMLBStatusPoll(){
  setTimeout(refreshMLBStatus, 10000); // first check: 10s after load (after initial fixtures settle)
  setInterval(refreshMLBStatus, 90000); // then every 90s, matching Night Owl's cadence
})();

async function fetchMLBFixtures(){
  if(!allData||!allData.sports) return;
  const today = new Date();

  // ── Try MLB Stats API first (official, free, CORS-open) ──────────────────
  // ARCHITECTURE: Adapter is PRIMARY source. mlbRaw is the OVERRIDE/EXCEPTION list
  // for national TV games (Apple Friday, Peacock Sunday, TBS Tuesday, FOX/FS1).
  // For all-local days, mlbRaw = [] and adapter provides the full slate.
  // This eliminates the need to manually enter standard local games each daily update.
  try {
    const mlbGames = await loadMLBSlate(today);
    if (mlbGames && mlbGames.length > 0) {
      let mlbSec = allData.sports.find(s => s.sport === 'Baseball (MLB)');

      // Collect national TV overrides from mlbRaw (games with nationalBundle set)
      const nationalOverrides = (mlbSec?.games || []).filter(g => g.nationalBundle);
      // Hour-bucket key: home|away|YYYY-MM-DDTHH prevents doubleheader games (same matchup,
      // different hours) from collapsing onto one override. Exact start_time string match would
      // be too brittle — minor API timing discrepancies (23:10 vs 23:15) would break the merge.
      // Games 1+ hour apart get distinct keys; games within the same hour still merge correctly.
      const gameHourKey = g => `${g.home}|${g.away}|${(g.start_time||'').slice(0,13)}`;
      const nationalKeys = new Set(nationalOverrides.map(gameHourKey));

      // REPLACE mlbSec.games: API games + preserve national TV overrides from mlbRaw
      // API games that match a national override are replaced by the override (richer data)
      const mergedGames = mlbGames.map(apiGame => {
        const key = gameHourKey(apiGame);
        return nationalKeys.has(key)
          ? nationalOverrides.find(o => gameHourKey(o) === key)  // mlbRaw override wins
          : apiGame;                                              // API game
      });
      // Add any national overrides not covered by the API (e.g. future confirmed entries)
      nationalOverrides.forEach(o => {
        const key = gameHourKey(o);
        if (!mlbGames.some(g => gameHourKey(g) === key)) mergedGames.push(o);
      });

      if (!mlbSec) { mlbSec = {sport:'Baseball (MLB)', games:[]}; allData.sports.push(mlbSec); }
      // Deterministic time-sort — without this the MLB section renders in raw
      // MLB-API order plus appended overrides, so the list reorders between renders.
      mlbSec.games = mergedGames
        .map(g => ({...g, _sport:'Baseball (MLB)', _dataSource: g.source || null}))
        .sort((a,b)=>{
          const ta=+new Date(a.start_time||0), tb=+new Date(b.start_time||0);
          return ta!==tb ? ta-tb : String(a._id||a.home||'').localeCompare(String(b._id||b.home||''));
        });
      // Tag doubleheaders: two games same matchup same day → Game 1 / Game 2 label
      const _dhCount=new Map();
      mlbSec.games.forEach(g=>{const k=`${g.home}|${g.away}`;_dhCount.set(k,(_dhCount.get(k)||0)+1);});
      const _dhSeq=new Map();
      mlbSec.games.forEach(g=>{
        const k=`${g.home}|${g.away}`;
        if((_dhCount.get(k)||0)>1){const n=(_dhSeq.get(k)||0)+1;_dhSeq.set(k,n);g._subtitle=`Game ${n}`;}
      });
      buildFilters(allData.sports);
      scheduleRenderAll();
      // Night Owl fix: now that MLB games are in allData, re-run finals detection.
      // checkForNewFinals() only matches against allData.sports — if games weren't
      // populated yet on first ESPN poll (race condition), finals were missed.
      // REMEDY P6: dispatch event instead of calling fetchESPNScores() directly.
      // Calling fetchESPNScores() here spawns a second scheduler chain — both persist,
      // eventually causing 4+ parallel pollers. Instead, signal the existing chain
      // to reschedule itself to 1s if MLB still hasn't been polled.
      window.dispatchEvent(new CustomEvent('field:data-ready', {detail:{sport:'mlb'}}));
      window._mlbDataReady = true; // Playwright sentinel — set only by MLB Stats API path
      setTimeout(()=>{
        checkForNewFinals();
        renderNightOwlRecap().catch(e=>captureFieldError('night-owl',e,false));
        injectJ1J4Badges();
      }, 400);
      if (FIELD_DEBUG) console.log(`[MLB Stats API] Primary source: ${mergedGames.length} games (${nationalOverrides.length} national TV overrides)`);
      return; // success — skip ESPN fallback
    }
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[MLB Stats API] error, falling back to ESPN:', e.message);
  }

  // ── ESPN fallback (original logic) ───────────────────────────────────────
  const dateStr = today.getFullYear()
    + String(today.getMonth()+1).padStart(2,"0")
    + String(today.getDate()).padStart(2,"0");
  try{
    const r = await fetch(`${ESPN_BASE}/baseball/mlb/scoreboard?dates=${dateStr}&limit=20`);
    if(!r.ok) return;
    const data = await r.json();
    const events = data.events||[];
    if(!events.length) return;
    let mlbSec = allData.sports.find(s=>s.sport==="Baseball (MLB)");
    if(!mlbSec){ mlbSec={sport:"Baseball (MLB)",games:[]}; allData.sports.push(mlbSec); }
    let added=0;
    events.forEach(ev=>{
      const comp=(ev.competitions||[])[0]; if(!comp) return;
      const comps=comp.competitors||[];
      const home=comps.find(t=>t.homeAway==="home")||comps[0];
      const away=comps.find(t=>t.homeAway==="away")||comps[1];
      if(!home||!away) return;
      const hN=home.team?.displayName||"";
      const aN=away.team?.displayName||"";
      // Skip if already in schedule (hardcoded or previously added)
      const exists=(mlbSec.games||[]).some(g=>
        espnTeamMatch(g.home,hN)&&espnTeamMatch(g.away,aN)
      );
      if(exists) return;
      const hKey=hN.toLowerCase().replace(/[^a-z0-9]/g,"").slice(0,12);
      const aKey=aN.toLowerCase().replace(/[^a-z0-9]/g,"").slice(0,12);
      mlbSec.games.push({
        _id:"mlb_"+hKey+"_"+aKey, _sport:"Baseball (MLB)",
        home:hN, away:aN,
        league:"MLB",
        start_time:ev.date||"",
        venue:(comp.venue?.fullName||""),
        streams:resolveBundle("MLB_LOCAL"),
        _postponed: ev.status?.type?.name === "STATUS_POSTPONED",
      });
      added++;
    });
    if(added>0){ buildFilters(allData.sports); scheduleRenderAll(); }
    if(FIELD_DEBUG) console.log(`[MLB] Added ${added} games from ESPN`);
  }catch(e){ if(FIELD_DEBUG) console.warn("[MLB] fixture fetch failed:",e.message); }
}

// ── FPL Live Score Adapter ─────────────────────────────────────────────────
// Source: fantasy.premierleague.com/api via field-relay-nba /fpl/ route
// Legal: Official PL fantasy game — public API, CORS-only restriction
// Architecture: relay worker fetches server-side, FIELD calls relay
//
// Three endpoints used:
//   /bootstrap-static → {teams:[{id,name,short_name}]} — team ID lookup (24hr cache)
//   /fixtures?event={gw} → [{team_h, team_a, team_h_score, team_a_score, minutes, started, finished}]
//   (live endpoint available for future journalism enrichment)
//
// Score injection: writes into espnScores[`${home}|${away}`] — same schema
// as fetchSoccerFixtures ESPN path. periodPrefix:"'" triggers soccer clock display.

const FPL_RELAY_BASE = 'https://field-relay-nba.jeffunglesbee.workers.dev/fpl';
const BDL_RELAY_BASE  = 'https://field-relay-nba.jeffunglesbee.workers.dev/bdl';   // BallDontLie — apiKey injected server-side
const MLS_RELAY_BASE  = 'https://field-relay-nba.jeffunglesbee.workers.dev/mls/stats';

const MLS_SEASON_2026 = 'MLS-SEA-0001KA';
const MLS_COMPETITION = 'MLS-COM-000001';
const _mlsTeamMap = {};     // opta_id → { name, abbreviation }
const _mlsGameOptaIds = {}; // "home_opta|away_opta" → game opta_id

async function fetchMLSLive() {
  try {
    // MLS relay match_date field uses ET date. Query both ET and UTC dates
    // to cover the full evening window (same dual-date pattern as fetchV2AllScores).
    // 7:30pm ET MLS games = ET date Jun 5 but UTC date Jun 6.
    // Uses fieldNowET() — DST-correct, no hardcoded offset.
    const _mlsET = fieldNowET();
    const utcDate = new Date().toISOString().slice(0,10);
    const etDate  = _mlsET.date;
    // Query the earlier date (ET); if ET==UTC, one query suffices.
    // The relay returns all matches for that date — dedup by opta key is safe.
    const datesToFetch = utcDate === etDate ? [utcDate] : [etDate, utcDate];
    const allMatches = [];
    for (const today of datesToFetch) {
      const url = MLS_RELAY_BASE +
        `/v1/matches?match_date%5Bgte%5D=${today}&match_date%5Blte%5D=${today}` +
        `&include=home_club_match&include=away_club_match&include=home_club&include=away_club&per_page=100`;
      const r = await fetch(url, {signal: AbortSignal.timeout(6000)});
      if (!r.ok) continue;
      const d = await r.json();
      const matches = d.schedule || d.matches || d || [];
      // Dedup: skip if we already have this game_id from the other date query
      for (const m of matches) {
        const gid = m.game_id || m.opta_id;
        if (!gid || allMatches.some(x => (x.game_id||x.opta_id) === gid)) continue;
        allMatches.push(m);
      }
    }
    allMatches.forEach(m => {
      const hClub = m.home_club||{}, aClub = m.away_club||{};
      const hMatch = m.home_club_match||{}, aMatch = m.away_club_match||{};
      const hId = hClub.opta_id, aId = aClub.opta_id;
      if (hId) _mlsTeamMap[hId] = {name:hClub.name,abbreviation:hClub.abbreviation};
      if (aId) _mlsTeamMap[aId] = {name:aClub.name,abbreviation:aClub.abbreviation};
      if (!hId||!aId) return;
      const key = `${hId}|${aId}`;
      const gameOptaId = m.game_id||m.opta_id;
      if (gameOptaId) _mlsGameOptaIds[key] = gameOptaId;
      const period = m.period||'';
      const isFinal = m.is_final||period==='FullTime';
      const isLive = !isFinal&&period&&period!=='PreMatch';
      espnScores[key] = {
        state:isFinal?'post':isLive?'in':'pre',
        period:period==='FirstHalf'?1:period==='SecondHalf'?2:0,
        clock:m.minute_display||'', detail:m.minute_display||(isFinal?'FT':period||''),
        homeScore:hMatch.score??0, awayScore:aMatch.score??0,
        homeName:hClub.name||'', awayName:aClub.name||'',
        home:hClub.name||'', away:aClub.name||'',
        homeWinning:(hMatch.score??0)>(aMatch.score??0),
        // CC-CMD-2026-07-16-mls-schedule-cards: _sport must be the short V2
        // sportKey ('mls'), not the section label ('MLS Soccer') -- this is
        // the same convention mapV2ToESPN uses (_sport: fg.sport, e.g.
        // "mls") and the one injectV2SportSection('mls','MLS Soccer')
        // filters on (espnScores[k]?._sport === sportKey). The old value
        // never matched that filter, so this one-shot boot fetch's data
        // was invisible to schedule-section injection regardless of the
        // section-creation gap fixed alongside this.
        periodPrefix:"'", source:'mls-relay', _sport:'mls',
        _mlsOptaHome:hId, _mlsOptaAway:aId, _gameId:String(gameOptaId||key),
      };
      espnScoreTs[key] = Date.now();
    });
    if (FIELD_DEBUG) console.log(`[MLS-relay] ${allMatches.length} matches (${datesToFetch.join('+')})`);
    return allMatches;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[MLS-relay] fetchMLSLive failed:', e.message);
    return [];
  }
}


// ── OpenF1 — Formula 1 live timing ───────────────────────────────────────────
const OPENF1_BASE = 'https://api.openf1.org/v1';
let _openF1SessionCache = {key:null,expiry:0,isLive:false};
let _openF1PollInterval = null;
let _openF1Drivers = {};

async function fetchOpenF1CurrentSession(){
  if(_openF1SessionCache.key&&Date.now()<_openF1SessionCache.expiry) return _openF1SessionCache;
  try{
    const today=new Date().toISOString().slice(0,10);
    const r=await fetch(`${OPENF1_BASE}/sessions?date_start>=${today}&session_type=Race,Qualifying,Sprint`,{signal:AbortSignal.timeout(5000)});
    const sessions=await r.json();
    if(!sessions?.length){_openF1SessionCache={key:null,expiry:Date.now()+300000,isLive:false};return _openF1SessionCache;}
    const s=sessions[sessions.length-1];
    const start=new Date(s.date_start).getTime(),end=new Date(s.date_end||s.date_start).getTime()+1800000,now=Date.now();
    _openF1SessionCache={key:s.session_key,name:s.session_name,location:s.location,year:s.year,
      isLive:now>=start-1800000&&now<=end,start,end,expiry:Date.now()+60000};
    return _openF1SessionCache;
  }catch(e){_openF1SessionCache={key:null,expiry:Date.now()+60000,isLive:false};return _openF1SessionCache;}
}
async function fetchOpenF1Positions(k){try{const r=await fetch(`${OPENF1_BASE}/position?session_key=${k}`,{signal:AbortSignal.timeout(5000)});const raw=await r.json();const l={};(raw||[]).forEach(p=>{if(!l[p.driver_number]||p.date>l[p.driver_number].date)l[p.driver_number]=p;});return Object.values(l).sort((a,b)=>a.position-b.position);}catch(e){return[];}}
async function fetchOpenF1RaceControl(k,since){try{const q=since?`?session_key=${k}&date>=${since}`:`?session_key=${k}`;const r=await fetch(`${OPENF1_BASE}/race_control${q}`,{signal:AbortSignal.timeout(5000)});return await r.json();}catch(e){return[];}}
async function fetchOpenF1Drivers(k){if(_openF1Drivers[k])return _openF1Drivers[k];try{const r=await fetch(`${OPENF1_BASE}/drivers?session_key=${k}`,{signal:AbortSignal.timeout(5000)});const drivers=await r.json();_openF1Drivers[k]={};(drivers||[]).forEach(d=>{_openF1Drivers[k][d.driver_number]={name:d.full_name,abbr:d.name_acronym,team:d.team_name,teamColour:'#'+d.team_colour?.replace(/^#/,'')};});return _openF1Drivers[k];}catch(e){return{};}}

window._openF1LiveData={positions:[],raceControl:[],drivers:{},sessionKey:null,lastUpdate:0};

async function pollOpenF1(){
  const session=await fetchOpenF1CurrentSession();
  if(!session.isLive||!session.key) return;
  if(!_openF1Drivers[session.key]) await fetchOpenF1Drivers(session.key);
  const [positions,control]=await Promise.all([fetchOpenF1Positions(session.key),fetchOpenF1RaceControl(session.key,window._openF1LiveData.lastUpdate?new Date(window._openF1LiveData.lastUpdate).toISOString():null)]);
  window._openF1LiveData={positions,raceControl:control,drivers:_openF1Drivers[session.key]||{},sessionKey:session.key,lastUpdate:Date.now()};
  if(typeof fieldEvents!=='undefined'){const p1=positions[0];if(p1){const prev=window._openF1LiveData._prevP1;if(prev&&prev!==p1.driver_number)fieldEvents.dispatchEvent(new CustomEvent('field:lead_change',{detail:{gameId:'f1_live',sport:'f1',newLeader:p1.driver_number,prevLeader:prev,source:'openf1',scoreline:`P1: #${p1.driver_number}`}}));window._openF1LiveData._prevP1=p1.driver_number;}}
}

async function startOpenF1Engine(){
  if(_openF1PollInterval) return;
  const session=await fetchOpenF1CurrentSession();
  if(!session.isLive) return;
  await pollOpenF1();
  _openF1PollInterval=setInterval(()=>pollOpenF1().catch(e=>captureFieldError('openf1-poll',e,true)),4000);
  const msLeft=session.end-Date.now();
  if(msLeft>0) setTimeout(()=>{clearInterval(_openF1PollInterval);_openF1PollInterval=null;},msLeft+60000);
}




// ── First Lead Change Drama Burst ─────────────────────────────────────────
// _leadTracker: tracks who is leading each live game across poll cycles
// _leadChangeBurst: active burst values {gameId: {startPoll, value:15}}
// When lead flips in isFinalPeriod → +15 burst, decays linearly over 3 polls
const _leadTracker    = new Map(); // gameId → {leadingTeam, period}
const _leadChangeBurst = new Map(); // gameId → {startPoll, value}
let _pollCycle = 0; // increments each fetchESPNScores() call

function getLeadChangeBurst(gameId) {
  const b = _leadChangeBurst.get(gameId);
  if (!b) return 0;
  const age = _pollCycle - b.startPoll;
  if (age >= 3) { _leadChangeBurst.delete(gameId); return 0; }
  return Math.round(b.value * (1 - age / 3)); // linear decay over 3 polls
}

