  // ── NBA ─────────────────────────────────────────────────────────────────
  'NBA_ESPN':     { pbp: 'Dave Pasch',       color: 'Hubie Brown',         tier: 'B' },
  'NBA_ABC':      { pbp: 'Mike Breen',       color: 'Richard Jefferson · Tim Legler',      tier: 'A' },
  'NBA_NBC':      { pbp: 'Mike Tirico',      color: 'Reggie Miller',       tier: 'A', sideline: 'Kristen Ledlow' },
  'NBA_PRIME':    { pbp: 'TBD',             color: 'TBD',                  tier: 'B' },
