// ── IP Geolocation (free, no key, ipapi.co) ────────────────────────────────
// Auto-sets timezone on first load. Respects manual selection. 3s timeout.
// ══ PRIVACY + CONSENT (C2) ══════════════════════════════════════════════════
function initPrivacyBanner(){
  const choice=localStorage.getItem('field_privacy_v1');
  if(choice) return; // already decided
  const banner=getEl('privacy-banner');
  if(!banner) return;
  banner.style.display='flex';
  const accept=getEl('privacy-accept');
  if(accept) accept.addEventListener('click',()=>{
    localStorage.setItem('field_privacy_v1','geo');
    banner.style.display='none';
    autoGeolocate();
  });
  const decline=getEl('privacy-decline');
  if(decline) decline.addEventListener('click',()=>{
    localStorage.setItem('field_privacy_v1','no-geo');
    banner.style.display='none';
  });
  const pLink=getEl('privacy-policy-link');
  if(pLink) pLink.addEventListener('click',e=>{
    e.preventDefault();
    showPrivacyPolicyModal();
  });
}

function showPrivacyPolicyModal(){
  const overlay=getEl('privacy-modal-overlay');
  if(overlay) overlay.style.display='flex';
}

function isEUTimezone(){
  const tz=Intl.DateTimeFormat().resolvedOptions().timeZone||'';
  return tz.startsWith('Europe/')||tz.startsWith('Atlantic/');
}

function showEUPushConsent(onAccept){
  const el=getEl('eu-push-consent');
  if(!el) return;
  el.style.display='block';
  const enable=getEl('eu-push-enable');
  if(enable) enable.addEventListener('click',()=>{
    localStorage.setItem('field_push_consent_v1','informed');
    el.style.display='none';
    if(onAccept) onAccept();
  },{once:true});
  const skip=getEl('eu-push-skip');
  if(skip) skip.addEventListener('click',()=>{
    el.style.display='none';
  },{once:true});
}

(async function autoGeolocate(){
  try{
    if(localStorage.getItem("field_tz")) return; // Respect manual TZ
    // C2 consent gate — replaces EU timezone bypass
    const privacyChoice = localStorage.getItem('field_privacy_v1');
    if(privacyChoice === 'no-geo') return; // user declined
    if(privacyChoice !== 'geo') return;    // not yet decided — wait for banner
    const r = await fetch("https://ipapi.co/json/",{signal:AbortSignal.timeout(3000)});
    if(!r.ok) return;
    const geo = await r.json();
    if(!geo.timezone) return;
    const tzSel = document.getElementById("tz-select");
    if(!tzSel) return;
    for(const opt of tzSel.options){
      if(opt.value===geo.timezone){ tzSel.value=geo.timezone; tzSel.dispatchEvent(new Event("change")); break; }
    }
    if(geo.city&&geo.region_code){
      sessionStorage.setItem("field_geo_city",    geo.city+", "+geo.region_code);
      localStorage.setItem("field_geo_tz",       geo.timezone);
      sessionStorage.setItem("field_geo_country", geo.country_code||"US");
      sessionStorage.setItem("field_geo_lat",     geo.latitude||"");
      sessionStorage.setItem("field_geo_lon",     geo.longitude||"");
    }
    // City-level disambiguation for split markets (PA → Philly vs Pittsburgh, TX → Dallas/Houston)
    if(geo.city) sessionStorage.setItem("field_geo_city_only", geo.city);
    if(FIELD_DEBUG) console.debug("FIELD geo:",geo.city,geo.region_code,geo.country_code,geo.timezone);
  }catch(e){
    if(FIELD_DEBUG) console.debug("FIELD geo unavailable:",e.message);
  }
})();

