let MY_TEAMS = new Set(JSON.parse(localStorage.getItem('field_my_teams')||'[]'));
function saveMyTeams(){
  try{ localStorage.setItem('field_my_teams', JSON.stringify([...MY_TEAMS])); }catch(e){captureFieldError('userdo:save-my-teams', e, true);}
  // Sync to Service Worker via the same keyed PREF_UPDATE channel (2026-07-06)
  // so push notifications can be scoped to followed teams.
  if(navigator.serviceWorker?.controller){
    navigator.serviceWorker.controller.postMessage({type:'PREF_UPDATE',key:'my_teams',value:[...MY_TEAMS]});
  }
}
