// ── PULSE: Viewing Conditions Score & Badge Engine (Wow#33 / Combo B-1+) ──
// Replaces Delta8. Fixes '3pt' dead branch. Adds SPORT_CRUNCH_RULES.
// isBlowout flag for J5 caller — this function does NOT suppress anything.
// Source: PULSE spec (16pkgCd8nz9fjfK32M6qu4qYGmslyNv30jhVqjgn8lj8)
const SPORT_CRUNCH_RULES = {
  'Basketball':                 ['4th','q4'],
  'Baseball':                   ['9th'],
  'Football':                   ['4th'],
  'Hockey':                     ['3rd','ot'],
  'Australian Football (AFL)':  ['q4','qt4','qtr4'], // Q4 = crunch regardless of margin
};

// AFL drama thresholds differ — 6-point goals make margin scale ~3× wider than NBA
// margin <6  = EXTREME (less than 1 goal difference — literally 1 kick wins it)
// margin 7-18 = HIGH (1–3 goals — anyone's game)
// margin 19-36 = MEDIUM (4–6 goals — large but chaseable in AFL)
// margin >36 = low (7+ goals, typically too far in last Q)
// Q4 last 5 min: 1.4× multiplier regardless of margin
function _aflDramaScore(margin, period, dramaScorePeak){
  let score = dramaScorePeak;
  const p = String(period||'').toLowerCase();
  const isQ4 = p.includes('q4')||p.includes('qt4')||p.includes('qtr4');
  if(isQ4){
    if(margin < 6)   score += 35; // within 1 goal in Q4
    else if(margin <= 18) score += 20; // within 3 goals
    else if(margin <= 36) score += 5;
    else score -= 15; // blowout
  } else {
    if(margin < 6)   score += 15;
    else if(margin <= 18) score += 8;
    else if(margin > 36) score -= 15;
  }
  return Math.max(0, Math.min(100, score));
}

const ViewingConditions = {
  evaluate(gameId, period, margin, sport) {
    // score field retained for back-compat (internal callers may inspect it);
    // ADR-002 (M1): badge comes from named tier, not composite + dial threshold.
    const dramaScorePeak = Number(localStorage.getItem('field_drama_peak_' + gameId)) || 50;
    let score = dramaScorePeak;
    let isCrunchTime = false;
    if (period && sport && SPORT_CRUNCH_RULES[sport]) {
      const p = String(period).toLowerCase();
      isCrunchTime = SPORT_CRUNCH_RULES[sport].some(rule => p.includes(rule));
    }
    if (sport === 'Australian Football (AFL)') {
      score = _aflDramaScore(margin, period, dramaScorePeak);
    } else {
      if (isCrunchTime && margin <= 5) score += 30;
      if (margin > 20)                 score -= 20;
      score = Math.max(0, Math.min(100, score));
    }
    const isBlowout = sport === 'Australian Football (AFL)' ? margin > 36 : margin > 20;
    const tier = fieldGameTier(gameId);
    if (tier === 'CRUNCH' || tier === 'EXTRA_TIME')
      return { score, badge: 'CRUNCH TIME',    color: 'var(--c-nba)', pulse: true,  isBlowout };
    if (tier === 'CLOSE_LATE')
      return { score, badge: 'WORTH WATCHING', color: 'var(--c-nhl)', pulse: false, isBlowout };
    return   { score, badge: null,             color: null,           pulse: false, isBlowout };
  }
};

