// ── Wikimedia Pageviews — Cultural Significance Signal (Patent Defense #5) ────
// Detects when teams are trending on Wikipedia — organic cultural interest,
// not broadcast hype. The relay's /wiki/trending endpoint now aggregates
// this server-side in one bulk call, keyed by team name; the client no
// longer holds its own team-name-to-wiki-title mapping or makes per-team
// wikimedia.org requests.
let _wikiTrendingCache=null;
let _wikiTrendingPromise=null;
// injectWikiChips() awaits fetchWikiSignificance(home) and fetchWikiSignificance(away)
// concurrently via Promise.all -- a plain "if(_wikiTrendingCache) return" guard only
// stops re-fetching AFTER the first call resolves, so the first card's two concurrent
// calls both see a null cache and both fire a real network request. Caching the
// in-flight promise (not just the resolved value) makes the second concurrent caller
// await the same request instead of starting its own.
async function fetchAllWikiTrending(){
  if(_wikiTrendingCache) return _wikiTrendingCache;
  if(_wikiTrendingPromise) return _wikiTrendingPromise;
  _wikiTrendingPromise=(async()=>{
    try{
      const today=new Date().toISOString().slice(0,10);
      const r=await fetch(`https://field-relay-nba.jeffunglesbee.workers.dev/wiki/trending?date=${today}`);
      _wikiTrendingCache=r.ok?await r.json():{};
    }catch(e){_wikiTrendingCache={};}
    return _wikiTrendingCache;
  })();
  return _wikiTrendingPromise;
}
async function fetchWikiSignificance(teamName){
  const all=await fetchAllWikiTrending();
  return all[teamName]||null;
}
// Inject wiki trending chips on cards after schedule renders
async function injectWikiChips(){
  const cards=document.querySelectorAll('.game-card[data-home][data-away]');
  for(const card of cards){
    if(card.querySelector('.wiki-chip')) continue; // already injected
    const home=card.dataset.home||'';
    const away=card.dataset.away||'';
    const[hWiki,aWiki]=await Promise.all([fetchWikiSignificance(home),fetchWikiSignificance(away)]);
    const venueLine=card.querySelector('.venue-line');
    if(!venueLine) continue;
    if(hWiki?.trending&&aWiki?.trending){
      const chip=document.createElement('div');chip.className='wiki-chip';
      chip.textContent=`📈 In the news — both teams trending nationally`;
      chip.style.cssText='font-size:.55rem;color:#34d399;margin-top:.15rem';
      venueLine.insertAdjacentElement('afterend',chip);
    }else if(hWiki?.trending){
      const chip=document.createElement('div');chip.className='wiki-chip';
      chip.textContent=`📈 In the news — ${home} (+${Math.round((hWiki.spikeRatio-1)*100)}% on Wikipedia)`;
      chip.style.cssText='font-size:.55rem;color:#34d399;margin-top:.15rem';
      venueLine.insertAdjacentElement('afterend',chip);
    }else if(aWiki?.trending){
      const chip=document.createElement('div');chip.className='wiki-chip';
      chip.textContent=`📈 In the news — ${away} (+${Math.round((aWiki.spikeRatio-1)*100)}% on Wikipedia)`;
      chip.style.cssText='font-size:.55rem;color:#34d399;margin-top:.15rem';
      venueLine.insertAdjacentElement('afterend',chip);
    }
  }
}

// ── SERVICE_FAMILIES — maps SR keys → service card family ─────────────────────
// Used by buildStreamingDiscovery() to score and sort service cards by
// tonight's actual game coverage. Each family key maps to one STREAMING_APPS card.
const SERVICE_FAMILIES = {
  // ESPN / Disney family
  espn:'espn', espn2:'espn', espnu:'espn', espnapp:'espn', espnplus:'espn', espnunlimited:'espn', abc:'espn',
  // Max / Warner family
  tnt:'max', trutv:'max', max:'max', tbs:'max',
  // Fox family
  fox:'fox', fs1:'fox',
  // Peacock / NBC family
  nbc:'peacock', peacock:'peacock', nbcsn:'peacock', usa:'peacock',
  // Apple family
  apple:'apple',
  // Paramount / CBS family
  paramount:'paramount', cbs:'paramount', paramountuk:'paramount',
  // Prime Video
  prime:'prime',
  // Netflix
  netflix:'netflix',
  // Bundles (YouTube TV, Fubo, Hulu, Sling, DirecTV)
  youtubetv:'bundle', fubo:'bundle', hulu:'bundle', sling:'bundle', directv:'bundle',
  // MLB
  mlbtv:'mlbtv', mlbn:'mlbtv', mlbplus:'mlbtv',
  // NBA / WNBA
  nbatv:'nbatv', wnbalp:'nbatv',
  // Local RSN / team DTC — map to 'rsn' family (shown last)
  rsn:'rsn', masn:'rsn', masnplus:'rsn', yes:'rsn', sny:'rsn', snp:'rsn',
  raystv:'rsn', clegtv:'rsn', dsntv:'rsn', royalstv:'rsn', brewerstv:'rsn',
  marlinstv:'rsn', cardinalstv:'rsn', redstv:'rsn', bravesvision:'rsn',
  marinerstv:'rsn', twinstv:'rsn', nationalstv:'rsn', texrsn:'rsn',
  fdsnwest:'rsn', rockiestv:'rsn', athleticstv:'rsn',
  nbcsca:'rsn', schn:'rsn',
  // Sport-specific / international
  tc:'tc', tcplus:'tc',
  fsp:'fsp',
  bein:'bein',
  dazn:'dazn', golazo:'dazn',
  watchafl:'watchafl', foxfooty:'watchafl',
  kayosports:'watchafl',
  willow:'willow', skycricket:'willow',
};

// ── buildStreamingDiscovery() — derived service card ordering ──────────────────
// Scores each STREAMING_APPS card by tonight's actual game coverage.
// Cards with games tonight float to the top; cards with nothing tonight sink.
// This replaces manual card ordering with data-driven relevance sorting.
// Spec: FIELD SMT & Streaming Discovery Intelligence Spec May 21 2026
function buildStreamingDiscovery() {
  if (!allData) return null; // called before data ready

  // Step 1: collect all SR stream keys from tonight's games
  const tonightKeys = new Set();
  (allData.sports || []).forEach(sec =>
    (sec.games || []).forEach(g =>
      (g.streams || []).forEach(s => { if (s.key) tonightKeys.add(s.key); })
    )
  );

  // Step 2: count games per service family
  const familyGameCount = {};
  const familyLiveCount = {};
  const familyPlayoffCount = {};
  // Gap 9: debrief-available count — final/post games with Debrief ready
  const familyDebriefCount = {};

  (allData.sports || []).forEach(sec => {
    (sec.games || []).forEach(g => {
      const st = g._espnState || g.state || '';
      const isLive = st === 'in';
      const isFinal = st === 'post' || st === 'final';
      const isPlayoff = !!(g.seriesRecord || /playoff|final|series/i.test(g.league || ''));
      // Debrief available = final game + data-debrief-injected card in DOM
      const hasDebrief = isFinal && !!(g._id && document.querySelector(
        '.game-card[data-gameid="' + (g._id || '').replace(/"/g,'') + '"][data-debrief-injected="1"]'
      ));
      (g.streams || []).forEach(s => {
        if (!s.key) return;
        const fam = SERVICE_FAMILIES[s.key];
        if (!fam) return;
        familyGameCount[fam] = (familyGameCount[fam] || 0) + 1;
        if (isLive)    familyLiveCount[fam]    = (familyLiveCount[fam]    || 0) + 1;
        if (isPlayoff) familyPlayoffCount[fam]  = (familyPlayoffCount[fam] || 0) + 1;
        if (hasDebrief) familyDebriefCount[fam] = (familyDebriefCount[fam] || 0) + 1;
      });
    });
  });

  // Gap 9: mode-specific scoring. Each mode surfaces a different signal.
  // PREVIEW: games scheduled tonight (what can I watch?)
  // PRIME:   live games right now (what's on now?)
  // NIGHT:   Debriefs available (what finished with a story?)
  // LATE/DAWN: total tonight coverage as archive-coverage proxy
  const mode = (typeof _circadianMode !== 'undefined') ? _circadianMode : 'PRIME';
  function _scoreForMode(games, live, debriefs, playoffs) {
    if (mode === 'PREVIEW') return (games * 10) + (playoffs * 2);
    if (mode === 'PRIME')   return (live  * 10) + (games   * 3);
    if (mode === 'NIGHT')   return (debriefs * 10) + (games * 2);
    // LATE / DAWN: archive coverage proxy — volume + historical significance
    return (games * 5) + (playoffs * 4);
  }
  function _badgeForMode(games, live, debriefs) {
    if (mode === 'PREVIEW' && games > 0)    return games    + (games    === 1 ? ' game tonight'       : ' games tonight');
    if (mode === 'PRIME'   && live > 0)     return live     + (live     === 1 ? ' live now'           : ' live now');
    if (mode === 'NIGHT'   && debriefs > 0) return debriefs + (debriefs === 1 ? ' Debrief available'  : ' Debriefs available');
    if ((mode === 'LATE' || mode === 'DAWN') && games > 0)
                                            return games    + (games    === 1 ? ' game tracked'       : ' games tracked');
    return '';
  }

  // Step 3: score each STREAMING_APPS card
  const scored = STREAMING_APPS.map(app => {
    const fam = app.key;
    const games    = familyGameCount[fam]    || 0;
    const live     = familyLiveCount[fam]    || 0;
    const playoffs = familyPlayoffCount[fam] || 0;
    const debriefs = familyDebriefCount[fam] || 0;
    const score = _scoreForMode(games, live, debriefs, playoffs);
    const badge = _badgeForMode(games, live, debriefs);
    return { ...app, _tonightScore: score, _tonightGames: games, _tonightLive: live,
             _tonightDebriefs: debriefs, _circadianBadge: badge };
  });

  // Step 4: stable sort — highest score first, preserve original order within same score
  scored.sort((a, b) => b._tonightScore - a._tonightScore);

  return scored;
}

function renderStreaming(){
  const grid = document.getElementById("streaming-grid");
  if(!grid) return;
  // Use buildStreamingDiscovery() to get data-sorted cards; fall back to static order
  const apps = buildStreamingDiscovery() || STREAMING_APPS;
  grid.innerHTML = apps.map(app=>{
    const logoStyle = `background:${app.color}18;border:1px solid ${app.color}40;color:${app.color}`;
    const items = app.items.map(item=>`
      <div class="app-item">
        <div class="app-item-dot" style="background:${app.color}80"></div>
        <div class="app-item-body">
          <div class="app-item-title">${item.title}</div>
          <div class="app-item-meta">${item.meta}</div>
        </div>
        <span class="app-item-badge ${item.cls}">${item.badge}</span>
      </div>`).join("");
    return `<div class="app-card">
      <div class="app-card-head">
        <div class="app-logo" style="${logoStyle}">${app.emoji}</div>
        <div>
          <div class="app-name">${app.name}</div>
          ${app._circadianBadge ? `<span class="app-circadian-badge">${app._circadianBadge}</span>` : ''}
        </div>
        <span class="app-price">${app.price}</span>
      </div>
      <div class="app-items">${items}</div>
      <div class="app-footer">
        <span class="app-note">${app.note}</span>
        <a class="app-link" href="${app.url}" target="_blank" rel="noopener">Open app →</a>
      </div>
    </div>`;
  }).join("");
}

// ── CC-CMD-2026-06-15-client-features Commit 2: Broadcast Archaeology ────────
// Aggregate broadcast / bundle usage from the archived games. The archive
// /archive/query endpoint serves briefs; for game records with streams we
// use the existing fetchArchiveDate() helper (also fire-and-forget) over a
// short rolling window. A pure-derived count per bundle is rendered as a
// compact list, sorted by usage count descending.

// buildBroadcastSummary(games) — derives a sorted [{bundle,count}] list.
// Tolerant of partial inputs: each game may have streams[] as objects with
// .label / .bundle / .id fields, or the WC26 path's nationalBundle string,
// or the older relay-bundle string. Unknown shapes contribute 'Unknown'.
function buildBroadcastSummary(games) {
  if (!Array.isArray(games)) return [];
  const counts = new Map();
  const sportOf = new Map();
  for (const g of games) {
    if (!g) continue;
    const sport = String(_gameSport(g)).toLowerCase();
    const bundles = [];
    if (g.nationalBundle) bundles.push(String(g.nationalBundle));
    if (Array.isArray(g.streams)) {
      for (const s of g.streams) {
        if (!s) continue;
        if (typeof s === 'string') bundles.push(s);
        else if (s.bundle) bundles.push(s.bundle);
        else if (s.label) bundles.push(s.label);
        else if (s.id) bundles.push(s.id);
      }
    } else if (typeof g.streams === 'string') {
      bundles.push(g.streams);
    }
    const seen = new Set();
    for (const b of bundles) {
      const key = String(b).replace(/[_-]+/g,' ').trim() || 'Unknown';
      if (seen.has(key)) continue;
      seen.add(key);
      counts.set(key, (counts.get(key) || 0) + 1);
      if (!sportOf.has(key)) sportOf.set(key, sport);
    }
  }
  const arr = Array.from(counts.entries())
    .map(([bundle, count]) => ({ bundle, count, sport: sportOf.get(bundle) || '' }))
    .sort((a, b) => b.count - a.count || a.bundle.localeCompare(b.bundle));
  return arr;
}

function renderBroadcastArchaeology(games) {
  const target = document.getElementById('broadcast-archaeology');
  if (!target) return;
  const rows = buildBroadcastSummary(games);
  if (!rows.length) { target.setAttribute('hidden',''); return; }
  const head = `<div class="broadcast-archaeology-head">
    <span class="broadcast-archaeology-eyebrow">Broadcast History</span>
    <span class="broadcast-archaeology-sub">recent archived bundles · top ${Math.min(rows.length, 12)}</span>
  </div>`;
  const listHTML = rows.slice(0, 12).map(r => {
    const stripeCls = ['nba','nhl','mlb','wnba','cfl','nfl','wc26','epl'].find(s => r.sport.includes(s)) || '';
    return `<li class="bcast-row">
      <span class="bcast-stripe ${stripeCls ? 'sport-' + stripeCls : ''}"></span>
      <span class="bcast-name">${r.bundle}</span>
      <span class="bcast-count">${r.count} game${r.count === 1 ? '' : 's'}</span>
    </li>`;
  }).join('');
  target.removeAttribute('hidden');
  target.innerHTML = head + `<ul class="broadcast-archaeology-list">${listHTML}</ul>`;
}

// Fire-and-forget archive sweep. Tries 14 days back from today; aggregates
// returned game records into the bundle counts. ARCHIVE_RELAY_READY gates
// the fetch; any failure leaves the target hidden.
function loadBroadcastArchaeology() {
  if (typeof fetchArchiveDate !== 'function') return;
  const cacheKey = 'field_broadcast_archaeology';
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const c = JSON.parse(cached);
      if (c && (Date.now() - (c.ts || 0)) < 1800000 && Array.isArray(c.games)) {
        renderBroadcastArchaeology(c.games);
        return;
      }
    }
  } catch(_e) { captureFieldError('broadcast-archaeology:cache-read', _e, true); }
  const today = new Date();
  const dates = [];
  for (let i = 1; i <= 14; i++) {
    const d = new Date(today.getTime() - i * 86400000);
    dates.push(d.toISOString().slice(0, 10));
  }
  Promise.all(dates.map(iso => fetchArchiveDate(iso).catch(() => null)))
    .then(results => {
      const games = [];
      for (const r of results) {
        if (!r) continue;
        const arr = Array.isArray(r) ? r
                  : Array.isArray(r.games) ? r.games
                  : Array.isArray(r.results) ? r.results
                  : [];
        for (const g of arr) games.push(g);
      }
      if (!games.length) return;
      try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), games })); } catch(_e) { captureFieldError('broadcast-archaeology:cache-write', _e, true); }
      renderBroadcastArchaeology(games);
    })
    .catch((e_) => { captureFieldError('broadcast-archaeology:build-render', e_, true); });
}

// ── Lazy-load below-fold sections ────────────────────────────────────────────
let mediaRendered   = false;

const lazyObs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(!e.isIntersecting) return;
    if(e.target.id==="media-section"&&!mediaRendered){
      renderMedia();mediaRendered=true;
      // CC-CMD-2026-07-13-hrd-live-wiring: fire-and-forget live bracket
      // fetch + poll loop, same pattern as loadBroadcastArchaeology below —
      // never blocks the media grid's own render.
      try { if (typeof _hrdPollLoop === 'function') _hrdPollLoop(); } catch(_) {}
    }
    if(e.target.id==="streaming-section"){
      renderStreaming();
      // CC-CMD-2026-06-15-client-features Commit 2: Broadcast Archaeology.
      // Fire-and-forget archive sweep; never blocks streaming render.
      try { if (typeof loadBroadcastArchaeology === 'function') loadBroadcastArchaeology(); } catch(_) {}
    }
    if(e.target.id==="field-desk-section"){
      // Delay 800ms — let compound prompt + series briefs settle first
      scheduleFieldDesk(800);
      setTimeout(renderJournalism, 800);
    }
  });
},{rootMargin:"800px"});  // Large margin: pre-renders betting before scroll on iPad
["media-section","streaming-section","field-desk-section"].forEach(id=>{
  const el=document.getElementById(id);
  if(el) lazyObs.observe(el);
});


// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: Pull-to-Refresh — touch gesture at top of page triggers reload
// Works in standalone PWA mode where native browser PTR is suppressed.
// ═══════════════════════════════════════════════════════════════════════════
(function initPullToRefresh(){
  const PTR_THRESHOLD = 72; // px to pull before triggering
  let _ptrStart = 0, _ptrDelta = 0, _ptrActive = false, _ptrTriggered = false;
  // Inject indicator element
  const ind = document.createElement('div');
  ind.id = 'ptr-indicator';
  ind.style.cssText = 'position:fixed;top:0;left:50%;transform:translateX(-50%) translateY(-48px);z-index:9999;background:var(--panel,#1a1a2e);border:1px solid rgba(255,255,255,.12);border-radius:50%;width:36px;height:36px;display:flex;align-items:center;justify-content:center;font-size:1.1rem;transition:transform .2s,opacity .2s;opacity:0;pointer-events:none;box-shadow:0 2px 12px rgba(0,0,0,.4)';
  ind.textContent = '↓';
  document.body.appendChild(ind);

  document.addEventListener('touchstart', e => {
    if (window.scrollY > 4) return; // only at very top
    _ptrStart = e.touches[0].clientY;
    _ptrDelta = 0;
    _ptrActive = true;
    _ptrTriggered = false;
  }, {passive:true});

  document.addEventListener('touchmove', e => {
    if (!_ptrActive) return;
    _ptrDelta = Math.max(0, e.touches[0].clientY - _ptrStart);
    if (_ptrDelta > 8) {
      const pull = Math.min(_ptrDelta, PTR_THRESHOLD + 20);
      const progress = Math.min(pull / PTR_THRESHOLD, 1);
      ind.style.opacity = String(progress);
      ind.style.transform = `translateX(-50%) translateY(${Math.min(pull * 0.6, 44)}px)`;
      ind.style.background = progress >= 1 ? 'var(--c-nba,#f97316)' : 'var(--panel,#1a1a2e)';
      ind.textContent = progress >= 1 ? '↺' : '↓';
    }
  }, {passive:true});

  document.addEventListener('touchend', async () => {
    if (!_ptrActive) return;
    _ptrActive = false;
    if (_ptrDelta >= PTR_THRESHOLD && !_ptrTriggered) {
      _ptrTriggered = true;
      ind.style.opacity = '1';
      ind.style.transform = `translateX(-50%) translateY(44px)`;
      ind.textContent = '↺';
      await fetchSchedule();
    }
    // Snap back
    setTimeout(() => {
      ind.style.opacity = '0';
      ind.style.transform = 'translateX(-50%) translateY(-48px)';
      ind.textContent = '↓';
    }, 600);
    _ptrDelta = 0;
  }, {passive:true});
})();


// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: PWA — Service Worker Registration + Install Prompt
// ═══════════════════════════════════════════════════════════════════════════
let _pwaPrompt = null;
(function initPWA(){
  // Only attempt over HTTPS or localhost
  if(typeof window === 'undefined' || typeof location === 'undefined') return;
  const isSecure = location.protocol === 'https:' || location.hostname === 'localhost';

  // SW_VERSION — bump on every deploy to bust returning user cache
  // Assertion 28 in smoke verifies this constant is present
  // Rule 23: suffix increments per deploy within a day (a → b → c); new day resets to 'a'.
  // July 12 ended at 'u'. July 13 starts here.
  const SW_VERSION = '2026-07-18n';
  window.SW_VERSION = SW_VERSION; // expose globally for health panel + debugging

  // Service Worker — registered from /sw.js for full origin scope (Cloudflare Pages HTTPS)
  // Cache strategy: API-only (ESPN scores, weather, odds, SportsDB).
  // index.html is NOT cached — always loads fresh from CDN.
  // SW_VERSION passed as query param so new deploys invalidate the cached SW.
  if(isSecure && 'serviceWorker' in navigator){
    try {
      const swPath = (location.hostname.endsWith('.pages.dev') || location.hostname.endsWith('.workers.dev') || !location.hostname.includes('localhost'))
        ? `/sw.js?v=${SW_VERSION}`
        : null;
      if(swPath){
        navigator.serviceWorker.register(swPath, {scope:'/'})
          .then(reg=>{
            // Drama Dial sync to SW removed 2026-07-06 -- the SW's push
            // trigger no longer reads this value (see isCrunchLikePush()
            // in sw.js). The dial is now a display-filter-only setting.
            // Sync My Teams to the SW on every page load, so it has a fresh
            // copy even if the user hasn't changed teams this session.
            if(navigator.serviceWorker.controller){
              navigator.serviceWorker.controller.postMessage({type:'PREF_UPDATE',key:'my_teams',value:[...MY_TEAMS]});
            }
            // Auto-reload when new SW activates (skipWaiting pattern).
            // Ensures users always get the current build within one load cycle —
            // on both iOS and Android. No manual close/reopen required.
            reg.addEventListener('updatefound', () => {
              const newSW = reg.installing;
              if(!newSW) return;
              newSW.addEventListener('statechange', () => {
                if(newSW.state === 'activated' && navigator.serviceWorker.controller) {
                  // New SW is active — reload to serve from fresh cache
                  window.location.reload();
                }
              });
            });
            // Force an active update check whenever the app becomes
            // visible again -- closes the gap where updatefound only
            // fires on the browser's own background check cycle, which
            // is meaningfully less frequent for installed PWAs on iOS
            // Safari than Android Chrome (documented in this project's
            // own May/June sessions: "yes on Android, no on iPad").
            // Standard PWA mitigation (MDN/web.dev): call .update() on
            // visibilitychange rather than relying solely on the
            // platform's own cadence. The existing updatefound listener
            // (above) still does the actual reload -- this only makes
            // the check itself fire promptly.
            document.addEventListener('visibilitychange', () => {
              if (document.visibilityState === 'visible') {
                reg.update().catch(() => {});
              }
            });
          })
          .catch(()=>{ /* SW registration failed — API caching unavailable */ });
      }
    } catch(e){}
  }

  // Install prompt — fires only on HTTPS when app is installable
  window.addEventListener('beforeinstallprompt', e => {
    e.preventDefault();
    _pwaPrompt = e;
    const _dismissed = localStorage.getItem('field_pwa_dismissed');
    const _dismissedMs = parseInt(_dismissed, 10);
    const _14days = 14 * 24 * 60 * 60 * 1000;
    if(_dismissed && (!isNaN(_dismissedMs) ? (Date.now() - _dismissedMs < _14days) : true)) return;
    const banner = document.getElementById('pwa-banner');
    if(banner) banner.style.display = 'flex';
  });

  const installBtn = document.getElementById('pwa-install-btn');
  const dismissBtn = document.getElementById('pwa-dismiss');
  if(installBtn) installBtn.addEventListener('click', async () => {
    if(!_pwaPrompt) return;
    _pwaPrompt.prompt();
    const {outcome} = await _pwaPrompt.userChoice;
    _pwaPrompt = null;
    const _pb = getEl('pwa-banner'); if(_pb) _pb.style.display = 'none';
  });
  if(dismissBtn) dismissBtn.addEventListener('click', () => {
    const _pb = getEl('pwa-banner'); if(_pb) _pb.style.display = 'none';
    localStorage.setItem('field_pwa_dismissed', String(Date.now()));
  });
})();

// appinstalled: fires when Chrome confirms PWA was installed.
// Distinguish from dismiss — installed users never need prompting again.
window.addEventListener('appinstalled', () => {
  localStorage.setItem('field_pwa_installed', String(Date.now()));
  // Remove dismissal flag so it doesn't interfere with future logic
  localStorage.removeItem('field_pwa_dismissed');
  // Hide banner — they installed
  const _pb = document.getElementById('pwa-banner');
  if(_pb) _pb.style.display = 'none';
  if(typeof window._fieldErrors !== 'undefined') {
    // Log install event to health panel
    console.log('[PWA] appinstalled fired — app installed successfully');
  }
});

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: OFFLINE DETECTION
// ═══════════════════════════════════════════════════════════════════════════
(function initOffline(){
  if(typeof window === 'undefined' || typeof navigator === 'undefined') return;
  const banner = document.getElementById('offline-banner');
  if(!banner) return;
  const show = () => { banner.style.display = navigator.onLine ? 'none' : 'block'; };
  show();
  window.addEventListener('online', show);
  window.addEventListener('offline', show);
})();

// ═══════════════════════════════════════════════════════════════════════════
// ── QW-1: Situation Drama Bonus (#11a) ───────────────────────────────────────
// Named game-state facts from ESPN's situation object → internal drama bonus.
// PATENT / post-RUWT: goaliePulled, power play, base occupancy, red zone,
// down/distance are named categorical events — NOT excitement thresholds.
// Output feeds dramaScoreLive() only; never displayed as a number (tier labels).
// Self-contained: recomputes diff/period/isFinalPeriod identically to caller.
// (Extracted verbatim from dramaScoreLive inline #11a — May 28 2026; behaviour
//  unchanged. Named fn enables VIBE-A / isCrunchTime reuse + smoke assertability.)
function applyQW1SituationBonus(eData, sport){
  if(!eData) return 0;
  const sp = (sport||'').toLowerCase();
  const sit = eData.situation || {};
  const diff = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const period = parseInt(eData.period)||1;
  let sitBonus = 0;

  // isFinalPeriod: amplifies bonuses in final quarter/period/inning
  const isFinalPeriod = (
    (sp.includes('nba')||sp.includes('basketball')) && period >= 4 ||
    (sp.includes('nhl')||sp.includes('hockey'))     && period >= 3 ||
    (sp.includes('mlb')||sp.includes('baseball'))   && period >= 9 ||
    (sp.includes('nfl')||sp.includes('football'))   && period >= 4
  );

  // ── HOCKEY ── (goalie pulled is valid any period — empty net)
  if(sp.includes('nhl')||sp.includes('hockey')){
    const homePull = sit.homeGoaliePulled||false;
    const awayPull = sit.awayGoaliePulled||false;
    if(homePull || awayPull) sitBonus += 22;              // goalie pulled — empty net pressure
    else if((sit.homePowerPlay||sit.awayPowerPlay) && diff===0) sitBonus += 18; // PP + tied
    else if((sit.homePowerPlay||sit.awayPowerPlay) && diff<=1)  sitBonus += 15; // PP + close
    if(sit.delayedPenalty && diff<=1) sitBonus += 8;     // delayed penalty + close
  }

  // ── BASEBALL ── (amplified in final innings)
  if(sp.includes('mlb')||sp.includes('baseball')){
    const runners = [eData.onFirst,eData.onSecond,eData.onThird].filter(Boolean).length;
    const risp    = eData.onSecond||eData.onThird;
    if(runners===3 && eData.outs===2)  sitBonus += isFinalPeriod ? 20 : 12; // bases loaded 2 out
    else if(runners===3)               sitBonus += isFinalPeriod ? 15 :  8; // bases loaded
    else if(risp && eData.outs===2)    sitBonus += isFinalPeriod ? 10 :  6; // RISP 2 out
    if(eData.balls===3 && eData.strikes===2 && risp) sitBonus += 8; // full count + RISP
    if(eData.outs===2 && period>=7)    sitBonus += 5;    // 2-out + late innings
  }

  // ── BASKETBALL ── (isFinalPeriod only — bonus fouls + shot clock)
  if(sp.includes('nba')||sp.includes('basketball')){
    if(isFinalPeriod){
      if((sit.homeFoulsBonus||sit.awayFoulsBonus) && diff<=5) sitBonus += 10;
      const sc = parseFloat(sit.shotClock||'99');
      if(sc<=8 && diff<=6) sitBonus += 8;                // shot clock pressure, close game
    }
  }

  // ── NFL ── (amplified in final period + 2-minute drill)
  if(sp.includes('nfl')||sp.includes('football')){
    const dnDist = (sit.shortDownDistanceText||sit.downDistanceText||'').toLowerCase();
    const in2min = dnDist.includes('2-minute')||dnDist.includes('2 minute');
    if(dnDist.includes('4th') && in2min)                  sitBonus += isFinalPeriod ? 15 : 10;
    else if(dnDist.includes('4th'))                       sitBonus += isFinalPeriod ?  8 :  5;
    if(sit.isRedZone && in2min && diff<=7)                sitBonus += 10;
    else if(sit.isRedZone)                                sitBonus +=  5;
  }

  // ── SOCCER / WC ── (stoppage time + advancement stake)
  if(sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
     sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
     /world.cup|fifa/i.test(sp)){
    if((eData.clock||'').includes('+')) sitBonus += 8;   // "90+2" stoppage time
    // WC advancement stake — qualification on the line amplifies drama.
    // _wcAdvProb merged onto eData by fetchWCLiveGames() after relay fetch.
    // RUWT-safe: factual P(advance) comparison, never a composite interest level.
    const _adv = eData._wcAdvProb;
    if(_adv){
      const _minAdv = Math.min(_adv.homeAdvance??1, _adv.awayAdvance??1);
      if(_minAdv < 0.20) sitBonus += 15;        // at least one team near elimination
      else if(_minAdv < 0.40) sitBonus += 8;   // both teams with tight path to advance
      // Swing from kickoff: ≥20pp shift means result is reshaping the group
      const _open = eData._wcOpeningAdvProb;
      if(_open){
        const _minOpen = Math.min(_open.homeAdvance??1, _open.awayAdvance??1);
        if((_minOpen - _minAdv) >= 0.20) sitBonus += 8;
      }
    }
  }

  return sitBonus;
}

// ── FIFA team rank cache (soccer upset-factor bonus, CC-CMD-2026-07-04-
// soccer-drama-scoring-fix TASK 4) ───────────────────────────────────────
// Real relay endpoint (Parse.bot-backed, confirmed live 2026-07-04):
// GET {V2_RELAY_BASE}/fifa-rankings/{team} -> {ok:true,rank,points,team}
// or {ok:false,error:"team not found in rankings"} for unmapped teams
// (confirmed real and expected via live probe against a nonexistent team
// name — not a crash, not a bug, just no upset bonus for that team).
// Ranks don't change per-game, so cached with a long (7-day) TTL, matching
// the relay's own KV cache lifetime and fetchBDLRecentForm's established
// in-memory + localStorage cache pattern (index.html ~17804), reused here
// rather than inventing a new caching mechanism.
const _fifaRankCache = {};
const FIFA_RANK_TTL = 7 * 24 * 60 * 60 * 1000; // 7 days
function _fifaRankCacheKey(teamName) {
  return `fifa_rank_${teamName.toLowerCase().replace(/\s+/g,'_')}`;
}
// Synchronous cache-only read (in-memory, then localStorage). Returns
// undefined if never looked up yet (caller should decide what to do),
// or the cached rank (a number, or null if the relay said "not found" /
// the fetch failed) if a fresh cache entry exists.
function _readCachedRank(ck) {
  if (_fifaRankCache[ck] !== undefined) return _fifaRankCache[ck];
  try {
    const cached = localStorage.getItem(ck);
    if (cached) {
      const p = JSON.parse(cached);
      if (Date.now() - p.ts < FIFA_RANK_TTL) { _fifaRankCache[ck] = p.rank; return p.rank; }
    }
  } catch(_e) { captureFieldError('scores:fifa-rank-cache-read', _e, true); }
  return undefined;
}
// Async fetch + cache. Use from paths that can await (the historical/
// backfill path — computeDramaRetroactive's caller already awaits
// fetchSoccerHistoricalStates, so awaiting this too adds no new blocking
// behavior class, just one more per-game relay call).
//
// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #6): the real bug
// here was never "the exception is swallowed" alone -- it was that BOTH a
// thrown exception AND a bare HTTP failure (!r.ok) got persisted to
// localStorage under the SAME FIFA_RANK_TTL (7 days) as a genuine "team
// not found in rankings" response. A single dropped request or transient
// 500 used to silence the upset-bonus signal for that team for a full
// week, indistinguishable from the team genuinely not being ranked. Fix:
// don't cache failures at all -- only a DEFINITIVE outcome (a real rank,
// or a confirmed "not found" from a valid API response) is written to the
// 7-day cache. A failure returns null for THIS call only; the cache stays
// unwritten, so the NEXT call (next render/poll cycle) retries from
// scratch -- that retry IS the fix, no new retry machinery needed.
async function fetchTeamRank(teamName) {
  if (!teamName) return null;
  const ck = _fifaRankCacheKey(teamName);
  const cached = _readCachedRank(ck);
  if (cached !== undefined) return cached;
  const result = await fieldOperation({subsystem:'scores', operation:'fetch-team-rank', retryable:true, context:{teamName}}, async () => {
    const r = await fetch(`${V2_RELAY_BASE}/fifa-rankings/${encodeURIComponent(teamName)}`,
      { signal: AbortSignal.timeout(5000) });
    if (!r.ok) {
      // Treated as a real failure, not a silent "not found" -- an HTTP
      // error status is not a valid business answer from the API, and
      // must not be cached as one.
      const httpErr = new Error(`fifa-rankings HTTP ${r.status}`);
      httpErr.status = r.status;
      throw httpErr;
    }
    const d = await r.json();
    // d.ok:false ("team not found in rankings") is expected for
    // unmapped teams (confirmed real error shape, not guessed) — rank
    // simply stays null, meaning no upset bonus is possible for them.
    // This IS a definitive outcome (a valid response, just "no"), unlike
    // the thrown-error case above -- it's correct to cache this for the
    // full TTL.
    return d.ok ? d.rank : null;
  });
  if (!result.ok) return null; // failure -- do not cache, see header comment
  const rank = result.value;
  _fifaRankCache[ck] = rank;
  try { localStorage.setItem(ck, JSON.stringify({ rank, ts: Date.now() })); } catch(_e) { captureFieldError('scores:fifa-rank-persist', _e, true); }
  return rank;
}
// Sync cache-only read for hot render paths that cannot await a fetch
// (injectDramaBadges, getOneToWatchGame run on every render/poll cycle).
// Returns the cached rank if known, else kicks off a background fetch
// (fire-and-forget) so it's available on a LATER render pass, and
// returns null for THIS pass rather than blocking — matches the
// CC-CMD's instruction to fall back to no upset bonus, not crash or
// retry indefinitely, for a rank that isn't resolved yet.
function getCachedTeamRank(teamName) {
  if (!teamName) return null;
  const ck = _fifaRankCacheKey(teamName);
  const cached = _readCachedRank(ck);
  if (cached !== undefined) return cached;
  // 2026-07-13: .catch(() => {}) removed -- fetchTeamRank() is now
  // migrated to fieldOperation(), whose own promise never rejects.
  fetchTeamRank(teamName);
  return null;
}

// FEATURE: DRAMA SCORE LIVE — QW-1 (Drama Cross-Reference doc)
// espnScores.situation modifiers on top of score-diff + time-urgency base
// Returns 0–100 integer. 0 = pregame/final, >80 = "fire" urgency.
// ═══════════════════════════════════════════════════════════════════════════
function dramaScoreLive(eData, sport){
  if(!eData) return 0;
  const state = eData.state || 'pre';
  if(state === 'post') return 0;
  if(state === 'pre')  return 0;  // use preGameScore() for pregame

  const diff = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const period = parseInt(eData.period)||1;
  const sp = (sport||'').toLowerCase();

  // ── Base: score closeness (sport-calibrated) ─────────────────────────
  let base;
  if(sp.includes('mlb') || sp.includes('baseball')){
    base = diff===0?1.0 : diff===1?0.85 : diff===2?0.55 : diff<=4?0.28 : 0.08;
  } else if(sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
            sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
            sp.includes('wc26')||sp.includes('world cup')){
    // wc26/world cup added (CC-CMD-2026-07-04-soccer-drama-scoring-fix):
    // confirmed live, the real WC26 section's sport label is literally
    // "FIFA World Cup 2026" (index.html section-injection + hardcoded
    // fallback schedule, both checked) -- this never matched the prior
    // condition, so a live WC26 game fell to the NBA/NHL/NFL else-branch
    // below and used the WRONG base-score calibration. Same substring
    // check classifySport() already uses for its own isWC26 (verified
    // via grep, reused rather than invented).
    base = diff===0?1.0 : diff===1?0.72 : diff===2?0.32 : 0.06;
  } else {
    // NBA / NHL / NFL — higher scoring, tighter windows
    base = diff===0?1.0 : diff<=3?0.82 : diff<=7?0.52 : diff<=14?0.22 : 0.05;
  }

  // ── Time urgency ─────────────────────────────────────────────────────
  let timeBonus = 0;
  const clock = eData.clock||'';
  const mins = parseFloat((clock.match(/^(\d+)/)||[0,0])[1])||12;

  if(sp.includes('nba')||sp.includes('basketball')){
    if(period>4) timeBonus=22;       // overtime
    else if(period>=3 && mins<2) timeBonus=18;
    else if(period===4) timeBonus=10;
    else if(period===3) timeBonus=5;
  } else if(sp.includes('nhl')||sp.includes('hockey')){
    if(period>3) timeBonus=25;       // overtime/shootout
    else if(period===3 && mins<5) timeBonus=18;
    else if(period===3) timeBonus=8;
  } else if(sp.includes('mlb')||sp.includes('baseball')){
    if(period>=10) timeBonus=22;     // extra innings
    else if(period>=9) timeBonus=16;
    else if(period>=7) timeBonus=7;
  } else if(sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
            sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
            sp.includes('wc26')||sp.includes('world cup')){
    // wc26/world cup added — see the matching base-score branch above for
    // why (the real WC26 sport label never matched this condition before).
    const minNum = parseInt(clock)||0;
    // Extra time gets its own tier, matching every other sport's overtime
    // bonus in this function (NHL +25, NBA/MLB +22, NFL +20) — soccer
    // previously had none, conflating stoppage time and actual extra time
    // into the same generic "≥90 minute" bucket. Threshold verified
    // 2026-07-04 against a real WC26 knockout-stage extra-time game
    // (Australia 1, Egypt 1, decided by penalties, ESPN event 760499):
    // real keyEvents confirm period 1-2 = normal halves, period 3 =
    // "Extra Time First Half", period 4 = "2nd Half Extra Time", period 5
    // = "Shootout" — period>=3 correctly captures all of it as one bucket.
    if(period>=3) timeBonus=24;         // extra time (incl. shootout)
    else if(minNum>=90) timeBonus=18;   // stoppage time (unchanged)
    else if(minNum>=80) timeBonus=10;
    else if(minNum>=70) timeBonus=5;
  } else if(sp.includes('nfl')||sp.includes('football')){
    if(period>4) timeBonus=20;
    else if(period===4 && mins<2) timeBonus=18;
    else if(period===4) timeBonus=8;
    else if(period===2 && mins<2) timeBonus=5;
  } else if(sp.includes('australian')||sp.includes('afl')){
    // AFL: 6-pt goals make margin scale ~3x wider than NBA/NHL
    // Calibrated: <6 = within 1 goal, ≤18 = within 3 goals, ≤36 = within 6 goals
    base = diff===0?1.0 : diff<6?0.82 : diff<=18?0.60 : diff<=36?0.28 : 0.05;
    // Q4 closing minutes — critical even at wider margins
    const q=period; // period from espnScores is the quarter number (1-4)
    if(q>=4 && mins<5) timeBonus=22;
    else if(q>=4)      timeBonus=14;
    else if(q===3)     timeBonus=5;
  } else if(sp.includes('cfl')||sp.includes('canadian football')){
    // CFL: similar scoring to NFL; 3-down game, wider field
    // Margins calibrated same as NFL (one-score = 8 pts or fewer)
    base = diff===0?1.0 : diff<=3?0.88 : diff<=8?0.62 : diff<=16?0.28 : 0.06;
    if(period>4) timeBonus=22;       // overtime
    else if(period===4 && mins<2) timeBonus=20;
    else if(period===4) timeBonus=10;
    else if(period===2 && mins<2) timeBonus=6; // two-minute warning
  }
  // WNBA: same calibration as NBA (48-min game, similar scoring)
  if(sp.includes('wnba')) {
    base = diff===0?1.0 : diff<=3?0.82 : diff<=7?0.52 : diff<=14?0.22 : 0.05;
    if(period>4) timeBonus=22;
    else if(period>=3 && mins<2) timeBonus=18;
    else if(period===4) timeBonus=10;
    else if(period===3) timeBonus=5;
  }
  // Tennis: drama is set-based; period = current set number
  if(sp.includes('tennis')||sp.includes('atp')||sp.includes('wta')) {
    base = diff===0?1.0 : diff===1?0.70 : 0.20;
    if(period>=3) timeBonus=18; // deciding set
    else if(period>=2) timeBonus=8;
  }

  // ── #11a Situation Drama Bonus (QW-1) ─────────────────────────────────
  // Named game-state facts (goaliePulled / runners / isRedZone / downDistance)
  // → internal bonus. Extracted to applyQW1SituationBonus(); behaviour unchanged.
  // Post-RUWT compliant: never excitement thresholds; feeds score, not display.
  let sitBonus = applyQW1SituationBonus(eData, sport);

  // ── Fix 6: Weather drama bonus ─────────────────────────────────────────
  // wxAlert fires for: rain > 5mm/hr, temp > 100°F, wind > 30mph
  // Bad weather genuinely affects outdoor game outcomes — legitimate drama signal
  // Outdoor sports only: MLB, NFL, Soccer, AFL. Indoor (NBA/NHL) ignored.
  const isOutdoor = sp.includes('baseball')||sp.includes('mlb')||sp.includes('nfl')||
                    sp.includes('football')||sp.includes('soccer')||sp.includes('league')||
                    sp.includes('mls')||sp.includes('liga')||sp.includes('premier')||
                    sp.includes('afl')||sp.includes('australian');
  if(isOutdoor && typeof wxCache !== 'undefined'){
    try{
      const wxEntry = Object.values(wxCache||{}).find(wx=>wx?.alert||(wx?.aqi||0)>100);
      if(wxEntry){
        // weatherDramaModifier: signed delta — replaces flat +10 (weather-intelligence build)
        sitBonus += weatherDramaModifier(wxEntry);
      } // weather drama modifier applied
    }catch(e){ captureFieldError('drama:live-weather-lookup', e, true); }
  }

  // ── Upset-factor bonus (soccer only, CC-CMD-2026-07-04-soccer-drama-
  // scoring-fix TASK 4) ─────────────────────────────────────────────────
  // Real FIFA rank data via the relay (Parse.bot-backed, 7-day cached,
  // confirmed live 2026-07-04: Argentina rank 1, Cape Verde/"Cabo Verde"
  // rank 67, gap 66). Deliberately CONDITIONAL, not a flat bonus for any
  // big ranking-gap game: only applies when the underdog is actually
  // competing RIGHT NOW (tied or within 1 goal) -- a 5-0 blowout by the
  // favorite gets nothing extra just because the ranking gap is large.
  // This matches how every other bonus in this function only rewards
  // currently-true conditions, not pre-game expectations (RUWT/ADR-002:
  // internal signal, not a pre-game-narrative score).
  let upsetBonus = 0;
  if (sp.includes('soccer') || sp.includes('league') || sp.includes('mls') ||
      sp.includes('liga') || sp.includes('ligue') || sp.includes('premier') ||
      sp.includes('wc26') || sp.includes('world cup')) {
      const rankGap = (typeof eData.homeRank === 'number' && typeof eData.awayRank === 'number')
          ? Math.abs(eData.homeRank - eData.awayRank) : 0;
      // Threshold: 30+ confirmed reasonable against the real Argentina
      // (1) vs Cape Verde (67) case (gap 66) -- fires correctly for the
      // motivating example. Not verified against the full real rank
      // distribution/every possible matchup; sanity-check against a few
      // more real WC26 pairings once live and adjust if it fires too
      // often/rarely.
      if (rankGap >= 30 && diff <= 1) {
          upsetBonus = Math.min(15, Math.floor(rankGap / 10)); // capped, scales with gap size
      }
  }

  const raw = base*52 + timeBonus + sitBonus + upsetBonus;
  // ── WP Delta bonus (ESPN Gambit Win Probability) ─────────────────────
  // wpDelta of 15+ pts across consecutive polls = significant swing
  // Contribution capped at 25pts to prevent WP from dominating score
  let wpBonus = 0;
  const wpNow  = eData?.wp      ?? null;
  const wpPrev = eData?.wp_prev ?? null;
  if (wpNow !== null && wpPrev !== null) {
    const wpDelta = Math.abs(wpNow - wpPrev) * 100; // API is 0-1 scale (e.g. 0.872 = 87.2%); convert to pct points
    wpBonus = Math.min(wpDelta * 1.5, 25);
  }
  return Math.min(100, Math.round(raw + wpBonus));
}

// #18c: Ghost Note / Statistical Extremes
// Reads homeLinescores/awayLinescores from espnScores (populated by #18b).
// Returns {dramaBonus:0-20, note:string|null}
// dramaBonus consumed by injectDramaBadges() in the smoothed path.
// note consumed by getCDWNote() for J7 CDW Notes context.
function getStatisticalExtremes(eData, sport){
  const result = {dramaBonus: 0, note: null};
  if(!eData || eData.state !== 'in') return result;
  const sp = (sport||'').toLowerCase();
  const homeLS = eData.homeLinescores || [];
  const awayLS = eData.awayLinescores || [];
  const diff   = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const period = parseInt(eData.period)||1;

  // ── NBA: 4th-quarter surge ───────────────────────────────────────────
  // Team outscoring opponent +8 in Q4, game still close → comeback signal
  if((sp.includes('nba')||sp.includes('basketball')) && period >= 4 && homeLS.length>=4){
    const hQ4 = homeLS[3]||0, aQ4 = awayLS[3]||0;
    if((hQ4 - aQ4 >= 8) && diff <= 5){
      result.dramaBonus += 12;
      result.note = `${teamNick(eData.homeName)||'Home'} outscoring +${hQ4-aQ4} in Q4 · comeback building`;
    } else if((aQ4 - hQ4 >= 8) && diff <= 5){
      result.dramaBonus += 12;
      result.note = `${teamNick(eData.awayName)||'Away'} outscoring +${aQ4-hQ4} in Q4 · comeback building`;
    }
  }

  // ── NBA: Period shutout ───────────────────────────────────────────────
  // Team scored 0 in consecutive periods, game still close → CDW note
  if((sp.includes('nba')||sp.includes('basketball')) && homeLS.length>=3 && diff<=4){
    const hLast2 = (homeLS.slice(-2)||[]).reduce((a,b)=>a+b,0);
    const aLast2 = (awayLS.slice(-2)||[]).reduce((a,b)=>a+b,0);
    if(hLast2===0 && period>=3){
      result.note = result.note || `${teamNick(eData.homeName)||'Home'} scored 0 in last 2 periods`;
    } else if(aLast2===0 && period>=3){
      result.note = result.note || `${teamNick(eData.awayName)||'Away'} scored 0 in last 2 periods`;
    }
  }

  // ── MLB: No-hitter / perfect game through 6+ innings ─────────────────
  // outs null check: eData.innings populated by fetchMLBLiveGame
  if((sp.includes('mlb')||sp.includes('baseball')) && period>=6){
    const inns = eData.innings||[];
    if(inns.length >= 5){
      const homeHits = inns.reduce((s,i)=>s+(i.away?.hits||0),0); // away hits against home pitcher
      const awayHits = inns.reduce((s,i)=>s+(i.home?.hits||0),0); // home hits against away pitcher
      if(homeHits===0 && period>=6){
        result.dramaBonus += 20;
        result.note = `No-hitter through ${period} innings — ${teamNick(eData.awayName)||'Away'} pitcher`;
      } else if(awayHits===0 && period>=6){
        result.dramaBonus += 20;
        result.note = `No-hitter through ${period} innings — ${teamNick(eData.homeName)||'Home'} pitcher`;
      }
    }
  }

  // ── MLB: Late comeback ────────────────────────────────────────────────
  // Down 3+, within 1, inning 7+
  if((sp.includes('mlb')||sp.includes('baseball')) && period>=7 && diff<=1 && diff>=0){
    const inns = eData.innings||[];
    if(inns.length>=4){
      const mid = Math.floor(inns.length/2);
      const earlyHomeDiff = (inns.slice(0,mid).reduce((s,i)=>s+(i.home?.runs||0),0)) -
                            (inns.slice(0,mid).reduce((s,i)=>s+(i.away?.runs||0),0));
      if(Math.abs(earlyHomeDiff)>=3 && diff<=1){
        result.dramaBonus += 15;
        result.note = result.note || `Comeback · trailed by ${Math.abs(earlyHomeDiff)}+ runs, within ${diff} in the ${period>=9?'9th':(period+'th')}`;
      }
    }
  }

  // ── Soccer: HT reversal ──────────────────────────────────────────────
  // Trailed at halftime, now tied or leading
  if(sp.includes('soccer')||sp.includes('league')||sp.includes('premier')){
    const htHome = eData.htHome ?? null;
    const htAway = eData.htAway ?? null;
    if(htHome!==null && htAway!==null){
      const htDiff = htHome - htAway;
      const nowDiff = (eData.homeScore||0) - (eData.awayScore||0);
      // Team that trailed at HT is now level or winning
      if(htDiff < 0 && nowDiff >= 0){
        result.dramaBonus += 10;
        result.note = `${teamNick(eData.homeName)||'Home'} trailed at half · reversed in 2nd half`;
      } else if(htDiff > 0 && nowDiff <= 0){
        result.dramaBonus += 10;
        result.note = `${teamNick(eData.awayName)||'Away'} trailed at half · reversed in 2nd half`;
      }
    }
  }

  result.dramaBonus = Math.min(20, result.dramaBonus); // cap at 20
  return result;
}

// iPad-14: drop the " LIVE" suffix. The .live-badge (red dot + LIVE)
// already conveys the LIVE state; this badge is meant to convey the
// drama TIER. "● LIVE" / "⚡ LIVE" / "🔥 LIVE" turned every drama-badge
// into a second LIVE indicator stacked next to .live-badge.
function dramaLabel(score){
  if(score>=80) return '🔥';
  if(score>=60) return '⚡';
  if(score>=40) return '●';
  return '';
}

// ── Inject drama badges into rendered live cards ─────────────────────────
// Called from renderESPNScores() after updating live scores.

// J2: SERIES PREVIEW CARDS
// stripJsonFences: removes markdown code fences and extracts first JSON object
// Defined here; called by fetchCompoundEditorial and other JSON-parsing paths.
function stripJsonFences(text) {
  if (!text) return '';
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim();
  // Extract first {...} object if there's leading/trailing prose
  const m = cleaned.match(/\{[\s\S]*\}/);
  return m ? m[0] : cleaned;
}

function stripMarkdown(text) {
  if (!text) return text;
  return text
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .replace(/`(.+?)`/g, '$1')
    .replace(/^[-*+]\s+/gm, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function trimToCompleteSentence(text) {
  if(!text) return text;
  const trimmed = text.trim();
  // Already ends cleanly
  if(/[.!?]["']?$/.test(trimmed)) return trimmed;
  // Find the last complete sentence boundary
  const lastEnd = Math.max(
    trimmed.lastIndexOf('. ') + 1,
    trimmed.lastIndexOf('! ') + 1,
    trimmed.lastIndexOf('? ') + 1,
    trimmed.lastIndexOf('."') + 2,
    trimmed.lastIndexOf('!"') + 2,
    trimmed.lastIndexOf('?"') + 2,
  );
  // Trim if result is at least 30 chars (one meaningful sentence).
  if(lastEnd >= 30 && lastEnd > trimmed.length * 0.3) {
    return trimmed.slice(0, lastEnd).trim();
  }
  // No sentence boundary found — return full text rather than ''.
  // A slightly incomplete sentence is almost always better than the generic
  // static fallback (e.g. "Premier League fixture — one of 38 games...").
  return trimmed;
}



// ── WC PERMUTATIONS ENGINE inlined from field_utils.js (2026-06-04) ──────
// Required by smoke A191. Engine v1.0+v1.1+v1.2+v1.4+v1.5.
// Updated automatically when field_utils.js is regenerated.

// ─────────────────────────────────────────────────────────────────────────────
// ── WC GROUP-STAGE PERMUTATIONS ENGINE ─────────────────────────────────────────
// Pure function. Given a group's current standings and remaining fixtures,
// enumerate every possible final outcome and summarize per-team qualification
// scenarios. Used by the WC Groups view to answer "what does Team X need?"
//
// MARGIN MODEL (documented limit): outcomes are enumerated as W/D/L only.
// Each scenario assumes minimum-margin goals — a win is 1-0, a draw is 0-0.
// Goal differential and goals-for therefore shift by ±1 per win and 0 per draw.
// This is the most conservative model — it answers "can this team finish 1st
// REGARDLESS of how many goals" rather than projecting actual scorelines.
// A future v1.1 can extend to margin tiers (close / comfortable / blowout).
//
// FIFA TIEBREAKERS (2026 group stage, applied in order):
//   1. Points
//   2. Goal difference
//   3. Goals scored
//   4. Head-to-head points (between the tied teams only)
//   5. Head-to-head goal difference
//   6. Head-to-head goals scored
// Fair play and drawing of lots are not modelled (rare, and FP requires
// season-long card tracking out of scope here).
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Sort a slice of teams by FIFA group-stage tiebreakers (1–7).
 * Mutates and returns the input array.
 * @param {Array<Object>} teams — each has {name, P, W, D, L, GF, GA, Pts}
 * @param {Array<Object>} playedMatches — [{home, away, homeScore, awayScore}, ...]
 *   Used for H2H tiebreakers among teams tied on points + GD + GF.
 * @param {Object} [fairPlayPoints] — optional {[teamName]: number}. FIFA FP schedule:
 *   yellow = −1, two-yellow red = −3, direct red = −3 (cumulative in tournament).
 *   Higher (less negative) is better. Omit to skip tiebreaker #7.
 * @returns {Array<Object>} the same array, sorted in finishing order (1st first).
 */
function wcSortByTiebreakers(teams, playedMatches, fairPlayPoints) {
  // Stage A — sort by base tiebreakers (Pts → GD → GF)
  const gd = t => t.GF - t.GA;
  teams.sort((a, b) =>
    (b.Pts - a.Pts) || (gd(b) - gd(a)) || (b.GF - a.GF)
  );
  // Stage B — resolve ties using head-to-head among the tied subset
  let i = 0;
  while (i < teams.length) {
    let j = i + 1;
    while (j < teams.length
        && teams[j].Pts === teams[i].Pts
        && gd(teams[j]) === gd(teams[i])
        && teams[j].GF === teams[i].GF) {
      j++;
    }
    if (j - i > 1) {
      // Tied subset is teams[i..j-1]. Compute mini-table from H2H matches.
      const tied = teams.slice(i, j);
      const tiedNames = new Set(tied.map(t => t.name));
      const h2h = {};
      tied.forEach(t => { h2h[t.name] = {Pts:0, GF:0, GA:0}; });
      for (const m of playedMatches) {
        if (!tiedNames.has(m.home) || !tiedNames.has(m.away)) continue;
        h2h[m.home].GF += m.homeScore;
        h2h[m.home].GA += m.awayScore;
        h2h[m.away].GF += m.awayScore;
        h2h[m.away].GA += m.homeScore;
        if (m.homeScore > m.awayScore)      h2h[m.home].Pts += 3;
        else if (m.homeScore < m.awayScore) h2h[m.away].Pts += 3;
        else { h2h[m.home].Pts += 1; h2h[m.away].Pts += 1; }
      }
      tied.sort((a, b) => {
        const ha = h2h[a.name], hb = h2h[b.name];
        // H2H pts → H2H GD → H2H GF → fair-play points (tiebreaker #7)
        return (hb.Pts - ha.Pts)
            || ((hb.GF - hb.GA) - (ha.GF - ha.GA))
            || (hb.GF - ha.GF)
            || (fairPlayPoints ? ((fairPlayPoints[b.name] || 0) - (fairPlayPoints[a.name] || 0)) : 0);
      });
      for (let k = i; k < j; k++) teams[k] = tied[k - i];
    }
    i = j;
  }
  return teams;
}

/**
 * Apply a single match outcome to the group standings (mutates copies).
 * v1.0/minimum model: home win = 1-0, draw = 0-0, away win = 0-1.
 * v1.4/poisson model: uses expected GD/GF derived from Poisson(λH, λA).
 *   Caller passes lambdaHome, lambdaAway via matchMeta to activate.
 * @param {Object} teamMap — {teamName: {name, P, W, D, L, GF, GA, Pts}, ...}
 * @param {string} home
 * @param {string} away
 * @param {('H'|'D'|'A')} outcome — Home win / Draw / Away win
 * @param {Array<Object>} playedSink — push the synthetic match here so H2H sees it
 * @param {{lambdaHome?: number, lambdaAway?: number}} [matchMeta]
 */
// WC_DRAW_AVG_LAMBDA: WC 2022 group-stage draws averaged ~1.1 goals per team.
// Used when Poisson lambdas are absent (no odds/totals line). Gives draws a
// 1-1 scoreline floor for GF tiebreaker realism instead of 0-0.
const WC_DRAW_AVG_LAMBDA = 1.1;

// Fair play Poisson card rates — WC 2022 group-stage empirical averages.
// FP_LAMBDA_YELLOW: 153 yellows / 48 matches / 2 teams = 1.59 → 1.6
// FP_LAMBDA_RED:    direct reds + second-yellow reds ≈ 0.20/team/match
// FIFA fair play scoring: yellow = −1, direct red = −3, second yellow = −3,
// yellow then red = −4. We model yellow (−1) and red (−3) only; the
// combined yellow+red case (~5% of reds) is absorbed into the red rate.
const FP_LAMBDA_YELLOW = 1.6;
const FP_LAMBDA_RED    = 0.2;

// Knuth Poisson sampler — O(λ) per call, adequate for λ ≤ 5.
// Requires rand: () => [0,1) PRNG supplied by caller.
function wcPoissonSample(lambda, rand) {
  const L = Math.exp(-lambda);
  let k = 0, p = 1;
  do { k++; p *= rand(); } while (p > L);
  return k - 1;
}

function wcApplyOutcome(teamMap, home, away, outcome, playedSink, matchMeta, rand = null) {
  const h = teamMap[home], a = teamMap[away];
  h.P += 1; a.P += 1;
  // v1.4: Poisson-expected GD if lambdas provided; else minimum-margin (1 or 0).
  const lH = matchMeta && matchMeta.lambdaHome > 0 ? matchMeta.lambdaHome : null;
  const lA = matchMeta && matchMeta.lambdaAway > 0 ? matchMeta.lambdaAway : null;
  if (outcome === 'H') {
    // Expected scoreline for a home win, rounded to nearest integer
    const hg = lH && lA ? Math.round(wcPoissonExpectedGoals(lH, lA, 'H', 'home')) : 1;
    const ag = lH && lA ? Math.round(wcPoissonExpectedGoals(lH, lA, 'H', 'away')) : 0;
    const safeHg = Math.max(hg, ag + 1);  // ensure result is actually a home win
    h.W += 1; h.Pts += 3; h.GF += safeHg; h.GA += ag;
    a.L += 1; a.GF += ag; a.GA += safeHg;
    playedSink.push({home, away, homeScore: safeHg, awayScore: ag});
  } else if (outcome === 'A') {
    const ag = lH && lA ? Math.round(wcPoissonExpectedGoals(lH, lA, 'A', 'away')) : 1;
    const hg = lH && lA ? Math.round(wcPoissonExpectedGoals(lH, lA, 'A', 'home')) : 0;
    const safeAg = Math.max(ag, hg + 1);
    a.W += 1; a.Pts += 3; a.GF += safeAg; a.GA += hg;
    h.L += 1; h.GF += hg; h.GA += safeAg;
    playedSink.push({home, away, homeScore: hg, awayScore: safeAg});
  } else {
    // Draw — expected goals each side (whole goals; uses ceiling so at least 0)
    const drHg = Math.round((lH ?? WC_DRAW_AVG_LAMBDA) * 0.6);  // ~1 goal each in avg WC draw
    const drAg = Math.round((lA ?? WC_DRAW_AVG_LAMBDA) * 0.6);
    h.D += 1; h.Pts += 1; h.GF += drHg; h.GA += drAg;
    a.D += 1; a.Pts += 1; a.GF += drAg; a.GA += drHg;
    playedSink.push({home, away, homeScore: drHg, awayScore: drAg});
  }
  // Fair play accumulation — Monte Carlo path only (rand provided by wcSampleScenario).
  // Enumeration path (wcEnumerateScenarios) passes rand = null → no FP sampling.
  // FIFA: yellow = −1, red = −3. Higher (less negative) FP = better ranking.
  if (rand) {
    const hT = teamMap[home], aT = teamMap[away];
    const hY = wcPoissonSample(FP_LAMBDA_YELLOW, rand);
    const aY = wcPoissonSample(FP_LAMBDA_YELLOW, rand);
    const hR = wcPoissonSample(FP_LAMBDA_RED,    rand);
    const aR = wcPoissonSample(FP_LAMBDA_RED,    rand);
    hT.FP = (hT.FP ?? 0) - hY - 3 * hR;
    aT.FP = (aT.FP ?? 0) - aY - 3 * aR;
  }
}

/**
 * Poisson expected goals for the WINNING side in a given outcome.
 * Computes E[goals | result] = Σ k × P(k goals) / P(result) for scorelines
 * where the result is consistent (home > away for H, etc.). Caps at 8 goals.
 * @param {number} lH — home team lambda (expected goals)
 * @param {number} lA — away team lambda
 * @param {('H'|'D'|'A')} outcome
 * @param {('home'|'away')} side — which team's goals to return
 * @returns {number} expected goals for that side, conditioned on the outcome
 */
function wcPoissonExpectedGoals(lH, lA, outcome, side) {
  const pois = (lam, k) => {
    let p = Math.exp(-lam), r = p;
    for (let i = 1; i <= k; i++) { r = r * lam / i; p = r; }
    return p;
  };
  let num = 0, den = 0;
  for (let h = 0; h <= 8; h++) {
    for (let a = 0; a <= 8; a++) {
      const relevant = outcome === 'H' ? h > a : outcome === 'A' ? a > h : h === a;
      if (!relevant) continue;
      const p = pois(lH, h) * pois(lA, a);
      den += p;
      num += p * (side === 'home' ? h : a);
    }
  }
  return den > 0 ? num / den : (side === 'home' ? lH : lA);
}


/**
 * Deep-copy a team-state map (small enough that JSON round-trip is fine).
 */
function wcCloneTeamMap(teamMap) {
  const out = {};
  for (const k in teamMap) out[k] = Object.assign({}, teamMap[k]);
  return out;
}

/**
 * Enumerate every W/D/L outcome combination for the remaining fixtures and
 * compute the resulting standings under FIFA tiebreakers. Returns one entry
 * per scenario, optionally weighted by per-match outcome probabilities.
 * @param {Object} teamMap — current standings keyed by team name
 * @param {Array<Object>} played — already-played matches (for H2H seeding)
 * @param {Array<Object>} remaining — [{home, away}, ...] unplayed
 * @param {Array<Object>} [outcomeProbs] — optional, parallel to remaining:
 *   [{pHome, pDraw, pAway}, ...]. When provided, each scenario carries a
 *   joint probability (product of per-match probs). When omitted, scenarios
 *   are returned with probability null and downstream code must treat them
 *   as a uniform distribution (1 / total).
 * @returns {Array<{outcomes, final, probability}>} list of 3^N scenarios
 */
function wcEnumerateScenarios(teamMap, played, remaining, outcomeProbs, fairPlayPoints) {
  const N = remaining.length;
  if (N > 8) {
    throw new Error(`wcEnumerateScenarios: ${N} remaining > supported max of 8`);
  }
  // Validate outcomeProbs if provided.
  let useProbs = false;
  if (Array.isArray(outcomeProbs) && outcomeProbs.length > 0) {
    if (outcomeProbs.length !== N) {
      throw new Error(`wcEnumerateScenarios: outcomeProbs length ${outcomeProbs.length} != remaining length ${N}`);
    }
    for (let i = 0; i < N; i++) {
      const p = outcomeProbs[i];
      if (!p || typeof p.pHome !== 'number' || typeof p.pDraw !== 'number' || typeof p.pAway !== 'number') {
        throw new Error(`wcEnumerateScenarios: outcomeProbs[${i}] missing pHome/pDraw/pAway`);
      }
      const sum = p.pHome + p.pDraw + p.pAway;
      if (Math.abs(sum - 1) > 0.01) {
        throw new Error(`wcEnumerateScenarios: outcomeProbs[${i}] sums to ${sum.toFixed(3)}, must be ~1.0`);
      }
    }
    useProbs = true;
  }
  const total = Math.pow(3, N);
  const scenarios = [];
  const codes = ['H', 'D', 'A'];
  for (let s = 0; s < total; s++) {
    const tm = wcCloneTeamMap(teamMap);
    const playedCopy = played.slice();
    const outcomeList = [];
    let bits = s;
    let prob = useProbs ? 1 : null;
    for (let k = 0; k < N; k++) {
      const code = codes[bits % 3];
      bits = Math.floor(bits / 3);
      outcomeList.push({home: remaining[k].home, away: remaining[k].away, outcome: code});
      // v1.4: pass matchMeta with Poisson lambdas when available in outcomeProbs
      const matchMeta = (useProbs && outcomeProbs[k]?.lambdaHome != null)
          ? { lambdaHome: outcomeProbs[k].lambdaHome, lambdaAway: outcomeProbs[k].lambdaAway }
          : null;
      wcApplyOutcome(tm, remaining[k].home, remaining[k].away, code, playedCopy, matchMeta);
      if (useProbs) {
        const p = outcomeProbs[k];
        prob *= (code === 'H' ? p.pHome : code === 'D' ? p.pDraw : p.pAway);
      }
    }
    const finalArr = Object.values(tm);
    wcSortByTiebreakers(finalArr, playedCopy, fairPlayPoints);
    scenarios.push({outcomes: outcomeList, final: finalArr.map(t => t.name), probability: prob});
  }
  return scenarios;
}

/**
 * Summarize per-team qualification possibilities across all scenarios.
 * If scenarios carry probability weights (probability !== null), the per-team
 * output additionally includes pFirst/pSecond/pThird/pFourth — probabilities
 * for each finishing position. If unweighted, those fields are null.
 * @param {Array<string>} teamNames
 * @param {Array<{outcomes, final, probability}>} scenarios
 * @returns {Object} per-team summary
 */
function wcSummarizePerTeam(teamNames, scenarios) {
  const out = {};
  const weighted = scenarios.length > 0 && scenarios[0].probability !== null;
  for (const name of teamNames) {
    let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
    let p1 = 0, p2 = 0, p3 = 0, p4 = 0;
    for (const sc of scenarios) {
      const idx = sc.final.indexOf(name);
      if (idx === 0)      { pos1++; if (weighted) p1 += sc.probability; }
      else if (idx === 1) { pos2++; if (weighted) p2 += sc.probability; }
      else if (idx === 2) { pos3++; if (weighted) p3 += sc.probability; }
      else                { pos4++; if (weighted) p4 += sc.probability; }
    }
    out[name] = {
      canTopGroup:      pos1 > 0,
      canQualifyTop2:   (pos1 + pos2) > 0,
      canFinish3rd:     pos3 > 0,
      alwaysTopGroup:   pos1 === scenarios.length,
      alwaysQualify:    (pos1 + pos2) === scenarios.length,
      alwaysEliminated: pos1 === 0 && pos2 === 0 && pos3 === 0,
      scenarioCounts:   {first: pos1, second: pos2, third: pos3, fourth: pos4},
      // Probability fields populated only when caller provided outcomeProbabilities.
      pFirst:           weighted ? p1 : null,
      pSecond:          weighted ? p2 : null,
      pThird:           weighted ? p3 : null,
      pFourth:          weighted ? p4 : null,
      pQualifyTop2:     weighted ? (p1 + p2) : null,
    };
  }
  return out;
}

/**
 * Main entrypoint — compute WC group-stage scenarios.
 *
 * @param {Object} input
 * @param {string} input.groupId — 'A' through 'L'
 * @param {Array<Object>} input.teams — current standings, each:
 *   {name, P, W, D, L, GF, GA, Pts}. Length must be 4.
 * @param {Array<Object>} input.played — already-played matches in this group:
 *   [{home, away, homeScore, awayScore}, ...]
 * @param {Array<Object>} input.remaining — unplayed fixtures: [{home, away}, ...]
 * @param {Array<Object>} [input.outcomeProbabilities] — optional, parallel to
 *   remaining: [{pHome, pDraw, pAway}, ...]. Each row must sum to ~1.0.
 *   When provided, perTeam output includes pFirst/pSecond/pThird/pFourth.
 * @returns {Object} {
 *   groupId, matchesRemaining, scenariosEnumerated,
 *   currentTable, perTeam, marginModel, weighted
 * }
 */
function computeGroupScenarios({groupId, teams, played, remaining, outcomeProbabilities, fairPlayPoints}) {
  if (!Array.isArray(teams) || teams.length !== 4) {
    throw new Error('computeGroupScenarios: teams must be an array of 4');
  }
  if (!Array.isArray(played))    played    = [];
  if (!Array.isArray(remaining)) remaining = [];
  // Build team map for fast lookup during enumeration.
  const teamMap = {};
  for (const t of teams) {
    teamMap[t.name] = Object.assign({}, t);
  }
  // Current table (under tiebreakers, no future outcomes applied).
  const currentSorted = Object.values(wcCloneTeamMap(teamMap));
  wcSortByTiebreakers(currentSorted, played, fairPlayPoints);
  // Enumerate (with optional probability weighting and fair-play tiebreaker).
  const scenarios = wcEnumerateScenarios(teamMap, played, remaining, outcomeProbabilities, fairPlayPoints);
  const perTeam   = wcSummarizePerTeam(teams.map(t => t.name), scenarios);
  return {
    groupId,
    matchesRemaining:    remaining.length,
    scenariosEnumerated: scenarios.length,
    currentTable:        currentSorted,
    perTeam,
    marginModel:         'minimum',
    weighted:            Array.isArray(outcomeProbabilities) && outcomeProbabilities.length > 0,
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// ── v1.2 — BEST-3rd CROSS-GROUP ENGINE ──────────────────────────────────────
// The 2026 WC format: 12 groups of 4 → top 2 from each group (24 teams) +
// best 8 third-place finishers across the 12 groups = 32 to Round of 32.
// Comparing third-place teams from DIFFERENT groups uses FIFA criteria:
// points → goal difference → goals scored → fair-play points → drawing of
// lots. H2H tiebreakers don't apply (the teams didn't play each other).
//
// Exhaustive enumeration across 12 groups is combinatorially infeasible
// (9^12 ≈ 2.8×10^11 at MD3, 729^12 ≈ 10^34 at MD0), so this is Monte Carlo.
// Default 10,000 samples is enough for stable P(qualify) estimates within
// roughly ±0.5% on a single team across runs. Increase samples for tighter
// confidence intervals.
//
// Determinism: pass a numeric `seed` to use a Mulberry32 PRNG for repeatable
// results in tests. Omit `seed` to use Math.random() (non-deterministic).
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Mulberry32 — tiny deterministic PRNG. Returns a function that yields
 * uniform [0, 1) on each call. State is closed over via `state`.
 * Reference: https://en.wikipedia.org/wiki/Mulberry32
 */
function wcMakePRNG(seed) {
  let state = (seed | 0) || 1;
  return function() {
    state = (state + 0x6D2B79F5) | 0;
    let t = state;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * Sample ONE outcome combination for a group's remaining matches and
 * compute the resulting final table. Used as the inner loop of the
 * cross-group Monte Carlo.
 * @param {Object} input — same shape as computeGroupScenarios inputs
 * @param {Function} rand — () => [0,1) PRNG
 * @returns {{finalTable: Array, thirdPlaceTeam: Object|null}}
 *   finalTable: sorted [{name, P, W, D, L, GF, GA, Pts}, ...]
 *   thirdPlaceTeam: the 3rd-place finisher's full record (or null on bad input)
 */
function wcSampleScenario({teams, played, remaining, outcomeProbabilities}, rand) {
  if (!Array.isArray(teams) || teams.length !== 4) return {finalTable: [], thirdPlaceTeam: null};
  if (!Array.isArray(played))    played    = [];
  if (!Array.isArray(remaining)) remaining = [];
  const useProbs = Array.isArray(outcomeProbabilities) && outcomeProbabilities.length === remaining.length;
  const teamMap = {};
  for (const t of teams) teamMap[t.name] = Object.assign({}, t);
  const playedCopy = played.slice();
  for (let k = 0; k < remaining.length; k++) {
    const r = rand();
    let outcome;
    if (useProbs) {
      const p = outcomeProbabilities[k];
      if      (r < p.pHome)             outcome = 'H';
      else if (r < p.pHome + p.pDraw)   outcome = 'D';
      else                              outcome = 'A';
    } else {
      // Uniform — equal probability for H/D/A
      outcome = r < 1/3 ? 'H' : r < 2/3 ? 'D' : 'A';
    }
    wcApplyOutcome(teamMap, remaining[k].home, remaining[k].away, outcome, playedCopy, null, rand);
  }
  const finalArr = Object.values(teamMap);
  wcSortByTiebreakers(finalArr, playedCopy);
  return {
    finalTable:     finalArr,
    thirdPlaceTeam: finalArr.length >= 3 ? finalArr[2] : null,
  };
}

// FNV-1a 32-bit hash of team name — deterministic drawing-of-lots tiebreaker
// (FIFA criteria 5). Reproducible across renders. Different teams produce
// distinct hashes with ~uniform distribution.
function _wcTeamNameHash(name) {
  let h = 2166136261;
  for (let i = 0; i < name.length; i++) {
    h ^= name.charCodeAt(i);
    h = (h * 16777619) >>> 0;
  }
  return h;
}

/**
 * Sort the third-place finishers across groups by FIFA cross-group criteria
 * (points → GD → GF → FP → drawing of lots). Returns the array sorted with
 * index 0 = best 3rd.
 */
function wcSortThirdPlaceAcrossGroups(thirdPlaceArr) {
  // FIFA cross-group best-3rd criteria (WC 2026):
  // 1. Points  2. GD  3. GF
  // 4. Fair play — accumulated via Poisson-sampled cards in wcSampleScenario
  //    (FP_LAMBDA_YELLOW=1.6, FP_LAMBDA_RED=0.2; less negative = better)
  // 5. Drawing of lots — seeded FNV-1a name hash (deterministic approximation)
  return thirdPlaceArr.slice().sort((a, b) =>
    (b.Pts - a.Pts)
      || ((b.GF - b.GA) - (a.GF - a.GA))
      || (b.GF - a.GF)
      || ((a.FP ?? 0) - (b.FP ?? 0))
      || (_wcTeamNameHash(a.name || '') - _wcTeamNameHash(b.name || ''))
  );
}

/**
 * Run cross-group Monte Carlo. For each sample, draws one scenario per
 * group, identifies each group's 3rd-place team, sorts them by FIFA
 * cross-group criteria, and credits the top 8 with one "qualify" count.
 *
 * @param {Object} input
 * @param {Array<Object>} input.groupInputs — array of group input objects,
 *   each {groupId, teams, played, remaining, outcomeProbabilities?}
 * @param {number} [input.samples=10000] — Monte Carlo iterations
 * @param {number|null} [input.seed=null] — PRNG seed (null = Math.random)
 * @param {number} [input.bestN=8] — how many third-place spots qualify (8 for WC 2026)
 * @returns {Object} {
 *   samples,
 *   bestN,
 *   perTeam: { [name]: { groupId, samplesAsThird, pAsThird, pQualifyAsBest3rd, pMissAsBest3rd } }
 * }
 */
function computeBest3rdRanking({groupInputs, samples = 10000, seed = null, bestN = 8}) {
  if (!Array.isArray(groupInputs) || groupInputs.length === 0) {
    throw new Error('computeBest3rdRanking: groupInputs must be a non-empty array');
  }
  const rand = (seed !== null && seed !== undefined) ? wcMakePRNG(seed) : Math.random;
  // Per-team counters across the run
  const counters = {};
  for (const gi of groupInputs) {
    for (const t of (gi.teams || [])) {
      counters[t.name] = counters[t.name] || {
        groupId:        gi.groupId,
        samplesAsThird: 0,
        samplesQualify: 0,
      };
    }
  }
  for (let s = 0; s < samples; s++) {
    // Sample one scenario per group, collect the third-place team
    const thirdPlace = [];
    for (const gi of groupInputs) {
      const res = wcSampleScenario(gi, rand);
      if (res.thirdPlaceTeam) {
        thirdPlace.push(Object.assign({groupId: gi.groupId}, res.thirdPlaceTeam));
      }
    }
    // Sort by FIFA cross-group criteria; top bestN qualify
    const sorted = wcSortThirdPlaceAcrossGroups(thirdPlace);
    for (let i = 0; i < sorted.length; i++) {
      const tp = sorted[i];
      counters[tp.name].samplesAsThird++;
      if (i < bestN) counters[tp.name].samplesQualify++;
    }
  }
  // Derive probabilities
  const perTeam = {};
  for (const name in counters) {
    const c = counters[name];
    perTeam[name] = {
      groupId:           c.groupId,
      samplesAsThird:    c.samplesAsThird,
      pAsThird:          c.samplesAsThird / samples,
      pQualifyAsBest3rd: c.samplesQualify / samples,
      // P(team finishes 3rd AND misses best-N cut) = P(3rd) − P(qualify as best-3rd)
      pMissAsBest3rd:    (c.samplesAsThird - c.samplesQualify) / samples,
    };
  }
  return {samples, bestN, perTeam};
}



// ── field_utils.js functions inlined (May 29 2026) ─────────────────────────
