function gameNetwork(g, defaultLabel='') {
  return (g && g.streams && g.streams[0] && g.streams[0].label) || defaultLabel;
}

function shiftTime(iso, minutes) {
  if (!iso) return iso;
  return new Date(new Date(iso).getTime() + minutes * 60 * 1000).toISOString();
}

function parseMatchweek(leagueStr) {
  const m = (leagueStr||'').match(/Matchweek\s*(\d+)/i);
  return m ? parseInt(m[1]) : null;
}

function dramaTier(score){
  if(score>=80) return 'fire';
  if(score>=60) return 'hot';
  if(score>=40) return 'warm';
  return '';
}

// iPad-12: national-team aliases. The word-match in espnTeamMatch requires
// shared tokens >3 chars, so short broadcaster shorthand (USMNT, USA, GBR,
// NED 3-letter ISO codes, etc.) misses against full names like "United States"
// or "Netherlands". ESPN's soccer/fifa.world feed often ships shortcodes;
// wc26Raw stores full national-team names. The alias map maps both
// directions so either side of the comparison resolves to a canonical form
// before substring/word match runs.
const _nationalTeamAlias = (() => {
  const pairs = {
    'usmnt':'united states', 'us':'united states', 'usa':'united states', 'united states':'united states',
    'mex':'mexico', 'can':'canada', 'arg':'argentina', 'bra':'brazil', 'col':'colombia',
    'fra':'france', 'esp':'spain', 'eng':'england', 'gbr':'england', 'ger':'germany', 'deu':'germany',
    'ita':'italy', 'por':'portugal', 'ned':'netherlands', 'nl':'netherlands', 'bel':'belgium',
    'sui':'switzerland', 'aut':'austria', 'cze':'czechia', 'czech republic':'czechia',
    'pol':'poland', 'cro':'croatia', 'ser':'serbia', 'srb':'serbia',
    'jpn':'japan', 'kor':'south korea', 'south korea':'south korea',
    'sau':'saudi arabia', 'saudi arabia':'saudi arabia', 'irn':'iran', 'aus':'australia',
    'mar':'morocco', 'sen':'senegal', 'tun':'tunisia', 'rsa':'south africa', 'south africa':'south africa',
    'gha':'ghana', 'civ':'ivory coast', 'ivory coast':'ivory coast', 'nga':'nigeria',
    'cod':'congo dr', 'cgo':'congo dr', 'dr congo':'congo dr', 'congo dr':'congo dr',
    'tur':'turkiye', 'türkiye':'turkiye', 'turkey':'turkiye',
    'cpv':'cape verde', 'cape verde':'cape verde',
    'cur':'curacao', 'curaçao':'curacao', 'curacao':'curacao',
    'nzl':'new zealand', 'new zealand':'new zealand',
    'crc':'costa rica', 'costa rica':'costa rica',
    'bih':'bosnia', 'bosnia and herzegovina':'bosnia',
    'swe':'sweden', 'nor':'norway', 'den':'denmark', 'fin':'finland',
    'alg':'algeria', 'egy':'egypt', 'kse':'kosovo',
  };
  return pairs;
})();
function _canonNationalTeam(name) {
  if (!name) return '';
  const n = String(name).toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9 ]/g, '').trim();
  return _nationalTeamAlias[n] || n;
}

function espnTeamMatch(espnName, fieldName){
  if(!espnName||!fieldName) return false;
  // Normalize: lowercase, remove diacritics, strip punctuation
  const norm = s => s.toLowerCase()
    .normalize("NFD").replace(/[̀-ͯ]/g,"")
    .replace(/[^a-z0-9 ]/g,"");
  const a = norm(espnName), b = norm(fieldName);
  if(a===b) return true;
  if(a.includes(b)||b.includes(a)) return true;
  // Word match: any word > 3 chars shared between names
  if (a.split(" ").some(w=>w.length>3&&b.includes(w))
   || b.split(" ").some(w=>w.length>3&&a.includes(w))) return true;
  // iPad-12: national-team alias match — short broadcaster shorthand
  // (USMNT, NED, JPN, etc.) resolves to canonical name before compare.
  const ca = _canonNationalTeam(espnName), cb = _canonNationalTeam(fieldName);
  if (ca && cb && ca === cb) return true;
  return false;
}

function journalismCallsToday(){
  const k='field_j_calls_'+fieldDateKey(new Date());
  return {
    get(){return parseInt(sessionStorage.getItem(k)||'0');},
    inc(){sessionStorage.setItem(k,String(this.get()+1));},
    // Blocks when session count exhausted OR within a 429 backoff window.
    // Prevents individual J2/J3 calls from firing during compound 429 backoff,
    // which would compound the Gemini quota burn and extend the outage.
    canCall(){
      if(this.get()>=50) return false;
      if(typeof _compoundRetryAfter!=='undefined' && Date.now()<_compoundRetryAfter) return false;
      return true;
    },
    // 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #5): additive
    // only -- canCall()'s boolean contract is unchanged, all 9 real
    // callers keep working exactly as before. Budget-exhausted (permanent
    // for the rest of the day, no retry-timing to offer) and 429-backoff
    // (temporary, _compoundRetryAfter IS the known expiry, already
    // computed elsewhere) were being collapsed to the same undifferentiated
    // false. A caller that wants to say WHY it's blocked (fetchCompoundEditorial
    // already tries to, see the fix on that function) can now ask.
    blockedReason(){
      if(this.get()>=50) return 'budget-exhausted';
      if(typeof _compoundRetryAfter!=='undefined' && Date.now()<_compoundRetryAfter) return 'backoff';
      return null;
    }
  };
}

// ── Card-level brief budget (separate from compound/J3 journalism budget) ─────
// MLB/WNBA/Stakes card briefs must not consume the compound editorial budget.
// With 15 MLB games, 3 WNBA games, and up to 4 stakes games, sharing the
// 8-call journalism budget with J3/Night Owl causes MLB briefs to silently
// fail when the compound call already used 1-2 budget slots.
// Card brief budget: 50 calls/session — raised from 15 (Tier 1: 4000 RPM, Jun 2026).
function cardBriefCallsToday(){
  const k='field_card_brief_calls_'+new Date().toISOString().slice(0,10);
  return {
    get(){return parseInt(sessionStorage.getItem(k)||'0');},
    inc(){sessionStorage.setItem(k,String(this.get()+1));},
    canCall(){return this.get()<50;}
  };
}

// ── Compound Editorial Call — eliminates RPM burst ───────────────────────────
// Replaces 5-7 simultaneous journalism calls with 1 structured JSON call.
// Content-addressed cache: only regenerates when game context changes.
// 429 fallback: temporal spread queue fires individual calls 3s apart.

function djb2Hash(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h) ^ str.charCodeAt(i);
  return (h >>> 0).toString(36);
}

