// Dispatcher: routes to correct source per sport, populates _relayStandingsCache
async function fetchStandingsForPrompt(sport) {
  if (!sport) return null;
  if (sport.includes('Baseball') || sport.includes('MLB'))     return fetchMLBStandingsParsed();
  if (sport.includes('Basketball') || sport.includes('NBA'))   return fetchNBAStandingsParsed();
  if (sport.includes('Hockey') || sport.includes('NHL'))       return fetchNHLStandingsParsed();
  if (sport.includes('MLS'))                                    return fetchMLSStandingsParsed();
  // Soccer: FD already populates fdStandingsCache — buildGameStandingsContext reads it directly
  // NFL: off-season, low urgency — ESPN on-demand via ▼ Table button is acceptable
  return null;
}
// Returns a compact standings line for a game using cached ESPN/FD data.
// Called synchronously — only uses whatever is already in cache.
// Pre-fetch via fetchESPNStandings() or fetchFDStandings() before calling.
//
// Output: "Standings: Cubs: 34-28, 3.0 GB · Cardinals: 37-25 (leads division)"
//         "Table: Arsenal: 2★ (75pts) · Chelsea: 4 (68pts)"
//         "" if no data available
function buildGameStandingsContext(game) {
  const sport = _gameSport(game);

  // ── Soccer: FD standings ────────────────────────────────────────────────
  const fdCode = typeof FD_LEAGUE_MAP !== 'undefined' && FD_LEAGUE_MAP[sport];
  if (fdCode && fdStandingsCache[fdCode]?.length) {
    const rows = fdStandingsCache[fdCode];
    const findFD = name => {
      const n = teamNick(name).toLowerCase();
      return rows.find(r => (r.team || '').toLowerCase().includes(n));
    };
    const fmt = (e, t) => !e ? '' :
      `${t}: ${e.pos}${e.pos <= 4 ? '★' : e.pos >= 18 ? '↓' : ''} (${e.pts}pts)`;
    const parts = [fmt(findFD(game.away), game.away), fmt(findFD(game.home), game.home)].filter(Boolean);
    return parts.length ? 'Table: ' + parts.join(' · ') : '';
  }

  // ── MLS Soccer: relay standings from fetchMLSStandingsParsed ─────────
  if (sport.includes('MLS')) {
    const mlsRows = _relayStandingsCache[sport];
    if (mlsRows?.length) {
      const n = name => teamNick(name).toLowerCase();
      const findMLS = name => mlsRows.find(r => (r.team||"").toLowerCase().includes(n(name)));
      const fmt = (e, t) => !e ? "" : `${t}: ${e.pts}pts`;
      const parts = [fmt(findMLS(game.away), game.away), fmt(findMLS(game.home), game.home)].filter(Boolean);
      return parts.length ? "Table: " + parts.join(" · ") : "";
    }
  }

  // ── US sports: relay/API standings first, ESPN on-demand as fallback ────
  // _relayStandingsCache populated by fetchStandingsForPrompt() (MLB Stats API / NBA relay / NHL relay)
  // espnStandingsCache populated only when user clicks ▼ Table — acceptable fallback
  const relayRows = _relayStandingsCache[sport];
  const map = ESPN_STANDINGS_MAP[sport];
  const espnRows = map ? espnStandingsCache[`${map.sport}/${map.league}`] : null;
  const standings = relayRows || espnRows;
  if (!standings?.length) return '';

  const findTeam = name => {
    const n = teamNick(name).toLowerCase();
    return standings.find(s =>
      (s.team || '').toLowerCase().includes(n) ||
      (s.abbrev || '').toLowerCase() === n
    );
  };
  const fmt = (e, t) => {
    if (!e) return '';
    const gb = parseFloat(e.gb);
    if (isNaN(gb) || gb === 0) return `${t}: ${e.wins}-${e.losses} (leads)`;
    return `${t}: ${e.wins}-${e.losses}, ${e.gb} GB`;
  };
  const parts = [fmt(findTeam(game.away), game.away), fmt(findTeam(game.home), game.home)].filter(Boolean);
  if (!parts.length) return '';
  // Standing Velocity: enrich each team's line with 7-day GB momentum if available
  const division = (standings[0]?.division || '');
  const awayVel = getStandingVelocity(sport, division, game.away, 7);
  const homeVel = getStandingVelocity(sport, division, game.home, 7);
  const velNote = (vel) => {
    if (!vel || Math.abs(vel.delta) < 0.5) return '';
    return vel.delta > 0 ? ` · gained ${vel.delta} GB last ${vel.days}d`
                         : ` · lost ${Math.abs(vel.delta)} GB last ${vel.days}d`;
  };
  // Re-build parts with velocity appended
  const awayFmt = fmt(findTeam(game.away), game.away) + velNote(awayVel);
  const homeFmt = fmt(findTeam(game.home), game.home) + velNote(homeVel);
  const velParts = [awayFmt, homeFmt].filter(Boolean);
  // Also record today's snapshot for future velocity computation
  recordStandingsSnapshot(sport, division, standings.map(s => ({
    team: s.team, abbrev: s.abbrev, gb: s.gb, wins: s.wins, losses: s.losses
  })));
  return 'Standings: ' + velParts.join(' · ');
}

