function getHeadCoachForTeam(teamName, sport) {
  if (!teamName) return null;
  const s = (sport || '').toLowerCase();
  try {
    if (s.includes('nhl') || s.includes('hockey')) {
      const abbrev = (typeof getNHLAbbrev === 'function') ? getNHLAbbrev(teamName) : null;
      return abbrev ? (NHL_HEAD_COACHES[abbrev] || null) : null;
    }
    if (s.includes('nba') || s.includes('basketball')) {
      return NBA_HEAD_COACHES[(teamName || '').toLowerCase()] || null;
    }
  } catch(_) {}
  return null;
}

function getSeriesHistoricalAnchor(game) {
  if (!game) return null;
  const league = (game.league || '').toLowerCase();
  const sport = (_gameSport(game)).toLowerCase();
  try {
    if ((sport.includes('nhl') || sport.includes('hockey')) && /stanley\s*cup\s*final/.test(league)) {
      return SERIES_HISTORICAL_ANCHORS['NHL_SCF_2026'] || null;
    }
    if ((sport.includes('nba') || sport.includes('basketball')) && /nba\s*finals/.test(league)) {
      return SERIES_HISTORICAL_ANCHORS['NBA_FINALS_2026'] || null;
    }
  } catch(_) {}
  return null;
}

// ── ESPN Injuries Feed (P1 followup: NHL injury feed + NBA injury upgrade) ──
// Source: site.api.espn.com /apis/site/v2/sports/{hockey,basketball}/{nhl,nba}/injuries
// Single league-wide endpoint per sport; CORS-open; cf-cached short TTL upstream.
// Endpoints VERIFIED via cors-probe runs 20260601T200655Z (NHL) + 20260601T200813Z
// (NBA) — both returned 200 with shape:
//   { timestamp, season, injuries: [
//     { id, displayName: "Team Name", injuries: [
//       { id, status, date, longComment, shortComment,
//         athlete: { firstName, lastName, displayName, shortName,
//                    position: {abbreviation}, team: {abbreviation, displayName} },
//         type: { name, description, abbreviation },
//         details: { type, detail?, location?, side?, returnDate } } ] } ] }
// ADR-001: counters (active injury status); must come from feed, never hardcoded.
//
// Replaces the operationally-inert bdlInjuryContextSync pass-through (BDL_SPORT_MAP
// has been empty since May 15 2026 — see comment at line ~9034 — so the PM-2
// Phase B subtask 8 wiring was structurally correct but produced no live data).
//
// Cache: 30-min TTL — injury status changes slowly, daily-update cadence in practice.
const ESPN_INJURY_TTL = 30 * 60 * 1000;
const _espnInjuryCache = {
  nhl: { data: null, fetchedAt: 0, inFlight: null },
  nba: { data: null, fetchedAt: 0, inFlight: null },
};

// Map sport label → { espnSport, espnLeague, storageKey }
function _espnInjurySportSlug(sportLabel) {
  const s = (sportLabel || '').toLowerCase();
  if (s.includes('nhl') || s.includes('hockey')) return { key: 'nhl', sport: 'hockey', league: 'nhl' };
  if (s.includes('nba') || s.includes('basketball')) return { key: 'nba', sport: 'basketball', league: 'nba' };
  return null;
}

// Parses ESPN's response shape into { teamAbbrev → ["Player Name (Status — Type)", ...] }
function buildESPNInjuriesByTeam(json) {
  const out = {};
  if (!json || !Array.isArray(json.injuries)) return out;
  json.injuries.forEach(teamBlock => {
    if (!teamBlock || !Array.isArray(teamBlock.injuries)) return;
    teamBlock.injuries.forEach(inj => {
      const ath = inj?.athlete || {};
      const teamAbbr = ath.team?.abbreviation || '';
      if (!teamAbbr) return;
      // Build short label: prefer shortName (e.g. "T. Terry") + position abbreviation
      const nm = ath.shortName || ath.displayName || (`${ath.firstName||''} ${ath.lastName||''}`.trim());
      if (!nm) return;
      const pos = ath.position?.abbreviation || '';
      // Status (from inj.status or inj.type.description; fall back to type.abbreviation)
      const status = inj.status || inj.type?.description || inj.type?.abbreviation || '';
      // Detail (body part / nature) from details.type
      const detail = inj.details?.type || inj.details?.detail || '';
      const parts = [];
      if (status) parts.push(status);
      if (detail) parts.push(detail);
      const label = pos ? `${nm} (${pos})` : nm;
      const tail = parts.length ? ` — ${parts.join(' / ')}` : '';
      out[teamAbbr] = out[teamAbbr] || [];
      // Cap 4 entries per team to keep prompt context tight
      if (out[teamAbbr].length < 4) out[teamAbbr].push(label + tail);
    });
  });
  return out;
}

async function fetchESPNInjuries(sportKey) {
  // sportKey: 'nhl' or 'nba'
  const slug = (sportKey === 'nhl' || sportKey === 'nba') ? { key: sportKey, sport: (sportKey === 'nhl' ? 'hockey' : 'basketball'), league: sportKey } : null;
  if (!slug) return {};
  const cache = _espnInjuryCache[slug.key];
  const now = Date.now();
  if (cache.data && (now - cache.fetchedAt) < ESPN_INJURY_TTL) return cache.data;
  try {
    const lsKey = 'field_espn_injuries_' + slug.key;
    const cached = localStorage.getItem(lsKey);
    if (cached) {
      const p = JSON.parse(cached);
      if (p?.ts && (now - p.ts) < ESPN_INJURY_TTL && p.data) {
        cache.data = p.data; cache.fetchedAt = p.ts;
        return p.data;
      }
    }
  } catch(_) {}
  if (cache.inFlight) return cache.inFlight;
  cache.inFlight = (async () => {
    try {
      const base = (typeof ESPN_BASE !== 'undefined') ? ESPN_BASE : 'https://site.api.espn.com/apis/site/v2/sports';
      const url = `${base}/${slug.sport}/${slug.league}/injuries`;
      const r = await fetch(url, { signal: AbortSignal.timeout(6000) });
      if (!r.ok) return cache.data || {};
      const json = await r.json().catch(()=>null);
      if (!json) return cache.data || {};
      const data = buildESPNInjuriesByTeam(json);
      cache.data = data; cache.fetchedAt = Date.now();
      try { localStorage.setItem('field_espn_injuries_' + slug.key, JSON.stringify({ ts: Date.now(), data })); } catch(_) {}
      if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.log(`[ESPN Injuries ${slug.key.toUpperCase()}] fetched ${Object.keys(data).length} teams · ${Object.values(data).reduce((a,arr)=>a+arr.length,0)} entries (FIELD_DEBUG)`);
      return data;
    } catch(_e) {
      captureFieldError('espn:injuries-prefetch', _e, true);
      return cache.data || {};
    } finally {
      cache.inFlight = null;
    }
  })();
  return cache.inFlight;
}

// Sync getter — reads from warm cache (NHL or NBA). Returns array of
// "ABBR Player (POS) — Status / Type" lines or null when cache empty.
function getESPNInjuriesForGame(game) {
  if (!game) return null;
  const slug = _espnInjurySportSlug(_gameSport(game));
  if (!slug) return null;
  const data = _espnInjuryCache[slug.key]?.data;
  if (!data) return null;
  // Resolve abbrevs for home + away. NHL uses getNHLAbbrev; NBA needs a separate
  // lookup since NBA_ABBREV_MAP only covers active-playoff teams. Build a tiny
  // fallback that pulls the abbrev directly from the cache key set when the
  // team name's last word matches an ESPN nickname (e.g. "Hurricanes" → "CAR").
  const nameToAbbr = (full) => {
    if (!full) return null;
    if (slug.key === 'nhl' && typeof getNHLAbbrev === 'function') {
      const a = getNHLAbbrev(full);
      if (a) return a;
    }
    if (slug.key === 'nba' && typeof getNBAAbbrev === 'function') {
      const a = getNBAAbbrev(full);
      if (a) return a;
    }
    // Last-resort: look for a cached team whose nickname (last word of full name)
    // appears in our data keys. We don't have nicknames in the cache, only
    // abbrevs, so this fallback is intentionally narrow: it only fires when the
    // sport-specific abbrev getter failed.
    return null;
  };
  const homeAbbr = game._homeAbbr || nameToAbbr(game.home);
  const awayAbbr = game._awayAbbr || nameToAbbr(game.away);
  const lines = [];
  if (awayAbbr && Array.isArray(data[awayAbbr])) {
    data[awayAbbr].forEach(l => lines.push(`${awayAbbr} ${l}`));
  }
  if (homeAbbr && Array.isArray(data[homeAbbr])) {
    data[homeAbbr].forEach(l => lines.push(`${homeAbbr} ${l}`));
  }
  return lines.length ? lines : null;
}

// Prefetch entrypoint — covers both sports in parallel. Fire-and-forget.
function espnInjuriesPrefetch() {
  try { fetchESPNInjuries('nhl'); } catch(_) {}
  try { fetchESPNInjuries('nba'); } catch(_) {}
}

// ── Subtask 9 — NHL Playoff Leaders Feed (Axis 3 Phase B, June 1 2026 PM-3) ──
// Source: api-web.nhle.com v1 skater-stats-leaders + goalie-stats-leaders,
// fetched via NHL_RELAY proxy (field-relay-nba /nhl/* → api-web.nhle.com/*).
// ADR-001: COUNTERS — values change game-by-game, must come from feed.
// Endpoints VERIFIED via cors-probe runs 20260601T194319Z (skater) +
// 20260601T194440Z (goalie) — both returned 200 with documented shape:
//   skater payload: { points:[…], goals:[…], assists:[…] }
//   goalie payload: { wins:[…], goalsAgainstAverage:[…], savePctg:[…], shutouts:[…] }
// Each entry has: { firstName.default, lastName.default, teamAbbrev, value }.
// Cache: 15-min TTL during games per HANDOFF spec. localStorage warm cache
// survives reloads. inFlight dedup prevents concurrent burst fetches.
const NHL_PLAYOFF_LEADERS_TTL = 15 * 60 * 1000;
const _nhlPlayoffLeadersCache = { data: null, fetchedAt: 0, inFlight: null };

// Builds { teamAbbrev → ["M. Marner 21 pts", "J. Eichel 16 A", "Hart 12W 2.22 GAA .924 SV%"] }
// Cap 4 entries per team to keep prompt context tight. Skater entries first
// (offense leaders), then goalie aggregate. Dedup by player surname.
function buildNHLPlayoffLeadersByTeam(skater, goalie) {
  const out = {};
  const pushUnique = (team, line, surname) => {
    if (!team || !line) return;
    out[team] = out[team] || [];
    const tag = surname ? new RegExp(`^[A-Z]\\.\\s*${surname.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}\\b`) : null;
    if (tag && out[team].some(s => tag.test(s))) return; // already have this player
    if (out[team].length < 4) out[team].push(line);
  };
  const initials = (p, lbl) => {
    const fn = p?.firstName?.default || '';
    const ln = p?.lastName?.default || '';
    const v = (typeof p?.value === 'number') ? p.value : null;
    if (!ln || v == null) return null;
    return { line: `${fn ? fn[0] + '. ' : ''}${ln} ${v} ${lbl}`, surname: ln };
  };
  if (skater && typeof skater === 'object') {
    (skater.points || []).slice(0, 5).forEach(p => {
      const f = initials(p, 'pts'); if (!f) return; pushUnique(p.teamAbbrev, f.line, f.surname);
    });
    (skater.goals || []).slice(0, 5).forEach(p => {
      const f = initials(p, 'G'); if (!f) return; pushUnique(p.teamAbbrev, f.line, f.surname);
    });
    (skater.assists || []).slice(0, 5).forEach(p => {
      const f = initials(p, 'A'); if (!f) return; pushUnique(p.teamAbbrev, f.line, f.surname);
    });
  }
  if (goalie && typeof goalie === 'object') {
    // Aggregate per (team, surname) so one goalie's wins+GAA+SV% become one line
    const agg = {};
    const addG = (g, field) => {
      if (!g?.teamAbbrev) return;
      const ln = g.lastName?.default || '';
      if (!ln) return;
      const k = g.teamAbbrev + '|' + ln;
      agg[k] = agg[k] || { team: g.teamAbbrev, name: ln };
      if (typeof g.value === 'number') agg[k][field] = g.value;
    };
    (goalie.wins || []).slice(0, 6).forEach(g => addG(g, 'wins'));
    (goalie.goalsAgainstAverage || []).slice(0, 6).forEach(g => addG(g, 'gaa'));
    (goalie.savePctg || []).slice(0, 6).forEach(g => addG(g, 'svPct'));
    Object.values(agg).forEach(gg => {
      const parts = [];
      if (gg.wins != null) parts.push(`${gg.wins}W`);
      if (gg.gaa != null) parts.push(`${gg.gaa.toFixed(2)} GAA`);
      if (gg.svPct != null) parts.push(`.${Math.round(gg.svPct * 1000)} SV%`);
      if (!parts.length) return;
      pushUnique(gg.team, `${gg.name} ${parts.join(' ')}`, gg.name);
    });
  }
  return out;
}

async function fetchNHLPlayoffLeaders() {
  const now = Date.now();
  if (_nhlPlayoffLeadersCache.data && (now - _nhlPlayoffLeadersCache.fetchedAt) < NHL_PLAYOFF_LEADERS_TTL) {
    return _nhlPlayoffLeadersCache.data;
  }
  try {
    const cached = localStorage.getItem('field_nhl_playoff_leaders');
    if (cached) {
      const p = JSON.parse(cached);
      if (p?.ts && (now - p.ts) < NHL_PLAYOFF_LEADERS_TTL && p.data) {
        _nhlPlayoffLeadersCache.data = p.data;
        _nhlPlayoffLeadersCache.fetchedAt = p.ts;
        return p.data;
      }
    }
  } catch(_) {}
  if (_nhlPlayoffLeadersCache.inFlight) return _nhlPlayoffLeadersCache.inFlight;
  _nhlPlayoffLeadersCache.inFlight = (async () => {
    try {
      const season = 20252026;
      const gameType = 3; // playoffs
      const base = (typeof NHL_RELAY !== 'undefined') ? NHL_RELAY : 'https://field-relay-nba.jeffunglesbee.workers.dev/nhl';
      const skUrl = `${base}/v1/skater-stats-leaders/${season}/${gameType}?categories=points,goals,assists&limit=10`;
      const gkUrl = `${base}/v1/goalie-stats-leaders/${season}/${gameType}?categories=wins,goalsAgainstAverage,savePctg&limit=10`;
      const [skR, gkR] = await Promise.allSettled([
        fetch(skUrl, { signal: AbortSignal.timeout(6000) }),
        fetch(gkUrl, { signal: AbortSignal.timeout(6000) }),
      ]);
      const sk = (skR.status === 'fulfilled' && skR.value.ok) ? await skR.value.json().catch(()=>null) : null;
      const gk = (gkR.status === 'fulfilled' && gkR.value.ok) ? await gkR.value.json().catch(()=>null) : null;
      if (!sk && !gk) return _nhlPlayoffLeadersCache.data || {}; // serve stale on full failure
      const data = buildNHLPlayoffLeadersByTeam(sk, gk);
      _nhlPlayoffLeadersCache.data = data;
      _nhlPlayoffLeadersCache.fetchedAt = Date.now();
      try { localStorage.setItem('field_nhl_playoff_leaders', JSON.stringify({ ts: Date.now(), data })); } catch(_) {}
      if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.log('[NHL Playoff Leaders] fetched', Object.keys(data).length, 'teams (FIELD_DEBUG)');
      return data;
    } catch(_e) {
      captureFieldError('nhl:playoff-leaders-prefetch', _e, true);
      return _nhlPlayoffLeadersCache.data || {};
    } finally {
      _nhlPlayoffLeadersCache.inFlight = null;
    }
  })();
  return _nhlPlayoffLeadersCache.inFlight;
}

// Sync getter — reads from warm cache. Used by populateSeriesContext.
// Returns array of leader lines (away team first, then home), or null if no
// data cached yet (degrades gracefully — no [PLAYOFF STATS:] tag emitted).
function getNHLPlayoffLeadersForGame(game) {
  if (!game) return null;
  const sport = (_gameSport(game)).toLowerCase();
  if (!sport.includes('nhl') && !sport.includes('hockey')) return null;
  const data = _nhlPlayoffLeadersCache.data;
  if (!data) return null;
  const homeAbbr = game._homeAbbr || (typeof getNHLAbbrev === 'function' ? getNHLAbbrev(game.home) : null);
  const awayAbbr = game._awayAbbr || (typeof getNHLAbbrev === 'function' ? getNHLAbbrev(game.away) : null);
  const lines = [];
  if (awayAbbr && Array.isArray(data[awayAbbr])) {
    data[awayAbbr].forEach(l => lines.push(`${awayAbbr} ${l}`));
  }
  if (homeAbbr && Array.isArray(data[homeAbbr])) {
    data[homeAbbr].forEach(l => lines.push(`${homeAbbr} ${l}`));
  }
  return lines.length ? lines : null;
}

// Prefetch entrypoint — call from init sequence alongside bdlPrefetchAll.
// Fire-and-forget; sync getter reads from cache once data lands.
function nhlPlayoffLeadersPrefetch() {
  try { fetchNHLPlayoffLeaders(); } catch(_) {}
}

// ── NBA Playoff Leaders (stats.nba.com via /nba-stats/leagueLeaders relay) ────
// Source: stats.nba.com/stats/leagueLeaders proxied through field-relay-nba.
// Rule 45 source-clearance: ADR-003 (Drive 1XUPoayJUTh2Ki_DYXgw8uOAYZoGtpDt2c7510vGq64w)
// records Jeff's explicit accept-the-risk decision on June 1 2026. NBA.com ToS
// requires attribution wherever the data displays — populateSeriesContext sets
// game._playoffLeadersAttribution = 'NBA.com' alongside game.playoffLeaders and
// buildSeriesContextTags surfaces it inline in the [PLAYOFF STATS:] tag.
// USPTO commercial transition is a re-evaluation trigger; see ADR-003.
//
// Response shape from stats.nba.com (row-based JSON):
//   { resultSet: { headers: [...], rowSet: [[PLAYER_ID, RANK, PLAYER, TEAM_ID,
//     TEAM, GP, MIN, FGM, FGA, FG_PCT, FG3M, FG3A, FG3_PCT, FTM, FTA, FT_PCT,
//     OREB, DREB, REB, AST, STL, BLK, TOV, PTS, EFF], ...] } }
// One request per StatCategory (PTS, REB, AST, FG3M). Combined into per-team
// leader lines, capped 4 per team, mirroring the NHL builder pattern.
const NBA_PLAYOFF_LEADERS_TTL = 15 * 60 * 1000;
const _nbaPlayoffLeadersCache = { data: null, fetchedAt: 0, inFlight: null };

// Parses one stats.nba.com leagueLeaders JSON response, extracting top-N players
// for the named statKey (which matches the column header in resultSet.headers).
// Returns array of { team, name, value }.
function _parseNBALeagueLeaders(json, statKey, topN) {
  try {
    const headers = json && json.resultSet && json.resultSet.headers;
    const rows = json && json.resultSet && json.resultSet.rowSet;
    if (!Array.isArray(headers) || !Array.isArray(rows)) return [];
    const iPlayer = headers.indexOf('PLAYER');
    const iTeam = headers.indexOf('TEAM');
    const iStat = headers.indexOf(statKey);
    if (iPlayer < 0 || iTeam < 0 || iStat < 0) return [];
    return rows.slice(0, topN).map(r => ({
      team: r[iTeam],
      name: r[iPlayer],
      value: r[iStat],
    })).filter(x => x.team && x.name && typeof x.value === 'number');
  } catch(_) { return []; }
}

// Builds { teamAbbrev → ["J. Brunson 26.9 pts", "OG Anunoby 6.9 reb", ...] }
// from four pre-parsed leader arrays (pts/reb/ast/3pm). Cap 4 entries per team.
// Dedup by surname so one star doesn't appear in all four categories.
function buildNBAPlayoffLeadersByTeam(ptsLeaders, rebLeaders, astLeaders, fg3mLeaders) {
  const out = {};
  const pushUnique = (team, line, surname) => {
    if (!team || !line) return;
    out[team] = out[team] || [];
    const tag = surname ? new RegExp(`\\b${surname.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')}\\b`) : null;
    if (tag && out[team].some(s => tag.test(s))) return; // already have this player
    if (out[team].length < 4) out[team].push(line);
  };
  const fmt = (p, lbl) => {
    if (!p || !p.name || typeof p.value !== 'number') return null;
    const parts = String(p.name).split(' ');
    const surname = parts[parts.length - 1];
    const first = parts.length > 1 ? parts[0][0] + '. ' : '';
    return { line: `${first}${surname} ${p.value.toFixed(1)} ${lbl}`, surname };
  };
  (ptsLeaders || []).forEach(p => {
    const f = fmt(p, 'pts'); if (!f) return; pushUnique(p.team, f.line, f.surname);
  });
  (rebLeaders || []).forEach(p => {
    const f = fmt(p, 'reb'); if (!f) return; pushUnique(p.team, f.line, f.surname);
  });
  (astLeaders || []).forEach(p => {
    const f = fmt(p, 'ast'); if (!f) return; pushUnique(p.team, f.line, f.surname);
  });
  (fg3mLeaders || []).forEach(p => {
    const f = fmt(p, '3PM'); if (!f) return; pushUnique(p.team, f.line, f.surname);
  });
  return out;
}

async function fetchNBAPlayoffLeaders() {
  const now = Date.now();
  if (_nbaPlayoffLeadersCache.data && (now - _nbaPlayoffLeadersCache.fetchedAt) < NBA_PLAYOFF_LEADERS_TTL) {
    return _nbaPlayoffLeadersCache.data;
  }
  try {
    const cached = localStorage.getItem('field_nba_playoff_leaders');
    if (cached) {
      const p = JSON.parse(cached);
      if (p && p.ts && (now - p.ts) < NBA_PLAYOFF_LEADERS_TTL && p.data) {
        _nbaPlayoffLeadersCache.data = p.data;
        _nbaPlayoffLeadersCache.fetchedAt = p.ts;
        return p.data;
      }
    }
  } catch(_) {}
  if (_nbaPlayoffLeadersCache.inFlight) return _nbaPlayoffLeadersCache.inFlight;
  _nbaPlayoffLeadersCache.inFlight = (async () => {
    try {
      const base = 'https://field-relay-nba.jeffunglesbee.workers.dev/nba-stats/leagueLeaders';
      const q = (cat) => `${base}?LeagueID=00&PerMode=PerGame&Scope=S&Season=2025-26&SeasonType=Playoffs&StatCategory=${cat}`;
      // TOP_N=30 ensures Finals-team coverage even when their stars cluster
      // outside the top 25 in any single category. Stats.nba.com's RANK
      // field uses tie-handling that puts shared ranks at later array indices
      // (e.g. Castle, Harden, McCollum, Thompson all share rank 23 and occupy
      // array indices 22-25). 4-per-team cap in the builder limits final
      // output size regardless.
      const TOP_N = 30;
      const [ptsR, rebR, astR, fg3mR] = await Promise.allSettled([
        fetch(q('PTS'),  { signal: AbortSignal.timeout(7000) }),
        fetch(q('REB'),  { signal: AbortSignal.timeout(7000) }),
        fetch(q('AST'),  { signal: AbortSignal.timeout(7000) }),
        fetch(q('FG3M'), { signal: AbortSignal.timeout(7000) }),
      ]);
      const pickJson = async (r) => (r.status === 'fulfilled' && r.value.ok) ? r.value.json().catch(()=>null) : null;
      const [ptsJ, rebJ, astJ, fg3mJ] = await Promise.all([pickJson(ptsR), pickJson(rebR), pickJson(astR), pickJson(fg3mR)]);
      const ptsArr  = _parseNBALeagueLeaders(ptsJ,  'PTS',  TOP_N);
      const rebArr  = _parseNBALeagueLeaders(rebJ,  'REB',  TOP_N);
      const astArr  = _parseNBALeagueLeaders(astJ,  'AST',  TOP_N);
      const fg3mArr = _parseNBALeagueLeaders(fg3mJ, 'FG3M', TOP_N);
      if (!ptsArr.length && !rebArr.length && !astArr.length && !fg3mArr.length) {
        return _nbaPlayoffLeadersCache.data || {}; // serve stale on full failure
      }
      const data = buildNBAPlayoffLeadersByTeam(ptsArr, rebArr, astArr, fg3mArr);
      _nbaPlayoffLeadersCache.data = data;
      _nbaPlayoffLeadersCache.fetchedAt = Date.now();
      try { localStorage.setItem('field_nba_playoff_leaders', JSON.stringify({ ts: Date.now(), data })); } catch(_) {}
      if (FIELD_DEBUG) console.log('[NBA Playoff Leaders] fetched', Object.keys(data).length, 'teams (FIELD_DEBUG)');
      return data;
    } catch(_e) {
      captureFieldError('nba:playoff-leaders-prefetch', _e, true);
      return _nbaPlayoffLeadersCache.data || {};
    } finally {
      _nbaPlayoffLeadersCache.inFlight = null;
    }
  })();
  return _nbaPlayoffLeadersCache.inFlight;
}

// Sync getter — reads from warm cache. Used by populateSeriesContext.
// Returns array of leader lines (away team first, then home), or null if no
// cache data. ADR-003 attribution is attached by the caller (populateSeriesContext
// sets game._playoffLeadersAttribution = 'NBA.com' alongside the leader lines).
function getNBAPlayoffLeadersForGame(game) {
  if (!game) return null;
  const sport = (_gameSport(game)).toLowerCase();
  if (!sport.includes('nba') && !sport.includes('basketball')) return null;
  const data = _nbaPlayoffLeadersCache.data;
  if (!data) return null;
  const homeAbbr = game._homeAbbr || (typeof getNBAAbbrev === 'function' ? getNBAAbbrev(game.home) : null);
  const awayAbbr = game._awayAbbr || (typeof getNBAAbbrev === 'function' ? getNBAAbbrev(game.away) : null);
  const lines = [];
  if (awayAbbr && Array.isArray(data[awayAbbr])) {
    data[awayAbbr].forEach(l => lines.push(`${awayAbbr} ${l}`));
  }
  if (homeAbbr && Array.isArray(data[homeAbbr])) {
    data[homeAbbr].forEach(l => lines.push(`${homeAbbr} ${l}`));
  }
  return lines.length ? lines : null;
}

function nbaPlayoffLeadersPrefetch() {
  try { fetchNBAPlayoffLeaders(); } catch(_) {}
}

// ── ADR-003 attribution guardrail (post-process J3 Brief output) ─────────────
// The prompt-level attribution inlined into the [PLAYOFF STATS:] tag relies on
// the AI preserving the "Stats: NBA.com" credit through banned-phrase chains,
// prose rewrites, and Datamuse freshness scoring. This guardrail catches cases
// where the credit gets dropped: if any NBA game in the slate had NBA leader
// data populated (signalled by game._playoffLeadersAttribution = 'NBA.com'),
// and the rendered brief text doesn't contain 'NBA.com', append a footer.
// Returns briefText unchanged when no NBA attribution is required or when the
// AI already preserved the credit.
function _enforceNBAAttributionFooter(briefText, sections) {
  if (typeof briefText !== 'string' || !briefText) return briefText;
  if (briefText.includes('NBA.com')) return briefText;
  if (!Array.isArray(sections)) return briefText;
  let nbaAttrRequired = false;
  for (let i = 0; i < sections.length && !nbaAttrRequired; i++) {
    const games = Array.isArray(sections[i] && sections[i].games) ? sections[i].games : null;
    if (!games) continue;
    for (let j = 0; j < games.length; j++) {
      if (games[j] && games[j]._playoffLeadersAttribution === 'NBA.com') {
        nbaAttrRequired = true;
        break;
      }
    }
  }
  if (!nbaAttrRequired) return briefText;
  const trimmed = briefText.replace(/\s+$/, '');
  const sep = /[.!?]$/.test(trimmed) ? ' ' : '. ';
  return trimmed + sep + 'Stats: NBA.com';
}

// populateSeriesContext: mutates the game object to fill optional fields read by
// buildSeriesContextTags. Idempotent (won't overwrite pre-populated values).
// Called at the per-game emission step in both J3 paths (standalone + compound).
function populateSeriesContext(game) {
  if (!game || typeof game !== 'object') return;
  try {
    // Subtask 6 — Coaches (STABLE, hardcoded)
    if (!game.coaches) {
      const sport = _gameSport(game);
      const homeCoach = getHeadCoachForTeam(game.home || '', sport);
      const awayCoach = getHeadCoachForTeam(game.away || '', sport);
      if (homeCoach || awayCoach) {
        game.coaches = {};
        if (homeCoach) game.coaches.home = homeCoach;
        if (awayCoach) game.coaches.away = awayCoach;
      }
    }
    // Subtask 7 — Historical anchor (STABLE, hardcoded; championship rounds only)
    if (!game.historical) {
      const anchor = getSeriesHistoricalAnchor(game);
      if (anchor) game.historical = anchor;
    }
    // Subtask 8 — Injuries (ESPN league-wide /injuries feed; NHL + NBA via same source).
    // Replaces the operationally-inert bdlInjuryContextSync pass-through that PM-2
    // wired through populateSeriesContext: BDL_SPORT_MAP has been empty since May 15
    // 2026, so the prior wiring was structurally correct but produced zero data.
    // ESPN's league-wide injuries endpoint is verified, CORS-open, and updates on a
    // 30-minute TTL via fetchESPNInjuries (prefetched at init by espnInjuriesPrefetch).
    if (!Array.isArray(game.injuries) || !game.injuries.length) {
      try {
        if (typeof getESPNInjuriesForGame === 'function') {
          const inj = getESPNInjuriesForGame(game);
          if (inj && inj.length) game.injuries = inj;
        }
      } catch(_) {}
    }
    // Subtask 9 — Playoff Leaders (COUNTERS, feed-driven). NHL via
    // _nhlPlayoffLeadersCache (api-web.nhle.com proxied through field-relay-nba).
    // NBA via _nbaPlayoffLeadersCache (stats.nba.com proxied through
    // field-relay-nba /nba-stats/leagueLeaders; ADR-003 accept-the-risk).
    // ADR-003 attribution: when NBA data populates, also set
    // game._playoffLeadersAttribution = 'NBA.com' so buildSeriesContextTags
    // surfaces the attribution inline in the [PLAYOFF STATS:] tag.
    if (!Array.isArray(game.playoffLeaders) || !game.playoffLeaders.length) {
      try {
        if (typeof getNHLPlayoffLeadersForGame === 'function') {
          const leaders = getNHLPlayoffLeadersForGame(game);
          if (leaders && leaders.length) game.playoffLeaders = leaders;
        }
        if ((!Array.isArray(game.playoffLeaders) || !game.playoffLeaders.length)
            && typeof getNBAPlayoffLeadersForGame === 'function') {
          const nbaLeaders = getNBAPlayoffLeadersForGame(game);
          if (nbaLeaders && nbaLeaders.length) {
            game.playoffLeaders = nbaLeaders;
            game._playoffLeadersAttribution = 'NBA.com'; // ADR-003
          }
        }
      } catch(_) {}
    }
  } catch(_) {}
}

// ── buildSeriesContextTags (Axis 3 Phase A scaffolding, June 1 2026) ──────────
// Emits structured context tags from optional fields on the game object.
// Each field is populated by future Phase B data sources (HANDOFF):
//   game.playoffLeaders : Array<string>  — one leader line per element
//   game.injuries       : Array<string>  — one injury line per element
//   game.coaches        : { home?: string, away?: string }
//   game.historical     : string         — single anchor (e.g. "First Cup Final since 2006")
// When a field is absent the corresponding tag is NOT emitted. Output is a
// "\n"-joined string of tag lines suitable for inclusion in per-game prompt
// blocks (both standalone fetchFIELDBriefFromClaude and compound
// buildCompoundPrompt callers). All tags carry the same "  [TAG: payload]"
// shape as existing context tags (BNI, MILESTONE, EMBER, etc.) so the AI
// reads them through the same channel. DO NOT INVENT: helper never fabricates
// payload content — it is a strict pass-through of provided field values.
function buildSeriesContextTags(game) {
  const lines = [];
  try {
    if (Array.isArray(game.playoffLeaders) && game.playoffLeaders.length) {
      const payload = game.playoffLeaders.filter(Boolean).join('; ');
      if (payload) {
        // ADR-003 attribution: NBA Statistics ToS requires prominent attribution
        // when the data displays. When the data source set an attribution flag
        // (populateSeriesContext sets game._playoffLeadersAttribution = 'NBA.com'
        // for NBA leaders), inline the credit into the tag so it propagates into
        // the AI prompt and the resulting prose.
        const attr = (typeof game._playoffLeadersAttribution === 'string' && game._playoffLeadersAttribution)
          ? ` — Stats: ${game._playoffLeadersAttribution}` : '';
        lines.push('  [PLAYOFF STATS: ' + payload + attr + ']');
      }
    }
    if (Array.isArray(game.injuries) && game.injuries.length) {
      const payload = game.injuries.filter(Boolean).join('; ');
      if (payload) lines.push('  [INJURY: ' + payload + ']');
    }
    if (game.coaches && (game.coaches.home || game.coaches.away)) {
      const parts = [];
      // Use nickname (Hurricanes) not full name (Carolina Hurricanes) — matches
      // HANDOFF acceptance: "[COACH: Hurricanes — Brind'Amour; Golden Knights — Tortorella]"
      const hNick = (typeof teamNick === 'function') ? teamNick(game.home || '') : (game.home || 'home');
      const aNick = (typeof teamNick === 'function') ? teamNick(game.away || '') : (game.away || 'away');
      if (game.coaches.home) parts.push(`${hNick || game.home || 'home'} — ${game.coaches.home}`);
      if (game.coaches.away) parts.push(`${aNick || game.away || 'away'} — ${game.coaches.away}`);
      if (parts.length) lines.push('  [COACH: ' + parts.join('; ') + ']');
    }
    if (typeof game.historical === 'string' && game.historical.trim()) {
      lines.push('  [HISTORICAL: ' + game.historical.trim() + ']');
    }
  } catch(_) {}
  return lines.join('\n');
}

// ── Game Notes Layer (Item 38) ────────────────────────────────────────────────
// Priority stack: P1 manual → P2 official league editorial → P3 structured → P4 RSS
// Replaces ESPN notes dependency entirely. All sources are official, free, CORS-open.
// P1: game.matchupNote / cdwNotes (daily update curation) — return immediately, zero API
// P2A: MLB Stats API game content (milestone > IL transaction > headline)
// P2B: NHL relay landing (gameInfo.gameNight.matchupEditorial.title)
// P3: structured assembly from _relayStandingsCache + _oddsCache + seriesRecord — zero calls
// P4: official league RSS (nba/nhl/mlb/nfl first-party feeds — legally clean)

// P3: assemble note from data FIELD already holds — zero API calls
function assembleNoteFromContext(game){
  const parts=[];
  const sport=_gameSport(game);
  if(game.seriesRecord) parts.push(game.seriesRecord);
  return parts.length?parts.join(' \u00b7 '):null;
}

// P2A: MLB editorial + IL transactions
async function fetchMLBGameNotes(gamePk,game){
  if(!gamePk) return null;
  try{
    const [cR,tR]=await Promise.allSettled([
      fetch(`${MLB_STATS_BASE}/game/${gamePk}/content`,{signal:AbortSignal.timeout(4000)}),
      fetch(`${MLB_STATS_BASE}/transactions?sportId=1&date=${TODAY_ISO}`,{signal:AbortSignal.timeout(4000)}),
    ]);
    const content=cR.status==='fulfilled'&&cR.value.ok?await cR.value.json():null;
    const milestone=content?.media?.milestones?.items?.[0]?.description;
    if(milestone) return milestone.slice(0,150);
    if(tR.status==='fulfilled'&&tR.value.ok){
      const td=await tR.value.json();
      const hn=teamNick(game?.home)||'';
      const an=teamNick(game?.away)||'';
      const tx=(td.transactions||[]).find(t=>
        t.typeCode==='DL'&&
        (t.team?.name?.includes(hn)||t.team?.name?.includes(an))
      );
      if(tx) return `${tx.player?.fullName||'Player'} placed on IL (${tx.description||'injury'})`;
    }
    const headline=content?.editorial?.preview?.articles?.home?.headline;
    return headline?headline.slice(0,150):null;
  }catch(e){ captureFieldError('gamenotes:mlb', e, true); return null; }
}

// P2B: NHL relay landing
async function fetchNHLGameNotes(gameId){
  if(!gameId) return null;
  try{
    const r=await fetch(`${NHL_RELAY_BASE}/v1/gamecenter/${gameId}/landing`,{signal:AbortSignal.timeout(4000)});
    if(!r.ok) return null;
    const d=await r.json();
    return (d.gameInfo?.gameNight?.matchupEditorial?.title||'').slice(0,150)||null;
  }catch(e){ captureFieldError('gamenotes:nhl', e, true); return null; }
}

// P4: official first-party league RSS routed through relay (direct browser fetch blocked by CORS)
const LEAGUE_RSS={
  'Basketball':'https://www.nba.com/feeds/rss/nba_articles.rss',
  'Hockey':    'https://www.nhl.com/news/rss.xml',
  'Baseball':  'https://www.mlb.com/feeds/news/rss.xml',
  'Football':  'https://www.nfl.com/feeds/rss/news.rss',
};
async function fetchLeagueRSS(sport,home,away){
  const feedUrl=Object.entries(LEAGUE_RSS).find(([k])=>sport.includes(k))?.[1];
  if(!feedUrl) return null;
  try{
    // Route through relay to bypass CORS — direct browser fetch to mlb.com/nhl.com blocked
    const relayUrl=`${_MLB_RELAY}/rss-proxy?url=${encodeURIComponent(feedUrl)}`;
    const r=await fetch(relayUrl,{signal:AbortSignal.timeout(4000)});
    if(!r.ok) return null;
    const doc=new DOMParser().parseFromString(await r.text(),'text/xml');
    const cutoff=Date.now()-86400000;
    const h=teamNick(home).toLowerCase();
    const a=teamNick(away).toLowerCase();
    for(const item of doc.querySelectorAll('item')){
      const title=item.querySelector('title')?.textContent||'';
      const pub=new Date(item.querySelector('pubDate')?.textContent||0).getTime();
      if(pub<cutoff) continue;
      if(title.toLowerCase().includes(h)||title.toLowerCase().includes(a))
        return title.slice(0,150);
    }
    return null;
  }catch(e){ captureFieldError('journalism:league-rss', e, true); return null; }
}

// Master dispatcher — P1→P2→P3→P4
async function fetchGameNotes(game){
  const sport=_gameSport(game);
  // P1: manual curation — return immediately, no API
  if(game.matchupNote) return game.matchupNote;
  // Cache check
  const cKey='field_game_notes_'+(game._id||`${game.home}_${game.away}`);
  try{const cached=localStorage.getItem(cKey);if(cached) return cached;}catch(e){}
  let note=null;
  // P2: official league editorial
  if((sport.includes('Baseball')||sport.includes('MLB'))&&game.sourceId){
    note=await fetchMLBGameNotes(game.sourceId,game);
  } else if((sport.includes('Hockey')||sport.includes('NHL'))&&game._nhlGameId){
    note=await fetchNHLGameNotes(game._nhlGameId);
  } else if(sport.includes('Basketball')||sport.includes('NBA')){
    // P2C: BDL milestone note — "SGA needs 2 more pts to reach 2500"
    const ms=await fetchBDLMilestones(game);
    if(ms) note=`${ms.playerName} needs ${ms.gap} more ${ms.stat} to reach ${ms.next}`;
  }
  // P3: structured assembly (any sport, zero API)
  if(!note) note=assembleNoteFromContext(game);
  // P4: official league RSS fallback
  if(!note&&game.home&&game.away) note=await fetchLeagueRSS(sport,game.home,game.away);
  try{if(note) localStorage.setItem(cKey,note);}catch(e){}
  return note;
}

// ── F09: REST Countries — country context for WC game briefs ─────────────
// Free, no auth, CORS open. Populates an in-memory cache per session so
// each country is fetched at most once. Used by the WC team context block
// in fetchNightOwlFromClaude to inject "[COUNTRY: Paraguay] Population
// 7.4M, capital Asunción, FIFA code PAR, South America" into the recap
// prompt alongside WC_TEAM_CONTEXT narratives.
//
// API spec: docs/F09 — restcountries.com/v3.1/name/{name}?fields=...
// Country context is enhancement; any error returns null silently so
// the recap still ships without it.
const _countryCtxCache = new Map();
// Edge cases where the team name doesn't match restcountries.com's primary
// name. For everything else (the vast majority), pass the team name as-is.
const WC_COUNTRY_API_NAME = {
  'USA': 'United States',
  'South Korea': 'Korea',
  'Türkiye': 'Turkey',
  'DR Congo': 'Congo',
  'Ivory Coast': "Côte d'Ivoire",
};
function _fmtCountryPop(n) {
  if (n == null || !isFinite(n)) return null;
  if (n >= 1000000) return (n / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
  if (n >= 1000)    return (n / 1000).toFixed(1).replace(/\.0$/, '')   + 'K';
  return String(n);
}
async function fetchCountryContext(countryName) {
  if (!countryName) return null;
  if (_countryCtxCache.has(countryName)) return _countryCtxCache.get(countryName);
  const apiName = WC_COUNTRY_API_NAME[countryName] || countryName;
  try {
    const url = `https://restcountries.com/v3.1/name/${encodeURIComponent(apiName)}?fields=name,population,capital,fifa,region,subregion`;
    const r = await fetch(url, { signal: AbortSignal.timeout(5000) });
    if (!r.ok) { _countryCtxCache.set(countryName, null); return null; }
    const arr = await r.json();
    const c = Array.isArray(arr) ? arr[0] : null;
    if (!c) { _countryCtxCache.set(countryName, null); return null; }
    const ctx = {
      population: _fmtCountryPop(c.population),
      capital:    Array.isArray(c.capital) ? c.capital[0] : (c.capital || null),
      fifaCode:   c.fifa || null,
      region:     c.subregion || c.region || null,
    };
    _countryCtxCache.set(countryName, ctx);
    return ctx;
  } catch(_e) {
    captureFieldError('wc:country-context', _e, true);
    _countryCtxCache.set(countryName, null);
    return null;
  }
}


// ── buildGameContext(g) — assembled signal object (ROOT 2) ───────────────────
// One function, pre-assembles ALL context signals for a game.
// Shared by: preGameScore drama_bb (already wired), J3 momentum briefs,
// assembleNoteFromContext, EMBER context boost, OTW why-line.
// Called once per game per render cycle — consumers read from the returned object.
function buildGameContext(g) {
  const gid = g._id || `${g.home}_${g.away}`;
  const sport = _gameSport(g);

  // Drama trend from history (positive = rising, negative = cooling)
  let dramaTrend = 0;
  try { dramaTrend = getDramaTrend(gid) ?? 0; } catch(e_) {}

  // Standings gap from _relayStandingsCache
  let standingsGap = null;
  try {
    const standings = _relayStandingsCache?.[sport];
    if (standings?.length) {
      const hSlug = teamNick(g.home).toLowerCase();
      const aSlug = teamNick(g.away).toLowerCase();
      const hTeam = standings.find(t => (t.team||'').toLowerCase().includes(hSlug));
      const aTeam = standings.find(t => (t.team||'').toLowerCase().includes(aSlug));
      if (hTeam && aTeam) {
        const hGB = parseFloat(hTeam.gb)||0, aGB = parseFloat(aTeam.gb)||0;
        standingsGap = Math.abs(hGB - aGB);
      }
    }
  } catch(e_) {}

  // Milestone from BDL cache
  const milestone = _bdlMilestonesCache?.[gid] || null;

  // Live smoothed drama score (if available)
  let liveDrama = null;
  try { liveDrama = getSmoothedDrama(gid); } catch(e_) {}

  return { gid, sport, dramaTrend, standingsGap, milestone, liveDrama };
}

// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #8): the sole
// caller (initFIELDBrief) used to show the SAME user-facing "verification
// chain failed" card for every null cause here -- proof-mode, budget
// exhaustion, a night with no ranked games, deliberate suppression, a
// real HTTP failure, or a thrown exception, 6 causes, one alarming
// message. Migrated the return contract from `string|null` to
// `{ok:true,text}` / `{ok:false,reason}` so the caller can tell
// intentional/expected states (which should silently leave the existing
// static brief text alone) from genuine failures (which should still show
// the verification-chain-failed card, unchanged). Exactly 1 real caller,
// updated in the same commit.
async function fetchFIELDBriefFromClaude(sections){
  if (_proofMode) return {ok:false, reason:'proof-mode'}; // proof mode: no AI calls
  const budget=journalismCallsToday();
  // J3 brief is served from relay KV (no Gemini call); compound 429 backoff must not gate it.
  // Hard ceiling only — read the counter directly, bypassing canCall() backoff bleed.
  const _jCount = parseInt(sessionStorage.getItem('field_j_calls_'+fieldDateKey(new Date()))||'0');
  if (_jCount >= 50) return {ok:false, reason:'budget-exhausted'};
  // Pre-fetch standings from relay/API sources (MLB Stats API, NBA relay, NHL relay — not ESPN)
  await Promise.allSettled(sections.slice(0, 5).map(s => fetchStandingsForPrompt(s.sport)));
  const all=sections.flatMap(s=>(s.games||[]).map(g=>({...g,_section:s.sport})));
  const ranked=all.filter(g=>g.home&&g.away&&g.home!=='ATP/WTA Field').sort((a,b)=>preGameScore(b)-preGameScore(a)).slice(0,8);
  if(!ranked.length) return {ok:false, reason:'no-ranked-games'};
  // Big-game flag: Conference Finals and above get doubled brief length.
  // Mirrors the compound path (line ~17293) so standalone J3 gets the same
  // editorial depth treatment when Conference Finals / Cup / NBA Finals are on
  // the slate. Pre-fix: this path hardcoded 100-120w regardless of stakes.
  const isBigGameJ3 = ranked.some(g =>
    /conference finals|cf g\d|nba finals|stanley cup final|wcf|ecf/i.test(g.league||'')
  );
  const briefWordsJ3 = isBigGameJ3
    ? '200-240 words. 3-4 paragraphs. No headers.'
    : '100-120 words. 2 short paragraphs. No headers.';
  // Brief suppression: skip Claude if top live game is cooling + late period (decided)
  // Saves journalism tokens on games that are already over narratively.
  try {
    const top = ranked[0];
    const topCtx = buildGameContext(top);
    if (topCtx.liveDrama != null && topCtx.liveDrama < 20 && topCtx.dramaTrend < -8) {
      const sport = (top._section||'').toLowerCase();
      const topEData = Object.values(espnScores||{}).find(e =>
        (e.homeName||'').toLowerCase().includes(teamNick(top.home).toLowerCase()));
      const period = topEData?.period || 0;
      const isLate = sport.includes('basketball') ? period >= 4
                   : sport.includes('hockey')     ? period >= 3
                   : sport.includes('baseball')   ? period >= 8 : false;
      if (isLate) {
        if (FIELD_DEBUG) console.log('[J3] suppressed — top game cooling in final period');
        return {ok:false, reason:'suppressed'};
      }
    }
  } catch(e_) {}
  // Pre-fetch game notes in parallel — P1 matchupNote → P2 league editorial → P3 structured → P4 RSS
  const noteResults=await Promise.allSettled(ranked.map(g=>fetchGameNotes(g)));
  const notes=noteResults.map(r=>r.status==='fulfilled'?r.value:null);
  const gameLines=ranked.map((g,i)=>{
    const stream=gameNetwork(g, 'local');
    const free=g.streams&&g.streams[0]&&new Set(['ABC','NBC','CBS','FOX','ION']).has(g.streams[0].label);
    const standingsCtx = buildGameStandingsContext(g);
    const crewCtx = getCrewContext(g);
    // PF-5: pre-format start time so the LLM never has to interpret raw ISO
    // dates like "2026-06-03T00:00:00Z" (which became "tips at 6/3" in May 31
    // screenshot). Format as "Sun May 31, 8:00 PM ET".
    const startLine = (() => {
      try {
        if (!g.start_time) return '';
        const d = new Date(g.start_time);
        const tz = selectedTz === 'local' ? localTz() : selectedTz;
        const tzLabel = (tz === 'America/New_York' || tz === 'local') ? 'ET' :
                        (tz === 'America/Los_Angeles') ? 'PT' :
                        (tz === 'America/Chicago') ? 'CT' :
                        (tz === 'America/Denver') ? 'MT' : tz.split('/').pop();
        const datePart = d.toLocaleDateString('en-US', { timeZone: tz === 'local' ? localTz() : tz, weekday: 'short', month: 'short', day: 'numeric' });
        const timePart = d.toLocaleTimeString('en-US', { timeZone: tz === 'local' ? localTz() : tz, hour: 'numeric', minute: '2-digit', hour12: true });
        return `  Start: ${datePart}, ${timePart} ${tzLabel}`;
      } catch(_) { return ''; }
    })();
    return ['- '+g.away+' @ '+g.home,
      g.seriesRecord?'  Series: '+g.seriesRecord:'',
      startLine,
      '  Network: '+stream+(free?' (FREE OTA)':''),
      crewCtx?'  Crew: '+crewCtx+(isMarqueeBroadcast(g)?' (marquee)':''):'',
      notes[i]&&!g.matchupNote?'  Context: '+notes[i]:'',
      g.matchupNote?'  Matchup: '+g.matchupNote:'',
      g._section?'  Sport: '+g._section:'',
      standingsCtx?'  '+standingsCtx:'',
      isScoutsPick(g)?"  [SCOUT'S PICK]":'',
      isNationalGame(g)&&isBigMarketGame(g)&&preGameScore(g)<35?'  [ANTI-HYPE]':'',
      (()=>{const b=computeBroadcastNarrativeIndex(g);return b?'  [BNI: '+b.replace(/-/g,' ').toUpperCase()+']':'';})()
,
      // ROOT 2: momentum + milestone context from buildGameContext()
      (()=>{
        try {
          const ctx = buildGameContext(g);
          const lines = [];
          if (ctx.dramaTrend > 10)  lines.push('  [DRAMA: RISING — game tightening]');
          if (ctx.dramaTrend < -10) lines.push('  [DRAMA: COOLING — pulling away]');
          if (ctx.milestone)        lines.push(`  [MILESTONE: ${ctx.milestone.playerName} needs ${ctx.milestone.gap} ${ctx.milestone.stat} for ${ctx.milestone.next}]`);
          if (ctx.standingsGap != null && ctx.standingsGap <= 2) lines.push('  [STANDINGS: teams within 2 games]');
          return lines.join('\n');
        } catch(e_) { return ''; }
      })(),
      // Axis 3 Phase B: populate coaches/historical/injuries on game obj before
      // tag emission. Same helper as standalone path — single source of truth.
      (()=>{try{populateSeriesContext(g)}catch(e_){}})(),
      // Axis 3 Phase A: structured series-context tags from optional fields
      // (playoffLeaders / injuries / coaches / historical). Same helper used
      // by buildCompoundPrompt; populated by populateSeriesContext above
      // (subtasks 6/7/8); playoff leaders await subtask 9 feed wiring.
      buildSeriesContextTags(g)
    ].filter(Boolean).join('\n');
  }).join('\n\n');
  // PF-5: TONIGHT anchor — gives the LLM a clear today-reference so it
  // never has to infer the current date from message context.
  const _todayAnchor = (() => {
    try {
      const now = new Date();
      const tz = selectedTz === 'local' ? localTz() : selectedTz;
      return now.toLocaleDateString('en-US', { timeZone: tz === 'local' ? localTz() : tz, weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });
    } catch(_) { return ''; }
  })();
  const prompt=[FIELD_VOICE_EXEMPLARS,"Write a FIELD Brief for tonight's sports slate.",'',_todayAnchor?`TODAY: ${_todayAnchor}.`:'',_todayAnchor?'':'','TONIGHT\'S GAMES:',gameLines,'','RULES:',`- ${briefWordsJ3}`,'- STRUCTURE: Paragraph 1 opens on the highest-stakes game with the specific situation (not the team name). Paragraph 2 covers the rest of the slate in order of importance. End on what carries forward.','- Lead with the specific situation, not the team. "48 minutes from their first Finals since 1999" not "The Knicks are looking to advance."','- Call out FREE over-the-air games explicitly.',"- Surface Scout's Pick if flagged.",'- If [ANTI-HYPE] appears in a game line, describe that matchup as low-stakes in plain prose — never echo the tag [ANTI-HYPE] verbatim.','- CORRECTNESS: write only from data above. Never invent scores, stats, records, or player tendencies.',
  // PF-5 + PF-7: explicit date-format and player-stat rules
  '- DATES: when referring to a game, use the "Start:" line value verbatim. Do not write fractions like "6/3" — write "June 2" or "Tuesday" or "tonight". Never invent or reformat dates.',
  '- PLAYER STATS: only cite a player stat number when it explicitly appears in context (e.g. "[MILESTONE: X needs 5 points for 1000]"). If a player is named without a stat, mention them by name but do NOT attach a fabricated number ("Dorofeyev leads the line" not "Dorofeyev posting 37"). Never invent goal totals, point totals, ERA, BA, etc.',
  '- SLATE BOUNDARY (mandatory): every league or sport you reference must appear in TONIGHT\'S GAMES above. If the Premier League, La Liga, Serie A, Ligue 1, Bundesliga, MLS, or any other league has no game in tonight\'s slate, DO NOT mention it, recap it, or include any result from it. Saying "In England, Man United routed Brighton 3-0" is FABRICATION when no EPL game is in the slate. The brief covers ONLY what is on tonight\'s slate.',
  FIELD_PROSE_STYLE,'- VOICE: third person only. Never use "you" or address the reader directly. Write like a columnist, not a chatbot.','- DIVISION ACCURACY: teams in the same division share ONE division race — never say "respective division races" for same-division teams. NHL has Atlantic/Metropolitan/Central/Pacific. NBA has Atlantic/Central/Southeast/Northwest/Pacific/Southwest. MLB has AL/NL East/Central/West.','- Plain prose only. No bullet points.','- Always complete every sentence. Never end mid-sentence.'].filter(Boolean).join('\n');
  try{
    // ── WOW 6 Phase 2: route through relay quality gate (multi-sport slate)
    const _viaRelay = await generateJournalismViaRelay(prompt, {
      sport: null, briefType: 'j3-brief', max_tokens: 1500,
    });
    if (_viaRelay && _viaRelay.length > 30) {
      budget.inc();
      scoreProse(_viaRelay, null).then(s=>renderProseScore(s,'J3 Brief'));
      return {ok:true, text: _viaRelay.replace(/\[ANTI-HYPE\]/gi,'').replace(/\s{2,}/g,' ').trim()};
    }
    // Fallback: legacy direct-proxy path
    const r=await fetch(CLAUDE_PROXY_URL,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:1500,messages:[{role:'user',content:prompt}]})});
    if(!r.ok) return {ok:false, reason:'http-failure'};
    const data=await r.json();
    let text=(data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('');
    if(text&&text.length>50){
      text=await retryWithoutCliches(prompt,text,CLAUDE_PROXY_URL);budget.inc();
      text=await retryWithoutWireCopy(prompt,text,CLAUDE_PROXY_URL);
      text=await retryWithoutNarrativeHallucination(prompt,text,CLAUDE_PROXY_URL,{seriesRecord:'',isGame1:false}); // J3 is multi-game slate — strictest pattern set is appropriate
      text=await checkLeadSentence(prompt,text,CLAUDE_PROXY_URL);
      text=await checkStatVerification(prompt,text,CLAUDE_PROXY_URL);
      text=await checkCrossSport(prompt,text,CLAUDE_PROXY_URL);
      text=await maybeScoreRetry(prompt,text,CLAUDE_PROXY_URL,'J3 Brief');
      scoreProse(text, null).then(s=>renderProseScore(s,'J3 Brief'));
      return {ok:true, text: text.replace(/\[ANTI-HYPE\]/gi,'').replace(/\s{2,}/g,' ').trim()};
    }
    // Fell through: text came back but didn't clear the length bar -- a
    // quality issue, not an infra failure. Was an implicit fallthrough to
    // the function's own final `return null;`; now explicit.
    return {ok:false, reason:'quality-too-short'};
  }catch(e){
    if(FIELD_DEBUG)console.error('[J3 FIELD Brief] proxy error:',e.message);
    return {ok:false, reason:'exception'};
  }
}

// ── My Teams Brief Line ───────────────────────────────────────────────────────
// Compact personalised "your teams tonight" line above J3 brief.
// DO NOT INVENT: only uses MY_TEAMS set + game data from allData.
function buildMyTeamsBriefLine(sections) {
  if (!MY_TEAMS || MY_TEAMS.size===0) return null;
  const myGames = (sections||[]).flatMap(s=>
    (s.games||[]).filter(g=>MY_TEAMS.has(g.home)||MY_TEAMS.has(g.away)).map(g=>({g,sport:s.sport}))
  );
  if (!myGames.length) return null;
  return myGames.slice(0,4).map(({g})=>{
    const myTeam = MY_TEAMS.has(g.home)?g.home:g.away;
    const opp   = MY_TEAMS.has(g.home)?g.away:g.home;
    const sr    = g.seriesRecord&&g.seriesRecord!=='0-0'?' ('+g.seriesRecord+')':'';
    const net   = gameNetwork(g);
    return (teamNick(myTeam))+' vs '+(teamNick(opp))+sr+' '+fmtTime(g.start_time)+(net?' · '+net:'');
  }).join(' | ');
}

async function initFIELDBrief(sections){
  const tz = localTz();
  const el=(_DOM?.fieldBrief||document.getElementById('field-brief'));
  if(!el) return;
  if(!sections.length){el.style.display='none';return;}
  // #field-brief and #night-owl are now separate elements — no slot-contention guard needed.
  // Night Owl renders into #night-owl; FIELD Brief renders into #field-brief independently.
  const d=new Date();const tzStr=(typeof tz==='string'?tz:'America/New_York');
  const dateLabel=d.toLocaleDateString('en-US',{timeZone:tzStr,weekday:'short',month:'short',day:'numeric'});
  const cacheKey=fieldBriefCacheKey();
  const cached=sessionStorage.getItem(cacheKey);
  el.style.display='block';
  const stateBadge=s=>s==='cached'?'<span class="brief-state-badge">○</span>':s==='updating'?'<span class="brief-state-badge updating">⟳</span>':'';
  const mkCard=(text,loaded,state)=>`<div class="field-brief-card" id="field-brief-inner"><div class="field-brief-header"><span class="field-brief-label">FIELD Brief</span><span class="field-brief-date">${dateLabel}</span>${stateBadge(state)}</div><div class="field-brief-text${loaded?'':' pending'}">${text}</div></div>`;
  if(cached){
    el.innerHTML=mkCard(trimToCompleteSentence(cached),true,'cached');
    document.getElementById('field-brief-inner')?.addEventListener('click',()=>getEl('field-brief-inner')?.classList.toggle('collapsed'));
    // Restore game_briefs from compound cache even on brief-text cache hit
    try{
      const compoundKey=buildCompoundCacheKey(sections);
      const compoundCached=sessionStorage.getItem(compoundKey);
      if(compoundCached){
        const c=JSON.parse(compoundCached);
        if(c.game_briefs?.length) c.game_briefs.forEach(b=>{
          if(!b?.brief||!b?.id) return;
          const slug=b.id.toLowerCase();
          (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
            if(!g._id) return;
            const h=(g.home||'').toLowerCase().replace(/\s+/g,'_');
            const a=(g.away||'').toLowerCase().replace(/\s+/g,'_');
            const _lp=slug.split('_').filter(Boolean).pop()||''; // guard: never match empty string
            if(_lp&&(slug.includes(h.slice(-6))||slug.includes(a.slice(-6))||h.includes(slug.split('_')[0])||a.includes(_lp)))
              _gameBriefCache[g._id]=trimToCompleteSentence(b.brief);
          }));
        });
      }
    }catch(e_){
    if(typeof window._fieldErrors !== 'undefined') window._fieldErrors.push({fn:'initFIELDBrief',err:e_?.message||String(e_),ts:Date.now()});}
    scheduleFieldDesk(400); // Cached-brief path: Desk was never triggered on reload
    setTimeout(renderJournalism, 400);
    return;
  }
  const staticText=buildFIELDBriefStatic(sections)||'Loading tonight\'s brief\u2026';
  const myTeamsLine=buildMyTeamsBriefLine(sections);
  if(myTeamsLine){const mtEl=document.getElementById('my-teams-brief-line')||(()=>{const d=document.createElement('div');d.id='my-teams-brief-line';d.style.cssText='font-size:.68rem;color:var(--gold2,#c9a84c);padding:.35rem 1rem .1rem;max-width:1200px;margin:0 auto;opacity:.85';el.insertAdjacentElement('beforebegin',d);return d;})();mtEl.textContent='★ Your teams: '+myTeamsLine;}
  el.innerHTML=mkCard(staticText,false,'');
  document.getElementById('field-brief-inner')?.addEventListener('click',()=>getEl('field-brief-inner')?.classList.toggle('collapsed'));

  // Pre-fetch standings so buildCompoundPrompt has relay data available
  await Promise.allSettled(sections.slice(0, 5).map(s => fetchStandingsForPrompt(s.sport)));

  // ── Layer 2: try relay pre-rendered prose first (O(1) Newspaper) ────────────
  const relayJournalism = await fetchPrerenderedJournalism();
  if (relayJournalism?.brief) {
    const textEl = el.querySelector('.field-brief-text');
    if (textEl) { textEl.textContent = _enforceNBAAttributionFooter(trimToCompleteSentence(stripMarkdown(relayJournalism.brief)), sections); textEl.classList.remove('pending'); textEl.classList.add('loaded'); }
    sessionStorage.setItem(cacheKey, relayJournalism.brief);
    try { archiveBrief('slate', null, null, relayJournalism.brief, null); } catch(_){}
    if (FIELD_DEBUG) console.log('[O(1)] Brief served from relay KV — no AI call');
    if (typeof renderAmbientPanel === 'function') setTimeout(renderAmbientPanel, 50);
    scheduleFieldDesk(300); // Relay path: Desk was never triggered here
    setTimeout(renderJournalism, 300);
    // Still try compound for series/game_briefs (non-brief fields) — but respect delta
    const currentHash = buildJournalismContextHash(sections);
    if (currentHash === _lastJournalismHash) {
      if (FIELD_DEBUG) console.log('[L3 Delta] Context unchanged — skipping compound editorial');
      return;
    }
    _lastJournalismHash = currentHash;
  }

  // ── Layer 3: delta check before client AI call ───────────────────────────────
  // FIX (May 29 2026): Only skip compound if relay SUCCESSFULLY served a brief.
  // When relay fails (KV placeholders, 503, etc.) compound must always run —
  // previous condition blocked client AI after any successful compound call even
  // when subsequent loads had no relay brief, causing journalism to go silent.
  const currentHash = buildJournalismContextHash(sections);
  if (relayJournalism?.brief && currentHash === _lastJournalismHash) {
    if (FIELD_DEBUG) console.log('[L3 Delta] Relay brief fresh + context unchanged — skipping compound');
    return;
  }
  _lastJournalismHash = currentHash;

  // Compound editorial call: 1 RPM covers all journalism pieces
  const compound=await fetchCompoundEditorial(sections);
  if(compound){
    if(compound.brief){
      const textEl=el.querySelector('.field-brief-text');
      if(textEl){textEl.textContent=_enforceNBAAttributionFooter(trimToCompleteSentence(compound.brief), sections);textEl.classList.remove('pending');textEl.classList.add('loaded');}
      sessionStorage.setItem(cacheKey,compound.brief);
      try { archiveBrief('slate', null, null, compound.brief, null); } catch(_){}
      // Brief content just resolved — re-render ambient panel so iPad editorial section shows it
      if(typeof renderAmbientPanel==='function') setTimeout(renderAmbientPanel, 50);
    }
    // Dispatch series previews from compound result
    if(compound.series?.length){
      compound.series.forEach(s=>{
        if(!s?.preview) return;
        const card=[...document.querySelectorAll('.game-card')].find(c=>{
          const h=(c.dataset.home||'').toLowerCase().replace(/\s+/g,'_');
          const a=(c.dataset.away||'').toLowerCase().replace(/\s+/g,'_');
          return s.id&&(s.id.toLowerCase().includes(h)||s.id.toLowerCase().includes(a));
        });
        // ADR-003: series preview can contain NBA leader data because the
        // compound prompt includes [PLAYOFF STATS:] for series-context games.
        if(card) injectSeriesPreviewText(card,_enforceNBAAttributionFooter(s.preview, sections));
      });
    }
    // Fix 2: Dispatch scouts_pick and bni_note as brief footer notes
    const briefInner=el.querySelector('#field-brief-inner');
    if(briefInner){
      if(compound.scouts_pick){
        let scoutEl=briefInner.querySelector('.brief-scout-note');
        if(!scoutEl){scoutEl=document.createElement('div');scoutEl.className='brief-scout-note';briefInner.appendChild(scoutEl);}
        // ADR-003: scouts_pick may name an NBA Finals game with leader stats.
        scoutEl.textContent='\uD83D\uDD0D Scout\u2019s Pick: '+_enforceNBAAttributionFooter(trimToCompleteSentence(compound.scouts_pick), sections);
      }
      if(compound.bni_note){
        let bniEl=briefInner.querySelector('.brief-bni-note');
        if(!bniEl){bniEl=document.createElement('div');bniEl.className='brief-bni-note';briefInner.appendChild(bniEl);}
        bniEl.textContent='\u26A0\uFE0F '+trimToCompleteSentence(compound.bni_note);
      }
    }
    // Fix 3: Dispatch EPL briefs from compound result — skips individual fetchEPLMatchBriefFromClaude calls
    if(compound.epl?.length){
      compound.epl.forEach(e=>{
        if(!e?.brief) return;
        const briefCard=[...document.querySelectorAll('.epl-match-brief-card')].find(c=>{
          const cid=(c.dataset.gameid||'').toLowerCase();
          return e.id&&(e.id.includes(cid)||cid.includes(e.id.split('_')[0]));
        });
        if(briefCard){
          const textEl=briefCard.querySelector('.epl-brief-text');
          if(textEl&&!textEl.classList.contains('loaded')){
            textEl.textContent=trimToCompleteSentence(e.brief);
            textEl.classList.remove('pending');
            textEl.classList.add('loaded');
          }
        }
      });
    }
    // Fix 4: Dispatch game_briefs — with sport vocab check before caching
    if(compound.game_briefs?.length){
      compound.game_briefs.forEach(b=>{
        if(!b?.brief||!b?.id) return;
        const slug = b.id.toLowerCase();
        (allData?.sports||[]).forEach(sec=>{
          (sec.games||[]).forEach(g=>{
            if(!g._id) return;
            const h=(g.home||'').toLowerCase().replace(/\s+/g,'_');
            const a=(g.away||'').toLowerCase().replace(/\s+/g,'_');
            const _lp2=slug.split('_').filter(Boolean).pop()||'';
            if(_lp2&&(slug.includes(h.slice(-6))||slug.includes(a.slice(-6))||h.includes(slug.split('_')[0])||a.includes(_lp2))){
              // Tier 2B: check sport vocab before caching game brief
              const _gbSp=_gameSport(g);
              const _gbViol=(typeof checkSportVocab==='function')?checkSportVocab(b.brief,_gbSp):[];
              if(_gbViol.length&&FIELD_DEBUG) console.warn('[JQ T2B] game_brief sport vocab:',_gbViol,'for',g._id);
              // ADR-003: per-game brief uses single-game scope so attribution
              // only fires when THIS specific game has the NBA flag set.
              _gameBriefCache[g._id]=_enforceNBAAttributionFooter(trimToCompleteSentence(b.brief), [{games:[g]}]);
            }
          });
        });
      });
    }
    // J6: SMT note — inject editorial line into Sports Media Today section
    if(compound.smt_note){
      const smtBar=document.getElementById('smt-note-bar');
      if(smtBar){smtBar.textContent='📋 '+trimToCompleteSentence(compound.smt_note);smtBar.style.display='block';}
    }
    // FIELD Desk: refresh after compound dispatch so it has all briefs available
    scheduleFieldDesk(200);
    setTimeout(renderJournalism, 200);
    return;
  }

  // Compound null (429 / parse fail): individual brief + temporal spread for series
  const briefResult=await fetchFIELDBriefFromClaude(sections);
  if(briefResult.ok){
    const claudeText=briefResult.text;
    const textEl=el.querySelector('.field-brief-text');
    if(textEl){textEl.textContent=_enforceNBAAttributionFooter(trimToCompleteSentence(claudeText), sections);textEl.classList.remove('pending');textEl.classList.add('loaded');}
    sessionStorage.setItem(cacheKey,claudeText);
    try { archiveBrief('slate', null, null, claudeText, null); } catch(_){}
    // FIELD Desk: must be triggered here too — compound null path never called renderFieldDesk
    scheduleFieldDesk(300);
    setTimeout(renderJournalism, 300);
  } else if (briefResult.reason==='proof-mode' || briefResult.reason==='budget-exhausted' || briefResult.reason==='no-ranked-games' || briefResult.reason==='suppressed') {
    // 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #8): intentional
    // or expected states, not failures -- a deliberate proof-mode test
    // skip, today's AI budget already spent, no ranked games tonight, or a
    // decided game deliberately suppressed. Leave the static brief text
    // (buildFIELDBriefStatic, already rendered into el before this call)
    // as-is. Showing "FIELD's verification chain didn't pass" when nothing
    // actually failed was actively misleading -- this was the queue's
    // core finding for this function.
  } else {
    // Genuine failure (http-failure / quality-too-short / exception) --
    // same brand-safe fallback card as before this migration, unchanged.
    // ── JQ Gate brand-safe fallback (PM-31-JQ) ──────────────────────────────
    // All three journalism paths failed (relay KV → compound editorial →
    // fetchFIELDBriefFromClaude). FIELD never fills silence with stale generic
    // prose — the failure mode is itself brand-defining.
    // Renders a fixed editorial attribution card. No AI text. No silence.
    // "We don't write what we can't verify." — Jun 5 2026 UI spec.
    const textEl=el.querySelector('.field-brief-text');
    if(textEl){
      const _jqAudit=window._lastJQAudit;
      const _retries=_jqAudit?.retries!=null?_jqAudit.retries:6;
      const _layer=_jqAudit?.layers_fired?.slice(-1)[0]||'2g';
      textEl.textContent='Tonight\'s narrative is unsettled. Series context and player-availability signals didn\'t pass FIELD\'s verification chain on time. We don\'t write what we can\'t verify.';
      textEl.classList.remove('pending');
      textEl.classList.add('loaded','jq-fallback');
      // Attribution line — surfaces the quality chain failure transparently
      const _attr=document.createElement('div');
      _attr.className='field-brief-attribution';
      _attr.textContent=`— FIELD editorial · JQ chain ${_retries}/6 retries · ${_layer} escalation`;
      textEl.after(_attr);
    }
  }
  // FIELD Desk: also refresh after series queue fires (series cards populated ~3s later)
  setTimeout(()=>{initJournalismQueue(sections);scheduleFieldDesk(500);setTimeout(renderJournalism,500);},3000);
// Re-inject scores on renderAll completion — catches cards rendered after initial ESPN poll
// Fixes: Galaxy A36 blank scores when ESPN data was already fetched before render
if(Object.keys(espnScores||{}).length){
  try { injectDramaBadges(); } catch(e_) {}
}

}



// ═══════════════════════════════════════════════════════════════════════════
// EPL MATCH BRIEFS — FIELD Brief card above each Premier League game
// Parallel to Series Preview (J2) but for league fixtures, not playoff series.
// Uses matchweek + stream context for static brief; Gemini for editorial.
// ═══════════════════════════════════════════════════════════════════════════

function buildEPLMatchBriefStatic(g) {
  const mw = parseMatchweek(g.league);
  const stream = gameNetwork(g);
  const streamNote = stream ? ` Available on ${stream}.` : '';
  const league = (g.league||'').toLowerCase();
  const leagueName = g.league || 'the match';
  let context = '';

  // UEFA Cup competitions — distinct context per competition
  if(league.includes('champions league')){
    if(league.includes('final')) context = 'The UEFA Champions League Final — the biggest club match in world football. Winner takes the trophy tonight.';
    else if(league.includes('semi')) context = 'UEFA Champions League semifinal — one win from the final.';
    else if(league.includes('quarter')) context = 'UEFA Champions League quarterfinal knockout football.';
    else context = 'UEFA Champions League knockout stage fixture.';
  } else if(league.includes('europa league')){
    if(league.includes('final')) context = 'The UEFA Europa League Final — second biggest European club trophy. Season-defining match for both clubs tonight.';
    else if(league.includes('semi')) context = 'UEFA Europa League semifinal — winner reaches the final.';
    else context = 'UEFA Europa League knockout fixture.';
  } else if(league.includes('conference league')){
    if(league.includes('final')) context = 'The UEFA Conference League Final — a first European trophy is on the line tonight.';
    else context = 'UEFA Conference League knockout fixture.';
  } else {
    // Premier League / domestic league: use matchweek context
    if(mw && mw >= 37) context = 'The final matchday of the Premier League season — every result matters for titles, European spots, and relegation.';
    else if(mw && mw >= 35) context = 'Late-season Premier League football — the table is being decided at both ends.';
    else if(mw && mw >= 28) context = 'The Premier League enters the decisive final stretch — points are becoming precious.';
    else context = `${leagueName} fixture.`;
  }
  return `${g.away} vs ${g.home} — ${leagueName}.${streamNote} ${context}`;
}


// ═══════════════════════════════════════════════════════════════════════════
// J-LAYER EXPANSION — Six new journalism types (May 29 2026)
//   J8  : MLB Game Brief card (park + weather + umpire + pitcher)
//   J9  : WNBA Game Brief card (standings + matchup context)
//   J10 : Stakes Brief (elimination / clinch / series-deciding)
//   J11 : On-demand Bottom Sheet Brief (all sports, lazy-fetch on tap)
//   MLS : Extend EPL brief to domestic soccer (see renderEPLMatchBriefCard)
//   NOX : Multi-final Night Owl (see renderNightOwlRecap)
// All use FIELD_PROSE_STYLE, retryWithoutCliches, journalismCallsToday()
// ═══════════════════════════════════════════════════════════════════════════

// ── J8: MLB Game Brief ───────────────────────────────────────────────────────
async function fetchMLBGameBriefFromClaude(g) {
  // Card briefs use a separate budget from compound/J3 (which share journalismCallsToday)
  // This prevents 15 MLB games from blocking J3/Night Owl via shared budget exhaustion
  const cardBudget = cardBriefCallsToday();
  if (!cardBudget.canCall()) return null;

  const abbr = (g._homeAbbr || g.homeTeam || '').toUpperCase();
  const pf   = abbr ? getParkFactor?.(abbr) : null;
  const ump  = (() => {
    const name = g._hpUmpire || g.umpire || '';
    if (!name) return '';
    const last = name.split(' ').pop();
    const u    = getUmpireABSRating?.(last);
    return u ? `${last}: ${Math.round(u.rate*100)}% K-rate${u.weakness?' · weak '+u.weakness+' zone':''}` : last;
  })();
  const umpLine = !!ump; // umpLine was referenced in prompt but never declared — caused ReferenceError → null

  // Park factor line
  const pfLine = pf ? (() => {
    const rd = pf.runFactor - 100;
    const hd = pf.hrFactor  - 100;
    return `Park (${pf.label||abbr}): ${rd > 0 ? '+' : ''}${rd}% runs · ${hd > 0 ? '+' : ''}${hd}% HR`;
  })() : '';

  // Weather from wxCache
  const wxLine = (() => {
    try {
      const wx = typeof wxCache !== 'undefined' ? wxCache[g._id] : null;
      if (!wx) return '';
      const wn = windContextNote?.(g.venue, wx.windDir, wx.gusts||wx.wind);
      return `Weather: ${wx.temp||'?'}°F · ${wx.wind||0}mph${wn ? ' · ' + wn : ''}`;
    } catch(_) { return ''; }
  })();

  // Probable pitchers
  const pitcherLine = (() => {
    const fmt = p => {
      if (!p) return null;
      const n   = p.name || p.lastName || '?';
      const era = p.era != null ? ` ${p.era} ERA` : '';
      const rec = (p.wins != null && p.losses != null) ? ` (${p.wins}-${p.losses})` : '';
      return `${n}${era}${rec}`;
    };
    const ap = fmt(g.awayPitcher), hp = fmt(g.homePitcher);
    if (!ap && !hp) return '';
    const parts = [ap ? `${teamNick(g.away||'')} ${ap}` : null, hp ? `${teamNick(g.home||'')} ${hp}` : null].filter(Boolean);
    return 'Pitchers: ' + parts.join(' vs ');
  })();

  const standingsCtx = (typeof buildGameStandingsContext === 'function') ? buildGameStandingsContext(g) : '';

  // Pull from the same analytics context that compound uses —
  // pitch arsenal, tempo, expected stats (xBA luck), team ABS challenge IQ
  const analyticsLines = (typeof getMLBAnalyticsContext === 'function') ? getMLBAnalyticsContext(g) : [];
  const analyticsCtx = analyticsLines.length ? analyticsLines.join('\n') : '';

  // Team momentum (last-10 record) — gives texture beyond raw standings
  // RUWT: fetchMLBTeamMomentum response fields verified against buildCompoundPrompt
  // usage at L15798 (same session, May 30 2026). Fields: {wins, losses, last10[]}
  // where last10 is array of 1/0 (win/loss). Re-verify if fetchMLBTeamMomentum changes.
  // VERIFIED May 30 2026 (inherited from compound prompt usage)
  let momentumCtx = '';
  try {
    const homeAbbr = g._homeAbbr || g.homeTeam || '';
    const awayAbbr = g._awayAbbr || g.awayTeam || '';
    const [hMom, aMom] = await Promise.all([
      homeAbbr ? fetchMLBTeamMomentum(homeAbbr).catch(()=>null) : Promise.resolve(null),
      awayAbbr ? fetchMLBTeamMomentum(awayAbbr).catch(()=>null) : Promise.resolve(null),
    ]);
    const fmtMom = (m, nick) => m?.last10?.length
      ? `${nick}: ${m.wins}-${m.losses} (L10: ${m.last10.filter(r=>r==='W').length}-${m.last10.filter(r=>r==='L').length})`
      : null;
    const parts = [fmtMom(hMom, teamNick(g.home||'')), fmtMom(aMom, teamNick(g.away||''))].filter(Boolean);
    if (parts.length) momentumCtx = 'Form: ' + parts.join(' · ');
  } catch(_) {}

  const prompt = [
    `Write a FIELD Match Brief for this MLB game.`,
    '',
    'GAME DATA:',
    `${g.away||'?'} @ ${g.home||'?'}${g.venue ? ' · ' + g.venue : ''}.`,
    pfLine, wxLine, pitcherLine, umpLine ? `Umpire: ${ump}` : '',
    standingsCtx || '',
    momentumCtx || '',
    analyticsCtx || '',
    g.matchupNote ? `Matchup: ${g.matchupNote}` : '',
    '',
    'Rules: 50-70 words. 2 sentences. Vary the angle — use whichever single fact is most interesting tonight: park factor, pitcher arsenal, expected stats luck, momentum, or standings gap. Not always standings.',
    '- Cite the exact figure if park, weather, or analytics data is provided — never paraphrase.',
    '- Write only from data above. No invented stats. Never explain what data is missing — if context is thin, write what you have.',
    FIELD_PROSE_STYLE,
    FIELD_BASEBALL_VOICE,
  ].filter(Boolean).join('\n');

  try {
    // ── WOW 6 Phase 2: route through relay quality gate
    const _viaRelay = await generateJournalismViaRelay(prompt, {
      sport: 'baseball', briefType: 'mlb-brief', max_tokens: 400,
      game: g || null,
      matchupNote: g?.matchupNote || g?.note || null,
    });
    if (_viaRelay && _viaRelay.length > 20) {
      cardBudget.inc();
      scoreProse(_viaRelay, g||null).then(s=>renderProseScore(s,'MLB Brief'));
      return _viaRelay.trim();
    }
    // Fallback: legacy direct-proxy path
    const r = await fetch(CLAUDE_PROXY_URL, {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({model:'claude-haiku-4-5-20251001', max_tokens:400,
        messages:[{role:'user',content:prompt}]}),
      signal: AbortSignal.timeout(10000),
    });
    if (!r.ok) {
      // 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #9): neither
      // real caller has a "leave existing content alone" option (both show
      // a "pending" card that must resolve to real text or removal --
      // removing on ANY failure reason, including a hypothetical budget-
      // exhausted differentiation, is already the correct behavior, per
      // this function's own sibling comment elsewhere: "never leave
      // 'Loading brief…' stuck"). So the real gap wasn't caller
      // differentiation -- it was that this function had ZERO telemetry on
      // any failure path, not even a console.warn. Health Panel was
      // completely blind to MLB brief failures. Added, matching the
      // pattern generateJournalismViaRelay already uses.
      captureFieldError('journalism:mlb-brief', new Error('HTTP ' + r.status), false);
      return null;
    }
    const data = await r.json();
    let text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('');
    if (text && text.length > 20) {
      text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
      text = await retryWithSportVocab(prompt, text, 'baseball', CLAUDE_PROXY_URL, 'MLB Brief');
      text = await checkLeadSentence(prompt, text, CLAUDE_PROXY_URL);
      text = await checkStatVerification(prompt, text, CLAUDE_PROXY_URL);
      text = await checkCrossSport(prompt, text, CLAUDE_PROXY_URL);
      text = await maybeScoreRetry(prompt, text, CLAUDE_PROXY_URL, 'MLB Brief');
      cardBudget.inc();
      scoreProse(text, g||null).then(s=>renderProseScore(s,'MLB Brief'));
      return stripPromptLeaks(text.trim());
    }
  } catch(e_) {
    captureFieldError('journalism:mlb-brief', e_, false);
  }
  return null;
}

// ── fetchPrerenderedGameBrief ─────────────────────────────────────────────────
// Checks relay KV for a pre-generated game brief before calling the proxy.
// The relay cron pre-generates briefs every 15min — browser gets instant load
// with zero AI calls on most requests. Falls back to browser-side generation
// if KV miss (cron hasn't run yet for this game) or relay unavailable.
// KV key: brief:game:{espnEventId}   TTL: 3600s
//
// Timeout: 1500ms. KV reads typically return in 5-50ms; 1500ms is generous
// for network round-trip + Worker cold start. Was 3000ms — reduced May 31
// 2026 so a slow/degraded KV doesn't drag the bottom-sheet UX. Falling
// through to live LLM after 1.5s is preferable to waiting 3s for nothing.
// ── GAME ARCHIVE consumers (CC-CMD-2026-06-15-archive-d1.md Task 3) ─────────
// Three fetch helpers that read from the relay's /archive/* endpoints backed
// by the field-archive D1 database (19 postseason_games + 146 regular_season
// _games + 5 postseason_series as of 2026-06-15 seed). Endpoints are NOT
// yet live in field-relay-nba — this client-side surface is scaffolded so
// the consumer can fire as soon as the relay endpoints ship.
//
// All calls gated by ARCHIVE_RELAY_READY — flip to true once
// `/archive/series/nba-ecf-2026` returns 200 from the relay. Until then the
// helpers return null without making a request (avoids 404 noise + speeds
// up the dev loop). Set via `window.ARCHIVE_RELAY_READY = true` at runtime
// for ad-hoc probing once the relay is ready.
//
// Cache: 30-min sessionStorage TTL matching the spec. Keyed by endpoint.
const ARCHIVE_RELAY_READY = true; // Relay live — 5 /archive/* endpoints deployed June 15 2026
const _archiveBase = (typeof V2_RELAY_BASE !== 'undefined')
  ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';

async function fetchSeriesArchive(seriesKey) {
  if (!ARCHIVE_RELAY_READY || !seriesKey) return null;
  const cacheKey = `field_archive_series_${seriesKey}`;
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      const c = JSON.parse(cached);
      if (Date.now() - c.ts < 1800000) return c.data;
    }
  } catch (_e) { captureFieldError('journalism:series-archive-cache-read', _e, true); }
  try {
    const r = await fetch(`${_archiveBase}/archive/series/${encodeURIComponent(seriesKey)}`);
    if (!r.ok) return null;
    const data = await r.json();
    try { sessionStorage.setItem(cacheKey, JSON.stringify({ ts: Date.now(), data })); } catch (_e) { captureFieldError('journalism:series-archive-cache-write', _e, true); }
    return data;
  } catch (_e) { captureFieldError('journalism:series-archive-fetch', _e, true); return null; }
}

async function fetchLastMeeting(teamA, teamB) {
  if (!ARCHIVE_RELAY_READY || !teamA || !teamB) return null;
  try {
    const r = await fetch(
      `${_archiveBase}/archive/last-meeting?home=${encodeURIComponent(teamA)}&away=${encodeURIComponent(teamB)}`,
      { signal: AbortSignal.timeout(2500) }
    );
    if (!r.ok) return null;
    return r.json();
  } catch (e) { captureFieldError('archive:last-meeting', e, true); return null; }
}

async function fetchArchiveDate(iso) {
  if (!ARCHIVE_RELAY_READY || !iso) return null;
  try {
    const r = await fetch(`${_archiveBase}/archive/date/${encodeURIComponent(iso)}`,
      { signal: AbortSignal.timeout(2500) });
    if (!r.ok) return null;
    return r.json();
  } catch (_e) { captureFieldError('broadcast-archaeology:date-fetch', _e, true); return null; }
}

async function fetchPrerenderedGameBrief(espnEventId) {
  if (!espnEventId) return null;
  try {
    const r = await fetch(
      `${JOURNALISM_RELAY.replace('/journalism/tonight', '')}/journalism/game/${espnEventId}`,
      { signal: AbortSignal.timeout(1500) }
    );
    if (!r.ok) return null;
    const data = await r.json();
    return data?.brief || null;
  } catch(_e) { captureFieldError('journalism:prerendered-game-brief', _e, true); return null; }
}

async function renderMLBGameBriefCard(gameCard) {
  const gameid = gameCard.dataset.gameid;
  if (!gameid) return;
  const sport = (gameCard.dataset.sport || '').toLowerCase();
  if (!sport.includes('baseball') && !sport.includes('mlb')) return;
  if (gameCard.previousElementSibling?.classList.contains('sport-game-brief-card')) return;

  let game = null;
  (allData?.sports||[]).forEach(s=>(s.games||[]).forEach(g=>{ if(g._id===gameid) game=g; }));
  if (!game) return;

  const eData = typeof findESPNScore === 'function' ? findESPNScore(game) : null;
  const status = eData?.state || 'pre';
  const cacheKey = 'field_mlb_brief_' + gameid + '_' + status;
  const cached = sessionStorage.getItem(cacheKey);

  const card = document.createElement('div');
  card.className = 'sport-game-brief-card sport-game-brief-mlb';
  card.dataset.gameid = gameid;

  const inner = document.createElement('div');
  inner.className = 'sgb-inner';
  inner.innerHTML = `<div class="sgb-tag">⚾ MLB · Field Brief</div>
    <div class="sgb-text pending">${cached || 'Loading brief…'}</div>`;
  card.appendChild(inner);
  gameCard.insertAdjacentElement('beforebegin', card);

  if (cached) { inner.querySelector('.sgb-text')?.classList.replace('pending','loaded'); return; }

  // Check relay KV first — zero cost if cron has pre-generated this brief
  const espnId = game._espnId || game.sourceId || gameid;
  const kvBrief = await fetchPrerenderedGameBrief(espnId);
  if (kvBrief) {
    const textEl = inner.querySelector('.sgb-text');
    if (textEl) { textEl.textContent = trimToCompleteSentence(kvBrief); textEl.classList.replace('pending','loaded'); }
    sessionStorage.setItem(cacheKey, kvBrief);
    try { archiveBrief('mlb_game', 'MLB', game&&(game._id||game.id)||null, kvBrief, null); } catch(_){}
    return;
  }

  const text = await fetchMLBGameBriefFromClaude(game);
  const textEl = inner.querySelector('.sgb-text');
  if (text && textEl) {
    textEl.textContent = trimToCompleteSentence(stripMarkdown(text));
    textEl.classList.replace('pending','loaded');
    sessionStorage.setItem(cacheKey, stripMarkdown(text));
    try { archiveBrief('mlb_game', 'MLB', game&&(game._id||game.id)||null, stripMarkdown(text), null); } catch(_){}
  } else {
    // Always remove card on failure — never leave "Loading brief…" stuck
    try { card.remove(); } catch(_) {}
  }
}

// ── J9: WNBA Game Brief ───────────────────────────────────────────────────────
async function fetchWNBAGameBriefFromClaude(g) {
  const cardBudget = cardBriefCallsToday();
  if (!cardBudget.canCall()) return null;

  const standingsCtx = (typeof buildGameStandingsContext === 'function') ? buildGameStandingsContext(g) : '';
  const stream = gameNetwork(g);

  // Only fire if we have something worth writing about — suppress card if context is bare
  const _wnbaHasContext = !!(standingsCtx || g.matchupNote || g.seriesRecord);
  if (!_wnbaHasContext) return null;

  const prompt = [
    `Write a FIELD Match Brief for this WNBA game.`,
    '',
    'GAME DATA:',
    `${g.away||'?'} @ ${g.home||'?'}${g.venue ? ' · ' + g.venue : ''}.`,
    stream ? `Broadcast: ${stream}.` : '',
    standingsCtx || '',
    g.matchupNote ? `Matchup: ${g.matchupNote}` : '',
    '',
    'Rules: 35-50 words. 1-2 sentences. Use only facts provided above.',
    '- If standings are provided, anchor the brief in where each team sits.',
    '- Write only from data above. No invented stats. If data is thin, write one simple factual sentence about the matchup.',
    FIELD_PROSE_STYLE,
  ].filter(Boolean).join('\n');

  try {
    const r = await fetch(CLAUDE_PROXY_URL, {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({model:'claude-haiku-4-5-20251001', max_tokens:200,
        messages:[{role:'user',content:prompt}]}),
    });
    if (!r.ok) return null;
    const data = await r.json();
    let text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('');
    if (text && text.length > 20) {
      text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
      text = await checkLeadSentence(prompt, text, CLAUDE_PROXY_URL);
      text = await maybeScoreRetry(prompt, text, CLAUDE_PROXY_URL, 'WNBA Brief');
      cardBudget.inc();
      scoreProse(text, g||null).then(s=>renderProseScore(s,'WNBA Brief'));
      return stripPromptLeaks(text.trim());
    }
  } catch(e_) { captureFieldError('journalism:wnba-brief', e_, true); }
  return null;
}

