// ── J10: Stakes Brief (elimination / clinch / series-deciding) ──────────────
async function fetchStakesBriefFromClaude(g) {
  const cardBudget = cardBriefCallsToday();
  if (!cardBudget.canCall()) return null;

  const imp = g._gameImportance || '';
  // Major finals (UCL, UEL, UECL, World Series etc.) may not have _gameImportance set
  const _isMajorFinalGame = /champions league.*final|europa league.*final|conference league.*final/i.test(g.league||'');
  if (!_isMajorFinalGame && (!imp || imp === 'playoff_impl')) return null;

  // European finals and domestic cup finals are showpiece events — not "elimination games"
  const isEuropeanFinal = /champions league.*final|europa league.*final|conference league.*final|fa cup.*final|league cup.*final/i.test(g.league||'');
  const isMajorFinal = isEuropeanFinal || /world series|super bowl|stanley cup final|nba finals|world cup.*final/i.test(g.league||'');
  const impLabel = isMajorFinal
    ? (() => {
        if (/champions league.*final/i.test(g.league||'')) return 'THE UEFA CHAMPIONS LEAGUE FINAL — the biggest club match in world football. One game for the trophy.';
        if (/europa league.*final/i.test(g.league||'')) return 'THE UEFA EUROPA LEAGUE FINAL — second biggest European club trophy. One game decides it.';
        if (/conference league.*final/i.test(g.league||'')) return 'THE UEFA CONFERENCE LEAGUE FINAL — a first European trophy for one of these clubs.';
        return 'MAJOR FINAL — one game, winner takes the trophy.';
      })()
    : imp === 'elimination' ? 'ELIMINATION GAME — a loss ends their season'
    : imp === 'series_deciding' ? 'SERIES-DECIDING GAME — winner advances'
    : imp === 'clinch' ? 'CLINCH OPPORTUNITY — win tonight to advance'
    : null;
  if (!impLabel) return null;

  const standingsCtx = (typeof buildGameStandingsContext === 'function') ? buildGameStandingsContext(g) : '';
  const series = g.seriesRecord || '';

  const prompt = [
    `Write a FIELD Stakes Brief for this high-stakes game.`,
    '',
    'GAME DATA:',
    `${g.away||'?'} @ ${g.home||'?'}${g.venue ? ' · '+g.venue : ''}.`,
    impLabel,
    series ? `Series: ${series}` : '',
    standingsCtx || '',
    g.matchupNote ? `Context: ${g.matchupNote}` : '',
    '',
    isMajorFinal
      ? 'Rules: 2 sentences. This is the FINAL — not a semifinal, not a knockout round. There is no next game. One match, winner takes the trophy. Lead with what the trophy means to each club (last won it, first final in X years, first ever). Cite only facts from Context above.'
      : 'Rules: 2 sentences. Lead with the historical weight — what losing or winning means beyond just tonight.',
    '- Cite specific year or franchise context if it sharpens the stakes.',
    '- If Context is provided, use only facts from it. NEVER invent round context, series history, or prior results not mentioned above.',
    '- Never explain what data is missing. If context is thin, write what you have in plain factual prose.',
    isMajorFinal ? '- CRITICAL: Do NOT use the words semifinal, quarter-final, knockout round, or elimination. This is the FINAL — the last game of the competition.' : '',
    g.venue ? `- VENUE: The match is at ${g.venue}. This is the only correct venue — never mention a different stadium.` : '',
    '- Write only from data above. No invented stats.',
    FIELD_PROSE_STYLE,
  ].filter(Boolean).join('\n');

  try {
    // ── WOW 6 Phase 2: route through relay quality gate
    const _sportHint = _gameSport(g);
    const _viaRelay = await generateJournalismViaRelay(prompt, {
      sport: _sportHint, briefType: 'stakes-brief', max_tokens: 200,
      game: g || null,
      matchupNote: g?.matchupNote || g?.note || null,
    });
    if (_viaRelay && _viaRelay.length > 20) {
      cardBudget.inc();
      scoreProse(_viaRelay, g||null).then(s=>renderProseScore(s,'Stakes Brief'));
      return _viaRelay.trim();
    }
    // Fallback: legacy direct-proxy path
    const r = await fetch(CLAUDE_PROXY_URL, {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({model:'claude-haiku-4-5-20251001', max_tokens:200,
        messages:[{role:'user',content:prompt}]}),
    });
    if (!r.ok) return null;
    const data = await r.json();
    let text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('');
    if (text && text.length > 20) {
      text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
      text = await checkLeadSentence(prompt, text, CLAUDE_PROXY_URL);
      text = await checkStatVerification(prompt, text, CLAUDE_PROXY_URL);
      text = await checkCrossSport(prompt, text, CLAUDE_PROXY_URL);
      text = await maybeScoreRetry(prompt, text, CLAUDE_PROXY_URL, 'Stakes Brief');
      cardBudget.inc();
      scoreProse(text, g||null).then(s=>renderProseScore(s,'Stakes Brief'));
      return stripPromptLeaks(text.trim());
    }
  } catch(e_) { captureFieldError('journalism:stakes-brief', e_, true); }
  return null;
}

async function renderStakesBriefCard(gameCard) {
  const gameid = gameCard.dataset.gameid;
  if (!gameid) return;
  let game = null;
  (allData?.sports||[]).forEach(s=>(s.games||[]).forEach(g=>{ if(g._id===gameid) game=g; }));
  if (!game) return;

  const imp = game._gameImportance || '';
  const _isMajorFinal = /champions league.*final|europa league.*final|conference league.*final/i.test(game.league||'');
  if (!_isMajorFinal && (!imp || imp === 'playoff_impl')) return;
  if (gameCard.previousElementSibling?.classList.contains('stakes-brief-card')) return;

  // Version cache key with SW_VERSION so stale briefs (e.g. "semifinal exit") auto-bust on deploy
  const _swv = window.SW_VERSION || '0';
  const cacheKey = 'field_stakes_brief_v' + _swv + '_' + gameid;
  const cached = sessionStorage.getItem(cacheKey);

  const card = document.createElement('div');
  card.className = 'stakes-brief-card';
  card.dataset.gameid = gameid;

  // Stakes label — context-aware
  // G7 conference finals gets 'FINALS BOUND', NBA/SCF Finals games get trophy label,
  // plain G7s get 'GAME 7', elimination gets 'WINNER-TAKE-ALL'.
  const _isG7 = /\bg7\b|game 7/i.test(game.league||'');
  const _isCFG7 = _isG7 && /conf.*final|conference.*final|west.*final|east.*final/i.test(game.league||'');
  const _isNBAFinalsGame = /nba finals/i.test(game.league||'');
  const _isSCFGame = /stanley cup final/i.test(game.league||'');
  const impIcon = _isMajorFinal
    ? (/champions league.*final/i.test(game.league||'') ? '🏆 UCL FINAL'
      : /europa league.*final/i.test(game.league||'') ? '🏆 UEL FINAL'
      : /conference league.*final/i.test(game.league||'') ? '🏆 UECL FINAL'
      : '🏆 FINAL')
    : _isNBAFinalsGame   ? '🏆 NBA FINALS'
    : _isSCFGame         ? '🏆 STANLEY CUP FINAL'
    : _isCFG7            ? '⚡ GAME 7 — FINALS BOUND'
    : _isG7              ? '⚡ GAME 7'
    : imp === 'elimination'     ? '💀 WINNER-TAKE-ALL'
    : imp === 'series_deciding' ? '⚡ SERIES DECIDING'
    : '🏆 CLINCH';
  const inner = document.createElement('div');
  inner.className = 'stakes-inner';
  inner.innerHTML = `<div class="stakes-tag">${impIcon}</div>
    <div class="stakes-text pending">${cached || 'Loading…'}</div>`;
  card.appendChild(inner);
  gameCard.insertAdjacentElement('beforebegin', card);

  if (cached) { inner.querySelector('.stakes-text')?.classList.replace('pending','loaded'); return; }

  const espnIdS = game._espnId || game.sourceId || gameid;
  const kvBriefS = await fetchPrerenderedGameBrief(espnIdS);
  if (kvBriefS) {
    const textEl = inner.querySelector('.stakes-text'); // fix: was .sgb-text (wrong)
    if (textEl) { textEl.textContent = trimToCompleteSentence(stripMarkdown(kvBriefS)); textEl.classList.replace('pending','loaded'); }
    sessionStorage.setItem(cacheKey, stripMarkdown(kvBriefS));
    try { archiveBrief('stakes', (game&&(_gameSport(game)))||null, game&&(game._id||game.id)||null, stripMarkdown(kvBriefS), null); } catch(_){}
    return;
  }

  const text = await fetchStakesBriefFromClaude(game);
  const textEl = inner.querySelector('.stakes-text');
  if (text && textEl) {
    const _stakesClean = stripMarkdown(text);
    textEl.textContent = trimToCompleteSentence(_stakesClean);
    textEl.classList.replace('pending','loaded');
    sessionStorage.setItem(cacheKey, _stakesClean);
    try { archiveBrief('stakes', (game&&(_gameSport(game)))||null, game&&(game._id||game.id)||null, _stakesClean, null); } catch(_){}
    _archiveBrief({briefType:'stakes_brief', sport:(game&&(_gameSport(game)))||null, gameId:game&&(game._id||game.id)||null, briefText:_stakesClean});
  } else {
    try { card.remove(); } catch(_) {}
  }
}

