// buildChampionshipContext — returns enrichment facts for the prompt or null.
// Inputs: game (allData entry), eData (espnScores entry — for live/final score).
// Returns {winner, trophy, drought, playoffRecord, journey, clinchType} or null.
// Only fires when the game is in the championship round AND clinched.
function buildChampionshipContext(game, eData) {
  if (!game) return null;
  const league = String(game.league || game._sport || '').trim();
  const series = String(game.seriesRecord || '').trim();
  const importance = String(game._gameImportance || '').trim();
  // Final round gate — Stanley Cup Final / NBA Finals / World Series / Super Bowl
  const isFinalsRound =
    /stanley cup final|nba finals|world series|super bowl/i.test(league) ||
    /finals?\s+g[1-7]\b/i.test(league);
  if (!isFinalsRound) return null;
  // Clinch gate — explicit importance OR series record reaching 4 wins
  const seriesM = /(\d)-(\d)/.exec(series);
  const isClinchBySeries = !!(seriesM && (parseInt(seriesM[1],10) === 4 || parseInt(seriesM[2],10) === 4));
  const isClinchByImportance = importance === 'clinch' || importance === 'series_deciding';
  if (!isClinchByImportance && !isClinchBySeries) return null;
  // Winner from eData (final score) — required for a verified championship claim.
  if (!eData || eData.homeScore == null || eData.awayScore == null) return null;
  const home = game.home || '';
  const away = game.away || '';
  let winner, loser, winnerScore, loserScore;
  if (eData.homeScore > eData.awayScore) {
    winner = home; loser = away;
    winnerScore = eData.homeScore; loserScore = eData.awayScore;
  } else if (eData.awayScore > eData.homeScore) {
    winner = away; loser = home;
    winnerScore = eData.awayScore; loserScore = eData.homeScore;
  } else {
    return null;  // tie — no clinch
  }
  const entry = FRANCHISE_LAST_TITLE[winner];
  if (!entry) return null;
  const trophy = entry.trophy;
  // Drought string
  const currentYear = new Date().getFullYear();
  let drought;
  if (entry.year === null) {
    drought = `First ${trophy} in franchise history`;
  } else if (entry.year === currentYear) {
    drought = `Back-to-back ${trophy} (won ${entry.year} as well)`;
  } else if (entry.year === currentYear - 1) {
    drought = `Back-to-back ${trophy} (last won ${entry.year})`;
  } else {
    drought = `First ${trophy} since ${entry.year} — ${currentYear - entry.year}-year drought`;
  }
  // Playoff record — current series only (full-postseason data not always available)
  const playoffRecord = seriesM
    ? `${winner === home ? seriesM[1] : seriesM[2]}-${winner === home ? seriesM[2] : seriesM[1]} this series`
    : 'Unknown';
  // Journey — current series outcome. Prior-round results would need historical data
  // that isn't reliably available client-side; this is the verifiable subset.
  const journey = seriesM
    ? `${winner} defeat ${loser} ${seriesM[1]}-${seriesM[2]} in ${trophy === 'Stanley Cup' ? 'Stanley Cup Final' : 'Finals'}`
    : `${winner} defeat ${loser} in ${trophy === 'Stanley Cup' ? 'Stanley Cup Final' : 'Finals'}`;
  // Clinch type from score + venue (winner on the road if winner === away)
  const margin = Math.abs(winnerScore - loserScore);
  const onRoad = winner === away;
  const venueWord = onRoad ? 'on the road' : 'at home';
  let clinchType;
  if (loserScore === 0)      clinchType = `Shutout ${venueWord}`;
  else if (margin >= 4)      clinchType = `Blowout ${venueWord} (${winnerScore}-${loserScore})`;
  else if (margin === 1)     clinchType = `One-goal win ${venueWord} (${winnerScore}-${loserScore})`;
  else                       clinchType = `${winnerScore}-${loserScore} win ${venueWord}`;
  return { winner, trophy, drought, playoffRecord, journey, clinchType };
}

// enrichChampionshipFromArchive — async wrapper that augments a champCtx
// with the winner's path-to-finals narrative from D1. buildChampionshipContext
// stays synchronous; this is the optional async patch layer. Returns the
// (possibly augmented) ctx. Null-safe: returns ctx unchanged on any failure
// or when ARCHIVE_RELAY_READY is false (fetchSeriesArchive short-circuits).
// Mapping is winner→conference-final series_key for the four 2026 Finals teams.
const _PATH_TO_FINALS_KEY = {
  // NBA Finals 2026 — NYK (East) via ECF, SAS (West) via WCF
  'New York Knicks':       'nba-ecf-2026',
  'San Antonio Spurs':     'nba-wcf-2026',
  // NHL SCF 2026 — CAR (East) via ECF, VGK (West) via WCF
  'Carolina Hurricanes':   'nhl-ecf-2026',
  'Vegas Golden Knights':  'nhl-wcf-2026',
};
async function enrichChampionshipFromArchive(game, ctx) {
  if (!ctx || !ctx.winner) return ctx;
  if (typeof fetchSeriesArchive !== 'function') return ctx;
  const key = _PATH_TO_FINALS_KEY[ctx.winner];
  if (!key) return ctx;
  try {
    const data = await fetchSeriesArchive(key);
    if (!data || data.ok === false || !data.series) return ctx;
    const s = data.series;
    const pathToFinals = s.narrative ||
      `Path to ${ctx.trophy}: defeated ${s.lower_seed || s.higher_seed || ''} ${s.result || ''} in ${s.round || ''}${s.mvp ? ` (${s.mvp} MVP)` : ''}.`.replace(/\s+/g,' ').trim();
    return { ...ctx, pathToFinals };
  } catch(_) {
    return ctx;
  }
}

// fetchGameBriefOnDemand — generic per-card brief generator.
// Dispatches to sport-specific brief function or generic fallback.
// Result stored in _gameBriefCache so subsequent opens are instant.
async function fetchGameBriefOnDemand(game, sport) {
  if (!game?._id) return null;
  if (_gameBriefCache[game._id]) return _gameBriefCache[game._id]; // already populated

  // ── O(1) Newspaper KV-first lookup (May 31 2026) ───────────────────────────
  // The relay cron pre-generates per-game briefs every 15 min and stores them in
  // KV (brief:game:{eventId}, 1hr TTL). If a fresh brief exists, serve it from
  // KV at near-zero cost (KV read ~5ms vs 1-2s LLM call). This is the dominant
  // contributor to the 97% LLM-cost reduction at scale: one cron call serves
  // N user taps. The live-path code below remains as fallback for KV misses
  // (cold cache, brief older than 1hr, sport not yet covered by cron).
  const espnId = game._espnId || game.sourceId || game._id;
  if (espnId) {
    const kvBrief = await fetchPrerenderedGameBrief(espnId);
    if (kvBrief && kvBrief.length > 30) {
      const trimmed = stripMarkdown(kvBrief).trim();
      _gameBriefCache[game._id] = trimmed;
      return trimmed;
    }
  }

  const sp = (sport || _gameSport(game)).toLowerCase();
  // At Tier 1 (4000 RPM), the shared budget (50/session) is essentially never
  // exhausted. Budget gates are now primarily a safety backstop against stuck
  // retry loops, not RPM protection. All sport paths share the same pool.
  const usesOwnBudget = sp.includes('baseball') || sp.includes('mlb') || sp.includes('wnba');
  // 2026-07-13 (CC-CMD-bucketb-tierc-cluster3): `budget` was previously
  // block-scoped to this `if`, but the generic NBA/NHL/other branch below
  // calls `budget.inc()` well outside this block -- a real ReferenceError
  // on every successful generic-branch generation, previously invisible
  // because it landed in that branch's own catch, which had zero telemetry
  // until this same CC-CMD added it. Adding the telemetry surfaced this;
  // hoisting the declaration to function scope is the real fix.
  // journalismCallsToday() itself is a pure factory (sessionStorage reads
  // only) -- safe to call unconditionally regardless of usesOwnBudget.
  const budget = journalismCallsToday();
  if (!usesOwnBudget && !budget.canCall()) return null;

  let text = null;

  // MLB: rich brief (park/weather/umpire/pitcher)
  if (sp.includes('baseball') || sp.includes('mlb')) {
    text = await fetchMLBGameBriefFromClaude(game);
  }
  // WNBA: standings + matchup
  else if (sp.includes('wnba')) {
    text = await fetchWNBAGameBriefFromClaude(game);
  }
  // NBA/NHL/other: generic brief from compound (if not already in cache)
  else {
    const standingsCtx = (typeof buildGameStandingsContext === 'function') ? buildGameStandingsContext(game) : '';
    const series = game.seriesRecord ? `Series: ${game.seriesRecord}.` : '';
    const stream = gameNetwork(game);
    // CHAMPIONSHIP-BRIEF-SPEC: when this game IS a championship clinch,
    // surface drought + trophy + clinch type so the prompt rises to the
    // moment. buildChampionshipContext returns null when not applicable —
    // the brief path is unchanged for non-clinch games. Brief word budget
    // is lifted to 60-90 when championship context is present so the
    // weight of the moment isn't crushed by the 35-50 floor.
    const _champEData = (typeof findESPNScore === 'function') ? findESPNScore(game) : null;
    let champCtx = buildChampionshipContext(game, _champEData);
    // Archive enrichment — path-to-finals narrative from D1 (cached, instant on repeat).
    if (champCtx && typeof enrichChampionshipFromArchive === 'function') {
      try { champCtx = await enrichChampionshipFromArchive(game, champCtx); } catch(_e) { captureFieldError('journalism:champ-archive-enrich', _e, true); }
    }
    const champBlock = champCtx
      ? `[CHAMPIONSHIP CONTEXT]
This is a championship-clinching game. ${champCtx.winner} wins the ${champCtx.trophy}.
${champCtx.drought}.
Playoff record: ${champCtx.playoffRecord}.
Journey: ${champCtx.journey}.
Clinch type: ${champCtx.clinchType}.${champCtx.pathToFinals ? `
Path to Finals: ${champCtx.pathToFinals}` : ''}
Write this brief at the level the moment deserves. Do not undersell a championship.`
      : '';
    const wordRule = champCtx
      ? 'Rules: 60-90 words. 2-3 sentences. Lead with the historical weight (drought + trophy), then the clinch type, then a single specific fact from the data above.'
      : 'Rules: 35-50 words. 1-2 sentences. Stakes-first or matchup-first.';
    // Golf-specific enrichment: when this game is a PGA card and the boot
    // path has populated window._pgaDataCache from /v2/golf/enriched, splice
    // the [GOLF CONTEXT] block (tournament header + leaderboard top 5 + per-
    // leader narrative-anchored stats) into the prompt. buildGolfPromptContext
    // returns '' when no PGA data is available so non-golf briefs are byte-for-
    // byte unchanged. Strokes gained is never referenced — pinned by A646.
    const _isGolfBrief = sp.includes('golf') || sp.includes('pga');
    const _golfCtx = (_isGolfBrief && typeof buildGolfPromptContext === 'function'
      && typeof window !== 'undefined' && window._pgaDataCache)
      ? buildGolfPromptContext(window._pgaDataCache) : '';
    // Home Run Derby enrichment (CC-CMD-2026-07-13-hrd-live-wiring TASK 2):
    // mirrors the golf splice exactly. HRD isn't a schedule-grid `game` object
    // today (it's a MEDIA_SPECIALS card — see injectHRDBracket's own doc
    // comment), so this gate currently only fires if a future game/brief is
    // ever sport-detected as HRD; window._hrdDataCache is populated by
    // injectHRDBracket() the same way window._pgaDataCache is populated by
    // the golf boot path. buildHRDPromptContext returns real content only —
    // never fabricates a live result the cached data doesn't contain.
    const _isHRDBrief = sp.includes('home run derby') || /home run derby/i.test(game.league || '') || /home run derby/i.test(game.home || '');
    const _hrdCtx = (_isHRDBrief && typeof buildHRDPromptContext === 'function'
      && typeof window !== 'undefined' && window._hrdDataCache)
      ? buildHRDPromptContext(buildHRDBracket(window._hrdDataCache)) : '';
    const prompt = [
      `Write a FIELD Game Brief.`,
      '',
      'GAME DATA:',
      `${game.away||'?'} @ ${game.home||'?'}${game.venue ? ' · '+game.venue : ''}.`,
      game.league ? `${game.league}.` : '',
      stream ? `Broadcast: ${stream}.` : '',
      series,
      standingsCtx || '',
      champBlock,
      _golfCtx,
      _hrdCtx,
      '',
      wordRule,
      '- Write only from data above.',
      FIELD_PROSE_STYLE,
    ].filter(Boolean).join('\n');
    try {
      // CHAMPIONSHIP-BRIEF-SPEC: lift max_tokens when the prompt carries
      // championship context so the 60-90 word brief has room. Default
      // 200 covers the 35-50 word standard brief.
      const _champMax = champCtx ? 360 : 200;
      const r = await fetch(CLAUDE_PROXY_URL, {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({model:'claude-haiku-4-5-20251001', max_tokens:_champMax,
          messages:[{role:'user',content:prompt}]}),
      });
      if (r.ok) {
        const data = await r.json();
        text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('').trim();
        if (text) {
          text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
          text = await checkLeadSentence(prompt, text, CLAUDE_PROXY_URL);
          budget.inc();
        }
      }
    } catch(_e) { captureFieldError('journalism:game-brief-on-demand', _e, true); }
  }

  if (text) {
    // Deterministic leak strip (CC-CMD-2026-07-10-prompt-data-separation
    // follow-up): unified point for all three branches above (MLB/WNBA
    // already stripped at their own return points; the generic NBA/NHL/
    // other branch is stripped here for the first time -- idempotent on
    // already-clean text, so no harm in the redundancy for the other two).
    _gameBriefCache[game._id] = trimToCompleteSentence(stripPromptLeaks(text));
    return _gameBriefCache[game._id];
  }
  return null;
}

async function fetchEPLMatchBriefFromClaude(g) {
  const budget = journalismCallsToday();
  if(!budget.canCall()) return null;
  const mw = parseMatchweek(g.league);
  const stream = gameNetwork(g);

  // Build H2H and form context from FD data (already cached by fdPrefetchSoccerLive)
  // Gives AI concrete facts: table position, form string, recent meetings
  let h2hLine = '', formLine = '';
  try {
    // Try to fetch H2H if we have the FD match ID
    const homeKey = (g.home||'').toLowerCase().replace(/[^a-z]/g,'').slice(0,6);
    const awayKey = (g.away||'').toLowerCase().replace(/[^a-z]/g,'').slice(0,6);
    const fdId = fdMatchIdCache[homeKey+'_'+awayKey];
    if(fdId) {
      const h2h = await fdFetchH2H(fdId);
      if(h2h) h2hLine = buildH2HSummary(fdId);
    }
    // FD standings form string — already in fdStandingsCache from fdPrefetchSoccerLive
    const fdCode = FD_LEAGUE_MAP[_gameSport(g)];
    if(fdCode && fdStandingsCache[fdCode]?.length) {
      const rows = fdStandingsCache[fdCode];
      const find = name => { const n=teamNick(name).toLowerCase(); return rows.find(r=>(r.team||'').toLowerCase().includes(n)); };
      const hRow = find(g.home), aRow = find(g.away);
      // Enhanced form: include GF/GA (goal difference proxy) and position context
      const fmtTeam = (r,t) => {
        if (!r) return '';
        const posCtx = r.pos<=4?'★ CL zone':r.pos<=6?'Euro zone':r.pos>=18?'relegation zone':r.pos>=16?'danger zone':'';
        const gdStr = (r.goalsFor!=null && r.goalsAgainst!=null) ? ` GD${r.goalsFor-r.goalsAgainst>0?'+':''}${r.goalsFor-r.goalsAgainst}` : '';
        return `${t}: ${r.pos}${posCtx?' ('+posCtx+')':''} ${r.pts}pts${gdStr} form ${r.form||'?'}`;
      };
      const parts = [fmtTeam(hRow,g.home), fmtTeam(aRow,g.away)].filter(Boolean);
      if(parts.length) formLine = 'Table: ' + parts.join('. ');
    }
  } catch(e_) { captureFieldError('journalism:epl-brief-context', e_, true); }

  const prompt = [
    'Write a FIELD Match Brief for this Premier League fixture.',
    '',
    'GAME DATA:',
    `${g.away} @ ${g.home}${g.venue ? ' · '+g.venue : ''}.`,
    g.league ? `${g.league}.` : '',
    stream ? `Broadcast: ${stream}.` : '',
    mw ? `Matchweek ${mw} of 38.` : '',
    formLine || '',
    h2hLine || '',
    g.matchupNote ? `Context: ${g.matchupNote}` : '',
    '',
    'Rules: 40-60 words. 1-2 sentences. Use the table/form/H2H data if provided — these are concrete facts worth mentioning.',
    '- VENUE: if venue is listed above, use it — never substitute a different stadium.',
    '- No invented stats beyond what is given. No markdown. Complete every sentence.',
    FIELD_PROSE_STYLE,
    FIELD_SOCCER_VOICE,
  ].filter(Boolean).join('\n');
  try {
    const r = await fetch(CLAUDE_PROXY_URL, {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:200,messages:[{role:'user',content:prompt}]})
    });
    if(!r.ok) return null;
    const data = await r.json();
    let text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('');
    if(text && text.length > 20) {
      // Layer 2: cliché + sport vocab + lead checks (same chain as J3/J5)
      text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
      text = await retryWithSportVocab(prompt, text, 'soccer', CLAUDE_PROXY_URL, 'EPL Brief');
      text = await checkLeadSentence(prompt, text, CLAUDE_PROXY_URL);
      budget.inc();
      scoreProse(text, g||null).then(s=>renderProseScore(s,'EPL Brief'));
      return stripPromptLeaks(text.trim());
    }
  } catch(e) { captureFieldError('journalism:epl-brief', e, true); }
  return null;
}

async function renderEPLMatchBriefCard(gameCard) {
  const gameid = gameCard.dataset.gameid;
  if(!gameid) return;
  let game = null;
  (allData?.sports||[]).forEach(s=>(s.games||[]).forEach(g=>{ if(g._id===gameid) game=g; }));
  if(!game) return;

  // Top European leagues + domestic soccer (MLS, Bundesliga, etc.)
  const sport = (gameCard.dataset.sport||'').toLowerCase();
  const isSoccerLeague = sport.includes('premier league') || sport.includes('la liga') ||
     sport.includes('ligue 1') || sport.includes('serie a') || sport.includes('uefa') ||
     sport.includes('mls') || sport.includes('bundesliga') || sport.includes('efl championship');
  if (!isSoccerLeague) return;

  // Don't add if already present
  if(gameCard.previousElementSibling?.classList.contains('epl-match-brief-card')) return;

  // QW-7: Cache key includes game status — pregame brief won't serve during live/final
  // field_epl_brief_{gameId}_{status} invalidates when game transitions pre→in→post
  const gameStatus = game?.status || game?.state || 'pre';
  const cacheKey = 'field_epl_brief_' + gameid + '_' + gameStatus;
  const cached = sessionStorage.getItem(cacheKey);

  const staticText = buildEPLMatchBriefStatic(game);
  const card = document.createElement('div');
  card.className = 'epl-match-brief-card';
  card.dataset.gameid = gameid;
  card.innerHTML = '<div class="epl-brief-label">FIELD Match Brief</div>'
    + '<div class="epl-brief-text' + (cached ? '' : ' pending') + '">'
    + (cached || staticText)
    + '</div>';
  card.addEventListener('click', () => card.classList.toggle('epl-brief-collapsed'));

  // Wrap brief + game card together so they sit in the same grid cell at ≥1200px
  const existingWrapper = gameCard.closest('.game-brief-pair');
  if(existingWrapper){
    existingWrapper.insertAdjacentElement('afterbegin', card);
  } else if(gameCard.parentNode) {
    const pair = document.createElement('div');
    pair.className = 'game-brief-pair';
    gameCard.parentNode.insertBefore(pair, gameCard);
    pair.appendChild(card);
    pair.appendChild(gameCard);
  } else {
    // Fallback: card detached from DOM — insert before game card directly
    gameCard.insertAdjacentElement('beforebegin', card);
  }

  if(cached) { card.querySelector('.epl-brief-text').textContent=trimToCompleteSentence(cached); card.querySelector('.epl-brief-text').classList.add('loaded'); return; }

  const aiText = await fetchEPLMatchBriefFromClaude(game);
  const textEl = card.querySelector('.epl-brief-text');
  if(aiText && textEl) {
    textEl.textContent = trimToCompleteSentence(aiText);
    textEl.classList.remove('pending');
    textEl.classList.add('loaded');
    sessionStorage.setItem(cacheKey, aiText);
    try { archiveBrief('epl_match', 'EPL', game&&(game._id||game.id)||null, aiText, null); } catch(_){}
  } else if(textEl) {
    textEl.textContent = staticText;
    textEl.classList.remove('pending');
    textEl.classList.add('loaded');
  }
}

function initEPLMatchBriefs() {
  if(!allData) return;
  // Top European leagues + MLS + Bundesliga (Fix 6: domestic soccer added)
  const BRIEF_LEAGUES = [
    { selector: '.game-card[data-sport*="Premier League"]', max: 3 },
    { selector: '.game-card[data-sport*="La Liga"]',        max: 2 },
    { selector: '.game-card[data-sport*="Serie A"]',        max: 2 },
    { selector: '.game-card[data-sport*="Ligue 1"]',        max: 2 },
    { selector: '.game-card[data-sport*="UEFA Champions"]', max: 4 },
    { selector: '.game-card[data-sport*="UEFA Europa"]',    max: 3 },
    { selector: '.game-card[data-sport*="UEFA Conference"]',max: 2 },
    { selector: '.game-card[data-sport*="MLS"]',            max: 2 },
    { selector: '.game-card[data-sport*="Bundesliga"]',     max: 2 },
    { selector: '.game-card[data-sport*="EFL Championship"]',max:2 },
  ];
  BRIEF_LEAGUES.forEach(({ selector, max }) => {
    const cards = [...document.querySelectorAll(selector)].slice(0, max);
    cards.forEach(card => {
      if(card.dataset.gameid) renderEPLMatchBriefCard(card).catch(()=>{});
    });
  });
}

