let _wcStandings = null;  // cached standings, refreshed each poll cycle
let _wcStandingsTs = 0;   // timestamp of last successful fetch

async function fetchWCStandings(group = null) {
  try {
    const relay = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : null)
                  || 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const url = group
      ? relay + '/wc/standings?group=' + encodeURIComponent(group)
      : relay + '/wc/standings';
    const r = await fetch(url, { cache: 'no-store' });
    if (!r.ok) return null;
    const data = await r.json();
    _wcStandings = data.groups || {};
    _wcStandingsTs = data.ts || Date.now();
    return _wcStandings;
  } catch(e) {
    captureFieldError('wc:standings', e, true);
    return null;
  }
}


