// ── resolveWCBracketTeam ─────────────────────────────────────────────────────
// Resolves one bracket slot descriptor → { name, group, tbd, is3rd }
// perGroupTable: { 'A': [{name, Pts, GF, GA, ...}, ...], 'B': [...], ... }
//   from scenarios.perGroup[X].currentTable
function resolveWCBracketTeam(slot, perGroupTable) {
  if (slot.pos === 1 || slot.pos === 2) {
    const table = perGroupTable[slot.group];
    const idx   = slot.pos - 1;
    if (!table || !table[idx] || !table[idx].name) {
      return { name: `${slot.pos===1?'W':'RU'}-${slot.group}`, group: slot.group, tbd: true };
    }
    return { name: table[idx].name, group: slot.group, tbd: false };
  }
  // Best 3rd from eligible groups (simplified Annex C pre-resolution)
  const groups = (slot.eligible || '').split('');
  const candidates = [];
  for (const g of groups) {
    const table = perGroupTable[g];
    if (table && table[2] && table[2].name) {
      candidates.push({ name: table[2].name, group: g, Pts: table[2].Pts||0,
        GD: (table[2].GF||0)-(table[2].GA||0), GF: table[2].GF||0 });
    }
  }
  if (!candidates.length) return { name: `Best 3rd (${slot.eligible})`, group:'', tbd: true, is3rd: true };
  candidates.sort((a,b) => (b.Pts-a.Pts) || (b.GD-a.GD) || (b.GF-a.GF));
  return { name: candidates[0].name, group: candidates[0].group, tbd: false, is3rd: true,
    eligibleNote: slot.eligible };
}

// ── renderWCConditionalBracket ───────────────────────────────────────────────
// Renders all 16 R32 matchups using current group standings.
// "If today's results hold" — one concrete bracket, most-likely path.
// Handles early-tournament state where groups have 0 games played (shows TBD gracefully).
// advancementState — maps pR32 probability to named advancement state.
// Live DOM: named label only. Debrief DOM (game final): label + pct.
// Thresholds match relay's advancementState in context-assembler.js.
function advancementState(prob) {
  if (prob <= 0)    return { label: 'ELIMINATED',   cls: 'state-elim' };
  if (prob < 0.15)  return { label: 'LIFE SUPPORT', cls: 'state-danger' };
  if (prob < 0.40)  return { label: 'DANGER',       cls: 'state-caution' };
  if (prob < 0.70)  return { label: 'ALIVE',        cls: 'state-info' };
  if (prob < 0.90)  return { label: 'STRONG',       cls: 'state-watch' };
  return                   { label: 'THROUGH',      cls: 'state-through' };
}

// ── renderWCTournamentBracket ──────────────────────────────────────────────────
// Primary Bracket tab renderer. Shows tournament path probabilities for all 48
// teams (from relay /wc/projections), daily movers, and journalism brief.
// Falls back gracefully when data is pending (relay computing first run).
// Also retains the conditional R32 matchup view as a secondary section.
async function renderWCTournamentBracket() {
  const el = document.getElementById('wc-bracket');
  if (!el) return;
  el.innerHTML = '<div class="wc-proj-loading">Computing tournament projections…</div>';
  const RELAY = typeof V2_RELAY_BASE !== 'undefined'
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  try {
    // Fetch projections, movers, brief, bracket traps in parallel
    // Third-place ranking now comes from projData (computed from live standings)
    const [projRes, moversRes, briefRes, trapsRes, elimTrapsRes] = await Promise.allSettled([
      fetch(`${RELAY}/wc/projections`,       { cache: 'no-store' }),
      fetch(`${RELAY}/wc/movers`,            { cache: 'no-store' }),
      fetch(`${RELAY}/wc/brief/tournament`,  { cache: 'no-store' }),
      fetch(`${RELAY}/wc/traps`,             { cache: 'no-store' }),
      fetch(`${RELAY}/wc/elimination-traps`, { cache: 'no-store' }),
    ]);
    const projData     = projRes.status     === 'fulfilled' && projRes.value.ok     ? await projRes.value.json()     : null;
    const moversData   = moversRes.status   === 'fulfilled' && moversRes.value.ok   ? await moversRes.value.json()   : null;
    const briefData    = briefRes.status    === 'fulfilled' && briefRes.value.ok    ? await briefRes.value.json()    : null;
    const trapsData    = trapsRes.status    === 'fulfilled' && trapsRes.value.ok    ? await trapsRes.value.json()    : null;
    const elimTrapsData = elimTrapsRes?.status === 'fulfilled' && elimTrapsRes.value.ok ? await elimTrapsRes.value.json() : null;

    let html = '';

    // 1. Journalism brief
    if (briefData?.text) {
      html += `<div class="wc-proj-brief"><div class="wc-proj-brief-head">Tournament Outlook</div>${briefData.text}</div>`;
    }

    // 2. Movers section
    const movers = moversData?.movers ?? moversData;
    if (movers && (movers.gainers?.length || movers.secondaryBeneficiaries?.length)) {
      html += `<div class="wc-movers"><div class="wc-movers-head">Today’s Movers</div>`;
      const allMovers = [
        ...(movers.gainers || []).map(d => ({...d, kind:'played'})),
        ...(movers.losers  || []).map(d => ({...d, kind:'played'})),
        ...(movers.secondaryBeneficiaries || []).map(d => ({...d, kind:'secondary'})),
        ...(movers.secondaryLosers || []).map(d => ({...d, kind:'secondary'})),
      ].sort((a,b) => Math.abs(b.deltaFinal) - Math.abs(a.deltaFinal)).slice(0, 8);
      for (const d of allMovers) {
        const up    = d.deltaFinal > 0;
        const pct   = v => `${Math.round(v * 100)}%`;
        const arrow = up ? '↑' : '↓';
        const cls   = up ? 'up' : 'down';
        html += `<div class="wc-mover-row">
          <div class="wc-mover-team">${d.name}</div>
          <div class="wc-mover-delta ${cls}">${arrow}${pct(Math.abs(d.deltaFinal))} to Final</div>
          ${d.kind==='secondary'?'<div class="wc-mover-secondary">did not play</div>':''}
        </div>`;
      }
      html += `</div>`;
    }

    // 2b. Best 8 third-place ranking (from projections — live with every goal)
    const thirdTeams = projData?.thirdPlaceRanking;
    if (thirdTeams?.length) {
      html += `<div class="wc-third-place"><div class="wc-third-head">Best 8 Third-Place · Best 8 third-place teams also advance</div>`;
      html += `<div class="wc-third-table-wrap"><table class="wc-third-table">`;
      html += `<thead><tr><th class="left"></th><th class="left">Team</th><th>Grp</th><th>Pts</th><th>GD</th><th>GF</th></tr></thead><tbody>`;
      for (let i = 0; i < thirdTeams.length; i++) {
        const t = thirdTeams[i];
        const qualifying = i < 8;
        const cutline = i === 7;
        html += `<tr class="${qualifying ? 'wc-third-in' : 'wc-third-out'}">`;
        html += `<td class="wc-third-rank">${i + 1}.</td>`;
        html += `<td class="wc-third-team">${t.team}</td>`;
        html += `<td class="wc-third-grp">${t.group_id}</td>`;
        html += `<td>${t.points}</td>`;
        html += `<td>${t.gd >= 0 ? '+' : ''}${t.gd}</td>`;
        html += `<td>${t.gf}</td>`;
        html += `</tr>`;
        if (cutline) {
          html += `<tr class="wc-third-cutline"><td colspan="6"><span>── qualifying cutline ──</span></td></tr>`;
        }
      }
      html += `</tbody></table></div></div>`;
    }

    // 3. Probability table
    const teams = projData?.teams;
    // CC-CMD-2026-06-16 (odds-quota pivot, Task 2): share the projections
    // payload with the WC WP bar (buildWCBars) so P(advance) reads pR32
    // without issuing a second fetch.
    if (teams?.length && typeof _wcProjectionsApplyTeams === 'function') {
      try { _wcProjectionsApplyTeams(teams); } catch (_) {}
    }
    if (teams?.length) {
      const pct = v => Math.round(v * 100);
      const cls = v => v >= 0.5 ? 'hi' : v >= 0.15 ? 'mid' : 'lo';
      const stateLabel = v => advancementState(v).label;
      const stateCls   = v => advancementState(v).cls;
      const N = projData.N || 0;
      const ts = projData.generatedAt ? new Date(projData.generatedAt).toLocaleTimeString('en-US', {hour:'2-digit',minute:'2-digit'}) : '';
      html += `<p class="wc-bracket-note">Path probabilities · ${N.toLocaleString()} simulations${ts ? ' · ' + ts : ''}</p>`;
      html += `<div class="wc-proj-table-wrap"><table class="wc-proj-table">
        <thead><tr>
          <th class="left">Team</th><th>Grp</th>
          <th>R32</th><th>R16</th><th>QF</th><th>SF</th><th>Final</th><th>Win</th>
        </tr></thead><tbody>`;
      for (const t of teams) {
        html += `<tr>
          <td class="team-cell">${t.name}</td>
          <td class="grp">${t.group}</td>
          <td><span class="wc-proj-state ${stateCls(t.pR32)}" title="${pct(t.pR32)}%">${stateLabel(t.pR32)}</span></td>
          <td><span class="wc-proj-pct ${cls(t.pR16)}">${pct(t.pR16)}%</span></td>
          <td><span class="wc-proj-pct ${cls(t.pQF)}">${pct(t.pQF)}%</span></td>
          <td><span class="wc-proj-pct ${cls(t.pSF)}">${pct(t.pSF)}%</span></td>
          <td><span class="wc-proj-pct ${cls(t.pFinal)}">${pct(t.pFinal)}%</span></td>
          <td><span class="wc-proj-pct ${cls(t.pChamp)}">${pct(t.pChamp)}%</span></td>
        </tr>`;
      }
      html += `</tbody></table></div>`;
      // Bracket traps — finish lower, go further
      const traps = trapsData?.bracketTraps || projData?.bracketTraps || [];
      if (traps.length) {
        html += `<div class="wc-traps"><div class="wc-traps-head">⚠ Bracket Traps — finishing 2nd beats finishing 1st</div>`;
        for (const t of traps.slice(0, 5)) {
          const delta = Math.round(t.delta * 100);
          html += `<div class="wc-trap-row">
            <span class="wc-trap-team">${t.team}</span>
            <span class="wc-trap-grp">Grp ${t.group}</span>
            <span class="wc-trap-stat">1st→Win <strong>${Math.round(t.pChampIf1st*100)}%</strong></span>
            <span class="wc-trap-stat">2nd→Win <strong>${Math.round(t.pChampIf2nd*100)}%</strong></span>
            <span class="wc-trap-delta">+${delta}pp if 2nd</span>
          </div>`;
        }
        html += `</div>`;
      }

      // Elimination traps — idle teams at risk from today's other games
      const elimTraps = elimTrapsData?.traps || [];
      if (elimTraps.length) {
        html += `<div class="wc-traps"><div class="wc-traps-head">🚨 Elimination Risk — at risk from today’s other games</div>`;
        for (const t of elimTraps) {
          html += `<div class="wc-trap-row">
            <span class="wc-trap-team">${t.team}</span>
            <span class="wc-trap-grp">Grp ${t.group}</span>
            <span class="wc-trap-stat"><strong>${t.type === 'ELIMINATION_TRAP' ? 'ELIMINATION' : 'DANGER'}</strong></span>
            <span class="wc-trap-delta" style="color:${t.type === 'ELIMINATION_TRAP' ? '#ef4444' : '#f97316'}">${t.type === 'ELIMINATION_TRAP' ? '☠' : '⚠'}</span>
          </div>`;
        }
        html += `</div>`;
      }
    } else if (projData?.pending) {
      html += `<div class="wc-proj-loading">Computing projections — check back in 30 seconds</div>`;
    } else {
      // First run / no data yet — show the conditional R32 matchup view as fallback
      if (window._wcLastStandings) {
        renderWCConditionalBracket(window._wcLastStandings, window._wcLastMatchResults,
          window._wcLastOddsProbs, window._wcLastLiveGames);
        return; // renderWCConditionalBracket sets innerHTML itself
      } else {
        html += `<div class="wc-proj-loading">Tournament projections not yet available</div>`;
      }
    }
    el.innerHTML = html;
  } catch(e) {
    el.innerHTML = `<div class="wc-proj-loading">Projections unavailable — ${e.message}</div>`;
  }
}

// Keep renderWCConditionalBracket as the R32 matchup fallback view
function renderWCConditionalBracket(standings, matchResults, oddsProbs, liveGames) {
  const el = document.getElementById('wc-bracket');
  if (!el) return;
  const scenarios = typeof _wcComputeAllScenarios === 'function'
    ? _wcComputeAllScenarios(standings, matchResults, null, oddsProbs, liveGames) : null;
  const perGroupTable = {};
  if (scenarios?.perGroup) {
    for (const [g, s] of Object.entries(scenarios.perGroup)) {
      perGroupTable[g] = s.currentTable || [];
    }
  }
  for (const [g, rows] of Object.entries(standings || {})) {
    if (!perGroupTable[g] && Array.isArray(rows)) perGroupTable[g] = rows;
  }
  const byDate = {};
  for (const slot of WC_R32_SLOTS) {
    if (!byDate[slot.date]) byDate[slot.date] = [];
    byDate[slot.date].push(slot);
  }
  let html = '<p class="wc-bracket-note">If current standings hold — updated live</p>';
  for (const [date, slots] of Object.entries(byDate)) {
    html += `<div class="wc-bracket-section-head">${date}</div><div class="wc-r32-grid">`;
    for (const slot of slots) {
      const home = resolveWCBracketTeam(slot.home, perGroupTable);
      const away = resolveWCBracketTeam(slot.away, perGroupTable);
      const posLabel = p => p===1?'W':p===2?'RU':'3rd';
      html += `<div class="wc-r32-card">
        <div class="wc-r32-match-num">Match ${slot.match}</div>
        <div class="wc-r32-team${home.tbd?' tbd':''}">${home.name}${home.group&&!home.tbd?`<span class="wc-r32-group-tag">${posLabel(slot.home.pos)}${home.group}</span>`:''}</div>
        <div class="wc-r32-vs">vs</div>
        <div class="wc-r32-team${away.tbd?' tbd':''}">${away.name}${away.group&&!away.tbd?`<span class="wc-r32-group-tag">${away.is3rd?'3rd-'+away.group:posLabel(slot.away.pos)+away.group}</span>`:''}</div>
        <div class="wc-r32-meta">${slot.date}</div>
      </div>`;
    }
    html += '</div>';
  }
  el.innerHTML = html;
}

function switchWCTab(tab) {
  const grpsEl    = (_DOM?.wcGroups || document.getElementById('wc-groups'));
  const bracketEl = document.getElementById('wc-bracket');
  const grpBtn    = document.getElementById('wc-tab-groups-btn');
  const bktBtn    = document.getElementById('wc-tab-bracket-btn');
  if (tab === 'bracket') {
    grpsEl?.setAttribute('hidden', '');
    bracketEl?.removeAttribute('hidden');
    grpBtn?.classList.remove('active');
    bktBtn?.classList.add('active');
    // At tablet landscape+ (≥1180px): render visual bracket tree
    // Below 1180px: render probability table
    const isWide = typeof window !== 'undefined' && window.matchMedia('(min-width:1180px)').matches;
    if (isWide && typeof renderWCBracketTree === 'function') {
      renderWCBracketTree().catch(() => {
        renderWCTournamentBracket().catch(() => {});
      });
    } else {
      renderWCTournamentBracket().catch(() => {
        // fallback to conditional bracket if projection fetch fails
        if (window._wcLastStandings) {
          renderWCConditionalBracket(window._wcLastStandings, window._wcLastMatchResults,
            window._wcLastOddsProbs, window._wcLastLiveGames);
        }
      });
    }
  } else {
    bracketEl?.setAttribute('hidden', '');
    grpsEl?.removeAttribute('hidden');
    grpBtn?.classList.add('active');
    bktBtn?.classList.remove('active');
  }
}

// Toggle WC view — mirrors toggleJournalismView()
function toggleWCView() {
  const isWC = document.body.classList.toggle('wc-mode');
  const navLink = document.getElementById('wc-nav-link');
  const section = document.getElementById('wc-section');
  if (isWC) {
    navLink?.classList.add('active');
    section?.removeAttribute('hidden');
    if (section) section.style.display = 'block'; // belt-and-suspenders: iOS Safari hidden attribute
    // Mutual exclusion: dismiss journalism-mode if active. Re-add hidden
    // attribute to its section so CSS body:not(.journalism-mode) #field-journalism-section{display:none}
    // is reinforced even if a later style override clears the rule.
    if (document.body.classList.contains('journalism-mode')) {
      document.body.classList.remove('journalism-mode');
      const _jrnNavLnk = document.getElementById('jrn-nav-link');
      if (_jrnNavLnk) _jrnNavLnk.classList.remove('active');
    }
    const jrnSec = document.getElementById('field-journalism-section');
    if (jrnSec) { jrnSec.setAttribute('hidden', ''); jrnSec.style.display = ''; }
    // Mutual exclusion: dismiss pickem-mode too (CC-CMD-2026-07-05-pick-em-reconcile — 3-way now).
    if (document.body.classList.contains('pickem-mode')) {
      document.body.classList.remove('pickem-mode');
      const _pickemNavLnk = document.getElementById('pickem-nav-link');
      if (_pickemNavLnk) _pickemNavLnk.classList.remove('active');
    }
    const pickemSec = document.getElementById('pickem-section');
    if (pickemSec) { pickemSec.setAttribute('hidden', ''); pickemSec.style.display = ''; }
    renderWCSection();
    // Subscribe to BSD for any live WC game with bsdEventId
    setTimeout(_bsdActivateForWC, 500); // defer 500ms — let V2 poll populate espnScores first
  } else {
    navLink?.classList.remove('active');
    section?.setAttribute('hidden', '');
    if (section) section.style.display = ''; // clear inline override
    // Close BracketDO WebSocket — no bracket updates needed off-screen
    if (window._bracketWS) window._bracketWS.close();
    // Unsubscribe BSD WebSocket fan-out
    _bsdDeactivate();
  }
}

// ── Pick 'em top-level surface (CC-CMD-2026-07-05-pick-em-reconcile) ────────
// Third mode, mirroring toggleWCView()'s exact shape (the simpler of the
// two existing precedents, per the surface-design doc's own recommendation
// docs/design-pick-em-surface-2026-07-05.md). Cross-sport by design, so it
// is NOT nested inside wc-mode or any other single-sport surface.
function togglePickEmView() {
  const isPickEm = document.body.classList.toggle('pickem-mode');
  const navLink = document.getElementById('pickem-nav-link');
  const section = document.getElementById('pickem-section');
  if (isPickEm) {
    navLink?.classList.add('active');
    section?.removeAttribute('hidden');
    if (section) section.style.display = 'block'; // belt-and-suspenders: iOS Safari hidden attribute
    // Mutual exclusion: dismiss journalism-mode if active.
    if (document.body.classList.contains('journalism-mode')) {
      document.body.classList.remove('journalism-mode');
      const _jrnNavLnk = document.getElementById('jrn-nav-link');
      if (_jrnNavLnk) _jrnNavLnk.classList.remove('active');
    }
    const jrnSec = document.getElementById('field-journalism-section');
    if (jrnSec) { jrnSec.setAttribute('hidden', ''); jrnSec.style.display = ''; }
    // Mutual exclusion: dismiss wc-mode if active.
    if (document.body.classList.contains('wc-mode')) {
      document.body.classList.remove('wc-mode');
      const _wcNavLnk = document.getElementById('wc-nav-link');
      if (_wcNavLnk) _wcNavLnk.classList.remove('active');
    }
    const wcSec = document.getElementById('wc-section');
    if (wcSec) { wcSec.setAttribute('hidden', ''); wcSec.style.display = ''; }
    renderPickEmSection();
  } else {
    navLink?.classList.remove('active');
    section?.setAttribute('hidden', '');
    if (section) section.style.display = ''; // clear inline override
  }
}

// Builds the pick 'em surface's content: every currently-known game across
// all sports that's in the PREVIEW circadian tier (upcoming, pickable),
// rendered via the existing buildPickWidgetHTML() -- reused as-is, not
// rebuilt (CC-CMD-2026-07-05-pick-em-reconcile TASK 2). Reads from
// allData.sports, the same source renderAll() reads from, so this always
// reflects the current schedule without a separate fetch.
function renderPickEmSection() {
  const content = document.getElementById('pickem-content');
  if (!content) return;
  const games = [];
  (allData?.sports || []).forEach(sec => {
    (sec.games || []).forEach(g => {
      // Same ID-assignment convention renderAll's own per-card loop uses
      // (index.html ~10831) -- games outside the main feed's current
      // filter (activeFilter/myTeamsFilter/etc.) may never have passed
      // through that loop, so g._id can genuinely be unset here. Assign
      // before any circadian computation, matching renderAll's own order.
      if (!g._id) g._id = "g" + (++_gid);
      const _circEData = typeof findESPNScore === 'function' ? findESPNScore(g) : null;
      const _circInput = { state: (_circEData ? _circEData.state : null) ?? g.state ?? null, status: g.status, _aflComplete: g._aflComplete, _id: g._id };
      if (typeof getCardCircadian === 'function' && getCardCircadian(_circInput) === 'PREVIEW') {
        games.push({ g, sport: g.sport || sec.sport });
      }
    });
  });

  // Stats + resolved picks from localStorage cache.
  // Cache stores predictedWinner/home/away/sport/wasCorrect per resolved entry.
  const { statsHTML, resolvedHTML } = (() => {
    const esc = s => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;');
    const cache = typeof _getPickCache === 'function' ? _getPickCache() : {};
    const resolved = Object.entries(cache).filter(([, p]) => p.resolved);
    if (!resolved.length) return { statsHTML: '', resolvedHTML: '' };

    // Aggregate overall, by sport, by team
    const overall = { w: 0, l: 0 };
    const bySport = {};
    const byTeam  = {};
    resolved.forEach(([, p]) => {
      const w = p.wasCorrect;
      overall[w ? 'w' : 'l']++;
      const sp = (p.sport || 'Other').replace(/\s*\(.*\)/, '').trim(); // strip "(MLB)" suffixes
      bySport[sp] = bySport[sp] || { w: 0, l: 0 };
      bySport[sp][w ? 'w' : 'l']++;
      const tm = p.predictedWinner || '';
      if (tm) {
        byTeam[tm] = byTeam[tm] || { w: 0, l: 0 };
        byTeam[tm][w ? 'w' : 'l']++;
      }
    });

    const rec = (o) => {
      const pct = o.w + o.l > 0 ? Math.round(100 * o.w / (o.w + o.l)) : 0;
      return `<span class="pickem-stat-rec">${o.w}-${o.l}</span><span class="pickem-stat-pct">${pct}%</span>`;
    };
    const overallLine = `<div class="pickem-stat-row pickem-stat-overall"><span class="pickem-stat-label">Overall</span>${rec(overall)}</div>`;

    const sportLines = Object.entries(bySport).sort((a,b) => (b[1].w+b[1].l)-(a[1].w+a[1].l))
      .map(([sp, o]) => `<div class="pickem-stat-row"><span class="pickem-stat-label">${esc(sp)}</span>${rec(o)}</div>`).join('');

    const teamLines = Object.entries(byTeam).sort((a,b) => (b[1].w+b[1].l)-(a[1].w+a[1].l))
      .map(([tm, o]) => `<div class="pickem-stat-row"><span class="pickem-stat-label">${esc(tm)}</span>${rec(o)}</div>`).join('');

    const statsHTML = `<div class="pickem-results-head">Record</div>
      <div class="pickem-stats-block">
        ${overallLine}
        ${sportLines ? `<div class="pickem-stat-group-head">By Sport</div>${sportLines}` : ''}
        ${teamLines  ? `<div class="pickem-stat-group-head">By Team</div>${teamLines}`   : ''}
      </div>`;

    const rows = resolved.map(([key, p]) => {
      const matchup = (p.away && p.home) ? `${esc(p.away)} @ ${esc(p.home)}` : '';
      const widgetHTML = typeof buildPickWidgetHTML === 'function'
        ? buildPickWidgetHTML({ _id: key, home: p.home || '', away: p.away || '' }, p.sport || '')
        : '';
      return `<div class="pickem-row">${matchup ? `<div class="pickem-matchup">${matchup}</div>` : ''}${widgetHTML}</div>`;
    }).join('');
    const resolvedHTML = `<div class="pickem-results-head">Results</div>${rows}`;

    return { statsHTML, resolvedHTML };
  })();

  if (!games.length && !resolvedHTML) {
    content.innerHTML = '<div class="pickem-empty">No upcoming games to pick right now — check back closer to game time.</div>';
    return;
  }
  const upcomingHTML = games.length
    ? games.map(({ g, sport }) =>
        `<div class="pickem-row"><div class="pickem-matchup">${(g.away||'').replace(/</g,'&lt;')} @ ${(g.home||'').replace(/</g,'&lt;')}</div>${typeof buildPickWidgetHTML === 'function' ? buildPickWidgetHTML(g, sport) : ''}</div>`
      ).join('')
    : '<div class="pickem-empty">No upcoming games to pick right now.</div>';
  content.innerHTML = upcomingHTML + statsHTML + resolvedHTML;
}

// ── BSD pitch helpers (2026-06-25) ────────────────────────────────────────
// Vanilla JS. Extends existing _es SSE singleton (no second EventSource).
// Subscribe/unsubscribe lifecycle tied to wc-mode panel state.

// Track active BSD subscription
var _bsdActiveId = null;
var _bsdShotData = [];
var _bsdBallPos  = null;

// Called on bsd:ball and bsd:stats frames from _onMessage
function _bsdOnSSEFrame(type, data) {
  if (type === 'bsd:ball') {
    _bsdBallPos = data;
    _bsdRepaint();
  } else if (type === 'bsd:stats') {
    const _bsdShots = data.shots || data.shotmap; if (Array.isArray(_bsdShots)) { _bsdShotData = _bsdShots; _bsdRepaint(); }
  }
}

// Subscribe to BSD WebSocket via AmbientDO
function _bsdActivate(eventId) {
  if (_bsdActiveId === eventId) return;
  _bsdActiveId = eventId;
  var base = (typeof V2_RELAY_BASE !== 'undefined') ? V2_RELAY_BASE : '';
  fetch(base + '/ambient/bsd/subscribe', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ event_id: eventId }),
  }).catch(function() {});
}

// Unsubscribe when leaving WC view
function _bsdDeactivate() {
  if (!_bsdActiveId) return;
  var base = (typeof V2_RELAY_BASE !== 'undefined') ? V2_RELAY_BASE : '';
  fetch(base + '/ambient/bsd/unsubscribe', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ event_id: _bsdActiveId }),
  }).catch(function() {});
  _bsdActiveId = null;
  _bsdBallPos  = null;
  _bsdShotData = [];
}

// Find any live BSD-covered game with bsdEventId and subscribe (CC-CMD-
// 2026-07-14-bsd-pitch-generalize -- no longer WC-only; bsdEventId is the
// authoritative "BSD covers this exact game right now" signal, same as
// WC26). Name kept for now -- still only ever triggered from
// toggleWCView()'s WC-entry branch (see setTimeout call below), so this
// only widens what it picks up while the WC tab happens to be open.
function _bsdActivateForWC() {
  try {
    if (typeof espnScores === 'undefined') return;
    var entry = null;
    Object.keys(espnScores).forEach(function(k) {
      var s = espnScores[k];
      if (s && s.state === 'in' && s.bsdEventId && !entry) {
        entry = s;
      }
    });
    if (entry) _bsdActivate(entry.bsdEventId);
  } catch (_e) {}
}

// SVG pitch renderer — called on each bsd:ball / bsd:stats frame
function _bsdRepaint() {
  var el = document.getElementById('bsd-pitch');
  if (!el) return;
  var W = el.clientWidth  || 300;
  var H = Math.round(W * 0.667);
  var shots = (_bsdShotData || []).map(function(s) {
    var cx = s.x * W / 100;
    var cy = (100 - s.y) * H / 100;
    var r  = 3 + (s.xg || 0) * 10;
    var col = s.team === 'home' ? 'rgba(99,179,237,0.75)' : 'rgba(252,129,74,0.75)';
    return '<circle cx="'+cx+'" cy="'+cy+'" r="'+r+'" fill="'+col+'" stroke="rgba(255,255,255,0.4)" stroke-width="0.8"/>';
  }).join('');
  var ball = '';
  if (_bsdBallPos && _bsdBallPos.x != null) {
    var bx = _bsdBallPos.x * W / 100;
    var by = (100 - _bsdBallPos.y) * H / 100;
    ball = '<circle cx="'+bx+'" cy="'+by+'" r="5" fill="#fff" stroke="rgba(0,0,0,0.4)" stroke-width="1"/>';
  }
  el.innerHTML =
    '<svg width="'+W+'" height="'+H+'" viewBox="0 0 '+W+' '+H+'" style="display:block;background:#2d5a27;border-radius:6px">'+
    '<rect x="'+W*.05+'" y="'+H*.05+'" width="'+W*.9+'" height="'+H*.9+'" fill="none" stroke="rgba(255,255,255,0.35)" stroke-width="1.5"/>'+
    '<line x1="'+W/2+'" y1="'+H*.05+'" x2="'+W/2+'" y2="'+H*.95+'" stroke="rgba(255,255,255,0.35)" stroke-width="1.5"/>'+
    '<circle cx="'+W/2+'" cy="'+H/2+'" r="'+Math.min(W,H)*.1+'" fill="none" stroke="rgba(255,255,255,0.35)" stroke-width="1.5"/>'+
    shots + ball +
    '</svg>';
}

// openWcGroup — bridge from a schedule WC card to the in-mode Groups view.
// Activates wc-mode (if not already), selects the Groups sub-tab, scrolls
// the matching .wc-group-block[data-group="X"] into view, and flashes a
// gold border for 600ms so the destination is obvious after the scroll.
// Wired from the group pill (rendered in the WC card builder) and called
// with stopPropagation so the surrounding card click doesn't fire.
function openWcGroup(letter) {
  if (!letter) return;
  const wasInWc = document.body.classList.contains('wc-mode');
  if (!wasInWc && typeof toggleWCView === 'function') toggleWCView();
  if (typeof switchWCTab === 'function') switchWCTab('groups');
  // Allow the WC section to render (renderWCSection runs inside toggleWCView)
  // before we look for the target block. requestAnimationFrame is enough on
  // a warm cache; cold renders settle within the 80ms timeout below.
  const scrollTo = () => {
    const target = document.querySelector(`.wc-group-block[data-group="${letter}"]`);
    if (!target) return false;
    try { target.scrollIntoView({behavior:'smooth', block:'start'}); } catch(_) { target.scrollIntoView(); }
    target.classList.add('group-highlight');
    setTimeout(() => target.classList.remove('group-highlight'), 600);
    return true;
  };
  if (!scrollTo()) {
    setTimeout(scrollTo, wasInWc ? 0 : 80);
  }
}

// Entry point — called by toggleWCView
// ── WC Journalism Tab Brief ───────────────────────────────────────────────────
// AI-generated preview injected above #wc-groups in the WC tab.
// Enqueues to relay journalism pipeline (which already has full WC team context
// from wc-team-context.js) — zero extra context work needed client-side.
// Cache: sessionStorage by date so it regenerates each day.
// Pattern: same enqueue+poll as Finals Desk (b9cd159).
async function fetchWCTabBrief(wcGames) {
  if (!wcGames || !wcGames.length || !JOURNALISM_ENQUEUE_RELAY) return null;
  const dateKey = TODAY_ISO || new Date().toISOString().slice(0, 10);
  const cacheKey  = `field_wc_tab_brief_v${_swv}_${dateKey}`;
  const jobIdKey  = `field_wc_tab_job_v${_swv}_${dateKey}`;
  // 1. Cached text → return immediately
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached && cached.length > 60) return cached;
  } catch(e_) {}
  // 2. Build game summary for prompt (team names + kickoff times only)
  const gameLines = wcGames.slice(0, 4).map(g => {
    const t = g.start_time ? fmtTime(g.start_time) : 'TBD';
    const net = g.nationalBundle === 'WC26_FREE' ? 'FOX/Tubi FREE'
              : g.nationalBundle === 'WC26_FS1'  ? 'FS1'
              : g.nationalBundle === 'WC26_FOX'  ? 'FOX'
              : 'FOX/FS1';
    const league = (g.league || '').replace('FIFA World Cup 2026 — ', '').replace('FIFA World Cup 2026', 'Group Stage');
    return `${g.away} vs ${g.home} · ${t} ET · ${net} · ${league}`;
  });
  // 3. Check for in-flight job
  let jobId = null;
  try { jobId = sessionStorage.getItem(jobIdKey); } catch(e_) {}
  if (!jobId) {
    // 4. Enqueue — relay injects WC team context at prompt time
    try {
      const prompt = [
        'Write a FIELD World Cup Today brief for the group stage action below.',
        '',
        'TODAY’S MATCHES:',
        ...gameLines.map(l => '- ' + l),
        '',
        'Rules:',
        '- 60-80 words. 1-2 short paragraphs. No headers. No bullet points.',
        '- Lead with the most interesting matchup or storyline across today’s slate.',
        '- Name specific teams and what’s at stake (advancement, elimination, Group rivalry).',
        '- Note any free broadcasts (Tubi/FOX) if relevant to fan access.',
        '- Plain prose. Write like a well-prepared friend explaining what to watch today.',
        '- CORRECTNESS: write only from match data above + your knowledge of these teams.',
        '- Never use: "must-watch", "clash", "showdown", "battle", "epic".',
      ].join('\n');
      const eq = await fetch(JOURNALISM_ENQUEUE_RELAY, {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        // Deliberately no home/away/matchupNote (CC-CMD-2026-07-14-wc-tab-
        // brief-context-doc): unlike scouts-pick/finals-desk/night-owl --
        // each a single-game brief, fixed this month for the same enqueue-
        // context-gap bug -- wc-tab-brief summarizes up to 4 games in one
        // prompt (gameLines above), so there's no single game to anchor
        // Context Anchoring/Matchup Depth to. Same shape as the relay's
        // own cron-slate path, which passes sport: null with no single-
        // game context for the identical reason. Not an oversight.
        body: JSON.stringify({
          prompt,
          sport: 'soccer',
          briefType: 'wc-tab-brief',
          max_tokens: 350,
          // scoreThreshold 240 -- see generateJournalismViaRelay's comment
          // (CC-CMD-2026-07-09-jq-threshold-240-migration).
          scoreThreshold: 240,
        }),
      });
      if (eq.ok) {
        const data = await eq.json();
        if (data.jobId) {
          try { sessionStorage.setItem(jobIdKey, data.jobId); } catch(e_) {}
          jobId = data.jobId;
        }
      }
    } catch(e_) { captureFieldError('journalism:wc-tab-brief-enqueue', e_, true); }
  }
  // 5. Poll for result (max 20s)
  if (jobId && JOURNALISM_RESULT_RELAY) {
    for (let i = 0; i < 10; i++) {
      await new Promise(r => setTimeout(r, 2000));
      try {
        const pr = await fetch(`${JOURNALISM_RESULT_RELAY}/${jobId}`,
          {signal: AbortSignal.timeout(3000)});
        if (!pr.ok) continue;
        const result = await pr.json();
        if (result.status === 'done' && result.text && result.text.length > 40) {
          try { sessionStorage.setItem(cacheKey, result.text); } catch(e_) {}
          try { archiveBrief('wc_tab', 'FIFA World Cup 2026', null, result.text, null); } catch(_){}
          try { sessionStorage.removeItem(jobIdKey); } catch(e_) {}
          return result.text;
        }
        if (result.status === 'failed') break;
      } catch(e_) { captureFieldError('journalism:wc-tab-brief-poll', e_, true); }
    }
  }
  return null;
}

// ── WC mini-card ──────────────────────────────────────────────────────
// Pin the linked WC group game (same round/group, also live) as a sticky
// mini-card at the top of #main during MD3 simultaneous kickoffs. Tap to
// scroll to the full card.
function getLinkedWCGame(currentGame, allGames) {
  if (!currentGame || !Array.isArray(allGames)) return null;
  const isWC = g => /world cup|fifa|wc26/i.test(g?.sport || g?._sport || g?.league || '');
  if (!isWC(currentGame)) return null;
  return allGames.find(g => g !== currentGame
    && isWC(g)
    && g.round === currentGame.round
    && (g.state === 'in' || g.state === 'live')
  ) || null;
}
function renderWCMiniCard(linkedGame) {
  const existing = document.getElementById('wc-mini-card');
  if (!linkedGame) {
    if (existing) existing.remove();
    return;
  }
  const card = existing || document.createElement('div');
  card.id = 'wc-mini-card';
  card.className = 'wc-mini-card';
  const hScore = linkedGame.homeScore != null ? linkedGame.homeScore : '–';
  const aScore = linkedGame.awayScore != null ? linkedGame.awayScore : '–';
  const detail = ((linkedGame.period || '') + ' ' + (linkedGame.clock || '')).trim();
  card.innerHTML =
    '<span class="mini-teams">' + (linkedGame.home || '') + ' ' + hScore +
    ' – ' + aScore + ' ' + (linkedGame.away || '') + '</span>' +
    '<span class="mini-detail">' + detail + '</span>';
  card.onclick = () => {
    const target = linkedGame._gameId || linkedGame._id;
    if (!target) return;
    const fullCard = document.querySelector('.game-card[data-gameid="' + target + '"]');
    if (fullCard) fullCard.scrollIntoView({ behavior: 'smooth', block: 'center' });
  };
  if (!existing) {
    const schedule = document.getElementById('main');
    if (schedule) schedule.insertBefore(card, schedule.firstChild);
  }
}

// ── CASCADE narrative ──────────────────────────────────────────────────
// Consumes the BracketDO bracket:updated payload when a LIVE WC goal
// produced cross-group shifts. Picks the top 3 teams in OTHER groups
// whose pChamp moved by at least 0.5pp and renders a small ripple panel
// at the top of the bracket tab.
//
// RUWT-clean: each line is a labelled team + a numeric delta from the
// relay's delta object. No drama math, no composite scoring.
function renderCascadeNarrative(bracketUpdate) {
  const delta = bracketUpdate && bracketUpdate.delta;
  if (!delta || !delta.shifts || !delta.shifts.length) return;
  const sourceGroup = bracketUpdate.sourceGroup || '';
  const ripples = (delta.shifts || [])
    .filter(s => s && s.group !== sourceGroup && Math.abs(s.pChampDelta || 0) >= 0.005)
    .sort((a, b) => Math.abs(b.pChampDelta) - Math.abs(a.pChampDelta))
    .slice(0, 3);
  if (!ripples.length) return;

  const bracketTab = document.querySelector('.wc-bracket-panel, .bracket-tab');
  if (!bracketTab) return; // bracket tab not in the DOM yet — silent skip

  let container = document.getElementById('cascade-narrative');
  const isNew = !container;
  if (isNew) {
    container = document.createElement('div');
    container.id = 'cascade-narrative';
    container.className = 'cascade-narrative';
  }

  const lines = ripples.map(r => {
    const dir  = r.pChampDelta > 0 ? '↑' : '↓';
    const pct  = Math.abs(r.pChampDelta * 100).toFixed(1);
    const grp  = r.group ? ' (' + r.group + ')' : '';
    const team = (r.team || '').replace(/</g, '&lt;');
    return '<div class="cascade-line">' + team + grp + ' ' + dir + pct + 'pp</div>';
  }).join('');

  container.innerHTML = '<div class="cascade-header">⚡ RIPPLE EFFECTS</div>' + lines;
  if (isNew) bracketTab.insertBefore(container, bracketTab.firstChild);
}

// ── BracketDO WebSocket client ────────────────────────────────────────────────
// Connects to /wc/bracket/live when WC mode is active.
// Receives bracket:updated on every confirmed result → re-renders active tab.
// One connection for the whole WC section — not per-tab.
// Singleton: window._bracketWS. Reconnects on unexpected close (max 3 attempts).
(function() {
  const RELAY_WSS  = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev')
    .replace(/^https:/, 'wss:').replace(/^http:/, 'ws:');
  const ENDPOINT   = RELAY_WSS + '/wc/bracket/live';
  const MAX_RECONN = 3;
  const PING_MS    = 45000;

  let _ws = null, _attempts = 0, _pingTimer = null, _reconnTimer = null;

  function _clearTimers() {
    if (_pingTimer)   { clearInterval(_pingTimer);   _pingTimer   = null; }
    if (_reconnTimer) { clearTimeout(_reconnTimer);  _reconnTimer = null; }
  }

  function _setLiveIndicator(on) {
    const btn = document.getElementById('wc-tab-bracket-btn');
    if (btn) btn.classList.toggle('bracket-live', on);
  }

  function _handleMessage(data) {
    if (data && data.type === 'bracket:pong') return;
    if (!data || (data.type !== 'bracket:updated' && data.type !== 'bracket:current')) return;
    if (!document.body.classList.contains('wc-mode')) return;
    if (data.delta && data.delta.significant && data.delta.narrativeSeeds && data.delta.narrativeSeeds.length) {
      const btn = document.getElementById('wc-tab-bracket-btn');
      if (btn) btn.setAttribute('title', 'Updated: ' + data.delta.narrativeSeeds[0]);
    }
    // CASCADE narrative: when a live goal triggered this update and the
    // delta carries cross-group shifts, render a ripple panel on the
    // bracket tab. Final-only deltas (no isLive flag) silently skip.
    if (data.isLive && data.delta) {
      try { renderCascadeNarrative(data); } catch (_e) {}
    }
    const _wcBracketBtn = document.getElementById('wc-tab-bracket-btn');
    const bracketActive = _wcBracketBtn && _wcBracketBtn.classList.contains('active');
    if (bracketActive) {
      const isWide = typeof window !== 'undefined' && window.matchMedia('(min-width:1180px)').matches;
      if (isWide && typeof renderWCBracketTree === 'function') {
        renderWCBracketTree().catch(function() { if (typeof renderWCTournamentBracket === 'function') renderWCTournamentBracket().catch(function(){}); });
      } else {
        if (typeof renderWCTournamentBracket === 'function') renderWCTournamentBracket().catch(function(){});
      }
    } else {
      if (typeof renderWCSection === 'function') renderWCSection().catch(function(){});
    }
  }

  function _open() {
    if (_ws && (_ws.readyState === 0 || _ws.readyState === 1)) return;
    _clearTimers();
    try {
      _ws = new WebSocket(ENDPOINT);
      _ws.onopen = function() {
        _attempts = 0;
        _setLiveIndicator(true);
        _pingTimer = setInterval(function() {
          if (_ws && _ws.readyState === 1) _ws.send(JSON.stringify({ type: 'bracket:ping' }));
        }, PING_MS);
      };
      _ws.onmessage = function(evt) {
        try { _handleMessage(JSON.parse(evt.data)); } catch (_e) {}
      };
      _ws.onclose = function(evt) {
        _clearTimers();
        _setLiveIndicator(false);
        if (document.body.classList.contains('wc-mode') && _attempts < MAX_RECONN && !evt.wasClean) {
          _attempts++;
          _reconnTimer = setTimeout(_open, 3000 * _attempts);
        }
      };
      _ws.onerror = function() {};
    } catch (_e) {}
  }

  function _close() {
    _clearTimers();
    _setLiveIndicator(false);
    if (_ws) { _ws.onclose = null; _ws.close(1000); _ws = null; }
    _attempts = 0;
  }

  window._bracketWS = { open: _open, close: _close };
})();

async function renderWCSection() {
  const phase = getWCPhase();
  // Update title
  const title = document.getElementById('wc-title');
  const navLink = document.getElementById('wc-nav-link');
  if (phase === 'bracket') {
    if (title) title.textContent = 'Knockout Stage';
    if (navLink) navLink.textContent = '⚽ Bracket';
    // In bracket phase, auto-switch to bracket tab
    switchWCTab('bracket');
  } else {
    if (title) title.textContent = 'Group Stage';
    if (navLink) navLink.textContent = '⚽ Groups';
    // Show groups tab by default unless user previously selected bracket
    const _wcBktBtn2 = document.getElementById('wc-tab-bracket-btn');
    const activeBkt = _wcBktBtn2 && _wcBktBtn2.classList.contains('active');
    if (!activeBkt) switchWCTab('groups');
  }
  const _wcFilterPill = document.getElementById('wc-filter-pill');
  if (_wcFilterPill) _wcFilterPill.classList.toggle('active', document.body.classList.contains('wc-mode'));
  // Open BracketDO WebSocket for live bracket updates
  if (window._bracketWS) window._bracketWS.open();
  renderWCGroupsLoading();
  // Fetch all WC data in parallel
  const [standings, matchResults, oddsProbs, liveGames] = await Promise.all([
    fetchWCStandings(),
    fetchWCResults(),
    fetchWCOddsProbabilities(),
    fetchWCLiveGames(),
  ]);
  // Cache data for bracket tab re-render on tab switch
  window._wcLastStandings   = standings;
  window._wcLastMatchResults = matchResults;
  window._wcLastOddsProbs   = oddsProbs;
  window._wcLastLiveGames   = liveGames;
  // Fetch journalism brief async — don't block render
  const wcGames = allData ? (allData.sports || [])
    .filter(s => (s.sport||'').includes('FIFA'))
    .flatMap(s => s.games || []) : [];
  fetchWCTabBrief(wcGames).then(brief => {
    if (!brief) return;
    const el = _DOM?.wcGroups || document.getElementById('wc-groups');
    if (!el) return;
    let hdr = el.querySelector('.wc-preview-header');
    if (!hdr) { hdr = document.createElement('div'); hdr.className = 'wc-preview-header'; el.prepend(hdr); }
    hdr.innerHTML = `<p class="wc-preview-intro">${brief}</p>`;
  }).catch(() => {});
  // Render groups table
  // Merge D1 standings with WC_TEAMS fallback for groups without D1 data yet.
  // Normalise D1 team names (API-Sports sends "Czech Republic", display uses "Czechia").
  // Uses module-level _wcFixTeamName (shared with _wcBuildGroupInput).
  const mergedStandings = {};
  for (const g of 'ABCDEFGHIJKL'.split('')) {
    const d1Teams = (standings && standings[g]) ? standings[g].map(r => ({...r, team: _wcFixTeamName(r.team)})) : [];
    // Defensive: when the relay's D1 has multiple rows for the same team under
    // different raw names (e.g. "Czech Republic" + "Czechia" → both rename to
    // "Czechia"), aggregate them into a single row before downstream use. Sums
    // counters and recomputes derived columns (gd, points). Relay-side root
    // cause is being addressed separately; this layer makes the client
    // resilient to any current or future name collisions.
    const merged = {};
    for (const r of d1Teams) {
      if (!merged[r.team]) { merged[r.team] = {...r}; continue; }
      const m = merged[r.team];
      m.played += r.played; m.won += r.won; m.drawn += r.drawn; m.lost += r.lost;
      m.gf += r.gf; m.ga += r.ga;
      m.gd = m.gf - m.ga;
      m.points = m.won * 3 + m.drawn;
    }
    const d1Merged = Object.values(merged);
    const d1Names = new Set(d1Merged.map(r => r.team));
    const allTeams = WC_TEAMS[g] || [];
    // Start with D1 teams (have match data), then append missing teams at 0-0-0
    mergedStandings[g] = [...d1Merged];
    for (const t of allTeams) {
      if (!d1Names.has(t)) {
        mergedStandings[g].push({
          group_id: g, team: t, played: 0, won: 0, drawn: 0, lost: 0,
          gf: 0, ga: 0, gd: 0, points: 0,
        });
      }
    }
  }
  renderWCGroups(mergedStandings, matchResults, oddsProbs, liveGames);
  // If bracket tab is active, render it with fresh data
  const _wcBktBtn3 = document.getElementById('wc-tab-bracket-btn');
  if (_wcBktBtn3 && _wcBktBtn3.classList.contains('active')) {
    renderWCTournamentBracket().catch(() => {
      renderWCConditionalBracket(standings, matchResults, oddsProbs, liveGames);
    });
  }
}

// v1.3.1 — fetch match results from relay /wc/results endpoint (wc_results D1 table)
async function fetchWCResults() {
  try {
    const base = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : null)
              || 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const r = await fetch(`${base}/wc/results`, { cache: 'no-store' });
    if (!r.ok) return [];
    const data = await r.json();
    return Array.isArray(data.results) ? data.results : [];
  } catch (e) { return []; }
}

// CFL odds cache — populated by fetchCFLOddsProbs() at startup
let _cflOddsCache = []; // [{home_team, away_team, commence, pHome, pAway, spread, total, bookmakers}]
let _cflOddsFetchedAt = 0;

// Fetches no-vig win probabilities + spread/total lines for CFL games from relay /cfl/odds-probs.
// CFL has no draw — pHome + pAway = 1.0. Cached 2 min (matches relay edge TTL).
async function fetchCFLOddsProbs() {
  const now = Date.now();
  if (now - _cflOddsFetchedAt < 120000 && _cflOddsCache.length) return _cflOddsCache;
  try {
    const base = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : null)
              || 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const r = await fetch(`${base}/cfl/odds-probs`, { cache: 'no-store' });
    if (!r.ok) return _cflOddsCache;
    const d = await r.json();
    if (d.ok && Array.isArray(d.probs) && d.probs.length) {
      _cflOddsCache = d.probs;
      _cflOddsFetchedAt = now;
      if (FIELD_DEBUG) console.debug('[CFL-ODDS] fetched', d.probs.length, 'games, remaining:', d.remaining);
    }
    return _cflOddsCache;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[CFL-ODDS] fetch failed:', e.message);
    return _cflOddsCache;
  }
}

// Match a CFL game object against the odds probs array.
// Returns {pHome, pAway, spread, total} or null.
function _cflMatchOdds(game) {
  if (!_cflOddsCache.length) return null;
  const norm = s => (s||'').toLowerCase().replace(/[^a-z]/g,' ').replace(/\s+/g,' ').trim();
  const h = norm(game.home), a = norm(game.away);
  for (const p of _cflOddsCache) {
    const ph = norm(p.home_team), pa = norm(p.away_team);
    if ((ph === h && pa === a) || (ph === a && pa === h)) {
      // Handle reversed home/away in odds (rare but possible)
      const flipped = ph === a;
      return {
        pHome: flipped ? p.pAway : p.pHome,
        pAway: flipped ? p.pHome : p.pAway,
        spread: flipped ? (p.spread != null ? -p.spread : null) : p.spread,
        total: p.total,
        bookmakers: p.bookmakers,
      };
    }
  }
  return null;
}

// ── CC-CMD-2026-06-16 (odds-quota pivot): Monte Carlo WP fallback ──────────
// Odds API is exhausted; relay /wc/match-wp serves Monte Carlo-derived
// {home_team, away_team, homeWP, drawWP, awayWP}. We pull lazily when the
// primary odds-WP path is stale or missing for a WC game.
//
// Cache: keyed by `${normHome}|${normAway}`, sessionStorage persists across
// route changes within a session. 60-second fetch coalesce so multiple
// stale-WC games on the same render don't trigger 6 simultaneous requests.
const _LIVE_ODDS_WP_STALE_MS = 5 * 60 * 1000;   // spec: ">5 min"
const _WC_MATCH_WP_TTL_MS    = 60 * 1000;       // re-fetch at most every 60s
let _wcMatchWPInflight = null;
let _wcMatchWPLastFetch = 0;

// Predicate: is the odds-sourced live WP missing OR older than the staleness
// window? Used to decide whether to overlay the MC fallback.
function _isLiveOddsWPStale(score) {
  const wp = score && score._liveOddsWP;
  if (!wp) return true;
  const ts = Number(wp.ts) || 0;
  if (!ts) return true;
  return (Date.now() - ts) > _LIVE_ODDS_WP_STALE_MS;
}

// Lookup MC WP for a fixture by (home, away) — tolerant to flipped pairings.
function _lookupWCMatchWP(home, away) {
  const cache = window._wcMatchWPCache;
  if (!cache) return null;
  const hk = _normWCName(home), ak = _normWCName(away);
  return cache[`${hk}|${ak}`] || (cache[`${ak}|${hk}`]
    ? { ...cache[`${ak}|${hk}`], _flipped: true }
    : null);
}

// Fire-and-forget loader for /wc/match-wp. Idempotent within the TTL.
// Result lands in window._wcMatchWPCache, then renderESPNScores re-runs to
// repaint the bars. .catch(() => {}) on the fetch is mandatory.
function loadWCMatchWP() {
  const now = Date.now();
  if (_wcMatchWPInflight) return _wcMatchWPInflight;
  if (now - _wcMatchWPLastFetch < _WC_MATCH_WP_TTL_MS) return Promise.resolve();
  // Try sessionStorage first
  if (!window._wcMatchWPCache) {
    try {
      const raw = sessionStorage.getItem('field_wc_match_wp');
      if (raw) {
        const c = JSON.parse(raw);
        if (c && (now - (c.ts || 0)) < _WC_MATCH_WP_TTL_MS) {
          window._wcMatchWPCache = c.data || {};
        }
      }
    } catch (_) {}
  }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  _wcMatchWPLastFetch = now;
  _wcMatchWPInflight = fetch(`${base}/wc/match-wp`, { signal: AbortSignal.timeout(2500) })
    .then(r => r.ok ? r.json() : null)
    .then(payload => {
      if (!payload) return;
      const arr = Array.isArray(payload) ? payload
                : Array.isArray(payload.matches) ? payload.matches
                : Array.isArray(payload.results) ? payload.results
                : Array.isArray(payload.games) ? payload.games
                : [];
      if (!arr.length) return;
      const cache = {};
      for (const m of arr) {
        const h = m.home_team || m.home || m.homeName;
        const a = m.away_team || m.away || m.awayName;
        if (!h || !a) continue;
        const k = `${_normWCName(h)}|${_normWCName(a)}`;
        cache[k] = {
          homeWP: Number(m.homeWP ?? m.pHome ?? m.home_wp) || 0,
          drawWP: Number(m.drawWP ?? m.pDraw ?? m.draw_wp) || 0,
          awayWP: Number(m.awayWP ?? m.pAway ?? m.away_wp) || 0,
          ts: Date.now(),
          source: 'monte-carlo',
        };
      }
      window._wcMatchWPCache = cache;
      try { sessionStorage.setItem('field_wc_match_wp', JSON.stringify({ ts: Date.now(), data: cache })); } catch (_) {}
      // Repaint live cards so the fallback bars land without waiting for the
      // next ESPN poll cycle.
      try { if (typeof renderESPNScores === 'function') renderESPNScores(); } catch (_) {}
    })
    .catch(e => { captureFieldError('wc:match-wp-load', e, true); })
    .finally(() => { _wcMatchWPInflight = null; });
  return _wcMatchWPInflight;
}

// ── CC-CMD-2026-06-16 (odds-quota pivot, Task 2): /wc/projections pR32 ─────
// P(advance) for each WC team is the pR32 field on the per-team row in
// /wc/projections. This data is Monte Carlo-derived from the relay and
// does NOT consume Odds API credits. The bracket renderer
// (renderWCTournamentBracket) already fetches /wc/projections — we
// piggyback on that cache; if it hasn't run yet, loadWCProjectionsCache
// triggers it lazily.
//
// Cache: window._wcProjectionsCache = { ts, byTeam: { normName → row } }.
// renderWCTournamentBracket populates the same cache after its own fetch.
const _WC_PROJ_TTL_MS = 5 * 60 * 1000;

function _wcProjectionsApplyTeams(teams) {
  if (!Array.isArray(teams) || !teams.length) return;
  const byTeam = {};
  for (const t of teams) {
    if (!t || !t.name) continue;
    byTeam[_normWCName(t.name)] = t;
  }
  window._wcProjectionsCache = { ts: Date.now(), byTeam };
  try { sessionStorage.setItem('field_wc_projections',
    JSON.stringify({ ts: Date.now(), teams })); } catch (_) {}
}

function _wcLookupAdvance(teamName) {
  const cache = window._wcProjectionsCache;
  if (!cache || !cache.byTeam) return null;
  const t = cache.byTeam[_normWCName(teamName)];
  if (!t || t.pR32 == null) return null;
  return Number(t.pR32);
}

function loadWCProjectionsCache() {
  const now = Date.now();
  const cur = window._wcProjectionsCache;
  if (cur && (now - (cur.ts || 0)) < _WC_PROJ_TTL_MS) return Promise.resolve();
  // Hydrate from sessionStorage first
  if (!cur) {
    try {
      const raw = sessionStorage.getItem('field_wc_projections');
      if (raw) {
        const c = JSON.parse(raw);
        if (c && (now - (c.ts || 0)) < _WC_PROJ_TTL_MS && Array.isArray(c.teams)) {
          _wcProjectionsApplyTeams(c.teams);
          return Promise.resolve();
        }
      }
    } catch (_) {}
  }
  const base = (typeof V2_RELAY_BASE !== 'undefined')
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  return fetch(`${base}/wc/projections`, { signal: AbortSignal.timeout(2500) })
    .then(r => r.ok ? r.json() : null)
    .then(data => {
      const teams = data && Array.isArray(data.teams) ? data.teams : null;
      if (teams) _wcProjectionsApplyTeams(teams);
    })
    .catch(() => {});
}

// v1.3.2 — fetch no-vig match probabilities from relay /wc/odds-probs
// Returns array of {home_team, away_team, pHome, pDraw, pAway, commence}
async function fetchWCOddsProbabilities() {
  try {
    const base = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : null)
              || 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const r = await fetch(`${base}/wc/odds-probs`, { cache: 'no-store' });
    if (!r.ok) return [];
    const data = await r.json();
    const probs = data.ok && Array.isArray(data.probs) ? data.probs : [];
    // Build _wcOddsCache keyed as buildWCBars expects:
    // home_team + away_team → lowercase, spaces→underscores
    const norm = s => (s||'').toLowerCase()
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
    window._wcOddsCache = {};
    for (const p of probs) {
      const key = `${norm(p.home_team)}_${norm(p.away_team)}`;
      window._wcOddsCache[key] = {
        homeWin: p.pHome,
        draw:    p.pDraw,
        awayWin: p.pAway,
      };
    }
    return probs;
  } catch (e) { return []; }
}

// Level 1 — fetch today's live WC games from V2 relay (/v2/games?sport=wc26)
// Returns live games with winProb attached (relay computes odds-blended WP)
// Also populates _wcLiveGamesCache for the Watch Engine.
let _wcLiveGamesCache = [];  // global: Watch Engine reads this for WC live state
async function fetchWCLiveGames() {
  try {
    const base = (typeof V2_RELAY_BASE !== 'undefined' ? V2_RELAY_BASE : null)
              || 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const today = new Date().toISOString().slice(0, 10);
    const r = await fetch(`${base}/v2/games?sport=wc26&date=${today}`, { cache: 'no-store' });
    if (!r.ok) return [];
    const data = await r.json();
    const live = (data.games || []).filter(g => g.state === 'live' && g.winProb);
    _wcLiveGamesCache = live;  // expose to Watch Engine
    // Merge advancementProb onto matching espnScores entries so
    // applyQW1SituationBonus() can use it as a drama signal without a
    // second lookup. This MUTATES a shared cache entry (not a display
    // read) -- treated with write-level rigor (CC-CMD-2026-07-09-wc-
    // advprob-and-keys-sweep): the old home-team-suffix-only scan had no
    // away-team check, no date check, not even findEspnEntry's baseline
    // staleness guard -- a wrong match here plants a false value that
    // persists on that entry and can bias drama scoring for a different
    // game until overwritten.
    //
    // _g's own `id`/`espnEventId` (confirmed live via probe_relay_route:
    // "espn:760510"-style) are relay-native ESPN IDs -- a different
    // namespace from FIELD's own game._id, no direct overlap -- so team
    // name is the only reliable cross-reference to FIELD's own schedule.
    // Two-stage resolution: (1) find the real FIELD game _g corresponds
    // to by matching BOTH home and away against allData.sports (not just
    // home), (2) pass that resolved game through the already-proven
    // findEspnEntry(game, {requireSameDate:true}) to get the verified,
    // stale-guarded espnScores entry. If either stage can't confirm a
    // match, skip the merge for that live entry entirely rather than
    // falling back to the old suffix scan.
    for (const _g of live) {
      if (!_g.advancementProb) continue;
      const _wcHome = (_g.home?.name || '').toLowerCase().replace(/[^a-z]/g,'');
      const _wcAway = (_g.away?.name || '').toLowerCase().replace(/[^a-z]/g,'');
      if (!_wcHome || !_wcAway) continue;
      const _resolvedGame = (allData?.sports || []).flatMap(s => s.games || []).find(g => {
        const gH = (g.home || '').toLowerCase().replace(/[^a-z]/g, '');
        const gA = (g.away || '').toLowerCase().replace(/[^a-z]/g, '');
        const homeOk = gH && (gH.endsWith(_wcHome) || _wcHome.endsWith(gH));
        const awayOk = gA && (gA.endsWith(_wcAway) || _wcAway.endsWith(gA));
        return homeOk && awayOk;
      });
      if (!_resolvedGame) continue;
      const _verifiedEntry = findEspnEntry(_resolvedGame, { requireSameDate: true });
      if (!_verifiedEntry) continue;
      _verifiedEntry._wcAdvProb        = _g.advancementProb;
      _verifiedEntry._wcOpeningAdvProb = _g.openingAdvanceProb || null;
    }
    return live;
  } catch (e) { return []; }
}

// Match odds-team-name to wc26Raw fixture team-name (The Odds API uses different name formats)
function _wcMatchTeamName(oddsName, fieldName) {
  if (!oddsName || !fieldName) return false;
  // NFD normalize strips diacritics (ü→u, ç→c, é→e etc.), then alphanum+space only
  const norm = s => s.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, ' ').replace(/\s+/g, ' ').trim();
  const a = norm(oddsName), b = norm(fieldName);
  if (a === b) return true;
  // Bidirectional alias table — confirmed from live /wc/odds-probs probe (June 4 2026)
  const ALIASES = {
    'usa':            'united states',
    'united states':  'usa',
    'turkey':         'turkiye',       // Odds API "Turkey" ↔ wc26Raw "Türkiye" → norm → "turkiye"
    'turkiye':        'turkey',
    'czech republic': 'czechia',       // Odds API "Czech Republic" ↔ wc26Raw "Czechia"
    'czechia':        'czech republic',
    'dr congo':       'congo dr',      // Odds API "DR Congo" ↔ wc26Raw "Congo DR"
    'congo dr':       'dr congo',
    'ivory coast':    'cote d ivoire',
    'cote d ivoire':  'ivory coast',
  };
  const aa = ALIASES[a] || a, bb = ALIASES[b] || b;
  if (aa === bb || aa === b || a === bb) return true;
  // 5-char prefix as final fallback
  const pfx = 5;
  if (a.length >= pfx && b.length >= pfx) {
    if (b.includes(a.slice(0, pfx)) || a.includes(b.slice(0, pfx))) return true;
  }
  return false;
}

// Resolve odds probability for a single remaining fixture from the probs array
// Returns {pHome, pDraw, pAway, lambdaHome, lambdaAway} or null.
// lambdaHome/lambdaAway come from totals-derived lambda (v1.4 Poisson margin model).
function _wcMatchOdds(fixture, oddsProbs) {
  if (!Array.isArray(oddsProbs)) return null;
  for (const p of oddsProbs) {
    const homeMatch = _wcMatchTeamName(p.home_team, fixture.home);
    const awayMatch = _wcMatchTeamName(p.away_team, fixture.away);
    if (homeMatch && awayMatch) {
      return {
        pHome: p.pHome, pDraw: p.pDraw, pAway: p.pAway,
        lambdaHome: p.lambdaHome || null,
        lambdaAway: p.lambdaAway || null,
      };
    }
    // Try reversed (some APIs flip home/away)
    const homeMatchR = _wcMatchTeamName(p.home_team, fixture.away);
    const awayMatchR = _wcMatchTeamName(p.away_team, fixture.home);
    if (homeMatchR && awayMatchR) {
      return {
        pHome: p.pAway, pDraw: p.pDraw, pAway: p.pHome,
        lambdaHome: p.lambdaAway || null,  // swap lambdas for reversed match
        lambdaAway: p.lambdaHome || null,
      };
    }
  }
  return null;
}


// Loading state
function renderWCGroupsLoading() {

// ── WC Live Standings Overlay ────────────────────────────────────────────
// Applies live SSE scores to cached D1 standings and re-renders the groups
// table. Called on every WC SSE score event. The overlay tracks live games
// in window._wcLiveScores (map of gameId → {home, away, homeScore, awayScore}).
// D1 standings don't update mid-game, so this is the only way to show
// real-time group table changes when a goal is scored.
function _wcRenderWithLiveOverlay() {
  const base = window._wcLastStandings;
  if (!base || !window._wcLiveScores) return;

  // Deep-clone standings so we don't mutate the D1-sourced cache
  const overlaid = {};
  for (const g of Object.keys(base)) {
    overlaid[g] = base[g].map(r => ({...r}));
  }

  // Apply each live game score as if it were a completed result
  for (const [gid, live] of Object.entries(window._wcLiveScores)) {
    for (const g of Object.keys(overlaid)) {
      const norm = s => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]/g,'');
      const homeRow = overlaid[g].find(r => norm(r.team) === norm(live.home));
      const awayRow = overlaid[g].find(r => norm(r.team) === norm(live.away));
      if (!homeRow || !awayRow) continue;

      // Check if this game's result is already in D1 standings
      // (played count would include it). If not, overlay it.
      // Simple heuristic: track overlay by gameId to avoid double-counting
      if (homeRow._liveOverlayId === gid) {
        // Already overlaid — update in place (score changed)
        homeRow.gf = (homeRow._baseGf ?? homeRow.gf) + live.homeScore;
        homeRow.ga = (homeRow._baseGa ?? homeRow.ga) + live.awayScore;
        awayRow.gf = (awayRow._baseGf ?? awayRow.gf) + live.awayScore;
        awayRow.ga = (awayRow._baseGa ?? awayRow.ga) + live.homeScore;
      } else {
        // First overlay for this game — save base values
        homeRow._baseGf = homeRow.gf; homeRow._baseGa = homeRow.ga;
        homeRow._basePts = homeRow.points; homeRow._baseW = homeRow.won;
        homeRow._baseD = homeRow.drawn; homeRow._baseL = homeRow.lost;
        homeRow._basePlayed = homeRow.played;
        awayRow._baseGf = awayRow.gf; awayRow._baseGa = awayRow.ga;
        awayRow._basePts = awayRow.points; awayRow._baseW = awayRow.won;
        awayRow._baseD = awayRow.drawn; awayRow._baseL = awayRow.lost;
        awayRow._basePlayed = awayRow.played;

        homeRow.gf += live.homeScore; homeRow.ga += live.awayScore;
        awayRow.gf += live.awayScore; awayRow.ga += live.homeScore;
        homeRow.played++; awayRow.played++;
        homeRow._liveOverlayId = gid; awayRow._liveOverlayId = gid;
      }

      // Recalculate W/D/L and points from base + live result
      const hBase = { w: homeRow._baseW, d: homeRow._baseD, l: homeRow._baseL };
      const aBase = { w: awayRow._baseW, d: awayRow._baseD, l: awayRow._baseL };
      if (live.homeScore > live.awayScore) {
        homeRow.won = hBase.w + 1; homeRow.drawn = hBase.d; homeRow.lost = hBase.l;
        awayRow.won = aBase.w; awayRow.drawn = aBase.d; awayRow.lost = aBase.l + 1;
      } else if (live.homeScore < live.awayScore) {
        homeRow.won = hBase.w; homeRow.drawn = hBase.d; homeRow.lost = hBase.l + 1;
        awayRow.won = aBase.w + 1; awayRow.drawn = aBase.d; awayRow.lost = aBase.l;
      } else {
        homeRow.won = hBase.w; homeRow.drawn = hBase.d + 1; homeRow.lost = hBase.l;
        awayRow.won = aBase.w; awayRow.drawn = aBase.d + 1; awayRow.lost = aBase.l;
      }
      homeRow.gd = homeRow.gf - homeRow.ga;
      awayRow.gd = awayRow.gf - awayRow.ga;
      homeRow.points = homeRow.won * 3 + homeRow.drawn;
      awayRow.points = awayRow.won * 3 + awayRow.drawn;

      // Re-sort group by FIFA criteria
      overlaid[g].sort((a, b) =>
        (b.points - a.points) || ((b.gf - b.ga) - (a.gf - a.ga)) || (b.gf - a.gf)
      );
      break; // Found the group, done
    }
  }

  // Re-render groups with overlaid standings
  if (typeof renderWCGroups === 'function') {
    renderWCGroups(overlaid,
      window._wcLastMatchResults || {},
      window._wcLastOddsProbs || [],
      window._wcLastLiveGames || []);
  }
}
// Expose for SSE handler
window._wcRenderWithLiveOverlay = _wcRenderWithLiveOverlay;
  const el = (_DOM?.wcGroups||document.getElementById('wc-groups'));
  if (!el) return;
  el.innerHTML = 'ABCDEFGHIJKL'.split('').map(g => `
    <div class="wc-group-block" data-group="${g}">
      <div class="wc-group-label">Group ${g}</div>
      <div class="wc-skeleton" style="width:80%"></div>
      <div class="wc-skeleton" style="width:90%"></div>
      <div class="wc-skeleton" style="width:75%"></div>
      <div class="wc-skeleton" style="width:85%"></div>
    </div>`).join('');
}

// Empty state — before tournament starts (no D1 results)
// opts: {groups, targetId} — both default to WC26's own values, so the zero
// real callers of this function (confirmed orphaned) still get byte-identical
// WC26 output if ever reconnected. Preview header/footer copy stays WC26-only
// text (dates, stadiums) — not one of the 3 assumptions this dispatch targets.
function renderWCGroupsEmpty(opts = {}) {
  const { groups = 'ABCDEFGHIJKL'.split(''), targetId = 'wc-groups' } = opts;
  const el = (targetId === 'wc-groups' && _DOM?.wcGroups) || document.getElementById(targetId);
  if (!el) return;
  const daysAway = Math.max(0, Math.round((new Date('2026-06-11') - new Date()) / 86400000));
  const previewHeader = daysAway > 0
    ? `<div class="wc-preview-header">
        <p class="wc-preview-intro">The 2026 FIFA World Cup opens <strong>June 11 at Estadio Azteca</strong> — the first tournament with 48 teams across 12 groups. 104 matches, three host nations (USA · Mexico · Canada), 39 days. The USMNT opens Group D on June 12 at SoFi Stadium against Paraguay, free on Tubi. All 72 group-stage games on FOX and FS1 in English; Telemundo and Peacock in Spanish. Group standings update automatically once play begins.</p>
       </div>`
    : '';
  el.innerHTML = previewHeader + groups.map(g => {
    const teams = WC_TEAMS[g] || [];
    const rows = teams.map((t, i) => `
      <tr class="wc-row wc-row--${i < 2 ? 'advance' : i === 2 ? 'maybe' : 'out'}">
        <td class="wc-td-pos">${i + 1}</td>
        <td class="wc-td-team">${t}</td>
        <td>—</td><td>—</td><td>—</td><td>—</td>
        <td class="wc-td-gf">—</td><td class="wc-td-ga">—</td>
        <td>—</td><td class="wc-td-pts">—</td>
      </tr>`).join('');
    return buildWCGroupShell(g, rows);
  }).join('') + '<p class="wc-footnote">Tournament begins June 11 · Standings update automatically</p>';
}

// Live standings from D1
// opts: {groups, advancementText, targetId} — all default to WC26's own
// current values, so both real live callers (unchanged, still pass exactly
// 4 positional args) get byte-identical WC26 output. groups threads through
// to _wcComputeAllScenarios so a non-WC26 caller's group count/letters are
// honored end-to-end, not just at this function's own surface iteration.
function renderWCGroups(standings, matchResults, oddsProbs, liveGames, opts = {}) {
  const {
    groups = 'ABCDEFGHIJKL'.split(''),
    advancementText = 'Top 2 from each group advance · Best 8 third-place teams also advance',
    targetId = 'wc-groups',
  } = opts;
  const el = (targetId === 'wc-groups' && _DOM?.wcGroups) || document.getElementById(targetId);
  if (!el) return;
  const scenarios = _wcComputeAllScenarios(standings, matchResults, null, oddsProbs, liveGames, groups);
  window._wcScenariosCache = scenarios;
  const groupInputs = (scenarios && scenarios.groupInputs) || [];
  el.innerHTML = groups.map(g => {
    const gi = groupInputs.find(x => x.groupId === g) || {};
    // Find live game in this group (if any)
    const liveGame = gi.liveGame || null;
    const rows = buildWCGroupRows(standings[g] || [], scenarios, g, liveGame);
    const simBanner = gi.simultaneousFinalDay
      ? `<div class="wc-sim-banner" title="FIFA rule: final-matchday games kick off simultaneously. Neither team knows the other result.">⚡ Final day · Both games kick off simultaneously · ${gi.simultaneousKickoffLabel || ''}</div>`
      : '';
    return buildWCGroupShell(g, rows, simBanner);
  }).join('') +
  `<p class="wc-footnote">${advancementText}</p>`;
}

// Build all rows for a group, injecting the Level 1 WP bar between the two live teams
function buildWCGroupRows(standingsArr, scenarios, groupId, liveGame) {
  if (!standingsArr.length) return `<tr><td colspan="10" class="wc-empty">No results yet</td></tr>`;
  const rows = standingsArr.map((r, i) => buildWCGroupRow(r, i, scenarios, groupId));
  // Level 1: inject WP bar between the two teams currently playing
  if (liveGame && liveGame.winProb) {
    const wp = liveGame.winProb;
    const homeIdx = standingsArr.findIndex(r => _wcMatchTeamName(r.team, liveGame.home.name));
    const awayIdx = standingsArr.findIndex(r => _wcMatchTeamName(r.team, liveGame.away.name));
    if (homeIdx !== -1 && awayIdx !== -1) {
      const insertAfter = Math.min(homeIdx, awayIdx); // insert bar after the higher-placed team
      const wpBar = _wcBuildWPBar(liveGame, wp, {scenarios, groupId});
      rows.splice(insertAfter + 1, 0, wpBar);
    }
  }
  return rows.join('');
}

// Build engine input for one group from relay standings + wc26Raw fixtures.
// played[] left empty in v1.3 — relay doesn't expose per-match results yet,
// so H2H tiebreaker degrades to base sort (pts → GD → GF). Acceptable for
// MD1/MD2 displays; H2H matters most on MD3, addressed in v1.3.1.
function _wcBuildGroupInput(groupLetter, groupStandings, allFixtures, nowMs, matchResults, oddsProbs, liveGames) {
  if (!groupStandings || groupStandings.length !== 4) return null;
  const teams = groupStandings.map(r => ({
    name: r.team, P: r.played||0, W: r.won||0, D: r.drawn||0, L: r.lost||0,
    GF: r.gf||0, GA: r.ga||0, Pts: r.points||0,
  }));
  const played = (Array.isArray(matchResults) ? matchResults : [])
    .filter(r => r.group_id === groupLetter || r.group_id === `Group ${groupLetter}`)
    .map(r => ({home: _wcFixTeamName(r.home), away: _wcFixTeamName(r.away), homeScore: r.home_score, awayScore: r.away_score}));
  const groupFixtures = allFixtures.filter(g => g.league && g.league.includes(`Group ${groupLetter}`));
  const remaining = groupFixtures
    .filter(g => new Date(g.start_time).getTime() > nowMs)
    .map(g => ({home: g.home, away: g.away, _startMs: new Date(g.start_time).getTime()}));

  // Identify if any remaining fixture is currently live (relay has winProb on it)
  // Live WP overrides pre-game odds for that specific fixture — real-time Permutations
  // Pre-game odds entries include lambdaHome/lambdaAway (totals-market derived, v1.4 Poisson margins)
  const liveFeed = Array.isArray(liveGames) ? liveGames : [];
  let liveGame = null;
  const outcomeProbabilities = remaining.map(f => {
    const live = liveFeed.find(g =>
      _wcMatchTeamName(g.home?.name, f.home) && _wcMatchTeamName(g.away?.name, f.away)
    );
    if (live && live.winProb) {
      liveGame = live;
      const wp = live.winProb;
      // For live games: relay already computed lambdas via oddsToLambda/totals.
      // V2 game object doesn't carry them, so omit — v1.4 uses minimum-margin for live fixtures.
      return {pHome: wp.homeWin, pDraw: wp.draw, pAway: wp.awayWin};
    }
    // Pre-game: _wcMatchOdds now includes lambdaHome/lambdaAway from totals market (v1.4)
    return _wcMatchOdds(f, oddsProbs);
  }).filter(Boolean);
  const fullOdds = outcomeProbabilities.length === remaining.length && remaining.length > 0
    ? outcomeProbabilities : undefined;

  // v1.7 simultaneous final matchday detection
  let simultaneousFinalDay = false, simultaneousKickoffLabel = null;
  if (remaining.length === 2) {
    const delta = Math.abs(remaining[0]._startMs - remaining[1]._startMs);
    if (delta <= 5 * 60 * 1000) {
      simultaneousFinalDay = true;
      const d = new Date(Math.min(remaining[0]._startMs, remaining[1]._startMs));
      simultaneousKickoffLabel = d.toLocaleString('en-US',
        {month:'short',day:'numeric',hour:'numeric',minute:'2-digit',timeZone:'America/New_York',hour12:true,timeZoneName:'short'}
      ).replace(':00','');
    }
  }
  return {
    groupId: groupLetter, teams, played,
    remaining: remaining.map(({home, away}) => ({home, away})),
    outcomeProbabilities: fullOdds,
    simultaneousFinalDay, simultaneousKickoffLabel,
    liveGame,  // Level 1: passed to buildWCGroupRows for WP bar insertion
  };
}

// Compute scenarios across all real groups (WC26's own 12 by default) +
// cross-group best-3rd ranking. Returns {perGroup, best3rd} or null on failure.
// groups: optional 6th param, defaults to WC26's own 12 letters so all 3 real
// call sites (unchanged, still pass exactly 5 positional args) are unaffected.
// best3rd's "best 8 third-place teams" is a real WC26-specific rule, correctly
// gated on groupInputs.length === 12 — a caller with a different group count
// correctly gets best3rd:null rather than an invented rule for its format.
// allFixtures stays sourced from wc26Raw regardless of groups (not one of the
// 3 assumptions this dispatch targets) — a real, disclosed residual for any
// future non-WC26 caller, not a silent gap.
function _wcComputeAllScenarios(standings, matchResults, fairPlayPoints, oddsProbs, liveGames, groups = 'ABCDEFGHIJKL'.split('')) {
  if (typeof computeGroupScenarios !== 'function') {
    captureFieldError('wc:compute-all-scenarios:missing-fn', new Error('computeGroupScenarios is not a function'), false);
    return null;
  }
  if (!standings || Object.keys(standings).length === 0) return null;
  try {
    const nowMs = Date.now();
    const allFixtures = (typeof wc26Raw !== 'undefined' && Array.isArray(wc26Raw))
      ? wc26Raw : [];
    const groupInputs = groups
      .map(g => _wcBuildGroupInput(g, standings[g], allFixtures, nowMs, matchResults, oddsProbs, liveGames))
      .filter(Boolean);
    const perGroup = {};
    for (const gi of groupInputs) {
      // v1.5 — pass optional fairPlayPoints if provided by caller
      const fp = fairPlayPoints && fairPlayPoints[gi.groupId];
      perGroup[gi.groupId] = computeGroupScenarios({...gi, fairPlayPoints: fp});
    }
    let best3rd = null;
    if (typeof computeBest3rdRanking === 'function' && groupInputs.length === 12) {
      try {
        best3rd = computeBest3rdRanking({groupInputs, samples: 5000, seed: 2026});
      } catch (e) { /* best3rd is optional */ }
    }
    return {perGroup, best3rd, groupInputs};
  } catch (e) {
    return null;
  }
}

// Level 1 — build the live WP bar row (injected between the two playing teams)
// ── Advancement Probability (fully integrated) ─────────────────────────────
//
// True P(advance) = pQualifyTop2 + pQualifyAsBest3rd from Permutations Engine.
// Fallback: relay g.advancementProb.homeAdvance/awayAdvance (single-game v2).
// Baseline: GameDO openingAdvanceProb (kickoff snapshot).
//
// The Permutations Engine supersedes the relay estimate when both are available
// because it considers ALL remaining fixtures; the relay considers only the
// current live game.

/**
 * Compute true P(advance) for a team.
 * Primary: Permutations Engine pQualifyTop2 + pQualifyAsBest3rd (full multi-game).
 * Fallback: relay g.advancementProb field (single-game scenario v2).
 * @param {string} teamName
 * @param {object} scenarios — from _wcComputeAllScenarios
 * @param {string} groupId
 * @param {object} liveGame — V2 game object with optional advancementProb field
 * @param {'home'|'away'} side
 * @returns {{pAdv: number, source: string}|null}
 */
function _wcAdvancementProb(teamName, scenarios, groupId, liveGame, side) {
  // Primary: Permutations Engine
  if (scenarios && groupId && scenarios.perGroup?.[groupId]?.perTeam?.[teamName]) {
    const pt = scenarios.perGroup[groupId].perTeam[teamName];
    const pTop2 = pt.pQualifyTop2 ?? 0;
    const b3 = scenarios.best3rd?.perTeam?.[teamName];
    const pB3 = b3?.pQualifyAsBest3rd ?? 0;
    return { pAdv: Math.min(1, pTop2 + pB3), source: 'permutations' };
  }
  // Fuzzy name match (Odds API names vs wc26Raw names may differ)
  if (scenarios && groupId && scenarios.perGroup?.[groupId]?.perTeam) {
    const pt = scenarios.perGroup[groupId].perTeam;
    const matchKey = Object.keys(pt).find(n => _wcMatchTeamName(n, teamName));
    if (matchKey) {
      const info = pt[matchKey];
      const pTop2 = info.pQualifyTop2 ?? 0;
      const b3 = scenarios.best3rd?.perTeam?.[matchKey];
      const pB3 = b3?.pQualifyAsBest3rd ?? 0;
      return { pAdv: Math.min(1, pTop2 + pB3), source: 'permutations' };
    }
  }
  // Fallback: relay single-game v2 estimate
  if (liveGame?.advancementProb) {
    const relay = liveGame.advancementProb;
    const pAdv = side === 'home' ? relay.homeAdvance : relay.awayAdvance;
    if (pAdv != null) return { pAdv, source: 'relay-v2' };
  }
  return null;
}

/**
 * Build the advancement probability bar (injected below WP bar when data available).
 * Shows P(advance) for both teams with opening-baseline delta from GameDO.
 */
function _wcBuildAdvBar(liveGame, hAdv, aAdv, hName, aName) {
  if (hAdv == null || aAdv == null) return '';
  const hPct = Math.round(hAdv * 100);
  const aPct = Math.round(aAdv * 100);
  // Space between bars = 100 - hPct - aPct (teams not qualified = neither)
  const gapPct = Math.max(0, 100 - hPct - aPct);
  // Opening baseline delta from GameDO
  const oa = liveGame?.openingAdvanceProb;
  let hDeltaStr = '', aDeltaStr = '';
  if (oa?.homeAdvance != null) {
    const hDelta = hPct - Math.round(oa.homeAdvance * 100);
    if (Math.abs(hDelta) >= 5) hDeltaStr = ` ${hDelta > 0 ? '▲' : '▼'}${Math.abs(hDelta)}pp`;
  }
  const hLabel = hPct >= 15 ? `${hName.split(' ')[0]} ${hPct}%${hDeltaStr}` : `${hPct}%`;
  const aLabel = aPct >= 15 ? `${aPct}%${aDeltaStr} ${aName.split(' ').pop()}` : `${aPct}%`;
  return `
    <div class="wc-adv-bar" title="P(advance to R32) · includes best-8 third-place path">
      <div class="wc-adv-home" style="width:${hPct}%">${hLabel}</div>
      ${gapPct > 0 ? `<div class="wc-adv-gap" style="width:${gapPct}%"></div>` : ''}
      <div class="wc-adv-away" style="width:${aPct}%">${aLabel}</div>
    </div>
    <div class="wc-adv-meta">P(advance to R32) · ${hAdv.source === 'permutations' ? 'full group scenarios' : 'single-game estimate'}</div>`;
}

// Level 1 + Surprise Layer — live win probability bar with full context.
// Integrates: GameDO (openingWP, wpDelta, openingAdvanceProb) +
//             Permutations Engine (current pQualifyTop2 per team)
//
// Display layers:
//   L1: 3-segment WP bar (home/draw/away), source label, pulse animation
//   L1+: wpDelta trend (↑↓ on ≥2pp shift per 30s poll)
//   L3a: WP Surprise — current vs opening baseline (≥5pp divergence shown)
//   L3b: Qualification context — current Permutations pQualifyTop2 for both teams
//   L3c: Qual Surprise — current vs opening advanceProb (≥8pp divergence shown)
function _wcBuildWPBar(liveGame, wp, ctx) {
  const {scenarios, groupId} = ctx || {};
  const hPct = Math.round(wp.homeWin * 100);
  const dPct = Math.round(wp.draw    * 100);
  const aPct = 100 - hPct - dPct;
  const hName = liveGame.home?.name || '';
  const aName = liveGame.away?.name || '';
  const clock = liveGame.situation?.elapsed ? `${liveGame.situation.elapsed}'` : 'LIVE';
  const src   = wp.source || 'shots-proxy';

  // L1+: wpDelta trend indicator (≥2pp threshold suppresses noise)
  const delta = liveGame.wpDelta;
  let homeTrend = '', awayTrend = '';
  if (delta && Math.abs(delta.homeWin) >= 0.02) {
    homeTrend = delta.homeWin > 0 ? ' ↑' : ' ↓';
    awayTrend = delta.homeWin > 0 ? ' ↓' : ' ↑';
  }
  const hLabel = hPct >= 12 ? `${hName.split(' ')[0]} ${hPct}%${homeTrend}` : `${hPct}%`;
  const aLabel = aPct >= 12 ? `${aPct}%${awayTrend} ${aName.split(' ').pop()}` : `${aPct}%`;
  const dLabel = dPct >= 8 ? `D ${dPct}%` : dPct >= 4 ? `${dPct}%` : '';

  // L3a: WP surprise — opening WP baseline from GameDO (≥5pp divergence)
  const opening = liveGame.openingWP;
  let surpriseFrag = '';
  if (opening && Math.abs(wp.homeWin - opening.homeWin) >= 0.05) {
    const openPct = Math.round(opening.homeWin * 100);
    const wpDelta5 = hPct - openPct;
    const sign = wpDelta5 > 0 ? '+' : '';
    surpriseFrag = ` · ${hName.split(' ')[0]} was ${openPct}% pre-match (${sign}${wpDelta5}pp)`;
  }

  // Advancement probability — full integration (Permutations primary, relay fallback)
  const hAdvResult = _wcAdvancementProb(hName, scenarios, groupId, liveGame, 'home');
  const aAdvResult = _wcAdvancementProb(aName, scenarios, groupId, liveGame, 'away');
  const advBarHTML = (hAdvResult && aAdvResult)
    ? _wcBuildAdvBar(liveGame, hAdvResult, aAdvResult, hName, aName)
    : '';

  return `<tr class="wc-wp-row">
    <td colspan="10">
      <div class="wc-wp-bar" title="Live win probability · ${clock} · source: ${src}">
        <div class="wc-wp-home" style="width:${hPct}%">${hLabel}</div>
        <div class="wc-wp-draw" style="width:${dPct}%">${dLabel}</div>
        <div class="wc-wp-away" style="width:${aPct}%">${aLabel}</div>
      </div>
      <div class="wc-wp-meta">⚽ Live · ${clock} · ${src}${surpriseFrag}</div>
      ${advBarHTML}
    </td>
  </tr>`;
}

// Build a single scenario badge for a team in a group.
function _wcScenarioBadge(teamName, groupId, scenarios) {
  if (!scenarios || !scenarios.perGroup || !scenarios.perGroup[groupId]) return '';
  const teamInfo = scenarios.perGroup[groupId].perTeam[teamName];
  if (!teamInfo) return '';
  // v1.7 — badges render on a second line below the team name (avoids overflow on long names)
  // Wrap return value in <div class="wc-sb-line"> which is display:block with no left margin.
  const wrap = (inner) => `<div class="wc-sb-line">${inner}</div>`;
  // Bracket implication helper — short form only (match number, no groups list)
  const bracketLine = (pos) => {
    const impl = typeof _wcBracketImplication === 'function'
      ? _wcBracketImplication(groupId, pos) : null;
    if (!impl) return '';
    // Trim to "R32 M85" — drop the " · vs 3rd from ..." portion to save space on second line
    const short = impl.replace(/\s*·\s*vs.*$/, '');
    return ` <span class="wc-sb--b3" title="${impl}">${short}</span>`;
  };
  if (teamInfo.alwaysTopGroup) {
    return wrap(`<span class="wc-sb wc-sb--safe" title="Mathematically topping the group — will finish 1st">✓ 1st</span>${bracketLine(1)}`);
  }
  if (teamInfo.alwaysQualify) {
    const b1 = typeof _wcBracketImplication === 'function' ? _wcBracketImplication(groupId, 1) : null;
    const b2 = typeof _wcBracketImplication === 'function' ? _wcBracketImplication(groupId, 2) : null;
    const b1short = b1 ? b1.replace(/\s*·\s*vs.*$/, '') : '';
    const b2short = b2 ? b2.replace(/\s*·\s*vs.*$/, '') : '';
    const bfrag = (b1short && b2short && b1short !== b2short)
      ? ` <span class="wc-sb--b3" title="R32 path varies by finish">${b1short} / ${b2short}</span>`
      : (b1short ? ` <span class="wc-sb--b3" title="${b1}">${b1short}</span>` : '');
    return wrap(`<span class="wc-sb wc-sb--safe" title="Mathematically qualified — through regardless of remaining results">✓ Through</span>${bfrag}`);
  }
  if (teamInfo.alwaysEliminated) {
    return wrap('<span class="wc-sb wc-sb--out" title="Mathematically eliminated — cannot finish top 2 or as best 3rd">✗ Out</span>');
  }
  const c = teamInfo.scenarioCounts;
  const total = c.first + c.second + c.third + c.fourth;
  if (!total) return '';
  const b3 = scenarios.best3rd && scenarios.best3rd.perTeam[teamName];
  const pB3 = b3?.pQualifyAsBest3rd ?? 0;
  const isWeighted = teamInfo.pQualifyTop2 !== null;
  const pTop2 = isWeighted ? (teamInfo.pQualifyTop2 ?? 0) : ((c.first + c.second) / total);
  const pAdvTotal = Math.min(1, pTop2 + pB3);
  const pAdvPct = Math.round(pAdvTotal * 100);
  const hasB3Path = pB3 >= 0.01;
  const title = isWeighted
    ? `P(advance to R32): ${pAdvPct}% = ${Math.round(pTop2*100)}% top-2 + ${Math.round(pB3*100)}% as best-8 third · market-weighted`
    : `P(advance to R32): ${pAdvPct}% (uniform scenario distribution) · top-2 ${Math.round(pTop2*100)}% + best-3rd ${Math.round(pB3*100)}%`;
  const label = hasB3Path
    ? `${pAdvPct}% adv`
    : `${Math.round(pTop2*100)}%${isWeighted ? '' : ' top 2'}`;
  return wrap(`<span class="wc-sb wc-sb--maybe" title="${title}">${label}</span>`);
}

// Group block shell (used by both empty + live)
function buildWCGroupShell(groupId, rowsHTML, bannerHTML) {
  return `
    <div class="wc-group-block" data-group="${groupId}">
      <div class="wc-group-label">Group ${groupId}</div>
      ${bannerHTML || ''}
      <table class="wc-table" aria-label="Group ${groupId} standings">
        <thead><tr>
          <th class="wc-th-pos">#</th>
          <th class="wc-th-team">Team</th>
          <th class="wc-th-num">P</th>
          <th class="wc-th-num">W</th>
          <th class="wc-th-num">D</th>
          <th class="wc-th-num">L</th>
          <th class="wc-th-num wc-th-gf">GF</th>
          <th class="wc-th-num wc-th-ga">GA</th>
          <th class="wc-th-num">GD</th>
          <th class="wc-th-pts">Pts</th>
        </tr></thead>
        <tbody>${rowsHTML}</tbody>
      </table>
    </div>`;
}

// Single standings row
function buildWCGroupRow(r, index, scenarios, groupId) {
  const cls = index < 2 ? 'wc-row--advance' : index === 2 ? 'wc-row--maybe' : 'wc-row--out';
  const gd  = r.gd > 0 ? `+${r.gd}` : String(r.gd ?? 0);
  const dash = (v) => (r.played ? String(v) : '—');
  const badge = (scenarios && groupId) ? _wcScenarioBadge(r.team, groupId, scenarios) : '';
  return `
    <tr class="wc-row ${cls}">
      <td class="wc-td-pos">${index + 1}</td>
      <td class="wc-td-team">${r.team || '—'}${badge}</td>
      <td>${dash(r.played)}</td>
      <td>${dash(r.won)}</td>
      <td>${dash(r.drawn)}</td>
      <td>${dash(r.lost)}</td>
      <td class="wc-td-gf">${dash(r.gf)}</td>
      <td class="wc-td-ga">${dash(r.ga)}</td>
      <td>${r.played ? gd : '—'}</td>
      <td class="wc-td-pts">${r.played ? r.points : '—'}</td>
    </tr>`;
}

// Show/hide WC nav link based on wcActive
// ── WC Bracket Tree Renderer ─────────────────────────────────────────────────
// Fetches /wc/bracket (Monte Carlo slot winners) and renders a visual
// knockout bracket at tablet landscape (1180px+).
// Slot IDs: R32_73-88, R16_0-7, QF_0-3, SF_0-1, Final, Champion

// R32 match → R16 index mapping (left half: 0-3, right half: 4-7)
const WCT_R32_SLOTS = [
  // Left half — R32 → R16 pairs [73,74],[75,76],[77,78],[79,80]
  {id:'R32_73',half:'left',r16:0,pos:0}, {id:'R32_74',half:'left',r16:0,pos:1},
  {id:'R32_75',half:'left',r16:1,pos:0}, {id:'R32_76',half:'left',r16:1,pos:1},
  {id:'R32_77',half:'left',r16:2,pos:0}, {id:'R32_78',half:'left',r16:2,pos:1},
  {id:'R32_79',half:'left',r16:3,pos:0}, {id:'R32_80',half:'left',r16:3,pos:1},
  // Right half — R32 → R16 pairs [81,82],[83,84],[85,86],[87,88]
  {id:'R32_81',half:'right',r16:4,pos:0},{id:'R32_82',half:'right',r16:4,pos:1},
  {id:'R32_83',half:'right',r16:5,pos:0},{id:'R32_84',half:'right',r16:5,pos:1},
  {id:'R32_85',half:'right',r16:6,pos:0},{id:'R32_86',half:'right',r16:6,pos:1},
  {id:'R32_87',half:'right',r16:7,pos:0},{id:'R32_88',half:'right',r16:7,pos:1},
];

// Country flag emoji from FIFA code
const WCT_FLAGS = {
  MEX:'🇲🇽',RSA:'🇿🇦',KOR:'🇰🇷',CZE:'🇨🇿',CAN:'🇨🇦',BIH:'🇧🇦',USA:'🇺🇸',PAR:'🇵🇾',
  QAT:'🇶🇦',SUI:'🇨🇭',BRA:'🇧🇷',MAR:'🇲🇦',HAI:'🇭🇹',SCO:'🏴󠁧󠁢󠁳󠁣󠁴󠁿',AUS:'🇦🇺',TUR:'🇹🇷',
  GER:'🇩🇪',CUW:'🇨🇼',NED:'🇳🇱',JPN:'🇯🇵',CIV:'🇨🇮',ECU:'🇪🇨',SWE:'🇸🇪',TUN:'🇹🇳',
  ESP:'🇪🇸',CPV:'🇨🇻',BEL:'🇧🇪',EGY:'🇪🇬',KSA:'🇸🇦',URU:'🇺🇾',IRN:'🇮🇷',NZL:'🇳🇿',
  FRA:'🇫🇷',SEN:'🇸🇳',IRQ:'🇮🇶',NOR:'🇳🇴',ARG:'🇦🇷',ALG:'🇩🇿',AUT:'🇦🇹',JOR:'🇯🇴',
  POR:'🇵🇹',COD:'🇨🇩',ENG:'🏴󠁧󠁢󠁥󠁮󠁧󠁿',CRO:'🇭🇷',GHA:'🇬🇭',PAN:'🇵🇦',UZB:'🇺🇿',COL:'🇨🇴',
};

function wctTeamCard(slotData, cls = '') {
  if (!slotData) {
    return `<div class="wct-team wct-tbd ${cls}"><span class="wct-name" style="color:var(--smoke);font-style:italic">TBD</span></div>`;
  }
  const flag = WCT_FLAGS[slotData.fifaCode] || '🏳️';
  const pct  = slotData.prob != null ? Math.round(slotData.prob * 100) + '%' : '';
  return `<div class="wct-team ${cls}">
    <span class="wct-flag">${flag}</span>
    <span class="wct-name">${slotData.team || 'TBD'}</span>
    ${pct ? `<span class="wct-prob">${pct}</span>` : ''}
  </div>`;
}

function wctMatchCard(slot1, slot2, extraCls = '') {
  return `<div class="wct-match ${extraCls}">
    ${wctTeamCard(slot1)}
    ${wctTeamCard(slot2)}
  </div>`;
}

async function renderWCBracketTree() {
  const el = document.getElementById('wc-bracket');
  if (!el) return;

  // Remove any existing tree
  const existing = el.querySelector('.wc-bracket-tree');
  if (existing) existing.remove();

  const RELAY = typeof V2_RELAY_BASE !== 'undefined'
    ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';

  // Loading state — tree placeholder
  const treeEl = document.createElement('div');
  treeEl.className = 'wc-bracket-tree';
  treeEl.innerHTML = '<div class="wct-loading">Computing most likely bracket…</div>';
  el.prepend(treeEl);

  let slots = {};
  try {
    const r = await fetch(`${RELAY}/wc/bracket`, { cache: 'no-store' });
    if (r.ok) {
      const data = await r.json();
      slots = data.bracketSlots || {};
    }
  } catch(e_) { captureFieldError('wc:bracket-tree-fetch', e_, true); }

  const hasData = Object.keys(slots).length > 0;

  // Build left half: 4 rounds (R32→R16→QF→SF) + champion + right half mirrored
  function col(ids, half='left') {
    const dir = half === 'right' ? 'wct-right' : '';
    return ids.map(id => {
      const s = slots[id];
      return `<div class="wct-match ${id.startsWith('SF') ? 'wct-sf' : id === 'Final' ? 'wct-final' : id === 'Champion' ? 'wct-champion' : ''} ${dir}">
        ${wctTeamCard(s, s ? '' : '')}
        <div class="wct-team" style="display:none"></div>
      </div>`;
    }).join('');
  }

  // For each round: array of match cards as a column
  function buildRound(slotIds, half='left', extraCls='') {
    const dir = half === 'right' ? 'wct-right' : '';
    return `<div class="wct-round ${dir}">` +
      slotIds.map(id => {
        const s = slots[id];
        const roundCls = id.startsWith('SF') ? 'wct-sf' : id === 'Final' ? 'wct-final' : '';
        return `<div class="wct-match ${roundCls} ${dir} ${extraCls}">
          ${wctTeamCard(s)}
          <div class="wct-team" style="visibility:hidden;height:0;padding:0;margin:0;border:none"></div>
        </div>`;
      }).join('') +
    '</div>';
  }

  // For R32: pairs need TWO teams per match slot
  function buildR32Round(pairs, half='left') {
    const dir = half === 'right' ? 'wct-right' : '';
    return `<div class="wct-round ${dir}">` +
      pairs.map(([idA, idB]) =>
        wctMatchCard(slots[idA], slots[idB], dir)
      ).join('') +
    '</div>';
  }

  const leftR32Pairs  = [
    [`R32_73_A`,`R32_73_B`],[`R32_74_A`,`R32_74_B`],
    [`R32_75_A`,`R32_75_B`],[`R32_76_A`,`R32_76_B`],
    [`R32_77_A`,`R32_77_B`],[`R32_78_A`,`R32_78_B`],
    [`R32_79_A`,`R32_79_B`],[`R32_80_A`,`R32_80_B`],
  ];
  const leftR16Pairs  = [
    [`R16_0_A`,`R16_0_B`],[`R16_1_A`,`R16_1_B`],
    [`R16_2_A`,`R16_2_B`],[`R16_3_A`,`R16_3_B`],
  ];
  const leftQFPairs   = [
    [`QF_0_A`,`QF_0_B`],[`QF_1_A`,`QF_1_B`],
  ];
  const leftSFPairs   = [
    [`SF_0_A`,`SF_0_B`],
  ];
  const rightR32Pairs = [
    [`R32_81_A`,`R32_81_B`],[`R32_82_A`,`R32_82_B`],
    [`R32_83_A`,`R32_83_B`],[`R32_84_A`,`R32_84_B`],
    [`R32_85_A`,`R32_85_B`],[`R32_86_A`,`R32_86_B`],
    [`R32_87_A`,`R32_87_B`],[`R32_88_A`,`R32_88_B`],
  ];
  const rightR16Pairs = [
    [`R16_4_A`,`R16_4_B`],[`R16_5_A`,`R16_5_B`],
    [`R16_6_A`,`R16_6_B`],[`R16_7_A`,`R16_7_B`],
  ];
  const rightQFPairs  = [
    [`QF_2_A`,`QF_2_B`],[`QF_3_A`,`QF_3_B`],
  ];
  const rightSFPairs  = [
    [`SF_1_A`,`SF_1_B`],
  ];
  const finalPair = [`Final_A`,`Final_B`];

  const champion   = slots['Champion'];
  const finalTeam1 = slots['Final'];   // champion
  const sfLeft     = slots['SF_0'];
  const sfRight    = slots['SF_1'];

  const note = hasData
    ? `<p class="wc-bracket-note" style="margin-top:.75rem">Most likely bracket · Updates every 15 min</p>`
    : '<p class="wc-bracket-note" style="margin-top:.75rem">Computing projections — check back shortly</p>';

  // Column headers
  const leftHeads  = ['R32','R16','QF','SF'].map(h =>
    `<div class="wct-col-head">${h}</div>`).join('');
  const rightHeads = ['SF','QF','R16','R32'].map(h =>
    `<div class="wct-col-head">${h}</div>`).join('');

  treeEl.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(4,1fr) 120px repeat(4,1fr);text-align:center;min-width:900px;margin-bottom:.3rem">
      ${leftHeads}
      <div class="wct-col-head" style="color:var(--gold)">🏆</div>
      ${rightHeads}
    </div>
    <div style="display:grid;grid-template-columns:repeat(4,1fr) 120px repeat(4,1fr);min-width:900px;align-items:center;gap:2px 0;padding:0 2px">
      ${buildR32Round(leftR32Pairs, 'left')}
      ${buildR32Round(leftR16Pairs, 'left')}
      ${buildR32Round(leftQFPairs, 'left')}
      ${buildR32Round(leftSFPairs, 'left')}
      <div style="display:flex;flex-direction:column;align-items:center;gap:.4rem;padding:0 4px">
        <div style="font-size:.9rem">🏆</div>
        <div class="wct-champion-label">Final</div>
        <div class="wct-match wct-champion" style="width:108px">
          ${wctTeamCard(slots['Final_A'])}
          ${wctTeamCard(slots['Final_B'])}
        </div>
        ${champion ? '<div style="font-size:.52rem;color:var(--gold2);text-align:center;margin-top:.2rem">Projected: ' + champion.team + ' ' + Math.round(champion.prob * 100) + '%</div>' : ''}
      </div>
      ${buildR32Round(rightSFPairs, 'right')}
      ${buildR32Round(rightQFPairs, 'right')}
      ${buildR32Round(rightR16Pairs, 'right')}
      ${buildR32Round(rightR32Pairs, 'right')}
    </div>
    ${note}
  `;
}

