// ── WHOLE FIELD toggle ────────────────────────────────────────────────────
// Persists desktop layout mode: 'essentials' (default) | 'whole'
// Laptop 1200-1439px: LEFT + RIGHT (ambient)
// Desktop 1440px+:   LEFT + CENTRE (editorial) + RIGHT (ambient)
(function initWFToggle() {
  const btn = document.getElementById('wf-toggle');
  if (!btn) return;

  const LS_KEY = 'field_desktop_mode';
  let mode = (typeof localStorage !== 'undefined' && localStorage.getItem(LS_KEY)) || 'essentials';

  function apply(m) {
    mode = m;
    const isWhole = m === 'whole';
    document.body.classList.toggle('wf-mode', isWhole);
    btn.textContent = isWhole ? 'WHOLE FIELD' : 'ESSENTIALS';
    btn.classList.toggle('wf-active', isWhole);
    btn.title = isWhole
      ? 'Switch to ESSENTIALS (schedule only)'
      : 'Switch to WHOLE FIELD (schedule + ambient panel)';
    try { localStorage.setItem(LS_KEY, m); } catch(e_) {}
    // Trigger ambient panel render on every toggle: populates content when
    // entering WHOLE FIELD, clears the inline display:flex (set during prior
    // iPad-range renders) when returning to ESSENTIALS so the CSS base rule
    // hides the panel cleanly.
    if (typeof renderAmbientPanel === 'function') {
      renderAmbientPanel();
    }
  }

  // Restore saved state on load
  apply(mode);

  btn.addEventListener('click', () => {
    apply(mode === 'whole' ? 'essentials' : 'whole');
  });
})();


// Build the Finals Desk prompt (sync — analytics context is all in-memory).
// Separated so both the enqueue path and any fallback can share it.
function _buildFinalsDeskPrompt(game, sport) {
  const series = game.seriesRecord || '0-0';
  let analyticsCtx = '';
  const sp = (sport || '').toLowerCase();
  if (sp.includes('nba') || sp.includes('basketball')) {
    analyticsCtx = getNBAAnalyticsContext(game);
    const gameChar = predictNBAGameCharacter(game);
    if (gameChar) analyticsCtx += `\n[GAME TYPE] ${gameChar.label}: ${gameChar.rationale}`;
    const regress = getNBARegression(game._id);
    if (regress) analyticsCtx += `\n[REGRESSION ALERT] ${regress.team}: ${regress.stat} at ${regress.observed} vs expected ${regress.expected}. ${regress.alert}`;
  } else if (sp.includes('nhl') || sp.includes('hockey')) {
    analyticsCtx = getNHLAnalyticsContext(game);
    const gameChar = predictNHLGameCharacter(game);
    if (gameChar) analyticsCtx += `\n[GAME TYPE] ${gameChar.label}: ${gameChar.rationale}`;
    const ha = game._homeAbbr || getNHLAbbrev(game.home);
    const aa = game._awayAbbr || getNHLAbbrev(game.away);
    const hPDO = getNHLPDO(ha), aPDO = getNHLPDO(aa);
    if (hPDO && hPDO.note) analyticsCtx += `\n[PDO] ${ha}: ${hPDO.note}`;
    if (aPDO && aPDO.note) analyticsCtx += `\n[PDO] ${aa}: ${aPDO.note}`;
  }
  const msLine = (() => { try { const ms = _bdlMilestonesCache?.[game._id]; return ms ? `[MILESTONE] ${ms.playerName} needs ${ms.gap} more ${ms.stat} for career milestone.` : ''; } catch(e_) { return ''; } })();
  return [
    `Write a FIELD Finals Desk analytical piece for today's ${/nba/i.test(game.league||'')?'NBA':'Stanley Cup'} Finals.`,
    `${game.away||'?'} @ ${game.home||'?'} · ${game.venue||''} · ${series ? 'Series: '+series : 'Series begins today'}.`,
    game.matchupNote ? `Series context: ${game.matchupNote}` : '',
    analyticsCtx || '',
    msLine,
    '',
    'Write exactly 4 sections with these headers (bold):',
    '**Series Arc** — 2 sentences. What has defined this series so far, or what defines the matchup if this is Game 1. Cite one specific fact.',
    '**Analytics Edge** — 2 sentences. The single most important statistical angle for tonight. Cite specific numbers from the context above — never paraphrase.',
    '**Player to Watch** — 2 sentences. One player on either team whose performance will be decisive tonight and why.',
    '**What to Watch** — 2 sentences. The tactical or situational thing that decides this game. Frame it as a question that gets answered by buzzer.',
    '',
    'Rules:',
    '- Total length: 8 sentences across 4 sections. No other sections. No intro or outro.',
    '- Cite specific numbers verbatim from context. Never use "elite", "dominant", "crucial", "huge".',
    '- If this is Game 1, Series Arc section should frame the series preview, not recap.',
    '- Never invent stats not present in context above.',
    '- Do not repeat the series record already shown in the card header.',
    FIELD_PROSE_STYLE,
  ].filter(Boolean).join('\n');
}

// Queue-backed Finals Desk fetch.
// First call: enqueues prompt to relay queue, stores jobId in sessionStorage.
// Subsequent calls: polls /journalism/result/:jobId until done or timeout.
// Falls back to direct CLAUDE_PROXY_URL if relay queue is unavailable.
// Cache key includes series record so it regenerates each new game.
async function fetchFinalsDesk(game, sport) {
  if (!game) return null;
  const isFinals = /nba finals|stanley cup final/i.test(game.league || '');
  if (!isFinals) return null;

  const series = game.seriesRecord || '0-0';
  const cacheKey    = `field_finals_desk_v${_swv}_${game._id}_${series.replace(/\s/g,'_')}`;
  const jobIdKey    = `field_finals_desk_job_v${_swv}_${game._id}_${series.replace(/\s/g,'_')}`;

  // 1. Completed text already in sessionStorage — return immediately
  try {
    const cached = sessionStorage.getItem(cacheKey);
    if (cached && cached.length > 100) return cached;
  } catch(e_) {}

  const prompt = _buildFinalsDeskPrompt(game, sport);

  // 2. Check if a job is already in flight — poll for result
  let jobId = null;
  try { jobId = sessionStorage.getItem(jobIdKey); } catch(e_) {}

  if (!jobId && JOURNALISM_ENQUEUE_RELAY) {
    // 3. No job yet — enqueue
    try {
      const eq = await fetch(JOURNALISM_ENQUEUE_RELAY, {
        method: 'POST',
        headers: {'Content-Type':'application/json'},
        body: JSON.stringify({
          prompt,
          sport: /nba/i.test(game.league||'') ? 'nba' : 'nhl',
          briefType: /nba/i.test(game.league||'') ? 'finals-desk-nba' : 'finals-desk-nhl',
          max_tokens: 600,
          // scoreThreshold 240 -- see generateJournalismViaRelay's comment
          // (CC-CMD-2026-07-09-jq-threshold-240-migration).
          scoreThreshold: 240,
          // home/away/homeScore/awayScore/matchupNote (CC-CMD-2026-07-09-
          // finals-desk-context-gap): identical enqueue-context-gap bug as
          // night-owl/scouts-pick -- Context Anchoring/Matchup Depth were
          // structurally unreachable regardless of scoreThreshold. All
          // three text fields already used to build `prompt` above
          // (_buildFinalsDeskPrompt reads game.home/game.away/
          // game.matchupNote directly); homeScore/awayScore aren't in the
          // prompt text itself (Finals Desk is a series-arc/analytics
          // piece, not a post-game recap) but this render path doesn't
          // gate on game state -- renderFinalsDesk() finds any NBA
          // Finals/SCF game regardless of live/final status -- so they're
          // included with the same ??null fallback night-owl uses, not
          // omitted the way scouts-pick's genuinely-always-pregame case
          // was.
          home: game.home || '',
          away: game.away || '',
          homeScore: game.homeScore ?? null,
          awayScore: game.awayScore ?? null,
          matchupNote: game.matchupNote || null,
        }),
      });
      if (eq.ok) {
        const data = await eq.json();
        if (data.jobId) {
          try { sessionStorage.setItem(jobIdKey, data.jobId); } catch(e_) {}
          jobId = data.jobId;
        }
      }
    } catch(e_) { captureFieldError('journalism:finals-desk-enqueue', e_, true); }
  }

  // 4. Poll for result (max 20s, 2s intervals)
  if (jobId && JOURNALISM_RESULT_RELAY) {
    for (let i = 0; i < 10; i++) {
      await new Promise(r => setTimeout(r, 2000));
      try {
        const pr = await fetch(`${JOURNALISM_RESULT_RELAY}/${jobId}`, {signal: AbortSignal.timeout(3000)});
        if (!pr.ok) continue;
        const result = await pr.json();
        if (result.status === 'done' && result.text && result.text.length > 80) {
          try { sessionStorage.setItem(cacheKey, result.text); } catch(e_) {}
          try { archiveBrief('game_ondemand', (game&&(_gameSport(game)))||null, game&&(game._id||game.id)||null, result.text, null); } catch(_){}
          try { sessionStorage.removeItem(jobIdKey); } catch(e_) {}
          return result.text;
        }
        if (result.status === 'failed') break; // fall through to direct path
      } catch(e_) { captureFieldError('journalism:finals-desk-poll', e_, true); }
    }
  }

  // 5. Fallback: direct proxy call if queue timed out or unavailable
  if (!CLAUDE_PROXY_URL) return null;
  try {
    const r = await fetch(CLAUDE_PROXY_URL, {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ model:'claude-haiku-4-5-20251001', max_tokens:500,
        messages:[{role:'user', content:prompt}] }),
    });
    if (!r.ok) return null;
    const data = await r.json();
    let text = (data.content||[]).filter(c=>c.type==='text').map(c=>c.text).join('').trim();
    if (text && text.length > 80) {
      text = await retryWithoutCliches(prompt, text, CLAUDE_PROXY_URL);
      text = await checkStatVerification(prompt, text, CLAUDE_PROXY_URL);
      try { sessionStorage.setItem(cacheKey, text); } catch(e_) {}
      try { archiveBrief('game_ondemand', (game&&(_gameSport(game)))||null, game&&(game._id||game.id)||null, text, null); } catch(_){}
      return text;
    }
  } catch(e_) { captureFieldError('journalism:finals-desk-fallback', e_, true); }
  return null;
}

// Render Finals Desk card into FIELD Desk grid
async function renderFinalsDesk() {
  if (!allData) return;
  const grid = document.getElementById('field-desk-grid');
  if (!grid) return;

  // Find the active Finals game (NBA Finals or SCF)
  let finalsGame = null, finalsSection = null;
  (allData.sports || []).forEach(sec => {
    (sec.games || []).forEach(g => {
      if (/nba finals|stanley cup final/i.test(g.league || ''))
        { finalsGame = g; finalsSection = sec; }
    });
  });
  if (!finalsGame) return;

  const sport = (finalsSection?.sport || '').toLowerCase();
  const series = finalsGame.seriesRecord || '0-0';
  const gameChar = sport.includes('nba') ? predictNBAGameCharacter(finalsGame) : predictNHLGameCharacter(finalsGame);

  // Check if a Finals Desk card already exists
  if (grid.querySelector('.desk-card.type-finals')) return;

  const placeholder = document.createElement('div');
  placeholder.className = 'desk-card type-finals';
  placeholder.style.cssText = 'border-left:3px solid var(--c-nba,#f97316);opacity:.6;';
  placeholder.innerHTML = `<div class="desk-card-label"><span class="desk-card-label-icon">📊</span>FINALS DESK${gameChar ? ' · '+gameChar.label : ''}</div><div class="desk-card-title">${finalsGame.away||''} @ ${finalsGame.home||''} · ${series}</div><div class="desk-card-body" style="font-style:italic;font-size:.7rem;">Loading analytics brief…</div>`;
  grid.insertBefore(placeholder, grid.firstChild);

  const text = await fetchFinalsDesk(finalsGame, sport).catch(() => null);
  if (!text) { placeholder.remove(); return; }

  const escaped = text.replace(/"/g,'&quot;');
  const preview = text.slice(0, 320).trim() + (text.length > 320 ? '\u2026' : '');
  placeholder.style.opacity = '1';
  placeholder.style.borderLeft = `3px solid ${sport.includes('nhl') ? 'var(--c-nhl,#38bdf8)' : 'var(--c-nba,#f97316)'}`;
  placeholder.setAttribute('data-full', escaped);
  placeholder.setAttribute('data-trunc-len', '320');
  placeholder.setAttribute('onclick', '_deskCardToggle(this)');
  placeholder.classList.add('tappable');
  placeholder.innerHTML = `<div class="desk-card-label"><span class="desk-card-label-icon">📊</span>FINALS DESK${gameChar ? ' · <span style="opacity:.8">'+gameChar.label+'</span>' : ''}</div><div class="desk-card-title">${finalsGame.away||''} @ ${finalsGame.home||''} · ${series}</div><div class="desk-card-body">${preview}</div>`;
}



// Inject series preview text directly into an existing card (used by compound dispatch)
function injectSeriesPreviewText(card, text) {
  if (!card || !text) return;
  // Big game (CF/Finals): inject inside card-body as inline brief
  let game=null;
  (allData?.sports||[]).forEach(s=>(s.games||[]).forEach(g=>{if(g._id===card.dataset.gameid)game=g;}));
  const isBig=game&&/conference finals|cf g\d|nba finals|stanley cup final|wcf|ecf/i.test(game.league||'');
  if(isBig){
    const cardBody=card.querySelector('.card-body');
    if(!cardBody) return;
    let briefEl=cardBody.querySelector('.card-brief-inline');
    if(!briefEl){
      briefEl=document.createElement('div');
      briefEl.className='card-brief-inline';
      briefEl.innerHTML='<div class="card-brief-inline-label">FIELD Series Brief</div><div class="card-brief-inline-text"></div>';
      cardBody.appendChild(briefEl);
    }
    const textEl=briefEl.querySelector('.card-brief-inline-text');
    if(textEl){textEl.textContent=trimToCompleteSentence(text);textEl.classList.add('loaded');}
    return;
  }
  // Non-big-game: original external card pattern
  if (card.previousElementSibling?.classList.contains('series-preview-card')) {
    const existing = card.previousElementSibling.querySelector('.series-preview-text');
    if (existing) { existing.textContent = trimToCompleteSentence(text); existing.classList.add('loaded'); }
    return;
  }
  const preview = document.createElement('div');
  preview.className = 'series-preview-card';
  preview.dataset.gameid = card.dataset.gameid || '';
  preview.innerHTML = '<div class="series-preview-label">FIELD Series Brief</div><div class="series-preview-text loaded">' + trimToCompleteSentence(text) + '</div>';
  preview.addEventListener('click', () => preview.classList.toggle('series-preview-collapsed'));
  card.insertAdjacentElement('beforebegin', preview);
}


// Wow #16: WATCH WINDOW + QW-6 STREAM DEEP-LINKS
const STREAM_DEEPLINKS={prime:{ios:'aiv://',web:'https://www.amazon.com/gp/video/storefront/sports'},peacock:{ios:'nbcuniversal://',web:'https://www.peacocktv.com/sports'},espn:{ios:'sportscenter://',web:'https://www.espn.com/watch/'},espnplus:{ios:'sportscenter://',web:'https://plus.espn.com/'},apple:{ios:'videos://',web:'https://tv.apple.com/channel/tvs.sbd.4000/sports'},max:{ios:'hbomax://',web:'https://play.max.com/sports'},youtubetv:{ios:'youtubetvapp://',web:'https://tv.youtube.com/'},sling:{web:'https://watch.sling.com/'},hulu:{ios:'hulu://',web:'https://www.hulu.com/live-tv'},fubo:{ios:'fubo://',web:'https://www.fubo.tv/live-tv'},directv:{web:'https://stream.directv.com/'},mlbtv:{ios:'atbat://',web:'https://www.mlb.com/tv'},nbcsn:{web:'https://www.peacocktv.com/sports'},tnt:{web:'https://www.tntdrama.com/watchtnt'},tbs:{web:'https://www.tbs.com/watchtbs'}};
function getDeepLink(srKey){const d=STREAM_DEEPLINKS[srKey];if(!d) return null;const isMobile=/iPhone|iPad|Android/.test(navigator.userAgent||'');if(isMobile&&d.ios&&/iPhone|iPad/.test(navigator.userAgent)) return d.ios;return d.web||null;}
// _wwDismissed + _wwInterval: moved before goToDate — see init block
// Watch Window "Why" — assembles a one-line reason for the recommendation
// Template-assembled from verified data: no LLM, no new API calls.
// Output: "OKC leads WCF 3-2 · drama 88 · Spurs +215 underdogs" or ""
function buildWatchWindowReason(game) {
  // #18c: extreme note dominates Watch Window — no-hitter in progress beats all other reasons
  const liveScoreWWR = typeof findESPNScore === 'function' ? findESPNScore(game) : null;
  if(liveScoreWWR?.state === 'in') {
    const extremes = getStatisticalExtremes(liveScoreWWR, game._sport||'');
    if(extremes.note) return extremes.note; // override — this IS the reason to watch
  }

  const parts = [];
  if (game.seriesRecord) parts.push(game.seriesRecord);

  // Scout's Pick: under-the-radar game — surface the signal in the Watch Window chip
  if (typeof isScoutsPick === 'function' && isScoutsPick(game)) {
    if (!game.seriesRecord) parts.push('🔍 Scout\'s Pick');
  }

  // #29b: franchise misery context (abbreviated) — "14yr drought" fits the chip
  const homeMiseryWWR = getFranchiseMisery(game.home||'');
  const awayMiseryWWR = getFranchiseMisery(game.away||'');
  // Only inject if no other parts yet and it has a duration ("X-year")
  const getMiseryChip = (misery) => {
    if(!misery) return null;
    const m = misery.match(/(\d+)[-\s]year/);
    return m ? m[1]+'yr drought' : null;
  };
  const miseryChip = getMiseryChip(homeMiseryWWR) || getMiseryChip(awayMiseryWWR);
  const gid = game._id;
  if (gid) {
    const smoothed = getSmoothedDrama(gid);
    if (smoothed && smoothed >= 50) parts.push('drama\u00a0' + smoothed);
  }
  // Volatility Index: add CHAOTIC / LOCKED IN label when distinctive
  if (parts.length < 3) {
    const volLabel = (typeof getVolatilityLabel === 'function') ? getVolatilityLabel(game._id || '') : null;
    if (volLabel) parts.push(volLabel);
  }
  if(miseryChip && parts.length < 2) parts.push(miseryChip);
  return parts.slice(0, 3).join('\u00a0\u00b7\u00a0');
}

// ── iPad Ambient Mode — renderAmbientPanel() ──────────────────────────────────
// Visible only at 820–1199px. Reads existing FIELD state — no new fetches.
// Called: on ESPN score cycle, after brief renders, on viewport resize.
function renderAmbientPanel(){
  const panel=(_DOM?.ambientPanel||document.getElementById('ambient-panel'));
  if(!panel) return;
  const w=window.innerWidth;
  // Desktop bug fix (June 15 2026): allow rendering at >=1200px when wf-mode
  // is active (WHOLE FIELD shows the panel via the @media wf-mode rules).
  // Without this branch the panel was visible-but-empty on desktop wf-mode
  // because the function returned before populating content.
  const isWfDesktop = w >= 1200 && document.body.classList.contains('wf-mode')
    && !document.body.classList.contains('wc-mode')
    && !document.body.classList.contains('journalism-mode');
  if (w < 820 || (w >= 1200 && !isWfDesktop)) {
    // Clear any inline display we may have set previously; CSS will hide
    // via base rule (#ambient-panel{display:none}) when no mode shows it.
    panel.style.display = '';
    return;
  }
  // iPad path (820-1199) keeps the inline display:flex for compat with
  // existing iPad-18 inset positioning. Desktop wf-mode lets the CSS
  // !important rule set display:flex — clear inline so we don't conflict.
  if (isWfDesktop) {
    panel.style.display = '';
  } else {
    panel.style.display = 'flex';
  }

  // ── Section 1: OTW fire state mirror ──────────────────────────────────
  // Drama Dial wiring: use getDramaDial() so user's sensitivity setting governs
  // OTW selection here, consistent with badge thresholds in getDramaScore().
  // Per RUWT Deep Analysis: MODERATE → resolved by user-controlled threshold
  // (server cannot set this; all computation client-side per getDramaDial).
  const fire=(typeof _otwFindLiveGame==='function')?_otwFindLiveGame(getDramaDial()):null;
  let otwHTML;
  if(fire){
    const{g,ed,score}=fire;
    // Fixed 2026-07-02: this rendered a raw composite-score number
    // ("FIRE 87") live in Ambient Panel -- exactly what ADR-002's named-tier
    // system (fieldGameTier + fieldTierLabel, already built June 14 2026,
    // already the documented single source of truth: "every consumer reads
    // a named tier, never a raw number") exists to prevent. This code path
    // was never migrated to it. `score` is still used for OTW *selection*
    // (getDramaDial threshold, unchanged, matches the existing card-badge
    // selection logic) -- only the DISPLAYED value changes, from a number
    // to a named tier.
    const tierName = (typeof fieldGameTier === 'function') ? fieldGameTier(g._id) : 'LIVE';
    const tierLabel = (typeof fieldTierLabel === 'function') ? (fieldTierLabel(tierName) || 'LIVE') : 'LIVE';
    const scoreStr=`${ed.awayScore||0}–${ed.homeScore||0}`;
    // Compute period label — use periodLabel if set, else build from periodPrefix+period
    const periodLbl=ed.periodLabel||(ed.periodPrefix&&ed.period?`${ed.periodPrefix}${ed.period}`:'');
    const isBball=ed.periodPrefix==='T'||ed.periodPrefix==='B'||/^[TB]\d/.test(periodLbl);
    const clockStr=(!isBball&&ed.clock)?` ${fmtESPNClock(ed.clock)}`:'';
    // Row 1: FIRE badge + season context; Row 2: matchup; Row 3: score + clock
    const _fc=typeof getCalendarContext==='function'?getCalendarContext():null;
    const ctxSuffix=_fc?` · ${_fc.label}`:'';
    otwHTML=`<div class="ap-otw-fire">
      <span class="ap-otw-header">One to Watch</span>
      <span class="ap-fire-badge">🔴 FIRE — ${tierLabel}${ctxSuffix}</span>
      <span class="ap-fire-game">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}</span>
      <div class="ap-fire-row3">
        <span class="ap-fire-score">${scoreStr}</span>
        ${(periodLbl||clockStr)?`<span class="ap-fire-clock">${periodLbl}${clockStr}</span>`:''}
      </div>
    </div>`;
  }else{
    // Check SOON state — next game within 2hr
    let soonGame=null;const now=Date.now();
    (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
      if(!g.start_time||!g.home||!g.away) return;
      const ms=new Date(g.start_time)-now;
      if(ms>0&&ms<7200000&&(!soonGame||ms<(new Date(soonGame.start_time)-now)))
        soonGame=g;
    }));
    if(soonGame){
      const net=gameNetwork(soonGame);
      const cd=buildOTWCountdown(soonGame.start_time);
      otwHTML=`<div class="ap-soon">
        <span class="ap-otw-header">One to Watch</span>
        <span class="ap-soon-label">Up Next · ${cd}</span>
        <span class="ap-soon-game">${soonGame.away} ${soonGame.neutral?'vs':'@'} ${soonGame.home}</span>
        ${net?`<span class="ap-soon-meta">${net}</span>`:''}
      </div>`;
    }else{
      otwHTML=''; // M4: suppress quiet OTW — ghost text wastes panel top; UPCOMING leads
    }
  }

  // ── Section 2: Live / Soon / Upcoming ────────────────────────────────
  const live=Object.values(espnScores||{}).filter(s=>
    s.state==='in'&&typeof s.homeScore==='number'&&typeof s.awayScore==='number'&&
    s.homeScore>=0&&s.awayScore>=0
  );
  let scoresHTML='';
  if(live.length){
    const rows=live.slice(0,5).map(s=>{
      const awayName=s.awayTricode||teamNick(s.awayName||s.away)||'';
      const homeName=teamNick(s.homeName||s.home)||s.homeTricode||'';
      const periodLbl=s.periodLabel||(s.periodPrefix&&s.period?`${s.periodPrefix}${s.period}`:'');
      const isBball=s.periodPrefix==='T'||s.periodPrefix==='B'||/^[TB]\d/.test(periodLbl);
      const clockStr=(!isBball&&s.clock&&s.clock!=='0:00'&&s.clock!=='PT00M00.00S')?` ${fmtESPNClock(s.clock)}`:'';
      const timeStr=(periodLbl||clockStr)?`${periodLbl}${clockStr}`:
        (s.detail&&s.detail!=='0:00'&&typeof s.detail==='string'&&s.detail.length<12?s.detail:'');
      // SCORE-UNIFORM-A: show leader-first to match OTW and card.
      // ambient panel uses ESPN's own team names + scores (already correctly paired),
      // so fix is purely reordering: leader name+score on left, trailer name+score on right.
      const awayLeading = s.awayScore >= s.homeScore;
      const leftName  = awayLeading ? awayName : homeName;
      const rightName = awayLeading ? homeName : awayName;
      const leftScore  = awayLeading ? s.awayScore : s.homeScore;
      const rightScore = awayLeading ? s.homeScore : s.awayScore;
      return `<div class="ap-score-row">
        <span class="ap-score-teams">${leftName}<strong class="ap-score-num">${leftScore}–${rightScore}</strong>${rightName}</span>
        ${timeStr?`<span class="ap-score-clock">${timeStr}</span>`:''}
      </div>`;
    }).join('');
    scoresHTML=`<div class="ap-scores"><div class="ap-section-label">Live</div>${rows}</div>`;
  }

  // Rail display: Hull City → Hull outside the main game card (spec May 23 2026)
  const railName=n=>n==='Hull City'?'Hull':teamNick(n||'');
  // SOON — games starting within 2 hours
  const _apNow=Date.now();
  const _apSoon=[];
  (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
    if(!g.start_time||!g.home||!g.away) return;
    const ms=new Date(g.start_time)-_apNow;
    if(ms>0&&ms<7200000) _apSoon.push({g,ms});
  }));
  _apSoon.sort((a,b)=>a.ms-b.ms);
  let soonHTML='';
  if(_apSoon.length){
    const rows=_apSoon.slice(0,3).map(({g,ms})=>{
      const mins=Math.round(ms/60000);
      const cd=mins<=1?'now':mins<60?`${mins}m`:`${Math.floor(mins/60)}h ${mins%60}m`;
      const net=gameNetwork(g);
      return `<div class="ap-score-row">
        <span class="ap-score-teams">${railName(g.away)} ${g.neutral?'vs':'@'} ${railName(g.home)}${net?` · <span style="opacity:.6">${net}</span>`:''}</span>
        <span class="ap-score-clock">${cd}</span>
      </div>`;
    }).join('');
    soonHTML=`<div class="ap-scores"><div class="ap-section-label">Soon</div>${rows}</div>`;
  }

  // UPCOMING — games later today (2h+ away)
  const _apUp=[];
  (allData?.sports||[]).forEach(sec=>(sec.games||[]).forEach(g=>{
    if(!g.start_time||!g.home||!g.away) return;
    if(new Date(g.start_time)-_apNow>=7200000) _apUp.push(g);
  }));
  _apUp.sort((a,b)=>new Date(a.start_time)-new Date(b.start_time));
  let upcomingHTML='';
  if(_apUp.length){
    const tz2=localTz()||'America/New_York';
    const rows=_apUp.slice(0,4).map(g=>{
      const t=new Date(g.start_time).toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit',hour12:true,timeZone:tz2});
      return `<div class="ap-score-row">
        <span class="ap-score-teams">${railName(g.away)} ${g.neutral?'vs':'@'} ${railName(g.home)}</span>
        <span class="ap-score-clock">${t}</span>
      </div>`;
    }).join('');
    const more=_apUp.length>4?`<div class="ap-score-row"><span class="ap-score-teams" style="opacity:.45;font-size:.62rem">+${_apUp.length-4} more</span></div>`:'';
    upcomingHTML=`<div class="ap-scores"><div class="ap-section-label">Upcoming</div>${rows}${more}</div>`;
  }

  // ── Section 3: Season context ──────────────────────────────────────────
  const ctx=(typeof getCalendarContext==='function')?getCalendarContext():null;
  // Context pill: clickable filter — taps scroll to first game of relevant league
  const ctxHTML=ctx
    ?`<div class="ap-season"><div class="ap-ctx-label">Season Context</div><span class="ap-ctx-pill" title="Filter to ${ctx.label}" onclick="(()=>{const s=document.querySelector('.game-card[data-sport*=\"${(ctx.relevantLeagues||[]).join('\"],[data-sport*=\"')}\"]');if(s)s.scrollIntoView({behavior:'smooth',block:'center'});})()" style="cursor:pointer">${ctx.label}</span></div>`
    :'';

  // ── Section 3 (editorial): FIELD Brief or Night Owl/Recap ─────────────────
  // On iPad, #field-brief and #night-owl are hidden from left pane — ambient panel
  // is the PRIMARY editorial surface. Renders as a styled card matching the section.
  let editorialHTML = '';
  try {
    const _owlEl = (_DOM?.nightOwl||document.getElementById('night-owl'));
    const _owlActive = _owlEl?.style.display === 'block' && _owlEl?.querySelector('.night-owl-card');
    const _briefEl = (_DOM?.fieldBrief||document.getElementById('field-brief'));
    const _briefActive = _briefEl?.innerHTML?.includes('field-brief-card');
    // Time-based label using ET timezone
    const _etHourStr = new Date().toLocaleString('en-US',{timeZone:'America/New_York',hour:'numeric',hour12:false});
    const _etH = parseInt(_etHourStr)||0;
    const _owlIcon  = _etH >= 22 || _etH < 6  ? '🦉' : _etH < 14 ? '☀️' : '🎯';
    const _owlLabel = _etH >= 22 || _etH < 6  ? 'Night Owl'
                    : _etH < 14                ? 'Morning Report'
                    :                            'Game Recap';
    if (_owlActive) {
      const _owlCard = _owlEl.querySelector('.night-owl-card');
      const _owlGame = _owlCard?.querySelector('.night-owl-winner')?.textContent?.trim()||
                       _owlCard?.querySelector('.night-owl-game')?.textContent?.trim()||'';
      const _owlScore= _owlCard?.querySelector('.night-owl-score-big')?.textContent?.trim()||'';
      const _owlTxtRaw = _owlCard?.querySelector('.night-owl-text')?.textContent?.trim()||'';
      // Cut at last sentence boundary before 260 chars — prevents "This result mov..." mid-sentence clips
      const _owlTxtWindow = _owlTxtRaw.slice(0,260);
      const _owlSentEnd = _owlTxtWindow.search(/[.!?](?=\s+[A-Z]|\s*$)/);
      const _owlTxt = (_owlSentEnd > 40 && _owlSentEnd < 255)
        ? _owlTxtWindow.slice(0, _owlSentEnd + 1)
        : _owlTxtWindow;
      const _owlFull = _owlTxtRaw.replace(/"/g,'&quot;');
      const _owlHasMore = _owlTxtRaw.length > _owlTxt.length;
      editorialHTML = `<div class="ap-card ap-card-owl${_owlHasMore?' ap-card-expandable':''}"
        ${_owlHasMore?`data-full="${_owlFull}" data-trunc-len="200" onclick="_deskCardToggle(this)" style="cursor:pointer"`:''}
        title="${_owlHasMore?'Tap to expand':''}">
        <div class="ap-card-header">
          <span class="ap-card-icon">${_owlIcon}</span>
          <span class="ap-card-label">${_owlLabel}</span>
          ${_owlHasMore?'<span class="ap-card-expand-hint" style="margin-left:auto;font-size:.55rem;color:var(--muted);font-family:var(--ff-mono)">+ expand</span>':''}
        </div>
        ${_owlGame?`<div class="ap-card-game">${_owlGame}${_owlScore?' <span style="opacity:.65;font-size:.7em">'+_owlScore+'</span>':''}</div>`:''}
        ${_owlTxt?`<p class="ap-card-text">${_owlTxt}${_owlHasMore?'…':''}</p>`:''}
      </div>`;
    } else if (_briefActive) {
      const _briefText = _briefEl.querySelector('.field-brief-text')?.textContent?.trim()||'';
      const _briefDate = _briefEl.querySelector('.field-brief-date')?.textContent?.trim()||'';
      if (_briefText.length > 20) {
        const _dfb = _briefText.replace(/"/g,'&quot;');
        editorialHTML = `<div class="ap-card ap-card-brief" data-full="${_dfb}" data-trunc-len="240" onclick="_deskCardToggle(this)">
          <div class="ap-card-header">
            <span class="ap-card-label">FIELD Brief</span>
            ${_briefDate?`<span class="ap-card-date">${_briefDate}</span>`:''}
          </div>
          <p class="ap-card-text">${_briefText.slice(0,240)}${_briefText.length>240?'\u2026':''}</p>
        </div>`;
      }
    }
  } catch(_) {}
  const briefHTML = editorialHTML; // alias for panel.innerHTML template

  // ── Section 5: Arbitrage summary (free games + best add) ──────────────
  // Shown only on iPad where #field-arb is hidden. Compact 1-2 line version.
  let arbHTML='';
  if(typeof buildArbitrageReport==='function'){
    const arb=buildArbitrageReport();
    if(arb&&(arb.freeCount>0||arb.bestAdd)){
      const arbRows=[];
      if(arb.freeCount>0){
        const svcs=[...new Set(arb.freeGames.flatMap(fg=>fg.svcs).filter(Boolean))].slice(0,3);
        arbRows.push(`<div class="ap-arb-row">🎯 <strong>${arb.freeCount} free tonight</strong> · ${svcs.join(' · ')}</div>`);
      }
      if(arb.bestAdd&&arb.missCount>0){
        arbRows.push(`<div class="ap-arb-row">💡 Add <strong>${arb.bestAdd.name}</strong> · ${arb.bestAdd.cost}/mo → +${arb.bestAdd.gameCount} games</div>`);
      }
      if(arbRows.length) arbHTML=`<div class="ap-card ap-card-arb">
        <div class="ap-card-header">
          <span class="ap-card-icon">📡</span>
          <span class="ap-card-label">Watch Free</span>
        </div>
        <div class="ap-card-arb-rows">${arbRows.join('')}</div>
      </div>`;
    }
  }

    // iPad-11: wrap rendered content in .ambient-scroll-inner — the inner
    // div is the scroll container; #ambient-panel is the fixed shell.
    const _apHTML=`${otwHTML}${scoresHTML?`<div class="ap-divider"></div>${scoresHTML}`:''}${soonHTML?`<div class="ap-divider"></div>${soonHTML}`:''}${upcomingHTML?`<div class="ap-divider"></div>${upcomingHTML}`:''}${ctxHTML?`<div class="ap-divider"></div>${ctxHTML}`:''}${arbHTML?`<div class="ap-divider"></div>${arbHTML}`:''}${briefHTML?`<div class="ap-divider"></div>${briefHTML}`:''}`;
  const _apWrapped=`<div class="ambient-scroll-inner">${_apHTML}</div>`;
  if(panel.dataset.lastAp!==_apHTML||panel.querySelector('.ambient-skeleton')){
    // iPad-19 (CLAUDE.md Rule 14 / STANDARDS Rule 24): renderAmbientPanel
    // fires every 15-30s via the ESPN poll cycle. The innerHTML write below
    // replaces the .ambient-scroll-inner element wholesale, which resets
    // scrollTop on the new element to 0 — even if iPad-18's CSS lets the
    // user actually scroll. Save scrollTop before the write, restore after.
    // Without this, every poll yanks the panel back to the top mid-read.
    const _apPrevScroll = panel.querySelector('.ambient-scroll-inner')?.scrollTop || 0;
    panel.dataset.lastAp=_apHTML;
    panel.innerHTML=_apWrapped;
    if (_apPrevScroll > 0) {
      const _apNewInner = panel.querySelector('.ambient-scroll-inner');
      if (_apNewInner) _apNewInner.scrollTop = _apPrevScroll;
    }
  }
}

// ── Broadcast Arbitrage Finder ──────────────────────────────────────────────
// Page-level "what's free tonight + what should I add" summary.
// Reads from allData + MY_SERVICES + SR + SERVICE_COST. No new API calls.
// Complements Wow#32 (per-chip cost) with a cross-game nightly summary.

function buildArbitrageReport(){
  if(!allData?.sports) return null;
  const freeGames=[], haveGames=[], missGames=[];

  (allData.sports||[]).forEach(sec=>{
    (sec.games||[]).forEach(g=>{
      if(!g.home||!g.away) return;
      const streams=resolveStreams(g.streams||[]);
      if(!streams.length) return;

      let isFree=false, isHave=false;
      const missKeys=[]; // cheapest covering keys for miss games

      streams.forEach(s=>{
        const key=s.key||s.srKey||'';
        if(!key) return;
        if(s.auth==='free'||FREE_OTA.has(key)){isFree=true;}
        if(MY_SERVICES.has(key)&&!RSN_KEYS.has(key)){isHave=true;}
        if(SERVICE_COST[key]) missKeys.push(key);
      });

      if(isFree){
        const freeSvcs=streams
          .filter(s=>s.auth==='free'||FREE_OTA.has(s.key||''))
          .map(s=>s.name||s.label||s.key||'')
          .filter(Boolean)
          .slice(0,2);
        freeGames.push({g,svcs:freeSvcs,sport:sec.sport});
      } else if(isHave){
        const haveSvcs=streams
          .filter(s=>MY_SERVICES.has(s.key||'')&&!RSN_KEYS.has(s.key||''))
          .map(s=>s.name||s.label||s.key||'')
          .filter(Boolean)
          .slice(0,1);
        haveGames.push({g,svcs:haveSvcs,sport:sec.sport});
      } else {
        // Sort by cost for miss-game grouping
        const sorted=missKeys.slice().sort((a,b)=>{
          const ca=parseFloat((SERVICE_COST[a]||'999').replace('$',''));
          const cb=parseFloat((SERVICE_COST[b]||'999').replace('$',''));
          return ca-cb;
        });
        missGames.push({g,keys:sorted,sport:sec.sport});
      }
    });
  });

  // Find best single service to add (max games / min cost)
  let bestAdd=null;
  if(missGames.length){
    const svcCount={}; // key → count of miss games it covers
    missGames.forEach(({keys})=>{
      const cheapest=keys[0]; // already sorted by cost
      if(cheapest) svcCount[cheapest]=(svcCount[cheapest]||0)+1;
    });
    let bestScore=-1;
    Object.entries(svcCount).forEach(([key,count])=>{
      const costNum=parseFloat((SERVICE_COST[key]||'999').replace('$',''));
      const score=count/costNum; // games per dollar
      if(score>bestScore||(score===bestScore&&count>(bestAdd?.gameCount||0))){
        bestScore=score;
        const srEntry=SR[key];
        bestAdd={key,name:srEntry?srEntry[0]:key.toUpperCase(),
          cost:SERVICE_COST[key]||'?',gameCount:count,url:srEntry?srEntry[1]:null};
      }
    });
  }

  return {freeGames,haveGames,missGames,bestAdd,
    totalGames:freeGames.length+haveGames.length+missGames.length,
    freeCount:freeGames.length,haveCount:haveGames.length,missCount:missGames.length};
}

function renderArbitrageBar(){
  const el=document.getElementById('field-arb');
  if(!el) return;
  const report=buildArbitrageReport();
  if(!report||report.totalGames===0){el.style.display='none';return;}

  const{freeGames,haveGames,missGames,bestAdd,
    freeCount,haveCount,missCount,totalGames}=report;

  // Nothing to show: no free games and My Services not configured
  if(freeCount===0&&MY_SERVICES.size===0){el.style.display='none';return;}

  const rows=[];

  // Row 1: Free games banner (always shown when free games exist)
  if(freeCount>0){
    const svcSet=new Set(freeGames.flatMap(fg=>fg.svcs));
    const svcsHTML=[...svcSet].slice(0,4)
      .map(n=>`<span class="arb-svc-chip">${n}</span>`).join('');
    rows.push(`<div class="arb-row arb-free arb-tap"
      onclick="document.querySelector('.free-badge')?.closest('.game-card')?.scrollIntoView({behavior:'smooth',block:'center'})"
      title="Tap to scroll to first free game">
      <span class="arb-icon">🎯</span>
      <span class="arb-text">
        <strong>${freeCount} ${freeCount===1?'game':'games'} FREE tonight</strong> — no subscription needed
        <div class="arb-svcs">${svcsHTML}</div>
      </span>
    </div>`);
  }

  // Row 2: Have/Miss split (only when My Services configured)
  if(MY_SERVICES.size>0){
    if(missCount===0){
      rows.push(`<div class="arb-row arb-have">
        <span class="arb-icon">📺</span>
        <span class="arb-text"><strong>You're covered</strong> — your subscriptions cover all ${totalGames} games tonight</span>
      </div>`);
    } else {
      rows.push(`<div class="arb-row arb-have">
        <span class="arb-icon">📺</span>
        <span class="arb-text">
          <strong>${haveCount+freeCount} of ${totalGames} games</strong> covered by your subscriptions
          ${missCount>0?`· <strong>${missCount}</strong> need a service you don't have`:''}
        </span>
      </div>`);
    }
  }

  // Row 3: Best add recommendation (when miss games exist)
  if(bestAdd&&missCount>0){
    rows.push(`<div class="arb-row arb-add arb-tap"
      ${bestAdd.url?`onclick="window.open('${bestAdd.url}','_blank')" title="Open ${bestAdd.name}"`:''}>
      <span class="arb-icon">💡</span>
      <span class="arb-text">
        <strong>Add ${bestAdd.name}</strong> · ${bestAdd.cost}/mo → +${bestAdd.gameCount} more ${bestAdd.gameCount===1?'game':'games'} tonight
      </span>
    </div>`);
  }

  if(rows.length===0){el.style.display='none';return;}
  el.style.display='flex';
  el.innerHTML='<div class="arb-header">📡 Watch Free Tonight</div>'+rows.join('');
}

function renderWatchWindow(){
  const el=document.getElementById('watch-window');
  if(!el||_wwDismissed||!allData) return;
  const now=Date.now(),WINDOW_MS=60*60*1000; // extended to 60 min (was 35)
  // ADR-002 (H4): pick best upcoming by named tier rank, not composite preGameScore.
  let best=null,bestRank=-1;
  (allData.sports||[]).forEach(sec=>{(sec.games||[]).forEach(g=>{
    if(!g.start_time) return;
    const startMs=new Date(g.start_time).getTime();
    const minsAway=(startMs-now)/60000;
    if(minsAway<-2||minsAway>60) return;
    const rank=fieldTierRank(fieldGameTier(g._id));
    if(rank>bestRank){bestRank=rank;best={g,sec,minsAway};}
  });});
  // Show only when top candidate hits a named tier worth surfacing (MARQUEE+).
  const _wwMinRank=fieldTierRank('MARQUEE_NATIONAL');
  if(!best||bestRank<_wwMinRank){el.style.display='none';if(_wwInterval){clearInterval(_wwInterval);_wwInterval=null;}return;}
  const {g,sec,minsAway}=best;
  const _wwSport=(sec.sport||'').toLowerCase();
  const _wwVerb=_wwSport.includes('baseball')?'First pitch':_wwSport.includes('hockey')||_wwSport.includes('nhl')?'Puck drop':_wwSport.includes('football')||_wwSport.includes('nfl')||_wwSport.includes('soccer')||_wwSport.includes('league')||_wwSport.includes('mls')||_wwSport.includes('efl')||_wwSport.includes('world cup')||_wwSport.includes('fifa')||_wwSport.includes('wc26')?'Kickoff':_wwSport.includes('afl')||_wwSport.includes('aussie')?'Bounce':'Tip-off';
  // 35+ min: softer "Up Next" label; <35 min: "Coming Up" with urgency
  const wwHeader = minsAway > 35 ? 'Up Next' : 'Coming Up';
  const minsStr=minsAway<=1?'Starting now':minsAway<=5?_wwVerb+' in '+Math.ceil(minsAway)+' min':minsAway<=35?'Starting in '+Math.ceil(minsAway)+' min':'In ~'+Math.round(minsAway)+' min';
  const stream=g.streams&&g.streams[0];
  const streamLabel=gameNetwork(g);
  const streamKey=stream?stream.key:'';
  const deepLink=streamKey?getDeepLink(streamKey):null;
  const netChip=streamLabel?'<a class="ww-net" '+(deepLink?'href="'+deepLink+'" target="_blank"':'')+'>'+streamLabel+'</a>':'';
  const seriesInfo=g.seriesRecord?' \u00b7 '+g.seriesRecord:'';
  const wwReason=buildWatchWindowReason(g);
  el.style.display='block';
  el.innerHTML='<div class="ww-bar" id="ww-inner"><span class="ww-pulse"></span><span class="ww-header">'+wwHeader+'</span><span class="ww-soon">'+minsStr+'</span><span class="ww-game">'+(g.away||'')+' '+(g.neutral?'vs':'@')+' '+(g.home||'')+seriesInfo+'</span>'+(wwReason?'<span class="ww-reason">'+wwReason+'</span>':'')+netChip+'<button class="ww-close" id="ww-close">\u2715</button></div>';
  document.getElementById('ww-close')?.addEventListener('click',e=>{e.stopPropagation();_wwDismissed=true;el.style.display='none';});
  document.getElementById('ww-inner')?.addEventListener('click',e=>{if(e.target.id==='ww-close'||e.target.closest('a')) return;const h=(g.home||'').replace(/[^a-z]/gi,'').toLowerCase();const card=[...document.querySelectorAll('.game-card')].find(c=>(c.dataset.home||'').replace(/[^a-z]/gi,'').toLowerCase()===h);if(card)card.scrollIntoView({behavior:'smooth',block:'center'});});
  if(!_wwInterval){_wwInterval=setInterval(()=>{const startMs=new Date(best.g.start_time).getTime();if(Date.now()>startMs+5*60000)_wwDismissed=false;renderWatchWindow();},60000);}
}


// J7: SITUATION-ROOM CDW NOTES
const CDW_STATS = {
  nfl_4th_short:   '4th and short: league avg 72% go-for-it. Success rate ~68%.',
  nfl_4th_any:     'NFL 4th down: analytics favor going for it more than coaches historically do.',
  nfl_2min:        '2-minute drill: ~1.4 scoring opportunities remain historically.',
  nfl_redzone:     'Red zone: NFL teams score TDs on ~58% of red zone possessions.',
  mlb_bases_full:  'Bases loaded: historical run-scoring rate is 61% for the at-bat.',
  mlb_bases_risp:  'Runner in scoring position: RBI rate ~28% for average hitter.',
  mlb_full_count:  'Full count (3-2): hit 28%, walk 14%, strikeout 22%.',
  mlb_2out_risp:   '2-out RISP: batting average drops to ~.240 historically under pressure.',
  nba_ot:          'NBA OT: teams up 3+ at OT tipoff win 67% of the time.',
  nhl_ot:          'NHL OT: 73% of games end within the first 5 minutes.',
};
// getCDWNote: checks #18c statistical extremes first, then inline detection
// #18c extremes: no-hitter, 4Q surge, comeback, HT reversal
function getCDWNote(score, sport){
  // #18c: check statistical extremes first — most specific and dramatic signals
  const extremes = getStatisticalExtremes(score, sport);
  if(extremes.note) return extremes.note;

  const sp=(sport||'').toLowerCase();
  const sit=score.situation||{};
  const dn=(sit.shortDownDistanceText||sit.downDistanceText||'').toLowerCase();
  if(sp.includes('nfl')||sp.includes('football')){
    if(dn.includes('4th')&&(/\b[12]\b/.test(dn)||sit.isRedZone)) return CDW_STATS.nfl_4th_short;
    if(dn.includes('4th')) return CDW_STATS.nfl_4th_any;
    if(dn.includes('2-minute')||dn.includes('2 minute')) return CDW_STATS.nfl_2min;
    if(sit.isRedZone) return CDW_STATS.nfl_redzone;
  }
  if(sp.includes('baseball')||sp.includes('mlb')){
    const bases=[score.onFirst,score.onSecond,score.onThird].filter(Boolean).length;
    if(bases===3) return CDW_STATS.mlb_bases_full;
    if(score.outs===2&&(score.onSecond||score.onThird)) return CDW_STATS.mlb_2out_risp;
    if(score.balls===3&&score.strikes===2&&(score.onSecond||score.onThird)) return CDW_STATS.mlb_full_count;
    if(score.onSecond||score.onThird) return CDW_STATS.mlb_bases_risp;
  }
  if(sp.includes('nba')||sp.includes('basketball'))
    if((score.period||0)>4) return CDW_STATS.nba_ot;
  if(sp.includes('nhl')||sp.includes('hockey'))
    if((score.period||0)>3) return CDW_STATS.nhl_ot;
  return null;
}


// ── DRAMA ARC STORAGE LAYER ──────────────────────────────────────────────────
// Stores drama score time-series per live game. The shared temporal primitive
// that makes EMBER, J5, DRIFT, BNI, and Social Contrarian coherent.
//
// KEY:  field_drama_history_{gameId} = [{t, s, p}]
//   t: timestamp ms  s: drama score 0-100 (garbage-time-capped)  p: period/inning
// Cap: 200 samples (~100 min at 30s resolution)
// Gate: 25s minimum between samples (prevents double-write on fast cycles)
//
// CONSUMERS:
//   EMBER (H-1):          getRecentDrama() + getDramaTrend() — recency-weighted evaluation
//   J5 Night Owl:         getDramaHistory() sparkline + getDramaSustained() game ranking
//   DRIFT v2.1 (A-1+):    getDramaTrend() → typed changeset dramaChanges[]
//   BNI (E-1):            getDramaTrend() → calibrate narrative-push confidence
//   Social Contrarian (G-1): getDramaPeakWithTime() → social buzz vs. drama timing
//   Broadcast Context (Wow#44): getDramaHistory() → disambiguate break vs. low-drama play
//
const DRAMA_HISTORY_KEY = 'field_drama_history_';
const DRAMA_HISTORY_MAX = 200;    // ~100 min at 30s
const DRAMA_SAMPLE_MIN  = 25000;  // ms — minimum gap between samples

function recordDramaHistory(gameId, score, period) {
  if (!gameId || score < 0) return;
  try {
    const key = DRAMA_HISTORY_KEY + gameId;
    const hist = JSON.parse(localStorage.getItem(key) || '[]');
    const now = Date.now();
    // Gate: skip if last sample was too recent
    if (hist.length > 0 && now - hist[hist.length - 1].t < DRAMA_SAMPLE_MIN) return;
    hist.push({ t: now, s: Math.round(score), p: period || 0 });
    if (hist.length > DRAMA_HISTORY_MAX) hist.splice(0, hist.length - DRAMA_HISTORY_MAX);
    localStorage.setItem(key, JSON.stringify(hist));
  } catch(e) { /* localStorage quota or unavailable */ }
}

// ── Consumer API ─────────────────────────────────────────────────────────────

// Full history array — primary access for J5 sparkline and Social timing
function getDramaHistory(gameId) {
  try { return JSON.parse(localStorage.getItem(DRAMA_HISTORY_KEY + gameId) || '[]'); }
  catch(e) { return []; }
}

// Last N samples (~30s each) — EMBER current-state check
function getRecentDrama(gameId, n = 3) {
  return getDramaHistory(gameId).slice(-n);
}

// Trend: + = rising, - = falling, 0 = flat or insufficient data
// Delta between oldest and newest of last N samples
// Used by: EMBER (is buried game currently rising?), DRIFT changeset, BNI calibration
function getDramaTrend(gameId, n = 4) {
  const hist = getDramaHistory(gameId);
  if (hist.length < 2) return 0;
  const w = hist.slice(-n);
  return w[w.length - 1].s - w[0].s;
}

// Minutes drama has been sustained above threshold in the given window
// Used by: J5 game selection (sustained > peak), EMBER context boost
// nowOverride (CC-CMD-2026-07-02 drama-backfill-client): optional 4th
// param, defaults to Date.now() — 100% backward compatible with every
// existing call site (none pass a 4th arg). Needed because retroactive
// backfill computes drama for games whose real timestamps are in the
// past; without an override, `cutoff = Date.now() - windowMs` would
// always be more recent than every historical sample, silently forcing
// sustainedMinutes to 0 for any backfilled game regardless of its real
// data.
function getDramaSustained(gameId, threshold = 65, windowMs = 30 * 60 * 1000, nowOverride) {
  const now = nowOverride ?? Date.now();
  const cutoff = now - windowMs;
  const inWindow = getDramaHistory(gameId).filter(h => h.t >= cutoff && h.s >= threshold);
  return Math.round(inWindow.length * 0.5 * 10) / 10; // minutes, 1dp
}

// Peak sample with timestamp — Social Contrarian timing comparison
// "Did social buzz arrive before or after the drama peaked?"
function getDramaPeakWithTime(gameId) {
  const hist = getDramaHistory(gameId);
  if (!hist.length) return { s: 0, t: 0, p: 0 };
  return hist.reduce((m, h) => h.s > m.s ? h : m, hist[0]);
}

// getDramaGateway: structural access point for drama data, keyed on game state.
// post  → {mode:'score', value, arc, peak}: numeric drama value only exits here.
// live  → {mode:'observation', value: named live condition}: never a raw number.
// pre   → {mode:'observation', value: named pre-game condition}: never a raw number.
// Structurally prevents live/pre render paths from receiving a numeric drama value.
// Named live states: CRUNCH_TIME, CLOSE_FINISH, BLOWOUT, IN_PROGRESS
// Named pre  states: MARQUEE, SCOUTS_PICK, STANDARD
function getDramaGateway(game, sport) {
  const state  = game?.state;
  const sp     = String(sport || game?._sport || '').toLowerCase();
  const isPost = state === 'post' || state === 'final';
  const isLive = state === 'in'   || state === 'live';

  if (isPost) {
    const gameId    = game._id || game.id || game._gameId || '';
    const peakInfo  = getDramaPeakWithTime(gameId);
    const hist      = getDramaHistory(gameId);
    const lastT     = hist.length ? hist[hist.length - 1].t : 0;
    const trend     = hist.length >= 2 ? hist[hist.length - 1].s - hist[0].s : 0;
    const sustained = getDramaSustained(gameId, 65, 30 * 60 * 1000, lastT || undefined);
    const arc       = _dramaArcClassify(peakInfo.s, sustained, trend, peakInfo.s);
    return { mode: 'score', value: peakInfo.s, arc, peak: peakInfo.s };
  }

  if (isLive) {
    const eData = typeof findEspnEntry === 'function' ? findEspnEntry(game) : null;
    if (eData) {
      if (isCrunchTimeGame(eData, sp))      return { mode: 'observation', value: 'CRUNCH_TIME' };
      if (isLateCloseGame(game, eData, sp)) return { mode: 'observation', value: 'CLOSE_FINISH' };
      const margin   = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
      const period   = eData.period || 0;
      const isFinalP = (
        (sp.includes('basketball')||sp.includes('nba')) ? period >= 4 :
        (sp.includes('hockey')    ||sp.includes('nhl')) ? period >= 3 :
        (sp.includes('football')  ||sp.includes('nfl')) ? period >= 4 :
        (sp.includes('baseball')  ||sp.includes('mlb')) ? period >= 9 : false
      );
      if (isFinalP && margin > 24) return { mode: 'observation', value: 'BLOWOUT' };
    }
    return { mode: 'observation', value: 'IN_PROGRESS' };
  }

  // pre-game (state==='pre') or unknown state
  if (typeof isMarqueeBroadcast === 'function' && isMarqueeBroadcast(game)) return { mode: 'observation', value: 'MARQUEE' };
  if (typeof isScoutsPick === 'function' && isScoutsPick(game))             return { mode: 'observation', value: 'SCOUTS_PICK' };
  return { mode: 'observation', value: 'STANDARD' };
}

// Rolling average of last N samples — smoothed drama score for badge decisions
// Use this instead of raw dramaScoreLive() output for any consumer that renders to screen.
// Raw scores go to recordDramaHistory() (preserve signal); smoothed scores drive display.
// Prevents single-poll spikes from triggering CRUNCH TIME / EMBER / BNI prematurely.
function getSmoothedDrama(gameId, n = 3) {
  const recent = getRecentDrama(gameId, n);
  if (recent.length < 2) return null; // insufficient history — caller falls back to raw
  return Math.round(recent.reduce((sum, h) => sum + h.s, 0) / recent.length);
}

// ── Retroactive Drama Backfill (CC-CMD-2026-07-02 drama-backfill-client) ──
// Fixes: drama_peak is NULL for completed games where no live session was
// open long enough to accumulate samples (structural gap since at least
// 2026-06-20 — the existing archival trigger at saveEspnFinal()'s drama-
// persistence block only fires if dramaPeak>0 was accumulated live).
// This replays the EXACT existing dramaScoreLive() against reconstructed
// historical game state instead — same function, historical snapshots
// instead of live ones. Does not touch RUWT/ADR-002; relay role unchanged.

// Classify arc shape — copied verbatim from the existing live archival
// trigger (saveEspnFinal, ~L36583) so backfilled and live-tracked games
// get identical classification logic, not a second diverging copy.
function _dramaArcClassify(peak, sustained, trend, peakScore) {
  return peak >= 80 && sustained >= 5 ? 'thriller'
    : peak >= 70 && trend > 10 ? 'nail-biter'
    : peak < 35 ? 'blowout'
    : trend > 15 && peakScore > 60 ? 'comeback'
    : 'sleeper';
}

// TASK 1: replays dramaScoreLive() against each historical snapshot,
// building the same {t,s,p}-shaped history recordDramaHistory() would
// have built live (t is the real historical wallclock, not Date.now()).
// Reuses getDramaHistory/getDramaPeakWithTime/getDramaSustained/
// getDramaTrend UNMODIFIED by writing the reconstructed history to a
// TEMPORARY, namespaced localStorage key — never the real live-tracking
// key for this gameId (avoids any collision with a concurrently-open
// live session) — then removing it immediately after reading the
// derived values. Nothing is left behind afterward: "compute in
// memory... discard" in effect, even though the existing consumer
// functions only know how to read from localStorage by gameId.
//
// IMPORTANT: dramaScoreLive() returns 0 immediately unless
// eData.state==='in' (confirmed via probe — state defaults to 'pre' and
// both 'pre'/'post' short-circuit to 0). Historical snapshots have no
// natural state field; every snapshot must be tagged state:'in' or this
// entire computation silently produces all zeros.
function computeDramaRetroactive(historicalStates, sport, homeRank, awayRank) {
  if (!historicalStates || !historicalStates.length) return null;
  const hist = historicalStates.map(st => {
    // CC-CMD-2026-07-04-soccer-drama-scoring-fix TASK 4: homeRank/awayRank
    // are optional (undefined for MLB, which never passes them) — spread
    // order puts them before state:'in' so they're always present as real
    // values (or undefined) rather than accidentally overwritten by
    // anything on st.
    const score = dramaScoreLive({ homeRank, awayRank, ...st, state: 'in' }, sport);
    return { t: st.t, s: Math.round(score), p: st.period || 0 };
  });

  const tempId = `_backfill_${Date.now()}_${Math.random().toString(36).slice(2)}`;
  const tempKey = DRAMA_HISTORY_KEY + tempId;
  try {
    localStorage.setItem(tempKey, JSON.stringify(hist));
    const peakInfo  = getDramaPeakWithTime(tempId);
    const lastT     = hist[hist.length - 1].t;
    // nowOverride=lastT: "sustained in the final 30 min of available
    // data", the historical equivalent of the live version's "last 30
    // min relative to now" — see getDramaSustained's nowOverride comment.
    const sustained = getDramaSustained(tempId, 65, 30 * 60 * 1000, lastT);
    const trend     = getDramaTrend(tempId);
    const fullHist  = getDramaHistory(tempId);

    const step = Math.max(1, Math.floor(fullHist.length / 10));
    const samples = fullHist.filter((_, i) => i % step === 0 || i === fullHist.length - 1)
      .map(h => ({ s: h.s, p: h.p }));

    return {
      peak: peakInfo.s,
      peakPeriod: peakInfo.p || 0,
      peakMinute: null, // same as the live path — future: compute from game start delta
      sustainedMinutes: sustained,
      trend: trend > 5 ? 'escalating' : trend < -5 ? 'declining' : 'steady',
      classification: _dramaArcClassify(peakInfo.s, sustained, trend, peakInfo.s),
      samples,
    };
  } finally {
    try { localStorage.removeItem(tempKey); } catch(e) {}
  }
}

// TASK 2: MLB retroactive state reconstruction. Fetches via
// ESPN_SUMMARY_RELAY, NOT a direct fetch to site.api.espn.com — ESPN's
// summary endpoint has CORS locked to espn.com in the browser (confirmed
// via the existing fetchESPNWinProb() precedent, same relay route
// pattern already proven working in this file). MLB's dramaScoreLive
// branch only reads period (extra-innings threshold), not clock —
// confirmed against the real function body during pre-build probe, and
// plays[] shape confirmed live against event 401815989 (Rays 4, Royals
// 0): 505 real entries, homeScore/awayScore/period.number/wallclock all
// present, final play matches the real 4-0 result.
async function fetchMLBHistoricalStates(espnEventId) {
  try {
    const url = `${ESPN_SUMMARY_RELAY}/sports/baseball/mlb/summary?event=${encodeURIComponent(String(espnEventId))}`;
    const r = await fetch(url, { signal: AbortSignal.timeout(15000) });
    if (!r.ok) return [];
    const data = await r.json();
    return (data.plays || [])
      .filter(p => p.wallclock)
      .map(p => ({
        homeScore: p.homeScore || 0,
        awayScore: p.awayScore || 0,
        period: p.period?.number || 1,
        clock: '', // MLB dramaScoreLive doesn't use clock, only period
        t: new Date(p.wallclock).getTime(),
      }));
  } catch(e) {
    if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.log('[DRAMA-BACKFILL] MLB fetch error:', e?.message);
    return [];
  }
}

// TASK 3: Soccer retroactive state reconstruction. keyEvents[] does NOT
// carry running score directly — reconstructed by iterating events in
// order and incrementing the scoring team's tally on each
// scoringPlay:true entry. Scoring team identified by event.team.id
// compared against the home team's ID from
// header.competitions[0].competitors — confirmed via a real probe
// against event 760495 (England 2-1 Congo DR): tracing all 3 real
// scoring events (team.id 2850/away then 448/home twice) reproduces
// exactly 2-1, not assumed from a guessed field name. League slug
// defaults to 'fifa.world', matching the existing blanket-slug pattern
// already used elsewhere in this file (~L37203 for all soccer/WC
// content) — confirmed via probe that 'fifa.world' ALSO resolves a
// genuine non-WC26 friendly (event 760495), so this is not a WC26-only
// special case; ESPN's summary routing is lenient about the league path
// segment for at least these two soccer leagues.
async function fetchSoccerHistoricalStates(espnEventId, league) {
  try {
    const slug = league || 'fifa.world';
    const url = `${ESPN_SUMMARY_RELAY}/sports/soccer/${slug}/summary?event=${encodeURIComponent(String(espnEventId))}`;
    const r = await fetch(url, { signal: AbortSignal.timeout(15000) });
    if (!r.ok) return [];
    const data = await r.json();
    const competitors = data.header?.competitions?.[0]?.competitors || [];
    const homeTeamId = competitors.find(c => c.homeAway === 'home')?.team?.id;
    if (!homeTeamId) return [];
    let homeScore = 0, awayScore = 0;
    const eventStates = (data.keyEvents || [])
      .filter(e => e.wallclock)
      .map(e => {
        if (e.scoringPlay) {
          if (String(e.team?.id) === String(homeTeamId)) homeScore++; else awayScore++;
        }
        return {
          homeScore, awayScore,
          period: e.period?.number || 1,
          clock: e.clock?.displayValue || '',
          t: new Date(e.wallclock).getTime(),
        };
      });
    if (eventStates.length < 2) return eventStates; // nothing to interpolate between

    // CC-CMD-2026-07-04-soccer-drama-scoring-fix TASK 2: keyEvents-only
    // sampling has no representation of time passing without a goal/card/
    // sub -- confirmed real gap via the Argentina/Cape Verde case (a tense
    // scoreless stretch approaching stoppage time had no keyEvent marking
    // it, so the peak-finder never evaluated that moment at all). Interpolate
    // synthetic sample points every 5 real minutes between consecutive
    // events, carrying forward the last-known score/period and synthesizing
    // an advancing clock value, so dramaScoreLive's time-bonus logic still
    // sees rising urgency even when nothing "key" happened. Real event
    // points are preserved unchanged -- this only fills the gaps.
    const FIVE_MIN_MS = 5 * 60 * 1000;
    const interpolated = [eventStates[0]];
    for (let i = 1; i < eventStates.length; i++) {
      const prev = eventStates[i - 1];
      const curr = eventStates[i];
      const gap = curr.t - prev.t;
      const steps = Math.floor(gap / FIVE_MIN_MS);
      for (let s = 1; s < steps; s++) {
        const prevClockMin = parseInt(prev.clock) || 0;
        interpolated.push({
          homeScore: prev.homeScore,
          awayScore: prev.awayScore,
          period: prev.period,
          clock: String(prevClockMin + s * 5), // approximate advancing minute
          t: prev.t + s * FIVE_MIN_MS,
        });
      }
      interpolated.push(curr);
    }
    return interpolated;
  } catch(e) {
    if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.log('[DRAMA-BACKFILL] Soccer fetch error:', e?.message);
    return [];
  }
}

// TASK 4: Discovery + backfill loop. Fires once per app session, capped
// at 3 games — same conservative per-session cap pattern already used
// elsewhere in this codebase (slice(0,3) multi-league scoreboard fetch).
// Fire-and-forget per game, never blocks app startup — same keepalive/
// .catch(()=>{}) pattern as the existing live drama POST. source_id in
// the POST uses the discovery response's own `id` field (its composite
// SPORT_DATE_HOME_AWAY identifier), not espn_event_id — the discovery
// endpoint's entire purpose is "this D1 row (keyed by source_id=id) is
// missing drama_peak"; espn_event_id is only used to know which ESPN
// summary endpoint to fetch for reconstruction.
async function runDramaBackfillDiscovery() {
  try {
    const relayBase = (typeof V2_RELAY_BASE !== 'undefined') ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
    const r = await fetch(`${relayBase}/archive/drama-missing?limit=20`, { signal: AbortSignal.timeout(8000) });
    if (!r.ok) return 0;
    const data = await r.json();
    const games = (data.games || []).slice(0, 20); // hard cap even if the relay ever returns more
    for (const g of games) {
      _backfillOneDramaGame(g).catch(e => captureFieldError('archive:drama-backfill-game', e, true)); // fire-and-forget, never blocks
    }
    return games.length;
  } catch(e) {
    captureFieldError('archive:drama-backfill-discovery', e, false);
    if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) console.log('[DRAMA-BACKFILL] discovery error:', e?.message);
    return 0;
  }
}

async function _backfillOneDramaGame(g) {
  const sp = (g.sport || '').toLowerCase();
  const isMLB = sp.includes('mlb') || sp.includes('baseball');
  const states = isMLB
    ? await fetchMLBHistoricalStates(g.espn_event_id)
    : await fetchSoccerHistoricalStates(g.espn_event_id);
  if (!states.length) return;
  // CC-CMD-2026-07-04-soccer-drama-scoring-fix TASK 4: fetch real FIFA
  // ranks for soccer games only (MLB has no rank concept here). Awaited
  // directly since this whole function is already async/fire-and-forget
  // from its own caller — adds one more per-game relay call, not a new
  // blocking behavior class. "Team not found" (unmapped team) resolves
  // to null via fetchTeamRank, which dramaScoreLive's upsetBonus already
  // treats as "no upset bonus for that game" rather than an error.
  let homeRank = null, awayRank = null;
  if (!isMLB) {
    [homeRank, awayRank] = await Promise.all([
      fetchTeamRank(g.home),
      fetchTeamRank(g.away),
    ]);
  }
  const arc = computeDramaRetroactive(states, isMLB ? 'mlb' : 'soccer', homeRank, awayRank);
  if (!arc) return;
  const relayBase = (typeof V2_RELAY_BASE !== 'undefined') ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
  fetch(`${relayBase}/archive/drama`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      source_id: g.id || g.espn_event_id,
      drama_peak: arc.peak,
      drama_arc: JSON.stringify(arc),
    }),
    keepalive: true,
  }).catch(e => captureFieldError('archive:drama-backfill', e, false));
}

// ── Broadcast Narrative Index (BNI) ──────────────────────────────────────────
// Detects when broadcast attention is disproportionate to game quality.
// Three signal types, ordered by strength:
//   'narrative-push':       market says blowout + network has marquee crew
//   'elimination-inflation': playoff/series framing on low-drama game
//   'home-market':          big-market team on national broadcast with A-crew
//
// Phase 1 (this build): signal detection + J3 injection
// Phase 2 (BNI session): wire into preGameScore confidence + EMBER distribution tier
// getDramaTrend() calibrates strength for live games (rising = weaker BNI)
function computeBroadcastNarrativeIndex(game) {
  if (!isNationalGame(game)) return null; // BNI only applies to national broadcasts

  // #11a: suppress BNI when situation is genuinely exciting (not manufactured hype)
  // Goalie pulled, bases loaded, 4th & short in final 2 min — real drama, not media push
  const liveScore = typeof findESPNScore === 'function' ? findESPNScore(game) : null;
  if(liveScore?.state === 'in') {
    const sit = liveScore.situation || {};
    if(sit.homeGoaliePulled || sit.awayGoaliePulled) return null;        // goalie pulled = real
    const runners = [liveScore.onFirst, liveScore.onSecond, liveScore.onThird].filter(Boolean).length;
    if(runners === 3) return null;                                         // bases loaded = real
    if(runners >= 1 && liveScore.outs === 2 && (liveScore.period||0)>=7) return null; // late RISP
  }

  const pgScore = preGameScore(game);
  const marquee  = isMarqueeBroadcast(game);


  // Patent fix: replace pgScore threshold comparisons with !isScoutsPick() boolean gate.
  // OLD: pgScore < 45 / pgScore < 50 — composite preGameScore thresholded directly.
  //      This is the patent bright line: composite value + threshold = interest-level claim.
  // NEW: isScoutsPick() is an independent boolean — "is this genuinely a good game?"
  //      If NOT a scout's pick → the series/market attention is manufactured hype.
  //      No composite number. No threshold. A single independent boolean gate.

  // 'elimination-inflation': series context on a game that isn't genuinely compelling
  if (game.seriesRecord && !isScoutsPick(game)) return 'elimination-inflation';

  // 'home-market': big market + marquee crew, game not genuinely interesting
  if (marquee && isBigMarketGame(game) && !isScoutsPick(game)) return 'home-market';

  return null;
}

// Calibrated BNI strength: rising drama weakens signal (game earning attention)
// falling drama strengthens it (hype confirmed to exceed reality)
// Returns 0-100 score for use by future EMBER + Social Contrarian phases
function getBNIStrength(game, bniType) {
  if (!bniType) return 0;
  const gid = game._id;
  const trend = gid ? getDramaTrend(gid) : 0;
  const trendMod = trend > 5 ? 0.6 : trend < -3 ? 1.4 : 1.0;
  const base = {'narrative-push':90,'elimination-inflation':65,'home-market':50}[bniType] || 0;
  return Math.round(base * trendMod);
}

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: EMBER — Buried Lead detector
// Fires when a game has low broadcast distribution but high drama or rich context.
// The distribution paradox: best game tonight ≠ most-promoted game.
// EMBER never fires on Tier 1 (ESPN/ABC/NBC/FOX/CBS). CRUNCH TIME pulses. BURIED LEAD sits.
// ═══════════════════════════════════════════════════════════════════════════
const EMBER_TIER1 = new Set(['NBA_ESPN','NBA_ABC','NBA_NBC','NHL_ESPN','NHL_ABC',
  'MLB_FOX','MLB_TBS','MLB_NBC','NFL_ESPN','NFL_ABC','NFL_NBC','NFL_FOX','NFL_CBS',
  'EPL_NBC','UCL_CBS','MLS_FOX','MLS_FS1']);
const EMBER_TIER2 = new Set(['NBA_PRIME','MLB_APPLE','MLB_PEACOCK_SNB','MLB_LEADOFF',
  'EPL_PEACOCK','EFL_PARAMOUNT','AFL_FS1','MLS_APPLE']);
// Tier 3/4 = anything else with a national bundle or streaming-only

function getEmberDistributionTier(g) {
  if (!g.nationalBundle) return 4; // local/RSN only — strongest EMBER candidate
  if (EMBER_TIER1.has(g.nationalBundle)) return 1; // not EMBER eligible
  if (EMBER_TIER2.has(g.nationalBundle)) return 2;
  return 3; // cable/niche streaming
}

// isLateCloseGame — independent boolean gate for EMBER patent fix.
// Returns true when a game is objectively late AND close:
//   - Late: final period/inning of regulation
//   - Close: margin ≤ 3 (or tied)
// Two independent observable facts. No composite. No threshold arithmetic.
// Patent note: this is Case C (Numerical Usage Policy) — classification by
// individual observable conditions, not by a single aggregated interest score.
function isLateCloseGame(g, ed, sport) {
  if (!ed || ed.state !== 'in') return false;
  const sp = (sport || '').toLowerCase();
  const period  = ed.period || 0;
  const margin  = Math.abs((ed.homeScore || 0) - (ed.awayScore || 0));
  const isClose = margin <= 3;
  const isLate  =
    (sp.includes('baseball') || sp.includes('mlb'))     ? period >= 8  :
    (sp.includes('basketball') || sp.includes('nba'))   ? period >= 4  :
    (sp.includes('hockey') || sp.includes('nhl'))       ? period >= 3  :
    (sp.includes('football') || sp.includes('nfl'))     ? period >= 4  :
    (sp.includes('soccer') || sp.includes('epl') || sp.includes('wc26') || sp.includes('world cup') || sp.includes('fifa')) ? period === 2 :
    false;
  return isLate && isClose;
}

function getEmberThreshold(tier, sport) {
  const sp = (sport||'').toLowerCase();
  if (tier === 2) {
    if (sp.includes('mls')) return 52; // MLS Season Pass fires readily
    if (sp.includes('efl') || sp.includes('championship')) return 52;
    return 68;
  }
  if (tier === 3) return 65;
  // Tier 4: niche streaming, lowest threshold
  if (sp.includes('afl')) return 50;
  return 60;
}

function hasEmberContextBoost(g, sport) {
  const sp = (sport||'').toLowerCase();
  if (g.seriesRecord && g.seriesRecord !== '0-0') return true;
  if (g._gameImportance && g._gameImportance !== 'none') return true;
  if (sp.includes('baseball') && g.matchupNote?.toLowerCase().includes('no-hit')) return true; // no-hitter override
  if (sp.includes('afl') && g.matchupNote?.toLowerCase().includes('anzac')) return true;
  return false;
}

function evaluateEMBER(g, sport, ed) {
  const tier = getEmberDistributionTier(g);
  if (tier === 1) return null; // national broadcast — not eligible
  const contextBoost = hasEmberContextBoost(g, sport);

  // Patent fix: replace dramaScore < threshold with isLateCloseGame() boolean gate.
  // OLD: baseThreshold arithmetic on dramaScore — composite value + threshold = bright line.
  // NEW: two independent boolean gates, non-summed:
  //   Gate A — isLateCloseGame(): observable game state (late + close)
  //   Gate B — hasEmberContextBoost(): structural context (series, importance flag)
  // EMBER fires when EITHER independent gate passes. No single aggregated number thresholded.
  // dramaScore deliberately EXCLUDED from signature and return — EMBER is distribution + game
  // state, never an interest level value. Removing prevents "general notification" exposure.
  const lateAndClose = isLateCloseGame(g, ed, sport);
  if (!lateAndClose && !contextBoost) return null;

  return {
    ember: true, tier,
    channel: gameNetwork(g, g.nationalBundle || 'local'),
    contextFlag: contextBoost,
    lateClose: lateAndClose,
  };
}

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: NBA LINEUP EDGE — Roster Advantage Index (RAI)
// Quality differential between current team rotations.
// Signal: BDL season +/- per player (pre-game quality proxy)
// Active players: ESPN boxscore minutes/starter status (who's been on court)
// Display: .rai-line on card (all viewports) + bottom sheet section
//          [CLOSING UNIT] badge when trailing team's top rotation is on late
// Architecture: async fetch → sessionStorage cache → sync display reads cache
// RUWT: named factual state (who is on court = observable) + historical rates ✅
// ═══════════════════════════════════════════════════════════════════════════

const _raiCache = {};     // espnGameId → {edge, homeQ, awayQ, homeAbbr, awayAbbr, ts}
const RAI_TTL = 90000;    // 90s — one refresh per ESPN poll cycle

// ═══════════════════════════════════════════════════════════════════════════
// NBA CDN PLAY-BY-PLAY — Three-tier fallback for exact lineup tracking
// Tier 1: NBA CDN  cdn.nba.com/static/json/liveData/playbyplay/playbyplay_{id}.json
//         → exact 5-man lineup via SUB events + stint net score (Layer 3)
// Tier 2: ESPN plays[] from summary relay (if site.web.api.espn.com route active)
//         → SUB events from ESPN's own data
// Tier 3: ESPN boxscore minutes (existing RAI approximation — always works)
//
// NBA CDN activation: add /nba-live/* route to field-relay-nba worker.
// Until then, fetchNBAPBP() returns null and Tier 3 stays active.
// PlayByPlayV2 deprecated 2025-26 — CDN endpoint is the correct live source.
// ═══════════════════════════════════════════════════════════════════════════

const _nbaGameIdMap   = {};    // 'homeLower_awayLower' → 10-digit NBA game ID
const _nbaBoxscoreCache = {};  // gameId → {homeLinescores:[], awayLinescores:[], homePlayers:[], awayPlayers:[], ts}
let   _nbaScoreboardTs = 0;    // last scoreboard fetch timestamp
const NBA_SCOREBOARD_TTL = 10 * 60 * 1000; // refresh every 10 min

// ── NBA Live Boxscore Cache (PM-30) ──────────────────────────────────────────
// Populated by fetchNBALiveBoxscore() on 90s cadence during live games.
// Schema mirrors CDN /liveData/boxscore/boxscore_{gameId}.json per-player fields.
// RUWT note: all fields are named observable facts (who is on court, foul count,
// current stint +/-) — not composite interest scores. Safe for live display.
const _nbaLiveBoxscoreCache = {}; // gameId → {
//   oncourt: [{name, tricode, pts, reb, ast, plusMinus, fouls}],  ← on court NOW
//   homeLeaders: {name, pts, reb, ast},                           ← top scorer home
//   awayLeaders: {name, pts, reb, ast},                           ← top scorer away
//   foulTrouble: [{name, tricode, fouls, isStarter}],             ← starters ≥3 fouls
//   officials: [{name, assignment}],                              ← referees
//   homeStintPM: number,  ← live current-lineup net (home)
//   awayStintPM: number,  ← live current-lineup net (away)
//   ts: timestamp }
let _nbaLiveBoxscoreTs = {}; // gameId → last fetch timestamp
const NBA_LIVE_BS_TTL = 90 * 1000; // 90s — one per ESPN poll cycle

// Gap 6 cache: gameLeaders from scoreboard (0-cost, already polled 30-60s)
const _nbaScoreLeaders = {}; // gameId → {home:{name,pts,reb,ast}, away:{name,pts,reb,ast}}

// ── parseNBAScoreboardGames — pure parsing helper for fetchNBAScoreboard ──────
// Extracted from the inner loop so it can be unit-tested synthetically (see
// field_utils.js + field_unit.js) without needing a live CDN response.
// Scoreboard P0 diagnostic confirmed CDN shape:
//   g.gameId / homeTeam.teamTricode / awayTeam.teamTricode /
//   homeTeam.teamName / awayTeam.teamName
// Writes 4 keys per game (tricode h_a, tricode a_h, teamName h_a, teamName a_h)
// so fetchNBAPBP can look up by either tricode or teamNick() output.
function parseNBAScoreboardGames(games, gameIdMap) {
  for (const g of (games || [])) {
    const id    = g.gameId;
    const hTri  = (g.homeTeam?.teamTricode || '').toLowerCase();
    const aTri  = (g.awayTeam?.teamTricode || '').toLowerCase();
    const hName = (g.homeTeam?.teamName    || '').toLowerCase();
    const aName = (g.awayTeam?.teamName    || '').toLowerCase();
    if (!id) continue;
    for (const [h, a] of [[hTri, aTri], [hName, aName]]) {
      if (h && a) {
        gameIdMap[`${h}_${a}`] = id;
        gameIdMap[`${a}_${h}`] = id;
      }
    }
    // Gap 6: extract live gameLeaders (top scorer per team) from scoreboard.
    // Zero extra cost — scoreboard is already polled every 30-60s.
    // Writes into _nbaScoreLeaders[gameId] for compound prompt + RAI context.
    try {
      const hl = g.gameLeaders?.homeLeaders;
      const al = g.gameLeaders?.awayLeaders;
      if (hl || al) {
        _nbaScoreLeaders[id] = {
          home: hl?.name ? { name: hl.name, pts: hl.points||0, reb: hl.rebounds||0, ast: hl.assists||0, tricode: hl.teamTricode||'' } : null,
          away: al?.name ? { name: al.name, pts: al.points||0, reb: al.rebounds||0, ast: al.assists||0, tricode: al.teamTricode||'' } : null,
          ts: Date.now(),
        };
      }
    } catch(_e30) {}
  }
  return gameIdMap;
}

// Fetch today's NBA scoreboard to build ESPN team abbr → NBA game ID map.
// Parsing logic extracted to parseNBAScoreboardGames (field_utils.js) so it
// can be unit-tested with synthetic data independent of live CDN state.
// Scoreboard P0 diagnostic: relay allow-list added (e0b44e7), CDN shape
// confirmed via probe (outbox/scoreboard-probe-20260605T140635Z.*).
async function fetchNBAScoreboard() {
  const now = Date.now();
  if (now - _nbaScoreboardTs < NBA_SCOREBOARD_TTL && Object.keys(_nbaGameIdMap).length) return;
  _nbaScoreboardTs = now;
  try {
    const r = await fetch(`${NBA_CDN_RELAY}/liveData/scoreboard/todaysScoreboard_00.json`,
      { signal: AbortSignal.timeout(4000) });
    if (!r.ok) return;
    const d = await r.json();
    parseNBAScoreboardGames(d?.scoreboard?.games, _nbaGameIdMap);
    if (FIELD_DEBUG) console.debug('[NBA-CDN] scoreboard mapped', Object.keys(_nbaGameIdMap).length/4, 'games');
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[NBA-CDN] scoreboard:', e.message);
  }
}

// ── fetchNBALiveBoxscore (PM-30) ─────────────────────────────────────────────
// Fetches the CDN live boxscore for a game during play. Runs on 90s cadence
// (same as fetchNHLLiveStats). Extracts:
//   Gap 1: oncourt[] — which 10 players are on the floor right now (oncourt:"1")
//   Gap 2: live stint plusMinusPoints — blended with season +/- for RAI quality
//   Gap 3: foul trouble — starters ≥ 3 fouls in Q1-Q2, or ≥ 4 in Q3 (named fact)
//   Gap 5: officials — referee names for compound prompt context
//
// RUWT compliance: all fields are named observable facts.
//   - oncourt: who is physically on the court (binary observable)
//   - plusMinusPoints: current unit net (factual score differential)
//   - foulsPersonal: foul count (factual observable, named threshold per NBA rules)
//   - officials: who is officiating (factual identity)
// None of these are composite interest/excitement scores. No threshold-comparison
// for live recommendation purposes. Foul trouble threshold (3 in Q1-Q2) mirrors
// the NBA rule threshold, not a FIELD interest score.
async function fetchNBALiveBoxscore(nbaId) {
  if (!nbaId) return null;
  const now = Date.now();
  if (_nbaLiveBoxscoreTs[nbaId] && now - _nbaLiveBoxscoreTs[nbaId] < NBA_LIVE_BS_TTL) {
    return _nbaLiveBoxscoreCache[nbaId] || null;
  }
  _nbaLiveBoxscoreTs[nbaId] = now;
  try {
    const r = await fetch(`${RELAY_BASE}/liveData/boxscore/boxscore_${nbaId}.json`,
      { signal: AbortSignal.timeout(5000) });
    if (!r.ok) return _nbaLiveBoxscoreCache[nbaId] || null;
    const d = await r.json();
    const game = d?.game;
    if (!game) return null;

    const period = game.period || 0;

    // Extract per-player data from both teams
    const parseTeam = (team) => {
      const players = team?.players || [];
      const oncourt = [];
      const foulTrouble = [];
      let stintPM = 0, stintN = 0;
      for (const p of players) {
        const s = p.statistics || {};
        const name = p.name || p.firstName + ' ' + p.familyName || '';
        const isOnCourt = p.oncourt === '1' || p.oncourt === 1;
        const fouls = s.foulsPersonal || 0;
        const pm = s.plusMinusPoints ?? null;
        const pts = s.points || 0;
        const reb = s.reboundsTotal || 0;
        const ast = s.assists || 0;
        const mins = parseFloat((s.minutesCalculated||'PT0M').replace('PT','').replace('M','')) || 0;
        const isStarter = p.starter === '1' || p.starter === 1;

        if (isOnCourt) {
          oncourt.push({ name, tricode: team.teamTricode || '', pts, reb, ast,
                         plusMinus: pm, fouls, mins, isStarter });
          if (pm != null) { stintPM += pm; stintN++; }
        }
        // Gap 3: foul trouble — starters with ≥3 fouls in Q1-Q2, or ≥4 in Q3+
        const foulThreshold = period <= 2 ? 3 : 4;
        if (isStarter && fouls >= foulThreshold && mins > 0) {
          foulTrouble.push({ name, tricode: team.teamTricode || '', fouls, isStarter, period });
        }
      }
      return { oncourt, foulTrouble, stintPM: stintN > 0 ? stintPM / stintN : null };
    };

    const home = parseTeam(game.homeTeam);
    const away = parseTeam(game.awayTeam);

    // Gap 5: officials (factual identity — no editorial weight)
    const officials = (game.officials || [])
      .filter(o => o.assignment !== 'ALTERNATE')
      .map(o => ({ name: o.name || '', assignment: o.assignment || '' }));

    const result = {
      oncourt:      [...home.oncourt, ...away.oncourt],
      homeOncourt:  home.oncourt,
      awayOncourt:  away.oncourt,
      foulTrouble:  [...home.foulTrouble, ...away.foulTrouble],
      officials,
      homeStintPM:  home.stintPM,
      awayStintPM:  away.stintPM,
      period,
      ts: now,
    };
    _nbaLiveBoxscoreCache[nbaId] = result;
    if (FIELD_DEBUG) console.debug('[PM-30] live boxscore cached:', nbaId,
      'oncourt:', result.oncourt.length, 'foul trouble:', result.foulTrouble.length);
    return result;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[PM-30] live boxscore failed:', e.message);
    captureFieldError('nba:live-boxscore', e, true);
    return _nbaLiveBoxscoreCache[nbaId] || null;
  }
}

// ── buildFoulTroubleContext (Gap 3) ──────────────────────────────────────────
// Returns a [FOUL TROUBLE] tag for the compound prompt when a key player is in
// foul trouble. RUWT-clean: named factual observable (foul count per NBA rule).
// Q1-Q2: 3+ fouls for a starter is significant (risk of sitting). Q3+: 4+ fouls.
function buildFoulTroubleContext(nbaId) {
  try {
    const bs = _nbaLiveBoxscoreCache[nbaId];
    if (!bs?.foulTrouble?.length) return '';
    const items = bs.foulTrouble
      .sort((a, b) => b.fouls - a.fouls)
      .slice(0, 3)
      .map(p => `${p.name.split(' ').slice(-1)[0]} ${p.fouls} fouls (${p.tricode})`);
    return `[FOUL TROUBLE] ${items.join(' · ')}`;
  } catch(_) { return ''; }
}

// ── buildNBAOncourtContext (Gap 1 display) ────────────────────────────────────
// Returns a formatted string of current on-court units for compound/Night Owl.
// Uses live boxscore oncourt flag — more reliable than PBP sub-event parsing.
function buildNBAOncourtContext(nbaId, homeLabel, awayLabel) {
  try {
    const bs = _nbaLiveBoxscoreCache[nbaId];
    if (!bs?.oncourt?.length) return '';
    const sp = (homeLabel + awayLabel).toLowerCase();
    const hFmt = bs.homeOncourt.map(p => p.name.split(' ').slice(-1)[0]).join('/');
    const aFmt = bs.awayOncourt.map(p => p.name.split(' ').slice(-1)[0]).join('/');
    const hPM  = bs.homeStintPM != null ? ` (${bs.homeStintPM > 0 ? '+' : ''}${bs.homeStintPM.toFixed(0)})` : '';
    const aPM  = bs.awayStintPM != null ? ` (${bs.awayStintPM > 0 ? '+' : ''}${bs.awayStintPM.toFixed(0)})` : '';
    return `[ON COURT] ${teamNick(homeLabel||'')}${hPM}: ${hFmt} · ${teamNick(awayLabel||'')}${aPM}: ${aFmt}`;
  } catch(_) { return ''; }
}

// ── buildNBAScoreLeadersContext (Gap 6 display) ───────────────────────────────
// Formats live game leaders from scoreboard (zero extra fetch cost).
function buildNBAScoreLeadersContext(nbaId) {
  try {
    const leaders = _nbaScoreLeaders[nbaId];
    if (!leaders) return '';
    const fmt = (l) => l ? `${l.name.split(' ').slice(-1)[0]} ${l.pts}pts/${l.reb}reb/${l.ast}ast (${l.tricode})` : null;
    const parts = [fmt(leaders.away), fmt(leaders.home)].filter(Boolean);
    return parts.length ? `[LEADERS] ${parts.join(' · ')}` : '';
  } catch(_) { return ''; }
}

// Fetch live PBP actions for a game — returns actions[] or null
async function fetchNBAPBP(homeLabel, awayLabel) {
  await fetchNBAScoreboard();
  // teamNick returns last word: "San Antonio Spurs" → "Spurs" → lowercase "spurs"
  // _nbaGameIdMap stores teamName keys: "spurs_thunder", "sas_okc", etc.
  const hNick = teamNick(homeLabel||'').toLowerCase() || (homeLabel||'').toLowerCase();
  const aNick = teamNick(awayLabel||'').toLowerCase() || (awayLabel||'').toLowerCase();
  const nbaId = _nbaGameIdMap[`${hNick}_${aNick}`] || _nbaGameIdMap[`${aNick}_${hNick}`];
  if (!nbaId) {
    if (FIELD_DEBUG) console.debug('[NBA-CDN] no ID for', homeLabel, 'vs', awayLabel, '| map keys:', Object.keys(_nbaGameIdMap).slice(0,6));
    return null;
  }
  try {
    const r = await fetch(`${NBA_CDN_RELAY}/liveData/playbyplay/playbyplay_${nbaId}.json`,
      { signal: AbortSignal.timeout(4000) });
    if (!r.ok) { if(FIELD_DEBUG) console.warn('[NBA-CDN] PBP HTTP', r.status); return null; }
    const d = await r.json();
    return d?.game?.actions || null;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[NBA-CDN] PBP:', e.message);
    captureFieldError('roster:nba-pbp', e, true);
    return null;
  }
}

// Parse NBA CDN actions[] → exact current lineup + stint statistics per team
function parseNBACDNActions(actions, homeTricode, awayTricode) {
  if (!actions?.length) return null;
  const hTri = (homeTricode||'').toUpperCase();
  const aTri = (awayTricode||'').toUpperCase();
  const homeLineup = new Set();
  const awayLineup = new Set();
  let homeStintScore = null; // {scoreHome, scoreAway} when current home lineup started
  let awayStintScore = null;
  let scoreHome = 0, scoreAway = 0;

  for (const a of actions) {
    if (a.scoreHome != null) scoreHome = parseInt(a.scoreHome) || scoreHome;
    if (a.scoreAway != null) scoreAway = parseInt(a.scoreAway) || scoreAway;
    const type = (a.actionType || '').toLowerCase();
    if (type !== 'substitution' && type !== 'sub') continue;
    const tri = (a.teamTricode || '').toUpperCase();
    const isH = tri === hTri;
    const isA = tri === aTri;
    if (!isH && !isA) continue;
    const name = a.playerName || a.playerNameI || '';
    if (!name) continue;
    if (a.subType === 'in') {
      (isH ? homeLineup : awayLineup).add(name);
      if (isH) homeStintScore = { scoreHome, scoreAway };
      if (isA) awayStintScore = { scoreHome, scoreAway };
    } else if (a.subType === 'out') {
      (isH ? homeLineup : awayLineup).delete(name);
    }
  }

  // Stint net: positive = that team outscored opponent during this lineup stint
  const homeStintNet = homeStintScore
    ? (scoreHome - homeStintScore.scoreHome) - (scoreAway - homeStintScore.scoreAway)
    : null;
  const awayStintNet = awayStintScore
    ? (scoreAway - awayStintScore.scoreAway) - (scoreHome - awayStintScore.scoreHome)
    : null;

  return {
    homeLineup: [...homeLineup].slice(0, 5),
    awayLineup: [...awayLineup].slice(0, 5),
    homeStintNet,
    awayStintNet,
    source: 'cdn'
  };
}

// Parse ESPN plays[] → current lineup via SUB events (Tier 2 fallback)
function parseESPNPlays(plays, homeLabel, awayLabel) {
  if (!plays?.length) return null;
  const hNick = teamNick(homeLabel||'').toLowerCase();
  const aNick = teamNick(awayLabel||'').toLowerCase();
  const homeLineup = new Set();
  const awayLineup = new Set();

  for (const p of plays) {
    const typeText = (p.type?.text || p.type?.id || '').toLowerCase();
    if (!typeText.includes('sub')) continue;
    const teamName = (p.team?.name || p.team?.displayName || '').toLowerCase();
    const isH = teamName.includes(hNick) || hNick.includes(teamName.split(' ').pop()||'');
    const isA = teamName.includes(aNick) || aNick.includes(teamName.split(' ').pop()||'');
    if (!isH && !isA) continue;
    const desc = p.text || p.shortText || '';
    // ESPN sub format: "Name in for Name" or participant list
    const parts = p.participants?.map(pt => pt.athlete?.displayName).filter(Boolean) || [];
    if (parts.length >= 2) {
      (isH ? homeLineup : awayLineup).add(parts[0]);
      (isH ? homeLineup : awayLineup).delete(parts[1]);
    }
  }

  const hl = [...homeLineup].slice(0, 5);
  const al = [...awayLineup].slice(0, 5);
  if (!hl.length && !al.length) return null;
  return { homeLineup: hl, awayLineup: al, homeStintNet: null, awayStintNet: null, source: 'espn' };
}

async function fetchRosterAdvantage(espnGameId, homeLabel, awayLabel) {
  // espnGameId required for ESPN boxscore (Tier 3); NBA CDN (Tier 1) uses labels only
  const cacheKey = espnGameId || `${homeLabel}|${awayLabel}`;
  if (!cacheKey) return null;
  const now = Date.now();
  const cached = _raiCache[cacheKey];
  if (cached && now - cached.ts < RAI_TTL) return cached;

  try {
    // Quality signal: BDL season +/- (shared cache from milestone system)
    const seasonAvgs = await fetchBDLSeasonAverages();
    const qMap = {};
    if (seasonAvgs?.length) {
      for (const p of seasonAvgs) {
        const key = `${p.player?.first_name||''} ${p.player?.last_name||''}`.trim().toLowerCase();
        if (key && p.plus_minus != null) qMap[key] = parseFloat(p.plus_minus) || 0;
      }
    }

    // ── Tier 0: NBA CDN live boxscore oncourt flag (PM-30) ────────────────────
    // More reliable than PBP sub-event parsing — direct "oncourt":"1" per player.
    // Also extracts live stint plusMinusPoints for Gap 2 blending.
    // RUWT: oncourt is a named binary observable fact. plusMinusPoints is the
    // factual score differential while that unit has been on the court.
    let tier0Data = null;
    const hNickR = teamNick(homeLabel||'').toLowerCase();
    const aNickR = teamNick(awayLabel||'').toLowerCase();
    const nbaIdR = espnGameId
      ? null  // if we have ESPN ID, derive NBA ID via map
      : (_nbaGameIdMap[`${hNickR}_${aNickR}`] || _nbaGameIdMap[`${aNickR}_${hNickR}`]);
    const nbaIdForBS = nbaIdR || Object.values(_nbaGameIdMap).find((v, _, arr) => {
      const k = Object.keys(_nbaGameIdMap).find(kk => _nbaGameIdMap[kk] === v && (kk.includes(hNickR) || kk.includes(aNickR)));
      return !!k;
    });
    if (nbaIdForBS) {
      const liveBS = await fetchNBALiveBoxscore(nbaIdForBS);
      if (liveBS?.homeOncourt?.length && liveBS?.awayOncourt?.length) {
        tier0Data = {
          homeLineup: liveBS.homeOncourt.map(p => p.name.toLowerCase()),
          awayLineup: liveBS.awayOncourt.map(p => p.name.toLowerCase()),
          homeStintNet: liveBS.homeStintPM,  // Gap 2: live unit net
          awayStintNet: liveBS.awayStintPM,
          source: 'boxscore-oncourt',
        };
        // Gap 2: blend live stint +/- into qMap for current on-court players
        // Each on-court player's live plusMinus overrides their season average
        // with a blended signal: 0.4×live + 0.6×season (season anchors small samples)
        for (const p of [...liveBS.homeOncourt, ...liveBS.awayOncourt]) {
          if (p.plusMinus == null) continue;
          const pNameLower = p.name.toLowerCase();
          const lastName = pNameLower.split(' ').slice(-1)[0];
          const seasonKey = pNameLower in qMap ? pNameLower
            : Object.keys(qMap).find(k => k.endsWith(' ' + lastName)) || null;
          const seasonPM = seasonKey ? qMap[seasonKey] : 0;
          const blended = 0.4 * p.plusMinus + 0.6 * seasonPM;
          qMap[pNameLower] = blended;  // overwrite with blended value
        }
        if (FIELD_DEBUG) console.debug('[RAI] Tier 0 oncourt:', tier0Data.homeLineup.length, 'vs', tier0Data.awayLineup.length, 'src: boxscore-oncourt');
      }
    }

    // ── Tier 1: NBA CDN play-by-play (exact lineup + stint stats) ────────────
    let pbpData = tier0Data; // Tier 0 takes precedence if available
    if (!pbpData && homeLabel && awayLabel) {
      const cdnActions = await fetchNBAPBP(homeLabel, awayLabel);
      if (cdnActions) {
        // Tricodes from _nbaGameIdMap scoreboard data — derive from team labels
        const hTri = teamNick(homeLabel||'').toUpperCase(); // "Spurs"→"SPURS" (CDN uses tricode)
        const aTri = teamNick(awayLabel||'').toUpperCase();
        // Try exact tricode match from NBA scoreboard data if available
        const hTriExact = Object.keys(_nbaGameIdMap).find(k => k.length === 3 && _nbaGameIdMap[k] === _nbaGameIdMap[`${teamNick(homeLabel||'').toLowerCase()}_${teamNick(awayLabel||'').toLowerCase()}`]);
        pbpData = parseNBACDNActions(cdnActions, hTri, aTri);
        if (FIELD_DEBUG && pbpData) console.debug('[RAI] NBA CDN T1:', pbpData.homeLineup?.length, pbpData.awayLineup?.length, 'source:', pbpData.source);
      }
    }

    // ── Single ESPN summary fetch: captures plays[] (Tier 2) + boxscore (Tier 3) ─
    // Avoids the prior double-fetch pattern. Relay edge-caches 25s — one call.
    let bsPlayers = null, espnSummaryD = null;
    if (espnGameId) {
      try {
        const r = await fetch(
          `${ESPN_SUMMARY_RELAY}/sports/basketball/nba/summary?event=${espnGameId}`,
          { signal: AbortSignal.timeout(5000) });
        if (r.ok) {
          espnSummaryD = await r.json();
          bsPlayers = espnSummaryD?.boxscore?.players;
          if (FIELD_DEBUG) console.debug('[RAI] ESPN summary:', !!bsPlayers, 'plays:', espnSummaryD?.plays?.length||0);
        }
      } catch(e) {
        if (FIELD_DEBUG) console.warn('[RAI] ESPN summary fetch:', e.message);
        captureFieldError('roster:espn-summary-fetch', e, true);
      }
    }

    // ── Tier 2: ESPN plays[] sub detection ────────────────────────────────────
    if (!pbpData && Array.isArray(espnSummaryD?.plays) && espnSummaryD.plays.length) {
      pbpData = parseESPNPlays(espnSummaryD.plays, homeLabel||'', awayLabel||'');
      if (FIELD_DEBUG && pbpData) console.debug('[RAI] ESPN plays T2:', pbpData?.source);
    }

    // ── Tier 3: ESPN boxscore (active players by minutes) ─────────────────────
    // Bug 3 fix: verify home/away order by matching team name against homeLabel
    // bsPlayers[].team.homeAway is NOT present in ESPN boxscore — don't use it
    // Instead: match displayName/abbreviation against homeLabel to determine index
    let homeIdx = 0, awayIdx = 1;
    if (Array.isArray(bsPlayers) && bsPlayers.length >= 2 && homeLabel) {
      const hNick = teamNick(homeLabel).toLowerCase();
      const p0name = (bsPlayers[0]?.team?.displayName || bsPlayers[0]?.team?.name || '').toLowerCase();
      const p1name = (bsPlayers[1]?.team?.displayName || bsPlayers[1]?.team?.name || '').toLowerCase();
      // If players[0] name does NOT match homeLabel but players[1] does → swap
      const p0match = p0name.includes(hNick) || hNick.includes(p0name.split(' ').pop()||'zzz');
      const p1match = p1name.includes(hNick) || hNick.includes(p1name.split(' ').pop()||'zzz');
      if (!p0match && p1match) { homeIdx = 1; awayIdx = 0; }
    }

    function bsTeamActive(idx) {
      if (!Array.isArray(bsPlayers) || bsPlayers.length <= idx) return [];
      return (bsPlayers[idx]?.statistics?.[0]?.athletes || [])
        .filter(a => !a.didNotPlay && a.active !== false)
        .map(a => ({
          name: (a.athlete?.displayName||'').toLowerCase(),
          // ESPN stats[0] = minutes "MM:SS" — parseFloat("32:41") → 32 (stops at colon)
          mins: parseFloat((a.stats||[])[0]||'0') || 0,
          starter: !!a.starter
        }))
        .filter(a => a.mins > 0 || a.starter)
        .sort((a,b) => b.mins - a.mins)
        .slice(0, 5);
    }

    // Quality calculation — tracks how many players had real qMap entries
    function computeQuality(playerNames) {
      if (!playerNames?.length) return { q: 0, matched: 0 };
      let total = 0, matched = 0;
      for (const rawName of playerNames) {
        const name = rawName.toLowerCase();
        const lastName = name.split(' ').slice(-1)[0] || '';
        const qVal = qMap[name]
          ?? Object.entries(qMap).find(([k]) => k.endsWith(' ' + lastName))?.[1]
          ?? null;
        total += qVal ?? 0;
        if (qVal != null) matched++;
      }
      return { q: total / playerNames.length, matched };
    }

    const homeNames = pbpData?.homeLineup?.length
      ? pbpData.homeLineup
      : bsTeamActive(homeIdx).map(a => a.name);
    const awayNames = pbpData?.awayLineup?.length
      ? pbpData.awayLineup
      : bsTeamActive(awayIdx).map(a => a.name);

    if (!homeNames.length && !awayNames.length) {
      if (FIELD_DEBUG) console.warn('[RAI] no active players found for either team');
      return null;
    }

    const homeR = computeQuality(homeNames);
    const awayR = computeQuality(awayNames);
    const totalMatched = homeR.matched + awayR.matched;

    const result = {
      edge: homeR.q - awayR.q,
      homeQ: homeR.q,
      awayQ: awayR.q,
      homeAbbr: bsPlayers?.[homeIdx]?.team?.abbreviation || teamNick(homeLabel||''),
      awayAbbr: bsPlayers?.[awayIdx]?.team?.abbreviation || teamNick(awayLabel||''),
      homeStintNet: pbpData?.homeStintNet ?? null,
      awayStintNet: pbpData?.awayStintNet ?? null,
      pbpSource: pbpData?.source || 'boxscore',
      matched: totalMatched, // track real data quality
      ts: now
    };
    _raiCache[cacheKey] = result;
    // Also cache under homeLabel|awayLabel for bottom sheet lookup (uses game._id not espnEventId)
    if (homeLabel && awayLabel) _raiCache[`${homeLabel}|${awayLabel}`] = result;
    if (FIELD_DEBUG) console.debug('[RAI] result:', result.edge.toFixed(1), 'matched:', totalMatched, 'src:', result.pbpSource);
    return result;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[RAI]', e.message);
    captureFieldError('roster:advantage', e, true);
    return null;
  }
}

function buildRaiCardLine(rai, homeLabel, awayLabel) {
  if (!rai) return '';
  // Only show if we had actual quality data (at least 1 player matched in BDL)
  if (!rai.matched) return '';
  const abs = Math.abs(rai.edge);
  const hL = rai.homeAbbr || teamNick(homeLabel||'') || 'Home';
  const aL = rai.awayAbbr || teamNick(awayLabel||'') || 'Away';
  if (abs < 0.5) return `Lineup edge: even`;
  const leader = rai.edge > 0 ? hL : aL;
  return `Lineup edge: ${leader} +${abs.toFixed(1)}`;
}

function buildRaiSheetSection(rai, homeLabel, awayLabel) {
  if (!rai || Math.abs(rai.edge) < 0.5) return '';
  const hL = rai.homeAbbr || teamNick(homeLabel) || 'Home';
  const aL = rai.awayAbbr || teamNick(awayLabel) || 'Away';
  const abs = Math.abs(rai.edge);
  const leader = rai.edge > 0 ? hL : aL;
  const ctx = abs >= 8 ? ' · significant' : abs >= 4 ? ' · clear edge' : abs >= 2 ? ' · slight edge' : '';

  // Stint net score display — only when NBA CDN PBP is active (Tier 1)
  function stintLabel(stintNet) {
    if (stintNet == null) return '';
    const sign = stintNet > 0 ? '+' : '';
    return ` <span class="rai-stint">(tonight: ${sign}${stintNet})</span>`;
  }
  const hStint = stintLabel(rai.homeStintNet);
  const aStint = stintLabel(rai.awayStintNet);

  // Source indicator — helps debug and shows data quality
  const srcLabel = rai.pbpSource === 'cdn' ? ' · Live PBP'
    : rai.pbpSource === 'espn' ? ' · ESPN plays'
    : '';

  return `<div class="bs-section">
    <div class="bs-section-label">Lineup Edge${srcLabel}</div>
    <div class="bs-section-body">
      <div class="rai-row"><span class="rai-lbl">${hL}</span><span class="rai-bar">${_raiQualityBar(rai.homeQ)}</span><span class="rai-val ${rai.homeQ>=0?'rai-pos':'rai-neg'}">${rai.homeQ>=0?'+':''}${rai.homeQ.toFixed(1)}${hStint}</span></div>
      <div class="rai-row"><span class="rai-lbl">${aL}</span><span class="rai-bar">${_raiQualityBar(rai.awayQ)}</span><span class="rai-val ${rai.awayQ>=0?'rai-pos':'rai-neg'}">${rai.awayQ>=0?'+':''}${rai.awayQ.toFixed(1)}${aStint}</span></div>
      <div class="rai-edge">${leader} edge: +${abs.toFixed(1)}${ctx}</div>
    </div>
  </div>`;
}

// Async: fetch RAI + inject .rai-line on card + [CLOSING UNIT] badge
// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: MLB PLATOON RAI — At-Bat Matchup Edge
// Computes batter vs pitcher handedness advantage per plate appearance.
// Primary: MLB Stats live feed → exact bat side + pitch hand + count
// Display: inside score-wrap, same location as NBA lineup edge
// Updates: every at-bat change (45-90s MLB poll cycle)
// RUWT: pitcher/batter hand = roster fact (pre-game). Count = observable. ✅
// ═══════════════════════════════════════════════════════════════════════════

const _mlbPlatoonCache = {};  // gamePk → {result, ts}
const MLB_PLATOON_TTL = 45000; // 45s — one per at-bat roughly

async function fetchMLBPlatoon(gamePk) {
  if (!gamePk) return null;
  const now = Date.now();
  const cached = _mlbPlatoonCache[gamePk];
  if (cached && now - cached.ts < MLB_PLATOON_TTL) return cached.result;

  try {
    const r = await fetch(
      `${MLB_STATS_RELAY}/game/${gamePk}/feed/live`,
      { signal: AbortSignal.timeout(4000) }
    );
    if (!r.ok) return null;
    const d = await r.json();

    const play    = d?.liveData?.plays?.currentPlay;
    const matchup = play?.matchup;
    const count   = play?.count;
    if (!matchup) return null;

    const batterName  = matchup.batter?.fullName || '';
    const pitcherName = matchup.pitcher?.fullName || '';
    const batSide     = matchup.batSide?.code  || '';   // 'L', 'R', 'S'
    const pitchHand   = matchup.pitchHand?.code || '';  // 'L', 'R'
    const balls       = count?.balls   ?? null;
    const strikes     = count?.strikes ?? null;
    const outs        = count?.outs    ?? null;
    const inning      = d?.liveData?.linescore?.currentInning ?? null;
    const inningHalf  = d?.liveData?.linescore?.inningHalf ?? '';  // 'Top'/'Bottom'

    // ── Platoon advantage ─────────────────────────────────────────────────
    // Switch hitter bats opposite to pitcher → always has platoon advantage
    // Opposite hands (L vs R or R vs L) = batter advantage (+~15 wOBA pts)
    // Same hand = pitcher advantage
    let platoonEdge = 'neutral', platoonLabel = '';
    if (batSide && pitchHand) {
      const effectiveSide = batSide === 'S'
        ? (pitchHand === 'R' ? 'L' : 'R')  // switch hitter flips
        : batSide;
      if (effectiveSide !== pitchHand) {
        platoonEdge  = 'batter';
        platoonLabel = `${effectiveSide} vs ${pitchHand} · batter edge`;
      } else {
        platoonEdge  = 'pitcher';
        platoonLabel = `${effectiveSide} vs ${pitchHand} · pitcher edge`;
      }
      if (batSide === 'S') platoonLabel = `Switch vs ${pitchHand} · batter edge`;
    }

    // ── Count context ─────────────────────────────────────────────────────
    // Adds a second dimension: pitcher/batter count advantage
    let countEdge = 'neutral', countLabel = '';
    if (balls !== null && strikes !== null) {
      if (balls === 3 && strikes === 0) {
        countEdge = 'batter'; countLabel = '3-0 count (batter)';
      } else if (balls >= 2 && strikes <= 1) {
        countEdge = 'batter'; countLabel = `${balls}-${strikes} hitter's count`;
      } else if (strikes === 2 && balls === 0) {
        countEdge = 'pitcher'; countLabel = '0-2 count (pitcher)';
      } else if (strikes === 2) {
        countEdge = 'pitcher'; countLabel = `${balls}-${strikes} pitcher's count`;
      }
    }

    const result = {
      batterName, pitcherName, batSide, pitchHand,
      balls, strikes, outs, inning, inningHalf,
      platoonEdge, platoonLabel,
      countEdge, countLabel,
      ts: now
    };
    _mlbPlatoonCache[gamePk] = { result, ts: now };
    return result;
  } catch(e) {
    if (FIELD_DEBUG) console.warn('[MLB-RAI]', e.message);
    captureFieldError('mlb:platoon', e, true);
    return null;
  }
}

function buildMLBPlatoonLine(p) {
  if (!p) return '';
  const parts = [];
  if (p.platoonLabel) parts.push(p.platoonLabel);
  // Only add count context when it's meaningfully lopsided
  if (p.countLabel && p.countEdge !== 'neutral') {
    // Avoid redundancy: if platoon and count both favor same side, simplify
    if (p.platoonEdge === p.countEdge) {
      parts.push(p.countLabel);
    } else if (p.countEdge !== 'neutral') {
      parts.push(p.countLabel);
    }
  }
  if (!parts.length) return '';
  return parts.join(' · ');
}

async function injectMLBPlatoon(card, eData, game) {
  const gamePk = game?.sourceId;
  if (!gamePk) return;

  const platoon = await fetchMLBPlatoon(gamePk);
  if (!platoon) return;

  const text = buildMLBPlatoonLine(platoon);
  let raiLine = card.querySelector('.rai-line');
  if (text) {
    if (!raiLine) {
      raiLine = document.createElement('div');
      raiLine.className = 'rai-line';
    }
    raiLine.textContent = text;
    const scoreWrap = card.querySelector('.score-wrap');
    if (scoreWrap) {
      if (!scoreWrap.contains(raiLine)) scoreWrap.appendChild(raiLine);
    } else {
      const cardBody = card.querySelector('.card-body');
      const tapHint  = cardBody?.querySelector('.card-tap-hint');
      if (tapHint) tapHint.insertAdjacentElement('beforebegin', raiLine);
      else if (cardBody) cardBody.appendChild(raiLine);
    }
    // Also cache under label key for _raiRehydrateScoreWrap reuse
    _mlbPlatoonCache[`${game.home||''}|${game.away||''}`] = { result: platoon, ts: Date.now() };
  } else if (raiLine) {
    raiLine.remove();
  }
}

async function injectLineupEdge(card, eData, sport) {
  const sp = (sport || '').toLowerCase();
  // NBA only — explicitly exclude WNBA (also contains 'basketball' via BDL avgs)
  if (!sp.includes('nba') && !sp.includes('nba playoffs')) return;
  if (sp.includes('wnba')) return;
  // Allow during live AND halftime — ESPN reports state='in' throughout
  if (eData?.state !== 'in' && eData?.state !== 'halftime') return;

  const espnId = eData?.espnEventId || eData?.id || eData?.gameId || card.dataset.espnid || '';
  if (!espnId) return;

  // MUST be declared before fetchRosterAdvantage call — temporal dead zone fix
  const homeLabel = card.dataset.home || '';
  const awayLabel = card.dataset.away || '';

  const rai = await fetchRosterAdvantage(espnId, homeLabel, awayLabel);
  if (!rai) return;

  // ── Card .rai-line — placed inside score-wrap (grid-column:2, grid-row:2)
  // score-wrap is always injected for live games, visible on all viewports.
  // Portrait phone: row 2 below card-body. Desktop: row 2 below card-body.
  // Landscape: same grid row 2. No grid-column ambiguity — score-wrap owns it.
  // Fallback: card-body → before tap-hint when score-wrap not yet present.
  const raiText = buildRaiCardLine(rai, homeLabel, awayLabel);
  let raiLine = card.querySelector('.rai-line');
  if (raiText) {
    if (!raiLine) {
      raiLine = document.createElement('div');
      raiLine.className = 'rai-line';
    }
    raiLine.textContent = raiText;
    // Primary target: score-wrap (always at grid-column:2 row:2 on all viewports)
    const scoreWrap = card.querySelector('.score-wrap');
    if (scoreWrap) {
      // Keep inside score-wrap so it stays in the correct grid column
      if (!scoreWrap.contains(raiLine)) scoreWrap.appendChild(raiLine);
    } else {
      // Fallback: inside card-body before tap-hint
      const cardBody = card.querySelector('.card-body');
      const tapHint = cardBody?.querySelector('.card-tap-hint');
      if (tapHint) tapHint.insertAdjacentElement('beforebegin', raiLine);
      else if (cardBody) cardBody.appendChild(raiLine);
      else card.appendChild(raiLine);
    }
  } else if (raiLine) {
    raiLine.remove();
  }

  // ── [CLOSING UNIT] badge (named condition) ────────────────────────────────
  // Fires when trailing team has lineup advantage AND isLateCloseGame
  card.querySelectorAll('.badge-closing').forEach(b => b.remove());
  const homeScore = eData.homeScore || 0;
  const awayScore = eData.awayScore || 0;
  const homeTrailing = homeScore < awayScore;
  const awayTrailing = awayScore < homeScore;
  const trailingHasEdge = (homeTrailing && rai.edge > 5) || (awayTrailing && rai.edge < -5);
  if (trailingHasEdge && isLateCloseGame({ _section: sport }, eData, sport)) {
    const liveEl = card.querySelector('.live-indicator,.live-dot');
    if (liveEl) {
      const cb = document.createElement('span');
      cb.className = 'badge-closing';
      const label = homeTrailing
        ? (rai.homeAbbr || teamNick(homeLabel))
        : (rai.awayAbbr || teamNick(awayLabel));
      cb.textContent = `◈ ${label} CLOSING UNIT`;
      liveEl.insertAdjacentElement('afterend', cb);
    }
  }
}

// ── PM-25 (June 5 2026): Card Render Slot ────────────────────────────────────
// Extracted from the inline drama badge block inside injectDramaBadges().
// renderCardBadges(card, eData, sport, gid, smoothed) is the single callsite
// for all live-card badge mutations: CRUNCH TIME, WORTH WATCHING, drama tier,
// EMBER, MLBN alert. Callers (WS Pulse, CRUNCH Fan-Out chip, future surfaces)
// call this instead of reimplementing the badge hierarchy.
// DO NOT INVENT: all badge logic is verbatim from the prior inline block.
// A191: extracted to index.html only (not field_utils — DOM dependency).
function renderCardBadges(card, eData, sport, gid, smoothed) {
  if (!card || !eData) return;
  // Remove existing badges before re-injecting
  card.querySelectorAll('.drama-badge,.badge-crunch,.badge-worth').forEach(b => b.remove());
  const liveEl = card.querySelector('.live-indicator,.live-dot');
  if (!liveEl) return;

  // ── PULSE: ViewingConditions CRUNCH TIME / WORTH WATCHING badge ──────
  const vcResult = ViewingConditions.evaluate(gid, eData.period,
    Math.abs((eData.homeScore||0) - (eData.awayScore||0)), sport);
  if (vcResult.badge) {
    const vcBadge = document.createElement('span');
    const gameCardObj = (()=>{ try {
      return {_id: gid, home: card.dataset.home||'', away: card.dataset.away||'', _section: card.dataset.sport||''};
    } catch(e_) { return null; } })();
    const milestoneMs = gameCardObj ? _bdlMilestonesCache?.[gid] : null;
    if (vcResult.badge === 'CRUNCH TIME') {
      vcBadge.className = 'badge-crunch badge-pulse';
      if (milestoneMs?.shortLabel) {
        vcBadge.textContent = `⚡ ${milestoneMs.shortLabel} · CRUNCH TIME`;
        vcBadge.title = `${milestoneMs.playerName} needs ${milestoneMs.gap} more ${milestoneMs.stat} to reach ${milestoneMs.next}`;
      } else {
        vcBadge.textContent = '⚡ CRUNCH TIME';
      }
      try {
        const sportKey = (card.dataset.sport||sport||'').toLowerCase();
        const gameIdNum = (gid||'').replace(/^[a-z]+:/, '');
        if (sportKey && gameIdNum && typeof ensureGameSocket === 'function' && !card.dataset.crunchSignaledP) {
          const gs = _gameSockets?.get(`${sportKey}:${gameIdNum}`);
          const detail = { gameId: gameIdNum, period: eData.period, periodLabel: eData.detail||'',
            home: card.dataset.home||'', away: card.dataset.away||'',
            homeScore: eData.homeScore??null, awayScore: eData.awayScore??null,
            broadcast: card.dataset.broadcast||'' };
          if (gs && gs.available) gs.signalCrunch(detail);
          else fetch(`${V2_RELAY_BASE}/signal/crunch/${encodeURIComponent(sportKey)}/${encodeURIComponent(gameIdNum)}`,
            { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(detail), keepalive:true }).catch(()=>{});
          card.dataset.crunchSignaledP = String(eData.period);
        }
      } catch(_) {}
    } else {
      vcBadge.className = 'badge-worth';
      vcBadge.textContent = '👀 WORTH WATCHING';
    }
    liveEl.insertAdjacentElement('afterend', vcBadge);
    // ── PM-27: emit field:crunch for CRUNCH TIME only (not WORTH WATCHING) ──
    // Subscribers (CRUNCH Fan-Out chip) listen for this to cascade to related cards.
    // RUWT-safe: this is a named binary condition, not a composite score threshold.
    if (vcResult.badge === 'CRUNCH TIME') {
      try {
        if (typeof fieldEvents !== 'undefined') {
          fieldEvents.dispatchEvent(new CustomEvent('field:crunch', { detail: {
            type: 'field:crunch', target: gid, source: 'badge_render',
            reason: 'crunch_time_badge', at: Date.now(),
            payload: {
              home: card.dataset.home || '', away: card.dataset.away || '',
              sport, period: eData.period,
              score: `${eData.awayScore||0}-${eData.homeScore||0}`
            }
          }}));
        }
      } catch(_) {}
    }
    // CRUNCH TIME/WORTH WATCHING replaces drama badge — no double-badge
    // Still allow EMBER + MLBN to run below
  } else {
    // Fallback: standard drama badge using smoothed score
    const displayTier = dramaTier(smoothed);
    if (displayTier) {
      const badge = document.createElement('span');
      badge.className = `drama-badge drama-${displayTier}`;
      badge.textContent = dramaLabel(smoothed);
      liveEl.insertAdjacentElement('afterend', badge);
    }
  }

  // ── EMBER: BURIED LEAD sits below, never pulses ───────────────────────
  try {
    const emberGame = { _id: gid, home: card.dataset.home||'', away: card.dataset.away||'',
      _section: card.dataset.sport||'', nationalBundle: card.dataset.bundle||'',
      seriesRecord: card.dataset.series||'',
      streams: card.dataset.stream ? [{label: card.dataset.stream}] : [] };
    const emberResult = evaluateEMBER(emberGame, sport, eData);
    if (emberResult) {
      const eb = document.createElement('span');
      eb.className = 'badge-ember';
      const tierLabel = emberResult.tier === 3 ? 'Local Gem' : emberResult.tier === 2 ? 'Regional Gem' : 'Buried Lead';
      eb.textContent = `🔍 ${tierLabel}`;
      eb.title = `Buried Lead: Tier ${emberResult.tier} on ${emberResult.channel}${emberResult.lateClose?' · late-close game':''}${emberResult.contextFlag?' · context boost':''}`;
      liveEl.insertAdjacentElement('afterend', eb);
      if (gid) _emberResultCache[gid] = emberResult;
    } else {
      if (gid) delete _emberResultCache[gid];
    }
  } catch(e_) {}

  // ── MLB Network Drama Alert ───────────────────────────────────────────
  try {
    const gameObj = { _id: gid, home: card.dataset.home||'', away: card.dataset.away||'',
      _section: sport, _sport: sport, nationalBundle: card.dataset.nationalBundle||'' };
    const mlbnHtml = buildMLBNAlertChip(gameObj, smoothed);
    if (mlbnHtml) {
      card.querySelectorAll('.mlbn-alert').forEach(el => el.remove());
      const mlbnEl = document.createElement('div');
      mlbnEl.innerHTML = mlbnHtml;
      const chip = mlbnEl.firstElementChild;
      if (chip) liveEl.insertAdjacentElement('afterend', chip);
    } else {
      card.querySelectorAll('.mlbn-alert').forEach(el => el.remove());
    }
  } catch(e_) {}

  // ── PM-25 Rich-visual confidence glyph (A496) ────────────────────────────
  // Injects a colored dot <span class="cg {conf}"> beside the score in .game-time.
  // Additive alongside the existing text glyph in buildCardTimeDisplay (PM-20 Step 5).
  // verified → green halo dot · mismatch → red ring dot · single → grey dot · null → remove
  // DOM-safe: removes any prior .cg before injecting; no-op if .game-time absent.
  try {
    const gtEl = card.querySelector('.game-time');
    if (gtEl) {
      gtEl.querySelectorAll('.cg').forEach(el => el.remove());
      const conf = eData?.confidence;
      if (conf === 'verified' || conf === 'mismatch' || conf === 'single') {
        const dot = document.createElement('span');
        dot.className = `cg ${conf}`;
        const _cgLabel = conf === 'verified' ? 'Score confirmed by 2 sources'
                       : conf === 'mismatch' ? 'Score sources disagree — check Health panel'
                       : 'Score from single source';
        dot.title = _cgLabel;
        dot.setAttribute('role', 'img');
        dot.setAttribute('aria-label', _cgLabel);
        gtEl.appendChild(dot);
      }
    }
  } catch(e_) {}
}

// ── Drama Dial header chip (Jun 9 2026 audit) ──────────────────────────────
// Surfaces the Dial value in the masthead so users discover personalization
// without opening My Services. Tapping opens My Services.
function _updateDialChip() {
  const chip = (_DOM?.dramaDialChip||document.getElementById('drama-dial-chip'));
  if (!chip) return;
  const val = typeof getDramaDial === 'function' ? getDramaDial() : 65;
  chip.textContent = 'Dial ' + val;
  chip.style.display = 'inline-flex';
  chip.style.alignItems = 'center';
}
// ── CC-CMD-2026-07-12-otw-tier-categorical / otw-live-tier-categorical ───────
// T3/T4 margin tiers, reused verbatim from dramaScoreLive()'s own base-score
// bucket boundaries per sport (not reinvented):
//   TIER1 (tightest): margin alone usually clears LIVE_GAME with room to
//     spare, and combined with ANY final-period presence clears CLOSE_FINISH.
//   TIER2: margin alone just clears LIVE_GAME; needs crunch-time to also
//     clear CLOSE_FINISH.
//   TIER3 (widest still-relevant): margin alone falls short of LIVE_GAME;
//     only clears it when crunch-time urgency is added on top.
// Calibrated against a 749-sample characterization sweep of the OLD
// smoothed-threshold behavior (see docs/outbox/cc-otw-tier-categorical-
// 2026-07-12.md) — 98.5% agreement, remaining mismatches documented there.
function _otwMarginTier(eData, sport) {
  const diff = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const sp = (sport||'').toLowerCase();
  if (sp.includes('wnba')) return diff===0?1 : diff<=3?2 : diff<=7?3 : 0;
  if (sp.includes('tennis')||sp.includes('atp')||sp.includes('wta')) return diff===0?1 : diff===1?2 : 0;
  if (sp.includes('australian')||sp.includes('afl')) return diff===0?1 : diff<6?2 : diff<=18?3 : 0;
  if (sp.includes('cfl')||sp.includes('canadian football')) return diff===0?1 : diff<=3?2 : diff<=8?3 : 0;
  if (sp.includes('mlb')||sp.includes('baseball')) return diff===0?1 : diff===1?2 : diff===2?3 : 0;
  if (sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
      sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
      sp.includes('wc26')||sp.includes('world cup')) return diff===0?1 : diff===1?3 : 0;
  if (sp.includes('nfl')||sp.includes('football')) return diff===0?1 : diff<=3?2 : diff<=7?3 : 0;
  if (sp.includes('nba')||sp.includes('basketball')) return diff===0?1 : diff<=3?2 : diff<=7?3 : 0;
  if (sp.includes('nhl')||sp.includes('hockey')) return diff===0?1 : diff<=3?2 : diff<=7?3 : 0;
  return diff===0?1 : diff<=3?2 : diff<=7?3 : 0;
}

// In the final regulation period at all (non-overtime — T2 already
// classifies overtime as EXTRA_TIME before this is reached).
function _otwIsFinalPeriod(eData, sport) {
  const sp = (sport||'').toLowerCase();
  const period = parseInt(eData.period) || 1;
  if (sp.includes('wnba')||sp.includes('nba')||sp.includes('basketball')||
      sp.includes('nfl')||sp.includes('football')||sp.includes('cfl')||
      sp.includes('canadian football')||sp.includes('australian')||sp.includes('afl')) return period >= 4;
  if (sp.includes('nhl')||sp.includes('hockey')) return period >= 3;
  if (sp.includes('mlb')||sp.includes('baseball')) return period >= 9;
  if (sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
      sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
      sp.includes('wc26')||sp.includes('world cup')) {
    // 2026-07-12 fix: clock-based (minNum>=70), not period>=2. period>=2 means
    // "2nd half at all" -- at minute 46 that's true but dramaScoreLive's own
    // soccer timeBonus is still 0 (its lowest nonzero tier is minNum>=70).
    // Confirmed via real-game regression sweep this produced 4 of 11 known
    // mismatches (docs/outbox/cc-otw-tier-categorical-2026-07-12.md).
    const minNum = parseInt(eData.clock) || 0;
    return minNum >= 70;
  }
  if (sp.includes('tennis')||sp.includes('atp')||sp.includes('wta')) return period >= 2;
  return false;
}

// dramaScoreLive()'s own highest non-overtime timeBonus tier per sport
// (reused thresholds, not reinvented).
function _otwIsCrunchTime(eData, sport) {
  const sp = (sport||'').toLowerCase();
  const period = parseInt(eData.period) || 1;
  const clock = eData.clock || '';
  const mins = parseFloat((clock.match(/^(\d+)/)||[0,0])[1]) || 12;
  if (sp.includes('wnba')) return period>=3 && mins<2;
  if (sp.includes('tennis')||sp.includes('atp')||sp.includes('wta')) return period>=3;
  if (sp.includes('australian')||sp.includes('afl')) return period>=4 && mins<5;
  if (sp.includes('cfl')||sp.includes('canadian football')) return period===4 && mins<2;
  if (sp.includes('mlb')||sp.includes('baseball')) return period>=9;
  if (sp.includes('soccer')||sp.includes('league')||sp.includes('mls')||
      sp.includes('liga')||sp.includes('ligue')||sp.includes('premier')||
      sp.includes('wc26')||sp.includes('world cup')) { const minNum=parseInt(clock)||0; return minNum>=80; }
  if (sp.includes('nfl')||sp.includes('football')) return period===4 && mins<2;
  if (sp.includes('nba')||sp.includes('basketball')) return period>=3 && mins<2;
  if (sp.includes('nhl')||sp.includes('hockey')) return period===3 && mins<5;
  return false;
}

// ── PM-25 / Drama Dial categorical tier refactor (June 5 2026), T3/T4
// rewritten 2026-07-12 ─────────────────────────────────────────────────────
// Named-condition tier selector for live ESPN games — mirrors _otwFindWCLiveGame.
// Returns a named condition string (never a numeric composite) or null.
// Replaces the dramaTier(score) numeric path in the OTW FIRE header chip and
// completes the RUWT Rule 95 MODERATE → RESOLVED path begun by A490.
// The FIRE callsite (getDramaDial() threshold) is already user-controlled (A490).
// T1/T2 (CRUNCH/EXTRA_TIME) were already boolean-gated named conditions.
// T3/T4 (CLOSE_FINISH/LIVE_GAME) used to compare a temporally-smoothed
// composite drama score against numeric thresholds (60/40) — selection
// logic, not just the display, was still a numeric-composite comparison.
// Rewritten to use only raw observables (score margin, period, clock) via
// _otwMarginTier/_otwIsFinalPeriod/_otwIsCrunchTime above — no smoothed
// composite score anywhere in tier SELECTION now, not just display.
// RUWT compliance: boolean-gated named conditions, never numerical threshold display.
function _otwGetLiveTier(eData, sport) {
  if (!eData) return null;
  const sp = (sport || '').toLowerCase();
  const period = eData.period || '';
  const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const p = String(period).toLowerCase();

  // T1: Final period + close game (sport-specific crunch rules)
  if (SPORT_CRUNCH_RULES?.[sport]) {
    const inCrunch = SPORT_CRUNCH_RULES[sport].some(r => p.includes(r.toLowerCase()));
    if (inCrunch && margin <= 5) return 'CRUNCH';
  }
  // T2: Overtime / extra innings / extra time
  if (p.includes('ot') || p.includes('overtime') || p.includes('extra') ||
      p.includes('so') || p.includes('shootout') || (sp.includes('baseball') && parseInt(period) > 9)) {
    return 'EXTRA_TIME';
  }

  const tier = _otwMarginTier(eData, sport);
  const crunch = _otwIsCrunchTime(eData, sport);
  const finalP = _otwIsFinalPeriod(eData, sport);
  // AFL/CFL's tier-3 margin bucket, and soccer's (margin=1, base=0.72), are
  // proportionally high enough that just reaching the final period (not full
  // crunch) already crosses the old LIVE_GAME threshold — confirmed against
  // dramaScoreLive()'s real numbers for these sports specifically via the
  // characterization sweep, not assumed uniformly across all sports. Soccer
  // added 2026-07-12: without this, a margin=1 soccer game between minute
  // 70-79 (finalP true, crunch false since crunch needs minute>=80) fell
  // through to null instead of LIVE_GAME — a real, confirmed regression
  // (docs/outbox/cc-otw-tier-categorical-2026-07-12.md).
  const looseTier3Sport = sp.includes('afl') || sp.includes('australian') || sp.includes('cfl') ||
    sp.includes('canadian football') || sp.includes('soccer') || sp.includes('league') ||
    sp.includes('mls') || sp.includes('liga') || sp.includes('ligue') || sp.includes('premier') ||
    sp.includes('wc26') || sp.includes('world cup');

  // T3: dead-even and in the final period at all, OR a still-tight margin
  // combined with true crunch-time urgency.
  if ((tier === 1 && finalP) || (tier === 2 && crunch)) return 'CLOSE_FINISH';
  // T4: a genuinely close margin on its own (tiers 1-2 clear the bar without
  // help), OR a wider-but-still-relevant margin combined with crunch-time
  // urgency (tier 3 needs the extra push) — or, for AFL/CFL specifically,
  // just the final period (see looseTier3Sport above).
  if (tier === 1 || tier === 2 || (tier === 3 && (crunch || (looseTier3Sport && finalP)))) return 'LIVE_GAME';
  return null;
}

// Local tier-ordinal helper for field:otw_changed_significant's tier-
// margin gate ONLY (CC-CMD-2026-07-09-otw-significant-event) -- never
// displayed, never exposed in any payload, comparison only. NOT
// fieldTierRank() below: that function's case list uses CLOSE_LATE/LIVE,
// not CLOSE_FINISH/LIVE_GAME -- the actual names _otwGetLiveTier above
// returns -- confirmed by reading both functions, not assumed. Reusing
// fieldTierRank() directly here would silently rank both to its default
// case (0), collapsing two of the four real tiers to no distinction.
// Named label for the OTW header chip — factual condition string, never a score.
// Callers: renderOneToWatch FIRE state header chip.
function _otwTierLabel(tier) {
  if (tier === 'CRUNCH')       return 'CRUNCH TIME';
  if (tier === 'EXTRA_TIME')   return 'OT / EXTRA';
  if (tier === 'CLOSE_FINISH') return 'CLOSE GAME';
  if (tier === 'LIVE_GAME')    return 'LIVE';
  return 'LIVE';
}

// ── ADR-002 Tier Foundation (June 14 2026) ───────────────────────────────────
// Single source of truth for game-tier classification across the app.
// Replaces composite preGameScore / dramaScoreLive thresholds at 13 audit sites
// (see outbox/adr-002-audit-v2.md) with named categorical tiers. Internal
// helpers may compute composites; every consumer reads a named tier, never a
// raw number. Sort order via fieldTierRank() is a sort key only — never a
// threshold gating display.
//
// Hierarchy (highest priority first):
//   FINALS              — championship-round game (NBA Finals, Stanley Cup Final, …)
//   ELIMINATION         — _gameImportance: 'elimination' | 'series_deciding'
//   CRUNCH              — live, sport-specific crunch period + margin ≤ 5
//   EXTRA_TIME          — live, overtime / extra innings / shootout
//   CLOSE_LATE          — live, late period + close margin (not yet CRUNCH)
//   PLAYOFF_SERIES      — _gameImportance: 'clinch' | 'playoff_impl', or active series
//   MARQUEE_NATIONAL    — national broadcast + semifinal/conf-final tier
//   LIVE                — any live game (state === 'in') not captured above
//   UPCOMING            — scheduled, not yet started
//   NONE                — postponed / final / no data
function fieldGameTier(gameId) {
  if (!gameId) return 'NONE';
  let game = null, sport = '';
  const sections = (typeof allData !== 'undefined' && allData?.sports) || [];
  for (const sec of sections) {
    const found = (sec.games||[]).find(g => g._id === gameId);
    if (found) { game = found; sport = sec.sport; break; }
  }
  if (!game || game._postponed) return 'NONE';
  const lbl = String(game.league||'');
  // T1: championship round
  if (/nba finals|stanley cup final|world series|super bowl|champions league final/i.test(lbl)) return 'FINALS';
  if (/FIFA World Cup 2026.*(Final|Third Place)/i.test(lbl)) return 'FINALS';
  // T2: elimination
  if (game._gameImportance === 'elimination' || game._gameImportance === 'series_deciding') return 'ELIMINATION';
  // Live-state tiers
  const eData = (typeof findESPNScore === 'function') ? findESPNScore(game) : null;
  if (eData && eData.state === 'in') {
    const period = String(eData.period||'').toLowerCase();
    const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
    const sp = (sport||'').toLowerCase();
    // T3: CRUNCH
    const periodNum = parseInt(eData.period) || 0;
    const clockMin  = parseInt(eData.clock) || 0;
    const _isSoccer = sp.includes('soccer') || sp.includes('league') || sp.includes('mls') ||
                      sp.includes('liga')   || sp.includes('ligue')   || sp.includes('premier') ||
                      /world.cup|fifa/i.test(sp);
    // WC/soccer: clock-based crunch — 80'+ and ≤1 goal. Named binary condition (RUWT-safe).
    // No period-based crunch rule exists for soccer; clock is the signal.
    if (_isSoccer && clockMin >= 80 && margin <= 1) return 'CRUNCH';
    const crunchRules = (typeof SPORT_CRUNCH_RULES !== 'undefined') ? SPORT_CRUNCH_RULES[sport] : null;
    if (crunchRules && crunchRules.some(r => period.includes(r.toLowerCase())) && margin <= 5) return 'CRUNCH';
    // T4: EXTRA_TIME
    if (period.includes('ot') || period.includes('overtime') || period.includes('extra') ||
        period.includes('so') || period.includes('shootout')) return 'EXTRA_TIME';
    if (sp.includes('baseball') && (parseInt(eData.period)||0) > 9) return 'EXTRA_TIME';
    // T5: CLOSE_LATE — sport-aware late period + close margin
    const inLate = _isSoccer
                     ? clockMin >= 70
                 : sp.includes('baseball') || sp.includes('mlb')
                     ? periodNum >= 7
                 : sp.includes('nhl') || sp.includes('hockey')
                     ? periodNum >= 3
                 : sp.includes('nfl') || sp.includes('football') || sp.includes('cfl')
                     ? periodNum >= 4
                 : periodNum >= 3;
    if (inLate && margin <= 8) return 'CLOSE_LATE';
  }
  // T6: PLAYOFF_SERIES
  if (game._gameImportance === 'clinch' || game._gameImportance === 'playoff_impl') return 'PLAYOFF_SERIES';
  if (game.seriesRecord && game.seriesRecord !== '0-0') return 'PLAYOFF_SERIES';
  // T7: MARQUEE_NATIONAL
  if (typeof isNationalGame === 'function' && isNationalGame(game)) {
    if (/conference finals|cf g\d|wcf|ecf g\d|conference semi|semifinal|copa final/i.test(lbl)) return 'MARQUEE_NATIONAL';
    if (/FIFA World Cup 2026.*(Semi|Quarter|Round of 16|Round of 32)/i.test(lbl)) return 'MARQUEE_NATIONAL';
  }
  // T8: LIVE
  if (eData && eData.state === 'in') return 'LIVE';
  // T9: UPCOMING
  if (eData && eData.state === 'pre') return 'UPCOMING';
  if (game.start_time && new Date(game.start_time).getTime() > Date.now()) return 'UPCOMING';
  return 'NONE';
}

// _isCloseAndLate: mirrors fieldGameTier()'s own established T5
// CLOSE_LATE computation above verbatim (CC-CMD-2026-07-09-game-reason-
// tags) -- not a new heuristic. A standalone helper rather than calling
// fieldGameTier() directly, because fieldGameTier() collapses to ONE
// tier by priority -- a game that's both ELIMINATION and genuinely
// close-and-late right now would report only 'ELIMINATION', hiding the
// close_late signal an independent-tag aggregator needs to surface
// alongside other simultaneously-true tags. fieldGameTier() itself is
// left untouched -- this doesn't refactor its 10+ existing call sites.
function _isCloseAndLate(eData, sport) {
  if (!eData || eData.state !== 'in') return false;
  const periodNum = parseInt(eData.period) || 0;
  const clockMin = parseInt(eData.clock) || 0;
  const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  const sp = (sport||'').toLowerCase();
  const _isSoccer = sp.includes('soccer') || sp.includes('league') || sp.includes('mls') ||
                    sp.includes('liga')   || sp.includes('ligue')   || sp.includes('premier') ||
                    /world.cup|fifa/i.test(sp);
  const inLate = _isSoccer
                   ? clockMin >= 70
               : sp.includes('baseball') || sp.includes('mlb')
                   ? periodNum >= 7
               : sp.includes('nhl') || sp.includes('hockey')
                   ? periodNum >= 3
               : sp.includes('nfl') || sp.includes('football') || sp.includes('cfl')
                   ? periodNum >= 4
               : periodNum >= 3;
  return inLate && margin <= 8;
}

// Numeric rank for sort comparisons ONLY. Higher = higher priority.
// Never thresholded against display — use the named tier directly for that.
// fieldTierRank extracted to src/utils/tier.js (Phase 3b).

// fieldTierLabel extracted to src/utils/tier.js (Phase 3b).

// V4: card tier resolver — maps fieldGameTier to one of three CSS scaffold
// classes used by .game-card. Spec lines 48 + 75-86: featured carries the
// editorial weight (finals, elimination, crunch, in-series playoff),
// standard is the default working tier, compact is for low-signal cards.
function _cardTierClass(g) {
  if (!g || !g._id) return 'card-tier-standard';
  const t = fieldGameTier(g._id);
  if (t === 'FINALS' || t === 'ELIMINATION' || t === 'CRUNCH' ||
      t === 'EXTRA_TIME' || t === 'PLAYOFF_SERIES') return 'card-tier-featured';
  if (t === 'UPCOMING' || t === 'NONE') return 'card-tier-compact';
  return 'card-tier-standard';
}

// Separate dimension: league-importance classifier for LLM prompt context.
// Returns a named tier string, not a numeric scalar. Replaces the
// _importanceScore bucket pattern at audit finding H7.
// Accepts a game object (preferred) or a bare label string.
function leagueImportanceTier(gameOrLabel) {
  const g = (gameOrLabel && typeof gameOrLabel === 'object') ? gameOrLabel : null;
  const l = String((g && (g.league || g._sport)) || gameOrLabel || '').toLowerCase();
  if (/nba finals|stanley cup final|world series|super bowl/i.test(l)) return 'final';
  if (/fifa world cup 2026.*(final|third place)/i.test(l)) return 'final';
  if (/conference finals|cf g\d|wcf|ecf|copa final|champions league final/i.test(l)) return 'final';
  if (/fifa world cup 2026.*semi/i.test(l) || /wc.*semifinal/i.test(l)) return 'semifinal';
  if (/conference semi|semifinal/i.test(l)) return 'semifinal';
  if (/fifa world cup 2026.*(quarter|round of 16|round of 32)/i.test(l) || /wc.*(quarter|knockout|r16|r32)/i.test(l)) return 'quarterfinal';
  if (/fifa world cup|wc26/i.test(l)) return 'group';
  if (g && g.seriesRecord) return 'series';
  if (g && /elimination/i.test(g._gameImportance||'')) return 'series';
  if (/playoff|round 2|second round/i.test(l)) return 'series';
  if (g && /playoffs/i.test(g._gameImportance||'')) return 'series';
  return 'reg';
}

// Sort rank for league tiers — internal sort key only, never thresholded for display.
function leagueImportanceRank(tier) {
  switch (tier) {
    case 'final':        return 10;
    case 'semifinal':    return 9;
    case 'quarterfinal': return 8;
    case 'group':        return 6;
    case 'series':       return 5;
    default:             return 1;
  }
}

// ── PM-32-VI: Viewer Intelligence Chip ──────────────────────────────────────
// Pre-game card chip surfacing game-specific intelligence at the intelligence
// level the user has configured. Three modes (STAKES / STORIES / MY TEAMS)
// reorder the same four boolean signals — no composite score, no server signal.
//
// Patent Defense Layer 2: client-side only (localStorage). Server sends
// identical data; each card renders differently based on user preference.
// ADR-002 Component 2: pure client-side classification.
// RUWT: all signals are factual conditions (elimination status, named narrative
// presence, schedule scarcity, team membership) — not excitement measures.
// Patent offense: user-controlled multi-dimensional boolean classification
// ordering is novel architecture distinct from RUWT's universal interest level.
//
// Modes:
//   stakes  — consequence-first (elimination > series-defining > story > scarcity > team)
//   stories — narrative-first  (story > elimination > scarcity > team)
//   myteams — proximity-first  (team > elimination > story > scarcity)

function getViewerIntelMode(){
  const v=localStorage.getItem('field_viewer_intel_mode');
  return (v==='stories'||v==='myteams')?v:'stakes';
}
function setViewerIntelMode(mode){
  if(mode==='stories'||mode==='myteams'||mode==='stakes'){
    localStorage.setItem('field_viewer_intel_mode',mode);
  }
  // Update button states if modal is open
  document.querySelectorAll('.vim-btn').forEach(b=>{
    b.classList.toggle('active',b.dataset.mode===mode);
  });
  const _vp=document.getElementById('vim-preview');
  if(_vp){
    const _vd={stakes:'Consequence first — elimination games and series-defining moments ranked above everything.',stories:'Narrative first — named storylines, historic moments, and milestones ranked above everything.',myteams:'Your teams first — games featuring teams you follow ranked above everything.'};
    _vp.textContent=_vd[mode]||_vd.stakes;
  }
  // Re-render all pre-game chips with new mode
  document.querySelectorAll('.viewer-intel-chip[data-gameid]').forEach(chip=>{
    const gid=chip.dataset.gameid;
    const card=[...document.querySelectorAll('.game-card')].find(c=>c.dataset.gameid===gid);
    if(!card||card.classList.contains('espn-live')) return;
    const g=(allData?.sports||[]).flatMap(s=>s.games||[]).find(g=>g._id===gid);
    if(!g) return;
    const newChip=buildViewerIntelChip(g,allData?.sports||[],mode);
    if(newChip){
      chip.outerHTML=newChip;
    } else {
      chip.remove();
    }
  });
}

// _isMyTeamGame: the single existing isMyTeam computation (CC-CMD-2026-
// 07-09-game-reason-tags TASK 2) -- extracted from buildViewerIntelChip
// below so getGameReasonTags() can share the identical logic instead of
// re-inlining the same MY_TEAMS check a second time. Note, confirmed by
// reading buildViewerIntelChip directly rather than assumed: isMyTeam
// was already computed exactly ONCE there (one const, referenced in 3
// mode branches) -- not triplicated as originally described; this
// extraction is still the correct, real, in-scope cleanup the doc's
// intent calls for, just not "3 duplicates to 1."
function _isMyTeamGame(g) {
  return typeof MY_TEAMS !== 'undefined' && (MY_TEAMS.has(g.home) || MY_TEAMS.has(g.away));
}

function buildViewerIntelChip(g,sections,mode){
  if(!g) return '';
  mode=mode||getViewerIntelMode();

  // ── Signal computation (all boolean/categorical — no composite score) ─────
  // S: Stakes — consequence-based (pre-game facts only, never game state)
  const isElim   = g._gameImportance==='elimination'||g._gameImportance==='series_deciding';
  const isPlayoff= !!(g._gameImportance)||/playoff|final|semifinal|conference|cup final/i.test(g.league||'');
  const seriesRec= (g.seriesRecord||'').trim();
  // Series G5/G6/G7 detection — high-leverage elimination-adjacent games
  const isLateGame=/G[567]|Game\s*[567]/i.test(g.gameLabel||g.league||'');
  const highStakes= isElim||(isPlayoff&&(isLateGame||/leads\s+[23]-[23]/i.test(seriesRec)));

  // N: Narrative — named storyline present (overlay matchupNote + importance set)
  const hasNarrative=!!(g.matchupNote&&g.matchupNote.length>40&&g._gameImportance);

  // Q: Scarcity — sole game in this sport tonight
  const sport=(_gameSport(g)).toLowerCase().split('(')[0].trim();
  const sportGames=(sections||[]).filter(s=>(s.sport||'').toLowerCase().includes(sport.split(' ')[0])).flatMap(s=>s.games||[]).length;
  const isOnlyGame=sportGames===1;

  // P: Proximity — user's saved team playing (client-side localStorage only)
  const isMyTeam=_isMyTeamGame(g);

  // A: Anti-hype gate — J1 flagged this game as low-stakes
  const isAntiHype=!!(g._antiHype);
  if(isAntiHype) return ''; // Never chip a game FIELD has flagged low-stakes

  // ── Mode-ordered label hierarchy ──────────────────────────────────────────
  // stakes: consequence first
  // stories: narrative first
  // myteams: proximity first
  // No arithmetic. Priority order encodes the weighting.

  if(mode==='stakes'){
    if(highStakes)   return `<span class="viewer-intel-chip vic-critical" data-gameid="${g._id||''}" title="High-stakes game — consequence matters" onclick="event.stopPropagation();openSetup?.()">DON'T MISS</span>`;
    if(hasNarrative) return `<span class="viewer-intel-chip vic-story"    data-gameid="${g._id||''}" title="Named storylines — context beyond the score" onclick="event.stopPropagation();openSetup?.()">STORY GAME</span>`;
    if(isOnlyGame)   return `<span class="viewer-intel-chip vic-only"     data-gameid="${g._id||''}" title="Only ${sport} game tonight" onclick="event.stopPropagation();openSetup?.()">ONLY GAME</span>`;
    if(isMyTeam)     return `<span class="viewer-intel-chip vic-team"     data-gameid="${g._id||''}" title="Your team is playing" onclick="event.stopPropagation();openSetup?.()">YOUR TEAM</span>`;
  } else if(mode==='stories'){
    if(hasNarrative) return `<span class="viewer-intel-chip vic-story"    data-gameid="${g._id||''}" title="Named storylines — context beyond the score" onclick="event.stopPropagation();openSetup?.()">STORY GAME</span>`;
    if(highStakes)   return `<span class="viewer-intel-chip vic-critical" data-gameid="${g._id||''}" title="High-stakes game — consequence matters" onclick="event.stopPropagation();openSetup?.()">DON'T MISS</span>`;
    if(isOnlyGame)   return `<span class="viewer-intel-chip vic-only"     data-gameid="${g._id||''}" title="Only ${sport} game tonight" onclick="event.stopPropagation();openSetup?.()">ONLY GAME</span>`;
    if(isMyTeam)     return `<span class="viewer-intel-chip vic-team"     data-gameid="${g._id||''}" title="Your team is playing" onclick="event.stopPropagation();openSetup?.()">YOUR TEAM</span>`;
  } else { // myteams
    if(isMyTeam)     return `<span class="viewer-intel-chip vic-team"     data-gameid="${g._id||''}" title="Your team is playing" onclick="event.stopPropagation();openSetup?.()">YOUR TEAM</span>`;
    if(highStakes)   return `<span class="viewer-intel-chip vic-critical" data-gameid="${g._id||''}" title="High-stakes game — consequence matters" onclick="event.stopPropagation();openSetup?.()">DON'T MISS</span>`;
    if(hasNarrative) return `<span class="viewer-intel-chip vic-story"    data-gameid="${g._id||''}" title="Named storylines — context beyond the score" onclick="event.stopPropagation();openSetup?.()">STORY GAME</span>`;
    if(isOnlyGame)   return `<span class="viewer-intel-chip vic-only"     data-gameid="${g._id||''}" title="Only ${sport} game tonight" onclick="event.stopPropagation();openSetup?.()">ONLY GAME</span>`;
  }
  return ''; // No signal fires — no chip (silence is information)
}

// getGameReasonTags (CC-CMD-2026-07-09-game-reason-tags) -- STAGED, no
// caller yet. Foundational, same discipline as tonight's other two
// primitives (claimCardRegion, field:otw_changed_significant): wiring
// this into Coach's Clipboard, Scout Mode, Pressure Stack, Pick'em
// Handshake, or any other bundle item is explicitly out of scope --
// none of them are built yet.
//
// Aggregates only signals already verified real by this CC-CMD's own
// probe -- no new heuristics: _isMyTeamGame (above), g._gameImportance
// (real value pushed verbatim -- elimination/series_deciding/clinch/
// playoff_impl/playoffs, whichever is present -- not translated into an
// invented taxonomy), _otwGetLiveTier()'s named tier when live eData
// exists, and _isCloseAndLate() (mirrors fieldGameTier()'s own T5
// logic).
//
// isRivalGame/isNationalGame/weather-extreme added (CC-CMD-2026-07-10-
// reason-tags-siloed-signals): three more real, already-computed
// signals, each previously feeding exactly one other consumer. Placed
// after user_team/_gameImportance and before the live-tier/close_late
// block -- these three are pregame-available facts, not live-state-
// dependent. Weather note: the doc's own citation (wxCache[gameId]
// .extreme) had drifted -- computeInsights() computes `extreme` as a
// LOCAL variable from wx.temp/wx.wind/wx.precip and attaches it to a
// separate `weather` object, never writes it back onto the wxCache
// entry itself, confirmed by grepping every `.extreme`/`extreme` site
// in the file. Mirrors that exact established formula verbatim,
// reading wxCache[game._id] directly, rather than depending on
// computeInsights() having already run for this game (getGameReasonTags
// has no guaranteed call-order relative to it).
//
// Fixed, simple priority order for this first version: user_team,
// _gameImportance, rivalry, national_tv, weather_extreme, then live
// tier severity, then close_late. Not a scored ranking -- callers
// needing one tag take tags[0]; callers needing several take
// tags.slice(0, n).
function getGameReasonTags(game, eData) {
  const tags = [];
  if (!game) return tags;
  if (_isMyTeamGame(game)) tags.push('user_team');
  if (game._gameImportance) tags.push(game._gameImportance);
  if (typeof isRivalGame === 'function' && typeof MY_TEAMS !== 'undefined' && MY_TEAMS.size > 0 && isRivalGame(game)) tags.push('rivalry');
  if (typeof isNationalGame === 'function' && isNationalGame(game)) tags.push('national_tv');
  if (typeof wxCache !== 'undefined' && game._id) {
    const wx = wxCache[game._id];
    if (wx && (wx.temp<20||wx.temp>100||wx.wind>25||wx.precip>0.5)) tags.push('weather_extreme');
  }
  if (eData) {
    const sport = _gameSport(game);
    // 2026-07-12: _otwGetLiveTier no longer takes a smoothed-drama arg —
    // T3/T4 selection is now raw-observable-only (see its own header comment).
    const liveTier = _otwGetLiveTier(eData, sport);
    if (liveTier) tags.push(liveTier);
    if (_isCloseAndLate(eData, sport)) tags.push('close_late');
  }
  return tags;
}

function injectDramaBadges(){
  const cards = document.querySelectorAll('.game-card.espn-live');
  cards.forEach(card => {
    const gid = card.dataset.gameid;
    if(!gid) return;
    // Migrated to findEspnEntry() (Task 2c, CC-CMD-2026-07-07-pickem-
    // stale-final-resolution-fix v6) -- inherits the stale-final guard.
    // findEspnEntry() takes a game object (needs .home/.away/.start_time
    // for the guard to apply), not a card's dataset, so resolves the real
    // game via the existing findGameById() helper first rather than
    // building a synthetic object without start_time, which would leave
    // the guard permanently inert for this caller.
    const game = findGameById(gid);
    const eData = game ? findEspnEntry(game) : null;
    if(!eData) return;
    const sport = card.dataset.sport||'';
    const _gwLive = getDramaGateway(game, sport);
    if (_gwLive.mode !== 'observation') return; // game is post; live badge skipped
    // CC-CMD-2026-07-04-soccer-drama-scoring-fix TASK 4: thread FIFA ranks
    // into a shallow copy (never mutate the shared espnScores entry) for
    // soccer/WC26 games only — sync cache-only read, never blocks this
    // render; getCachedTeamRank kicks off a background fetch on a cache
    // miss so ranks become available on a later pass.
    const _sp4 = sport.toLowerCase();
    const _isSoccer4 = _sp4.includes('soccer')||_sp4.includes('league')||_sp4.includes('mls')||
      _sp4.includes('liga')||_sp4.includes('ligue')||_sp4.includes('premier')||
      _sp4.includes('wc26')||_sp4.includes('world cup');
    const _dramaEData = _isSoccer4
      ? { ...eData, homeRank: getCachedTeamRank(eData.homeName), awayRank: getCachedTeamRank(eData.awayName) }
      : eData;
    let score = dramaScoreLive(_dramaEData, sport);

    // ── Wow#41: Garbage Time cap ─────────────────────────────────────────
    // Cap drama at 20 when game is in its final period and margin > 24.
    // Prevents blowout games from carrying misleading high drama badges.
    const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
    const period = eData.period || 0;
    const sp = sport.toLowerCase();
    const isFinalPeriod = (
      (sp.includes('basketball')||sp.includes('nba'))  ? period >= 4 :
      (sp.includes('hockey')||sp.includes('nhl'))       ? period >= 3 :
      (sp.includes('football')||sp.includes('nfl'))     ? period >= 4 :
      (sp.includes('baseball')||sp.includes('mlb'))     ? period >= 9 :
      (sp.includes('soccer')||sp.includes('epl')||sp.includes('wc26')||sp.includes('world cup')||sp.includes('fifa')) ? period === 2 : false
    );
    if (isFinalPeriod && margin > 24) score = Math.min(score, 20);

    // ── #18c Statistical Extremes bonus ──────────────────────────────────
    // Applied AFTER garbage time cap so extremes can't rescue blowouts.
    // No-hitter, 4Q surge, comeback, HT reversal. Max +20.
    if(score > 20){  // skip if already capped by garbage time
      const extremes = getStatisticalExtremes(eData, sport);
      if(extremes.dramaBonus > 0) score = Math.min(100, score + extremes.dramaBonus);
    }

    // ── First Lead Change Drama Burst ─────────────────────────────────
    // Detect when the leading team changes in the final period.
    // First lead change → +15 burst to score, decays over 3 polls (~90s).
    if (gid && isFinalPeriod) {
      const currLeader = (eData.homeScore||0) >= (eData.awayScore||0)
        ? (eData.home||'') : (eData.away||'');
      const prev = _leadTracker.get(gid);
      if (prev && prev.leadingTeam && prev.leadingTeam !== currLeader && prev.period === period) {
        // Lead just flipped in the same period → burst
        _leadChangeBurst.set(gid, {startPoll: _pollCycle, value: 15});
        if (FIELD_DEBUG) console.log(`[LeadChange] ${gid} lead flipped to ${currLeader} — burst +15`);
      }
      _leadTracker.set(gid, {leadingTeam: currLeader, period});
    }
    // Reset lead tracker on period change
    if (gid) {
      const prev = _leadTracker.get(gid);
      if (prev && prev.period !== period) _leadTracker.set(gid, {leadingTeam: null, period});
    }
    // Detect story moments from score delta (DO NOT INVENT — score deltas only)
    detectAndStoreStoryMoment(gid, eData, sport);
    // Apply card pulse based on smoothed drama
    // Apply burst to score (before history recording — burst is part of the live signal)
    score = Math.min(100, score + getLeadChangeBurst(gid || ''));

    const tier = dramaTier(score);
    if(gid && score > 0){
      const peakKey = 'field_drama_peak_' + gid;
      // Dual-write (CC-CMD-2026-07-08-pick-cross-session-resolution follow-up):
      // gid is session-volatile, so a peak accumulated under one _id is lost
      // if _gid resets mid-game (midnight-crossover watcher, goToDate() back
      // to Today). `game` is a real object here (findGameById above), so also
      // write under the cross-session-stable key; the running max considers
      // both so a reset mid-accumulation doesn't regress the tracked peak.
      // Same-session-only readers (ViewingConditions.evaluate, gid-only) keep
      // working unchanged off peakKey.
      const stableGameKey = (typeof _pickStorageKey === 'function') ? _pickStorageKey(game) : '';
      const stablePeakKey = stableGameKey ? 'field_drama_peak_' + stableGameKey : '';
      const prevPeak = Math.max(
        parseFloat(localStorage.getItem(peakKey)||'0'),
        stablePeakKey ? (parseFloat(localStorage.getItem(stablePeakKey)||'0')) : 0
      );
      if(score > prevPeak){
        localStorage.setItem(peakKey, score.toString());
        if (stablePeakKey) localStorage.setItem(stablePeakKey, score.toString());
      }
      // ── Drama Arc: record RAW score to history ───────────────────────
      recordDramaHistory(gid, score, eData.period);
      // ── Score snapshot: records factual score changes for OTW momentum ─
      // Uses observable fact (did total score change?) NOT drama score delta.
      // RUWT defense: binary factual event, not composite interest signal.
      recordScoreSnapshot(gid, parseInt(eData.homeScore)||0, parseInt(eData.awayScore)||0);
      // ── PM-28c: Persist interval scores for journalism context ─────────
      // homeLinescores/awayLinescores arrive from ESPN or V2 relay each poll cycle.
      // recordLinescores() only writes when period count increases (guard prevents
      // mid-period stale overwrites). eData.innings only populated for MLB.
      if (typeof recordLinescores === 'function' && eData.homeLinescores?.length) {
        recordLinescores(gid, eData.homeLinescores, eData.awayLinescores,
          eData._sport || '', eData.innings || []);
      }
    }

    // ── Smoothing: use rolling average for display decisions ──────────
    // Raw score preserved in history and peak key above.
    // Badges and ViewingConditions use the smoothed score to prevent
    // single-poll spikes from triggering CRUNCH TIME / EMBER prematurely.
    const smoothed = getSmoothedDrama(gid) ?? score;
    // Apply card pulse (ambient drama signal)
    applyCardPulse(gid, smoothed);

    // ── PM-25 Card Render Slot: delegate all badge mutations to renderCardBadges()
    // Single callsite for CRUNCH TIME / WORTH WATCHING / drama tier / EMBER / MLBN.
    renderCardBadges(card, eData, sport, gid, smoothed);
  });
  // Update ticker + pin widget + life stages on every drama cycle
  renderScoreTicker();
  updatePinWidget();
  updateCardLifeStages();

  // NBA Lineup Edge — async, fires per live NBA card after badges settle (NOT WNBA)
  document.querySelectorAll('.game-card.espn-live').forEach(card => {
    const sport = card.dataset.sport || '';
    const spL = sport.toLowerCase();
    if (!spL.includes('nba') && !spL.includes('nba playoffs')) return;
    if (spL.includes('wnba')) return;
    const gid = card.dataset.gameid;
    if (!gid) return;
    // Migrated to findEspnEntry() (CC-CMD-2026-07-09-espnscores-display-
    // consumer-sweep): the old inline scan matched a loose home-OR-away
    // substring/includes check, distinct from and weaker than
    // findEspnEntry's stricter suffix match, with no stale-final guard.
    const _leGame = findGameById(gid);
    const eData = _leGame ? findEspnEntry(_leGame) : null;
    if (eData?.state === 'in') injectLineupEdge(card, eData, sport).catch(()=>{});
  });

  // MLB Platoon RAI — per live baseball card after badges settle
  document.querySelectorAll('.game-card.espn-live').forEach(card => {
    const sport = card.dataset.sport || '';
    if (!sport.toLowerCase().includes('baseball') && !sport.toLowerCase().includes('mlb')) return;
    const gid = card.dataset.gameid;
    if (!gid) return;
    // Find the FIELD game object for sourceId (MLB gamePk) -- moved before
    // the eData lookup (CC-CMD-2026-07-09-espnscores-display-consumer-
    // sweep) so findEspnEntry(game) can reuse it, replacing the old
    // home-only substring/includes scan.
    const game = allData?.sports?.flatMap(s=>s.games||[]).find(g=>g._id===gid);
    const eData = game ? findEspnEntry(game) : null;
    if (eData?.state === 'in') {
      if (game?.sourceId) injectMLBPlatoon(card, eData, game).catch(()=>{});
    }
  });

  // J7: CDW Notes — inject situational stats on qualifying live cards
  document.querySelectorAll('.game-card.espn-live').forEach(card => {
    const gid = card.dataset.gameid;
    if (!gid) return;
    // Migrated to findEspnEntry() (CC-CMD-2026-07-09-espnscores-display-
    // consumer-sweep), replacing the old home-only substring/includes scan.
    const _cdwGame = findGameById(gid);
    const eData = _cdwGame ? findEspnEntry(_cdwGame) : null;
    if (!eData) return;
    const cdwNote = getCDWNote(eData, card.dataset.sport||'');
    let cdwEl = card.querySelector('.cdw-note');
    if (cdwNote) {
      if (!cdwEl) {
        cdwEl = document.createElement('div');
        cdwEl.className = 'cdw-note';
        // Append to .card-body (flex column) not card root (3-col grid) —
        // bare grid children auto-place into the 3px accent column, causing per-word wrap
        (card.querySelector('.card-body') || card).appendChild(cdwEl);
      }
      cdwEl.textContent = cdwNote;
    } else {
      cdwEl?.remove();
    }
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: DOUBLE FEATURE — Banner when 2+ live games hit a tense named tier
// Cross-sport: "NBA Game · CRUNCH TIME + NHL Game · CLOSE GAME" simultaneously.
// Unique editorial product — no other sports app does this across leagues.
// ADR-002: tier-gated (named conditions), no composite score, no number in DOM.
// ═══════════════════════════════════════════════════════════════════════════

function detectAndRenderDoubleFeature() {
  const HOT_TIERS = new Set(['CRUNCH','EXTRA_TIME','CLOSE_LATE']);
  const hotGames = [];
  (allData?.sports||[]).forEach(sec => {
    (sec.games||[]).forEach(g => {
      if (!g._id) return;
      const tier = fieldGameTier(g._id);
      if (HOT_TIERS.has(tier)) {
        hotGames.push({
          gid: g._id,
          tier,
          rank: fieldTierRank(tier),
          label: (g.away||'?') + ' @ ' + (g.home||'?'),
        });
      }
    });
  });

  let banner = document.getElementById('double-feature-banner');

  if (hotGames.length >= 2) {
    hotGames.sort((a, b) => b.rank - a.rank);
    const top2 = hotGames.slice(0, 2);
    const text = '🎬 Double Feature — '
      + top2[0].label + ' · ' + fieldTierLabel(top2[0].tier)
      + ' + ' + top2[1].label + ' · ' + fieldTierLabel(top2[1].tier);

    if (!banner) {
      banner = document.createElement('div');
      banner.id = 'double-feature-banner';
      banner.className = 'double-feature-banner';
      banner.addEventListener('click', () => banner.remove());
      const container = (_DOM?.fieldBrief||document.getElementById('field-brief')) || document.body;
      container.insertAdjacentElement('beforebegin', banner);
    }
    banner.textContent = text;
    banner.style.display = '';
  } else if (banner) {
    banner.style.display = 'none'; // auto-dismiss when count drops
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: ONE TO WATCH — Highest-drama live game banner
// ═══════════════════════════════════════════════════════════════════════════
// ── One to Watch — omnipresent five-state banner ─────────────────────────────
// State priority: FIRE (≥50 live) → LIVE (<50 live) → SOON (<2hr) → TONIGHT → QUIET
// Banner always renders — never display:none. State drives content + accent colour.
// Dismiss is per-state-key: dismissing one game doesn't kill the banner.

// ── buildOTWStateLabel: named game-state label for OTW banner ────────────────
// Replaces drama tier badges (MUST WATCH / FIRE GAME / COMPELLING) with
// sport-specific factual state descriptions. Returns null when no named
// condition applies — banner shows no badge rather than a drama signal.
// Architecture: named binary conditions only, never a drama score threshold.
function buildOTWStateLabel(g, ed, sport) {
  if (!ed) return null;
  const sp = (sport || g?._section || '').toLowerCase();
  const period = String(ed.period || '');
  const isOT = /ot|overtime|extra/i.test(period);
  const home = parseInt(ed.homeScore) || 0;
  const away = parseInt(ed.awayScore) || 0;
  const margin = Math.abs(home - away);

  if (isOT) return 'OVERTIME';

  if (sp.includes('baseball') || sp.includes('mlb')) {
    const inn = parseInt(period.replace(/[TB]/g,'')) || 0;
    if (inn >= 9) return margin === 0 ? '9TH · TIED' : inn > 9 ? `${inn}TH · ${margin}-RUN` : `9TH · ${margin === 1 ? '1-RUN GAME' : margin + '-RUN GAME'}`;
    if (inn >= 7 && margin <= 2) return `${inn}TH · CLOSE`;
  }
  if (sp.includes('basketball') || sp.includes('nba')) {
    if (period === '4') {
      if (margin === 0) return 'Q4 · TIED';
      if (margin <= 3) return `Q4 · ${margin}-POINT GAME`;
      if (margin <= 8) return 'Q4 · CLOSE';
    }
  }
  if (sp.includes('hockey') || sp.includes('nhl')) {
    if (period === '3') {
      if (margin === 0) return '3RD · TIED';
      if (margin === 1) return '3RD · ONE-GOAL GAME';
    }
  }
  if (sp.includes('soccer') || sp.includes('epl') || sp.includes('mls') ||
      sp.includes('league') || sp.includes('bundesliga') || sp.includes('serie') || sp.includes('ligue')) {
    const min = parseInt(period) || 0;
    if (min >= 70) {
      if (margin === 0) return `${min}\' · TIED`;
      if (margin === 1) return `${min}\' · ONE-GOAL GAME`;
    }
  }
  if (sp.includes('afl')) {
    if (period === '4' && margin <= 7) return 'Q4 · CLOSE';
  }
  return null;
}

const OTW_TIER_LABELS = { fire:'FIRE GAME', hot:'MUST WATCH', warm:'COMPELLING' };

function buildOTWWhyLine(g, ed, sport, isPreGame){
  if(isPreGame){
    const parts=[];
    if(g.start_time){try{const t=new Date(g.start_time).toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit',timeZone:'America/New_York',hour12:true});parts.push(t+' ET');}catch(e){}}
    const net=g.streams?.[0]?.label;if(net&&typeof net==='string') parts.push(net);
    if(g.seriesRecord&&g.seriesRecord!=='0-0') parts.push(g.seriesRecord);
    if(g.matchupNote){const _mn=g.matchupNote.split('.')[0].trim().slice(0,45);if(_mn&&_mn!==g.seriesRecord&&!parts.includes(_mn)) parts.push(_mn);}
    // Fix 5: BNI strength → OTW pre-game anti-hype framing
    const bniOTW=(typeof computeBroadcastNarrativeIndex==='function')?computeBroadcastNarrativeIndex(g):null;
    if(bniOTW){const bniStr=(typeof getBNIStrength==='function')?getBNIStrength(g,bniOTW):0;if(bniStr>=65)parts.push(bniOTW==='narrative-push'?'\u26a0\ufe0f broadcaster hype':bniOTW==='elimination-inflation'?'\u26a0\ufe0f series inflation':'\u26a0\ufe0f marquee push');}
    return parts.slice(0,4).join(' \u00b7 ');
  }
  const parts=[];
  const sp2=sport.toLowerCase();
  if(ed.period){const p=ed.period;parts.push(sportContext(sp2).periodFmt(p,''));}
  if(ed.clock) parts.push(fmtESPNClock(ed.clock));
  const hS=parseInt(ed.homeScore)||0,aS=parseInt(ed.awayScore)||0,gap=Math.abs(hS-aS);
  const trailingNick = hS < aS ? teamNick(g.home||'') : teamNick(g.away||'');
  if(gap===0) parts.push('tied');
  else if(gap===1) parts.push(`${trailingNick} down 1`);
  else if(gap<=3) parts.push(sportContext(sp2).gap(gap));
  if(g.seriesRecord&&g.seriesRecord!=='0-0') parts.push(g.seriesRecord);
  // Fix 5: BNI confirmed live blowout → surface in live why line
  const bniLive=(typeof computeBroadcastNarrativeIndex==='function')?computeBroadcastNarrativeIndex(g):null;
  if(bniLive==='narrative-push'){const bniLStr=(typeof getBNIStrength==='function')?getBNIStrength(g,bniLive):0;if(bniLStr>=75)parts.push('\u26a0\ufe0f hype check');}
  return parts.slice(0,4).join(' \u00b7 ');
}

// ── Score Snapshot — factual score-change tracker for OTW momentum ──────────
// Records observable fact: did the total score change? Binary yes/no.
// RUWT defense: this is NOT a composite interest score. It is a factual record
// of scoring events — the same observable fact a fan watching would notice.
// TTL: entries beyond 5 minutes old are irrelevant for momentum display.
const SCORE_SNAP_KEY = 'field_score_snap_';
const SCORE_SNAP_MAX = 10;

// ── PM-28a: Linescore persistence ────────────────────────────────────────────
// Persists per-period/quarter/inning scores to localStorage so postgame
// journalism prompts can reference them. Previously all interval data was
// discarded at the end of each poll cycle.
//
// Schema: { h:[int], a:[int], sport:str, periods:int, t:ms,
//            innings:[{n,hr,hh,he,ar,ah,ae}] (MLB only) }
// Guard: only update when homeLS.length > stored.periods (never overwrite
//   with stale mid-period data from a later poll that has fewer entries).
// Key: 'field_linescore_' + gameId — pruned by existing midnight prune
//   (prune checks .t against 15-day cutoff, matching this schema).
const LINESCORE_KEY = 'field_linescore_';

function recordLinescores(gameId, homeLS, awayLS, sport, innings) {
  if (!gameId || !homeLS || !homeLS.length) return;
  try {
    const key = LINESCORE_KEY + gameId;
    const stored = JSON.parse(localStorage.getItem(key) || '{"h":[],"a":[],"sport":"","periods":0}');
    if (homeLS.length > (stored.periods || 0)) {
      const entry = {
        h:       homeLS.map(Number),
        a:       awayLS ? awayLS.map(Number) : [],
        sport:   sport || '',
        periods: homeLS.length,
        t:       Date.now(),
      };
      // MLB only: store innings H/R/E array if provided
      if (innings && innings.length) entry.innings = innings;
      localStorage.setItem(key, JSON.stringify(entry));
    }
  } catch(e) {}
}

function getLinescores(gameId) {
  try {
    const raw = localStorage.getItem(LINESCORE_KEY + gameId);
    return raw ? JSON.parse(raw) : null;
  } catch(e) { return null; }
}

// PM-28f: buildLinescoreContext() — formats per-period/quarter/inning scores for AI context
// Live path: eData.homeLinescores / eData.awayLinescores (in-memory, updated each poll)
// Postgame path: getLinescores(gameId) (localStorage, persisted by recordLinescores)
// Output: "[LINE SCORE] Q1: Suns 28, Knicks 26 | Q2: Suns 50, Knicks 55 | ..."
// Team labels are mandatory in the output to prevent LLM convention ambiguity
// (broadcast convention reads pairs as away-home; raw cum-score pairs in home-away
// order caused inverted narratives — see CC-CMD-2026-06-18 Night Owl inversion).
// Guard: returns '' if fewer than 2 completed periods (insufficient signal)
function buildLinescoreContext(eData, gameId, homeLabel, awayLabel) {
  try {
    let homeLS = eData?.homeLinescores || [];
    let awayLS  = eData?.awayLinescores || [];
    // Postgame fallback: read from localStorage
    if (!homeLS.length && gameId) {
      const stored = getLinescores(gameId);
      if (stored) { homeLS = stored.h || []; awayLS = stored.a || []; }
    }
    if (homeLS.length < 2 || awayLS.length < 2) return '';
    const sp = (eData?._sport || '').toLowerCase();
    // Label schema by sport
    const label = (i) => {
      if (sp.includes('nba') || sp.includes('basketball')) return `Q${i+1}`;
      if (sp.includes('nhl') || sp.includes('hockey'))    return `P${i+1}`;
      if (sp.includes('mlb') || sp.includes('baseball'))  return `Inn${i+1}`;
      if (sp.includes('soccer') || sp.includes('league') || sp.includes('mls') ||
          sp.includes('epl') || sp.includes('ucl') || sp.includes('wc26'))
        return i === 0 ? '1H' : i === 1 ? '2H' : `ET${i-1}`;
      return `P${i+1}`;
    };
    // Team nicks for unambiguous labelling. Convention: AWAY listed first
    // (matches "AWAY @ HOME" already in the prompt header and the way broadcasters
    // read box scores). Falls back to 'Away'/'Home' if nicks unavailable.
    const hNick = (typeof teamNick === 'function' && teamNick(homeLabel || '')) || homeLabel || 'Home';
    const aNick = (typeof teamNick === 'function' && teamNick(awayLabel || '')) || awayLabel || 'Away';
    // Build cumulative running score after each period/inning (not per-period isolated)
    // Explicit team names per slot — no positional ambiguity left for the LLM.
    let cumH = 0, cumA = 0;
    const parts = homeLS.map((h, i) => {
      cumH += Number(h) || 0;
      cumA += Number(awayLS[i] ?? 0) || 0;
      return `${label(i)}: ${aNick} ${cumA}, ${hNick} ${cumH}`;
    });
    return `[LINE SCORE] ${parts.join(' | ')}`;
  } catch(e_) { return ''; }
}

// PM-28g: buildGoalTimeline() — formats soccer goal timeline for AI context
// Primary path: _fdGoalCache["{home}|{away}"] → [{player,minute,team}] (football-data.org)
// API-Football path: _afEventCache[gameId] (populated by fetchAFGoalEvents, called on demand)
// Output: "[GOAL TIMELINE] 23' Arsenal/Saka (Odegaard) · 67' Chelsea/Palmer [HT: 1-0]"
// Guard: returns '' for non-soccer or no goal data
const _afEventCache = {}; // gameId → [{time:{elapsed},team:{name},player:{name},assist:{name},type,detail}]
function buildGoalTimeline(game, eData) {
  try {
    const sp = (_gameSport(game) || _gameSport(eData)).toLowerCase();
    if (!(sp.includes('soccer') || sp.includes('league') || sp.includes('mls') ||
          sp.includes('epl')    || sp.includes('ucl')    || sp.includes('liga') ||
          sp.includes('serie')  || sp.includes('ligue')  || sp.includes('bundesliga') ||
          sp.includes('wc26'))) return '';
    const key = `${game?.home||''}|${game?.away||''}`;
    // FD path first (football-data.org goals already normalized)
    const fdGoals = _fdGoalCache[key] || _fdGoalCache[`${game?.away||''}|${game?.home||''}`] || [];
    // AF path: _afEventCache keyed by numeric game ID
    const afGoals = (eData?._gameId ? _afEventCache[eData._gameId] : null) || [];
    const goals = fdGoals.length ? fdGoals : afGoals;
    if (!goals.length) return '';
    const htHome = eData?.htHome ?? null;
    const htAway = eData?.htAway ?? null;
    const htStr  = (htHome !== null && htAway !== null) ? ` [HT: ${htHome}-${htAway}]` : '';
    const events = goals
      .filter(g => g.minute != null)
      .sort((a,b) => (a.minute??0) - (b.minute??0))
      .map(g => {
        const min   = g.minute ?? g.time?.elapsed ?? '?';
        const team  = g.team?.name || g.team || '';
        const player= g.player?.name || g.player || '';
        const assist= g.assist?.name || g.assist || '';
        const short = team ? `${team.split(' ').slice(-1)[0]}` : '';
        const assistStr = assist ? ` (${assist.split(' ').slice(-1)[0]})` : '';
        return `${min}' ${short}/${player.split(' ').slice(-1)[0]}${assistStr}`;
      });
    if (!events.length) return '';
    return `[GOAL TIMELINE] ${events.join(' · ')}${htStr}`;
  } catch(e_) { return ''; }
}

// PM-28h: buildNBAPlayerContext() — top scorers from _nbaBoxscoreCache
// Output: "[NBA BOX] Brunson 32pts/7ast · KAT 24pts/11reb (NYK)"
function buildNBAPlayerContext(game, eData) {
  try {
    const sp = (_gameSport(game) || _gameSport(eData)).toLowerCase();
    if (!(sp.includes('nba') || sp.includes('basketball'))) return '';
    // Look up by all possible ID forms
    const hNick = teamNick(game?.home||'').toLowerCase();
    const aNick = teamNick(game?.away||'').toLowerCase();
    const nbaId = _nbaGameIdMap[`${hNick}_${aNick}`] || _nbaGameIdMap[`${aNick}_${hNick}`];
    const cached = nbaId ? _nbaBoxscoreCache[nbaId] : null;
    if (!cached) return '';
    const fmt = (p) => {
      if (!p?.name) return null;
      const last = p.name.split(' ').slice(-1)[0];
      const teamShort = teamNick(p.team||'');
      const stats = [`${p.pts}pts`];
      if (p.ast >= 5) stats.push(`${p.ast}ast`);
      else if (p.reb >= 7) stats.push(`${p.reb}reb`);
      return `${last} ${stats.join('/')} (${teamShort})`;
    };
    const players = [...(cached.homePlayers||[]), ...(cached.awayPlayers||[])]
      .sort((a,b) => (b.pts||0) - (a.pts||0))
      .slice(0,3)
      .map(fmt).filter(Boolean);
    if (!players.length) return '';
    return `[NBA BOX] ${players.join(' · ')}`;
  } catch(e_) { return ''; }
}

// normalizeApiFootballStats removed (CC-CMD-2026-07-15-never-adopted-
// utilities-disposal): zero real callers, confirmed genuinely superseded
// -- the real, live soccer [MATCH STATS] feature (P6A/P6B) reads
// possession/shots/corners directly from a differently-shaped
// localStorage payload (soccer_stats_{home}|{away}), bypassing this
// normalizer entirely. An independently-built, simpler mechanism
// shipped instead.

function recordScoreSnapshot(gameId, homeScore, awayScore) {
  if (!gameId) return;
  try {
    const key = SCORE_SNAP_KEY + gameId;
    const log = JSON.parse(localStorage.getItem(key) || '[]');
    // Monotonicity repair: real scores never decrease. If the new
    // snapshot is lower than the trailing end of the log in either
    // team's score, that trailing entry — not this new one — is the
    // anomaly (findEspnEntry() re-resolves independently every poll,
    // so a transient game-identity mismatch is exactly as likely on an
    // earlier poll as this one; the newer read isn't inherently less
    // trustworthy). Drop trailing entries this snapshot contradicts
    // rather than rejecting the snapshot outright — a hard reject was
    // tried first and found to backfire: a same-direction bad spike
    // (e.g. a 1-run game briefly logging an impossible 4-run lead, the
    // exact shape of the originally reported bug) passes the check
    // unmodified when it's written, then the REAL settling value that
    // arrives afterward looks like a decrease relative to that bad
    // spike and would itself get permanently rejected — entrenching
    // the bad value instead of correcting it. Popping instead of
    // rejecting self-heals: the bad spike gets dropped the moment a
    // later, real snapshot doesn't fit above it.
    while (log.length && (homeScore < log[log.length - 1].h || awayScore < log[log.length - 1].a)) {
      const dropped = log.pop();
      if (FIELD_DEBUG) console.warn('[recordScoreSnapshot] dropped non-monotonic prior snapshot (likely game-identity mismatch):', gameId, 'dropped', dropped.h, dropped.a, 'in favor of', homeScore, awayScore);
    }
    const last = log[log.length - 1];
    const total = homeScore + awayScore;
    // Only append when total score changes (a scoring event occurred)
    if (!last || last.h + last.a !== total) {
      log.push({ h: homeScore, a: awayScore, t: Date.now() });
      if (log.length > SCORE_SNAP_MAX) log.splice(0, log.length - SCORE_SNAP_MAX);
      localStorage.setItem(key, JSON.stringify(log));
    }
  } catch(e) {}
}

// OTW Momentum: returns 'up' if a scoring event happened within the last 3 minutes.
// RUWT-compliant replacement for drama-score-delta approach.
// Uses binary factual observable: did scoring happen recently? Yes/No.
// No composite score, no threshold comparison on interest level.
function getOTWMomentum(gameId) {
  try {
    const key = SCORE_SNAP_KEY + gameId;
    const log = JSON.parse(localStorage.getItem(key) || '[]');
    if (log.length < 2) return null; // need at least one score change
    const lastChange = log[log.length - 1].t;
    // 'up' if scoring happened within 3 minutes (factual recency check)
    return (Date.now() - lastChange) < 3 * 60 * 1000 ? 'up' : null;
  } catch(e) { return null; }
}

function buildOTWCountdown(startTime){
  const ms=new Date(startTime)-Date.now();
  if(ms<=0) return 'starting';
  const m=Math.floor(ms/60000);
  if(m<60) return `in ${m}m`;
  return `in ${Math.floor(m/60)}h ${m%60}m`;
}

// Dismiss keys: game._id for live/soon, 'tonight' for tonight state
let _otwDismissedId=null;
let _otwCountdownTimer=null;
// PM-27: OTW changeover tracking (field:otw_changed emitter)
let _prevOTWId=null;
// field:otw_changed_significant gating (CC-CMD-2026-07-09-otw-
// significant-event) -- additive to field:otw_changed above, whose
// condition/payload/timing is completely unchanged. Three independent
// protections for this second, ceremonial event only: streak (a
// candidate must win 2 consecutive renderOneToWatch() evaluations),
// tier-margin (named tier must beat the last SIGNIFICANT tier, not just
// be a different game at the same tier), and cooldown (minimum real-time
// gap between significant fires).
let _otwSigCandidateId = null;
let _otwSigCandidateStreak = 0;
let _otwLastSigId = null;
let _otwLastSigTier = null;
let _otwLastSigFireAt = 0;
// Spans several renderOneToWatch() poll cycles (~15-30s cadence per the
// live-score poll this fires from) so cooldown is enforced beyond the
// streak requirement alone, without suppressing a genuinely new
// significant swap for unreasonably long.
const OTW_SIG_COOLDOWN_MS = 90000;
// PM-27: WS freshness tracking — Map<canonical_key, timestamp_ms> (field:ws_fresh emitter)
const _lastWSMessageTime = new Map();

// ADR-002 (M2): categorical-tier selection mirroring _otwFindWCLiveGame.
// minScore arg retained for back-compat; treated as a minimum named-tier
// rank only — the caller's getDramaDial() bound is interpreted as a tier
// floor, not a composite threshold. Highest tier wins.
function _otwFindLiveGame(minScore){
  let best=null,bestRank=-1;
  (allData?.sports||[]).forEach(sec=>{
    (sec.games||[]).forEach(g=>{
      if(!g._id) return;
      // Migrated to findEspnEntry() (CC-CMD-2026-07-09-wc-advprob-and-
      // keys-sweep): the old inline scan's own comment claimed "last
      // whitespace-split word" matching, but alpha-stripping (which also
      // removes spaces) ran before the split, making it a no-op -- the
      // real mechanism was bidirectional endsWith() suffix matching on the
      // full alpha-stripped name, home-only, no away check, no date guard
      // -- the same collision class proven live against a real WC game
      // (this CC-CMD's outbox). state==='in' is kept as an explicit
      // follow-up check since findEspnEntry() doesn't filter by state.
      const ed=findEspnEntry(g, { requireSameDate: true });
      if(!ed || ed.state!=='in') return;
      const tier=fieldGameTier(g._id);
      const rank=fieldTierRank(tier);
      // Only consider tiers above plain LIVE (i.e. CLOSE_LATE+).
      if(rank<fieldTierRank('CLOSE_LATE')) return;
      if(rank>bestRank){
        bestRank=rank;
        // 2026-07-12: dropped the score:_s (dramaScoreLive) computation that
        // used to live here — it was retained solely "for back-compat with
        // downstream _otwGetLiveTier call (smoothed-drama fallback)", and
        // that downstream call site no longer accepts or uses a smoothed
        // arg (CC-CMD-2026-07-12-otw-tier-categorical). Internal sort still
        // uses tier rank, unaffected. The soccer FIFA-rank threading existed
        // only to feed that now-removed computation.
        best={g,ed,sport:sec.sport,tier};
      }
    });
  });
  return best;
}


// RUWT-compliant WC live game selector for the Watch Engine.
//
// NOVEL ARCHITECTURE — categorical hierarchy replaces composite arithmetic:
//   Old pattern (risk): sel = f(crunch, WP, elapsed) → numerical composite → threshold
//   New pattern (clean): strict categorical tiers, no mathematical combination
//
// Within each tier, sort by elapsed time only (single observable fact).
// No composite score is computed — the tier IS the priority, not a scalar derived from it.
//
// RUWT defense: recommendation is driven by categorical classification
// (which named condition tier applies?), not by a composite interest level.
// The RUWT claim requires a composite scalar + threshold comparison.
// Categorical hierarchy with a single within-tier sort key is not that structure.
function _otwFindWCLiveGame() {
  if (!_wcLiveGamesCache.length) return null;
  // Tier 1-6 priority. Named conditions (relay-classified, binary) dominate.
  // Each tier is mutually exclusive based on binary observable facts.
  // Within a tier: latest elapsed wins (most time pressure = most urgency).
  const tiers = [
    // T1: penalty shootout — binary relay condition
    g => g._crunch === 'penalty_shootout' ? 1 : 0,
    // T2: man advantage or stoppage — binary relay conditions
    g => (g._crunch === 'man_advantage' || g._crunch === 'added_time') ? 2 : 0,
    // T3: late deficit — binary relay condition
    g => g._crunch === 'late_deficit' ? 3 : 0,
    // T4: late close game (elapsed ≥ 80 AND draw likely) — two binary checks, AND-gated
    g => {
      const el = g.situation?.elapsed || 0;
      const wp = g.winProb;
      return (el >= 80 && wp && (wp.draw > 0.20 || Math.max(wp.homeWin, wp.awayWin) < 0.65)) ? 4 : 0;
    },
    // T5: late game, draw likely (elapsed ≥ 60 AND draw > 25%) — two binary checks
    g => {
      const el = g.situation?.elapsed || 0;
      const wp = g.winProb;
      return (el >= 60 && wp && wp.draw > 0.25) ? 5 : 0;
    },
    // T6: any live WC game — floor
    g => 6,
  ];
  let bestTier = 99, bestElapsed = -1, best = null;
  for (const g of _wcLiveGamesCache) {
    for (const tier of tiers) {
      const t = tier(g);
      if (!t) continue;
      const el = g.situation?.elapsed || 0;
      if (t < bestTier || (t === bestTier && el > bestElapsed)) {
        bestTier = t; bestElapsed = el; best = { g, tier: t, crunch: g._crunch };
      }
      break; // first matching tier wins for this game
    }
  }
  return best;
}

// Named state label for a live WC game in the Watch Engine (RUWT-compliant).
// Returns a factual binary condition string — never a numerical drama value.
function _buildWCOTWLabel(wcLive) {
  const {g, crunch} = wcLive || {};
  if (crunch === 'penalty_shootout') return 'SHOOTOUT';
  if (crunch === 'man_advantage')    return 'MAN ADV';
  if (crunch === 'added_time')       return 'STOPPAGE';
  if (crunch === 'late_deficit')     return 'LATE · 1 GOAL';
  const elapsed = g?.situation?.elapsed;
  if (elapsed >= 80) return `${elapsed}' · WC`;
  if (elapsed >= 45) return 'WC LIVE';
  return 'WC';
}

function renderOneToWatch(){
  const banner=(_DOM?.otwBanner||document.getElementById('otw-banner'));
  if(!banner) return;
  if(_otwCountdownTimer){clearInterval(_otwCountdownTimer);_otwCountdownTimer=null;}
  banner.style.display='block'; // always visible

  // Calendar context — used across all OTW states
  const _otwCalCtx=typeof getCalendarContext==='function'?getCalendarContext():null;
  const _otwCtxLabel=_otwCalCtx?_otwCalCtx.label:null;
  const _otwCtxHigh=_otwCalCtx&&(_otwCalCtx.urgency==='high'||_otwCalCtx.urgency==='max');

  const dismissBtn=()=>`<button class="otw-close" id="otw-close" aria-label="Dismiss">\u2715</button>`;
  const wire=(dismissId,scrollGame)=>{
    document.getElementById('otw-close')?.addEventListener('click',e=>{e.stopPropagation();_otwDismissedId=dismissId;renderOneToWatch();});
    // Watch button: direct broadcast open (Pipeline B action layer)
    document.getElementById('otw-watch')?.addEventListener('click',e=>{
      e.stopPropagation();
      const btn=document.getElementById('otw-watch');
      const url=btn?.dataset.watchUrl||null;
      if(url) window.open(url,'_blank','noopener');
    });
    document.getElementById('otw-inner')?.addEventListener('click',e=>{
      if(e.target.id==='otw-close'||e.target.id==='otw-watch'||e.target.closest('#otw-watch')) return;
      if(!scrollGame) return;
      const h=(scrollGame.home||'').replace(/[^a-z]/gi,'').toLowerCase();
      const card=[...document.querySelectorAll('.game-card')].find(c=>(c.dataset.home||'').replace(/[^a-z]/gi,'').toLowerCase()===h);
      if(card) card.scrollIntoView({behavior:'smooth',block:'center'});
    });
  };

  // ── STATE 1: FIRE — high-drama live game (ESPN or WC V2) ─────────────────
  // Drama Dial wiring: getDramaDial() replaces hardcoded 50 so user's sensitivity
  // governs OTW selection. Dial range 45-90, default 65. User set to 80 → only
  // tightest games fire as OTW; set to 45 → more games qualify. Server cannot
  // influence this value (localStorage, client-side only). Per RUWT Deep Analysis
  // (Rule 95): MODERATE risk resolved — threshold is now user-controlled, not fixed.
  const fire=_otwFindLiveGame(getDramaDial());
  if(fire&&fire.g._id!==_otwDismissedId){
    const {g,ed,sport}=fire;
    const _gwOTW = getDramaGateway(g, sport);
    if (_gwOTW.mode !== 'observation') return; // game resolved to post; skip OTW
    // ── PM-25 categorical tier refactor: named condition replaces numeric tier ──
    // _otwGetLiveTier returns a named condition string (CRUNCH/EXTRA_TIME/CLOSE_FINISH/LIVE_GAME).
    // _otwTierLabel converts to display string. CSS class still uses the legacy tier name
    // for styling continuity — the change is that the displayed label is now factual, not numeric.
    // 2026-07-12: dropped the smoothed-drama fallback arg (getSmoothedDrama(g._id) ?? score) —
    // _otwGetLiveTier no longer accepts or uses it; T3/T4 are raw-observable-only now.
    const _liveTierKey = _otwGetLiveTier(ed, sport) || 'LIVE_GAME';
    const tier = _liveTierKey === 'CRUNCH' ? 'fire' : _liveTierKey === 'EXTRA_TIME' ? 'fire' : _liveTierKey === 'CLOSE_FINISH' ? 'hot' : 'warm';
    const tierBadge = buildOTWStateLabel(g, ed, sport) || _otwTierLabel(_liveTierKey);
    const _n = (typeof computeGameNarrative==='function') ? computeGameNarrative(g,ed,null) : null;
    const scoreStr = _n?.scoreline || `${ed.awayScore||0}\u2013${ed.homeScore||0}`;
    const why=buildOTWWhyLine(g,ed,sport,false);
    const momentum=getOTWMomentum(g._id);
    const bc=typeof resolveGameBroadcast==='function'?resolveGameBroadcast(g):null;
    const watchLabel=bc?bc.label:'LIVE';
    const watchUrl=bc?.watchUrl||null;
    const isFree=bc?.isFreeOTA||false;
    const watchBtn=watchUrl
      ?`<button class="otw-watch-btn${isFree?' otw-watch-free':''}" id="otw-watch" data-watch-url="${watchUrl}">WATCH \u00b7 ${watchLabel}${isFree?' FREE':''} \u2197</button>`
      :'';
    banner.innerHTML=`<div class="otw-inner${watchBtn?' otw-inner-has-watch':''}" id="otw-inner" role="button" tabindex="0">
      <span class="otw-pulse"></span>
      <span class="otw-label">One to Watch</span>
      <span class="otw-matchup">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''} \u00a0${scoreStr}</span>
      ${why?`<span class="otw-why">${why}</span>`:''}
      ${momentum==='up'?'<span class="otw-momentum up">\u2191</span>':''}
      ${tierBadge?`<span class="otw-drama d-${tier}">${tierBadge}</span>`:""}
      ${watchBtn}
      ${dismissBtn()}
    </div>`;
    // ── PM-27: emit field:otw_changed if OTW game changed ──────────────────
    try {
      const _newOTWId = g._id;
      if (_prevOTWId !== null && _prevOTWId !== _newOTWId && typeof fieldEvents !== 'undefined') {
        fieldEvents.dispatchEvent(new CustomEvent('field:otw_changed', { detail: {
          type: 'field:otw_changed', target: 'otw', source: 'render_otw',
          reason: 'momentum_swap', at: Date.now(),
          payload: { fromId: _prevOTWId, toId: _newOTWId, toHome: g.home||'', toAway: g.away||'' }
        }}));
      }
      _prevOTWId = _newOTWId;
    } catch(_) {}

    // ── field:otw_changed_significant (CC-CMD-2026-07-09-otw-significant-
    // event) -- a second, independent check alongside field:otw_changed
    // above, not a modification of it. Streak tracker updates on every
    // pass, regardless of whether the other two gates hold.
    try {
      if (g._id === _otwSigCandidateId) {
        _otwSigCandidateStreak++;
      } else {
        _otwSigCandidateId = g._id;
        _otwSigCandidateStreak = 1;
      }
      const _streakOk = _otwSigCandidateStreak >= 2;
      const _tierImproved = _otwLastSigId === null ||
        _otwSigTierRank(_liveTierKey) > _otwSigTierRank(_otwLastSigTier);
      const _cooldownCleared = (Date.now() - _otwLastSigFireAt) >= OTW_SIG_COOLDOWN_MS;
      if (_streakOk && _tierImproved && _cooldownCleared && typeof fieldEvents !== 'undefined') {
        fieldEvents.dispatchEvent(new CustomEvent('field:otw_changed_significant', { detail: {
          type: 'field:otw_changed_significant', target: 'otw', source: 'render_otw',
          reason: 'significant_momentum_swap', at: Date.now(),
          payload: { fromId: _otwLastSigId, toId: g._id, toHome: g.home||'', toAway: g.away||'', tier: _liveTierKey }
        }}));
        _otwLastSigId = g._id;
        _otwLastSigTier = _liveTierKey;
        _otwLastSigFireAt = Date.now();
      }
    } catch(_) {}

    wire(g._id,g); return;
  }

  // WC high-drama: check V2 WC live games for FIRE-tier conditions (T1-T3: named CRUNCH states)
  // Categorical: tier 1-3 = named relay conditions. No composite score comparison.
  const wcFire = _otwFindWCLiveGame();
  if(wcFire && wcFire.tier <= 3 && wcFire.g._id !== _otwDismissedId) {
    const {g, crunch} = wcFire;
    const label = _buildWCOTWLabel(wcFire);
    const hScore = g.home?.score ?? 0, aScore = g.away?.score ?? 0;
    const scoreStr = `${aScore}\u2013${hScore}`;
    const bc = typeof resolveGameBroadcast==='function' ? resolveGameBroadcast(g) : null;
    const watchUrl = bc?.watchUrl || null;
    const watchBtn = watchUrl
      ? `<button class="otw-watch-btn${bc.isFreeOTA?' otw-watch-free':''}" id="otw-watch" data-watch-url="${watchUrl}">WATCH \u00b7 ${bc.label}${bc.isFreeOTA?' FREE':''} \u2197</button>`
      : '';
    banner.innerHTML=`<div class="otw-inner${watchBtn?' otw-inner-has-watch':''}" id="otw-inner" role="button" tabindex="0">
      <span class="otw-pulse"></span>
      <span class="otw-label">One to Watch</span>
      <span class="otw-matchup">${g.away?.name||''} @ ${g.home?.name||''} \u00a0${scoreStr}</span>
      <span class="otw-drama d-fire">${label}</span>
      ${watchBtn}
      ${dismissBtn()}
    </div>`;
    wire(g._id, g); return;
  }

  // ── STATE 2: LIVE — any live game, low drama ──────────────────────────────
  const live=_otwFindLiveGame(0);
  if(live&&live.g._id!==_otwDismissedId){
    const {g,ed,sport}=live;
    const _n2 = (typeof computeGameNarrative==='function') ? computeGameNarrative(g,ed,null) : null;
    const scoreStr = _n2?.scoreline || `${ed.awayScore||0}\u2013${ed.homeScore||0}`;
    const why=buildOTWWhyLine(g,ed,sport,false);
    banner.innerHTML=`<div class="otw-inner otw-live" id="otw-inner" role="button" tabindex="0">
      <span class="otw-pulse otw-pulse-live"></span>
      <span class="otw-label">Live</span>
      <span class="otw-matchup">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''} \u00a0${scoreStr}</span>
      ${why?`<span class="otw-why">${why}</span>`:''}
      ${dismissBtn()}
    </div>`;
    wire(g._id,g); return;
  }

  // WC any-live: show any live WC game in STATE 2 position
  if(wcFire && wcFire.g._id !== _otwDismissedId) {
    const {g} = wcFire;
    const label = _buildWCOTWLabel(wcFire);
    const hScore = g.home?.score ?? 0, aScore = g.away?.score ?? 0;
    banner.innerHTML=`<div class="otw-inner otw-live" id="otw-inner" role="button" tabindex="0">
      <span class="otw-pulse otw-pulse-live"></span>
      <span class="otw-label">Live · WC</span>
      <span class="otw-matchup">${g.away?.name||''} @ ${g.home?.name||''} \u00a0${aScore}\u2013${hScore}</span>
      <span class="otw-drama d-pregame">${label}</span>
      ${dismissBtn()}
    </div>`;
    wire(g._id, g); return;
  }

  // ── STATE 3: SOON — game starting in <2 hours ─────────────────────────────
  let soon=null;
  const now=Date.now();
  (allData?.sports||[]).forEach(sec=>{(sec.games||[]).forEach(g=>{
    if(!g.start_time||!g.home||!g.away) return;
    const ms=new Date(g.start_time)-now;
    if(ms>0&&ms<7200000&&(!soon||(new Date(g.start_time)-now)<(new Date(soon.g.start_time)-now)))
      soon={g,sport:sec.sport};
  });});
  if(soon&&_otwDismissedId!=='soon_'+soon.g._id){
    const {g}=soon;
    const net=gameNetwork(g);
    const cd=buildOTWCountdown(g.start_time);
    const startRender=()=>{
      const el=document.getElementById('otw-countdown');
      if(el) el.textContent=buildOTWCountdown(g.start_time);
    };
    banner.innerHTML=`<div class="otw-inner otw-pregame" id="otw-inner" role="button" tabindex="0">
      <span class="otw-pulse otw-pulse-pre"></span>
      <span class="otw-label">${_otwCtxHigh&&_otwCtxLabel?_otwCtxLabel:'Soon'}</span>
      <span class="otw-matchup">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}</span>
      <span class="otw-countdown" id="otw-countdown">${cd}</span>
      ${net?`<span class="otw-drama d-pregame">${net}</span>`:''}
      ${dismissBtn()}
    </div>`;
    _otwCountdownTimer=setInterval(startRender,30000);
    wire('soon_'+g._id,g); return;
  }

  // ── STATE 4: TONIGHT — best upcoming game today ───────────────────────────
  // ADR-002 (H5): rank by named tier, not composite preGameScore + hardcoded
  // 55 threshold. Surface only when top candidate hits MARQUEE_NATIONAL+.
  if(_otwDismissedId!=='tonight'){
    let top=null,topRank=-1;
    (allData?.sports||[]).forEach(sec=>{(sec.games||[]).forEach(g=>{
      if(!g.home||!g.away) return;
      const r=fieldTierRank(fieldGameTier(g._id));
      if(r>topRank){topRank=r;top={g,sport:sec.sport,rank:r};}
    });});
    const _tonightMinRank=fieldTierRank('MARQUEE_NATIONAL');
    if(top&&topRank>=_tonightMinRank){
      const {g}=top;
      const why=buildOTWWhyLine(g,{},top.sport,true);
      banner.innerHTML=`<div class="otw-inner otw-pregame" id="otw-inner" role="button" tabindex="0">
        <span class="otw-pulse otw-pulse-pre"></span>
        <span class="otw-label">${_otwCtxHigh&&_otwCtxLabel?_otwCtxLabel:'Tonight'}</span>
        <span class="otw-matchup">${g.away||''} ${g.neutral?'vs':'@'} ${g.home||''}</span>
        ${why?`<span class="otw-why">${why}</span>`:''}
        <span class="otw-drama d-pregame">TOP PICK</span>
        ${dismissBtn()}
      </div>`;
      wire('tonight',g); return;
    }
  }

  // ── STATE 5: QUIET — nothing notable ─────────────────────────────────────
  // Guard: never show QUIET when a WC game is live (WC bypasses espnScores entirely)
  if(_wcLiveGamesCache.length > 0) {
    // WC is live but user dismissed the game — show minimal live indicator
    const g = _wcLiveGamesCache[0];
    banner.innerHTML=`<div class="otw-inner otw-live" aria-hidden="true">
      <span class="otw-pulse otw-pulse-live"></span>
      <span class="otw-label">Live · WC</span>
      <span class="otw-matchup">${g.away?.name||''} @ ${g.home?.name||''}</span>
    </div>`;
    return;
  }
  const quietMsg=_otwCalCtx?`${_otwCalCtx.label} season`:'No live games right now';
  banner.innerHTML=`<div class="otw-inner otw-quiet" aria-hidden="true">
    <span class="otw-label">${_otwCalCtx?'Season':'Quiet'}</span>
    <span class="otw-matchup">${quietMsg}</span>
  </div>`;
}

// ── Mobile Intelligence Bar — live game summaries on phone ≤600px ─────────
// Patent Defense #1: uses getDramaDial() for client-side personalization.
// Server sends identical data; each phone renders different intelligence
// based on localStorage Drama Dial setting.
function renderMobileLiveBar(){
  const bar=document.getElementById('mobile-live-bar');
  if(!bar) return;
  // Only show on mobile
  if(window.innerWidth>600){bar.style.display='none';return;}
  // Collect all live games with drama scores
  const liveGames=[];
  const dial=typeof getDramaDial==='function'?getDramaDial():65;
  (allData?.sports||[]).forEach(sec=>{
    (sec.games||[]).forEach(g=>{
      if(!g._id) return;
      // Migrated to findEspnEntry() (CC-CMD-2026-07-09-wc-advprob-and-
      // keys-sweep) -- same fix as _otwFindLiveGame's identical inline scan.
      const ed=findEspnEntry(g, { requireSameDate: true });
      if(!ed || ed.state!=='in') return;
      // ADR-002 (H6): tier-driven chip, not composite drama + 4-band thresholds.
      const _mlbTier=fieldGameTier(g._id);
      liveGames.push({g,ed,sport:sec.sport,tier:_mlbTier,rank:fieldTierRank(_mlbTier)});
    });
  });
  if(liveGames.length<2){bar.style.display='none';return;}
  liveGames.sort((a,b)=>b.rank-a.rank);
  const top=liveGames.slice(0,5);
  const chips=top.map(({g,ed,tier:_t})=>{
    const tier = (_t==='CRUNCH'||_t==='EXTRA_TIME') ? 'fire'
               : _t==='CLOSE_LATE'                  ? 'crunch'
               : _t==='LIVE'                        ? 'warm' : 'low';
    const tierLabel = (_t==='CRUNCH'||_t==='EXTRA_TIME') ? '🔥'
                    : _t==='CLOSE_LATE'                  ? '⚡'
                    : _t==='LIVE'                        ? '●' : '';
    const tn=typeof teamNick==='function'?teamNick:n=>n;
    const away=tn(g.away||'').slice(0,12);
    const home=tn(g.home||'').slice(0,12);
    const scoreStr=`${ed.awayScore||0}-${ed.homeScore||0}`;
    const hId=(g.home||'').replace(/[^a-z]/gi,'').toLowerCase();
    // Patent note: removed raw drama number. Tier label (🔥/⚡/●) conveys the same
    // information without exposing a threshold-comparable numerical value on a card.
    // dramaScoreLive() is Case C (single dimension, live game state) — safe — but
    // the number is unnecessary when the tier label already communicates intensity level.
    return `<div class="mlb-chip" data-scroll-home="${hId}">
      <span class="mlb-chip-teams">${away} @ ${home}</span>
      <span class="mlb-chip-score">${scoreStr}</span>
      <span class="mlb-chip-drama d-${tier}">${tierLabel}</span>
    </div>`;
  }).join('');
  bar.innerHTML=`<div class="mlb-header">\u26a1 ${liveGames.length} Live</div><div class="mlb-row">${chips}</div>`;
  bar.style.display='block';
  // Tap chip → scroll to game card
  bar.querySelectorAll('.mlb-chip').forEach(chip=>{
    chip.addEventListener('click',()=>{
      const h=chip.dataset.scrollHome;
      const card=[...document.querySelectorAll('.game-card')].find(c=>(c.dataset.home||'').replace(/[^a-z]/gi,'').toLowerCase()===h);
      if(card) card.scrollIntoView({behavior:'smooth',block:'center'});
    });
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// FEATURE: SHARE GAME CARD (Web Share API + clipboard fallback)
// ═══════════════════════════════════════════════════════════════════════════
// ── ICS Export — Add to Calendar ──────────────────────────────────────────────
// Generates a .ics file for any game card. Works with Apple Calendar, Google
// Calendar (import), Outlook, and any standards-compliant calendar app.
// Duration: 2h30m default (covers most games; user can adjust in calendar)
function generateICS(game){
  const start=new Date(game.start_time);
  const end=new Date(start.getTime()+150*60000); // +2h30m
  const fmt=d=>d.toISOString().replace(/[-:]/g,'').split('.')[0]+'Z';
  const esc=s=>(s||'').replace(/[,;\\]/g,'\\$&').replace(/\n/g,'\\n');
  const title=`${game.away||'Game'} @ ${game.home||'TBD'}`;
  const network=gameNetwork(game);
  const desc=esc([
    game.league||'',
    network?`Watch on ${network}`:'',
    game.matchupNote||'',
    'Added from FIELD Global Sports Intelligence'
  ].filter(Boolean).join(' · '));
  const ics=[
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//FIELD Global Sports//EN',
    'CALSCALE:GREGORIAN',
    'METHOD:PUBLISH',
    'BEGIN:VEVENT',
    `DTSTART:${fmt(start)}`,
    `DTEND:${fmt(end)}`,
    `SUMMARY:${esc(title)}`,
    `DESCRIPTION:${desc}`,
    game.venue?`LOCATION:${esc(game.venue)}`:'',
    `UID:field-${game._id||Date.now()}@jubilant-bassoon.jeffunglesbee.workers.dev`,
    `DTSTAMP:${fmt(new Date())}`,
    'END:VEVENT',
    'END:VCALENDAR'
  ].filter(Boolean).join('\r\n');

  const blob=new Blob([ics],{type:'text/calendar;charset=utf-8'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  const safeTitle=title.replace(/[^a-z0-9]+/gi,'-').toLowerCase().slice(0,40);
  a.href=url; a.download=`field-${safeTitle}.ics`;
  document.body.appendChild(a); a.click();
  setTimeout(()=>{URL.revokeObjectURL(url);a.remove();},1000);
}

// 2026-07-13 (TYPED-RESULT-MIGRATION-QUEUE.md Bucket A #13): two real
// issues found reading this closely, not just the queue's original note.
// (1) The original note: both navigator.share and the clipboard fallback
// failing silently left the user with zero feedback -- they click Share,
// nothing happens, no error. Fixed with a real failure toast.
// (2) Found while fixing (1): navigator.share() throws a DOMException
// named 'AbortError' when the user simply CANCELS the native share sheet
// -- a deliberate choice, not a failure. The old code treated that
// identically to a genuine share failure, silently writing the share text
// to the clipboard anyway and showing "Copied to clipboard!" for an
// action the user never took. Now respects a deliberate cancel: no
// clipboard fallback, no toast, nothing happens (matching what the user
// actually asked for by dismissing the sheet).
async function shareGame(home, away, time, league, streams){
  const svcNames = (streams||[]).slice(0,2).map(k=>{
    const sr = (typeof SR!=='undefined'&&SR[k])||null;
    return sr ? sr[0] : k;
  }).join('/');
  const shareText = [
    `${away||''} @ ${home||''}`,
    time ? `🕐 ${time}` : '',
    svcNames ? `📺 ${svcNames}` : '',
    league||'',
    '— via FIELD',
  ].filter(Boolean).join(' · ');

  if(navigator.share){
    try {
      await navigator.share({title:'FIELD', text:shareText, url:location.href});
      return; // native share sheet handled it — OS shows its own confirmation, no toast needed
    } catch(e){
      if(e && e.name === 'AbortError') return; // user deliberately cancelled — respect it
      // any other navigator.share failure falls through to the clipboard attempt below
    }
  }

  try {
    await navigator.clipboard.writeText(shareText);
    showShareToast('Copied to clipboard!');
  } catch(e2){
    showShareToast("Couldn't share this game — try again.");
  }
}

function showShareToast(msg){
  const t = document.getElementById('share-toast');
  if(!t) return;
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'), 2200);
}

// ── Delegate share button clicks ─────────────────────────────────────────
document.addEventListener('click', e => {
  const btn = e.target.closest('.share-btn');
  if(!btn) return;
  e.stopPropagation();
  const card = btn.closest('.game-card');
  if(!card) return;
  const home = card.dataset.home||'';
  const away = card.dataset.away||'';
  const sport = card.dataset.sport||'';
  const league = card.querySelector('.league-badge')?.textContent||sport;
  const time = card.querySelector('.time-display,.time')?.textContent||'';
  const streams = [];  // streams not easily available here — use league context
  shareGame(home, away, time, league, streams);
});

// ── Delegate calendar button clicks ──────────────────────────────────────
document.addEventListener('click', e => {
  const btn = e.target.closest('.cal-btn');
  if(!btn) return;
  e.stopPropagation();
  const card = btn.closest('.game-card');
  if(!card) return;
  // Reconstruct minimal game object from card data attributes
  const game = {
    home:   card.dataset.home||'',
    away:   card.dataset.away||'',
    _id:    card.dataset.gameid||btn.dataset.gameId||Date.now(),
    start_time: card.dataset.starttime||'',
    league: card.querySelector('.league-badge')?.textContent||card.dataset.sport||'',
    venue:  card.dataset.venue||'',
    streams: [],
    matchupNote: ''
  };
  // Enrich from live allData if available
  if(typeof allData!=='undefined'&&allData.sports){
    const id=card.dataset.gameId||card.dataset.gameid;
    const found=allGamesFlat().find(g=>g._id===id);
    if(found) Object.assign(game,found);
  }
  if(!game.start_time){showShareToast('\u274c No time data for this game');return;}
  generateICS(game);
  showShareToast('\u2705 .ics downloaded \u2014 open to add to calendar');
});


// ── iOS Safari "Add to Home Screen" prompt ──────────────────────────────────
// iOS doesn't fire beforeinstallprompt. Show manual instructions after 3rd visit.
(function iosInstallPrompt(){
  if(typeof window === 'undefined' || typeof navigator === 'undefined') return;
  const isIOS = /iPhone|iPad|iPod/.test(navigator.userAgent);
  const isStandalone = (typeof window.matchMedia === 'function' && window.matchMedia('(display-mode: standalone)').matches) ||
                       window.navigator?.standalone === true;
  if(!isIOS || isStandalone) return;
  if(localStorage.getItem('field_ios_prompt_dismissed')) return;

  const visits = parseInt(localStorage.getItem('field_visit_count')||'0') + 1;
  localStorage.setItem('field_visit_count', visits);
  if(visits < 3) return;  // show after 3rd visit

  // Create iOS-specific prompt (different UI, explains Share→Add to Home Screen)
  const banner = document.getElementById('pwa-banner');
  if(!banner) return;
  banner.innerHTML = `
    <span class="pwa-banner-icon">📲</span>
    <div class="pwa-banner-copy">
      <div class="pwa-banner-title">INSTALL FIELD ON YOUR iPhone</div>
      <div class="pwa-banner-sub">Tap <strong>Share ↑</strong> then "Add to Home Screen"</div>
    </div>
    <button class="pwa-dismiss" id="pwa-dismiss-ios" aria-label="Dismiss">✕</button>
  `;
  banner.style.display = 'flex';
  document.getElementById('pwa-dismiss-ios')?.addEventListener('click', () => {
    banner.style.display = 'none';
    localStorage.setItem('field_ios_prompt_dismissed','1');
  });
})();


