// ── Baseball Situation Renderer ──────────────────────────────────────────────
function renderBaseballSitChip(eData){
  if(!eData) return "";
  const {onFirst,onSecond,onThird,outs,balls,strikes} = eData;
  if(onFirst===undefined && outs===undefined) return "";  // not MLB

  // Base diamond grid: 3rd (top-left), 2nd (top-mid), 1st (top-right)
  const b1 = onFirst  ? "on" : "";
  const b2 = onSecond ? "on" : "";
  const b3 = onThird  ? "on" : "";
  const basesHTML = `<div class="sit-bases" title="Bases">
    <span></span><span class="sit-base ${b2}" title="2nd"></span><span></span>
    <span class="sit-base ${b3}" title="3rd"></span><span></span><span class="sit-base ${b1}" title="1st"></span>
  </div>`;

  const outsNum = outs ?? 0;
  const outsStr = `${outsNum} out${outsNum===1?"":"s"}`;

  let countStr = "";
  if(balls!==undefined && strikes!==undefined){
    const full = balls===3 && strikes===2;
    const urgent = full || (balls===3 && outsNum===2) || (strikes===2 && outsNum===2);
    countStr = `<span class="${urgent?"sit-urgent":"sit-count"}">${balls}-${strikes}${full?" Full":""}${strikes===2?" ⚠️":""}</span>`;
  }

  // Bases loaded urgency
  const basesLoaded = onFirst && onSecond && onThird;
  const situNote = basesLoaded
    ? `<span class="sit-urgent">🚨 Bases Loaded</span>`
    : (onSecond||onThird) ? `<span class="sit-count">RISP</span>` : "";

  return `<div class="baseball-sit">${basesHTML}${countStr}<span class="sit-outs">${outsStr}</span>${situNote}</div>`;
}

// ── Inject baseball situation chips into live MLB cards ───────────────────────
function injectBaseballSitChips(){
  const cards = document.querySelectorAll(".game-card.espn-live[data-sport='Baseball (MLB)']");
  cards.forEach(card => {
    // Remove existing chip
    card.querySelectorAll(".baseball-sit").forEach(c=>c.remove());
    // Migrated to findEspnEntry() (CC-CMD-2026-07-09-espnscores-display-
    // consumer-sweep), replacing the old home-only exact/suffix scan.
    const _bsGame = findGameById(card.dataset.gameid);
    const eData = _bsGame ? findEspnEntry(_bsGame) : null;
    if(!eData || eData.state !== "in") return;
    const chip = renderBaseballSitChip(eData);
    if(!chip) return;
    const matchup = card.querySelector(".matchup");
    if(matchup) matchup.insertAdjacentHTML("afterend", chip);
  });
}

// renderMLBWhosUpNextChip (CC-CMD-2026-07-10-mlb-whos-up-next): mirrors
// renderBaseballSitChip's own pattern -- pure render function, no fetch,
// no DOM access; the caller (refreshMLBStatus) supplies a real forecast
// object or null. Only states WHO and roughly WHEN (lineup math), never
// an outcome, per this codebase's anti-fabrication rules.
function renderMLBWhosUpNextChip(forecast){
  if(!forecast) return "";
  const esc = s => String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
  return `<div class="mlb-whos-up-next">🔜 In ~${forecast.estMinutes} min: likely ${esc(forecast.name)}'s at-bat (#${forecast.slot})</div>`;
}


