// Wow #37: MY RIVALS
const RIVALRIES=[['boston celtics','los angeles lakers'],['chicago bulls','detroit pistons'],['new york knicks','miami heat'],['los angeles lakers','golden state warriors'],['cleveland cavaliers','chicago bulls'],['boston celtics','new york knicks'],['golden state warriors','oklahoma city thunder'],['miami heat','boston celtics'],['montreal canadiens','toronto maple leafs'],['boston bruins','montreal canadiens'],['new york rangers','new jersey devils'],['detroit red wings','colorado avalanche'],['chicago blackhawks','st. louis blues'],['pittsburgh penguins','philadelphia flyers'],['vegas golden knights','colorado avalanche'],['new york yankees','boston red sox'],['new york mets','new york yankees'],['chicago cubs','st. louis cardinals'],['los angeles dodgers','san francisco giants'],['cleveland guardians','chicago white sox'],['detroit tigers','chicago white sox'],['atlanta braves','new york mets'],['dallas cowboys','philadelphia eagles'],['new england patriots','new york jets'],['green bay packers','chicago bears'],['san francisco 49ers','seattle seahawks'],['baltimore ravens','pittsburgh steelers'],['kansas city chiefs','las vegas raiders'],['new york giants','dallas cowboys'],['manchester united','manchester city'],['arsenal','tottenham hotspur'],['liverpool','manchester united'],['real madrid','fc barcelona'],['la galaxy','lafc'],['seattle sounders','portland timbers']];
const RIVAL_MAP=new Map();
for(const [a,b] of RIVALRIES){if(!RIVAL_MAP.has(a))RIVAL_MAP.set(a,new Set());if(!RIVAL_MAP.has(b))RIVAL_MAP.set(b,new Set());RIVAL_MAP.get(a).add(b);RIVAL_MAP.get(b).add(a);}
// rivalsFilter: moved earlier — see before goToDate(TODAY_ISO)
function isRivalGame(g){
  try {
    const h=(g.home||'').toLowerCase(),a=(g.away||'').toLowerCase();
    for(const t of MY_TEAMS){const tl=t.toLowerCase();if(h===tl||a===tl)return false;const rivals=RIVAL_MAP.get(tl)||new Set();if(rivals.has(h)||rivals.has(a))return true;}
    return false;
  } catch(e) { captureFieldError('rivalry:is-rival-game', e, true); return false; } // guard: RIVAL_MAP may be in TDZ if called before line 18657
}

// ── VIBE-A helpers (2026-05-28) ──────────────────────────────────────────────
// isCrunchTimeGame: named game-state (SPORT_CRUNCH_RULES period + margin ≤5).
// Replaces local isCrunchTime var inside ViewingConditions. Better patent posture:
// no composite score, pure named conditions. Same pattern as isLateCloseGame.
function isCrunchTimeGame(eData, sport) {
  if (!eData || eData.state !== 'in') return false;
  const period = String(eData.period || '').toLowerCase();
  if (!SPORT_CRUNCH_RULES?.[sport]) return false;
  const inCrunchPeriod = SPORT_CRUNCH_RULES[sport].some(r => period.includes(r));
  const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  return inCrunchPeriod && margin <= 5;
}

// isObjectiveRival: checks RIVAL_MAP directly (no MY_TEAMS dependency).
// BLOOD GAME fires for any rivalry game regardless of user's team preferences.
// Replaces computeRivalry() (which did not exist).
function isObjectiveRival(g) {
  try {
    const h = (g.home||'').toLowerCase();
    const a = (g.away||'').toLowerCase();
    return (RIVAL_MAP.get(h) || new Set()).has(a);
  } catch(e) { captureFieldError('rivalry:is-objective-rival', e, true); return false; }
}

// isGrindingGame: named game-state for GRINDING badge.
// RUWT fix: replaces isGrindState (used dramaScoreLive() threshold = patent risk).
// Named conditions: live + close margin + not crunch time. No composite score.
function isGrindingGame(eData, sport) {
  if (!eData || eData.state !== 'in') return false;
  const margin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
  if (margin > 8) return false;
  // If already crunch time, CRUNCH TIME badge takes precedence
  if (typeof isCrunchTimeGame === 'function' && isCrunchTimeGame(eData, sport)) return false;
  return true;
}

// isAloneOnScreen: only game in a ±45min window.
// Fix: allData (not window.allData — it is a module-level variable).
function isAloneOnScreen(game) {
  if (!allData?.sports) return false;
  const gameTime = new Date(game.start_time).getTime();
  const allGames = allData.sports.flatMap(s => s.games || []);
  return !allGames.some(g => {
    if ((g._id||g) === (game._id||game)) return false;
    return Math.abs(new Date(g.start_time).getTime() - gameTime) < 45 * 60 * 1000;
  });
}

// buildVibeChips: returns [{label, cls}] for .ganalytics strip.
// All nine states are categorical named facts — patent: ✅ safe.
// MUTED: bni !== null (BNI categorical output, not getBNIStrength threshold).
// GRINDING: isGrindingGame() named conditions (not dramaScore gate).
function buildVibeChips(game, eData, sport) {
  const chips = [];
  const st = eData?.state || 'pre';
  const isLive = st === 'in', isPost = st === 'post', isPre = !isLive && !isPost;

  if (isPost) {
    // DEBRIEF renders for ALL post-state games. The post state IS the
    // amnesty / quiet-game tier — exactly the cards that rarely receive a
    // game-specific J1 brief. Gating the chip on _gameBriefCache[g._id]
    // suppressed it on the matchups it was designed for; the journalism
    // section always has J3 + other content the user can land on instead.
    const _gid = game?._id;
    // Click: open journalism (toggleJournalismView is a toggle, so only
    // call it when journalism-mode is currently off), then 150ms later try
    // to scroll to this game's brief via the data-gameid hook. If the
    // game-specific brief element doesn't exist (quiet-game path), fall
    // back to scrolling the journalism section root into view so the chip
    // still does something useful.
    const _onclick = `event.stopPropagation();if(!document.body.classList.contains('journalism-mode'))toggleJournalismView();setTimeout(()=>{const _el=document.querySelector('[data-gameid=\\'${_gid}\\']')||document.getElementById('field-journalism-section');if(_el)_el.scrollIntoView({behavior:'smooth',block:'start'});},150)`;
    return [{ label: 'DEBRIEF', cls: 'post', onclick: _onclick }];
  }

  // MUTED — BNI fired (categorical string, not a numeric threshold gate)
  if (isPre) {
    const bni = typeof computeBroadcastNarrativeIndex === 'function'
      ? computeBroadcastNarrativeIndex(game) : null;
    if (bni) chips.push({ label: '\uD83D\uDD07 MUTED', cls: 'mute' });
  }
  // CRUNCH TIME
  if (isLive && isCrunchTimeGame(eData, sport))
    chips.push({ label: 'CRUNCH TIME', cls: 'crunch' });
  // ELIMINATION
  if (game._gameImportance === 'elimination')
    chips.push({ label: 'ELIMINATION', cls: 'stakes' });
  // BLOOD GAME
  if (isObjectiveRival(game) &&
      (game._gameImportance === 'clinch' || game.isPlayoff || game.seriesRecord))
    chips.push({ label: 'BLOOD GAME', cls: 'blood' });
  // ALONE ON SCREEN — pre-game and live only (not post-game/final)
  if (isAloneOnScreen(game) && eData?.state !== 'post')
    chips.push({ label: 'ALONE ON SCREEN', cls: 'alone' });
  // MISSION
  if (game._gameImportance === 'series_deciding')
    chips.push({ label: 'MISSION', cls: 'mission' });
  // VOLATILE
  if (isPre && isVolatileMatchup(game))
    chips.push({ label: 'VOLATILE', cls: 'volatile' });
  // GRINDING — named conditions only (no dramaScore gate)
  if (isLive && isGrindingGame(eData, sport))
    chips.push({ label: 'GRINDING', cls: 'grind' });

  // ── Win probability chip (ESPN scalar wp, 0-1 scale) ─────────────────
  // eData.wp is the home team win probability as a 0-1 fraction (L19293
  // verified: 0.872 = 87.2%). Shown only when game is live AND the trailing
  // team has <= 25% chance — outcome in genuine doubt. Data path verified:
  // eData IS the espnScores entry passed via findESPNScore(g) at L10430.
  const wpVal = eData?.wp;
  if (isLive && wpVal != null) {
    const homeWp = wpVal;
    const awayWp = 1 - homeWp;
    const trailingWp = Math.min(homeWp, awayWp);
    if (trailingWp <= 0.25) {
      const trailingAbbr = homeWp < awayWp
        ? (game._homeAbbr || game.home || 'HOME')
        : (game._awayAbbr || game.away || 'AWAY');
      const pct = Math.round(trailingWp * 100);
      chips.push({ label: `${trailingAbbr} ${pct}%`, cls: 'long' });
    }
  }

  return chips;
}


