// ── Game-card tap delegate — belt-and-suspenders for Android/Samsung ─────────
// Some Android browsers (Samsung Internet, Chrome on Galaxy) suppress 'click'
// on divs even with cursor:pointer. The touchend delegate catches these cases.
// Tap threshold: <8px movement (not a scroll). stopPropagation if child button caught it.
(function initCardTapDelegate(){
  let _tStartX=0,_tStartY=0,_lastCardTap=0;
  document.addEventListener('touchstart',e=>{
    _tStartX=e.touches[0].clientX; _tStartY=e.touches[0].clientY;
  },{passive:true});
  document.addEventListener('touchend',e=>{
    const dx=Math.abs((e.changedTouches[0]?.clientX||0)-_tStartX);
    const dy=Math.abs((e.changedTouches[0]?.clientY||0)-_tStartY);
    if(dx>8||dy>8) return; // scrolled — not a tap
    const card=e.target.closest('.game-card');
    if(!card) return;
    if(e.target.closest('.pin-btn,.star-btn,.cal-btn,.share-btn')) return; // let buttons handle
    const gid=card.dataset.gameid;
    if(!gid) return;
    _lastCardTap=Date.now();
    openBottomSheet(gid);
  },{passive:true});
  // Suppress the synthetic click that follows touchend on Android to prevent double-open
  document.addEventListener('click',e=>{
    if(Date.now()-_lastCardTap<600){
      const card=e.target.closest('.game-card');
      if(card) e.stopImmediatePropagation();
    }
  },true); // capture phase — runs before inline onclick
})();

// ── Star button delegate ─────────────────────────────────────────────────
function _dismissTeamPicker(){ document.querySelectorAll('.team-picker').forEach(p=>p.remove()); }
document.addEventListener('click', e => {
  // Dismiss open picker on outside click
  if(!e.target.closest('.team-picker') && !e.target.closest('.star-btn')) _dismissTeamPicker();

  const btn = e.target.closest('.star-btn');
  if(!btn) return;
  e.stopPropagation();
  const card = btn.closest('.game-card');
  if(!card) return;
  const home = card.dataset.home || '';
  const away = card.dataset.away || '';

  if(!MY_TEAMS.has(home) && MY_TEAMS.has(away)){
    // Away already starred — unstar it
    _dismissTeamPicker();
    toggleMyTeam(away);
  } else if(MY_TEAMS.has(home)){
    // Home already starred — unstar it
    _dismissTeamPicker();
    toggleMyTeam(home);
  } else {
    // Neither starred — show two-button team picker
    const existing = card.querySelector('.team-picker');
    if(existing){ existing.remove(); return; }
    _dismissTeamPicker();
    const picker = document.createElement('div');
    picker.className = 'team-picker';
    const awayLabel = away || 'Away';
    const homeLabel = home || 'Home';
    picker.innerHTML =
      `<button class="tp-btn" data-team="${away}">★ ${awayLabel}</button>`+
      `<button class="tp-btn" data-team="${home}">★ ${homeLabel}</button>`;
    picker.addEventListener('click', ev => {
      const tb = ev.target.closest('.tp-btn');
      if(!tb) return;
      ev.stopPropagation();
      toggleMyTeam(tb.dataset.team);
      picker.remove();
    });
    btn.insertAdjacentElement('afterend', picker);
  }
});



