// Monthly prices for streaming services — used by coverage dashboard + marginal cost display
const PRICES = {
  peacock:9.99, max:16.99, prime:14.99, apple:9.99, espnplus:11.99, paramount:7.99,
  tcplus:9.99, netflix:7.99, mlbtv:24.99, mlbplus:5.99, bein:9.99, willow:9.99,
  youtubetv:82.99, fubo:79.99, hulu:82.99, sling:45.99, directv:84.99,
};

// ── Coverage stats for tonight's schedule ───────────────────────────────────
function computeCoverageStats(services){
  try {
  const allGames = allGamesFlat().filter(g=>g.streams?.length);
  const total = allGames.length;
  const covered = allGames.filter(g=>g.streams.some(s=>services.has(s.key))).length;
  const uncovered = allGames.filter(g=>!g.streams.some(s=>services.has(s.key)));
  // Find best single add to maximize coverage (must have a price)
  const svcGain = {};
  uncovered.forEach(g=>(g.streams||[]).forEach(s=>{ svcGain[s.key]=(svcGain[s.key]||0)+1; }));
  const bestAdd = Object.entries(svcGain)
    .filter(([k])=>PRICES[k] && !services.has(k))
    .sort((a,b)=>b[1]-a[1])[0];
  return {total, covered, uncoveredCount:total-covered, uncovered, bestAdd};
  } catch(e) { return {total:0,covered:0,uncoveredCount:0,uncovered:[],bestAdd:null}; } // TDZ guard: PRICES may not be initialized
}

// ── Render coverage bar at top of My Services modal ─────────────────────────
function renderCoverageDashboard(){
  const existing = document.getElementById('coverage-bar');
  if(existing) existing.remove();
  if(!allData?.sports?.length) return;
  const stats = computeCoverageStats(MY_SERVICES);
  const pct = stats.total ? Math.round((stats.covered/stats.total)*100) : 100;
  const allCovered = stats.uncoveredCount === 0;
  const bestKey = stats.bestAdd?.[0];
  const bestGain = stats.bestAdd?.[1]||0;
  const bestName = bestKey ? (SR[bestKey]?.[0]||bestKey) : '';
  const bestPrice = bestKey ? PRICES[bestKey] : null;

  const bar = document.createElement('div');
  bar.id = 'coverage-bar';
  bar.className = 'coverage-bar';
  bar.innerHTML = allCovered
    ? `<div class="cov-head">✓ All ${stats.total} games tonight covered with your subscriptions</div>`
    : `<div class="cov-head">Tonight: <strong>${stats.covered}/${stats.total}</strong> games covered
        <span class="cov-pct">${pct}%</span></div>
       ${bestKey ? `<div class="cov-tip">➕ Add <strong>${bestName}</strong>${bestPrice?` ($${bestPrice}/mo)`:''}
         → unlocks <strong>${bestGain}</strong> more game${bestGain===1?'':'s'} tonight</div>` : ''}
       ${stats.uncoveredCount>0 ? `<div class="cov-missing">${stats.uncovered.slice(0,3).map(g=>`${g.away||''}${g.away?' @ ':''}${g.home||''}`).join(' · ')}${stats.uncoveredCount>3?` +${stats.uncoveredCount-3} more`:''}</div>` : ''}`;

  const body = document.getElementById('setup-body');
  if(body) body.prepend(bar);
}



