// FEATURE: LAST NIGHT'S RESULTS — Wow #22
// espnFinals cache: final scores saved with date tag, shown next morning
// Closes the "resolution" emotional loop — the digital sports page check
// ═══════════════════════════════════════════════════════════════════════════
const FINALS_KEY = 'field_espn_finals';
const FINALS_DATE_KEY = 'field_espn_finals_date';

// Load yesterday's finals from localStorage
function loadEspnFinals(){
  try{
    const savedDate = localStorage.getItem(FINALS_DATE_KEY);
    const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0,10);
    if(savedDate === yesterday){
      return JSON.parse(localStorage.getItem(FINALS_KEY)||'[]');
    }
    // Clear if older than yesterday
    if(savedDate && savedDate < yesterday){
      localStorage.removeItem(FINALS_KEY);
      localStorage.removeItem(FINALS_DATE_KEY);
    }
    return [];
  }catch(e){ return []; }
}

// Save a completed game to finals cache
// _eDataMatchesGame: the same home/away/date-compatibility check
// findEspnEntry() uses to confirm a candidate espnScores entry belongs to
// a given game (CC-CMD-2026-07-09-saveespnfinal-internal-guard). Extracted
// as a standalone function -- NOT a call to findEspnEntry(game) itself --
// because saveEspnFinal() has a real caller (the DOM-fallback
// MutationObserver path, ~line 22614) whose eData is built directly from
// card.dataset/previousScores and never touches espnScores at all; calling
// findEspnEntry(game) and requiring it to return that exact object would
// incorrectly reject this genuinely legitimate call. This checks eData's
// OWN homeName/awayName/state fields against game, regardless of what
// object or data source eData actually came from. findEspnEntry() itself
// is left untouched (multiple other, already-tested consumers; refactoring
// it was not asked for and not needed to fix this).
function _eDataMatchesGame(game, eData) {
  if (!game || !eData) return false;
  // Real-ID fast path, same rationale as findEspnEntry() above: when both
  // sides carry a real external _gameId, compare directly and skip the
  // stale-date guard (ID equality already proves same real-world event).
  if (game._gameId && eData._gameId) {
    return game._gameId === eData._gameId;
  }
  const h = (game.home || '').toLowerCase().replace(/[^a-z]/g, '').slice(-6);
  const a = (game.away || '').toLowerCase().replace(/[^a-z]/g, '').slice(-6);
  const vh = (eData.homeName || '').toLowerCase().replace(/[^a-z]/g, '');
  const va = (eData.awayName || '').toLowerCase().replace(/[^a-z]/g, '');
  if (!(vh.endsWith(h) && va.endsWith(a))) return false;
  // Stale-final guard, matching findEspnEntry's own logic exactly.
  if (eData.state === 'post' && game.start_time &&
      new Date(game.start_time).getTime() > Date.now()) {
    return false;
  }
  return true;
}

// 2026-07-13 (CC-CMD-2026-07-13-saveespnfinal-migration): migrated to
// fieldOperation() -- a mid-function exception (e.g. JSON.parse on a
// corrupted localStorage entry, or setItem throwing on quota) used to be
// swallowed by this function's own outer try/catch into an implicit
// `undefined` return, identical to the genuine success path. Both real
// callers (~L23281, ~L41881) branch on the return value and could not
// tell "genuinely saved" from "an exception occurred mid-save" -- a
// broken save was silently counted as successful by both. fieldOperation()
// is now the SOLE catcher of unexpected exceptions; a deliberate guard
// rejection still returns `false` (not a thrown error -- see below), so
// callers must check BOTH result.ok (no exception) AND result.value (the
// business-logic outcome) to fully replicate the pre-migration behavior
// for the guard-rejection case while fixing the exception-masking bug.
async function saveEspnFinal(game, eData){
  return fieldOperation({subsystem:'scores', operation:'save-espn-final', retryable:true, context:{gameId: game?._id||''}}, async () => {
    // Internal guard (CC-CMD-2026-07-09-saveespnfinal-internal-guard):
    // saveEspnFinal() previously trusted whatever eData it was handed,
    // unconditionally, for pick resolution/drama-peak lookup/D1 archive
    // writes -- safe today only because its known callers happen to
    // already verify via findEspnEntry() before calling this, a
    // by-convention guarantee, not one this function enforces itself.
    // eData===game (CFL: the game object carries its own scores directly,
    // never populating espnScores) is trivially "same event" by
    // construction and must never be blocked.
    if (eData !== game && !_eDataMatchesGame(game, eData)) {
      if (typeof FIELD_DEBUG !== 'undefined' && FIELD_DEBUG) {
        console.warn('[saveEspnFinal] rejected -- eData does not match game:',
          game?.home, game?.away, '|', eData?.homeName, eData?.awayName);
      }
      return false;
    }
    // Write under both ET date and UTC date so loadTonightFinals always finds it
    // regardless of when (relative to midnight ET/UTC) the read happens.
    const etToday  = new Date().toLocaleDateString('en-CA',{timeZone:'America/New_York'});
    const utcToday = new Date().toISOString().slice(0,10);
    const today    = etToday; // primary key stays ET for backwards compat
    const existing = JSON.parse(localStorage.getItem(FINALS_KEY)||'[]');
    const id = game._id || (game.home+game.away);
    // Pick 'em resolution (CC-CMD-2026-07-05-pick-em-ui TASK 2, re-keyed by
    // CC-CMD-2026-07-08-pick-cross-session-resolution): deliberately uses a
    // SEPARATE key from `id` above -- `id` is fine for the FINALS_KEY
    // same-session dedup check it's used for here, but game._id is a
    // session-local counter that resets every page load, so a pick made in
    // an earlier session could never be found by it when the game finishes
    // in this one. _pickStorageKey() is stable across sessions (sport+hour+
    // home+away); falls back to `id` only if a stable key can't be built
    // (e.g. missing start_time), matching the pre-fix behavior in that
    // narrow case rather than silently doing nothing differently.
    //
    // CC-CMD-2026-07-11-pick-resolution-retry-decouple: this call is
    // DELIBERATELY placed BEFORE the "already saved" dedup guard below, not
    // after it as originally written. _resolvePickIfExists() has its own
    // idempotency (checks pick.resolved internally, no-ops if the pick
    // doesn't exist or is already resolved) -- calling it on every
    // saveEspnFinal invocation, including ones the dedup guard below would
    // otherwise short-circuit, is safe: a nonexistent or already-resolved
    // pick is a no-op, an unresolved one gets a real retry. Before this
    // change, a transient failure here (relay/network/whatever
    // _resolvePickIfExists could throw) was silently swallowed AND
    // structurally permanent -- existing.push(entry) below fires
    // unconditionally once per game, so the dedup guard would block this
    // function from ever attempting pick-resolution again for that game.
    // Moving the call here means the poll loop that already calls
    // saveEspnFinal repeatedly is the retry mechanism -- no new
    // queue/scheduler needed.
    const pickId = (typeof _pickStorageKey === 'function' ? _pickStorageKey(game) : '') || id;
    if (typeof _resolvePickIfExists === 'function') {
      try { _resolvePickIfExists(pickId, game, eData); }
      catch(_pickErr) { captureFieldError('pick:resolve-final', _pickErr, false); }
    }
    if(existing.some(f=>f.id===id)) return true; // already saved -- genuine success (idempotent). Everything below here (drama persistence, entry/D1 write, night-owl enqueue, tonight-finals write) is a genuine one-time-per-game side effect and stays correctly gated by this guard. Pick-resolution above is NOT gated by it (see comment above).
    const dramaPeak = getDramaPeak(game._id||'', game);
    // ── Drama persistence: POST summary to relay archive (CC-CMD-2026-06-19 / Prompt 11B)
    // Fires once per game at final state — the existing-check above gates
    // this same as the entry write. Relay stores in D1 for Context Graph /
    // Debrief / WOW features. RUWT compliant: client computes, server stores
    // — no server-side drama scoring.
    try {
      const _gameId = game._id || '';
      if (_gameId && dramaPeak > 0) {
        const _peakInfo = (typeof getDramaPeakWithTime === 'function')
          ? getDramaPeakWithTime(_gameId) : { s: dramaPeak, t: 0, p: 0 };
        const _sustained = (typeof getDramaSustained === 'function')
          ? getDramaSustained(_gameId, 65) : 0;
        const _trend = (typeof getDramaTrend === 'function')
          ? getDramaTrend(_gameId) : 0;
        const _hist = (typeof getDramaHistory === 'function')
          ? getDramaHistory(_gameId) : [];

        // Downsample history to ~10 points for sparkline reconstruction.
        const _step = Math.max(1, Math.floor(_hist.length / 10));
        const _samples = _hist.filter((_, i) => i % _step === 0 || i === _hist.length - 1)
          .map(h => ({ s: h.s, p: h.p }));

        // Classify arc shape from the data.
        const _cls = dramaPeak >= 80 && _sustained >= 5 ? 'thriller'
          : dramaPeak >= 70 && _trend > 10 ? 'nail-biter'
          : dramaPeak < 35 ? 'blowout'
          : _trend > 15 && _peakInfo.s > 60 ? 'comeback'
          : 'sleeper';

        const _arcPayload = {
          peak: Math.round(dramaPeak),
          peakPeriod: _peakInfo.p || 0,
          peakMinute: null, // future: compute from game start time delta
          sustainedMinutes: _sustained,
          trend: _trend > 5 ? 'escalating' : _trend < -5 ? 'declining' : 'steady',
          classification: _cls,
          samples: _samples,
        };

        const _relayBase = (typeof V2_RELAY_BASE !== 'undefined')
          ? V2_RELAY_BASE : 'https://field-relay-nba.jeffunglesbee.workers.dev';
        fetch(_relayBase + '/archive/drama', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            source_id: _gameId,
            drama_peak: Math.round(dramaPeak),
            drama_arc: JSON.stringify(_arcPayload),
          }),
          keepalive: true,
        }).catch(e => captureFieldError('archive:drama-final-fetch', e, false)); // fire-and-forget, never blocks saveEspnFinal
      }
    } catch(e) { captureFieldError('archive:drama-final', e, false); } // drama persistence failure cannot affect final save (still observable now)
    // Snapshot stat context at game completion while caches are still warm.
    // Night Owl reads this back via entry.statCtx so it has player stats even
    // after ESPN clears the live box score (the cold-cache J5 ceiling fix).
    let statCtx = '';
    try {
      const _sp = (game._sport||game.league||'').toLowerCase();
      // NBA player box (PM-28h/j)
      if (_sp.includes('nba') || _sp.includes('basketball')) {
        const hNickS = teamNick(game.home||'').toLowerCase();
        const aNickS = teamNick(game.away||'').toLowerCase();
        const nbaIdS = (typeof _nbaGameIdMap!=='undefined')
          ? (_nbaGameIdMap[`${hNickS}_${aNickS}`] || _nbaGameIdMap[`${aNickS}_${hNickS}`]) : null;
        if (nbaIdS && typeof buildNBAScoreLeadersContext==='function') {
          const lCtx = buildNBAScoreLeadersContext(nbaIdS);
          if (lCtx) statCtx += (statCtx?'\n':'') + '  ' + lCtx;
        }
        if (nbaIdS && typeof buildFoulTroubleContext==='function') {
          const fCtx = buildFoulTroubleContext(nbaIdS);
          if (fCtx) statCtx += (statCtx?'\n':'') + '  ' + fCtx;
        }
      }
      // NHL PP/PK (PM-28l)
      if (_sp.includes('nhl') || _sp.includes('hockey')) {
        const nhlKey = Object.keys(window._nhlAnalyticsCache||{}).find(k =>
          k.includes((game.home||'').slice(0,4).toLowerCase()));
        const nhlCtx = nhlKey ? (window._nhlAnalyticsCache||{})[nhlKey] : null;
        if (nhlCtx?.pp && nhlCtx?.pk)
          statCtx += (statCtx?'\n':'') + `  [PP/PK] PP ${nhlCtx.pp}% · PK ${nhlCtx.pk}%`;
        const nhlLiveKey = `${game.home||''}|${game.away||''}`;
        const nhlLive = (typeof _nhlLiveStatsCache!=='undefined')
          ? (_nhlLiveStatsCache[nhlLiveKey] || _nhlLiveStatsCache[`${game.away||''}|${game.home||''}`] || '') : '';
        if (nhlLive) statCtx += (statCtx?'\n':'') + '  [NHL LIVE] ' + nhlLive;
      }
      // Linescore removed from prompt (June 20 2026) — analytical buildScoreNarrativeContext used instead.
    } catch(_) { captureFieldError('scores:statctx-build', _, true); }
    const entry = {
      id, home:game.home||'', away:game.away||'',
      homeScore:eData.homeScore, awayScore:eData.awayScore,
      sport:game._sport||'', league:game.league||'',
      seriesRecord: game.seriesRecord||'',
      sourceId: game.sourceId||'',
      matchupNote: game.matchupNote||'',
      date: today, dramaPeak,
      statCtx: statCtx || '',  // stat snapshot — survives ESPN cache clearing
      // start_time + _sport (CC-CMD-2026-07-08-pick-cross-session-resolution
      // follow-up): field names must match what _pickStorageKey()/_gameSport()
      // read on a real game object (game._sport, not the `sport` field above)
      // so downstream readers of this snapshot (Night Owl's Scout's Pick
      // lookup) compute the identical stable key this entry was written under.
      start_time: game.start_time || '', _sport: game._sport || '',
    };
    existing.push(entry);
    localStorage.setItem(FINALS_KEY, JSON.stringify(existing.slice(-20)));
    localStorage.setItem(FINALS_DATE_KEY, today);
    // Item 3: enqueue Night Owl brief as soon as game goes final.
    // Result lands in relay KV before user opens the owl card.
    // renderNightOwlRecap polls the job key and injects without waiting on a
    // synchronous fetchNightOwlFromClaude call in the render path.
    // Only enqueues when relay Queue endpoint is available and margin is not a blowout.
    try {
      const _owlFinalMargin = Math.abs((eData.homeScore||0) - (eData.awayScore||0));
      if (JOURNALISM_ENQUEUE_RELAY && _owlFinalMargin <= 20) {
        const _owlQueueSwV = window.SW_VERSION || '0';
        const _owlQueueKey = 'field_owl_job_v' + _owlQueueSwV + '_' + id;
        const _owlBriefKey = 'field_nightowl_v' + _owlQueueSwV + '_' + id;
        // Only enqueue if no cached brief and no pending job
        const alreadyHasBrief = (() => { try { return !!sessionStorage.getItem(_owlBriefKey); } catch(e_) { captureFieldError('scores:night-owl-brief-cache-read', e_, true); return false; } })();
        const alreadyQueued   = (() => { try { return !!sessionStorage.getItem(_owlQueueKey); } catch(e_) { captureFieldError('scores:night-owl-queue-cache-read', e_, true); return false; } })();
        if (!alreadyHasBrief && !alreadyQueued) {
          // Build a minimal prompt from the entry data — full context added by
          // fetchNightOwlFromClaude when it runs as fallback, but queue gives us
          // a head start using the stat snapshot already in entry.statCtx.
          const _owlQ_sp = (game._sport || game.league || '').toLowerCase();
          const _owlQ_winner = (eData.awayScore||0) > (eData.homeScore||0) ? game.away : game.home;
          const _owlQ_margin = _owlFinalMargin;
          const _owlQ_unit = (_owlQ_sp.includes('baseball')||_owlQ_sp.includes('mlb')) ? 'run'
            : (_owlQ_sp.includes('hockey')||_owlQ_sp.includes('nhl')||_owlQ_sp.includes('soccer')) ? 'goal'
            : 'point';
          const _owlQ_prompt = [
            'Write a FIELD Night Owl recap.',
            '',
            'GAME DATA:',
            `Game: ${game.away||'?'} @ ${game.home||'?'}`,
            `Final: ${eData.awayScore}–${eData.homeScore} (${_owlQ_winner} wins)`,
            `MARGIN: ${_owlQ_margin}-${_owlQ_unit}${_owlQ_margin===1?'':'s'} (winner ${_owlQ_winner})`,
            game.seriesRecord ? 'Series: ' + game.seriesRecord : '',
            game.matchupNote ? 'Matchup: ' + game.matchupNote : '',
            entry.statCtx || '',
            '',
            'Rules: 80-100 words. Tactical. Not emotional. Lead with the turning point.',
            '- Write only from data above — never invent statistics or play-by-play.',
            '- CRITICAL — DO NOT FABRICATE SPECIFICS: no specific inning/quarter/at-bat details unless in stat context above.',
          ].filter(Boolean).join('\n');
          fetch(JOURNALISM_ENQUEUE_RELAY, {
            method: 'POST',
            headers: {'Content-Type':'application/json'},
            body: JSON.stringify({
              prompt: _owlQ_prompt,
              sport: game._sport || '',
              briefType: 'night-owl',
              max_tokens: 600,
              // scoreThreshold 240 -- see generateJournalismViaRelay's
              // comment (CC-CMD-2026-07-09-jq-threshold-240-migration).
              scoreThreshold: 240,
              // home/away/homeScore/awayScore/matchupNote (CC-CMD-2026-07-09-
              // enqueue-context-gap): the enqueue endpoint's queue message
              // never carried these, so the consumer's Context Anchoring (25
              // pts) and Matchup Depth (30 pts) were structurally unreachable
              // regardless of scoreThreshold. All five already computed above
              // for _owlQ_prompt -- reused, not fetched anew.
              home: game.home || '',
              away: game.away || '',
              homeScore: eData.homeScore ?? null,
              awayScore: eData.awayScore ?? null,
              matchupNote: game.matchupNote || null,
            }),
          }).then(r => r.ok ? r.json() : null).then(data => {
            if (data?.jobId) {
              try { sessionStorage.setItem(_owlQueueKey, data.jobId); } catch(e_) { captureFieldError('scores:night-owl-jobid-cache-write', e_, true); }
            }
          }).catch((e) => { captureFieldError('scores:night-owl-enqueue-fetch', e, true); });
        }
      }
    } catch(e_) { captureFieldError('scores:night-owl-enqueue', e_, true); }
    // Write to both ET and UTC tonight-finals keys so loadTonightFinals finds it
    // even when ET date (save time) ≠ ET date (read time) across midnight boundary.
    for(const dateKey of [etToday, utcToday]){
      try{
        const tnKey='field_tonight_finals_'+dateKey;
        const tnPool=JSON.parse(localStorage.getItem(tnKey)||'[]');
        if(!tnPool.some(f=>f.id===id)){
          tnPool.push(entry);
          localStorage.setItem(tnKey,JSON.stringify(tnPool.slice(-10)));
        }
      }catch(e2){ captureFieldError('scores:tonight-finals-write', e2, true); }
    }
    return true;
  });
}

// Render Last Night's Results bar above the schedule

// J5: NIGHT OWL RECAP
function loadTonightFinals(){
  try{
    // Primary: ET date key (canonical)
    const today=new Date().toLocaleDateString('en-CA',{timeZone:'America/New_York'});
    const primary=JSON.parse(localStorage.getItem('field_tonight_finals_'+today)||'[]');
    if(primary.length) return primary;
    // Fallback 1: UTC date (catches games saved after midnight UTC but before midnight ET)
    const utcToday=new Date().toISOString().slice(0,10);
    if(utcToday!==today){
      const utcFallback=JSON.parse(localStorage.getItem('field_tonight_finals_'+utcToday)||'[]');
      if(utcFallback.length) return utcFallback;
    }
    // Fallback 2: local browser date (catches timezone mismatch from older saves)
    const localToday=new Date().toLocaleDateString('en-CA');
    if(localToday!==today && localToday!==utcToday){
      const fallback=JSON.parse(localStorage.getItem('field_tonight_finals_'+localToday)||'[]');
      if(fallback.length) return fallback;
    }
    return [];
  }catch(e){return [];}
}

// ── hydrateEspnScoresFromFinals ───────────────────────────────────────────────
// Writes correct final scores from tonight's localStorage finals into espnScores.
// This is the authoritative source for completed game scores — more reliable than
// V2 which frequently returns null scores for finished games. Called:
//   1. After renderAll() so score-wraps render with real scores
//   2. After each V2 poll cycle so null-score writes don't overwrite known finals
// Key format matches V2: "Home Team|Away Team" (V2 fg.home.name|fg.away.name)
function hydrateEspnScoresFromFinals() {
  try {
    const finals = loadTonightFinals();
    if (!finals.length) return;
    for (const f of finals) {
      if (f.homeScore == null || f.awayScore == null) continue;
      if (!f.home || !f.away) continue;
      const key = `${f.home}|${f.away}`;
      const existing = espnScores[key];
      // Only write if: no entry exists, OR existing entry has 0-0 scores on a final
      const existingIsBlank = existing?.state === 'post' &&
        (existing.homeScore || 0) === 0 && (existing.awayScore || 0) === 0;
      if (!existing || existingIsBlank) {
        espnScores[key] = {
          state: 'post',
          homeScore: f.homeScore, awayScore: f.awayScore,
          home: f.home, away: f.away,
          homeName: f.home, awayName: f.away,
          homeWinning: f.homeScore > f.awayScore,
          clock: '', detail: 'F', period: 0,
          periodPrefix: '', source: 'finals-cache',
          espnEventId: null, wp: null, wp_prev: null,
          homeLeader: null, awayLeader: null,
          homeLinescores: [], awayLinescores: [],
          _scoresNull: false,
        };
        espnScoreTs[key] = Date.now();
      }
    }
    // Layer 2 fallback (June 15 2026): scan static schedule for games with
    // homeScore/awayScore fields. Catches completed playoff games where V2
    // returns null scores and localStorage finals have expired (next-day load).
    // Only writes when espnScores has no entry or has a 0-0 final (null-score residue).
    if (typeof allData !== 'undefined' && allData?.sports) {
      for (const sec of allData.sports) {
        for (const g of (sec.games || [])) {
          if (g.homeScore == null || g.awayScore == null) continue;
          if (!g.home || !g.away) continue;
          // Only backfill past games (start_time already passed)
          if (g.start_time && new Date(g.start_time).getTime() > Date.now()) continue;
          const key = `${g.home}|${g.away}`;
          const existing = espnScores[key];
          const existingIsBlank = existing?.state === 'post' &&
            (existing.homeScore || 0) === 0 && (existing.awayScore || 0) === 0;
          if (!existing || existingIsBlank) {
            espnScores[key] = {
              state: 'post',
              homeScore: g.homeScore, awayScore: g.awayScore,
              home: g.home, away: g.away,
              homeName: g.home, awayName: g.away,
              homeWinning: g.homeScore > g.awayScore,
              clock: '', detail: 'F', period: 0,
              periodPrefix: V2_PERIOD_PREFIX[classifySport(g, null)?.isNHL ? 'nhl' : ''] || '',
              source: 'schedule-cache',
              espnEventId: null, wp: null, wp_prev: null,
              homeLeader: null, awayLeader: null,
              homeLinescores: [], awayLinescores: [],
              _scoresNull: false,
            };
            espnScoreTs[key] = Date.now();
          }
        }
      }
    }
  } catch(e) { captureFieldError('scores:hydrate-espn-from-finals', e, true); }
}
