  // FIELD Brief = pre-game context. Night Owl/Recap = post-game editorial. Separate slots.
  const el = (_DOM?.nightOwl||document.getElementById('night-owl'));
  if(!el) return;

  // Primary path: localStorage (populated by saveEspnFinal via checkForNewFinals)
  let finals=loadTonightFinals();

